window.HADITH_CACHE["tirmidzi_4"] = {"2001":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَامِرٍ الْعَقَدِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ إِسْمَعِيلَ بْنِ أَبِي حَبِيبَةَ عَنْ دَاوُدَ بْنِ حُصَيْنٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُعَلِّمُهُمْ مِنْ الْحُمَّى وَمِنْ الْأَوْجَاعِ كُلِّهَا أَنْ يَقُولَ بِسْمِ اللَّهِ الْكَبِيرِ أَعُوذُ بِاللَّهِ الْعَظِيمِ مِنْ شَرِّ كُلِّ عِرْقٍ نَعَّارٍ وَمِنْ شَرِّ حَرِّ النَّارِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ إِبْرَاهِيمَ بْنِ إِسْمَعِيلَ بْنِ أَبِي حَبِيبَةَ وَإِبْرَاهِيمُ يُضَعَّفُ فِي الْحَدِيثِ وَيُرْوَى عِرْقٌ يَعَّارٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar]; telah menceritakan kepada kami [Abu 'Amir Al 'Aqadi]; telah menceritakan kepada kami [Ibrahim bin Isma'il bin Abu Habibah] dari [Dawud bin Hushain] dari ['Ikrimah] dari [Ibnu 'Abbas] dia berkata; Bahwasanya Nabi shallallahu 'alaihi wasallam senantiasa mengajarkan kepada mereka apabila terkena sakit panas dan sakit yang lain untuk mengucapkan: \"BISMILLAHIL KABIIR, A'UUDZU BILLAHIL 'AZHIIM MIN SYARRI KULLI 'IRQIN NA'AARIN WA MIN SYARRI HARRIN NAAR (Dengan nama Allah Yang Mahabesar, aku berlindung kepada Allah Yang Mahaagung dari tekanan darah yang tinggi dan bergejolak sehingga menimbulkan sakit panas dan dari panasnya api neraka.) \" Berkata Abu Isa; Ini merupakan hadits gharib tidak kami ketahui kecuali dari hadits yang diriwayatkan Ibrahim bin Isma'il bin Abi Habibah, namun Ibrahim didha'ifkan dalam periwayatan hadits. Dan diriwayatkan dengan lafazh 'irqun ya'aar\"."},"2002":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا يَحْيَى بْنُ إِسْحَقَ حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ نَوْفَلٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ عَنْ ابْنَةَ وَهْبٍ وَهِيَ جُدَامَةُ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَرَدْتُ أَنْ أَنْهَى عَنْ الْغِيَالِ فَإِذَا فَارِسُ وَالرُّومُ يَفْعَلُونَ وَلَا يَقْتُلُونَ أَوْلَادَهُمْقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أَسْمَاءَ بِنْتِ يَزِيدَ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَاهُ مَالِكٌ عَنْ أَبِي الْأَسْوَدِ عَنْ عُرْوَةَ عَنْ عَائِشَةَ عَنْ جُدَامَةَ بِنْتِ وَهْبٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ قَالَ مَالِكٌ وَالْغِيَالُ أَنْ يَطَأَ الرَّجُلُ امْرَأَتَهُ وَهِيَ تُرْضِعُ","id":"Telah menceritakan kepada kami [Ahmad bin Mani']; telah menceritakan kepada kami [Yahya bin Ishaq]; telah menceritakan kepada kami [Yahya bin Ayyub] dari [Muhammad bin 'Abdurrahman bin Naufal] dari ['Urwah] dari ['Aisyah] dari puteri Wahb yaitu [Judamah] dia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku hendak melarang Al Ghiyal, namun orang-orang Persi dan Ramawi melakukannya dan mereka pun tidak membunuh (mendatangkan madharat bagi) anak-anak mereka.\" Abu Isa berkata; Hadits semakna juga diriwayatkan dari Asma` binti Yazid. Dan ini adalah hadits hasan shahih. Hadits ini telah diriwayatkan pula oleh [Malik] dari [Abul Aswad] dari ['Urwah] dari ['Aisyah] dari [Judamah bintu Wahb] dari Nabi shallallahu 'alaihi wasallam. Malik berkata, 'Ghiyal adalah laki-laki yang menjima' istri yang sedang dalam masa menyusui.\""},"2003":{"ar":"حَدَّثَنَا عِيسَى بْنُ أَحْمَدَ حَدَّثَنَا ابْنُ وَهْبٍ حَدَّثَنِي مَالِكٌ عَنْ أَبِي الْأَسْوَدِ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ نَوْفَلٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ عَنْ جُدَامَةَ بِنْتِ وَهْبٍ الْأَسَدِيَّةِأَنَّهَا سَمِعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَقَدْ هَمَمْتُ أَنْ أَنْهَى عَنْ الْغِيلَةِ حَتَّى ذَكَرْتُ أَنَّ الرُّومَ وَفَارِسَ يَصْنَعُونَ ذَلِكَ فَلَا يَضُرُّ أَوْلَادَهُمْقَالَ مَالِكٌ وَالْغِيلَةُ أَنْ يَمَسَّ الرَّجُلُ امْرَأَتَهُ وَهِيَ تُرْضِعُ قَالَ عِيسَى بْنُ أَحْمَدَ وَحَدَّثَنَا إِسْحَقُ بْنُ عِيسَى حَدَّثَنِي مَالِكٌ عَنْ أَبِي الْأَسْوَدِ نَحْوَهُ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ صَحِيحٌ","id":"Telah menceritakan kepada kami ['Isa bin Ahmad]; telah menceritakan kepada kami [Ibnu Wahb]; telah menceritakan kepadaku [Malik] dari [Abul Aswad Muhammad bin 'Abdurrahman bin Naufal] dari ['Urwah] dari ['Aisyah] dari [Judamah bintu Wahb Al Asadiyyah] bahwasanya ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh, aku telah berniat untuk melarang Al Ghilah namun aku mengingat bahwa orang-orang Persi dan Ramawi melakukannya, dan hal itu ternyata tidak berpengaruh buruk pada anak-anak mereka.\" Malik berkata; Al Ghailah adalah seorang yang menggauli isterinya yang sedang dalam masa menyusui. Isa bin Ahmad berkata; Telah menceritakan kepada kami [Ishaq bin 'Isa]; Telah menceritakan kepadaku [Malik] dari [Abul Aswad] semisalnya. Abu Isa berkata; Ini adalah hadits hasan shahih."},"2004":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ أَبِي عَبْدِ اللَّهِ عَنْ زَيْدِ بْنِ أَرْقَمَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَنْعَتُ الزَّيْتَ وَالْوَرْسَ مِنْ ذَاتِ الْجَنْبِ قَالَ قَتَادَةُ يَلُدُّهُ وَيَلُدُّهُ مِنْ الْجَانِبِ الَّذِي يَشْتَكِيهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَأَبُو عَبْدِ اللَّهِ اسْمُهُ مَيْمُونٌ هُوَ شَيْخٌ بَصْرِيٌّ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar]; telah menceritakan kepada kami [Mu'adz bin Hisyam]; telah menceritakan kepadaku [bapakku] dari [Qatadah] dari [Abu 'Abdullah] dari [Zaid bin Arqam] bahwasanya Nabi shallallahu 'alaihi wasallam biasanya menjelaskan tentang (khasiat) minyak zaitun dan wars bagi orang yang menderita radang selaput dada. Qatadah berkata, \"Meminumnya, yakni meminum dan mengarahkannya pada salah satu sisi mulut (kanan atau kiri) sesuai dengan bagian yang terasa sakit.\" Abu Isa berkata; Ini adalah hadits hasan shahih. Dan Abu Abdullah namanya adalah Maimun dan seorang Syaikh Bashri."},"2005":{"ar":"حَدَّثَنَا رَجَاءُ بْنُ مُحَمَّدٍ الْعُذْرِيُّ الْبَصْرِيُّ حَدَّثَنَا عَمْرُو بْنُ مُحَمَّدِ بْنِ أَبِي رَزِينٍ حَدَّثَنَا شُعْبَةُ عَنْ خَالِدٍ الْحَذَّاءِ حَدَّثَنَا مَيْمُونٌ أَبُو عَبْدِ اللَّهِ قَال سَمِعْتُ زَيْدَ بْنَ أَرْقَمَ قَالَأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَتَدَاوَى مِنْ ذَاتِ الْجَنْبِ بِالْقُسْطِ الْبَحْرِيِّ وَالزَّيْتِقَالَ أَبُو عِيسَى هَذَا حَدِيث�� حَسَنٌ غَرِيبٌ صَحِيحٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ مَيْمُونٍ عَنْ زَيْدِ بْنِ أَرْقَمَ وَقَدْ رَوَى عَنْ مَيْمُونٍ غَيْرُ وَاحِدٍ مِنْ أَهْلِ الْعِلْمِ هَذَا الْحَدِيثَ وَذَاتُ الْجَنْبِ يَعْنِي السِّلَّ","id":"Telah menceritakan kepada kami [Raja' bin Muhammad Al 'Udzri Al Bashri]; telah menceritakan kepada kami ['Amr bin Muhammad bin Abu Razin]; telah menceritakan kepada kami [Syu'bah] dari [Khalid Al Hadzdza']; telah menceritakan kepada kami [Maimun Abu 'Abdullah] dia berkata; aku mendengar [Zaid bin Arqam] berkata; Rasulullah shallallahu 'alaihi wasallam memerintahkan kepada kami agar berobat dengan menggunakan al qusth al bahri dan minyak Zaitun jika menderita radang selaput dada. Abu Isa berkata; Ini adalah hadits Hasan Gharib Shahih, kami tidak mengetahuinya kecuali dari haditsnya Maimun dari Zaid bin Arqam. Dan hadits ini telah diriwayatkan pula oleh lebih dari satu orang perawi dari Maimun Dzatul Janb maksudnya adalah batuk. "},"2006":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مُوسَى الْأَنْصَارِيُّ حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكٌ عَنْ يَزِيدَ بْنِ خُصَيْفَةَ عَنْ عَمْرِو بْنِ عَبْدِ اللَّهِ بْنِ كَعْبٍ السُّلَمِيِّ أَنَّ نَافِعَ بْنَ جُبَيْرِ بْنِ مُطْعِمٍ أَخْبَرَهُ عَنْ عُثْمَانَ بْنِ أَبِي الْعَاصِ أَنَّهُ قَالَأَتَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبِي وَجَعٌ قَدْ كَانَ يُهْلِكُنِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ امْسَحْ بِيَمِينِكَ سَبْعَ مَرَّاتٍ وَقُلْ أَعُوذُ بِعِزَّةِ اللَّهِ وَقُدْرَتِهِ وَسُلْطَانِهِ مِنْ شَرِّ مَا أَجِدُ قَالَ فَفَعَلْتُ فَأَذْهَبَ اللَّهُ مَا كَانَ بِي فَلَمْ أَزَلْ آمُرُ بِهِ أَهْلِي وَغَيْرَهُمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ishaq bin Musa Al Anshari]; telah menceritakan kepada kami [Ma'n]; telah menceritakan kepada kami [Malik] dari [Yazid bin Khushaifah] dari ['Amr bin 'Abdullah bin Ka'b As Sulami] bahwasanya [Nafi' bin Jubair bin Muth'im] mengabarkan kepadanya dari ['Utsman bin Abul 'Ash] bahwasanya ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah mendatangiku saat aku menderi sakit yang hampir membinasakanku, maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Usapkanlah dengan tangan kananmu sebanyak tujuh kali dan bacalah, 'A'UUDZU BI'IZZATILLAHI WA QUDRATIHI WA SHULTHAANIHI MIN SYARRI MAA AJIDU (Aku berlindung kepada Allah, kemuliaan, dan kekuasaanNya dari kejelekan yang aku temui).\" Lalu aku pun melakukan hal itu, maka Allah pun menghilangkan rasa sakit yang kuderita sebelumnya. Dan aku selalu menyuruh kerabatku dan selain mereka untuk mengamalkannya. Abu Isa berkata; Ini adalah hadits hasan shahih."},"2007":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ حَدَّثَنِي عُتْبَةُ بْنُ عَبْدِ اللَّهِ عَنْ أَسْمَاءَ بِنْتِ عُمَيْسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَأَلَهَا بِمَ تَسْتَمْشِينَ قَالَتْ بِالشُّبْرُمِ قَالَ حَارٌّ جَارٌّ قَالَتْ ثُمَّ اسْتَمْشَيْتُ بِالسَّنَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ أَنَّ شَيْئًا كَانَ فِيهِ شِفَاءٌ مِنْ الْمَوْتِ لَكَانَ فِي السَّنَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ يَعْنِي دَوَاءَ الْمَشِيِّ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar]; telah menceritakan kepada kami [Muhammad bin Bakr]; telah menceritakan kepada kami ['Abdul Hamid bin Ja'far]; telah menceritakan kepadaku ['Utbah bin 'Abdullah] dari [Asma' bintu 'Umais] bahwasanya Rasulullah shallallahu 'alaihi wasallam bertanya kepadanya: \"Dengan obat apakah engkau mengeluarkan isi perutmu (obat untuk membuat orang mencret)?\" Asma' menjawab, \"Dengan Syubrum.\" Beliau bersabda: \"Sungguh itu obat yang sangat panas.\" Asma' berkata; Setelah itu akau meminum as sanaa, lantas Nabi shallallaahu 'alaihi wa sallam bersabda: \"Jika ada obat yang dapat mencegah dari kematian tentu itu adalah as sanaa.\" Berkata Abu Isa; Ini merupakan hadits hasan gharib."},"2008":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَبِي الْمُتَوَكِّلِ عَنْ أَبِي سَعِيدٍ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ أَخِي اسْتَطْلَقَ بَطْنُهُ فَقَالَ اسْقِهِ عَسَلًا فَسَقَاهُ ثُمَّ جَاءَ فَقَالَ يَا رَسُولَ اللَّهِ قَدْ سَقَيْتُهُ عَسَلًا فَلَمْ يَزِدْهُ إِلَّا اسْتِطْلَاقًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْقِهِ عَسَلًا فَسَقَاهُ ثُمَّ جَاءَهُ فَقَالَ يَا رَسُولَ اللَّهِ قَدْ سَقَيْتُهُ عَسَلًا فَلَمْ يَزِدْهُ إِلَّا اسْتِطْلَاقًا قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَدَقَ اللَّهُ وَكَذَبَ بَطْنُ أَخِيكَ اسْقِهِ عَسَلًا فَسَقَاهُ عَسَلًا فَبَرَأَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar]; telah menceritakan kepada kami [Muhammad bin Ja'far]; telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Abul Mutawakkil] dari [Abu Sa'id] dia berkata; Seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam dan berkata, \"Sesungguhnya perut saudaraku kendor.\" Maka beliau bersabda: \"Berilah ia madu.\" Lalu laki-laki itu pun memberikannya madu. Kemudian laki-laki itu kembali lagi dan berkata, \"Wahai Rasulullah, aku telah memberinya madu, namun tidak ada perubahan kecuali semakin kempes.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda lagi: \"Berilah ia madu.\" Dan laki-laki itu pun kembali meminumkan saudaranya dengan air madu dan datang lagi menemui beliau seraya berkata, \"Wahai Rasulullah, sesungguhnya aku telah meminumkannya air madu, namun tidak ada perubahan kecual semakin kempes.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah telah berkata benar, namun perut saudaramulah yang telah berdusta. Minumkanlah padanya air madu.\" Maka laki-laki itu kembali meminumkan saudaranya dengan air madu, lalu sembuh seketika. Abu Isa berkata; Ini adalah hadits hasan shahih."},"2009":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ يَزِيدَ بْنِ خَالِدٍ قَال سَمِعْتُ الْمِنْهَالَ بْنَ عَمْرٍو يُحَدِّثُ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَا مِنْ عَبْدٍ مُسْلِمٍ يَعُودُ مَرِيضًا لَمْ يَحْضُرْ أَجَلُهُ فَيَقُولُ سَبْعَ مَرَّاتٍ أَسْأَلُ اللَّهَ الْعَظِيمَ رَبَّ الْعَرْشِ الْعَظِيمِ أَنْ يَشْفِيَكَ إِلَّا عُوفِيَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ الْمِنْهَالِ بْنِ عَمْرٍو","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna]; telah menceritakan kepada kami [Muhammad bin Ja'far]; telah menceritakan kepada kami [Syu'bah] dari [Yazid bin Khalid]; dia berkata; aku mendengar [Al Minhal bin 'Amr] bercerita dari [Sa'id bin Jubair] dari [Ibnu 'Abbas] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang hamba muslim menjenguk orang yang sakit yang belium sekarat kemudian ia membaca sebanyak tujuh kali, 'AS`ALULLAAHAL 'AZHIIM RABBAL 'ARSYIL KARIIM AN YASYFIYAKA (Aku meminta kepada Allah yang Maha Agung, Rabb-nya Arsy yang mulia untuk menyembuhkanmu) kecuali ia akan sembuh.\" Abu Isa berkata; Ini adalah hadits hasan gharib, kami tidak mengetahuinya kecuali dari haditsnya Al Minhal bin Amr."},"2010":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ سَعِيدٍ الْأَشْقَرُ الرِّبَاطِيُّ حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ حَدَّثَنَا مَرْزُوقٌ أَبُو عَبْدِ اللَّهِ الشَّامِيُّ حَدَّثَنَا سَعِيدٌ رَجُلٌ مِنْ أَهْلِ الشَّامِ أَخْبَرَنَا ثَوْبَانُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَصَابَ أَحَدَكُمْ الْحُمَّى فَإِنَّ الْحُمَّى قِطْعَةٌ مِنْ النَّارِ فَلْيُطْفِئْهَا عَنْهُ بِالْمَاءِ فَلْيَسْتَنْقِعْ نَهْرًا جَارِيًا لِيَسْتَقْبِلَ جِرْيَتَهُ فَيَقُولُ بِسْمِ اللَّهِ اللَّهُمَّ اشْفِ عَبْدَكَ وَصَدِّقْ رَسُولَكَ بَعْدَ صَلَاةِ الصُّبْحِ قَبْلَ طُلُوعِ الشَّمْسِ فَلْيَغْتَمِسْ فِيهِ ثَلَاثَ غَمَسَاتٍ ثَلَاثَةَ أَيَّامٍ فَإِنْ لَمْ يَبْرَأْ فِي ثَلَاثٍ فَخَمْسٍ وَإِنْ لَمْ يَبْرَأْ فِي خَمْسٍ فَسَبْعٌ فَإِنْ لَمْ يَبْرَأْ فِي سَبْعٍ فَتِسْعٍ فَإِنَّهَا لَا تَكَادُ تُجَاوِزُ تِسْعًا بِإِذْنِ اللَّهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Ahmad bin Sa'id Al Asyqar Ar Rabathi]; telah menceritakan kepada kami [Rauh bin 'Ubadah]; telah menceritakan kepada kami [Marzuq Abu 'Abdullah Asy Syami]; telah menceritakan kepada kami [Sa'id] seorang laki-laki dari penduduk Syam; telah mengabarkan kepada kami [Tsauban] dari Nabi shallallahu 'alaihi wasallam beliau bersabda; \"Jika salah seorang dari kalian menderita sakit panas (sesungguhnya panas itu bagian dari api neraka), maka hendaknya dia menurunkannya dengan air, hendaknya dia berendam diri di sungai yang mengalir sambil mengucapkan, 'BISMILLAHI ALLAHUMMASYFI 'ABDAKA WA SHADDIQ RASULAKA BA'DA SHALAATISH SHUBHI QABLA THULU'ISY SYAMSYI (Ya Allah, sembuhkanlah hamba-Mu dan benarkanlah RasulMu; yaitu setelah shalat shubuh sebelum terbitnya matahari).' Dan dia berendam diri sebanyak tiga kali selama tiga hari, jika belum sembuh lanjutkanlah selama lima hari, jika belum sembuh juga maka lanjutkanlah selama tujuh hari dan jika belum sembuh juga maka selama sembilan hari, karena hal itu jarang sekali melebihi sembilan hari dengan izin Allah.\" Berkata Abu Isa; Ini merupakan hadits gharib."},"2011":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي حَازِمٍ قَالَ سُئِلَ سَهْلُ بْنُ سَعْدٍوَأَنَا أَسْمَعُ بِأَيِّ شَيْءٍ دُووِيَ جَرْحُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا بَقِيَ أَحَدٌ أَعْلَمُ بِهِ مِنِّي كَانَ عَلِيٌّ يَأْتِي بِالْمَاءِ فِي تُرْسِهِ وَفَاطِمَةُ تَغْسِلُ عَنْهُ الدَّمَ وَأُحْرِقَ لَهُ حَصِيرٌ فَحَشَا بِهِ جُرْحَهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ibnu Abu 'Umar]; telah menceritakan kepada kami [Sufyan] dari [Abu Hazim] dia berkata; [Sahl bin Sa'd] pernah ditanya dan saya mendengarkannya, \"Dengan apa luka Rasulullah shallallahu 'alaihi wasallam diobati?\" Maka ia pun menjawab, \"Tidak lagi tersisa seorang pun yang paling mengetahuinya daripada aku. Biasanya Ali membawakan air di dalam tamengnya sementara Fathimah mencuci dan membersihkan darah. Lalu luka beliau dibalut.\" Abu Isa berkata; Ini adalah hadits hasan shahih."},"2012":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَخْبَرَنَا الْوَلِيدُ بْنُ مُحَمَّدٍ الْمُوَقَّرِيُّ عَنْ الزُّهْرِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا مَثَلُ الْمَرِيضِ إِذَا بَرَأَ وَصَحَّ كَالْبَرْدَةِ تَقَعُ مِنْ السَّمَاءِ فِي صَفَائِهَا وَلَوْنِهَا","id":"Telah menceritakan kepada kami ['Ali bin Hujr] dia berkata; telah mengabarkan kepada kami [Al Walid bin Muhammad Al Muwaqqiri] dari [Az Zuhri] dari [Anas bin Malik] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perumpamaan seorang yang sembuh dan kembali sehat seperti salju yang turun dari langit tatkala langit sedang cerah.\""},"2013":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ الْأَشَجُّ حَدَّثَنَا عُقْبَةُ بْنُ خَالِدٍ السَّكُّونِيُّ عَنْ مُوسَى بْنِ مُحَمَّدِ بْنِ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَخَلْتُمْ عَلَى الْمَرِيضِ فَنَفِّسُوا لَهُ فِي أَجَلِهِ فَإِنَّ ذَلِكَ لَا يَرُدُّ شَيْئًا وَيُطَيِّبُ نَفْسَهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ","id":"Telah menceritakan kepada kami ['Abdullah bin Sa'id Al Asyaj]; telah menceritakan kepada kami ['Uqbah bin Khalid As Sakkauni] dari [Musa bin Muhammad bin Ibrahim At Taimi] dari [bapaknya] dari [Abu Sa'id Al Khudri] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika kalian menjenguk orang yang sakit, hendaknya ringankanlah bebannya dan hiburlah dia jika mendekati ajalnya, karena hal itu tidak dapat menolak taqdir dan hal itu dapat menenangkan jiwanya.\" Berkata Abu Isa: Ini merupakan hadits gharib."},"2014":{"ar":"حَدَّثَنَا هَنَّادٌ وَمَحْمُودُ بْنُ غَيْلَانَ قَالَا حَدَّثَنَا أَبُو أُسَامَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ بْنِ جَابِرٍ ع��نْ إِسْمَعِيلَ بْنِ عُبَيْدِ اللَّهِ عَنْ أَبِي صَالِحٍ الْأَشْعَرِيِّ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَادَ رَجُلًا مِنْ وَعَكٍ كَانَ بِهِ فَقَالَ أَبْشِرْ فَإِنَّ اللَّهَ يَقُولُ هِيَ نَارِي أُسَلِّطُهَا عَلَى عَبْدِي الْمُذْنِبِ لِتَكُونَ حَظَّهُ مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Hannad] dan [Mahmud bin Ghailan] mereka berdua berkata; telah menceritakan kepada kami [Abu Usamah] dari ['Abdurrahman bin Yazid bin Jabir] dari [Isma'il bin 'Ubaidullah] dari [Abu Shalih Al Asy'ari] dari [Abu Hurairah] bahwasanya Nabi shallallahu 'alaihi wasallam pernah menjenguk seseorang yang menderita sakit. Maka beliau pun bersabda: \"Bergembiralah, karena sesungguhnya itu adalah api milik-Ku yang Aku timpakan kepada hamba-Ku yang berbuat dosa, agar api itu menjaganya dari api neraka.\""},"2015":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ سُفْيَانَ الثَّوْرِيِّ عَنْ هِشَامِ بْنِ حَسَّانَ عَنْ الْحَسَنِ قَالَكَانُوا يَرْتَجُونَ الْحُمَّى لَيْلَةً كَفَّارَةً لِمَا نَقَصَ مِنْ الذُّنُوبِ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] dia berkata; telah mengabarkan kepada kami ['Abdurrahman bin Mahdi] dari [Sufyan Ats Tsauri] dari [Hisyam bin Hassan] dari [Al Hasan] dia berkata, \"Mereka para sahabat mengharap sakit demam di malam hari sebagai kafarah. Yakni sebagai kafarah untuk mengurangi dosa-dosa.\""},"2016":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ يَحْيَى بْنِ سَعِيدٍ الْأُمَوِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو حَدَّثَنَا أَبُو سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَرَكَ مَالًا فَلِأَهْلِهِ وَمَنْ تَرَكَ ضَيَاعًا فَإِلَيَّقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَفِي الْبَاب عَنْ جَابِرٍ وَأَنَسٍ وَقَدْ رَوَاهُ الزُّهْرِيُّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَطْوَلَ مِنْ هَذَا وَأَتَمَّ مَعْنَى ضَيَاعًا ضَائِعًا لَيْسَ لَهُ شَيْءٌ فَأَنَا أَعُولُهُ وَأُنْفِقُ عَلَيْهِ","id":"Telah menceritakan kepada kami [Sa'id bin Yahya bin Sa'id Al Umawi]; [bapakku] telah menceritakan kepada kamil; telah menceritakan kepada kami [Muhammad bin 'Amr]; telah menceritakan kepada kami [Abu Salamah] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang meninggalkan harta, maka harta itu adalah milik keluarganya. Dan barangsiapa yang meninggalkan anak-anak, maka mereka itu akan kembali kepadaku.\" Abu Isa berkata; Ini adalah hadits Hasan Shahih. Hadits semakna juga diriwayatkan dari Jabir dan Anas. Dan hadits ini telah diriwayatkan pula oleh [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, dengan redaksi yang lebih panjang dari ini serta maknanya juga lebih yakni: \"Anak-anak yang tidak memiliki sesuatu, maka akulah yang akan menanggung dan berinfaq kepadanya.\""},"2017":{"ar":"حَدَّثَنَا عَبْدُ الْأَعْلَى بْنُ وَاصِلٍ حَدَّثَنَا مُحَمَّدُ بْنُ الْقَاسِمِ الْأَسَدِيُّ حَدَّثَنَا الْفَضْلُ بْنُ دَلْهَمٍ حَدَّثَنَا عَوْفٌ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَعَلَّمُوا الْقُرْآنَ وَالْفَرَائِضَ وَعَلِّمُوا النَّاسَ فَإِنِّي مَقْبُوضٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ فِيهِ اضْطِرَابٌ وَرَوَى أَبُو أُسَامَةَ هَذَا الْحَدِيثَ عَنْ عَوْفٍ عَنْ رَجُلٍ عَنْ سُلَيْمَانَ بْنِ جَابِرٍ عَنْ ابْنِ مَسْعُودٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَنَا بِذَلِكَ الْحُسَيْنُ بْنُ حُرَيْثٍ أَخْبَرَنَا أَبُو أُسَامَةَ عَنْ عَوْفٍ بِهَذَا بِمَعْنَاهُ وَمُحَمَّدُ بْنُ الْقَاسِمِ الْأَسَدِيُّ قَدْ ضَعَّفَهُ أَحْمَدُ بْنُ حَنْبَلٍ وَغَيْرُهُ","id":"Telah menceritakan kepada kami ['Abdul A'la bin Washil]; telah menceritakan kepada kami [Muhammad bin Al Qasim Al Asadi]; telah menceritakan kepada kami [Al Fadhl bin Dalham]; telah menceritakan kepada kami ['Auf] dari [Syahr bin Hausyab] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pelajarilah Al Qur`an dan fara`idl dan ajarkanlah kepada manusia karena aku akan meninggal.\" Abu Isa berkata; Dalam hadits ini terdapat Idlthirab. [Abu Usamah] telah meriwayatkan hadits ini dari ['Auf] dari [seorang lelaki] dari [Sulaiman bin Jabir] dari [Ibnu Mas'ud] dari Nabi shallallahu 'alaihi wasallam. [Al Husain bin Huraits] telah menceritakannya pula kepada kami, ia berkata; Telah mengabarkan kepada kami [Abu Usamah] dari ['Auf] dengan hadits yang semakna. Muhammad bin Al Qasim Al Asadi telah didlaifkan oleh Ahmad bin Hanbal dan oleh selainnya."},"2018":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنِي زَكَرِيَّاءُ بْنُ عَدِيٍّ أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ عَمْرٍو عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَجَاءَتْ امْرَأَةُ سَعْدِ بْنِ الرَّبِيعِ بِابْنَتَيْهَا مِنْ سَعْدٍ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ هَاتَانِ ابْنَتَا سَعْدِ بْنِ الرَّبِيعِ قُتِلَ أَبُوهُمَا مَعَكَ يَوْمَ أُحُدٍ شَهِيدًا وَإِنَّ عَمَّهُمَا أَخَذَ مَالَهُمَا فَلَمْ يَدَعْ لَهُمَا مَالًا وَلَا تُنْكَحَانِ إِلَّا وَلَهُمَا مَالٌ قَالَ يَقْضِي اللَّهُ فِي ذَلِكَ فَنَزَلَتْ آيَةُ الْمِيرَاثِ فَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى عَمِّهِمَا فَقَالَ أَعْطِ ابْنَتَيْ سَعْدٍ الثُّلُثَيْنِ وَأَعْطِ أُمَّهُمَا الثُّمُنَ وَمَا بَقِيَ فَهُوَ لَكَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ وَقَدْ رَوَاهُ شَرِيكٌ أَيْضًا عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ","id":"Telah menceritakan kepada kami ['Abd bin Humaid]; telah menceritakan kepadaku [Zakariya bin 'Adi]; telah mengabarkan kepada kami ['Ubaidullah bin 'Amr] dari ['Abdullah bin Muhammad bin 'Aqil] dari [Jabir bin 'Abdullah] dia berkata; Istri Sa'ad bin Rabi' datang kepada Nabi Shallallaahu 'Alaihi wa sallam beserta kedua putrinya, dia berkata, \"Wahai Rasulullah, ini adalah kedua putrinya Sa'ad bin Rabi' yang telah syahid pada perang Uhud bersamamu dan sesungguhnya pamannya mengambil seluruh hartanya dan tidak menyisakan sedikitpun untuk keduanya dan tentunya keduanya tidak dapat dinikahkan kecuali jika memiliki uang.\" Maka beliau menjawab: \"Semoga Allah memutuskan dalam perkara ini.\" Setelah itu, turunlah ayat waris, lalu Rasulullah shallallahu 'alaihi wasallam mengutus seseorang kepada paman keduanya dengan perintah: \"Berikanlah kepada kedua putri Sa'ad dua pertiga harta, dan berilah ibu mereka seperdelapan, lalu harta yang tersisa menjadi milikmu.\" Berkata Abu Isa: Ini merupakan hadits hasan Shahih tidak kami ketahui kecuali dari haditsnya Abdulah bin Muhammad bin 'Aqil dan [Syarik] juga telah meriwayatkannya dari [Abdulah bin Muhammad bin 'Aqil]."},"2019":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَرَفَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ سُفْيَانَ الثَّوْرِيِّ عَنْ أَبِي قَيْسٍ الْأَوْدِيِّ عَنْ هُزَيْلِ بْنِ شُرَحْبِيلَ قَالَجَاءَ رَجُلٌ إِلَى أَبِي مُوسَى وَسَلْمَانَ بْنِ رَبِيعَةَ فَسَأَلَهُمَا عَنْ الِابْنَةِ وَابْنَةِ الِابْنِ وَأُخْتٍ لِأَبٍ وَأُمٍّ فَقَالَ لِلِابْنَةِ النِّصْفُ وَلِلْأُخْتِ مِنْ الْأَبِ وَالْأُمِّ مَا بَقِيَ وَقَالَا لَهُ انْطَلِقْ إِلَى عَبْدِ اللَّهِ فَاسْأَلْهُ فَإِنَّهُ سَيُتَابِعُنَا فَأَتَى عَبْدَ اللَّهِ فَذَكَرَ ذَلِكَ لَهُ وَأَخْبَرَهُ بِمَا قَالَا قَالَ عَبْدُ اللَّهِ قَدْ ضَلَلْتُ إِذًا وَمَا أَنَا مِنْ الْمُهْتَدِينَ وَلَكِنْ أَقْضِي فِيهِمَا كَمَا قَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلِابْنَةِ النِّصْفُ وَلِابْنَةِ الِابْنِ السُّدُسُ تَكْمِلَةَ الثُّلُثَيْنِ وَلِلْأُخْتِ مَا بَقِيَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَأَبُو قَيْسٍ الْأَوْدِيُّ اسْمُهُ عَبْدُ الرَّحْمَنِ بْنُ ثَرْوَانَ الْكُوفِيُّ وَقَدْ رَوَاهُ شُعْبَةُ عَنْ أَبِي قَيْسٍ","id":"Telah menceritakan kepada kami [Al Hasan bin 'Arafah]; telah menceritakan kepada kami [Yazid bin Harun] dari [Sufyan Ats Tsauri] dari [Abu Qais Al Audi] dari [Huzail bin Syurahbil] dia berkata; Seorang laki-laki mendatangi Abu Musa dan Salman bin Rabi'ah dan bertanya kepada keduanya mengenai bagian anak perempuan dan cucu perempuan dari anak laki-laki saudara perempuan dari bapak dan dari ibu. Maka ia pun menjawab, \"Untuk anak perempuan adalah setengah. Untuk saudara perempuan dari jalur bapak dan ibu adalah apa yang tersisa.\" Setelah itu, keduanya pun berkata pada laki-laki itu, \"Pergilah kamu untuk menemui Abdullah dan bertanyalah padanya, sebab dia akan mengikuti kami.\" Lalu laki-laki itu pun pergi menemui [Abdullah] dan menuturkan hal itu padanya dan mengabarkan apa telah dikatakan keduanya. Maka Abdullah berkata, \"Sungguh, kalau begitu aku telah tersesat dan bukanlah aku termasuk ke dalam orang-orang yang mendapatkan hidayah. Namun, aku akan memutuskan pada keduanya sebagaimana yang telah ditetapkan oleh Rasulullah shallallahu 'alaihi wasallam, yaitu; Untuk anak perempuan setengah, sedangkan untuk cucu perempuan dari anak laki-laki adalah seperenam untuk menyempurnakan dua pertiga. Dan untuk saudara perempuan adalah sisa.\" Abu Isa berkata; Ini adalah hadits Hadits Hasan Shahih. Abu Qais Al Audi namanya adalah Abdurrahman bin Tsarwan Al Kufi. Dan [Syu'bah] telah meriwayatkannya dari [Abu Qais]."},"2020":{"ar":"حَدَّثَنَا بُنْدَارٌ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ الْحَارِثِ عَنْ عَلِيٍّ أَنَّهُ قَالَإِنَّكُمْ تَقْرَءُونَ هَذِهِ الْآيَةَ{ مِنْ بَعْدِ وَصِيَّةٍ تُوصُونَ بِهَا أَوْ دَيْنٍ }وَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى بِالدَّيْنِ قَبْلَ الْوَصِيَّةِ وَإِنَّ أَعْيَانَ بَنِي الْأُمِّ يَتَوَارَثُونَ دُونَ بَنِي الْعَلَّاتِ الرَّجُلُ يَرِثُ أَخَاهُ لِأَبِيهِ وَأُمِّهِ دُونَ أَخِيهِ لِأَبِيهِحَدَّثَنَا بُنْدَارٌ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا زَكَرِيَّا بْنُ أَبِي زَائِدَةَ عَنْ أَبِي إِسْحَقَ عَنْ الْحَارِثِ عَنْ عَلِيٍّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ","id":"Telah menceritakan kepada kami [Bundar]; telah menceritakan kepada kami [Yazid bin Harun]; telah mengabarkan kepada kami [Sufyan] dari [Abu Ishaq] dari [Al Harits] dari ['Ali] bahwasanya dia berkata; Sesungguhnya kalian telah sering membaca ayat ini, \"MIM BA'DI WASHIYYATIN TUUSHUUNA BIHAA AUW DA`IN.\" setelah (dipenuhi) wasiat yang mereka buat atau (dan setelah dbayar) utangnya) (QS. An Nisaa`: 12) Dan sesungguhnya Rasulullah shallallahu 'alaihi wasallam lebih dahulu mengedepankan pembayaran hutang sebelum wasiat. Sesungguhnya saudara-saudara kandung saling mewarisi lain halnya dengan saudara-saudara yang tidak sekandung. Seorang laki-laki mewarisi saudaranya sebapak dan seibuknya, namun saudaranya sebapak tidak demikian. Telah menceritakan kepada kami [Bundar]; telah menceritakan kepada kami [Yazid bin Harun]; telah mengabarkan kepada kami [Zakariya bin Abu Zaidah] dari [Abu Ishaq] dari [Al Harits] dari ['Ali] dari Nabi shallallahu 'alaihi wasallam sepertinya."},"2021":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا أَبُو إِسْحَقَ عَنْ الْحَارِثِ عَنْ عَلِيٍّ قَالَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ أَعْيَانَ بَنِي الْأُمِّ يَتَوَارَثُونَ دُونَ بَنِي الْعَلَّاتِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ أَبِي إِسْحَقَ عَنْ الْحَارِثِ عَنْ عَلِيٍّ وَقَدْ تَكَلَّمَ بَعْضُ أَهْلِ الْعِلْمِ فِي الْحَارِثِ وَالْعَمَلُ عَلَى هَذَا الْحَدِيثِ عِنْدَ عَامَّةِ أَهْلِ الْعِلْمِ","id":"Telah menceritakan kepada kami [Ibnu Abu 'Umar]; telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Abu Ishaq] dari [Al Harits] dari ['Ali] dia berkata; Rasulullah shallallahu 'alaihi wasallam memutuskan: \"Sesungguhnya anak-anak sekandung ibu adalah saling mewarisi, namun tidak demikian dengan anak-anak yang sebapak.\" Abu Isa berkata; Hadits ini tidak kami ketahui kecuali dari haditsnya Abu Ishaq dari Al Harits dari Ali. Sebagian Ahlul Ilmi telah memberikan komentar terhadap Al Harits. Dan menurut mayoritas ulama hadits ini boleh diamalkan."},"2022":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ سَعْدٍ أَخْبَرَنَا عَمْرُو بْنُ أَبِي قَيْسٍ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَجَاءَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعُودُنِي وَأَنَا مَرِيضٌ فِي بَنِي سَلَمَةَ فَقُلْتُ يَا نَبِيَّ اللَّهِ كَيْفَ أَقْسِمُ مَالِي بَيْنَ وَلَدِي فَلَمْ يَرُدَّ عَلَيَّ شَيْئًا فَنَزَلَتْ{ يُوصِيكُمُ اللَّهُ فِي أَوْلَادِكُمْ لِلذَّكَرِ مِثْلُ حَظِّ الْأُنْثَيَيْنِ }الْآيَةَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَاهُ شُعْبَةُ وَابْنُ عُيَيْنَةَ وَغَيْرُهُ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرٍ","id":"Telah menceritakan kepada kami ['Abd bin Humaid]; telah menceritakan kepada kami ['Abdurrahman bin Sa'd]; telah mengabarkan kepada kami ['Amr bin Abu Qais] dari [Muhammad bin Al Munkadir] dari [Jabir bin 'Abdullah] dia berkata; Rasulullah shallallahu 'alaihi wasallam pernah menjengukku sementara saatu itu aku sedang menderita sakit di Bani Salamah. Kemudian aku pun berkata, \"Wahai Nabiyullah, bagaimanakah aku membagi hartaku di antara anak-anakku.\" Namun beliau tidak memberikan jawaban apa-apa, maka turunlah ayat, \"Sesungguhnya Allah berwasiat kepada kalian mengenai (pembagian hartamu) terhadap anak-anakmu. Yaitu untuk bagian anak laki-laki sama dengan dua bagian anak perempuan.\" Abu Isa berkata; Hadits ini adalah hadits hasan shahih. [Syu'bah] dan [Ibnu 'Uyainah] serta yang lain telah meriwayatkannya dari [Muhammad bin Al Munkadir] dari [Jabir]."},"2023":{"ar":"حَدَّثَنَا الْفَضْلُ بْنُ الصَّبَّاحِ الْبَغْدَادِيُّ أَخْبَرَنَا ابْنُ عُيَيْنَةَ أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُنْكَدِرِ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُمَرِضْتُ فَأَتَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعُودُنِي فَوَجَدَنِي قَدْ أُغْمِيَ عَلَيَّ فَأَتَى وَمَعَهُ أَبُو بَكْرٍ وَعُمَرُ وَهُمَا مَاشِيَانِ فَتَوَضَّأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَبَّ عَلَيَّ مِنْ وَضُوئِهِ فَأَفَقْتُ فَقُلْتُ يَا رَسُولَ اللَّهِ كَيْفَ أَقْضِي فِي مَالِي أَوْ كَيْفَ أَصْنَعُ فِي مَالِي فَلَمْ يُجِبْنِي شَيْئًا وَكَانَ لَهُ تِسْعُ أَخَوَاتٍ حَتَّى نَزَلَتْ آيَةُ الْمِيرَاثِ{ يَسْتَفْتُونَكَ قُلْ اللَّهُ يُفْتِيكُمْ فِي الْكَلَالَةِ }الْآيَةَ قَالَ جَابِرٌ فِيَّ نَزَلَتْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Al Fadhl bin Ash Shabbah Al Baghdadi]; telah mengabarkan kepada kami [Ibnu 'Uyainah]; telah mengabarkan kepada kami [Muhammad bin Al Munkadir] dia mendengar [Jabir bin 'Abdullah] berkata; Aku pernah menderita sakitt, kemudian Rasulullah shallallahu 'alaihi wasallam menjengukku, dan belau mendapatiku dalam keadaan pingsan. Beliau datang bersama Abu Bakar dan Utsman, keduanya berjalan, kemudian Rasulullah shallallahu 'alaihi wasallam berjalan lalu memercikkan air wudlunya padaku dan aku pun tersadar. Aku bertanya, \"Wahai Rasulullah, bagaimanakah aku harus memberi putusan terkait dengan hartaku? Atau apakah yang harus aku perbuat terhadap hartaku?\" Namun beliau belum menjawab pertanyaanku. Ia memiliki sembilan saudara perempuan, hingga turunlah ayat Mirats.\"Mereka meminta fatwa kepadamu, katakanlah; Allah yang memberi fatwa pada kalian dalam permasalahan Al Kalalah.\" Jabir berkata; Terkait dengan masalahku ayat itu turun. Abu Isa berkata; Ini adalah hadits hasan shahih. "},"2024":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ أَخْبَرَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا ابْنُ طَاوُوسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَلْحِقُوا الْفَرَائِضَ بِأَهْلِهَا فَمَا بَقِيَ فَهُوَ لِأَوْلَى رَجُلٍ ذَكَرٍحَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ ابْنِ طَاوُوسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ وَقَدْ رَوَى بَعْضُهُمْ عَنْ ابْنِ طَاوُوسٍ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْسَلًا","id":"Telah menceritakan kepada kami ['Abdullah bin 'Abdurrahman]; telah mengabarkan kepada kami [Muslim bin Ibrahim]; telah menceritakan kepada kami [Wuhaib]; telah menceritakan kepada kami [Ibnu Thawus] dari [bapaknya] dari [Ibnu 'Abbas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Serahkanlah urusan Al Fara`idh kepada ahlinya. Sedangkan apa yang tersisa maka itu untuk laki-laki.\" Telah menceritakan kepada kami [Abdu bin Humaid] Telah mengabarkan kepada kami [Abdurrazzaq] dari [Ma'mar] dari [Ibnu Thawus] dari [bapaknya] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam secara mursal."},"2025":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَرَفَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ هَمَّامِ بْنِ يَحْيَى عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَجَاءَ رَجُلٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ ابْنِي مَاتَ فَمَا لِي فِي مِيرَاثِهِ قَالَ لَكَ السُّدُسُ فَلَمَّا وَلَّى دَعَاهُ فَقَالَ لَكَ سُدُسٌ آخَرُ فَلَمَّا وَلَّى دَعَاهُ قَالَ إِنَّ السُّدُسَ الْآخَرَ طُعْمَةٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَفِي الْبَاب عَنْ مَعْقِلِ بْنِ يَسَارٍ","id":"Telah menceritakan kepada kami [Al Hasan bin 'Arafah]; telah menceritakan kepada kami [Yazid bin Harun] dari [Hammam bin Yahya] dari [Qatadah] dari [Al Hasan] dari ['Imran bin Hushain] dia berkata; Seorang lelaki datang kepada Nabi shallallaahu 'alaihi wasallam dan berkata, \"Sesungguhnya anakku mati, berapakah bagianku dari harta warisannya?\" beliau pun menjawab: \"Seperenam.\" Tatkala dia pergi membelakangi, beliau bersabda lagi: \"Dan kamu juga mendapatkan seperenam yang lain.\" Dan ketika dia pergi membelakangi, Nabi berkata lagi: \"Sesungguhnya seperenam yang lainnya merupakan rizki tambahan untukmu (karena sedikitnya ashhabul furudl).\" Berkata Abu Isa; Ini adalah hadits Hasan Shahih. Dan hadits semakna juga diriwayatkan dari Ma'qil bin Yasar."},"2026":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا الزُّهْرِيُّ قَالَ مَرَّةً قَالَ قَبِيصَةُ و قَالَ مَرَّةً رَجُلٌ عَنْ قَبِيصَةَ بْنِ ذُؤَيْبٍ قَالَجَاءَتْ الْجَدَّةُ أُمُّ الْأُمِّ وَأُمُّ الْأَبِ إِلَى أَبِي بَكْرٍ فَقَالَتْ إِنَّ ابْنَ ابْنِي أَوْ ابْنَ بِنْتِي مَاتَ وَقَدْ أُخْبِرْتُ أَنَّ لِي فِي كِتَابِ اللَّهِ حَقًّا فَقَالَ أَبُو بَكْرٍ مَا أَجِدُ لَكِ فِي الْكِتَابِ مِنْ حَقٍّ وَمَا سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى لَكِ بِشَيْءٍ وَسَأَسْأَلُ النَّاسَ قَالَ فَسَأَلَ النَّاسَ فَشَهِدَ الْمُغِيرَةُ بْنُ شُعْبَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْطَاهَا السُّدُسَ قَالَ وَمَنْ سَمِعَ ذَلِكَ مَعَكَ قَالَ مُحَمَّدُ بْنُ مَسْلَمَةَ قَالَ فَأَعْطَاهَا السُّدُسَ ثُمَّ جَاءَتْ الْجَدَّةُ الْأُخْرَى الَّتِي تُخَالِفُهَا إِلَى عُمَرَقَالَ سُفْيَانُ وَزَادَنِي فِيهِ مَعْمَرٌ عَنْ الزُّهْرِيِّ وَلَمْ أَحْفَظْهُ عَنْ الزُّهْرِيِّ وَلَكِنْ حَفِظْتُهُ مِنْ مَعْمَرٍ أَنَّ عُمَرَ قَالَ إِنْ اجْتَمَعْتُمَا فَهُوَ لَكُمَا وَأَيَّتُكُمَا انْفَرَدَتْ بِهِ فَهُوَ لَهَا","id":"Telah menceritakan kepada kami [Ibnu Abu 'Umar]; telah menceritakan kepada kami [Sufyan]; telah menceritakan kepada kami [Az Zuhri] dia berkata pada suatu kali; [Qabishah] berkata; dan pada kali yang lain; seorang lelaki dari Qabishah bin Dzu'aib berkata; Seorang nenek yaitu ibu dari ibu dan ibu dari bapak mendatangi [Abu Bakar] seraya berkata, \"Sesungguhnya anaknya putraku atau anaknya putriku telah meninggal dan aku diberitahu bahwa berdasarkan Al Quran aku memiliki bagian dari hartanya.\" lalu Abu Bakar pun berkata, \"Aku tidak mendapati dalam Al Quran bahwa Anda mendapatkan bagian dan akupun tidak mendengar Rasulullah shallallahu 'alaihi wasallam memberikan untukmu bagian. Namun aku akan menanyaakannya kepada orang-orang.\" Kemudian Abu Bakar bertanya kepada para shahabat, lantas [Mughirah bin Syu'bah] bersaksi bahwa Rasulullah Shallallaahu 'Alaihi wasallam telah memberinya seperenam.\" Abu Bakar betanya, \"Siapakah yang mendengarnya bersamamu?\" Mughirah menjawab, \" [Muhammad bin Maslamah].\" Qabishah berkata; Lalu Abu Bakar memberinya seperenam. Kemudian datang nenek yang lain (ibunya bapak) kepada Umar -Sufyan berkata; Ma'mar menambahkannya dari Zuhri, namun aku tidak hafal yang dari Zuhri akan tetapi aku menghafalnya dari Ma'mar; Sesungguhnya Umar berkata, \"Jika kalian berdua berkumpul (yaitu keduanya hidup) maka seperenam itu untuk kalian berdua dan siapa saja diantara kalian yang tersisa (sendiri) maka seperenam itu menjadi miliknya.\""},"2027":{"ar":"حَدَّثَنَا الْأَنْصَارِيُّ حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عُثْمَانَ بْنِ إِسْحَقَ بْنِ خَرَشَةَ عَنْ قَبِيصَةَ بْنِ ذُؤَيْبٍ قَالَجَاءَتْ الْجَدَّةُ إِلَى أَبِي بَكْرٍ تَسْأَلُهُ مِيرَاثَهَا قَالَ فَقَالَ لَهَا مَا لَكِ فِي كِتَابِ اللَّهِ شَيْءٌ وَمَا لَكِ فِي سُنَّةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْءٌ فَارْجِعِي حَتَّى أَسْأَلَ النَّاسَ فَسَأَلَ النَّاسَ فَقَالَ الْمُغِيرَةُ بْنُ شُعْبَةَ حَضَرْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَعْطَاهَا السُّدُسَ فَقَالَ أَبُو بَكْرٍ هَلْ مَعَكَ غَيْرُكَ فَقَامَ مُحَمَّدُ بْنُ مَسْلَمَةَ الْأَنْصَارِيُّ فَقَالَ مِثْلَ مَا قَالَ الْمُغِيرَةُ بْنُ شُعْبَةَ فَأَنْفَذَهُ لَهَا أَبُو بَكْرٍ قَالَ ثُمَّ جَاءَتْ الْجَدَّةُ الْأُخْرَى إِلَى عُمَرَ بْنِ الْخَطَّابِ تَسْأَلُهُ مِيرَاثَهَا فَقَالَ مَا لَكِ فِي كِتَابِ اللَّهِ شَيْءٌ وَلَكِنْ هُوَ ذَاكَ السُّدُسُ فَإِنْ اجْتَمَعْتُمَا فِيهِ فَهُوَ بَيْنَكُمَا وَأَيَّتُكُمَا خَلَتْ بِهِ فَهُوَ لَهَاقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ بُرَيْدَةَ وَهَذَا أَحْسَنُ وَهُوَ أَصَحُّ مِنْ حَدِيثِ ابْنِ عُيَيْنَةَ","id":"Telah menceritakan kepada kami [Al Anshari]; telah menceritakan kepada kami [Ma'n]; telah menceritakan kepada kami [Malik] dari [Ibnu Syihab] dari ['Utsman bin Ishaq bin Kharasyah] dari [Qabishah bin Dzu'aib] dia berkata; Seorang nenek mendatangi Abu Bakar guna bertanya mengenai bagiannya dalam harta warisan. Lalu Abu Bakar pun berkata kepadanya, \"Bagianmu tidak disebutkan di dalam Al Qur`an sedikit pun, dan tidak pula di dalam sunnah Rasulullah shallallahu 'alaihi wasallam. Karena itu, kembalilah hingga aku menanyakannya kepada orang-orang.\" Kemudian berkatalah [Al Mughirah bin Syu'bah], \"Aku pernah menghadiri Rasulullah shallallahu 'alaihi wasallam. Ternyata, beliau memberikannya seperenam.\" Maka Abu Bakar bertanya, \"Apakah ada orang lain selainmu yang turut menyaksikannya?\" Kemudian berdirilah [Muhammad bin Maslamah] dan mengemukakan sebagaimana apa yang dikatakan Al Mughirah bin Syu'bah, sehingga Abu Bakar pun segera menunaikannya. Kemudian seorang nenek lain mendatangi Umar bin Al Khaththab guna menanyakan bagiannya dari harta warisan, lalu Umar pun berkata, \"Tidak ada sedikit pun bagianmu disebutkan di dalam Al Qur`an. Namun bagianmu adalah yang seperenam itu. Jika kamu berdua dalam bagian yang seperenam itu, maka yang seperenam itu dibagi di antara kalian berdua. Akan tetapi, jika salah seorang di antara kalian telah tiada, maka seperenam itu menjadi miliknya.\" Abu Isa berkata; Hadits semakna juga diriwayatkan dari Buraidah. Namun, yang ini yang lebih hasan dan lebih shahih daripada haditsnya Ibnu 'Uyainah."},"2028":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَرَفَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ مُحَمَّدِ بْنِ سَالِمٍ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَفِي الْجَدَّةِ مَعَ ابْنِهَا إِنَّهَا أَوَّلُ جَدَّةٍ أَطْعَمَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُدُسًا مَعَ ابْنِهَا وَابْنُهَا حَيٌّقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ لَا نَعْرِفُهُ مَرْفُوعًا إِلَّا مِنْ هَذَا الْوَجْهِ وَقَدْ وَرَّثَ بَعْضُ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْجَدَّةَ مَعَ ابْنِهَا وَلَمْ يُوَرِّثْهَا بَعْضُهُمْ","id":"Telah menceritakan kepada kami [Al Hasan bin 'Arafah]; telah menceritakan kepada kami [Yazid bin Harun] dari [Muhammad bin Salim] dari [Asy Sya'bi] dari [Masruq] dari ['Abdullah bin Mas'ud], ia berkata mengenai seorang nenek yang masih hidup bersama anak laki-lakiny, \"Dia adalah nenek pertama yang diberi bagian warisan oleh Rasulullah seperenam bersama anaknya sedang anaknya masih hidup.\" Abu Isa berkata; Ini merupakan hadits yang tidak kami ketahui diriwayatkan secara marfu' kecuali dari jalur ini. Dan sebagian para shahabat Nabi Shallallaahu 'alaihi wa sallam telah memberikan bagian warisan untuk nenek bersama anaknya, sedangkan sebagian yang lain tidak memberikannya bagian warisan."},"2029":{"ar":"حَدَّثَنَا بُنْدَارٌ حَدَّثَنَا أَبُو أَحْمَدَ الزُّبَيْرِيُّ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ عَنْ حَكِيمِ بْنِ حَكِيمِ بْنِ عَبَّادِ بْنِ حُنَيْفٍ عَنْ أَبِي أُمَامَةَ بْنِ سَهْلِ بْنِ حُنَيْفٍ قَالَ كَتَبَ عُمَرُ بْنُ الْخَطَّابِ إِلَى أَبِي عُبَيْدَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اللَّهُ وَرَسُولُهُ مَوْلَى مَنْ لَا مَوْلَى لَهُ وَالْخَالُ وَارِثُ مَنْ لَا وَارِثَ لَهُقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عَائِشَةَ وَالْمِقْدَامِ بْنِ مَعْدِي كَرِبَ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Bundar]; telah menceritakan kepada kami [Abu Ahmad Az Zubairi]; telah menceritakan kepada kami [Sufyan] dari ['Abdurrahman bin Al Harits] dari [Hakim bin 'Abbad bin Hunaif] dari [Abu Umamah bin Sahl bin Hunaif] dia berkata; [Umar bin Khattab] pernah menulis kepada Abu Ubaidah yang berbunyi; Sesungguhnya Rasulullah shallallaahu 'alaihi wasallam bersabda: \"Allah dan Rasul-Nya merupakan wali bagi yang tidak memiliki wali, dan bibi dari ibu mewarisi anak yang tidak memiliki ahli waris.\" Berkata Abu Isa: hadits semakna juga diriwayatkan dari dari 'Aisyah dan Miqdam bin Ma'di karib. Ini merupakan hadits hasan shahih."},"2030":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ عَمْرِو بْنِ مُسْلِمٍ عَنْ طَاوُوسٍ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْخَالُ وَارِثُ مَنْ لَا وَارِثَ لَهُوَهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَقَدْ أَرْسَلَهُ بَعْضُهُمْ وَلَمْ يَذْكُرْ فِيهِ عَنْ عَائِشَةَ وَاخْتَلَفَ فِيهِ أَصْحَابُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَرَّثَ بَعْضُهُمْ الْخَالَ وَالْخَالَةَ وَالْعَمَّةَ وَإِلَى هَذَا الْحَدِيثِ ذَهَبَ أَكْثَرُ أَهْلِ الْعِلْمِ فِي تَوْرِيثِ ذَوِي الْأَرْحَامِ وَأَمَّا زَيْدُ بْنُ ثَابِتٍ فَلَمْ يُوَرِّثْهُمْ وَجَعَلَ الْمِيرَاثَ فِي بَيْتِ الْمَالِ","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur]; telah mengabarkan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] dari ['Amr bin Muslim] dari [Thawus] dari ['Aisyah] dia berkata, \"Bibi dari ibu mewarisi anak yang tidak memiliki ahli waris.\" Dan ini merupakan hadits Hasan Gharib, sebagian mereka memursalkan hadits ini dengan tidak menyebutkannya dari 'Aisyah. Para shahabat Nabi berselisih pendapat dalam hal ini, maka sebagian mereka memberikan warisan kepada paman dari ibu, bibi dari ibu dan bibi dari bapak, berdasarkan hadits ini para ulama berpendapat memberikan warisan kepada dzawul arham. Adapun Zaid bin Tsabit tidak memberikan warisan kepada mereka dan menyerahkan hartanya ke baitul mal."},"2031":{"ar":"حَدَّثَنَا بُنْدَارٌ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا سُفْيَانُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَصْبِهَانِيِّ عَنْ مُجَاهِدٍ وَهُوَ ابْنُ وَرْدَانَ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ مَوْلًى لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَعَ مِنْ عِذْقِ نَخْلَةٍ فَمَاتَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْظُرُوا هَلْ لَهُ مِنْ وَارِثٍ قَالُوا لَا قَالَ فَادْفَعُوهُ إِلَى بَعْضِ أَهْلِ الْقَرْيَةِوَهَذَا حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Bundar]; telah menceritakan kepada kami [Yazid bin Harun]; telah mengabarkan kepada kami [Sufyan] dari ['Abdurrahman bin Al Ashbihani] dari [Mujahid bin Wardan] dari ['Urwah] dari ['Aisyah] bahwasanya seorang budak Nabi Shallallaahu 'Alaihi wa Sallam jatuh dari pohon kurma lalu meninggal. Lantas Nabi Shallallaahu 'Alaihi wa Sallam bersabda: \"Caritahulah, apakah dia memiliki ahli waris.\" Para sahabat pun berkata, \"Dia tidak memiliki.\" Nabi Shallallaahu 'Alaihi wa Sallam bersabda: \"Berikanlah hartanya kepada sebagian penduduk desa.\" Ini merupakan hadits hasan."},"2032":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عَوْسَجَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ رَجُلًا مَاتَ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ يَدَعْ وَارِثًا إِلَّا عَبْدًا هُوَ أَعْتَقَهُ فَأَعْطَاهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِيرَاثَهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ وَالْعَمَلُ عِنْدَ أَهْلِ الْعِلْمِ فِي هَذَا الْبَابِ إِذَا مَاتَ الرَّجُلُ وَلَمْ يَتْرُكْ عَصَبَةً أَنَّ مِيرَاثَهُ يُجْعَلُ فِي بَيْتِ مَالِ الْمُسْلِمِينَ","id":"Telah menceritakan kepada kami [Ibnu Abu 'Umar]; telah menceritakan kepada kami [Sufyan] dari ['Amr bin Dinar] dari ['Ausajah] dari [Ibnu 'Abbas] bahwasanya seorang lelaki meninggal pada zaman Nabi shallallahu 'alaihi wasallam dan dia tidak meninggalkan seorangpun ahli waris kecuali seorang hamba yang telah dia merdekakan, lalu Nabi Shallallaahu 'alaihi wa sallam memberinya (hambanya) harta warisannya. Abu Isa berkata; Ini adalah hadits hasan dan diamalkan oleh para ulama. Dalam bab ini, bahwa jika seorang lelaki meninggal dan tidak memiliki 'Ashabah, maka warisannya diberikan kepada baitul mal."},"2033":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عَبْدِ الرَّحْمَنِ الْمَخْزُومِيُّ وَغَيْرُ وَاحِدٍ قَالُوا حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ ح و حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا هُشَيْمٌ عَنْ الزُّهْرِيِّ عَنْ عَلِيِّ بْنِ حُسَيْنٍ عَنْ عَمْرِو بْنِ عُثْمَانَ عَنْ أُسَامَةَ بْنِ زَيْدٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَرِثُ الْمُسْلِمُ الْكَافِرَ وَلَا الْكَافِرُ الْمُسْلِمَحَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا الزُّهْرِيُّ نَحْوَهُ قَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ جَابِرٍ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ هَكَذَا رَوَاهُ مَعْمَرٌ وَغَيْرُ وَاحِدٍ عَنْ الزُّهْرِيِّ نَحْوَ هَذَا وَرَوَى مَالِكٌ عَنْ الزُّهْرِيِّ عَنْ عَلِيِّ بْنِ حُسَيْنٍ عَنْ عُمَرَ بْنِ عُثْمَانَ عَنْ أُسَامَةَ بْنِ زَيْدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ وَحَدِيثُ مَالِكٍ وَهْمٌ وَهِمَ فِيهِ مَالِكٌ وَقَدْ رَوَاهُ بَعْضُهُمْ عَنْ مَالِكٍ فَقَالَ عَنْ عَمْرِو بْنِ عُثْمَانَ وَأَكْثَرُ أَصْحَابِ مَالِكٍ قَالُوا عَنْ مَالِكٍ عَنْ عُمَرَ بْنِ عُثْمَانَ وَعَمْرُو بْنُ عُثْمَانَ بْنِ عَفَّانَ هُوَ مَشْهُورٌ مِنْ وَلَدِ عُثْمَانَ وَلَا يُعْرَفُ عُمَرُ بْنُ عُثْمَانَ وَالْعَمَلُ عَلَى هَذَا الْحَدِيثِ عِنْدَ أَهْلِ الْعِلْمِ وَاخْتَلَفَ بَعْضُ أَهْلِ الْعِلْمِ فِي مِيرَاثِ الْمُرْتَدِّ فَجَعَلَ أَكْثَرُ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَغَيْرِهِمْ الْمَالَ لِوَرَثَتِهِ مِنْ الْمُسْلِمِينَ و قَالَ بَعْضُهُمْ لَا يَرِثُهُ وَرَثَتُهُ مِنْ الْمُسْلِمِينَ وَاحْتَجُّوا بِحَدِيثِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَرِثُ الْمُسْلِمُ الْكَافِرَ وَهُوَ قَوْلُ الشَّافِعِيِّ","id":"Telah menceritakan kepada kami [Sa'id bin 'Abdurrahman Al Makhzumi] dan lebih dari satu orang, mereka berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] -Dalam riwayat lain- Dan telah menceritakan kepada kami ['Ali bin Hujr]; telah mengabarkan kepada kami [Husyaim] dari [Az Zuhri] dari ['Ali bin Husain] dari ['Amr bin 'Utsman] dari [Usamah bin Zaid] bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang Muslim tidak boleh mewarisi seorang yang kafir, dan orang kafir juga tidak boleh mewarisi orang Mukmin.\" Telah menceritakan kepada kami [Ibnu Abu 'Umar]; telah menceritakan kepada kami [Sufyan]; telah menceritakan kepada kami [Az Zuhri] dengan hadits semisalnya. Abu Isa berkata; Hadits semakna juga diriwayatkan dari Jabir dan Abdullah bin Amr. Dan hadits ini adalah Hasan Shahih. Seperti ini pula yang diriwayatkan oleh [Ma'mar] dan lebih dari satu orang perawi dari Az Zuhri. Dan [Malik] juga telah meriwatkannya dari [Az Zuhri] dari [Ali bin Husain] dari [Umar bin Utsman] dari [Usamah bin Zaid] dari Nabi shallallahu 'alaihi wasallam, dengan hadits semisalnya. Di dalam haditsnya Malik terdapat Wahm. Hadits ini telah diriwatkan oleh sebagian mereka dari Malik dengan mengatakan; Dari Amr bin Utsman. Sebagian besar sahabat Malik menyebutkannya; Dari Malik dari Amr bin Utsman. Sedangkan Amr bin Utsman lebih dikenal bahwa ia adalah salah satu dari anaknya Utsman dan tidak dikenal dengan nama Umar bin Utsman. Menurut Ahli ilmu, hadits ini diamalkan. Sedangkan sebagian yang lain berselisih pendapat terkait dengan harta warisan dari seorang yang murtad. Karena itu, sebagian bersar sahabat Nabi shallallahu 'alaihi wasallam menjadikan harta tersebut untuk ahli warisnya dari kaum muslim. Dan sebagian mereka berkata, \"Ahli warisnya yang muslim, tidak boleh mewarisi harta warisannya.\" Dan mereka berdalih dengan hadits Nabi shallallahu 'alaihi wasallam, \"Seorang Muslim tidak boleh mewarisi seorang yang kafir.\" Ini adalah pendapat Imam Asy Syafi'i."},"2034":{"ar":"حَدَّثَنَا حُمَيْدُ بْنُ مَسْعَدَةَ حَدَّثَنَا حُصَيْنُ بْنُ نُمَيْرٍ عَنْ ابْنِ أَبِي لَيْلَى عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَتَوَارَثُ أَهْلُ مِلَّتَيْنِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ لَا نَعْرِفُهُ مِنْ حَدِيثِ جَابِرٍ إِلَّا مِنْ حَدِيثِ ابْنِ أَبِي لَيْلَى","id":"Telah menceritakan kepada kami [Humaid bin Mas'adah]; telah menceritakan kepada kami [Hushain bin Numair] dari [Ibnu Abu Laila] dari [Abu Az Zubair] dari [Jabir] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak boleh saling mewarisi dua orang yang berbeda agama.\" Berkata Abu Isa: Ini merupakan hadits yang tidak kami ketahui dari haditsnya jabir kecuali dari haditsnya Ibnu Abi Laila."},"2035":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ عَنْ الزُّهْرِيِّ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْقَاتِلُ لَا يَرِثُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ لَا يَصِحُّ لَا يُعْرَفُ إِلَّا مِنْ هَذَا الْوَجْهِ وَإِسْحَقُ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي فَرْوَةَ قَدْ تَرَكَهُ بَعْضُ أَهْلِ الْحَدِيثِ مِنْهُمْ أَحْمَدُ بْنُ حَنْبَلٍ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَهْلِ الْعِلْمِ أَنَّ الْقَاتِلَ لَا يَرِثُ كَانَ الْقَتْلُ عَمْدًا أَوْ خَطَأً و قَالَ بَعْضُهُمْ إِذَا كَانَ الْقَتْلُ خَطَأً فَإِنَّهُ يَرِثُ وَهُوَ قَوْلُ مَالِكٍ","id":"Telah menceritakan kepada kami [Qutaibah]; telah menceritakan kepada kami [Al Laits] dari [Ishaq bin 'Abdullah] dari [Az Zuhri] dari [Humaid bin 'Abdurrahman] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Orang yang membunuh tidak boleh mewarisi.\" Berkata Abu Isa: Ini merupakan hadits yang tidak shahih, tidak diketahui kecuali melalui jalur ini. Dan Ishaq bin Abdullah bin Abi Farwah telah ditinggalkan oleh sebagian ahli hadits seperti Ahmad bin Hambal, namun hadits ini diamalkan oleh para ulama bahwa orang yang membunuh tidak boleh mewarisi baik itu pembunuhan yang disengaja atau tidak. Adapun sebagian ulama berpendapat bahwa, jika pembunuhannya tidak disengaja maka dia boleh mewarisi, dan ini merupakan pendapatnya Malik."},"2036":{"ar":"حَدَّثَنَا قُتَيْبَةُ وَأَحْمَدُ بْنُ مَنِيعٍ وَغَيْرُ وَاحِدٍ قَالُوا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ قَالَ قَالَ عُمَرُ الدِّيَةُ عَلَى الْعَاقِلَةِ وَلَا تَرِثُ الْمَرْأَةُ مِنْ دِيَةِ زَوْجِهَا شَيْئًا فَأَخْبَرَهُ الضَّحَّاكُ بْنُ سُفْيَانَ الْكِلَابِيُّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتَبَ إِلَيْهِ أَنْ وَرِّثْ امْرَأَةَ أَشْيَمَ الضِّبَابِيِّ مِنْ دِيَةِ زَوْجِهَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] dan [Ahmad bin Mani'] dan lebih dari satu orang, mereka berkata; telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dia berkata; Umar berkata, \"Diyat itu dibebankan atas seorang yang berakal. Dan seorang wanita tidaklah mewarisi dari Diyat suaminya barang sedikit pun.\" Maka [Adl Dlahak bin Sufyan Al Kilabi] pun mengabarkan kepadanya bahwasanya Rasulullah shallallahu 'alaihi wasallam pernah menulis kepadanya yang berisikan: \"Isteri Aysyam bin Dlibabi hendaklah mewarisi diyat suaminya.\" Abu Isa berkata; Ini adalah hadits hasan shahih."},"2037":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى فِي جَنِينِ امْرَأَةٍ مِنْ بَنِي لِحْيَانَ سَقَطَ مَيِّتًا بِغُرَّةٍ عَبْدٍ أَوْ أَمَةٍ ثُمَّ إِنَّ الْمَرْأَةَ الَّتِي قُضِيَ عَلَيْهَا بِالْغُرَّةِ تُوُفِّيَتْ فَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ مِيرَاثَهَا لِبَنِيهَا وَزَوْجِهَا وَأَنَّ عَقْلَهَا عَلَى عَصَبَتِهَاقَالَ أَبُو عِيسَى وَرَوَى يُونُسُ هَذَا الْحَدِيثَ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ وَأَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ وَرَوَاهُ مَالِكٌ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ وَمَالِكٌ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْسَلٌ","id":"Telah menceritakan kepada kami [Qutaibah]; telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah] bahwasanya Rasulullah shallallahu 'alaihi wasallam menetapkian Diyat terhadap janin yang keguguran dari seorang wanita Bani Lihyan yakni dengan membebaskan seorang budak wanita. Kemudian wanita yang telah ditetapkan Diyat atasnya tersebut meninggal, maka Rasulullah shallallahu 'alaihi wasallam memutuskan bahwa harta warisannya adalah untuk anak-anak dan suaminya. Sedangkan 'Aqil (sisa) -nya adalah untuk 'Ashabahnya. Abu 'Isa berkata; [Yunus] meriwayatkan hadits ini dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dan [Abu Salamah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam semisalnya. Dan [Malik] meriwayatkannya dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah], dan [Malik] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dari Nabi shallallahu 'alaihi wasallam secara mursal."},"2038":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو أُسَامَةَ وَابْنُ نُمَيْرٍ وَوَكِيعٌ عَنْ عَبْدِ الْعَزِيزِ بْنِ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ عَنْ عَبْدِ اللَّهِ بْنِ مَوْهِبٍ وَقَالَ بَعْضُهُمْ عَنْ عَبْدِ اللَّهِ بْنِ وَهْبٍ عَنْ تَمِيمٍ الدَّارِيِّ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا السُّنَّةُ فِي الرَّجُلِ مِنْ أَهْلِ الشِّرْكِ يُسْلِمُ عَلَى يَدَيْ رَجُلٍ مِنْ الْمُسْلِمِينَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ أَوْلَى النَّاسِ بِمَحْيَاهُ وَمَمَاتِهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ عَبْدِ اللَّهِ بْنِ وَهْبٍ وَيُقَالُ ابْنُ مَوْهِبٍ عَنْ تَمِيمٍ الدَّارِيِّ وَقَدْ أَدْخَلَ بَعْضُهُمْ بَيْنَ عَبْدِ اللَّهِ بْنِ وَهْبٍ وَبَيْنَ تَمِيمٍ الدَّارِيِّ قَبِيصَةَ بْنَ ذُؤَيْبٍ وَلَا يَصِحُّ رَوَاهُ يَحْيَى بْنُ حَمْزَةَ عَنْ عَبْدِ الْعَزِيزِ بْنِ عُمَرَ وَزَادَ فِيهِ قَبِيصَةَ بْنَ ذُؤَيْبٍ وَالْعَمَلُ عَلَى هَذَا الْحَدِيثِ عِنْدَ بَعْضِ أَهْلِ الْعِلْمِ وَهُوَ عِنْدِي لَيْسَ بِمُتَّصِلٍ و قَالَ بَعْضُهُمْ يُجْعَلُ مِيرَاثُهُ فِي بَيْتِ الْمَالِ وَهُوَ قَوْلُ الشَّافِعِيِّ وَاحْتَجَّ بِحَدِيثِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ الْوَلَاءَ لِمَنْ أَعْتَقَ","id":"Telah menceritakan kepada kami [Abu Kuraib]; telah menceritakan kepada kami [Abu Usamah] dan [Ibnu Numair] dan [Waki'] dari ['Abdul 'Aziz bin 'Umar bin 'Abdul 'Aziz] dari ['Abdullah bin Mauhib] dan berkata sebagian mereka dari 'Abdullah bin Wahb dari [Tamim Ad Dari] dia berkata; aku bertanya kepada Rasulullah shallallahu 'alaihi wasallam, \"Bagaimanakah sunnahnya, bila seorang musyrik menyerahkan dirinya di tangan seorang Muslim?\" Maka Rasulullah shallallahu 'alaihi wasallam menjawab: \"Dialah yang lebih berhak akan keberlangsungan hidup dan matinya.\" Abu Isa berkata; Ini adalah hadits yang tidak kami ketahui kecuali dari haditsnya Abdullah bin Wahb -ia dikenal juga dengan Ibnu Maihab- dari Tamim Ad Dari. Sebagian mereka memasukkan Qabishah bin Dzu`aib di antara Abdullah bin Wahb dan Tamim Ad Dari, namun hal itu tidaklah shahih. [Yahya bin Hamzah] telah meriwayatkannya dari [Abdul Aziz bin Umar] dan di dalamnya ia menambahkan; [Qabishah bin Dzu`aib]. Kemudian menurut sebagian Ahli ilmu, hadits ini diamalkan. Namun, menurutku, sanad hadits ini tidaklah muttashil. Dan menurut sebagian yang lain, bahwa warisannya diserahkan kepada Baitul Mal, ini adalah pendapatnya Imam Asy Syafi'i, dan ia berdalih dengan Hadits Nabi shallallahu 'alaihi wasallam: \"Bahwa Al Wala`(perwalian) adalah bagi yang membebaskan.\""},"2039":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَيُّمَا رَجُلٍ عَاهَرَ بِحُرَّةٍ أَوْ أَمَةٍ فَالْوَلَدُ وَلَدُ زِنَا لَا يَرِثُ وَلَا يُورَثُقَالَ أَبُو عِيسَى وَقَدْ رَوَى غَيْرُ ابْنِ لَهِيعَةَ هَذَا الْحَدِيثَ عَنْ عَمْرِو بْنِ شُعَيْبٍ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَهْلِ الْعِلْمِ أَنَّ وَلَدَ الزِّنَا لَا يَرِثُ مِنْ أَبِيهِ","id":"Telah menceritakan kepada kami [Qutaibah]; telah menceritakan kepada kami [Ibnu Lahi'ah] dari ['Amr bin Syu'aib] dari [bapaknya] dari [kakeknya] bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa saja lelaki yang berzina dengan wanita merdeka maupun budak wanita, maka anaknya ialah anak hasil zina. Dia tidak mewarisi juga tidak diwarisi.\" Berkata Abu Isa: Selain Ibnu Lahi'ah hadsits ini telah diriwayatkan pula dari Amr bin Syu'aib. Hadits ini diamalkan oleh para ulama bahwa anak hasil zina tidak boleh mewarisi dari bapaknya."},"2040":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَرِثُ الْوَلَاءَ مَنْ يَرِثُ الْمَالَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ لَيْسَ إِسْنَادُهُ بِالْقَوِيِّ","id":"Telah menceritakan kepada kami [Qutaibah]; telah menceritakan kepada kami [Ibnu Lahi'ah] dari ['Amr bin Syu'aib] dari [bapaknya] dari [kakeknya] bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seluruh 'Ashabah yang mewarisi harta dia berhak mewarisi harta budak yang dimerdekakan oleh si mayyit.\" Abu Isa berkata; Ini merupakan hadits yang sanadnya tidak kuat."},"2041":{"ar":"حَدَّثَنَا هَارُونُ أَبُو مُوسَى الْمُسْتَمْلِيُّ الْبَغْدَادِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ حَرْبٍ حَدَّثَنَا عُمَرُ بْنُ رُؤْبَةَ التَّغْلَبِيُّ عَنْ عَبْدِ الْوَاحِدِ بْنِ عَبْدِ اللَّهِ بْنِ بُسْرٍ النَّصْرِيِّ عَنْ وَاثِلَةَ بْنِ الْأَسْقَعِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَرْأَةُ تَحُوزُ ثَلَاثَةَ مَوَارِيثَ عَتِيقَهَا وَلَقِيطَهَا وَوَلَدَهَا الَّذِي لَاعَنَتْ عَلَيْهِهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا يُعْرَفُ إِلَّا مِنْ هَذَا الْوَجْهِ مِنْ حَدِيثِ مُحَمَّدِ بْنِ حَرْبٍ","id":"Telah menceritakan kepada kami [Harun Abu Musa Al Mustamli Al Baghdadi]; telah menceritakan kepada kami [Muhammad bin Harb]; telah menceritakan kepada kami ['Umar bin Ru'yah At Taghlibi] dari ['Abdul Wahid bin 'Abdullah bin Busr An Nashri] dari [Watsilah bin Al Asqa'] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang wanita dapat mendapatkan tiga warisan: Dari budak yang dimerdekakan, anak yang dia temukan, dan anaknya yang mana dia telah melakukan mula'anah dengan suaminya.\" Ini merupakan hadits Hasan Gharib tidak kami ketahui kecuali dari jalur ini yaitu dari haditsnya Muhammad bin Harb."},"2042":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عَامِرِ بْنِ سَعْدِ بْنِ أَبِي وَقَّاصٍ عَنْ أَبِيهِ قَالَمَرِضْتُ عَامَ الْفَتْحِ مَرَضًا أَشْفَيْتُ مِنْهُ عَلَى الْمَوْتِ فَأَتَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعُودُنِي فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّ لِي مَالًا كَثِيرًا وَلَيْسَ يَرِثُنِي إِلَّا ابْنَتِي أَفَأُوصِي بِمَالِي كُلِّهِ قَالَ لَا قُلْتُ فَثُلُثَيْ مَالِي قَالَ لَا قُلْتُ فَالشَّطْرُ قَالَ لَا قُلْتُ فَالثُّلُثُ قَالَ الثُّلُثُ وَالثُّلُثُ كَثِيرٌ إِنَّكَ إِنْ تَدَعْ وَرَثَتَكَ أَغْنِيَاءَ خَيْرٌ مِنْ أَنْ تَدَعَهُمْ عَالَةً يَتَكَفَّفُونَ النَّاسَ وَإِنَّكَ لَنْ تُنْفِقَ نَفَقَةً إِلَّا أُجِرْتَ فِيهَا حَتَّى اللُّقْمَةَ تَرْفَعُهَا إِلَى فِي امْرَأَتِكَ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ أُخَلَّفُ عَنْ هِجْرَتِي قَالَ إِنَّكَ لَنْ تُخَلَّفَ بَعْدِي فَتَعْمَلَ عَمَلًا تُرِيدُ بِهِ وَجْهَ اللَّهِ إِلَّا ازْدَدْتَ بِهِ رِفْعَةً وَدَرَجَةً وَلَعَلَّكَ أَنْ تُخَلَّفَ حَتَّى يَنْتَفِعَ بِكَ أَقْوَامٌ وَيُضَرَّ بِكَ آخَرُونَ اللَّهُمَّ أَمْضِ لِأَصْحَابِي هِجْرَتَهُمْ وَلَا تَرُدَّهُمْ عَلَى أَعْقَابِهِمْ لَكِنْ الْبَائِسُ سَعْدُ ابْنُ خَوْلَةَ يَرْثِي لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ مَاتَ بِمَكَّةَقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ ابْنِ عَبَّاسٍ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ مِنْ غَيْرِ وَجْهٍ عَنْ سَعْدِ بْنِ أَبِي وَقَّاصٍ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَهْلِ الْعِلْمِ أَنَّهُ لَيْسَ لِلرَّجُلِ أَنْ يُوصِيَ بِأَكْثَرَ مِنْ الثُّلُثِ وَقَدْ اسْتَحَبَّ بَعْضُ أَهْلِ الْعِلْمِ أَنْ يَنْقُصَ مِنْ الثُّلُثِ لِقَوْلِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالثُّلُثُ كَثِيرٌ","id":"Telah menceritakan kepada kami [Ibnu Abu 'Umar]; telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dari ['Amir bin Sa'd bin Abu Waqqash] dari [bapaknya] dia berkata; Pada tahun Fathu Makkah, aku tertimpa sakit dan aku merasa akan mengalami kematian. Kemudian Rasulullah shallallahu 'alaihi wasallam pun menjengukku, maka aku pun berkata pada beliau, \"Wahai Rasulullah, sesungguhnya aku memiliki harta yang banyak, sedangkan tidak ada orang yang akan mewarisiku kecuali anak perempuanku seorang diri. Apakah aku harus berwasiat dengan hartaku seluruhnya?\" beliau menjawab: \"Tidak.\" Aku berkata, \"Atau duapertiga darinya?\" Beliau menjawab: \"Tidak.\" Aku berkata lagi, \"Atau setengahnya?\" beliau menjawab: \"Tidak.\" Aku berkata lagi, \"Kalau begitu, sepertiga darinya?\" Akhirnya beliau bersabda: \"Sepertiga. Namun, sepertiga adalah jumlah yang banyak. Sesungguhnya, bila kamu meninggalkan ahli warismu dalam keadaan berkecukupan adalah lebih baik daripada kamu meninggalkan mereka dalam keadaan fakir dan meminta-minta kepada manusia. Dan tidaklah kamu menginfakkan sesuatu pun, kecuali kamu akan diberi ganjaran pahala, hingga sesuap makanan yang kamu suapkan pada mulut isterimu.\" Lalu aku bertanya, \"Wahai Rasulullah, apakah aku telah ditinggalkan dari hijrahku?\" Beliau menjawab: \"Sesungguhnya, kamu tidak akan ditinggalkan setelahku, sehingga kamu mengerjakan amalan yang dengannya kamu mengharap wajah Allah, sehingga membuat derajatmu (di sisi-Nya) semakin tinggi. Dan semoga sepeninggalmu setelahku nanti, orang-orang dapat mengambil manfaat darimu, dan yang lain mendapat kecelakaan. Ya Allah, terimalah hijrah para sahabatku, dan janganlah Engkau tolak akan kesudahan mereka.\" Akan tetapi Al Ba`is Sa'd bin Khaulah, Rasulullah shallallahu 'alaihi wasallam telah mewarisinya, agar ia dapat meninggal di Makkah. Abu Isa berkata; Hadits semakna juga diriwayatkan dari Ibnu Abbas. Ini adalah hadits Hasan Shahih. Dan hadits ini telah diriwayatkan pula oleh lebih dari satu orang perawi dari Sa'd bin Abu Waqhas. Menurut Ahli imu, hadits ini diamalkan, yakni, seorang laki-laki tidak boleh mewasiatkan lebih dari sepertiga hartanya. Sedangkan sebagian ulama, adalah suatu hal yang Mustahab (sunnah) bila wasiat kurang dari sepertiga, berdasarkan Sabda Rasulullah shallallahu 'alaihi wasallam: \"Dan sepertiga itu, merupakan jumlah yang banyak.\""},"2043":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ حَدَّثَنَا الْأَشْعَثُ بْنُ جَابِرٍ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَبِي هُرَيْرَةَ أَنَّهُ حَدَّثَهُعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الرَّجُلَ لَيَعْمَلُ وَالْمَرْأَةُ بِطَاعَةِ اللَّهِ سِتِّينَ سَنَةً ثُمَّ يَحْضُرُهُمَا الْمَوْتُ فَيُضَارَّانِ فِي الْوَصِيَّةِ فَتَجِبُ لَهُمَا النَّارُ ثُمَّ قَرَأَ عَلَيَّ أَبُو هُرَيْرَةَ{ مِنْ بَعْدِ وَصِيَّةٍ يُوصَى بِهَا أَوْ دَيْنٍ غَيْرَ مُضَارٍّ وَصِيَّةً مِنْ اللَّهِ إِلَى قَوْلِهِ ذَلِكَ الْفَوْزُ الْعَظِيمُ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ وَنَصْرُ بْنُ عَلِيٍّ الَّذِي رَوَى عَنْ الْأَشْعَثِ بْنِ جَابِرٍ هُوَ جَدُّ نَصْرِ بْنِ عَلِيٍّ الْجَهْضَمِيِّ","id":"Telah menceritakan kepada kami [Nashr bin 'Ali Al Jahdhami]; telah menceritakan kepada kami ['Abdush Shamad bin 'Abdul Warits]; telah menceritakan kepada kami [Nashr bin 'Ali]; telah menceritakan kepada kami [Al Asy'ats bin Jabir] dari [Syahr bin Hausyab] dari [Abu Hurairah] bahwasanya dia menceritakan kepadanya dari Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya seorang lelaki dan perempuan bisa jadi beramal ketaatan kepada Allah selama enam puluh tahun, kemudian ketika tiba ajal keduanya melakukan sesuatu yang membahayakan bagi ahli waritsnya, sehingga mengharuskan keduanya masuk ke dalam neraka.\" Kemudian Abu Hurairah membacakan ayat kepadaku: \"MIM BA'DI WASIYYATIY YUUSHAA BIHAA AU DAININ GHAIRA MUDLAARRIW WASIYYATAM MINALLAAH (sesudah dipenuhi wasiat yang dibuat olehnya atau sesudah dibayar hutangnya dengan tidak memberi mudharat kepada ahli waris. (Allah menetapkan yang demikian itu sebagai) syari`at yang benar-benar dari Allah).\" (QS An Nisa': 12) sampai firman Allah, \"DZALIKAL FAUZUL 'ADZIIM (dan itulah kemenangan yang besar).\" (QS An Nisa': 13) Abu Isa berkata; Hadits ini adalah hasan shahih gharib, adapun Nashr bin Ali yang meriwayatkan dari Ats'ats bin Jabir dia adalah kakeknya Nahsr bin Ali Al Jahdlami."},"2044":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا حَقُّ امْرِئٍ مُسْلِمٍ يَبِيتُ لَيْلَتَيْنِ وَلَهُ مَا يُوصِي فِيهِ إِلَّا وَوَصِيَّتُهُ مَكْتُوبَةٌ عِنْدَهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Ibnu Abu 'Umar]; telah menceritakan kepada kami [Sufyan] dari [Ayyub] dari [Nafi'] dari [Ibnu 'Umar] dia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak ada hak bagi seorang muslim untuk bermalam selama dua hari, sementara ia memiliki harta yang harus ia wasiatkan, kecuali wasiatnya itu telah tertulis di sisinya.\" Abu Isa berkata; Ini adalah hadits Hasan Shahih. Dan telah diriwayatkan pula dari [Az Zuhri] dari [Salim] dari [Ibnu 'Umar] dari Nabi shallallahu 'alaihi wasallam dengan hadits semisalnya."},"2045":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا أَبُو قَطَنٍ عَمْرُو بْنُ الْهَيْثَمِ الْبَغْدَادِيُّ حَدَّثَنَا مَالِكُ بْنُ مِغْوَلٍ عَنْ طَلْحَةَ بْنِ مُصَرِّفٍ قَالَ قُلْتُ لِابْنِ أَبِي أَوْفَىأَوْصَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا قُلْتُ كَيْفَ كُتِبَتْ الْوَصِيَّةُ وَكَيْفَ أَمَرَ النَّاسَ قَالَ أَوْصَى بِكِتَابِ اللَّهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ مَالِكِ بْنِ مِغْوَلٍ","id":"Telah menceritakan kepada kami [Ahmad bin Mani']; telah menceritakan kepada kami [Abu Qathan 'Amr bin Al Haitsam Al Baghdadi]; telah menceritakan kepada kami [Malik bin Mighwal] dari [Thalhah bin Musharrif] dia berkata; Aku pernah bertanya kepada [Ibnu Abu Aufa], \"Apakah Rasulullah shallallahu 'alaihi wasallam berwasiat (terkait dengan hartanya)?\" Ia menjawab, \"Tidak.\" Kemudian aku bertanya lagi, \"Lalu, kenapa wasiat diwajibkan. Dan kenapa pula beliau memerintahkan orang-orang untuk menunaikannya?\" Ia menjawab, \"Beliau telah berwasiat dengan kitab Allah.\" Abu Isa berkata; Ini adalah hadits Hasan Shahih Gharib. Kami tidak mengetahuinya kecuali dari haditsnya Malik bin Mighwal."},"2046":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ وَهَنَّادٌ قَالَا حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ حَدَّثَنَا شُرَحْبِيلُ بْنُ مُسْلِمٍ الْخَوْلَانِيُّ عَنْ أَبِي أُمَامَةَ الْبَاهِلِيِّ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي خُطْبَتِهِ عَامَ حَجَّةِ الْوَدَاعِ إِنَّ اللَّهَ قَدْ أَعْطَى لِكُلِّ ذِي حَقٍّ حَقَّهُ فَلَا وَصِيَّةَ لِوَارِثٍ الْوَلَدُ لِلْفِرَاشِ وَلِلْعَاهِرِ الْحَجَرُ وَحِسَابُهُمْ عَلَى اللَّهِ وَمَنْ ادَّعَى إِلَى غَيْرِ أَبِيهِ أَوْ انْتَمَى إِلَى غَيْرِ مَوَالِيهِ فَعَلَيْهِ لَعْنَةُ اللَّهِ التَّابِعَةُ إِلَى يَوْمِ الْقِيَامَةِ لَا تُنْفِقُ امْرَأَةٌ مِنْ بَيْتِ زَوْجِهَا إِلَّا بِإِذْنِ زَوْجِهَا قِيلَ يَا رَسُولَ اللَّهِ وَلَا الطَّعَامَ قَالَ ذَلِكَ أَفْضَلُ أَمْوَالِنَا ثُمَّ قَالَ الْعَارِيَةُ مُؤَدَّاةٌ وَالْمِنْحَةُ مَرْدُودَةٌ وَالدَّيْنُ مَقْضِيٌّ وَالزَّعِيمُ غَارِمٌقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عَمْرِو بْنِ خَارِجَةَ وَأَنَسٍ وَهُوَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ عَنْ أَبِي أُمَامَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ غَيْرِ هَذَا الْوَجْهِ وَرِوَايَةُ إِسْمَعِيلَ بْنِ عَيَّاشٍ عَنْ أَهْلِ الْعِرَاقِ وَأَهْلِ الْحِجَازِ لَيْسَ بِذَلِكَ فِيمَا تَفَرَّدَ بِهِ لِأَنَّهُ رَوَى عَنْهُمْ مَنَاكِيرَ وَرِوَايَتُهُ عَنْ أَهْلِ الشَّامِ أَصَحُّ هَكَذَا قَالَ مُحَمَّدُ بْنُ إِسْمَعِيلَ قَال سَمِعْتُ أَحْمَدَ بْنَ الْحَسَنِ يَقُولُ قَالَ أَحْمَدُ بْنُ حَنْبَلٍ إِسْمَعِيلُ بْنُ عَيَّاشٍ أَصْلَحُ حَدِيثًا مِنْ بَقِيَّةَ وَلِبَقِيَّةَ أَحَادِيثُ مَنَاكِيرُ عَنْ الثِّقَاتِ و سَمِعْت عَبْدَ اللَّهِ بْنَ عَبْدِ الرَّحْمَنِ يَقُولُ سَمِعْتُ زَكَرِيَّا بْنَ عَدِيٍّ يَقُولُ قَالَ أَبُو إِسْحَقَ الْفَزَارِيُّ خُذُوا عَنْ بَقِيَّةَ مَا حَدَّثَ عَنْ الثِّقَاتِ وَلَا تَأْخُذُوا عَنْ إِسْمَعِيلَ بْنِ عَيَّاشٍ مَا حَدَّثَ عَنْ الثِّقَاتِ وَلَا عَنْ غَيْرِ الثِّقَاتِ","id":"Telah menceritakan kepada kami ['Ali bin Hujr] dan [Hannad] mereka berdua berkata; telah menceritakan kepada kami [Isma'il bin 'Ayyasy]; telah menceritakan kepada kami [Syurahbil bin Muslim Al Khaulani] dari [Abu Umamah Al Bahili] dia berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda di dalam khuthbahnya pada saat haji wada': \"Sesungguhnya Allah telah memberikan kepada setiap yang berhak apa yang menjadi haknya. Maka tidak ada wasiat bagi ahli waris. Nasab seorang anak adalah untuk bapaknya. Untuk seorang pezina, maka baginya adalah batu (dirajam) dan adapun hisabnya diserahkan kepada Allah. Dan barangsiapa yang menasabkan dirinya kepada selain bapaknya, atau berwali kepada selain walinya, maka laknat Allah akan tertimpa atasnya hingga datangnya hari kiamat. Seorang isteri tidak boleh menginfakkan harta suaminya, kecuali dengan seizinnya.\" Kemudian ditanyakanlah kepada beliau, \"Wahai Rasulullah, apakah makanan juga tidak boleh?\" Beliau menjawab: \"Makanan adalah harta yang paling utama dari harta yang kita miliki.\" Kemudian beliau bersabda lagi: \"Para wanita yang telanjang akan dihukum. Pemberian akan ditolak, sedangkan hutang akan balas. Dan seorang penjamin akan membayar.\" Abu Isa berkata; Hadits semakna juga diriwayatkan dari Amru bin Kharijah dan Anas. Ini adalah hadits Hasan Shahih. Dan telah diriwayatkan pula dari Umamah dari Nabi shallallahu 'alaihi wasallam selain dari jalur ini. Riwayat Isma'il bin Ayyas dari penduduk Irak. Sedangkan penduduk Hijaz tidaklah seperti itu, terkait dengan hadits yang didalamnya terdapat tafarrud (bersendirinya rawi dalam meriwayatkan hadits), sebab para Munkarul Hadits (para perawi yang riwayatnya munkar) telah meriwayatkan dari mereka. Dan riwayatnya dari penduduk Syam lebih shahih. Seperti inilah yang dikatakan oleh Muhammad bin Isma'il. Ia berkata; Aku mendengar Muhammad bin Isma'il berkata; aku mendengar Ahmad bin Al Hasan berkata; berkata Ahmad bin Hambal; Isma'il bin 'Ayyasy lebih baik haditsnya daripada yang lainnya. Sebab yang lainnya adalah hadits-hadits yang Munkar yang diriwayatkan dari Ats Tsiqqah. Dan saya mendengar Abdullah bin Abdurrahman berkata; aku mendengar Zakariya bin 'Adi berkata; Abu Ishaq Al Fazari berkata, \"Ambillah dari Al Baqiyyah, yakni hadits yang mereka riwayatkan dari Ats Tsiqqaat. Dan janganlah kalian mengambil hadits dari Isma'il bin 'Ayyasy baik yang ia riwayatkan dari Ats Tsiqqaat atau pun dari selain Ats Tsiqqaat."},"2047":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ غَنْمٍ عَنْ عَمْرِو بْنِ خَارِجَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطَبَ عَلَى نَاقَتِهِ وَأَنَا تَحْتَ جِرَانِهَا وَهِيَ تَقْصَعُ بِجِرَّتِهَا وَإِنَّ لُعَابَهَا يَسِيلُ بَيْنَ كَتِفَيَّ فَسَمِعْتُهُ يَقُولُ إِنَّ اللَّهَ أَعْطَى كُلَّ ذِي حَقٍّ حَقَّهُ وَلَا وَصِيَّةَ لِوَارِثٍ وَالْوَلَدُ لِلْفِرَاشِ وَلِلْعَاهِرِ الْحَجَرُ وَمَنْ ادَّعَى إِلَى غَيْرِ أَبِيهِ أَوْ انْتَمَى إِلَى غَيْرِ مَوَالِيهِ رَغْبَةً عَنْهُمْ فَعَلَيْهِ لَعْنَةُ اللَّهِ لَا يَقْبَلُ اللَّهُ مِنْهُ صَرْفًا وَلَا عَدْلًاقَالَ و سَمِعْت أَحْمَدَ بْنَ الْحَسَنِ يَقُولُ قَالَ أَحْمَدُ بْنُ حَنْبَلٍ لَا أُبَالِي بِحَدِيثِ شَهْرِ بْنِ حَوْشَبٍ قَالَ وَسَأَلْتُ مُحَمَّدَ بْنَ إِسْمَعِيلَ عَنْ شَهْرِ بْنِ حَوْشَبٍ فَوَثَّقَهُ وَقَالَ إِنَّمَا يَتَكَلَّمُ فِيهِ ابْنُ عَوْنٍ ثُمَّ رَوَى ابْنُ عَوْنٍ عَنْ هِلَالِ بْنِ أَبِي زَيْنَبَ عَنْ شَهْرِ بْنِ حَوْشَبٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah]; telah menceritakan kepada kami [Abu 'Awanah] dari [Qatadah] dari [Syahr bin Hausyab] dari ['Abdurrahman bin Ghanm] dari ['Amr bin Kharijah] bahwasanya Nabi shallallahu 'alaihi wasallam pernah menyampaikan khuthbah di atas Unta miliknya, sementara aku tetap berada di bawah leher Untanya yang sedang mengalirkan busa liurnya dan bertetesan di atantara kedua pundakku. Maka aku pun mendengar beliau bersabda: \"Sesungguhnya Allah telah memberikan kepada semua yang berhak apa yang menjadi haknya. Karena itu, tidak ada lagi wasiat bagi ahli waris. Nasab seorang anak adalah milik bapaknya. Untuk seorang pezina, maka baginya adalah batu (dirajam). Barangsiapa yang bernasab kepada selain bapaknya atau berwali kepada selain walinya karena benci terhadap mereka, maka laknat Allah akan tertimpa atasnya dan Allah tidak akan menerima darinya, baik itu amalan sunnah atau pun amalan wajib.\" Abu Isa berkata; Aku mendengar Ahmad bin Al Husain berkata; Ahmad bin Hanbal berkata; Aku tidak peduli terhadap haditsnya Syahri bin Hausyab. Dan aku pernah bertanya kepada Muhammad bin Isma'il mengenai Syahri bin Hausyab, maka ia pun men-tsiqqah-kannya kemudian berkata, \"Yang berkomentar tentangnya hanyalah Ibnu 'Aun. Kemudian Ibnu 'Aun meriwayatkan dari Hilal bin Abu Zainab, dari Syahri bin Hausyab. Abu Isa berkata; Ini adalah hadits Hasan Shahih."},"2048":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَبِي إِسْحَقَ الْهَمْدَانِيِّ عَنْ الْحَارِثِ عَنْ عَلِيٍّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى بِالدَّيْنِ قَبْلَ الْوَصِيَّةِ وَأَنْتُمْ تُقِرُّونَ الْوَصِيَّةَ قَبْلَ الدَّيْنِقَالَ أَبُو عِيسَى وَالْعَمَلُ عَلَى هَذَا عِنْدَ عَامَّةِ أَهْلِ الْعِلْمِ أَنَّهُ يُبْدَأُ بِالدَّيْنِ قَبْلَ الْوَصِيَّةِ","id":"Telah menceritakan kepada kami [Ibnu Abu 'Umar]; telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Abu Ishaq Al Hamdani] dari [Al Harits] dari ['Ali] bahwasanya Nabi shallallahu 'alaihi wasallam lebih mendahulukan pembayaran hutang, sebelum pelaksanaan wasiat. Sementara kalian lebih mendahulukan wasiat daripada pembayaran hutang. Abu Isa berkata; Menurut mayoritas ulama, hadits ini diamalkan. Yakni, hendaklah dimulai dari hutang terlebih dahulu, sebelum pelaksanaan wasiat."},"2049":{"ar":"حَدَّثَنَا بُنْدَارٌ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي حَبِيبَةَ الطَّائِيِّ قَالَ أَوْصَى إِلَيَّ أَخِي بِطَائِفَةٍ مِنْ مَالِهِ فَلَقِيتُ أَبَا الدَّرْدَاءِ فَقُلْتُ إِنَّ أَخِي أَوْصَى إِلَيَّ بِطَائِفَةٍ مِنْ مَالِهِ فَأَيْنَ تَرَى لِي وَضْعَهُ فِي الْفُقَرَاءِ أَوْ الْمَسَاكِينِ أَوْ الْمُجَاهِدِينَ فِي سَبِيلِ اللَّهِ فَقَالَ أَمَّا أَنَا فَلَوْ كُنْتُ لَمْ أَعْدِلْ بِالْمُجَاهِدِينَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَثَلُ الَّذِي يَعْتِقُ عِنْدَ الْمَوْتِ كَمَثَلِ الَّذِي يُهْدِي إِذَا شَبِعَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Bundar]; telah menceritakan kepada kami ['Abdurrahman bin Mahdi]; telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq] dari [Abu Habibah Ath Tha'i] dia berkata; Saudaraku berwasiat kepadaku akan setumpuk harta yang dimilikinya. Maka aku pun menemui [Abu Darda`] dan berkata padanya, \"Sesungguhnya saudaraku telah mewasiatkan kepadaku setumpuk dari harta miliknya. Lalu bagaimanakah pendapat Anda, apakah aku harus mealokasikannya kepada para fuqara` atau orang-orang miskin, atau kepada para Mujahidin di jalan Allah?\" Maka ia menjawab; Kalau menurutku, sekiranya aku belum berbuat adil kepada para mujahidin. Aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perumpamaan orang yang membebaskan budak saat ia hendak meninggal (sakarat), adalah seperti seorang yang memberikan hadiah saat ia telah merasa kenyang.\" Abu Isa berkata; Ini adalah hadits hasan shahih."},"2050":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ أَنَّ عَائِشَةَ أَخْبَرَتْهُأَنَّ بَرِيرَةَ جَاءَتْ تَسْتَعِينُ عَائِشَةَ فِي كِتَابَتِهَا وَلَمْ تَكُنْ قَضَتْ مِنْ كِتَابَتِهَا شَيْئًا فَقَالَتْ لَهَا عَائِشَةُ ارْجِعِي إِلَى أَهْلِكِ فَإِنْ أَحَبُّوا أَنْ أَقْضِيَ عَنْكِ كِتَابَتَكِ وَيَكُونَ لِي وَلَاؤُكِ فَعَلْتُ فَذَكَرَتْ ذَلِكَ بَرِيرَةُ لِأَهْلِهَا فَأَبَوْا وَقَالُوا إِنْ شَاءَتْ أَنْ تَحْتَسِبَ عَلَيْكِ وَيَكُونَ لَنَا وَلَاؤُكِ فَلْتَفْعَلْ فَذَكَرَتْ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ابْتَاعِي فَأَعْتِقِي فَإِنَّمَا الْوَلَاءُ لِمَنْ أَعْتَقَ ثُمَّ قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا بَالُ أَقْوَامٍ يَشْتَرِطُونَ شُرُوطًا لَيْسَتْ فِي كِتَابِ اللَّهِ مَنْ اشْتَرَطَ شَرْطًا لَيْسَ فِي كِتَابِ اللَّهِ فَلَيْسَ لَهُ وَإِنْ اشْتَرَطَ مِائَةَ مَرَّةٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ عَائِشَةَ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَهْلِ الْعِلْمِ أَنَّ الْوَلَاءَ لِمَنْ أَعْتَقَ","id":"Telah menceritakan kepada kami [Qutaibah]; telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari ['Urwah] bahwasanya ['Aisyah] mengabarkan kepadanya bahwasanya Barirah datang untuk meminta pertolongan kepada 'Aisyah terkait dengan Kitabahnya (perjanjian kebebasannya dengan membayar sejumlah uang), namun Aisyah belum sempat untuk menunaikannya. Lalu Aisyah pun berkata kepada Barirah, \"Kembalilah kepada tuanmu, jika mereka rela aku menunaikan kitabahmu dan perwalianmu akan menjadi hakku, niscaya aku akan melakukannya.\" Akhirnya Barirah menuturkan hal itu kepada majikannya, namun mereka enggan seraya berkata, \"Jika ia mau, maka ia boleh membebaskanmu, namun perwalianmu tetap kepada kam.\" Kemudian Aisyah menuturkan hal itu kepada Rasulullah shallallahu 'alaihi wasallam, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apa yang akan terjadi terhadap mereka, sehingga memberikan persyaratan dengan sesuatu yang tidak terdapat di dalam Kibatullah. Barangsiapa yang memberikan syarat dengan sesuatu yang tidak terdapat di dalam Kitabullah, maka persyaratan itu tidaklah berarti baginya, meskipun ia mempersyaratkan seratus kali.\" Abu Isa berkata; Ini adalah hadits Hasan Shahih. Dan hadits ini telah diriwayatkan pula oleh lebih dari satu orang perawi dari Aisyah. Menurut Ahlul Imi, hadits ini diamalkan. Yakni, perwalian itu adalah milik yang membebaskan."},"2051":{"ar":"حَدَّثَنَا بُنْدَارٌ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَأَنَّهَا أَرَادَتْ أَنْ تَشْتَرِيَ بَرِيرَةَ فَاشْتَرَطُوا الْوَلَاءَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْوَلَاءُ لِمَنْ أَعْطَى الثَّمَنَ أَوْ لِمَنْ وَلِيَ النِّعْمَةَقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ ابْنِ عُمَرَ وَأَبِي هُرَيْرَةَ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَهْلِ الْعِلْمِ","id":"Telah menceritakan kepada kami [Bundar]; telah menceritakan kepada kami ['Abdurrahman bin Mahdi]; telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Ibrahim] dari [Al Aswad] dari ['Aisyah] bahwasanya; Ia ingin membeli Barirah, namun majikannya mempersyaratkan Al Wala` (kepemilikan tetap terhadap mereka), maka Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya perwalian (hak milik) itu adalah bagi yang membayar, atau bagi waliyun ni'mah (yang merdekakan).\" Abu Isa berkata; Hadits semakna juga diriwayatkan dari Ibnu Umar dan Abu Hurairah. Dan ini adalah hadits Hasan Shahih. Dan menurut Ahlul Ilmi, hadits ini diamalkan."},"2052":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دِينَارٍ سَمِعَ عَبْدَ اللَّهِ بْنَ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ الْوَلَاءِ وَعَنْ هِبَتِهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ نَهَى عَنْ بَيْعِ الْوَلَاءِ وَعَنْ هِبَتِهِ وَقَدْ رَوَاهُ شُعْبَةُ وَسُفْيَانُ الثَّوْرِيُّ وَمَالِكُ بْنُ أَنَسٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ وَيُرْوَى عَنْ شُعْبَةَ قَالَ لَوَدِدْتُ أَنَّ عَبْدَ اللَّهِ بْنَ دِينَارٍ حِينَ حَدَّثَ بِهَذَا الْحَدِيثِ أَذِنَ لِي حَتَّى كُنْتُ أَقُومُ إِلَيْهِ فَأُقَبِّلُ رَأْسَهُ وَرَوَى يَحْيَى بْنُ سُلَيْمٍ هَذَا الْحَدِيثَ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ وَهْمٌ وَهِمَ فِيهِ يَحْيَى بْنُ سُلَيْمٍ وَالصَّحِيحُ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَكَذَا رَوَاهُ غَيْرُ وَاحِدٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ قَالَ أَبُو عِيسَى وَتَفَرَّدَ عَبْدُ اللَّهِ بْنُ دِينَارٍ بِهَذَا الْحَدِيثِ","id":"Telah menceritakan kepada kami [Ibnu Abu 'Umar]; telah menceritakan kepada kami [Sufyan bin 'Uyainah]; telah menceritakan kepada kami ['Abdullah bin Dinar] dia mendengar ['Abdullah bin 'Umar] bahwasanya Rasulullah shallallahu 'alaihi wasallam melarang penjualan Al Wala` (kepemilikan) dan juga menghibahkannya. Abu Isa berkata; Ini adalah hadits Hasan Shahih, kami tidak mengetahuinya kecuali dari haditsnya Abdullah bin Dinar dari Ibnu Umar dari Nabi shallallahu 'alaihi wasallam bahwasanya, beliau melarang penjualan Al Wala` atau pun menghibahkannya. Hadits ini juga telah diriwayatkan oleh [Syu'bah], [Sufyan Ats Tsauri] dan [Malik bin Anas] dari [Abdullah bin Dinar]. Dan diriwayatkan pula dari Syu'bah, ia berkata, \"Sungguh, aku berkeinginan bahwa Abdullah bin Dinar ketika meriwayatkan hadits ini untuk mengizinkan kepadaku agar aku mencium kepalanya. [Yahya bin Sulaim] juga meriwayatkan hadits ini dari [Ubaidullah bin Umar], dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam, namun di dalamnya terdapat Wahm. Yang shahih adalah dari Ubaidullah bin Umar dari Abdullah bin Dinar dari Ibnu Umar dari Nabi shallallahu 'alaihi wasallam. Dan seperti ini pula yang diriwayatkan oleh lebih dari satu perawi dari Ubaidullah bin Umar. Abu Isa berkata; Abdullah bin Umar bersendirian dalam meriwayatkan hadits ini."},"2053":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ أَبِيهِ قَالَ خَطَبَنَا عَلِيٌّ فَقَالَمَنْ زَعَمَ أَنَّ عِنْدَنَا شَيْئًا نَقْرَؤُهُ إِلَّا كِتَابَ اللَّهِ وَهَذِهِ الصَّحِيفَةَ صَحِيفَةٌ فِيهَا أَسْنَانُ الْإِبِلِ وَأَشْيَاءٌ مِنْ الْجِرَاحَاتِ فَقَدْ كَذَبَ وَقَالَ فِيهَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةُ حَرَامٌ مَا بَيْنَ عَيْرٍ إِلَى ثَوْرٍ فَمَنْ أَحْدَثَ فِيهَا حَدَثًا أَوْ آوَى مُحْدِثًا فَعَلَيْهِ لَعْنَةُ اللَّهِ وَالْمَلَائِكَةِ وَالنَّاسِ أَجْمَعِينَ لَا يَقْبَلُ اللَّهُ مِنْهُ يَوْمَ الْقِيَامَةِ صَرْفًا وَلَا عَدْلًا وَمَنْ ادَّعَى إِلَى غَيْرِ أَبِيهِ أَوْ تَوَلَّى غَيْرَ مَوَالِيهِ فَعَلَيْهِ لَعْنَةُ اللَّهِ وَالْمَلَائِكَةِ وَالنَّاسِ أَجْمَعِينَ لَا يُقْبَلُ مِنْهُ صَرْفٌ وَلَا عَدْلٌ وَذِمَّةُ الْمُسْلِمِينَ وَاحِدَةٌ يَسْعَى بِهَا أَدْنَاهُمْقَالَ أَبُو عِيسَى وَرَوَى بَعْضُهُمْ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ الْحَارِثِ بْنِ سُوَيْدٍ عَنْ عَلِيٍّ نَحْوَهُ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ عَلِيٍّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Hannad]; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Ibrahim At Taimi] dari [bapaknya] dia berkata; [Ali] pernah menyampaikan khuthbah kepada kami seraya berkata, \"Barangsiapa yang menyangka, bahwa kami memiliki sesuatu yang kami baca kecuali Kitabullah (Al Qur`an) dan di dalam Shahifah ini gigi unta, atau pun sesuatu dari batu-batu, maka sungguh ia telah berdusta.\" Dan di dalam khuthbahnya, ia juga berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kota Madinah adalah haram (suci), yakni daerah antara 'Air dan Tsaur. Maka barangsiapa yang berbuat kejahatan di dalamnya, atau berniat hendak melakukan kejahatan di dalamnya, niscaya laknat Allah, para Malaikat dan laknat seluruh manusia akan tertimpa atasnya. Allah tidak akan menerima darinya, baik itu amalan wajib atau pun amalan sunnahnya. Dan barangisapa yang bernasab kepada selain bapaknya, atau berwali kepada selain walinya, maka laknat Allah, para Malaikat dan laknat seluruh manusia akan tertimpa atasnya, tidak akan diterima lagi darinya, baik itu amalan wajib atau pun amalan sunnahnya. Dzimmah kaum muslimin adalah satu. Dan akan lebih tinggi lagi, orang-orang yang paling rendah dari mereka.\" Abu Isa berkata; Sebagian mereka meriwayatkan dari [Al A'masy] dari [Ibrahim At Tamimi], dari [Al Harits bin Suwaid], dari [Ali] dengan hadits semisalnya. Abu Isa berkata; Ini adalah hadits hasan shahih. Dan telah pula diriwayatkan lebih dari satu jalur dari Ali dari Nabi shallallahu 'alaihi wasallam."},"2054":{"ar":"حَدَّثَنَا عَبْدُ الْجَبَّارِ بْنُ الْعَلَاءِ بْنِ عَبْدِ الْجَبَّارِ الْعَطَّارُ وَسَعِيدُ بْنُ عَبْدِ الرَّحْمَنِ الْمَخْزُومِيُّ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيِّبِ عَنْ أَبِي هُرَيْرَةَ قَالَجَاءَ رَجُلٌ مِنْ بَنِي فَزَارَةَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ امْرَأَتِي وَلَدَتْ غُلَامًا أَسْوَدَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ لَكَ مِنْ إِبِلٍ قَالَ نَعَمْ قَالَ فَمَا أَلْوَانُهَا قَالَ حُمْرٌ قَالَ فَهَلْ فِيهَا أَوْرَقُ قَالَ نَعَمْ إِنَّ فِيهَا لَوُرْقًا قَالَ أَنَّى أَتَاهَا ذَلِكَ قَالَ لَعَلَّ عِرْقًا نَزَعَهَا قَالَ فَهَذَا لَعَلَّ عِرْقًا نَزَعَهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami ['Abdul Jabbar bin Al 'Ala bin 'Abdul Jabbar Al 'Aththar] dan [Sa'id bin 'Abdurrahman Al Makhzumi] mereka berdua berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah] dia berkata; Ada seorang laki-laki Bani Fararah datang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, sesungguhnya isteri telah melahirkan seorang anak yang hitam.\" Maka Nabi shallallahu 'alaihi wasallam bertanya: \"Apakah kamu memiliki beberapa ekor unta?\" Laki-laki itu menjawab, \"Ya.\" Beliau bertanya lagi: \"Lalu apa sajakah warna-warna kulitnya?\" Laki-laki itu menjawab, \"Merah.\" Beliau bertanya lagi: \"Apakah diantaranya ada yang berwarna hijau?\" laki-laki itu menjawab, \"Ya.\" Beliau bertanya lagi: \"Lantas darimana warna itu datang?\" Laki-laki itu pun menjawab, \"Mungkin saja dari akar yang ia cabut.\" Akhirnya beliau pun bersabda: \"Maka demikian pula halnya dengan ini, mungkin saja dari akar yang ia cabut.\" Abu Isa berkata; Ini adalah hadits hasan shahih."},"2055":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَيْهَا مَسْرُورًا تَبْرُقُ أَسَارِيرُ وَجْهِهِ فَقَالَ أَلَمْ تَرَيْ أَنَّ مُجَزِّزًا نَظَرَ آنِفًا إِلَى زَيْدِ بْنِ حَارِثَةَ وَأُسَامَةَ بْنِ زَيْدٍ فَقَالَ هَذِهِ الْأَقْدَامُ بَعْضُهَا مِنْ بَعْضٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَى ابْنُ عُيَيْنَةَ هَذَا الْحَدِيثَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ وَزَادَ فِيهِ أَلَمْ تَرَيْ أَنَّ مُجَزِّزًا مَرَّ عَلَى زَيْدِ بْنِ حَارِثَةَ وَأُسَامَةَ بْنِ زَيْدٍ قَدْ غَطَّيَا رُءُوسَهُمَا وَبَدَتْ أَقْدَامُهُمَا فَقَالَ إِنَّ هَذِهِ الْأَقْدَامَ بَعْضُهَا مِنْ بَعْضٍ وَهَكَذَا حَدَّثَنَا سَعِيدُ بْنُ عَبْدِ الرَّحْمَنِ وَغَيْرُ وَاحِدٍ عَنْ سُفْيَانَ بْنِ عُيَيْنَةَ هَذَا الْحَدِيثَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ احْتَجَّ بَعْضُ أَهْلِ الْعِلْمِ بِهَذَا الْحَدِيثِ فِي إِقَامَةِ أَمْرِ الْقَافَةِ","id":"Telah menceritakan kepada kami [Qutaibah]; telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari ['Urwah] dari ['Aisyah] bahwasanya Nabi shallallahu 'alaihi wasallam pernah menemuinya dalam keadaan senang dengan wajah yang berseri-seri seraya bersabda: \"Apakah kamu tidak memperhatikan bahwa tadi Mujazziz melihat ke arah Zaid bin Haritsah dan Usamah bin Zaid?\" Beliau berkata lagi, \"Sesungguhnya kaki ini, sebagiannya bersal dari sebagian yang lain.\" Abu Isa berkata; Ini adalah hadits hasan shahih. Ibnu Uyainah telah meriwayatkan hadits ini dari Az Zuhri dari Urwah dari 'Aisyah, dan ia menambahkan di dalamnya; \"Tidakkah kamu perhatikan, bahwa Mujazziz melewati Zaid bin Haritsah dan Usamah bin Zaid yang keduanya telah menutupi kepalanya, sementara kaki-kakitnya terlihat?\" kemudian beliau bersabda: \"Sesungguhnya kaki-kaki ini, sebagiannya berasal dari sebagian yang lain.\" Dan seperti ini pula, [Sa'id bin Abdurrahman] dan yang lainnya meriwayatkan hadits ini dari [Sufyan bin Uyainah] dari [Zuhri] dari [Urwah] dari [Aisyah]. Dan hadits ini adalah hasan shahih. Sebagian Ulama telah berdalih dengan hadits ini, yakni terkait dengan perintah untuk menegakkan perkara Al Qafah."},"2056":{"ar":"حَدَّثَنَا أَزْهَرُ بْنُ مَرْوَانَ الْبَصْرِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ سَوَاءٍ حَدَّثَنَا أَبُو مَعْشَرٍ عَنْ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَهَادَوْا فَإِن��َ الْهَدِيَّةَ تُذْهِبُ وَحَرَ الصَّدْرِ وَلَا تَحْقِرَنَّ جَارَةٌ لِجَارَتِهَا وَلَوْ شِقَّ فِرْسِنِ شَاةٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَأَبُو مَعْشَرٍ اسْمُهُ نَجِيحٌ مَوْلَى بَنِي هَاشِمٍ وَقَدْ تَكَلَّمَ فِيهِ بَعْضُ أَهْلِ الْعِلْمِ مِنْ قِبَلِ حِفْظِهِ","id":"Telah menceritakan kepada kami [Azhar bin Marwan Al Bashri]; telah menceritakan kepada kami [Muhammad bin Sawa']; telah menceritakan kepada kami [Abu Ma'syar] dari [Sa'id] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Hendaknya kalian saling memberikan hadiah, karena hadiah dapat menghilangkan sifat benci dalam dada, dan janganlah seseorang meremehkan pemberian tetangganya walaupun hanya secuil kaki kambing.\" Abu Isa berkata; Hadits ini gharib bila ditinjau dari jalur sanad ini. Adapun Abu Mi'syar namanya adalah Najih, yakni bekas budaknya Bani Hasyim, dan sebagian ahli ilmu telah membicarakannya dari sisi hafalannya."},"2057":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا إِسْحَقُ بْنُ يُوسُفَ الْأَزْرَقُ حَدَّثَنَا حُسَيْنٌ الْمُكَتَّبُ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ طَاوُسٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَثَلُ الَّذِي يُعْطِي الْعَطِيَّةَ ثُمَّ يَرْجِعُ فِيهَا كَالْكَلْبِ أَكَلَ حَتَّى إِذَا شَبِعَ قَاءَ ثُمَّ عَادَ فَرَجَعَ فِي قَيْئِهِقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ ابْنِ عَبَّاسٍ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو","id":"Telah menceritakan kepada kami [Ahmad bin Mani']; telah menceritakan kepada kami [Ishaq bin Yusuf Al Azraq]; telah menceritakan kepada kami [Husain Al Mukattab] dari ['Amr bin Syu'aib] dari [Thawus] dari [Ibnu 'Umar] bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perumpaan orang yang memberikan suatu pemberian lalu mengambilnya kembali adalah seperti seekor anjing yang makan hingga kekenyangan dan memuntahkannya, lalu ia kembali memakannya.\" Abu Isa berkata; Hadits semakna juga diriwayatkan dari Ibnu Abbas dan Abdullah bin Amru."},"2058":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ حُسَيْنٍ الْمُعَلِّمِ عَنْ عَمْرِو بْنِ شُعَيْبٍ حَدَّثَنِي طَاوُوسٌ عَنْ ابْنِ عُمَرَ وَابْنِ عَبَّاسٍ يَرْفَعَانِ الْحَدِيثَ قَالَلَا يَحِلُّ لِلرَّجُلِ أَنْ يُعْطِيَ عَطِيَّةً ثُمَّ يَرْجِعُ فِيهَا إِلَّا الْوَالِدَ فِيمَا يُعْطِي وَلَدَهُ وَمَثَلُ الَّذِي يُعْطِي الْعَطِيَّةَ ثُمَّ يَرْجِعُ فِيهَا كَمَثَلِ الْكَلْبِ أَكَلَ حَتَّى إِذَا شَبِعَ قَاءَ ثُمَّ عَادَ فِي قَيْئِهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ قَالَ الشَّافِعِيُّ لَا يَحِلُّ لِمَنْ وَهَبَ هِبَةً أَنْ يَرْجِعَ فِيهَا إِلَّا الْوَالِدَ فَلَهُ أَنْ يَرْجِعَ فِيمَا أَعْطَى وَلَدَهُ وَاحْتَجَّ بِهَذَا الْحَدِيثِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar]; telah menceritakan kepada kami [Ibnu Abu 'Adi] dari [Husain Al Mu'allim] dari ['Amr bin Syu'aib]; telah menceritakan kepadaku [Thawus] dari [Ibnu 'Umar] dan [Ibnu Abbas] - keduanya memarfukkan hadits ini- ia berkata, \"Tidak halal bagi seseorang untuk memberikan pemberian kemudian ia menariknya kembali. Kecuali bagi seorang bapak terhadap apa yang diberikannya pada anaknya. Dan perumpamaan seorang yang memberikan pemberian, lalu ia menariknya kembali, adalah seperti seekor kambing yang makan hingga kekenyangan dan muntah, lalu memakan muntahannya kembali.\" Abu Isa berkata; Ini adalah hadits Hasan Shahih. Asy Syafi'i berkata, \"Tidak halal, bagi seorang yang telah menghibahkan sesuatu, lalu ia menariknya kembali. Kecuali bagi seorang bapak, maka ia boleh mengambil kembali apa yang telah diberikannya pada anaknya.\" Kemudian ia berdalik dengan hadits ini."},"2059":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُعَاوِيَةَ الْجُمَحِيُّ الْبَصْرِيُّ حَدَّثَنَا صَالِحٌ الْمُرِّيُّ عَنْ هِشَامِ بْنِ حَسَّانَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَخَرَجَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ نَتَنَازَعُ فِي الْقَدَرِ فَغَضِبَ حَتَّى احْمَرَّ وَجْهُهُ حَتَّى كَأَنَّمَا فُقِئَ فِي وَجْنَتَيْهِ الرُّمَّانُ فَقَالَ أَبِهَذَا أُمِرْتُمْ أَمْ بِهَذَا أُرْسِلْتُ إِلَيْكُمْ إِنَّمَا هَلَكَ مَنْ كَانَ قَبْلَكُمْ حِينَ تَنَازَعُوا فِي هَذَا الْأَمْرِ عَزَمْتُ عَلَيْكُمْ أَلَّا تَتَنَازَعُوا فِيهِقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عُمَرَ وَعَائِشَةَ وَأَنَسٍ وَهَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ مِنْ حَدِيثِ صَالِحٍ الْمُرِّيِّ وَصَالِحٌ الْمُرِّيُّ لَهُ غَرَائِبُ يَنْفَرِدُ بِهَا لَا يُتَابَعُ عَلَيْهَا","id":"Telah menceritakan kepada kami ['Abdullah bin Mu'awiyah Al Jumahi Al Bashri]; telah menceritakan kepada kami [Shalih Al Murri]; dari [Hisyam bin Hassan] dari [Muhammad bin Sirin] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam keluar menemui kami sementara kami sedang berselisih dalam masalah taqdir, kemudian beliau marah hingga wajahnya menjadi merah sampai seakan akan pipinya seperti buah delima yang dibelah, lalu beliau bertanya \"Apakah kalian diperintahkan seperti ini atau apakah aku diutus kepada kalian untuk masalah ini? Sesungguhnya binasanya orang-orang sebelum kalian adalah lantaran perselisihan mereka dalam perkara ini. Karena itu, aku tekankan pada kalian untuk tidak berselisih dalam masalah ini.\" Abu Isa berkata; Hadits semakna juga diriwayatkan dari dari Umar, A'isyah dan Anas. Dan hadits ini adalah Gharib, kami tidak mengetahuinya kecuali dari jalur sanad ini dari hadits Shalih Al Murri, sedangkan Shalih Al Murri memiliki hadits hadits Gharib yang dia riwayatkan dengan sendirian dan tidak ada yang mengikutinya."},"2060":{"ar":"حَدَّثَنَا يَحْيَى بْنُ حَبِيبِ بْنِ عَرَبِيٍّ حَدَّثَنَا الْمُعْتَمِرُ بْنُ سُلَيْمَانَ حَدَّثَنَا أَبِي عَنْ سُلَيْمَانَ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ احْتَجَّ آدَمُ وَمُوسَى فَقَالَ مُوسَى يَا آدَمُ أَنْتَ الَّذِي خَلَقَكَ اللَّهُ بِيَدِهِ وَنَفَخَ فِيكَ مِنْ رُوحِهِ أَغْوَيْتَ النَّاسَ وَأَخْرَجْتَهُمْ مِنْ الْجَنَّةِ قَالَ فَقَالَ آدَمُ وَأَنْتَ مُوسَى الَّذِي اصْطَفَاكَ اللَّهُ بِكَلَامِهِ أَتَلُومُنِي عَلَى عَمَلٍ عَمِلْتُهُ كَتَبَهُ اللَّهُ عَلَيَّ قَبْلَ أَنْ يَخْلُقَ السَّمَوَاتِ وَالْأَرْضَ قَالَ فَحَجَّ آدَمُ مُوسَىقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عُمَرَ وَجُنْدَبٍ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ مِنْ حَدِيثِ سُلَيْمَانَ التَّيْمِيِّ عَنْ الْأَعْمَشِ وَقَدْ رَوَى بَعْضُ أَصْحَابِ الْأَعْمَشِ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ و قَالَ بَعْضُهُمْ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي سَعِيدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ مِنْ غَيْرِ وَجْهٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Yahya bin Habib bin 'Arabi]; telah menceritakan kepada kami [Al Mu'tamir bin Sulaiman]; [bapakku] telah menceritakan kepada kami dari [Sulaiman Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Nabi Adam dan Musa bersilat lidah. Berkatalah Musa, 'Wahai Adam, kamulah yang telah diciptakan Allah, dan meniupkan padamu bagian dari ruh-Nya. Namun kamu menyesatkan manusia dan mengeluarkan manusia dari surga.' Kemudian Adam balas berkata, 'Wahai Musa, kamu telah disucikan Allah dengan Kalam-Nya, apakah kamu mencelaku akan suatu amalan yang telah aku perbuat dan telah pula ditetapkan Allah sebelum Dia menciptakan langit dan bumi? ' Maka Nabi Adam pun berdalih atas Musa.\" Abu Isa berkata; Hadits semakna juga diriwayatkan dari Umar dan Jundub. Dan ini adalah hadits hasan shahih gharib bila ditinjau dari jalur ini, yakni dari haditsnya Sulaiman At Tamimi dari Al A'masy. Sebagian sahabat A'masy telah meriwayatkan dari A'masy dari Abu Shalih dari Abu Hurairah dari Nabi shallallahu 'alaihi wasallam dengan hadits semisalnya. Dan sebagian lagi menyebutkan dari [Al A'masy] dari [Abu Shalih] dari [Abu Sa'id] dari Nabi shallallahu 'alaihi wasallam. Dan hadits ini telah diriwayatkan lebih dari satu jalur dari Abu Hurairah, dari Nabi shallallahu 'alaihi wasallam."},"2061":{"ar":"حَدَّثَنَا بُنْدَارٌ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا شُعْبَةُ عَنْ عَاصِمِ بْنِ عُبَيْدِ اللَّهِ قَال سَمِعْتُ سَالِمَ بْنَ عَبْدِ اللَّهِ يُحَدِّثُ عَنْ أَبِيهِ قَالَقَالَ عُمَرُ يَا رَسُولَ اللَّهِ أَرَأَيْتَ مَا نَعْمَلُ فِيهِ أَمْرٌ مُبْتَدَعٌ أَوْ مُبْتَدَأٌ أَوْ فِيمَا قَدْ فُرِغَ مِنْهُ فَقَالَ فِيمَا قَدْ فُرِغَ مِنْهُ يَا ابْنَ الْخَطَّابِ وَكُلٌّ مُيَسَّرٌ أَمَّا مَنْ كَانَ مِنْ أَهْلِ السَّعَادَةِ فَإِنَّهُ يَعْمَلُ لِلسَّعَادَةِ وَأَمَّا مَنْ كَانَ مِنْ أَهْلِ الشَّقَاءِ فَإِنَّهُ يَعْمَلُ لِلشَّقَاءِقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عَلِيٍّ وَحُذَيْفَةَ بْنِ أَسِيدٍ وَأَنَسٍ وَعِمْرَانَ بْنِ حُصَيْنٍ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Bundar]; telah menceritakan kepada kami ['Abdurrahman bin Mahdi]; telah menceritakan kepada kami [Syu'bah] dari ['Ashim bin 'Ubaidullah] dia berkata; aku mendengar [Salim bin 'Abdullah] bercerita dari [bapaknya], dia berkata; Umar pernah bertanya, \"Wahai Rasulullah bagaimana pendapatmu apakah kami melakukan sesuatu yang diada-adakan atau sesuatu yang baru (belum ditentukan takdirnya) atau sesuatu yang sudah ditetapkan takdirnya?\" Maka beliau pun menjawab: \"Sesuatu yang sudah ditetapkan atas takdirnya, wahai Ibnul Khaththab, dan setiap orang akan dimudahkan, adapun orang yang termasuk Ahlu Sa'adah (orang yang berbahagia) maka dia akan beramal untuk kebahagiaan, sedangkan orang yang termasuk ahlu saqa' (orang yang celaka) maka dia akan beramal untuk kecelakaan.\" Abu Isa berkata; Dalam bab ini ada hadits dari Ali, Hudzaifah bin Asid, Anas dan Imran bin Hushain. Dan hadits ini adalah hadits hasan shahih."},"2062":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْحُلْوَانِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ وَوَكِيعٌ عَنْ الْأَعْمَشِ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ أَبِي عَبْدِ الرَّحْمَنِ السُّلَمِيِّ عَنْ عَلِيٍّ قَالَبَيْنَمَا نَحْنُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَنْكُتُ فِي الْأَرْضِ إِذْ رَفَعَ رَأْسَهُ إِلَى السَّمَاءِ ثُمَّ قَالَ مَا مِنْكُمْ مِنْ أَحَدٍ إِلَّا قَدْ عُلِمَ وَقَالَ وَكِيعٌ إِلَّا قَدْ كُتِبَ مَقْعَدُهُ مِنْ النَّارِ وَمَقْعَدُهُ مِنْ الْجَنَّةِ قَالُوا أَفَلَا نَتَّكِلُ يَا رَسُولَ اللَّهِ قَالَ لَا اعْمَلُوا فَكُلٌّ مُيَسَّرٌ لِمَا خُلِقَ لَهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Al Hasan bin 'Ali Al Hulwani]; telah menceritakan kepada kami ['Abdullah bin Numair] dan [Waki'] dari [Al A'masy] dari [Sa'd bin 'Ubaidah] dari [Abu 'Abdurrahman As Sulami] dari ['Ali] dia berkata; Ketika kami bersama Rasulullah shallallahu 'alaihi wasallam yang saat itu beliau sedang menunduk ke tanah. Tiba-tiba, beliau mengangkat kepalanya ke arah langit kemudian bersabda: \"Tidak seorang pun dari kalian, kecuali telah diketahui (takdir) -nya.\" Waki' berkata, \"Kecuali telah ditulis tempat duduknya, apakah dari neraka ataukah dari surga.\" Para sahabat kemudian bertanya, \"Kalau begitu, bukankah lebih baik kita bertawakkal saja wahai Rasulullah?\" beliau menjawab: \"Tidak! Beramallah kalian, sebab, setiap orang akan dimudahkan terhadap sesuatu yang telah diciptakan baginya.\" Abu Isa berkata; Ini adalah hadits hasan shahih."},"2063":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ زَيْدِ بْنِ وَهْبٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَحَدَّثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ الصَّادِقُ الْمَصْدُوقُ إِنَّ أَحَدَكُمْ يُجْمَعُ خَلْقُهُ فِي بَطْنِ أُمِّهِ فِي أَرْبَعِينَ يَوْمًا ثُمَّ يَكُونُ عَلَقَةً مِثْلَ ذَلِكَ ثُمَّ يَكُونُ مُضْغَةً مِثْلَ ذَلِكَ ثُمَّ يُرْسِلُ اللَّهُ إِلَيْهِ الْمَلَكَ فَيَنْفُخُ فِيهِ الرُّوحَ وَيُؤْمَرُ بِأَرْبَعٍ يَكْتُبُ رِزْقَهُ وَأَجَلَهُ وَعَمَلَهُ وَشَقِيٌّ أَوْ سَعِيدٌ فَوَالَّذِي لَا إِلَهَ غَيْرُهُ إِنَّ أَحَدَكُمْ لَيَعْمَلُ بِعَمَلِ أَهْلِ الْجَنَّةِ حَتَّى مَا يَكُونُ بَيْنَهُ وَبَيْنَهَا إِلَّا ذِرَاعٌ ثُمَّ يَسْبِقُ عَلَيْهِ الْكِتَابُ فَيُخْتَمُ لَهُ بِعَمَلِ أَهْلِ النَّارِ فَيَدْخُلُهَا وَإِنَّ أَحَدَكُمْ لَيَعْمَلُ بِعَمَلِ أَهْلِ النَّارِ حَتَّى مَا يَكُونَ بَيْنَهُ وَبَيْنَهَا إِلَّا ذِرَاعٌ ثُمَّ يَسْبِقُ عَلَيْهِ الْكِتَابُ فَيُخْتَمُ لَهُ بِعَمَلِ أَهْلِ الْجَنَّةِ فَيَدْخُلُهَاقَالَ أَبُو عِيسَى وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا الْأَعْمَشُ حَدَّثَنَا زَيْدُ بْنُ وَهْبٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَ حَدَّثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ مِثْلَهُ قَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَأَنَسٍ و سَمِعْت أَحْمَدَ بْنَ الْحَسَنِ قَال سَمِعْتُ أَحْمَدَ بْنَ حَنْبَلٍ يَقُولُ مَا رَأَيْتُ بِعَيْنِي مِثْلَ يَحْيَى بْنِ سَعِيدٍ الْقَطَّانِ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَى شُعْبَةُ وَالثَّوْرِيُّ عَنْ الْأَعْمَشِ نَحْوَهُ حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا وَكِيعٌ عَ��ْ الْأَعْمَشِ عَنْ زَيْدٍ نَحْوَهُ","id":"Telah menceritakan kepada kami [Hannad]; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Zaid bin Wahb] dari ['Abdullah bin Mas'ud] dia berkata; Rasulullah shallallahu 'alaihi wasallam pernah bercerita kepada kami: \"Sesungguhnya salah seorang di antara kalian, telah dikumpulkan penciptaannya di dalam perut ibunya selama empat puluh hari. Kemudian ia menjadi darah pada empat puluh hari kemudian. Lalu empat puluh hari kemudian segumpal darah. Dan barulah pada saat itu, diutuslah Malaikat untuk meniupkan ruh kepanya. Kemudian ia diperintahkan dengan empat hal. Ditulis rezkinya, ajalnya, amalnya, dan apakah ia akan bahagia ataukah sengsara. Maka demi Dzat yang jiwaku berada di tangan-Nya. Sesungguhnya salah seorang dari kalian ada yang beramal dengan amalan penduduk surga hingga tidak lagi tersisa jarak antara ia dan surga kecuali hanya sejengkal, namun kitab telah mendahuluinya, lalu ia pun ditutup dengan amalan penduduk neraka dan ia pun memasukinya. Dan sungguh, salah seorang dari kalian beramal dengan amalan penduduk neraka hingga tidak ada jarak antara dirinya dengan neraka kecuali hanya sehasta, lalu ia pun didahului oleh kitab, lalu ia pun ditutup dengan amalan penduduk surga, lalu ia memasukinya.\" Abu Isa berkata; Ini adalah hadits hasan shahih. Telah menceritakan kepada kami [Muhammad bin Basysyar]; telah menceritakan kepada kami [Yahya bin Sa'id]; telah menceritakan kepada kami [Al A'masy]; telah menceritakan kepada kami [Zaid bin Wahb] dari ['Abdullah bin Mas'ud] dia berkata; Rasulullah shallallahu 'alaihi wasallam menceritakan kepada kami, dengan hadits semisalnya. Abu Isa berkata; Hadits semakna juga diriwayatkan dari Abu Hurairah dan Anas. Aku mendengar Ahmad bin Al Hasan berkata; Aku mendengar Ahmad bin Hanbal berkata, \"Aku tidak pernah melihat dengan mata kepalaku sendiri seorang seperti Yahya bin Sa'id Al Qaththani. Dan ini adalah hadits Hasan Shahih. [Syu'bah] dan [Ats Tsauri] telah meriwayatkan dari [Al A'masy] semisalnya. Telah menceritakan kepada kami [Muhammad bin Al Ala`] Telah menceritakan kepada kami [Waki'] dari [Al A'masy] dari [Zaid] hadits semisalnya."},"2064":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى الْقُطَعِيُّ الْبَصْرِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ رَبِيعَةَ الْبُنَانِيُّ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّ مَوْلُودٍ يُولَدُ عَلَى الْمِلَّةِ فَأَبَوَاهُ يُهَوِّدَانِهِ أَوْ يُنَصِّرَانِهِ أَوْ يُشَرِّكَانِهِ قِيلَ يَا رَسُولَ اللَّهِ فَمَنْ هَلَكَ قَبْلَ ذَلِكَ قَالَ اللَّهُ أَعْلَمُ بِمَا كَانُوا عَامِلِينَ بِهِحَدَّثَنَا أَبُو كُرَيْبٍ وَالْحُسَيْنُ بْنُ حُرَيْثٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ بِمَعْنَاهُ وَقَالَ يُولَدُ عَلَى الْفِطْرَةِ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَاهُ شُعْبَةُ وَغَيْرُهُ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يُولَدُ عَلَى الْفِطْرَةِ وَفِي الْبَاب عَنْ الْأَسْوَدِ بْنِ سَرِيعٍ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya Al Qutha'i Al Bashri]; telah menceritakan kepada kami ['Abdul 'Aziz bin Rabi'ah Al Bunani]; telah menceritakan kepada kami [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap anak dilahirkan di atas al millah (agama fithrahnya, Islam), namun, kedua orangtuanyalah yang menjadikannya Yahudi atau Nasrani, atau menjadikannya seorang yang musyrik.\" Kemudian ditanyakanlah pada beliau, \"Wahai Rasulullah, lalu bagaimanakah dengan yang binasa sebelum itu?\" belaiu menjawab: \"Allah-lah yang lebih tahu terhadap apa yang mereka kerjakan.\" Telah menceritakan kepada kami [Abu Kuraib] dan [Al Husain bin Huraits] keduanya berdua berkata; telah menceritakan kepada kami [Waki'] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam sepertinya dan dengan makna yang sama pula dan beliau bersabda: \"Dilahirkan dalam keadaan fithrah.\" Abu Isa berkata; Ini adlah hadits Hasan Shahih. Dan hadits ini telah diriwayatkan pula oleh [Syu'bah] dan selainnya dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dari Nabi Nabi shallallahu 'alaihi wasallam, ia pun menyebutkan; \"Dilahirkan dalam keadaan fithrah.\" Hadits semakna juga diriwayatkan dari Al Aswad bin Sari'."},"2065":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ حُمَيْدٍ الرَّازِيُّ وَسَعِيدُ بْنُ يَعْقُوبَ قَالَا حَدَّثَنَا يَحْيَى بْنُ الضُّرَيْسِ عَنْ أَبِي مَوْدُودٍ عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ أَبِي عُثْمَانَ النَّهْدِيِّ عَنْ سَلْمَانَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَرُدُّ الْقَضَاءَ إِلَّا الدُّعَاءُ وَلَا يَزِيدُ فِي الْعُمْرِ إِلَّا الْبِرُّقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أَبِي أَسِيدٍ وَهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ حَدِيثِ سَلْمَانَ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ يَحْيَى بْنِ الضُّرَيْسِ وَأَبُو مَوْدُودٍ اثْنَانِ أَحَدُهُمَا يُقَالُ لَهُ فِضَّةُ وَهُوَ الَّذِي رَوَى هَذَا الْحَدِيثَ اسْمُهُ فِضَّةُ بَصْرِيٌّ وَالْآخَرُ عَبْدُ الْعَزِيزِ بْنُ أَبِي سُلَيْمَانَ أَحَدُهُمَا بَصْرِيٌّ وَالْآخَرُ مَدَنِيٌّ وَكَانَا فِي عَصْرٍ وَاحِدٍ","id":"Telah menceritakan kepada kami [Muhammad bin Humaid Ar Razi] dan [Sa'id bin Ya'qub] mereka berdua berkata; telah menceritakan kepada kami [Yahya bin Adh Dhurais] dari [Abu Maudud] dari [Sulaiman At Taimi] dari [Abu 'Utsman An Nahdi] dari [Salman] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada yang dapat mencegah takdir kecuali do'a dan tidak ada yang bisa menambah umur kecuali amal kebajikan.\" Abu Isa berkata; Hadits semakna juga diriwayatkan dari Abu Asid. Hadits ini adalah hasan gharib dari hadits Salman, kami tidak mengetahuinya kecuali dari hadits Yahya bin Ad Durais, adapun Abu Maudud ada dua orang salah satunya yang terkenal dengan sebutan Fiddah yaitu orang yang meriwayatkan hadits ini namanya Fidldlah Bashri, sedangkan yang lainnya bernama Abdul Aziz bin Abu Sulaiman, yang satu orang Bashrah, sedangkan yang lainnya orang Madinah dan keduanya hidup dalam satu masa."},"2066":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ أَنَسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُكْثِرُ أَنْ يَقُولَ يَا مُقَلِّبَ الْقُلُوبِ ثَبِّتْ قَلْبِي عَلَى دِينِكَ فَقُلْتُ يَا رَسُولَ اللَّهِ آمَنَّا بِكَ وَبِمَا جِئْتَ بِهِ فَهَلْ تَخَافُ عَلَيْنَا قَالَ نَعَمْ إِنَّ الْقُلُوبَ بَيْنَ أُصْبُعَيْنِ مِنْ أَصَابِعِ اللَّهِ يُقَلِّبُهَا كَيْفَ يَشَاءُقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ النَّوَّاسِ بْنِ سَمْعَانَ وَأُمِّ سَلَمَةَ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو وَعَائِشَةَ وَهَذَا حَدِيثٌ حَسَنٌ وَهَكَذَا رَوَى غَيْرُ وَاحِدٍ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ أَنَسٍ وَرَوَى بَعْضُهُمْ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَحَدِيثُ أَبِي سُفْيَانَ عَنْ أَنَسٍ أَصَحُّ","id":"Telah menceritakan kepada kami [Hannad]; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Sufyan] dari [Anas] dia berkata; adalah Rasulullah shallallahu 'alaihi wasallam terbiasa membaca do'a \"YA MUQALLIBAL QULUUB TSABBIT QALBII 'ALAA DIINIKA (wahai Dzat yang membolak balikkan hati teguhkanlah hatiku berada di atas agamamu).\" Kemudian aku pun bertanya, \"Wahai Rasulullah, kami beriman kepadamu dan kepada apa yang Anda bawa. Lalu apakah Anda masih khawatir kepada kami?\" beliau menjawab: \"Ya, karena sesungguhnya hati manusia berada di antara dua genggaman tangan Allah yang Dia bolak-balikkan menurut yang dikehendaki-Nya.\" Abu Isa berkata; Hadits semakna juga diriwayatkan dari An Nawwas bin Sam'an, Ummu Salamah, Abdullah bin Amr dan A'isyah. Dan ini adalah hadits Hasan, demikianlah kebanyakan telah meriwayatkannya dari Al A'masy dari Abu Sufyan dari Anas, dan sebagian yang lainnya telah meriwayatkannya dari [Al A'masy] dari [Abu Sufyan] dari [Jabir] dari Nabi shallallahu 'alaihi wasallam, namun hadits Abu Sufyan dari Anas lebih shahih."},"2067":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ أَبِي قَبِيلٍ عَنْ شُفَيِّ بْنِ مَاتِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِ قَالَخَرَجَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفِي يَدِهِ كِتَابَانِ فَقَالَ أَتَدْرُونَ مَا هَذَانِ الْكِتَابَانِ فَقُلْنَا لَا يَا رَسُولَ اللَّهِ إِلَّا أَنْ تُخْبِرَنَا فَقَالَ لِلَّذِي فِي يَدِهِ الْيُمْنَى هَذَا كِتَابٌ مِنْ رَبِّ الْعَالَمِينَ فِيهِ أَسْمَاءُ أَهْلِ الْجَنَّةِ وَأَسْمَاءُ آبَائِهِمْ وَقَبَائِلِهِمْ ثُمَّ أُجْمِلَ عَلَى آخِرِهِمْ فَلَا يُزَادُ فِيهِمْ وَلَا يُنْقَصُ مِنْهُمْ أَبَدًا ثُمَّ قَالَ لِلَّذِي فِي شِمَالِهِ هَذَا كِتَابٌ مِنْ رَبِّ الْعَالَمِينَ فِيهِ أَسْمَاءُ أَهْلِ النَّارِ وَأَسْمَاءُ آبَائِهِمْ وَقَبَائِلِهِمْ ثُمَّ أُجْمِلَ عَلَى آخِرِهِمْ فَلَا يُزَادُ فِيهِمْ وَلَا يُنْقَصُ مِنْهُمْ أَبَدًا فَقَالَ أَصْحَابُهُ فَفِيمَ الْعَمَلُ يَا رَسُولَ اللَّهِ إِنْ كَانَ أَمْرٌ قَدْ فُرِغَ مِنْهُ فَقَالَ سَدِّدُوا وَقَارِبُوا فَإِنَّ صَاحِبَ الْجَنَّةِ يُخْتَمُ لَهُ بِعَمَلِ أَهْلِ الْجَنَّةِ وَإِنْ عَمِلَ أَيَّ عَمَلٍ وَإِنَّ صَاحِبَ النَّارِ يُخْتَمُ لَهُ بِعَمَلِ أَهْلِ النَّارِ وَإِنْ عَمِلَ أَيَّ عَمَلٍ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدَيْهِ فَنَبَذَهُمَا ثُمَّ قَالَ فَرَغَ رَبُّكُمْ مِنْ الْعِبَادِ فَرِيقٌ فِي الْجَنَّةِ وَفَرِيقٌ فِي السَّعِيرِحَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا بَكْرُ بْنُ مُضَرٍ عَنْ أَبِي قَبِيلٍ نَحْوَهُ قَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ ابْنِ عُمَرَ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ وَأَبُو قَبِيلٍ اسْمُهُ حُيَيُّ بْنُ هَانِئٍ","id":"Telah menceritakan kepada kami [Qutaibah]; telah menceritakan kepada kami [Al Laits] dari [Abu Qabil] dari [Syufayyi bin Mati'] dari ['Abdullah bin 'Amr bin Al 'Ash] dia berkata; Rasulullah shallallahu 'alaihi wasallam keluar menemui kami sementara di tangan beliau terdapat dua kitab. Kemudian beliau pun bertanya: \"Apakah kalian tahu kitab apakah kedua kitab ini?\" Maka kami pun menjawab: \"Tidak wahai Rasulullah, kecuali Anda mengabarkannya pada kami.\" Akhirnya beliau pun bersabda terkait dengan kitab yang berada pada tangan kanannya: \"Ini adalah kitab yang berasal dari Rabb semesta alam. Di dalamnya terdapat nama-nama penduduk surga dan juga nama-nama orang tua serta kabilah mereka. Jumlahnya telah ditutup dengan orang yang terakhir dari mereka, dan tidak akan ditambah dan jumlah mereka tidak pula dikurangi lagi.\" Kemudian beliau bersabda terkait dengan kitab yang berada di tangan kirinya: \"Adapun ini, ia adalah kitab yang juga berasal dari Rabb semesta alam. Di dalamnya telah tercantum nama-nama penghuni neraka, dan juga nama-nama bapak mereka serta kabilah mereka, dan telah dijumlah dengan orang yang terakhir dari mereka. Sehingga jumlah mereka tidak lagi akan bertambah dan tidak pula akan berkurang selama-lamanya.\" Kemudian para sahabat pun berkata, \"Kalau begitu, dimanakah letaknya amalan wahai Rasulullah jika memang perkara sudah habis?\" beliau menjawab: \"Berusahalah dan mendekatlah, karena sesungguhnya penduduk surga akan ditutup dengan amalan penduduk ahli surga, meskipun ia mengamalkan amalan apa saja. Dan sesungguhnya penduduk neraka akan ditutup pula dengan amalan penduduk neraka, meskipun ia mengerjakan amalan apa saja.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda dengan kedua tangannya lalu menghempaskannya dan bersabda: \"Sesungguhnya Allah telah selesai terhadap urusan para hamba-Nya. Satu golongan di dalam surga dan satu kelompok pula di dalam neraka.\" Telah menceritakan kepada kami [Qutaibah]; telah menceritakan kepada kami [Bakr bin Mudhar] dari [Abu Qabil] dengan hadits semisalnya. Abu Isa berkata; Hadits semakna juga diriwayatkan dari Ibnu Umar. Dan hadits ini adalah Hasan Shahih Gharib. Abu Qabil, namanya adalah Huyaiy bin Hani`."},"2068":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ جَعْفَرٍ عَنْ حُمَيْدٍ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَرَادَ اللَّهُ بِعَبْدٍ خَيْرًا اسْتَعْمَلَهُ فَقِيلَ كَيْفَ يَسْتَعْمِلُهُ يَا رَسُولَ اللَّهِ قَالَ يُوَفِّقُهُ لِعَمَلٍ صَالِحٍ قَبْلَ الْمَوْتِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami ['Ali bin Hujr]; telah menceritakan kepada kami [Isma'il bin Ja'far] dari [Humaid] dari [Anas] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila Allah menghendaki kebaikan bagi seorang hamba, maka Dia akan menggunakannya.\" Lalu ditanyakanlah pada beliau, \"Bagaimanakah Allah menggunakannya wahai Rasulullah?\" beliau menjawab: \"Dia akan memberinya taufiq untuk beramal shalih sebelum dijemput kematian.\" Abu Isa berkata; Ini adalah hadits hasan shahih. "},"2069":{"ar":"حَدَّثَنَا بُنْدَارٌ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ عُمَارَةَ بْنِ الْقَعْقَاعِ حَدَّثَنَا أَبُو زُرْعَةَ بْنُ عَمْرِو بْنِ جَرِيرٍ قَالَ حَدَّثَنَا صَاحِبٌ لَنَا عَنْ ابْنِ مَسْعُودٍ قَالَقَامَ فِينَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَا يُعْدِي شَيْءٌ شَيْئًا فَقَالَ أَعْرَابِيٌّ يَا رَسُولَ اللَّهِ الْبَعِيرُ الْجَرِبُ الْحَشَفَةُ بِذَنَبِهِ فَتَجْرَبُ الْإِبِلُ كُلُّهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَنْ أَجْرَبَ الْأَوَّلَ لَا عَدْوَى وَلَا صَفَرَ خَلَقَ اللَّهُ كُلَّ نَفْسٍ وَكَتَبَ حَيَاتَهَا وَرِزْقَهَا وَمَصَائِبَهَاقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَابْنِ عَبَّاسٍ وَأَنَسٍ قَالَ و سَمِعْت مُحَمَّدَ بْنَ عَمْرِو بْنِ صَفْوَانَ الثَّقَفِيَّ الْبَصْرِيَّ قَال سَمِعْتُ عَلِيَّ بْنَ الْمَدِينِيِّ يَقُولُ لَوْ حَلَفْتُ بَيْنَ الرُّكْنِ وَالْمَقَامِ لَحَلَفْتُ أَنِّي لَمْ أَرَ أَحَدًا أَعْلَمَ مِنْ عَبْدِ الرَّحْمَنِ بْنِ مَهْدِيٍّ","id":"Telah menceritakan kepada kami [Bundar]; telah menceritakan kepada kami ['Abdurrahman bin Mahdi]; telah menceritakan kepada kami [Sufyan] dari ['Umarah bin Al Qa'qa']; telah menceritakan kepada kami [Abu Zur'ah bin 'Amr bin Jarir] dia berkata; [seorang sahabat kami] telah menceritakan kepada kami dari [Ibnu Mas'ud] dia berkata; Rasulullah shallallahu 'alaihi wasallam berdiri dihadapan kami lalu bersabda: \"Sesuatu tidak dapat menular kepada sesuatu yang lain.\" Lantas, berkatalah seorang Arab Badui, \"Wahai Rasulullah, bagaimana dengan kemaluan Unta yang berkudis melalui ekornya kemudian menjalar keseluruh Unta?\" Maka Rasulullah shallallahu 'alaihi wasallam pun menjawab: \"Siapakah yang menjadikan kudis pertama? Tidak ada penyakit dan cacing yang menular, Allah telah menciptakan setiap yang bernyawa dan telah mencatat hidupnya, rizkinya, dan musibah musibahnya.\" Abu Isa berkata; Hadits semakna juga diriwayatkan dari Abu Hurairah, Ibnu Abbas dan Anas. Dan aku telah mendengar Muhammad bin Amr bin Sufyan Ats Tsaqafi Al Bashri berkata; Aku mendengar Ali bin Al Madini berkata, \"Seandainya aku bersumpah di antara rukun (Hajar Aswad) dan maqam (maqam Ibrahim) pasti aku akan bersumpah bahwa sesungguhnya aku tidak pernah melihat seseorang yang lebih alim (pandai) dari Abdur Rahman bin Mahdi.\""},"2070":{"ar":"حَدَّثَنَا أَبُو الْخَطَّابِ زِيَادُ بْنُ يَحْيَى الْبَصْرِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَيْمُونٍ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُؤْمِنُ عَبْدٌ حَتَّى يُؤْمِنَ بِالْقَدَرِ خَيْرِهِ وَشَرِّهِ حَتَّى يَعْلَمَ أَنَّ مَا أَصَابَهُ لَمْ يَكُنْ لِيُخْطِئَهُ وَأَنَّ مَا أَخْطَأَهُ لَمْ يَكُنْ لِيُصِيبَهُقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عُبَادَةَ وَجَابِرٍ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو وَهَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ عَبْدِ اللَّهِ بْنِ مَيْمُونٍ وَعَبْدُ اللَّهِ بْنُ مَيْمُونٍ مُنْكَرُ الْحَدِيثِ","id":"Telah menceritakan kepada kami [Abul Khaththab Ziyad bin Yahya Al Bashri]; telah menceritakan kepada kami ['Abdullah bin Maimun] dari [Ja'far bin Muhammad] dari [bapaknya] dari [Jabir bin 'Abdullah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang hamba tidak dikatakan beriman sampai dia mengimani tentang takdir yang baik dan takdir yang buruk, sampai dia mengetahui bahwa apa yang menimpanya tidak mungkin akan meleset darinya, dan sesuatu yang tidak ditetapkan atasnya tidak akan mungkin mengenainya.\" Abu Isa berkata; Hadits semakna juga diriwayatkan dari Ubadah, Jabir dan Abdullah bin Amr, dan ini adalah hadits gharib, kami tidak mengetahuinya kecuali dari hadits Abdullah bin Maymun, sedangkan Abdullah bin Maymun adalah seorang Munkarul Hadits (Hadits haditsnya munkar)."},"2071":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ أَنْبَأَنَا شُعْبَةُ عَنْ مَنْصُورٍ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ عَنْ عَلِيٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُؤْمِنُ عَبْدٌ حَتَّى يُؤْمِنَ بِأَرْبَعٍ يَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنِّي مُحَمَّدٌ رَسُولُ اللَّهِ بَعَثَنِي بِالْحَقِّ وَيُؤْمِنُ بِالْمَوْتِ وَبِالْبَعْثِ بَعْدَ الْمَوْتِ وَيُؤْمِنُ بِالْقَدَرِحَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا النَّضْرُ بْنُ شُمَيْلٍ عَنْ شُعْبَةَ نَحْوَهُ إِلَّا أَنَّهُ قَالَ رِبْعِيٌّ عَنْ رَجُلٍ عَنْ عَلِيٍّ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي دَاوُدَ عَنْ شُعْبَةَ عِنْدِي أَصَحُّ مِنْ حَدِيثِ النَّضْرِ وَهَكَذَا رَوَى غَيْرُ وَاحِدٍ عَنْ مَنْصُورٍ عَنْ رِبْعِيٍّ عَنْ عَلِيٍّ حَدَّثَنَا الْجَارُودُ قَال سَمِعْتُ وَكِيعًا يَقُولُ بَلَغَنَا أَنَّ رِبْعِيًّا لَمْ يَكْذِبْ فِي الْإِسْلَامِ كِذْبَةً","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan]; telah menceritakan kepada kami [Abu Dawud]; dia berkata; telah memberitakan kepada kami [Syu'bah] dari [Manshur] dari [Rib'i bin Hirasy] dari ['Ali] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah beriman seorang hamba sehingga dia mengimani empat hal; Bersaksi bahwasanya tidak ada Ilah (yang berhak disembah) selain Allah dan aku adalah Muhammad utusan Allah yang Dia utus dengan membawa Al Haq (kebenaran), beriman kepada adanya kematian, beriman kepada adanya hari kebangkitan setelah kematian, dan beriman kepada taqdir.\" Telah menceritakan kepada kami [Mahmud bin Ghailan]; telah menceritakan kepada kami [An Nadhr bin Syumail] dari [Syu'bah] dengan hadits semisalnya. Hanya saja ia menyebutkan; Dari [Rib'i] dari [seorang laki-laki] dari [Ali]. Abu Musa berkata; Haditsnya Abu Dawud dari Syu'bah, menurutku adalah lebih shahih daripada hadits An Nadlr. Dan seperti ini pula yang telah diriwayatkan oleh lebih dari satu orang perawi dari [Manshur] dari [Rib'i] dari ['Ali]. Telah menceritakan kepada kami Al Jarud dia berkata; aku mendengar Waki' berkata; telah sampai kepada kami bahwasanya Rib'i tidak berdusta dalam Islam sekali pun."},"2072":{"ar":"حَدَّثَنَا بُنْدَارٌ حَدَّثَنَا مُؤَمَّلٌ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ مَطَرِ بْنِ عُكَامِسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَضَى اللَّهُ لِعَبْدٍ أَنْ يَمُوتَ بِأَرْضٍ جَعَلَ لَهُ إِلَيْهَا حَاجَةًقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أَبِي عَزَّةَ وَهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَلَا يُعْرَفُ لِمَطَرِ بْنِ عُكَامِسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَيْرُ هَذَا الْحَدِيثِ حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا مُؤَمَّلٌ وَأَبُو دَاوُدَ الْحَفَرِيُّ عَنْ سُفْيَانَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Bundar]; telah menceritakan kepada kami [Muammal]; telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq] dari [Mathar bin 'Ukamis] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila Allah telah menetapkan kematian seseorang bertempat di suatu negeri, maka Allah akan menjadikan ia memiliki kebutuhan di negeri itu.\" Abu Isa berkata; Hadits semakna juga diriwayatkan dari Abu 'Azzah. Dan hadits ini adalah Hasan Gharib, dan Mathar bin Ukamis tidak diketahui memiliki periwayatan dari Nabi shallallahu 'alaihi wasallam selain daripada hadits ini. Telah menceritakan kepada kami [Mahmud bin Ghailan]; telah menceritakan kepada kami [Muammmal] dan [Abu Dawud Al Hafari] dari [Sufyan] dengan hadits semisalnya."},"2073":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ وَعَلِيُّ بْنُ حُجْرٍ الْمَعْنَى وَاحِدٌ قَالَا حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ أَيُّوبَ عَنْ أَبِي الْمَلِيحِ بْنِ أُسَامَةَ عَنْ أَبِي عَزَّةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَضَى اللَّهُ لِعَبْدٍ أَنْ يَمُوتَ بِأَرْضٍ جَعَلَ لَهُ إِلَيْهَا حَاجَةً أَوْ قَالَ بِهَا حَاجَةًقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ صَحِيحٌ وَأَبُو عَزَّةَ لَهُ صُحْبَةٌ وَاسْمُهُ يَسَارُ بْنُ عَبْدٍ وَأَبُو الْمَلِيحِ اسْمُهُ عَامِرُ بْنُ أُسَامَةَ بْنِ عُمَيْرٍ الْهُذَلِيُّ وَيُقَالُ زَيْدُ بْنُ أُسَامَةَ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] dan ['Ali bin Hujr] dengan makna yang satu, mereka berdua berkata; telah menceritakan kepada kami [Isma'il bin Ibrahim] dari [Ayyub] dari [Abul Malih bin Usamah] dari [Abu 'Izzah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila Allah telah menetapkan kematian seorang hamba di suatu negeri, maka Allah jadikan dia mempunyai keperluan kepadanya, atau ada keperluan di dalamnya.\" Abu Isa berkata; Hadits ini Shahih, dan Abu 'Azzah pernah bertemu dengan Nabi shallallahu 'alaihi wasallam, namanya adalah Yasar bin Abd. Sedangkan Abul Malih namanya adalah 'Amir bin Usamah bin Umair Al Hudzali dan dinamakan juga Zaid bin Usamah."},"2074":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عَبْدِ الرَّحْمَنِ الْمَخْزُومِيُّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ ابْنِ أَبِي خُزَامَةَ عَنْ أَبِيهِأَنَّ رَجُلًا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أَرَأَيْتَ رُقًى نَسْتَرْقِيهَا وَدَوَاءً نَتَدَاوَى بِهِ وَتُقَاةً نَتَّقِيهَا هَلْ تَرُدُّ مِنْ قَدَرِ اللَّهِ شَيْئًا فَقَالَ هِيَ مِنْ قَدَرِ اللَّهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ الزُّهْرِيِّ وَقَدْ رَوَى غَيْرُ وَاحِدٍ هَذَا عَنْ سُفْيَانَ عَنْ الزُّهْرِيِّ عَنْ أَبِي خُزَامَةَ عَنْ أَبِيهِ وَهَذَا أَصَحُّ هَكَذَا قَالَ غَيْرُ وَاحِدٍ عَنْ الزُّهْرِيِّ عَنْ أَبِي خُزَامَةَ عَنْ أَبِيهِ","id":"Telah menceritakan kepada kami [Sa'id bin 'Abdurrahman Al Makhzumi]; telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dari [Ibnu Abu Khuzamah] dari [bapaknya] bahwasanya seorang lelaki mendatangi Nabi shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, bagaimanakah menurut Anda mengenai Ruqyah yang kita gunakan untuk meruqyah dan juga obat yang kita gunakan untuk berobat, dan hal-hal yang kita takuti, apakah semua itu dapat menolak takdir Allah?\" maka beliau menjawab: \"Hal itu juga termasuk takdir Allah.\" Abu Isa berkata; Hadits ini tidak kami ketahui kecuali dari haditsnya Az Zuhri. Dan hadits ini telah diriwayatkan pula oleh lebih dari seorang perawi dari Sufyan dari Az Zuhri, dari Abu Khuzamah, dari bapaknya. Dan ini lebih shahih. Seperti ini pula yang dikatakan oleh lebih dari seorang dari Az Zuhri dari Abu Khuzamah dari bapaknya."},"2075":{"ar":"حَدَّثَنَا وَاصِلُ بْنُ عَبْدِ الْأَعْلَى الْكُوفِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ الْقَاسِمِ بْنِ حَبِيبٍ وَعَلِيُّ بْنُ نِزَارٍ عَنْ نِزَارٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صِنْفَانِ مِنْ أُمَّتِي لَيْسَ لَهُمَا فِي الْإِسْلَامِ نَصِيبٌ الْمُرْجِئَةُ وَالْقَدَرِيَّةُقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عُمَرَ وَابْنِ عُمَرَ وَرَافِعِ بْنِ خَدِيجٍ وَهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ حَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ حَدَّثَنَا سَلَّامُ بْنُ أَبِي عَمْرَةَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مُحَمَّدُ بْنُ رَافِعٍ وَحَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ حَدَّثَنَا عَلِيُّ بْنُ نِزَارٍ عَنْ نِزَارٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Washil bin 'Abdul A'la Al Kufi]; telah menceritakan kepada kami [Muhammad bin Fudhail] dari [Al Qasim bin Habib] dan ['Ali bin Nizar] dari [Nizar] dari ['Ikrimah] dari [Ibnu 'Abbas] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dua kelompok dari ummatku yang keduanya tidak termasuk bagian dari Islam yaitu Al Qadariyah dan Murji'ah.\" Abu Isa berkata; Hadits semakna juga diriwayatkan dari Umar, Ibnu Umar dan Rafi' bin Khadij, dan hadits ini hasan gharib. Telah menceritakan kepada kami [Muhammad bin Rafi']; telah menceritakan kepada kami [Muhammad bin Bisyr]; telah menceritakan kepada kami [Sallam bin Abu 'Amrah] dari ['Ikrimah] dari [Ibnu 'Abbas] dari Nabi shallallahu 'alaihi wasallam. [Muhammad bin Rafi'] berkata; dan telah menceritakan kepada kami [Muhammad bin Bisyr]; telah menceritakan kepada kami ['Ali bin Nizar] dari [Nizar] dari ['Ikrimah] dari [Ibnu 'Abbas] dari Nabi shallallahu 'alaihi wasallam semisalnya."},"2076":{"ar":"حَدَّثَنَا أَبُو هُرَيْرَةَ مُحَمَّدُ بْنُ فِرَاسٍ الْبَصْرِيُّ حَدَّثَنَا أَبُو قُتَيْبَةَ حَدَّثَنَا أَبُو الْعَوَّامِ عَنْ قَتَادَةَ عَنْ مُطَرِّفِ بْنِ عَبْدِ اللَّهِ بْنِ الشِّخِّيرِ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مُثِّلَ ابْنُ آدَمَ وَإِلَى جَنْبِهِ تِسْعٌ وَتِسْعُونَ مَنِيَّةً إِنْ أَخْطَأَتْهُ الْمَنَايَا وَقَعَ فِي الْهَرَمِ حَتَّى يَمُوتَقَالَ أَبُو عِيسَى وَهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ وَأَبُو الْعَوَّامِ هُوَ عِمْرَانُ وَهُوَ ابْنُ دَاوَرَ الْقَطَّانُ","id":"Telah menceritakan kepada kami [Abu Hurairah Muhammad bin Firaz Al Bashri]; telah menceritakan kepada kami [Abu Qutaibah]; telah menceritakan kepada kami [Abul 'Awwam] dari [Qatadah] dari [Mutharrif bin 'Abdullah bin Asy Syikhkhir] dari [bapaknya] dari Nabi shallallahu 'alaihi wasallam, beliau berkata: \"Anak keturunan adam diciptakan sementara di sisinya (menghadang) sembilan puluh sembilan Maniyyah (sebab sebab kematian), jika selamat dari Maniyyah itu, maka dia akan terkena pada penyakit pikun sampai meninggal.\" Abu Isa berkata; Hadits ini hasan gharib, kami tidak mengetahuinya kecuali dari jalur sanad ini, adapun Abul 'Awwam dia adalah Imran dan dia adalah anaknya Daud Al Qaththan."},"2077":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَامِرٍ عَنْ مُحَمَّدِ بْنِ أَبِي حُمَيْدٍ عَنْ إِسْمَعِيلَ بْنِ مُحَمَّدِ بْنِ سَعْدِ بْنِ أَبِي وَقَّاصٍ عَنْ أَبِيهِ عَنْ سَعْدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ سَعَادَةِ ابْنِ آدَمَ رِضَاهُ بِمَا قَضَى اللَّهُ لَهُ وَمِنْ شَقَاوَةِ ابْنِ آدَمَ تَرْكُهُ اسْتِخَارَةَ اللَّهِ وَمِنْ شَقَاوَةِ ابْنِ آدَمَ سَخَطُهُ بِمَا قَضَى اللَّهُ لَهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ مُحَمَّدِ بْنِ أَبِي حُمَيْدٍ وَيُقَالُ لَهُ أَيْضًا حَمَّادُ بْنُ أَبِي حُمَيْدٍ وَهُوَ أَبُو إِبْرَاهِيمَ الْمَدَنِيُّ وَلَيْسَ هُوَ بِالْقَوِيِّ عِنْدَ أَهْلِ الْحَدِيثِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar]; telah menceritakan kepada kami [Abu 'Amir] dari [Muhammad bin Abu Humaid] dari [Isma'il bin Muhammad bin Sa'd bin Abi Waqqash] dari [bapaknya] dari [Sa'd] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Termasuk di antara kebahagiaan anak Adam, adalah rasa ridhanya terhadap apa yang telah Allah tetapkan baginya. Dan termasuk kesengsaraan seorang anak Adam, adalah bila ia meninggalkan istikharah kepada Allah. Dan termasuk kesusahan Ibnu Adam, adalah rasa benci dan tidak menerima terhap apa yang telah Allah tetapkan baginya.\" Abu Isa berkata; Ini adalah hadits gharib, kami tidak mengetahuinya kecuali dari haditsnya Muhammad bin Abu Humaid, dan dipanggil pula Hammad bin Abu Humaid, dan ia dalah Abu Ibrahim Al Madini, dan ia bukanlah seorang rawi yang kuat menurut Ahli hadits."},"2078":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَاصِمٍ حَدَّثَنَا حَيْوَةُ بْنُ شُرَيْحٍ أَخْبَرَنِي أَبُو صَخْرٍ قَالَ حَدَّثَنِي نَافِعٌ أَنَّ ابْنَ عُمَرَجَاءَهُ رَجُلٌ فَقَالَ إِنَّ فُلَانًا يَقْرَأُ عَلَيْكَ السَّلَامَ فَقَالَ لَهُ إِنَّهُ بَلَغَنِي أَنَّهُ قَدْ أَحْدَثَ فَإِنْ كَانَ قَدْ أَحْدَثَ فَلَا تُقْرِئْهُ مِنِّي السَّلَامَ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَكُونُ فِي هَذِهِ الْأُمَّةِ أَوْ فِي أُمَّتِي الشَّكُّ مِنْهُ خَسْفٌ أَوْ مَسْخٌ أَوْ قَذْفٌ فِي أَهْلِ الْقَدَرِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ وَأَبُو صَخْرٍ اسْمُهُ حُمَيْدُ بْنُ زِيَادٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar]; telah menceritakan kepada kami [Abu 'Ashim]; telah menceritakan kepada kami [Haiwah bin Syuraih]; telah mengabarkan kepadaku [Abu Shakhrah] dia berkata; telah menceritakan kepadaku [Nafi'] bahwasanya; [Ibnu Umar] pernah didatangi seorang lelaki kemudian berkata, \"Sesungguhnya si Fulan menyampaikan salam kepadamu.\" Kemudian Ali berkata kepada laki-laki itu, \"Sesungguhnya telah sampai berita kepadaku bahwa dia telah melakukan sesuatu yang baru (mengada-ada dalam urusan agama), jika dia telah melakukan sesuatu yang baru maka jangan sampaikan salamku kepadanya, karena aku telah mendengar Rosulullah shallallahu 'alaihi wasallam bersabda: 'Akan terjadi peristiwa pada ummat ini atau pada ummatku (kata Aw keraguan dari Tirmidzi) berupa dibinasakan, di ganti bentuknya dan tuduhan terhadap orang orang yang mengingkari takdir.'\" Abu Isa berkata; Hadits ini adalah hasan shahih gharib, dan Abu Shakhr namanya Humaid bin Ziyad."},"2079":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا رِشْدِينُ بْنُ سَعْدٍ عَنْ أَبِي صَخْرٍ حُمَيْدِ بْنِ زِيَادٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَكُونُ فِي أُمَّتِي خَسْفٌ وَمَسْخٌ وَذَلِكَ فِي الْمُكَذِّبِينَ بِالْقَدَرِ","id":"Telah menceritakan kepada kami [Qutaibah]; telah menceritakan kepada kami [Risydin bin Sa'd] dari [Abu Shakhr Humaid bin Ziyad] dari [Nafi'] dari [Ibnu 'Umar] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Akan terjadi pada umatku, yaitu kebinasaan. Dan hal itu akan terjadi pada orang-orang yang mengingkari takdir.\""},"2080":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ زَيْدِ بْنِ أَبِي الْمَوَالِي الْمُزَنِيُّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ مَوْهَبٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سِتَّةٌ لَعَنْتُهُمْ وَلَعَنَهُمْ اللَّهُ وَكُلُّ نَبِيٍّ كَانَ الزَّائِدُ فِي كِتَابِ اللَّهِ وَالْمُكَذِّبُ بِقَدَرِ اللَّهِ وَالْمُتَسَلِّطُ بِالْجَبَرُوتِ لِيُعِزَّ بِذَلِكَ مَنْ أَذَلَّ اللَّهُ وَيُذِلَّ مَنْ أَعَزَّ اللَّهُ وَالْمُسْتَحِلُّ لِحُرُمِ اللَّهِ وَالْمُسْتَحِلُّ مِنْ عِتْرَتِي مَا حَرَّمَ اللَّهُ وَالتَّارِكُ لِسُنَّتِيقَالَ أَبُو عِيسَى هَكَذَا رَوَى عَبْدُ الرَّحْمَنِ بْنُ أَبِي الْمَوَالِي هَذَا الْحَدِيثَ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ مَوْهَبٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَوَاهُ سُفْيَانُ الثَّوْرِيُّ وَحَفْصُ بْنُ غِيَاثٍ وَغَيْرُ وَاحِدٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ مَوْهَبٍ عَنْ عَلِيِّ بْنِ حُسَيْنٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْسَلًا وَهَذَا أَصَحُّ","id":"Telah menceritakan kepada kami [Qutaibah]; telah menceritakan kepada kami ['Abdurrahman bin Zaid bin Abul Mawali Al Muzani] dari ['Ubaidullah bin 'Abdurrahman bin Mauhab] dari ['Amrah] dari ['Aisyah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tiga orang yang aku, Allah dan setiap Nabi melaknat mereka yaitu orang yang menambah-nambah dalam kitabullah (Al Qur'an), orang yang mengingkari takdir Allah, orang yang berkuasa dengan diktator untuk memuliakan orang yang telah dihinakan oleh Allah dan menghinakan orang yang telah Allah muliakan, orang yang menghalalkan apa apa yang diharamkan Allah, orang yang menghalalkan Ahli Baitku yang telah diharamkan oleh Allah, dan orang yang meninggalkan sunnahku.\" Abu Isa berkata; Demikianlah Abdur Rahman bin Abul Mawali telah meriwayatkan hadits ini dari Ubaidillah bin Abdur Raman bin Mauhab dari 'Amrah dari A'isyah dari Nabi shallallahu 'alaihi wasallam. [Sufyan Ats Tsauri], [Hafs bin Ghiyats] dan yang lainnya telah meriwayatkan dari [Ubaidillah bin Abdur Rahman bin Mauhab] dari [Ali bin Husain] dari Nabi shallallahu 'alaihi wasallam secara mursal, dan ini yang lebih shahih."},"2081":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُوسَى حَدَّثَنَا أَبُو دَاوُدَ الطَّيَالِسِيُّ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ سُلَيْمٍ قَالَقَدِمْتُ مَكَّةَ فَلَقِيتُ عَطَاءَ بْنَ أَبِي رَبَاحٍ فَقُلْتُ لَهُ يَا أَبَا مُحَمَّدٍ إِنَّ أَهْلَ الْبَصْرَةِ يَقُولُونَ فِي الْقَدَرِ قَالَ يَا بُنَيَّ أَتَقْرَأُ الْقُرْآنَ قُلْتُ نَعَمْ قَالَ فَاقْرَأْ الزُّخْرُفَ قَالَ فَقَرَأْتُ{ حم وَالْكِتَابِ الْمُبِينِ إِنَّا جَعَلْنَاهُ قُرْآنًا عَرَبِيًّا لَعَلَّكُمْ تَعْقِلُونَ وَإِنَّهُ فِي أُمِّ الْكِتَابِ لَدَيْنَا لَعَلِيٌّ حَكِيمٌ }فَقَالَ أَتَدْرِي مَا أُمُّ الْكِتَابِ قُلْتُ اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ فَإِنَّهُ كِتَابٌ كَتَبَهُ اللَّهُ قَبْلَ أَنْ يَخْلُقَ السَّمَاوَاتِ وَقَبْلَ أَنْ يَخْلُقَ الْأَرْضَ فِيهِ إِنَّ فِرْعَوْنَ مِنْ أَهْلِ النَّارِ وَفِيهِ{ تَبَّتْ يَدَا أَبِي لَهَبٍ وَتَبَّ }قَالَ عَطَاءٌ فَلَقِيتُ الْوَلِيدَ بْنَ عُبَادَةَ بْنِ الصَّامِتِ صَاحِبَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلْتُهُ مَا كَانَ وَصِيَّةُ أَبِيكَ عِنْدَ الْمَوْتِ قَالَ دَعَانِي أَبِي فَقَالَ لِي يَا بُنَيَّ اتَّقِ اللَّهَ وَاعْلَمْ أَنَّكَ لَنْ تَتَّقِيَ اللَّهَ حَتَّى تُؤْمِنَ بِاللَّهِ وَتُؤْمِنَ بِالْقَدَرِ كُلِّهِ خَيْرِهِ وَشَرِّهِ فَإِنْ مُتَّ عَلَى غَيْرِ هَذَا دَخَلْتَ النَّارَ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ أَوَّلَ مَا خَلَقَ اللَّهُ الْقَلَمَ فَقَالَ اكْتُبْ فَقَالَ مَا أَكْتُبُ قَالَ اكْتُبْ الْقَدَرَ مَا كَانَ وَمَا هُوَ كَائِنٌ إِلَى الْأَبَدِقَالَ أَبُو عِيسَى وَهَذَا حَدِيثٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Yahya bin Musa]; telah menceritakan kepada kami [Abu Dawud Ath Thayalisi]; telah menceritakan kepada kami ['Abdul Wahid bin Sulaim]; dia berkata; Aku memasuki Makkah kemudian aku menemui ['Atha bin Abu Rabbah]. Maka aku berkata kepadanya, \"Wahai Abu Muhammad, sesungguhnya penduduk Bashrah memperbincangkan masalah Qadar.\" Lalu Atha' berkata, \"Wahai anakku, apakah kamu membaca Al Qur'an?\" Aku menjawab, \"Ya\" 'Atha` melanjutkan, \"Bacalah surat Az-Zukhruf.\" Abdul Wahid berkata; Maka aku pun membaca, \"HAA MIIM WAL KITAABIL MUBIIN, INNAA JA'ALNAAHU QUR'AANAN 'AROBIYYAN LA'ALLAKUM TA'QILUUN, WA INNAHU FII UMMIL KITAABI LADAINAA LA'ALIYYUN HAKIIM (HAA MIIM, Demi Kitab (Al Qur'an) yang menerangkan. Sesungguhnya Kami menjadikan Al Qur'an dalam bahasa Arab supaya kamu memahami-nya. Dan sesungguhnya Al Qur'an itu dalam induk Al Kitab (Lauhul Mahfudz) di sisi kami, adalah benar benar tinggi (nilainya) dan amat banyak mengandung hikmah).\" Kemudian Atha' bertanya, \" Apakah kamu tahu apa maksudnya Ummul Kitab?\" aku menjawab, \"Hanya Allah dan Rasul-Nya yang lebih tahu.\" Atha' berkata, \"Susungguhnya Ummul Kitab adalah kitab yang ditulis oleh Allah sebelum menciptakan langit dan bumi di dalamnya terdapat ayat yang menyatakan bahwa Fir'aun termasuk penghuni neraka, dan di dalamnya terdapat ayat, 'TABBAT YADAA ABII LAHABIW WATAB (Binasalah kedua tangan Abu Lahab dan sesungguhnya dia akan binasa).'\" Atha' berkata lagi; Aku bertemu dengan [Al Walid bin Ubadah bin Ash Shamith] sahabat Rasulullah shallallahu 'alaihi wasallam, aku tanyakan kepadanya tentang, \"Wasiat apakah yang di wasiatkan bapakmu pada saat saat wafat?\" Dia menjawab; [Bapakku] pernah memanggilku kemudian dia berkata kepadaku, \"Wahai anakku, bertakwalah kepada Allah dan ketahuilah sesungguhnya kamu tidak akan sekali kali bertakwa kepada Allah sehingga kamu beriman kepada Allah dan beriman kepada adanya takdir seluruhnya yang baik maupun yang buruk, jika kamu meninggal tidak berada di atas keimanan ini maka kamu akan masuk neraka, sesungguhnya aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Sesungguhnya yang pertama kali Allah ciptakan adalah Al Qalam kemudian Allah berfirman: 'Tulislah' Maka Al Qalam bertanya, 'Apa yang aku tulis? ' Lalu Allah berfirman: 'Tulislah takdir yang telah terjadi dan yang akan terjadi sepanjang masa.'\" Abu Isa berkata; Hadits ini adalah gharib bila ditinjau dari jalur sanad ini."},"2082":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُنْذِرِ الْبَاهِلِيُّ الصَّنْعَانِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ الْمُقْرِئُ حَدَّثَنَا حَيْوَةُ بْنُ شُرَيْحٍ حَدَّثَنِي أَبُو هَانِئٍ الْخَوْلَانِيُّ أَنَّهُ سَمِعَ أَبَا عَبْدِ الرَّحْمَنِ الْحُبُلِيَّ يَقُول�� سَمِعْتُ عَبْدَ اللَّهِ بْنَ عَمْرٍو يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ قَدَّرَ اللَّهُ الْمَقَادِيرَ قَبْلَ أَنْ يَخْلُقَ السَّمَاوَاتِ وَالْأَرْضَ بِخَمْسِينَ أَلْفَ سَنَةٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Ibrahim bin 'Abdullah bin Al Mundzir Al Bahili Ash Shan'ani]; telah menceritakan kepada kami ['Abdullah bin Yazid Al Muqri']; telah menceritakan kepada kami [Haiwah bin Syuraih]; telah menceritakan kepadaku [Abu Hani' Al Khaulani] bahwasanya dia mendengar [Abu 'Abdurrahman Al Hubuli] berkata; aku mendengar ['Abdullah bin 'Amr] berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah telah menentukan takdir segala sesuatu, lima puluh ribu tahun sebelum menciptakan lagit dan bumi.\" Abu Isa berkata; Ini adalah hadits hasan shahih gharib."},"2083":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ مُحَمَّدُ بْنُ الْعَلَاءِ وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ الثَّوْرِيِّ عَنْ زِيَادِ بْنِ إِسْمَعِيلَ عَنْ مُحَمَّدِ بْنِ عَبَّادِ بْنِ جَعْفَرٍ الْمَخْزُومِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَجَاءَ مُشْرِكُو قُرَيْشٍ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُخَاصِمُونَ فِي الْقَدَرِ فَنَزَلَتْ هَذِهِ الْآيَةُ{ يَوْمَ يُسْحَبُونَ فِي النَّارِ عَلَى وُجُوهِهِمْ ذُوقُوا مَسَّ سَقَرَ إِنَّا كُلَّ شَيْءٍ خَلَقْنَاهُ بِقَدَرٍ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Abu Kuraib Muhammad bin Al 'Ala] dan [Muhammad bin Basysyar] mereka berdua berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan Ats Tsauri] dari [Ziyad bin Isma'il] dari [Muhammad bin 'Abbad bin Ja'far Al Makhzumi] dari [Abu Hurairah] dia berkata; Orang-orang musyrik Quraisy datang kepada Rasulullah shallallahu 'alaihi wasallam guna memperdebatkan masalah takdir, maka turunlah ayat ini: \"Wajah-wajah mereka tersungkur di dalam neraka. (Dikatakanlah pada mereka) Rasakanlah siksa yang pedih, sesungguhnya segala sesuatu kami ciptakan dengan takdirnya.\" Abu Isa berkata; Ini adalah hadits hasan shahih."},"2084":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ الضَّبِّيُّ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ أَبِي أُمَامَةَ بْنِ سَهْلِ بْنِ حُنَيْفٍ أَنَّ عُثْمَانَ بْنَ عَفَّانَأَشْرَفَ يَوْمَ الدَّارِ فَقَالَ أَنْشُدُكُمْ اللَّهَ أَتَعْلَمُونَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَحِلُّ دَمُ امْرِئٍ مُسْلِمٍ إِلَّا بِإِحْدَى ثَلَاثٍ زِنًا بَعْدَ إِحْصَانٍ أَوْ ارْتِدَادٍ بَعْدَ إِسْلَامٍ أَوْ قَتْلِ نَفْسٍ بِغَيْرِ حَقٍّ فَقُتِلَ بِهِ فَوَاللَّهِ مَا زَنَيْتُ فِي جَاهِلِيَّةٍ وَلَا فِي إِسْلَامٍ وَلَا ارْتَدَدْتُ مُنْذُ بَايَعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا قَتَلْتُ النَّفْسَ الَّتِي حَرَّمَ اللَّهُ فَبِمَ تَقْتُلُونَنِيقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ ابْنِ مَسْعُودٍ وَعَائِشَةَ وَابْنِ عَبَّاسٍ وَهَذَا حَدِيثٌ حَسَنٌ وَرَوَاهُ حَمَّادُ بْنُ سَلَمَةَ عَنْ يَحْيَى بْنِ سَعِيدٍ فَرَفَعَهُ وَرَوَى يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ وَغَيْرُ وَاحِدٍ عَنْ يَحْيَى بْنِ سَعِيدٍ هَذَا الْحَدِيثَ فَأَوْقَفُوهُ وَلَمْ يَرْفَعُوهُ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ مِنْ غَيْرِ وَجْهٍ عَنْ عُثْمَانَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرْفُوعًا","id":"Telah menceritakan kepada kami [Ahmad bin 'Abdah Adh Dhabi]; telah menceritakan kepada kami [Hammad bin Zaid] dari [Yahya bin Sa'id] dari [Abu Umamah bin Sahl bin Hunaif] bahwasanya ['Utsman bin 'Affan] memuliakan hari Ad Dari, maka ia pun berkata; Apakah kalian tahu bahwa Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Darah seorang mukmin tidaklah halal kecuali dengan salah satu sebab dari tiga perkara, yakni berzina setelah nikah, atau murtad setelah memeluk Islam, atau membunuh jiwa secara tidak benar, sehingga ia pun dibunuh karenanya.\" Maka demi Allah, aku tidak pernah berzina pada masa jahiliyah, dan tidak pula setelah Islam. Aku juga tidak pernah murtad semenjak aku membai'at Rasulullah shallallahu 'alaihi wasallam, dan aku tidak pula pernah membunuh jiwa yang telah Allah haramkan, lalu dengan alasan apa kalian membunuhku? Abu Isa berkata; Hadits semakna juga diriwayatkan dari Ibnu Mas'ud, Aisyah dan Ibnu Abbas. Dan ini adalah hadits hasan. Hadits ini juga diriwayatkan oleh [Hammad bin Salamah] dari [Yahya bin Sa'id] lalu ia memarfu'kannya. Yahya bin Sa'id Al Qaththan dan lebih dari seorang telah meriwayatkan hadits ini dari dari Yahya bin Sa'id namun mereka mewaqafkannya. Dan hadits ini telah diriwayatkan pula oleh lebih dri seorang rawi dari Utsman dari Nabi shallallahu 'alaihi wasallam secara marfu'."},"2085":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ شَبِيبِ بْنِ غَرْقَدَةَ عَنْ سُلَيْمَانَ بْنِ عَمْرِو بْنِ الْأَحْوَصِ عَنْ أَبِيهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي حَجَّةِ الْوَدَاعِ لِلنَّاسِ أَيُّ يَوْمٍ هَذَا قَالُوا يَوْمُ الْحَجِّ الْأَكْبَرِ قَالَ فَإِنَّ دِمَاءَكُمْ وَأَمْوَالَكُمْ وَأَعْرَاضَكُمْ بَيْنَكُمْ حَرَامٌ كَحُرْمَةِ يَوْمِكُمْ هَذَا فِي بَلَدِكُمْ هَذَا أَلَا لَا يَجْنِي جَانٍ إِلَّا عَلَى نَفْسِهِ أَلَا لَا يَجْنِي جَانٍ عَلَى وَلَدِهِ وَلَا مَوْلُودٌ عَلَى وَالِدِهِ أَلَا وَإِنَّ الشَّيْطَانَ قَدْ أَيِسَ مِنْ أَنْ يُعْبَدَ فِي بِلَادِكُمْ هَذِهِ أَبَدًا وَلَكِنْ سَتَكُونُ لَهُ طَاعَةٌ فِيمَا تَحْتَقِرُونَ مِنْ أَعْمَالِكُمْ فَسَيَرْضَى بِهِقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أَبِي بَكْرَةَ وَابْنِ عَبَّاسٍ وَجَابِرٍ وَحِذْيَمِ بْنِ عَمْرٍو السَّعْدِيِّ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَرَوَى زَائِدَةُ عَنْ شَبِيبِ بْنِ غَرْقَدَةَ نَحْوَهُ وَلَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ شَبِيبِ بْنِ غَرْقَدَةَ","id":"Telah menceritakan kepada kami [Hannad]; telah menceritakan kepada kami [Abul Ahwash] dari [Syabib bin Gharqadah] dari [Sulaiman bin 'Amr bin Al Ahwash] dari [bapaknya], dia berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda ketika haji wada': \"Hari apakah ini?\" Mereka pun menjawab, \"Hari haji akbar.\" Kemudian beliau bersabda: \"Sesungguhnya darah kalian, harta kalian dan harga diri kalian adalah haram (untuk dirusak) di antara kalian sebagaimana haramnya (sucinya) hari ini, di negeri kalian ini. Ketahuilah, janganlah seseorang berbuat aniaya kecuali kepada dirinya sendiri, janganlah seseorang berbuat aniaya kepada anaknya dan jangan juga seorang anak kepada orang tuanya. Ketahuilah, sesungguhnya syetan telah putus asa untuk disembah di negeri kalian ini selamanya, namun akan terjadi ketaatan kepadanya dalam amal perbuatan yang kalian remehkan sehingga dia akan ridla kepadanya.\" Abu Isa berkata; Hadits semakna juga diriwayatkan dari Abu Bakrah, Ibnu Abbas, Jabir dan Hidzyam bin Amr As Sa'di, dan hadits ini hasan shahih. [Za'idah] telah meriwayatkan hadits yang semakna dari [Syabib bin Gharqadah], dan kami tidak mengetahuinya kecuali dari hadits Syabib bin Gharqadah."},"2086":{"ar":"حَدَّثَنَا بُنْدَارٌ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ السَّائِبِ بْنِ يَزِيدَ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَأْخُذْ أَحَدُكُمْ عَصَا أَخِيهِ لَاعِبًا أَوْ جَادًّا فَمَنْ أَخَذَ عَصَا أَخِيهِ فَلْيَرُدَّهَا إِلَيْهِقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ ابْنِ عُمَرَ وَسُلَيْمَانَ بْنِ صُرَدَ وَجَعْدَةَ وَأَبِي هُرَيْرَةَ وَهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ ابْنِ أَبِي ذِئْبٍ وَالسَّائِبُ بْنُ يَزِيدَ لَهُ صُحْبَةٌ قَدْ سَمِعَ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحَادِيثَ وَهُوَ غُلَامٌ وَقُبِضَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ ابْنُ سَبْعِ سِنِينَ وَوَالِدُهُ يَزِيدُ بْنُ السَّائِبِ لَهُ أَحَادِيثُ هُوَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ رَوَى عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالسَّائِبُ بْنُ يَزِيدَ هُوَ ابْنُ أُخْتِ نَمِرٍ","id":"Telah menceritakan kepada kami [Bundar]; telah menceritakan kepada kami [Yahya bin Sa'id]; telah menceritakan kepada kami [Ibnu Abu Dzi'b]; telah menceritakan kepada kami ['Abdullah bin As Saib bin Yazid] dari [bapaknya] dari [kakeknya] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah salah seorang dari kalian mengambil tombak saudaranya baik dengan bermaksud main-main ataupun sungguh-sungguh. Maka siapa yang mengambil tombak saudaranya, hendaklah ia mengembalikan tombak itu padanya.\" Abu Isa berkata; Hadits semakna juga diriwayatkan dari Ibnu Umar, Sulaiman bin Shurad, Jad'ah, dan Abu Hurairah. Dan hadits ini adalah hasan gharib, kami tidak mengetahuinya kecuali dari haditsnya Ibnu Abu Dzi`b dan As Sa`ib bin, ia memliki shuhbah (bermulazamah dengan Nabi) dan ia telah mendengar dari Nabi shallallahu 'alaihi wasallam sejumlah hadits saat ia masih anak kecil. Ketika Nabi shallallahu 'alaihi wasallam wafat, ia baru berumur tujuh tahun. Sedangkan bapaknya Yazid bin As Sa`ib, juga memiliki hadits-hadits, dan ia juga termasuk sahabat Rasulullah shallallahu 'alaihi wasallam. Ia telah meriwayatkan pula dari Nabi shallallahu 'alaihi wasallam. As Sa`ib bin Yazid adalah anak dari saudara perempuannya Namir."},"2087":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ عَنْ مُحَمَّدِ بْنِ يُوسُفَ عَنْ السَّائِبِ بْنِ يَزِيدَ قَالَحَجَّ يَزِيدُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَجَّةَ الْوَدَاعِ وَأَنَا ابْنُ سَبْعِ سِنِينَفَقَالَ عَلِيُّ بْنُ الْمَدِينِيِّ عَنْ يَحْيَى بْنِ سَعِيدٍ الْقَطَّانِ كَانَ مُحَمَّدُ بْنُ يُوسُفَ ثَبْتًا صَاحِبَ حَدِيثٍ وَكَانَ السَّائِبُ بْنُ يَزِيدَ جَدَّهُ وَكَانَ مُحَمَّدُ بْنُ يُوسُفَ يَقُولُ حَدَّثَنِي السَّائِبُ بْنُ يَزِيدَ وَهُوَ جَدِّي مِنْ قِبَلِ أُمِّي","id":"Telah menceritakan kepada kami [Qutaibah]; telah menceritakan kepada kami [Hatim bin Isma'il] dari [Muhammad bin Yusuf] dari [As Saib bin Yazid] dia berkata; Yazid berhaji bersama Nabi shallallahu 'alaihi wasallam pada saat haji Wada', sementa saat itu adalah anak yang baru menginjak usia tujuh tahun. Kemudian berkatalah Ali bin Al Madini, dari Yahya bin Sa'id Al Qaththan; Muhammad bin Yusuf adalah seorang yang tsabit, dan juga memiliki beberapa periwayatan hadits. Sedangkan As Sa`ib bin Yazid adalah kakeknya. Muhammad bin Yusuf berkata; Telah menceritakan kepadaku As Sa`ib bin Yazid dan ia adalah kakekku dari jalur ibuku."},"2088":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الصَّبَّاحِ الْعَطَّارُ الْهَاشِمِيُّ حَدَّثَنَا مَحْبُوبُ بْنُ الْحَسَنِ حَدَّثَنَا خَالِدٌ الْحَذَّاءُ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَشَارَ عَلَى أَخِيهِ بِحَدِيدَةٍ لَعَنَتْهُ الْمَلَائِكَةُقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أَبِي بَكْرَةَ وَعَائِشَةَ وَجَابِرٍ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ يُسْتَغْرَبُ مِنْ حَدِيثِ خَالِدٍ الْحَذَّاءِ وَرَوَاهُ أَيُّوبُ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ نَحْوَهُ وَلَمْ يَرْفَعْهُ وَزَادَ فِيهِ وَإِنْ كَانَ أَخَاهُ لِأَبِيهِ وَأُمِّهِ قَالَ و أَخْبَرَنَا بِذَلِكَ قُتَيْبَةُ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ بِهَذَا","id":"Telah menceritakan kepada kami ['Abdullah bin Ash Shabbah Al 'Aththar Al Hasyimi]; telah menceritakan kepada kami [Mahbub bin Al Hasan]; telah menceritakan kepada kami [Khalid Al Hadza'] dari [Muhammad bin Sirin] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Barangsiapa yang menghunuskan besi kepada saudaranya maka Malaikat akan melaknatnya.\" Abu Isa berkata; Hadits semakna juga diriwayatkan dari Abu Bakrah, A'isyah dan Jabir. Hadits ini adalah hadits hasan shahih gharib dari jalur sanad ini dan digharibkan dari haditsnya Khalid Al Hadza', sedangkan [Ayyub] telah meriwayatkannya dari [Muhammad bin Sirin] dari [Abu Hurairah] dengan hadits yang semakna namun tidak me-marfu'-kannya dan dia menambah dalam hadits itu \"Sekalipun saudaranya sebapak dan seibu.\" Abu Isa berkata; Dan [Qutaibah] telah mengkhabarkan demikian kepada kami bahwa [Hammad bin Zaid] telah bercerita kepada kami dari [Ayyub] dengan hadits ini."},"2089":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُعَاوِيَةَ الْجُمَحِيُّ الْبَصْرِيُّ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُتَعَاطَى السَّيْفُ مَسْلُولًاقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أَبِي بَكْرَةَ وَهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ حَدِيثِ حَمَّادِ بْنِ سَلَمَةَ وَرَوَى ابْنُ لَهِيعَةَ هَذَا الْحَدِيثَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ عَنْ بَنَّةَ الْجُهَنِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَحَدِيثُ حَمَّادِ بْنِ سَلَمَةَ عِنْدِي أَصَحُّ","id":"Telah menceritakan kepada kami ['Abdullah bin Mu'awiyah Al Jumahi Al Bashri]; telah menceritakan kepada kami [Hammad bin Salamah] dari [Abu Az Zubair] dari [Jabir] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang memberikan pedang dalam keadaan terhunus.\" Abu Isa berkata; Hadits semakna juga diriwayatkan dari Abu Bakrah, dan hadits ini adalah hasan gharib dari haditsnya Hammad bin Salamah, sedangkan [Ibnu Lahi'ah] telah meriwayatkan hadits ini dari [Abu Zubair] dari [Jabir] dari [Bannata Al Juhani] dari Nabi shallallahu 'alaihi wasallam. Adapun hadits Hammad bin Salamah menurutku lebih shahih."},"2090":{"ar":"حَدَّثَنَا بُنْدَارٌ حَدَّثَنَا مَعْدِيُّ بْنُ سُلَيْمَانَ حَدَّثَنَا ابْنُ عَجْلَانَ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ صَلَّى الصُّبْحَ فَهُوَ فِي ذِمَّةِ اللَّهِ فَلَا يُتْبِعَنَّكُمْ اللَّهُ بِشَيْءٍ مِنْ ذِمَّتِهِقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ جُنْدَبٍ وَابْنِ عُمَرَ وَهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Bundar]; telah menceritakan kepada kami [Ma'di bin Sulaiman]; telah menceritakan kepada kami [Ibnu 'Ajlan] dari [bapaknya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda; \"Barangsiapa yang melaksanakan shalat shubuh maka dia berada dalam tanggungan Allah, maka janganlah kalian menyertakan permintaan sesuatu yang lain dari tanggungan Allah.\" Abu Isa berkata; Hadits semakna juga diriwayatkan dari Jundub dan Ibnu Umar, dan hadits ini adalah hasan gharib bila ditinjau dari jalur sanad ini."},"2091":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا النَّضْرُ بْنُ إِسْمَعِيلَ أَبُو الْمُغِيرَةِ عَنْ مُحَمَّدِ بْنِ سُوقَةَ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ قَالَخَطَبَنَا عُمَرُ بِالْجَابِيَةِ فَقَالَ يَا أَيُّهَا النَّاسُ إِنِّي قُمْتُ فِيكُمْ كَمَقَامِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِينَا فَقَالَ أُوصِيكُمْ بِأَصْحَابِي ثُمَّ الَّذِينَ يَلُونَهُمْ ثُمَّ الَّذِينَ يَلُونَهُمْ ثُمَّ يَفْشُو الْكَذِبُ حَتَّى يَحْلِفَ الرَّجُلُ وَلَا يُسْتَحْلَفُ وَيَشْهَدَ الشَّاهِدُ وَلَا يُسْتَشْهَدُ أَلَا لَا يَخْلُوَنَّ رَجُلٌ بِامْرَأَةٍ إِلَّا كَانَ ثَالِثَهُمَا الشَّيْطَانُ عَلَيْكُمْ بِالْجَمَاعَةِ وَإِيَّاكُمْ وَالْفُرْقَةَ فَإِنَّ الشَّيْطَانَ مَعَ الْوَاحِدِ وَهُوَ مِنْ الِاثْنَيْنِ أَبْعَدُ مَنْ أَرَادَ بُحْبُوحَةَ الْجَنَّةِ فَلْيَلْزَمْ الْجَمَاعَةَ مَنْ سَرَّتْهُ حَسَنَتُهُ وَسَاءَتْهُ سَيِّئَتُهُ فَذَلِكُمْ الْمُؤْمِنُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَقَدْ رَوَاهُ ابْنُ الْمُبَارَكِ عَنْ مُحَمَّدِ بْنِ سُوقَةَ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ مِنْ غَيْرِ وَجْهٍ عَنْ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ahmad bin Mani']; telah menceritakan kepada kami [An Nadhr bin Isma'il Abul Mughirah] dari [Muhammad bin Suqah] dari ['Abdullah bin Dinar] dari [Ibnu 'Umar] dia berkata; Suatu ketika Umar menyampaikan pidato kepada kami di Jabiyyah. [Umar] berkata, \"Wahai sekalian manusia, aku berdiri di tengah-tengah kalian sebagaimana posisi Rasulullah shallallahu 'alaihi wasallam yang ketika itu juga berdiri di tengah-tengah kami dan bersabda: 'Aku berwasiat kepada kalian dengan (melalui) para sahabat-sahabatku kemudian orang-orang setelah mereka dan orang-orang yang datang lagi setelah mereka. Kemudian merajalelalah kedustaan. Hingga seseorang bersumpah tanpa ia diminta untuk bersumpah, kemudian seseorang memberi kesaksian padahal ia tidak diminta untuk menjadi saksi. Sungguh, tidaklah seorang laki-laki berduaan dengan seorang wanita, kecuali pihak ketiganya adalah setan. Hendaklah kalian selalu bersama Al Jama'ah. Dan janganlah kalian berpecah belah, karena setan itu selalu bersama dengan orang yang sendirian, sedangkan terhadap dua orang, ia lebih jauh. Barangsiapa yang menginginkan Buhbuhata Al Jannah, maka hendaklah ia komitmen untuk menetapi Al Jama'ah. Barangsiapa kebaikannya yang ia lakukan membuatnya lapang dan bahagia, dan keburukannya membuatnya penat dan susah, maka dia adalah seorang mukmin.'\" Abu Isa berkata; Ini adalah hadits hasan shahih gharib bila ditinjau dari jalur ini. Dan hadits ini telah diriwayatkan pula oleh [Ibnul Mubarak] dari [Muhammad bin Suqah]. Dan telah diriwayatkan pula lebih dari satu jalur dari Umar dari Nabi shallallahu 'alaihi wasallam. "},"2092":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُوسَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا إِبْرَاهِيمُ بْنُ مَيْمُونٍ عَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدُ اللَّهِ مَعَ الْجَمَاعَةِوَهَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ مِنْ حَدِيثِ ابْنِ عَبَّاسٍ إِلَّا مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Yahya bin Musa]; telah menceritakan kepada kami ['Abdurrazzaq]; telah mengabarkan kepada kami [Ibrahim bin Maimun] dari [Ibnu Thawus] dari [bapaknya] dari [Ibnu 'Abbas] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tangan Allah bersama Al Jama'ah.\" Dan hadits ini gharib dari jalur sanad ini, kami tidak mengetahuinya dari hadits Ibnu Abbas kecuali dari jalur sanad ini."},"2093":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ نَافِعٍ الْبَصْرِيُّ حَدَّثَنِي الْمُعْتَمِرُ بْنُ سُلَيْمَانَ حَدَّثَنَا سُلَيْمَانُ الْمَدَنِيُّ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ لَا يَجْمَعُ أُمَّتِي أَوْ قَالَ أُمَّةَ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى ضَلَالَةٍ وَيَدُ اللَّهِ مَعَ الْجَمَاعَةِ وَمَنْ شَذَّ شَذَّ إِلَى النَّارِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَسُلَيْمَانُ الْمَدَنِيُّ هُوَ عِنْدِي سُلَيْمَانُ بْنُ سُفْيَانَ وَقَدْ رَوَى عَنْهُ أَبُو دَاوُدَ الطَّيَالِسِيُّ وَأَبُو عَامِرٍ الْعَقَدِيُّ وَغَيْرُ وَاحِدٍ مِنْ أَهْلِ الْعِلْمِ قَالَ أَبُو عِيسَى وَتَفْسِيرُ الْجَمَاعَةِ عِنْدَ أَهْلِ الْعِلْمِ هُمْ أَهْلُ الْفِقْهِ وَالْعِلْمِ وَالْحَدِيثِ قَالَ و سَمِعْت الْجَارُودَ بْنَ مُعَاذٍ يَقُولُ سَمِعْتُ عَلِيَّ بْنَ الْحَسَنِ يَقُولُ سَأَلْتُ عَبْدَ اللَّهِ بْنَ الْمُبَارَكِ مَنْ الْجَمَاعَةُ فَقَالَ أَبُو بَكْرٍ وَعُمَرُ قِيلَ لَهُ قَدْ مَاتَ أَبُو بَكْرٍ وَعُمَرُ قَالَ فُلَانٌ وَفُلَانٌ قِيلَ لَهُ قَدْ مَاتَ فُلَانٌ وَفُلَانٌ فَقَالَ عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ وَأَبُو حَمْزَةَ السُّكَّرِيُّ جَمَاعَةٌ قَالَ أَبُو عِيسَى وَأَبُو حَمْزَةَ هُوَ مُحَمَّدُ بْنُ مَيْمُونٍ وَكَانَ شَيْخًا صَالِحًا وَإِنَّمَا قَالَ هَذَا فِي حَيَاتِهِ عِنْدَنَا","id":"Telah menceritakan kepada kami [Abu Bakr bin Nafi' Al Bashri]; telah menceritakan kepadaku [Al Mu'tamir bin Sulaiman]; telah menceritakan kepada kami [Sulaiman Al Madani] dari ['Abdullah bin Dinar] dari [Ibnu 'Umar] bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah tidak akan mengumpulkan ummatku, atau beliau bersabda (keraguan dari perawi) ummat Muhammad shallallahu 'alaihi wasallam berada di atas kesesatan, dan tangan Allah bersama Al Jama'ah, dan barangsiapa yang hidup menyendiri maka dia akan menyendiri pula masuk neraka.\" Abu Isa berkata; Ini adalah hadits gharib ditinjau dari jalur ini. Adapun Sulaiman Al Madani menurutku dia adalah Sulaiman bin Sufyan yang Abu Daud Ath Thayalisi, Abu 'Amir Al 'Aqadi dan yang lainnya dari ahli ilmu telah meriwayatkan hadits darinya. Abu Isa berkata; Adapun penafsiran makna Al Jama'ah menurut para ulama adalah mereka para ahli fiqih, ahli ilmu dan ahli hadits. Dan aku mendengar Al Jarud bin Mu'adz berkata; Aku telah mendengar Ali bin Al Hasan berkata; Aku bertanya kepada Abdullah bin Al Mubarak, \"Siapakah Al Jama'ah itu?\" kemudian dia pun menjawab, \"Abu Bakar dan Umar.\" lalu dikatakan kepadanya \"Abu Bakar dan Umar telah meninggal.\" Dia menjawab, \"Fulan dan Fulan.\" Dikatakan lagi kepadanya, \"Fulan dan Fulan sudah meninggal.\" Kemudian dia berkata, \"Abdullah bin Al Mubarak dan Abu Hamzah As Sukkari adalah Jama'ah.\" Abu Isa berkata; Abu Hamzah dia adalah Muhammad bin Maymun. Yakni, seorang syeikh yang shalih, dan ia mengatakan hal ini ketika syaikh itu masih hidup."},"2094":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنْ أَبِي بَكْرٍ الصِّدِّيقِ أَنَّهُ قَالَأَيُّهَا النَّاسُ إِنَّكُمْ تَقْرَءُونَ هَذِهِ الْآيَةَ{ يَا أَيُّهَا الَّذِينَ آمَنُوا عَلَيْكُمْ أَنْفُسَكُمْ لَا يَضُرُّكُمْ مَنْ ضَلَّ إِذَا اهْتَدَيْتُمْ }وَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ النَّاسَ إِذَا رَأَوْا الظَّالِمَ فَلَمْ يَأْخُذُوا عَلَى يَدَيْهِ أَوْشَكَ أَنْ يَعُمَّهُمْ اللَّهُ بِعِقَابٍ مِنْهُحَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ نَحْوَهُ قَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عَائِشَةَ وَأُمِّ سَلَمَةَ وَالنُّعْمَانِ بْنِ بَشِيرٍ وَعَبْدِ اللَّهِ بْنِ عُمَرَ وَحُذَيْفَةَ وَهَذَا حَدِيثٌ صَحِيحٌ وَهَكَذَا رَوَى غَيْرُ وَاحِدٍ عَنْ إِسْمَعِيلَ نَحْوَ حَدِيثِ يَزِيدَ وَرَفَعَهُ بَعْضُهُمْ عَنْ إِسْمَعِيلَ وَأَوْقَفَهُ بَعْضُهُمْ","id":"Telah menceritakan kepada kami [Ahmad bin Mani']; telah menceritakan kepada kami [Yazid bin Harun]; telah mengabarkan kepada kami [Isma'il bin Abu Khalid] dari [Qais bin Abu Hazim] dari [Abu Bakr Ash Shiddiq] bahwasanya dia berkata, \"Wahai sekalian manusia, sesungguhnya kalian sudah membaca ayat ini, 'Wahai orang-orang yang beriman, hendaklah kalian perhatikan diri kalian sendiri, mereka yang sesat tidak akan menimpa kalian, jika kalian berada di atas petunjuk.' Dan sungguh, aku telah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Sesungguhnya, apabila manusia melihat seorang yang melakukan kezhaliman, namun mereka tidak mencegahnya, atau ragu-ragu, maka Allah akan meratakan siksaan-Nya (menimpakan siksaan kepada mereka semua).'\" Telah menceritakan kepada kami [Muhammad bin Basysyar]; telah menceritakan kepada kami [Yazid bin Harun] dari [Isma'il bin Abu Khalid] semisalnya."},"2095":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ عَمْرِو بْنِ أَبِي عَمْرٍو عَنْ عَبْدِ اللَّهِ الْأَنْصَارِيِّ عَنْ حُذَيْفَةَ بْنِ الْيَمَانِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ لَتَأْمُرُنَّ بِالْمَعْرُوفِ وَلَتَنْهَوُنَّ عَنْ الْمُنْكَرِ أَوْ لَيُوشِكَنَّ اللَّهُ أَنْ يَبْعَثَ عَلَيْكُمْ عِقَابًا مِنْهُ ثُمَّ تَدْعُونَهُ فَلَا يُسْتَجَابُ لَكُمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا إِسْمَعِيلُ بْنُ جَعْفَرٍ عَنْ عَمْرِو بْنِ أَبِي عَمْرٍو بِهَذَا الْإِسْنَادِ نَحْوَهُ","id":"Telah menceritakan kepada kami [Qutaibah]; telah menceritakan kepada kami ['Abdul 'Aziz bin Muhammad] dari ['Amr bin Abu 'Amrah] dari ['Abdullah Al Anshari] dari [Hudzaifah bin Al Yaman] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Demi Dzat yang jiwaku berada di tangannya, hendaknya kalian beramar ma'ruf dan nahi munkar atau jika tidak niscaya Allah akan mengirimkan siksa-NYa dari sisi-Nya kepada kalian, kemudian kalian memohon kepada-Nya namun do'a kalian tidak lagi dikabulkan.\" Abu Isa berkata; Hadits ini hasan. Telah menceritakan kepada kami ['Ali bin Hujr]; telah mengabarkan kepada kami [Isma'il bin Ja'far] dari ['Amr bin Abu 'Amr] dengan sanad ini dan dengan hadits semisalnya."},"2096":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ عَمْرِو بْنِ أَبِي عَمْرٍو عَنْ عَبْدِ اللَّهِ وَهُوَ ابْنُ عَبْدِ الرَّحْمَنِ الْأَنْصَارِيُّ الْأَشْهَلِيُّ عَنْ حُذَيْفَةَ بْنِ الْيَمَانِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ لَا تَقُومُ السَّاعَةُ حَتَّى تَقْتُلُوا إِمَامَكُمْ وَتَجْتَلِدُوا بِأَسْيَافِكُمْ وَيَرِثَ دُنْيَاكُمْ شِرَارُكُمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ إِنَّمَا نَعْرِفُهُ مِنْ حَدِيثِ عَمْرِو بْنِ أَبِي عَمْرٍو","id":"Telah menceritakan kepada kami [Qutaibah]; telah menceritakan kepada kami ['Abdul 'Aziz bin Muhammad] dari ['Amr bin Abu 'Amrah] dari ['Abdullah bin 'Abdurrahman Al Anshari Al Asyhali] dari [Hudzaifah bin Al Yaman] bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda, \"Demi Dzat yang jiwaku berada di Tangan-Nya, tidak akan terjadi hari kiamat hingga kalian membunuh imam kalian sendiri dan kalian saling menghujam dengan pedang-pedang kalian, serta dunia kalian diwarisi oleh orang-orang buruk di antara kalian.\" Abu Isa berkata; Hadits ini adalah hadits hasan, kami hanya mengetahuinya dari hadits Amr bin Abu Amr."},"2097":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا سُفْيَانُ عَنْ مُحَمَّدِ بْنِ سُوقَةَ عَنْ نَافِعِ بْنِ جُبَيْرٍ عَنْ أُمِّ سَلَمَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ ذَكَرَ الْجَيْشَ الَّذِي يُخْسَفُ بِهِمْ فَقَالَتْ أُمُّ سَلَمَةَ لَعَلَّ فِيهِمْ الْمُكْرَهُ قَالَ إِنَّهُمْ يُبْعَثُونَ عَلَى نِيَّاتِهِمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ نَافِعِ بْنِ جُبَيْرٍ عَنْ عَائِشَةَ أَيْضًا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Nashr bin 'Ali Al Jahdhami]; telah menceritakan kepada kami [Sufyan] dari [Muhammad bin Suqah] dari [Nafi' bin Jubair] dari [Ummu Salamah] dari Nabi shallallahu 'alaihi wasallam bahwa beliau menceritakan tentang bala tentara yang dihancurkan, kemudian Ummu Salamah bertanya, \"Mungkin saja di antara mereka ada yang ikut karena dipaksa?\" Kemudian beliau pun bersabda: \"Sesungguhnya mereka akan dibangkitkan berdasarkan niat mereka masing-masing.\" Abu Isa berkata; Ini adalah hadits hasan gharib bila ditinjau melalui jalur ini. Dan hadits ini telah diriwayatkan juga dari [Nafi' bin Jubair] dari [A'isyah] dari Nabi shallallahu 'alaihi wasallam."},"2098":{"ar":"حَدَّثَنَا بُنْدَارٌ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ قَيْسِ بْنِ مُسْلِمٍ عَنْ طَارِقِ بْنِ شِهَابٍ قَالَأَوَّلُ مَنْ قَدَّمَ الْخُطْبَةَ قَبْلَ الصَّلَاةِ مَرْوَانُ فَقَامَ رَجُلٌ فَقَالَ لِمَرْوَانَ خَالَفْتَ السُّنَّةَ فَقَالَ يَا فُلَانُ تُرِكَ مَا هُنَالِكَ فَقَالَ أَبُو سَعِيدٍ أَمَّا هَذَا فَقَدْ قَضَى مَا عَلَيْهِ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ رَأَى مُنْكَرًا فَلْيُنْكِرْهُ بِيَدِهِ وَمَنْ لَمْ يَسْتَطِعْ فَبِلِسَانِهِ وَمَنْ لَمْ يَسْتَطِعْ فَبِقَلْبِهِ وَذَلِكَ أَضْعَفُ الْإِيمَانِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Bundar]; telah menceritakan kepada kami ['Abdurrahman bin Mahdi]; telah menceritakan kepada kami [Sufyan] dari [Qais bin Muslim] dari [Thariq bin Syihab] dia berkata; Orang yang pertama kali mendahulukan khutbah daripada shalat adalah Marwan. Maka seorang laki-laki pun berdiri seraya berkata kepada Marwan, \"Anda telah menyelisihi sunnah.\" Marwan berkata, \"Wahai Fulan, hal itu telah ditinggalkan.\" Maka [Abu Sa'id] berkata; Adapun orang ini, maka sungguh ia telah menunaikan apa yang menjadi kewajibannya. Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa diantara kalian melihat suatu kemungkaran, maka hendaklah ia mengingkari dengan tangannya, kalau tidak mampu, maka dengan lisannya, dan jika tidak mampu juga maka dengan hatinya. Dan itu adalah selemah-lemah iman.\" Abu Isa berkata; Ini adalah hadits hasan shahih."},"2099":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ الشَّعْبِيِّ عَنْ النُّعْمَانِ بْنِ بَشِيرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَثَلُ الْقَائِمِ عَلَى حُدُودِ اللَّهِ وَالْمُدْهِنِ فِيهَا كَمَثَلِ قَوْمٍ اسْتَهَمُوا عَلَى سَفِينَةٍ فِي الْبَحْرِ فَأَصَابَ بَعْضُهُمْ أَعْلَاهَا وَأَصَابَ بَعْضُهُمْ أَسْفَلَهَا فَكَانَ الَّذِينَ فِي أَسْفَلِهَا يَصْعَدُونَ فَيَسْتَقُونَ الْمَاءَ فَيَصُبُّونَ عَلَى الَّذِينَ فِي أَعْلَاهَا فَقَالَ الَّذِينَ فِي أَعْلَاهَا لَا نَدَعُكُمْ تَصْعَدُونَ فَتُؤْذُونَنَا فَقَالَ الَّذِينَ فِي أَسْفَلِهَا فَإِنَّا نَنْقُبُهَا مِنْ أَسْفَلِهَا فَنَسْتَقِي فَإِنْ أَخَذُوا عَلَى أَيْدِيهِمْ فَمَنَعُوهُمْ نَجَوْا جَمِيعًا وَإِنْ تَرَكُوهُمْ غَرِقُوا جَمِيعًاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ahmad bin Mani']; telah menceritakan kepada kami [Abu Mu'awiyah]; telah menceritakan kepada kami [Al A'masy] dari [Asy Sya'bi] dari [An Nu'man bin Basyir] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda; \"Perumpamaan mereka yang menegakkan hukum dan berjalan di atasnya adalah bagaikan suatu kaum yang berada di atas perahu di tengah hamparan lautan yang luas. Sebagian dari mereka bertempat di atasnya dan sebagian yang lain berada di bawah. Mereka yang berada di bawah apabila membutuhkan air, maka mereka akan naik ke atas lalu menimba air sehingga mengganggu mereka yang berada di atas. Maka orang-orang yang berada di atas pun berkata, 'Kami tidak akan membiarkan kalian naik ke atas sehingga kalian menyusahkan kami.' Sedangkan mereka yang berada di bawah juga berkata, 'Kalau begitu, maka kami akan membuat lubang di bawah sehingga memudahkan kami untuk mengambil air.' Maka apabila mereka mencegahnya, niscaya mereka semua akan selamat. Namun bila mereka meninggalkannya, niscaya mereka semua akan tenggelam.\" Abu Isa berkata; Ini adalah hadits hasan shahih."},"2100":{"ar":"حَدَّثَنَا الْقَاسِمُ بْنُ دِينَارٍ الْكُوفِيُّ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مُصْعَبٍ أَبُو يَزِيدَ حَدَّثَنَا إِسْرَائِيلُ عَنْ مُحَمَّدِ بْنِ جُحَادَةَ عَنْ عَطِيَّةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ مِنْ أَعْظَمِ الْجِهَادِ كَلِمَةَ عَدْلٍ عِنْدَ سُلْطَانٍ جَائِرٍقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أَبِي أُمَامَةَ وَهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Al Qasim bin Dinar Al Kufi]; telah menceritakan kepada kami ['Abdurrahman bin Mush'ab Abu Yazid]; telah menceritakan kepada kami [Isra'il] dari [Muhammad bin Juhadah] dari ['Athiyyah] dari [Abu Sa'id Al Khudri] bahwasanya Nabi shallallahu 'alaihi wasallam bersabda; \"Sesungguhnya jihad yang paling agung adalah ungkapan yang adil (benar) yang disampaikan di hadapan penguasa yang zhalim.\" Abu Isa berkata; Hadits semakna juga diriwayatkan dari Abu Umamah. Dan ini adalah hadits hasan gharib ditinjau dari jalur ini."},"2101":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا أَبِي قَال سَمِعْتُ النُّعْمَانَ بْنَ رَاشِدٍ يُحَدِّثُ عَنْ الزُّهْرِيِّ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ عَنْ عَبْدِ اللَّهِ بْنِ خَبَّابِ بْنِ الْأَرَتِّ عَنْ أَبِيهِ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةً فَأَطَالَهَا قَالُوا يَا رَسُولَ اللَّهِ صَلَّيْتَ صَلَاةً لَمْ تَكُنْ تُصَلِّيهَا قَالَ أَجَلْ إِنَّهَا صَلَاةُ رَغْبَةٍ وَرَهْبَةٍ إِنِّي سَأَلْتُ اللَّهَ فِيهَا ثَلَاثًا فَأَعْطَانِي اثْنَتَيْنِ وَمَنَعَنِي وَاحِدَةً سَأَلْتُهُ أَنْ لَا يُهْلِكَ أُمَّتِي بِسَنَةٍ فَأَعْطَانِيهَا وَسَأَلْتُهُ أَنْ لَا يُسَلِّطَ عَلَيْهِمْ عَدُوًّا مِنْ غَيْرِهِمْ فَأَعْطَانِيهَا وَسَأَلْتُهُ أَنْ لَا يُذِيقَ بَعْضَهُمْ بَأْسَ بَعْضٍ فَمَنَعَنِيهَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ وَفِي الْبَاب عَنْ سَعْدٍ وَابْنِ عُمَرَ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Wahb bin Jarir] telah menceritakan kepada kami [bapakku] berkata: aku mendengar [Nu'man bin Rasyid] menceritakan dari [Az Zuhri] dari [Abdullah bin Al Harits] dari [Abdullah bin Khabbab bin Al Arts] dari [bapaknya] berkata: Rasulullah Shallallahu 'alaihi wa Salam melaksanakan shalat dan beliau memperlama, para sahabat bertanya: wahai Rasulullah, engkau melaksanakan shalat tidak sebagaimana biasanya? beliau menjawab: \"Betul, itu adalah shalat antara cinta dan takut, dalam shalat itu aku memohon kepada Allah tiga hal, kemudian Allah mengabulkan dua hal dan tidak mengabulkanku satu hal; aku memohon kepadaNya agar tidak membinasakan ummatku dengan kelaparan dan Allah mengabulkannya, aku memohon agar ummatku tidak dikuasai oleh musuh selain mereka dan Allah mengabulkannya, kemudian aku memohon agar tidak terjadi peperangan internal di antara mereka namun Allah tidak mengabulkannya.\" Abu Isa berkata: hadits ini hasan shahih gharib, dan dalam bab ini ada hadits dari Sa'ad dan Ibnu Umar."},"2102":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي أَسْمَاءَ الرَّحَبِيِّ عَنْ ثَوْبَانَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ زَوَى لِيَ الْأَرْضَ فَرَأَيْتُ مَشَارِقَهَا وَمَغَارِبَهَا وَإِنَّ أُمَّتِي سَيَبْلُغُ مُلْكُهَا مَا زُوِيَ لِي مِنْهَا وَأُعْطِيتُ الْكَنْزَيْنِ الْأَحْمَرَ وَالْأَبْيَضَ وَإِنِّي سَأَلْتُ رَبِّي لِأُمَّتِي أَنْ لَا يُهْلِكَهَا بِسَنَةٍ عَامَّةٍ وَأَنْ لَا يُسَلِّطَ عَلَيْهِمْ عَدُوًّا مِنْ سِوَى أَنْفُسِهِمْ فَيَسْتَبِيحَ بَيْضَتَهُمْ وَإِنَّ رَبِّي قَالَ يَا مُحَمَّدُ إِنِّي إِذَا قَضَيْتُ قَضَاءً فَإِنَّهُ لَا يُرَدُّ وَإِنِّي أَعْطَيْتُكَ لِأُمَّتِكَ أَنْ لَا أُهْلِكَهُمْ بِسَنَةٍ عَامَّةٍ وَأَنْ لَا أُسَلِّطَ عَلَيْهِمْ عَدُوًّا مِنْ سِوَى أَنْفُسِهِمْ فَيَسْتَبِيحَ بَيْضَتَهُمْ وَلَوْ اجْتَمَعَ عَلَيْهِمْ مَنْ بِأَقْطَارِهَا أَوْ قَالَ مَنْ بَيْنَ أَقْطَارِهَا حَتَّى يَكُونَ بَعْضُهُمْ يُهْلِكُ بَعْضًا وَيَسْبِي بَعْضُهُمْ بَعْضًاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Abu Qilabah] dari [Abu Asma` Ar Rahabi] dari [Tsauban] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Allah mengisutkan bumi untukku lalu aku melihat timur dan baratnya dan kekuasaan ummatku akan mencapai yang dikisutkan untukku, aku diberi dua harta simpanan; merah dan putih, dan aku meminta Rabbku untuk ummatku agar tidak dibinasakan oleh kekeringan setahun, agar Ia tidak memberi kuasa musuh untuk menguasai mereka selain diri mereka sendiri lalu menyerang perkumpulan mereka, dan Rabbku berfirman: Hai Muhammad, Aku bila menentukan takdir tidak bisa dirubah, Aku memberikan untuk umatmu agar tidak dibinasakan oleh kekeringan setahun, Aku tidak memberi kuasa musuh untuk menyerang mereka selain diri mereka sendiri lalu mereka menyerang perkumpulan mereka meski mereka dikepung dari segala penjurunya -atau bersabda: Musuh dari segala penjuru- hingga sebagian dari mereka membinasakan sebagian lainnya dan saling menawan satu sama lain.\" berkata Abu Isa: Ini hadits hasan-shahih."},"2103":{"ar":"حَدَّثَنَا عِمْرَانُ بْنُ مُوسَى الْقَزَّازُ الْبَصْرِيُّ حَدَّثَنَا عَبْدُ الْوَارِثِ بْنُ سَعِيدٍ حَدَّثَنَا مُحَمَّدُ بْنُ جُحَادَةَ عَنْ رَجُلٍ عَنْ طَاوُسٍ عَنْ أُمِّ مَالِكٍ الْبَهْزِيَّةِ قَالَتْذَكَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِتْنَةً فَقَرَّبَهَا قَالَتْ قُلْتُ يَا رَسُولَ اللَّهِ مَنْ خَيْرُ النَّاسِ فِيهَا قَالَ رَجُلٌ فِي مَاشِيَتِهِ يُؤَدِّي حَقَّهَا وَيَعْبُدُ رَبَّهُ وَرَجُلٌ آخِذٌ بِرَأْسِ فَرَسِهِ يُخِيفُ الْعَدُوَّ وَيُخِيفُونَهُقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أُمِّ مُبَشِّرٍ وَأَبِي سَعِيدٍ وَابْنِ عَبَّاسٍ وَهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَقَدْ رَوَاهُ اللَّيْثُ بْنُ أَبِي سُلَيْمٍ عَنْ طَاوُسٍ عَنْ أُمِّ مَالِكٍ الْبَهْزِيَّةِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami ['Imran bin Musa Al Qazzaz Al Bashri] telah menceritakan kepada kami [Abdul Warits bin Sa'id] telah menceritakan kepada kami [Muhammad bin Juhadah] dari [seseorang] dari [Thawus] dari [Ummu Malik Al Bahziyyah] berkata: Rasulullah Shallallahu 'alaihi wa Salam menyebutkan suatu fitnah lalu beliau mendekatkannya. Berkata Ummu Malik: Wahai Rasulullah, siapakah orang terbaik dalam fitnah itu. Rasulullah Shallallahu 'alaihi wa Salam menjawab: Seseorang berada di antara binatang ternaknya, ia menunaikan hak binatang ternaknya, menyembah Rabbnya, seseorang yang memegang kepala kudanya seraya menakuti-nakuti musuh dan mereka takut padanya.\" Berkata Abu Isa: Dalam hal ini ada hadits serupa dari Ummu Mubasysyir, Abu Sa'id dan Ibnu 'Abbas dan hadits ini hasan gharib dari sanad ini. [Al Laits bin Abu Sulaim] meriwayatkannya dari [Thawus] dari [Ummu Malik Al Bahziyyah] dari nabi Shallallahu 'alaihi wa Salam."},"2104":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُعَاوِيَةَ الْجُمَحِيُّ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ لَيْثٍ عَنْ طَاوُسٍ عَنْ زِيَادِ بْنِ سِيْمِينَ كُوْشَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَكُونُ فِتْنَةٌ تَسْتَنْظِفُ الْعَرَبُ قَتْلَاهَا فِي النَّارِ اللِّسَانُ فِيهَا أَشَدُّ مِنْ السَّيْفِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ سَمِعْت مُحَمَّدَ بْنَ إِسْمَعِيلَ يَقُولُ لَا يُعْرَفُ لِزِيَادِ بْنِ سِيْمِينَ كُوْشَ غَيْرُ هَذَا الْحَدِيثِ رَوَاهُ حَمَّادُ بْنُ سَلَمَةَ عَنْ لَيْثٍ فَرَفَعَهُ وَرَوَاهُ حَمَّادُ بْنُ زَيْدٍ عَنْ لَيْثٍ فَأَوْقَفَهُ","id":"Telah menceritakan kepada kami [Abdullah bin Mu'awiyah Al Jumahi] telah menceritakan kepada kami [Hammad bin Salamah] telah menceritakan kepada kami [Laits] dari [Thawus] dari [Ziyad bin Simin Kusy] dari [Abdullah bin 'Amru] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Akan terjadi fitnah, orang-orang arab yang berusaha membersihkan korban-korbannya akan masuk neraka, dan lidah pada waktu itu lebih tajam dari pedang.\" Abu Isa berkata: Hadits ini gharib, aku telah mendengar Muhammad bin Isma'il berkata: Tidak dikenal dari Ziyad bin Simin kusy selain hadits ini. Hammad bin Salamah telah meriwayatkan hadits ini dari Laits dan memarfu'kannya (sampai kepada Nabi Shallallahu 'alaihi wa Salam), sedangkan Hammad bin Zaid telah meriwayatkannya dari Laits namun memauqufkannya (hanya sampai pada sahabat)."},"2105":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ زَيْدِ بْنِ وَهْبٍ عَنْ حُذَيْفَةَ بْنِ الْيَمَانِحَدَّثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدِيثَيْنِ قَدْ رَأَيْتُ أَحَدَهُمَا وَأَنَا أَنْتَظِرُ الْآخَرَ حَدَّثَنَا أَنَّ الْأَمَانَةَ نَزَلَتْ فِي جَذْرِ قُلُوبِ الرِّجَالِ ثُمَّ نَزَلَ الْقُرْآنُ فَعَلِمُوا مِنْ الْقُرْآنِ وَعَلِمُوا مِنْ السُّنَّةِ ثُمَّ حَدَّثَنَا عَنْ رَفْعِ الْأَمَانَةِ فَقَالَ يَنَامُ الرَّجُلُ النَّوْمَةَ فَتُقْبَضُ الْأَمَانَةُ مِنْ قَلْبِهِ فَيَظَلُّ أَثَرُهَا مِثْلَ الْوَكْتِ ثُمَّ يَنَامُ نَوْمَةً فَتُقْبَضُ الْأَمَانَةُ مِنْ قَلْبِهِ فَيَظَلُّ أَثَرُهَا مِثْلَ أَثَرِ الْمَجْلِ كَجَمْرٍ دَحْرَجْتَهُ عَلَى رِجْلِكَ فَنَفَطَتْ فَتَرَاهُ مُنْتَبِرًا وَلَيْسَ فِيهِ شَيْءٌ ثُمَّ أَخَذَ حَصَاةً فَدَحْرَجَهَا عَلَى رِجْلِهِ قَالَ فَيُصْبِحُ النَّاسُ يَتَبَايَعُونَ لَا يَكَادُ أَحَدُهُمْ يُؤَدِّي الْأَمَانَةَ حَتَّى يُقَالَ إِنَّ فِي بَنِي فُلَانٍ رَجُلًا أَمِينًا وَحَتَّى يُقَالَ لِلرَّجُلِ مَا أَجْلَدَهُ وَأَظْرَفَهُ وَأَعْقَلَهُ وَمَا فِي قَلْبِهِ مِثْقَالُ حَبَّةٍ مِنْ خَرْدَلٍ مِنْ إِيمَانٍ قَالَ وَلَقَدْ أَتَى عَلَيَّ زَمَانٌ وَمَا أُبَالِي أَيُّكُمْ بَايَعْتُ فِيهِ لَئِنْ كَانَ مُسْلِمًا لَيَرُدَّنَّهُ عَلَيَّ دِينُهُ وَلَئِنْ كَانَ يَهُودِيًّا أَوْ نَصْرَانِيًّا لَيَرُدَّنَّهُ عَلَيَّ سَاعِيهِ فَأَمَّا الْيَوْمَ فَمَا كُنْتُ لِأُبَايِعَ مِنْكُمْ إِلَّا فُلَانًا وَفُلَانًاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Zaid bin Wahab] dari [Hudzaifah bin Al Yaman] telah menceritakan kepada kami Rasulullah Shallallahu 'alaihi wa Salam dua hadits; salah satunya sudah aku ketahui dan yang lainnya tengah aku nanti-nanti, beliau menceritakan kepada kami bahwa amanat turun di hati orang-orang kemudian Al-Qur`an turun dan mereka mengetahui dari sunnah lalu beliau menceritakan kami tentang tercabutnya amanah, beliau bersabda: \"Seseorang tidur lalu amanah dicabut dari hatinya kemudian membekas seperti jejak kaki lalu ia tidur lagi kemudian amanat dicabut dari hatinya hingga bekasnya tetap ada seperti jejak tangan seperti bara api yang kau gelindingkan di atas kakimu lalu kau melihatnya membengkak padahal tidak ada apa pun didalamnya.\" Setelah itu Rasulullah Shallallahu 'alaihi wa Salam mengambil batu kerikil dan menggelindingkannya di atas kaki, orang-orang pun berbaiat kepada beliau hingga hampir salah seorang di antara mereka tidaklah menunaikan amanat hingga dikatakan: Di Bani Fulan ada seseorang terpercaya, hingga dikatakan pada seseorang: Alangkah kuatnya dia, alangkah cerdasnya ia, alangkah berakalnya ia padahal dihatinya tidak ada sedikit pun keimanan. Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Suatu masa telah mendatangiku dan aku tidak perduli siapa diantara kalian yang aku baiat di masa itu, bila ia muslim pastilah agamanya akan mengembalikannya padaku dan bila Yahudi atau Nasrani, para penarik pajaknya akan mengembalikannya padaku, sementara saat ini, aku hanya membaiat fulan dan fulan dari kalian.\" Berkata Abu Isa: Hadits hasan shahih."},"2106":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عَبْدِ الرَّحْمَنِ الْمَخْزُومِيُّ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سِنَانِ بْنِ أَبِي سِنَانٍ عَنْ أَبِي وَاقِدٍ اللَّيْثِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا خَرَجَ إِلَى حُنَيْنٍ مَرَّ بِشَجَرَةٍ لِلْمُشْرِكِينَ يُقَالُ لَهَا ذَاتُ أَنْوَاطٍ يُعَلِّقُونَ عَلَيْهَا أَسْلِحَتَهُمْ فَقَالُوا يَا رَسُولَ اللَّهِ اجْعَلْ لَنَا ذَاتَ أَنْوَاطٍ كَمَا لَهُمْ ذَاتُ أَنْوَاطٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُبْحَانَ اللَّهِ هَذَا كَمَا قَالَ قَوْمُ مُوسَى اجْعَلْ لَنَا إِلَهًا كَمَا لَهُمْ آلِهَةٌ وَالَّذِي نَفْسِي بِيَدِهِ لَتَرْكَبُنَّ سُنَّةَ مَنْ كَانَ قَبْلَكُمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَأَبُو وَاقِدٍ اللَّيْثِيُّ اسْمُهُ الْحَارِثُ بْنُ عَوْفٍ وَفِي الْبَاب عَنْ أَبِي سَعِيدٍ وَأَبِي هُرَيْرَةَ","id":"Telah menceritakan kepada kami [Sa'id bin Abdurrahman Al Makhzumi] telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Sinan bin Abu Sinan] dari [Abu Waqid Al Laitsi], saat Rasulullah Shallallahu 'alaihi wa Salam pergi ke Hunain, beliau melintasi sebuah pepohonan kaum musyrikin bernama Dzat Anwath, mereka biasa menggantungkan persenjataan mereka di pohon itu, para sahabat berkata: Wahai Rasulullah, buatkan kami Dzat Anwath seperti milik mereka, lalu nabi Shallallahu 'alaihi wa Salam bersabda: \"Subhaanallaah, ini seperti yang dikatakan kaum Musa: Buatkan kami ilah seperti ilah-ilah mereka. demi Dzat yang jiwaku berada ditanganNya, kalian akan melakukan perilaku-perilaku orang sebelum kalian.\" Berkata Abu Isa: Hadits ini hasan shahih. Abu Abu Waqid Al Laitsi namanya Al Harits bin 'Auf dalam hal ini ada hadits serupa dari Abu Sa'id dan Abu Hurairah."},"2107":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ وَكِيعٍ حَدَّثَنَا أَبِي عَنْ الْقَاسِمِ بْنِ الْفَضْلِ حَدَّثَنَا أَبُو نَضْرَةَ الْعَبْدِيُّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالَّذِي نَفْسِي بِيَدِهِ لَا تَقُومُ السَّاعَةُ حَتَّى تُكَلِّمَ السِّبَاعُ الْإِنْسَ وَحَتَّى تُكَلِّمَ الرَّجُلَ عَذَبَةُ سَوْطِهِ وَشِرَاكُ نَعْلِهِ وَتُخْبِرَهُ فَخِذُهُ بِمَا أَحْدَثَ أَهْلُهُ مِنْ بَعْدِهِقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ الْقَاسِمِ بْنِ الْفَضْلِ وَالْقَاسِمُ بْنُ الْفَضْلِ ثِقَةٌ مَأْمُونٌ عِنْدَ أَهْلِ الْحَدِيثِ وَثَّقَهُ يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ وَعَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ","id":"Telah menceritakan kepada kami [Sufyan bin Waki'] telah menceritakan kepada kami [ayahku] dari [Al Qasim bin Al Fadll] telah menceritakan kepada kami [Abu Nadlrah Al 'Abdi] dari [Abu Sa'id Al Khudri] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Demi Dzat yang jiwaku berada di tangannya, tidaklah kiamat terjadi hingga binatang-binatang buas berbicara kepada manusia, hingga ujung cambuknya, tali sendalnya berbicara pada orang dan hingga lututnya memberitahukan padanya apa yang dilakukan keluarganya sepeninggalnya.\" Berkata Abu Isa: dalam hal ini ada hadits serupa dari Abu Hurairah dan hadits ini hasan shahih gharib, kami tidak mengetahuinya kecuali dari hadits Al Qasim bin Al Fadll dan Al Qasim adalah perawi terpercaya menurut ahli hadits. Yahya bin Sa'id Al Qaththan dan Abdurrahman bin Mahdi menyatakan bahwa ia adalah perawi terpercaya."},"2108":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ عَنْ شُعْبَةَ عَنْ الْأَعْمَشِ عَنْ مُجَاهِدٍ عَنْ ابْنِ عُمَرَ قَالَانْفَلَقَ الْقَمَرُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اشْهَدُواقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ ابْنِ مَسْعُودٍ وَأَنَسٍ وَجُبَيْرِ بْنِ مُطْعِمٍ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah bererita kepada kami [Abu Daud] telah menceritakan kepada kami [Syu'bah] dari [Al A'masy] dari [Mujahid] dari [Ibnu Umar] berkata: di masa Rasulullah Shallallahu 'alaihi wa Salam bulan terbelah menjadi dua, kemudian Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Saksikanlah.\" Abu Isa berkata: dalam hal ini ada hadits serupa dari Ibnu Mas'ud, Anas dan Jubair bin Muth'im dan hadits ini hasan shahih."},"2109":{"ar":"حَدَّثَنَا بُنْدَارٌ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ فُرَاتٍ الْقَزَّازِ عَنْ أَبِي الطُّفَيْلِ عَنْ حُذَيْفَةَ بْنِ أَسِيدٍ قَالَأَشْرَفَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ غُرْفَةٍ وَنَحْنُ نَتَذَاكَرُ السَّاعَةَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقُومُ السَّاعَةُ حَتَّى تَرَوْا عَشْرَ آيَاتٍ طُلُوعَ الشَّمْسِ مِنْ مَغْرِبِهَا وَيَأْجُوجَ وَمَأْجُوجَ وَالدَّابَّةَ وَثَلَاثَةَ خُسُوفٍ خَسْفٌ بِالْمَشْرِقِ وَخَسْفٌ بِالْمَغْرِبِ وَخَسْفٌ بِجَزِيرَةِ الْعَرَبِ وَنَارٌ تَخْرُجُ مِنْ قَعْرِ عَدَنَ تَسُوقُ النَّاسَ أَوْ تَحْشُرُ النَّاسَ فَتَبِيتُ مَعَهُمْ حَيْثُ بَاتُوا وَتَقِيلُ مَعَهُمْ حَيْثُ قَالُواحَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ فُرَاتٍ نَحْوَهُ وَزَادَ فِيهِ الدُّخَانَ حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ فُرَاتٍ الْقَزَّازِ نَحْوَ حَدِيثِ وَكِيعٍ عَنْ سُفْيَانَ حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ الطَّيَالِسِيُّ عَنْ شُعْبَةَ وَالْمَسْعُودِيِّ سَمِعَا مِنْ فُرَاتٍ الْقَزَّازِ نَحْوَ حَدِيثِ عَبْدِ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ فُرَاتٍ وَزَادَ فِيهِ الدَّجَّالَ أَوْ الدُّخَانَ حَدَّثَنَا أَبُو مُوسَى مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا أَبُو النُّعْمَانِ الْحَكَمُ بْنُ عَبْدِ اللَّهِ الْعِجْلِيُّ عَنْ شُعْبَةَ عَنْ فُرَاتٍ نَحْوَ حَدِيثِ أَبِي دَاوُدَ عَنْ شُعْبَةَ وَزَادَ فِيهِ قَالَ وَالْعَاشِرَةُ إِمَّا رِيحٌ تَطْرَحُهُمْ فِي الْبَحْرِ وَإِمَّا نُزُولُ عِيسَى ابْنِ مَرْيَمَ قَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عَلِيٍّ وَأَبِي هُرَيْرَةَ وَأُمِّ سَلَمَةَ وَصَفِيَّةَ بِنْتِ حُيَيٍّ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Bundar] telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Sufyan] dari [Furat Al Qazzar] dari [Abu Ath Thufail] dari [Hudzaifah bin Usaid] berkata: Rasulullah Shallallahu 'alaihi wa Salam melihat kami dari kamar dan kami tengah membicarakan tentang kiamat lalu nabi Shallallahu 'alaihi wa Salam bersabda: \"Kiamat tidaklah terjadi hingga kalian melihat sepuluh tanda-tanda; terbitnya matahari dari barat, ya'juj dan ma'juj, binatang, tiga gerhana; gerhana di timur, gerhana di barat dan gerhana di jazirah arab, api muncul dari bawah 'Aden menggiring manusia atau mengumpulkan manusia lalu menginap bersama mereka di tempat mereka menginap dan tidur siang bersama mereka di tempat mereka tidur siang.\" Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Furat] sepertinya dan ia menambahkan dalam riwayatnya: Asap. Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Abu Al Ahwash] dari [Furat Al Qaffaz] seperti hadits Waki' dari Sufyan. Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Dawud Ath Thayalisi] dari [Syu'bah] dan [Al Mas'udi] keduanya mendengar dari [Furat Al Qazzaz] seperti hadits Abdurrahman dari Sufyan dari Furat dan ia menambahkan dalam riwayatnya: Dajjal atau asap. Telah menceritakan kepada kami [Abu Musa Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Abu An Nu'man Al Hakam bin Abdullah Al 'Ijlani] dari [Syu'bah] dari [Furat] seperti hadits Abu Dawud dari Syu'bah dan ia menambahkan: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Dan yang kesepuluh mungkin angin melemparkan mereka ke laut atau turunnya Isa bin Maryam. Berkata Abu Isa: dalam hal ini ada hadits serupa dari 'Ali, Abu Hurairah, Ummu Salamah, Shafiyyah binti Huyay dan hadits ini hasan shahih."},"2110":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ أَبِي إِدْرِيسَ الْمُرْهِبِيِّ عَنْ مُسْلِمِ بْنِ صَفْوَانَ عَنْ صَفِيَّةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَنْتَهِي النَّاسُ عَنْ غَزْوِ هَذَا الْبَيْتِ حَتَّى يَغْزُوَ جَيْشٌ حَتَّى إِذَا كَانُوا بِالْبَيْدَاءِ أَوْ بِبَيْدَاءَ مِنْ الْأَرْضِ خُسِفَ بِأَوَّلِهِمْ وَآخِرِهِمْ وَلَمْ يَنْجُ أَوْسَطُهُمْ قُلْتُ يَا رَسُولَ اللَّهِ فَمَنْ كَرِهَ مِنْهُمْ قَالَ يَبْعَثُهُمْ اللَّهُ عَلَى مَا فِي أَنْفُسِهِمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Salamah bin Kuhail] dari [Abu Idris Al Murhabi] dari [Muslim bin Shafwan] dari [Shafiyyah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Manusia tidak berhenti menyerang baitullah (ka'bah) ini hingga sekelompok tentara menyerang hingga ketika mereka berada di Baida', mereka dibenamkan dari bagian depan hingga belakang sementara bagian tengahnya tidak selamat. Aku bertanya: Wahai Rasulullah, lalu orang yang benci dari mereka? Rasulullah Shallallahu 'alaihi wa Salam menjawab: Allah akan membangkitkan mereka berdasarkan niat yang ada di dalam jiwa mereka. berkata Abu Isa: hadits ini hasan shahih."},"2111":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا صَيْفِيُّ بْنُ رِبْعِيٍّ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَ قَالَتْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَكُونُ فِي آخِرِ الْأُمَّةِ خَسْفٌ وَمَسْخٌ وَقَذْفٌ قَالَتْ قُلْتُ يَا رَسُولَ اللَّهِ أَنَهْلِكُ وَفِينَا الصَّالِحُونَ قَالَ نَعَمْ إِذَا ظَهَرَ الْخُبْثُ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ مِنْ حَدِيثِ عَائِشَةَ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ وَعَبْدُ اللَّهِ بْنُ عُمَرَ تَكَلَّمَ فِيهِ يَحْيَى بْنُ سَعِيدٍ مِنْ قِبَلِ حِفْظِهِ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Shoifi bin Rib'i] telah menceritakan kepada kami [Abdullah bin Umar] dari ['Ubaidillah bin Umar] dari [Al Qasim bin Muhammad] dari [Aisyah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Akan terjadi pada akhir ummat nanti longsor, perubahan bentuk dan angin kencang yang menghempaskan manusia.\" A'isyah berkata: aku bertanya: wahai Rasulullah, apakah kita akan dibinasakan sementara di antara kami ada orang orang yang shalih? beliau menjawab: \"Ya, jika kemaksiatan telah meraja lela.\" Abu Isa berkata: hadits ini gharib dari hadits A'isyah, kami tidak mengetahuinya kecuali dari jalur sanad ini, adapun Abdullah bin 'Amru dibicarakan oleh Yahya bin Sa'id dari sisi hafalannya."},"2112":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ أَبِيهِ عَنْ أَبِي ذَرٍّ قَالَدَخَلْتُ الْمَسْجِدَ حِينَ غَابَتْ الشَّمْسُ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَالِسٌ فَقَالَ يَا أَبَا ذَرٍّ أَتَدْرِي أَيْنَ تَذْهَبُ هَذِهِ قَالَ قُلْتُ اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ فَإِنَّهَا تَذْهَبُ تَسْتَأْذِنُ فِي السُّجُودِ فَيُؤْذَنُ لَهَا وَكَأَنَّهَا قَدْ قِيلَ لَهَا اطْلُعِي مِنْ حَيْثُ جِئْتِ فَتَطْلُعُ مِنْ مَغْرِبِهَا قَالَ ثُمَّ قَرَأَ وَذَلِكَ مُسْتَقَرٌّ لَهَا قَالَ وَذَلِكَ قِرَاءَةُ عَبْدِ اللَّهِ بْنِ مَسْعُودٍقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ صَفْوَانَ بْنِ عَسَّالٍ وَحُذَيْفَةَ بْنِ أَسِيدٍ وَأَنَسٍ وَأَبِي مُوسَى وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Ibrahim At Taimi] dari [ayahnya] dari [Abu Dzarr] berkata: Aku masuk masjid saat matahari terbenam sementara nabi Shallallahu 'alaihi wa Salam tengah duduk, beliau bertanya: \"Hai Abu Dzarr, tahukah kamu kemanakah perginya matahari?\" Abu Dzarr berkata: Aku menjawab: Allah dan rasulNya lebih tahu. Rasulullah Shallallahu 'alaihi wa Salam bersabda: \" ia pergi meminta izin untuk bersujud lalu ia diberi izin, sepertinya dikatakan kepadanya: Terbitlah dari tempat di mana kau datang. lalu ia terbit dari tempat terbenamnya, setelah itu beliau membaca: \"Dan itulah tempat ketetapannya.\" Berkata Abu Dzarr: Itulah bacaan Abdullah bin Mas'ud. Berkata Abu Isa: dalam hal ini ada hadits serupa dari Shafwan bin 'Assal, Hudzaifah bin Usaid, Anas, Abu Musa dan hadits ini hasan shahih."},"2113":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عَبْدِ الرَّحْمَنِ الْمَخْزُومِيُّ وَأَبُو بَكْرِ بْنُ نَافِعٍ وَغَيْرُ وَاحِدٍ قَالُوا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ زَيْنَبَ بِنْتِ أَبِي سَلَمَةَ عَنْ حَبِيبَةَ عَنْ أُمِّ حَبِيبَةَ عَنْ زَيْنَبَ بِنْتِ جَحْشٍ قَالَتْ اسْتَيْقَظَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ نَوْمٍ مُحْمَرًّا وَجْهُهُ وَهُوَ يَقُولُ لَا إِلَهَ إِلَّا اللَّهُ يُرَدِّدُهَا ثَلَاثَ مَرَّاتٍ وَيْلٌ لِلْعَرَبِ مِنْ شَرٍّ قَدْ اقْتَرَبَ فُتِحَ الْيَوْمَ مِنْ رَدْمِ يَأْجُوجَ وَمَأْجُوجَ مِثْلُ هَذِهِ وَعَقَدَ عَشْرًا قَالَتْ زَيْنَبُ قُلْتُ يَا رَسُولَ اللَّهِ أَفَنَهْلِكُ وَفِينَا الصَّالِحُونَ قَالَ نَعَمْ إِذَا كَثُرَ الْخُبْثُ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ جَوَّدَ سُفْيَانُ هَذَا الْحَدِيثَ هَكَذَا رَوَى الْحُمَيْدِيُّ وَعَلِيُّ بْنُ الْمَدِينِيِّ وَغَيْرُ وَاحِدٍ مِنْ الْحُفَّاظِ عَنْ سُفْيَانَ بْنِ عُيَيْنَةَ نَحْوَ هَذَا و قَالَ الْحُمَيْدِيُّ قَالَ سُفْيَانُ بْنُ عُيَيْنَةَ حَفِظْتُ مِنْ الزُّهْرِيِّ فِي هَذَا الْحَدِيثِ أَرْبَعَ نِسْوَةٍ زَيْنَبَ بِنْتَ أَبِي سَلَمَةَ عَنْ حَبِيبَةَ وَهُمَا رَبِيبَتَا النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أُمِّ حَبِيبَةَ عَنْ زَيْنَبَ بِنْتِ جَحْشٍ زَوْجَيْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهَكَذَا رَوَى مَعْمَرٌ وَغَيْرُهُ هَذَا الْحَدِيثَ عَنْ الزُّهْرِيِّ وَلَمْ يَذْكُرُوا فِيهِ عَنْ حَبِيبَةَ وَقَدْ رَوَى بَعْضُ أَصْحَابِ ابْنِ عُيَيْنَةَ هَذَا الْحَدِيثَ عَنْ ابْنِ عُيَيْنَةَ وَلَمْ يَذْكُرُوا فِيهِ عَنْ أُمِّ حَبِيبَةَ","id":"Telah menceritakan kepada kami [Sa'id bin Abdurrahman Al Makhzumi] dan [Abu Bakar bin Nafi'] serta lainnya, mereka berkata: telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dari ['Urwah bin Az Zubair] dari [Zainab binti Abu Salamah] dari [Habibah] dari [Ummu Habibah] dari [Zainab binti Jahsy] berkata: Rasulullah Shallallahu 'alaihi wa Salam bangun tidur 'Aisyah wajah memerah, beliau mengucapkan: LAA ILAAHA ILLALLAAH, beliau mengulanginya tiga kali, celakalah bagi bangsa arab karena keburukan yang telah mendekat, saat ini penghalang Ya'juj dan Ma'juj telah dibuka seperti ini -beliau memperagakan jarinya dengan membentuk angka sepuluh--. Berkata Zainab: Aku bertanya: Apakah kami akan binasa padahal di tengah-tengah kami ada orang-orang Shalih? Rasulullah Shallallahu 'alaihi wa Salam menjawab: \"Ya, bila kekejian kian banyak.\" Berkata Abu Isa: Hadits ini hasan shahih dan Sufyan memperindah hadits ini. seperti itulah [Al Humaidi], ['Ali bin Al Madini] dan yang lainnya dari para hafidz meriwayatkan dari [Sufyan bin 'Uyainah] seperti ini. berkata Al Humaidi: Berkata Sufyan bin 'Uyainah: Aku menghafal dari Az Zuhri dalam hadits ini ada empat wanita; Zainab binti Abu Salamah dari Habibah, keduanya adalah putri rabibah nabi Shallallahu 'alaihi wa Salam dari Ummu Habibah dari Zainab binti Jahsy, keduanya adalah istri nabi Shallallahu 'alaihi wa Salam. Seperti itulah [Ma'mar] dan lainnya meriwayatkan hadits ini dari [Az Zuhri] tapi mereka tidak menyebut: Dari Habibah dan sebagaian sahabat Ibnu 'Uyainah meriwayatkan hadits ini dari Ibnu 'Uyainah dan mereka tidak menyebutkan: Dari Ummu Habibah."},"2114":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ عَاصِمٍ عَنْ زِرٍّ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْرُجُ فِي آخِرِ الزَّمَانِ قَوْمٌ أَحْدَاثُ الْأَسْنَانِ سُفَهَاءُ الْأَحْلَامِ يَقْرَءُونَ الْقُرْآنَ لَا يُجَاوِزُ تَرَاقِيَهُمْ يَقُولُونَ مِنْ قَوْلِ خَيْرِ الْبَرِيَّةِ يَمْرُقُونَ مِنْ الدِّينِ كَمَا يَمْرُقُ السَّهْمُ مِنْ الرَّمِيَّةِ قَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عَلِيٍّ وَأَبِي سَعِيدٍ وَأَبِي ذَرٍّ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ فِي غَيْرِ هَذَا الْحَدِيثِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَيْثُ وَصَفَ هَؤُلَاءِ الْقَوْمَ الَّذِينَ يَقْرَءُونَ الْقُرْآنَ لَا يُجَاوِزُ تَرَاقِيَهُمْ يَمْرُقُونَ مِنْ الدِّينِ كَمَا يَمْرُقُ السَّهْمُ مِنْ الرَّمِيَّةِ إِنَّمَا هُمْ الْخَوَارِجُ الْحَرُورِيَّةُ وَغَيْرُهُمْ مِنْ الْخَوَارِجِ","id":"Telah menceritakan kepada kami [Abu Kuraib Muhammad bin Al 'Alla`] telah menceritakan kepada kami [Abu Bakar bin 'Ayyasy] dari ['Ashim] dari [Zirr] dari [Abdullah bin Mas'ud] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Di akhir zaman akan muncul kaum berusia muda, lemah akal, mereka membaca Al-Qur`an tidak mencapai kerongkongan (sebatas di mulut tak sampai hati), mereka mengatakan dari perkataan orang terbaik, mereka meninggalkan agama dengan cepatnya seperti terlepasnya anak panah dari panah.\" Berkata Abu Isa: dalam hal ini ada hadits serupa dari 'Ali, Abu Sa'id dan Abu Dzarr, hadits ini hasan shahih. diriwayatkan dalam selain hadits ini dari nabi Shallallahu 'alaihi wa Salam yang menyebutkan ciri-ciri kaum itu, mereka membaca Al-Qur`an dan tidak mencapai kerongkongan, mereka meninggalkan agama dengan cepatnya seperti terlepasnya anak panah dari panah itu tidak lain adalah kaum Khawarij Al Haruriyah dan kalangan Khawarij lain."},"2115":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ حَدَّثَنَا أَنَسُ بْنُ مَالِكٍ عَنْ أُسَيْدِ بْنِ حُضَيْرٍ أَنَّ رَجُلًا مِنْ الْأَنْصَارِ قَالَ يَا رَسُولَ اللَّهِ اسْتَعْمَلْتَ فُلَانًا وَلَمْ تَسْتَعْمِلْنِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّكُمْ سَتَرَوْنَ بَعْدِي أَثَرَةً فَاصْبِرُوا حَتَّى تَلْقَوْنِي عَلَى الْحَوْضِ قَالَ أَبُو عِيسَى وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Dawud] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] telah menceritakan kepada kami [Anas bin Malik] dari [Usaid bin Hudlair], seorang Anshar berkata: Wahai Rasulullah, anda menugaskan fi fulan tapi anda tidak menugaskanku. Rasulullah Shallallahu 'alaihi wa Salam bersabda: \" kalian akan melihat sifat mementingkan diri (egoism), bersabarlah kalian hingga kalian menemuiku di telaga. Berkata Abu Isa: Hadits ini hasan shahih."},"2116":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ الْأَعْمَشِ عَنْ زَيْدِ بْنِ وَهْبٍ عَنْ عَبْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّكُمْ سَتَرَوْنَ بَعْدِي أَثَرَةً وَأُمُورًا تُنْكِرُونَهَا قَالَ فَمَا تَأْمُرُنَا يَا رَسُولَ اللَّهِ قَالَ أَدُّوا إِلَيْهِمْ حَقَّهُمْ وَسَلُوا اللَّهَ الَّذِي لَكُمْ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Al A'masy] dari [Zaid bin Wahab] dari [Abdullah] dari nabi Shallallahu 'alaihi wa Salam bersabda: \" kalian akan melihat sikap mementingkan diri (egoism) dan hal-hal yang kalian ingkari. Bertanya Abdullah: Apa yang anda perintahkan kepada kami, wahai Rasulullah? Rasulullah Shallallahu 'alaihi wa Salam menjawab: \"Tunaikan hak mereka dan mintalah hak kalian kepada Allah.\" Berkata Abu Isa: hadits ini hasan shahih."},"2117":{"ar":"حَدَّثَنَا عِمْرَانُ بْنُ مُوسَى الْقَزَّازُ الْبَصْرِيُّ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا عَلِيُّ بْنُ زَيْدِ بْنِ جُدْعَانَ الْقُرَشِيُّ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَصَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا صَلَاةَ الْعَصْرِ بِنَهَارٍ ثُمَّ قَامَ خَطِيبًا فَلَمْ يَدَعْ شَيْئًا يَكُونُ إِلَى قِيَامِ السَّاعَةِ إِلَّا أَخْبَرَنَا بِهِ حَفِظَهُ مَنْ حَفِظَهُ وَنَسِيَهُ مَنْ نَسِيَهُ وَكَانَ فِيمَا قَالَ إِنَّ الدُّنْيَا حُلْوَةٌ خَضِرَةٌ وَإِنَّ اللَّهَ مُسْتَخْلِفُكُمْ فِيهَا فَنَاظِرٌ كَيْفَ تَعْمَلُونَ أَلَا فَاتَّقُوا الدُّنْيَا وَاتَّقُوا النِّسَاءَ وَكَانَ فِيمَا قَالَ أَلَا لَا يَمْنَعَنَّ رَجُلًا هَيْبَةُ النَّاسِ أَنْ يَقُولَ بِحَقٍّ إِذَا عَلِمَهُ قَالَ فَبَكَى أَبُو سَعِيدٍ فَقَالَ قَدْ وَاللَّهِ رَأَيْنَا أَشْيَاءَ فَهِبْنَا فَكَانَ فِيمَا قَالَ أَلَا إِنَّهُ يُنْصَبُ لِكُلِّ غَادِرٍ لِوَاءٌ يَوْمَ الْقِيَامَةِ بِقَدْرِ غَدْرَتِهِ وَلَا غَدْرَةَ أَعْظَمُ مِنْ غَدْرَةِ إِمَامِ عَامَّةٍ يُرْكَزُ لِوَاؤُهُ عِنْدَ اسْتِهِ فَكَانَ فِيمَا حَفِظْنَا يَوْمَئِذٍ أَلَا إِنَّ بَنِي آدَمَ خُلِقُوا عَلَى طَبَقَاتٍ شَتَّى فَمِنْهُمْ مَنْ يُولَدُ مُؤْمِنًا وَيَحْيَا مُؤْمِنًا وَيَمُوتُ مُؤْمِنًا وَمِنْهُمْ مَنْ يُولَدُ كَافِرًا وَيَحْيَا كَافِرًا وَيَمُوتُ كَافِرًا وَمِنْهُمْ مَنْ يُولَدُ مُؤْمِنًا وَيَحْيَا مُؤْمِنًا وَيَمُوتُ كَافِرًا وَمِنْهُمْ مَنْ يُولَدُ كَافِرًا وَيَحْيَا كَافِرًا وَيَمُوتُ مُؤْمِنًا أَلَا وَإِنَّ مِنْهُمْ الْبَطِيءَ الْغَضَبِ سَرِيعَ الْفَيْءِ وَمِنْهُمْ سَرِيعُ الْغَضَبِ سَرِيعُ الْفَيْءِ فَتِلْكَ بِتِلْكَ أَلَا وَإِنَّ مِنْهُمْ سَرِيعَ الْغَضَبِ بَطِيءَ الْفَيْءِ أَلَا وَخَيْرُهُمْ بَطِيءُ الْغَضَبِ سَرِيعُ الْفَيْءِ أَلَا وَشَرُّهُمْ سَرِيعُ الْغَضَبِ بَطِيءُ الْفَيْءِ أَلَا وَإِنَّ مِنْهُمْ حَسَنَ الْقَضَاءِ حَسَنَ الطَّلَبِ وَمِنْهُمْ سَيِّئُ الْقَضَاءِ حَسَنُ الطَّلَبِ وَمِنْهُمْ حَسَنُ الْقَضَاءِ سَيِّئُ الطَّلَبِ فَتِلْكَ بِتِلْكَ أَلَا وَإِنَّ مِنْهُمْ السَّيِّئَ الْقَضَاءِ السَّيِّئَ الطَّلَبِ أَلَا وَخَيْرُهُمْ الْحَسَنُ الْقَضَاءِ الْحَسَنُ الطَّلَبِ أَلَا وَشَرُّهُمْ سَيِّئُ الْقَضَاءِ سَيِّئُ الطَّلَبِ أَلَا وَإِنَّ الْغَضَبَ جَمْرَةٌ فِي قَلْبِ ابْنِ آدَمَ أَمَا رَأَيْتُمْ إِلَى حُمْرَةِ عَيْنَيْهِ وَانْتِفَاخِ أَوْدَاجِهِ فَمَنْ أَحَسَّ بِشَيْءٍ مِنْ ذَلِكَ فَلْيَلْصَقْ بِالْأَرْضِ قَالَ وَجَعَلْنَا نَلْتَفِتُ إِلَى الشَّمْسِ هَلْ بَقِيَ مِنْهَا شَيْءٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا إِنَّهُ لَمْ يَبْقَ مِنْ الدُّنْيَا فِيمَا مَضَى مِنْهَا إِلَّا كَمَا بَقِيَ مِنْ يَوْمِكُمْ هَذَا فِيمَا مَضَى مِنْهُقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ حُذَيْفَةَ وَأَبِي مَرْيَمَ وَأَبِي زَيْدِ بْنِ أَخْطَبَ وَالْمُغِيرَةِ بْنِ شُعْبَةَ وَذَكَرُوا أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَهُمْ بِمَا هُوَ كَائِنٌ إِلَى أَنْ تَقُومَ السَّاعَةُ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami ['Imran bin Musa Al Qazzaz Al Bashri] telah menceritakan kepada kami [Hammad bin Zaid] telah menceritakan kepada kami ['Ali bin Zaid bin Jud'an Al Qurasy] dari [Abu Nadlrah] dari [Abu Sa'id Al Khudri] berkata: Rasulullah Shallallahu 'alaihi wa Salam shalat ashar bersama kami pada suatu hari setelah itu beliau berkhotbah, beliau tidak meninggalkan apa pun yang ada dihadapan hari kiamat melainkan beliau pasti memberitahukannya kepada kami, siapa yang hafal musti hafal dan siapa yang lupa pasti melupakannya. Diantara yang beliau sampaikan: \" dunia manis dan hijau dan Allah akan menjadikan kalian sebagai pemimpinnya lalu Ia akan memperhatikan apa yang kalian lakukan, ingat, takutlah pada dunia, takutlah pada wanita.\" Diantara yang beliau sampaikan: \"Ingat, jangan sampai rasa segan pada manusia menghalangi seseorang untuk menyampaikan kebenaran bila ia mengetahuinya.\" Abu Sa'id menangis lalu berkata: Demi Allah, kami telah melihat berbagai hal lalu kami takut dan diantara yang beliau sampaikan: \"Ingat, untuk setiap pengkhianat akan ditegakkan bendera baginya pada hari kiamat berdasarkan tingkat pengkhianatannya dan tidak ada pengkhianatan yang lebih besar dari pengkhianatan pemimpin rakyat, benderanya dipusatkan didekat pantatnya.\" Diantara yang kami hafal saat itu: \"Ingat, anak cucu Adam diciptakan diatas beberapa tingkatan yang banyak, diantara mereka ada yang dilahirkan dalam keadaan mu`min dan mati dalam keadaan mu`min, diantara mereka ada yang terlahir kafir, hidup sebagai orang kafir dan mati dalam keadaan kafir, diantara mereka ada yang terlahir mu`min, hidup sebagai mu`min dan mati dalam keadaan kafir, diantara mereka ada yang terlahir kafir, hidup sebagai orang kafir tapi mati dalam keadaan beriman, ingat, diantara mereka ada yang lamban marah dan cepat sadar, ada juga yang cepat marah dan cepat sadar, maka itu sebagai ganti yang itu, ingat, diantara mereka ada yang cepat marah dan lamban sadar, ingat, yang terbaik dari mereka adalah yang lamban marah tapi cepat sadar, ingat yang terburuk dari mereka adalah yang cepat marah dan lamban sadar, ingat, diantara mereka ada yang menunaikan (hutang) dengan baik dan menagih dengan baik, diantara mereka ada yang menunaikan (hutang) dengan buruk dan menagih dengan buruk, ingat dan yang terbaik dari mereka adalah yang menunaikan (hutang) dengan baik dan menagih dengan baik, ingat, dan yang paling buruk dari mereka adalah yang menunaikan (hutang) dengan buruk dan menagih (hutang) dengan buruk, ingat, marah itu bara api di hati manusia, apa kalian tidak melihat merahnya mata orang marah dan uratnya membengkak. Barangsiapa yang merasakan sesuatu darinya, hendaklah menempel tanah.\" Berkata Ibnu Mas'ud: Kami lalu melihat matahari, apakah masih ada yang tersisa lalu Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Ingatlah, tidaklah tersisa dari dunia dari waktu yang telah berlalu kecuali seperti sisa hari kalian yang masih ada ini dari hari yang telah berlalu.\" Berkata Abu Isa: dalam hal ini ada hadits serupa dari Hudzaifah, Abu Maryam, Abu Zaid bin Akhthab dan Al Mughirah bin Syu'bah, mereka menyebutkan bahwa nabi Shallallahu 'alaihi wa Salam menceritakan apa yang akan terjadi hingga hari kiamat terjadi kepada mereka. hadits ini hasan shahih."},"2118":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا شُعْبَةُ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ عَنْ أَبِيهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا فَسَدَ أَهْلُ الشَّامِ فَلَا خَيْرَ فِيكُمْ لَا تَزَالُ طَائِفَةٌ مِنْ أُمَّتِي مَنْصُورِينَ لَا يَضُرُّهُمْ مَنْ خَذَلَهُمْ حَتَّى تَقُومَ السَّاعَةُ قَالَ مُحَمَّدُ بْنُ إِسْمَعِيلَ قَالَ عَلِيُّ بْنُ الْمَدِينِيِّ هُمْ أَصْحَابُ الْحَدِيثِ قَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ حَوَالَةَ وَابْنِ عُمَرَ وَزَيْدِ بْنِ ثَابِتٍ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا بَهْزُ بْنُ حَكِيمٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ أَيْنَ تَأْمُرُنِي قَالَ هَا هُنَا وَنَحَا بِيَدِهِ نَحْوَ الشَّامِ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Daud] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami dari [Mu'awiyah bin Qurrah] dari [bapaknya] berkata \" Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Jika penduduk Syam telah rusak maka tidak ada kebaikan lagi di antara kalian, akan senantiasa ada sekelompok dari ummatku yang diberi kemenangan, orang orang yang menghina mereka tidak akan membahayakan mereka sampai hari kiamat.\" Muhammad bin Isma'il berkata bahwa Ali bin Al Madini berkata: Mereka itu adalah ahli hadits. Abu Isa berkata: dan dalam bab ini ada hadits dari Abdullah bin Hawalah, Ibnu Umar, Zaid bin Tsabit dan Abdullah bin 'Amru, dan hadits ini hasan shahih. [Ahmad bin Mani'] telah menceritakan kepada kami bahwa [Yazid bin Harun] telah menceritakan kepada kami bahwa [Bahz bin Hakim] telah mengkhabarkan kepada kami dari [bapaknya] dari [kakeknya] dia berkata: Aku bertanya Wahai Rasulullah, kemana yang engkau perintahkan kepadaku? beliau menjawab: Ke sana.\" beliau menunjuk dengan tangannya ke arah Syam. Abu Isa berkata: Hadits ini hasan shahih."},"2119":{"ar":"حَدَّثَنَا أَبُو حَفْصٍ عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا فُضَيْلُ بْنُ غَزْوَانَ حَدَّثَنَا عِكْرِمَةُ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَرْجِعُوا بَعْدِي كُفَّارًا يَضْرِبُ بَعْضُكُمْ رِقَابَ بَعْضٍقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ وَجَرِيرٍ وَابْنِ عُمَرَ وَكُرْزِ بْنِ عَلْقَمَةَ وَوَاثِلَةَ وَالصُّنَابِحِيِّ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Abu Hafs 'Amru bin 'Ali] menceritakan kepada kami bahwa [Yahya bin Sa'id] telah menceritakan kepada kami bahwa [Fudlail bin Ghozwan] telah menceritakan kepada kami bahwa [Ikrimah] telah menceritakan kepada kami dari [Ibnu 'Abbas] dia berkata bahwa Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Janganlah kalian kembali menjadi kafir sepeninggalku, satu sama lain saling berperang.\" Abu Isa berkata: Dan dalam bab ini ada hadits dari Abdullah bin Mas'ud, Jarir, Ibnu Umar, Kurz bin Al Qamah, Watsilah dan Ash Shunabihi dan hadits ini hasan shahih."},"2120":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ عَيَّاشِ بْنِ عَبَّاسٍ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ بُسْرِ بْنِ سَعِيدٍ أَنَّ سَعْدَ بْنَ أَبِي وَقَّاصٍقَالَ عِنْدَ فِتْنَةِ عُثْمَانَ بْنِ عَفَّانَ أَشْهَدُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّهَا سَتَكُونُ فِتْنَةٌ الْقَاعِدُ فِيهَا خَيْرٌ مِنْ الْقَائِمِ وَالْقَائِمُ خَيْرٌ مِنْ الْمَاشِي وَالْمَاشِي خَيْرٌ مِنْ السَّاعِي قَالَ أَفَرَأَيْتَ إِنْ دَخَلَ عَلَيَّ بَيْتِي وَبَسَطَ يَدَهُ إِلَيَّ لِيَقْتُلَنِي قَالَ كُنْ كَابْنِ آدَمَقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَخَبَّابِ بْنِ الْأَرَتِّ وَأَبِي بَكْرَةَ وَابْنِ مَسْعُودٍ وَأَبِي وَاقِدٍ وَأَبِي مُوسَى وَخَرَشَةَ وَهَذَا حَدِيثٌ حَسَنٌ وَرَوَى بَعْضُهُمْ هَذَا الْحَدِيثَ عَنْ اللَّيْثِ بْنِ سَعْدٍ وَزَادَ فِي هَذَا الْإِسْنَادِ رَجُلًا قَالَ أَبُو عِيسَى وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ سَعْدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ غَيْرِ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari ['Ayyasy bin 'Abbas] dari [Bukair bin Abdullah bin Al Asyujj] dari [Busr bin Sa'id] bahwa [Sa'ad bin Abi Waqqash] berkata saat terjadi fitnah yang menimpa 'Utsman bin 'Affan: Aku bersaksi bahwa Rasulullah Shallallahu 'alaihi wa Salam bersabda: \" akan terjadi fitnah, orang duduk saat itu lebih baik dari orang berdiri, orang yang berdiri lebih baik dari orang yang berjalan, orang yang berjalan lebih baik dari orang yang berlari kecil.\" Abu Sa'id bertanya: Bagaimana menurut baginda bila seseorang masuk ke rumahku dan ia membentangkan tangannya kepadaku untuk membunuhku? Rasulullah Shallallahu 'alaihi wa Salam menjawab: \"Jadilah seperti putra Adam.\" Berkata Abu Isa: dalam hal ini ada hadits serupa dari Abu Hurairah, Khabbab bin Al Arat, Abu Bakrah, Ibnu Mas'ud, Abu Waqid, Abu Musa dan Kharasyah dan hadits ini hasan. Sebagian dari mereka meriwayatkan hadits ini dari Al Laits bin Sa'ad dan menambahkan seseorang dalam sanad dalam ini. berkata Abu Isa: Hadits ini juga diriwayatkan dari Sa'ad dari nabi Shallallahu 'alaihi wa Salam melalui sanad lain."},"2121":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَادِرُوا بِالْأَعْمَالِ فِتَنًا كَقِطَعِ اللَّيْلِ الْمُظْلِمِ يُصْبِحُ الرَّجُلُ مُؤْمِنًا وَيُمْسِي كَافِرًا وَيُمْسِي مُؤْمِنًا وَيُصْبِحُ كَافِرًا يَبِيعُ أَحَدُهُمْ دِينَهُ بِعَرَضٍ مِنْ الدُّنْيَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abdul 'Aziz bin Muhammad] dari [Al 'Alla` bin Abdurrahman] dari [ayahnya] dari [Abu Huraiah], Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Segeralah melakukan berbagai amal sebelum datangnya berbagai fitnah seperti bagian malam gelap, di pagi hari seseorang beriman dan di sore hari menjadi kafir, sore hari beriman dan di pagi hari menjadi kafir, salah seorang dari mereka menjual agamanya dengan barang dunia.\" Berkata Abu Isa: Hadits ini hasan shahih."},"2122":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ نَصْرٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ هِنْدٍ بِنْتِ الْحَارِثِ عَنْ أُمِّ سَلَمَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَيْقَظَ لَيْلَةً فَقَالَ سُبْحَانَ اللَّهِ مَاذَا أُنْزِلَ اللَّيْلَةَ مِنْ الْفِتْنَةِ مَاذَا أُنْزِلَ مِنْ الْخَزَائِنِ مَنْ يُوقِظُ صَوَاحِبَ الْحُجُرَاتِ يَا رُبَّ كَاسِيَةٍ فِي الدُّنْيَا عَارِيَةٌ فِي الْآخِرَةِهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Suwaid bin Nashr] telah menceritakan kepada kami [Abdullah bin Al Mubarak] telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Hindun binti Al Harits] dari [Ummu Salamah], pada suatu malam nabi Shallallahu 'alaihi wa Salam bangun lalu bersabda: \"Subhaanallaah, fitnah apa yang diturunkan tadi malam, harta simpanan apa yang diturunkan, siapa yang membangunkan orang-orang tidur, alangkah banyaknya wanita berpakaian di dunia tapi telanjang di akhirat.\" Hadits ini hasan shahih."},"2123":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ سَعْدِ بْنِ سِنَانٍ عَنْ أَنَسِ بْنِ مَالِكٍ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَكُونُ بَيْنَ يَدَيْ السَّاعَةِ فِتَنٌ كَقِطَعِ اللَّيْلِ الْمُظْلِمِ يُصْبِحُ الرَّجُلُ فِيهَا مُؤْمِنًا وَيُمْسِي كَافِرًا وَيُمْسِي مُؤْمِنًا وَيُصْبِحُ كَافِرًا يَبِيعُ أَقْوَامٌ دِينَهُمْ بِعَرَضٍ مِنْ الدُّنْيَا قَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَجُنْدَبٍ وَالنُّعْمَانِ بْنِ بَشِيرٍ وَأَبِي مُوسَى وَهَذَا حَدِيثٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits bin Sa'ad] telah menceritakan kepada kami [Yazid bin Abu Habib] dari [Sa'ad bin Sinan] dari [Anas bin Malik] dari Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Pada akhir masa menjelang kiamat akan terjadi fitnah seperti waktu malam yang gelap gulita, ketika itu seseorang beriman di waktu pagi hari namun menjadi kafir pada sore harinya, dan sore hari beriman namun pagi harinya menjadi kafir, segolongan orang menjual agama mereka dengan materi duniawi.\" Abu Isa berkata: Dan dalam bab ini ada hadits dari Abu Hurairah, Jundub, Nu'man bin Basyir dan Abu Musa, dan hadits ini gharib dari jalur sanad ini."},"2124":{"ar":"حَدَّثَنَا صَالِحُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا جَعْفَرُ بْنُ سُلَيْمَانَ عَنْ هِشَامٍ عَنْ الْحَسَنِ قَالَ كَانَ يَقُولُ فِي هَذَا الْحَدِيثِ يُصْبِحُ الرَّجُلُ مُؤْمِنًا وَيُمْسِي كَافِرًا وَيُمْسِي مُؤْمِنًا وَيُصْبِحُ كَافِرًا قَالَ يُصْبِحُ الرَّجُلُ مُحَرِّمًا لِدَمِ أَخِيهِ وَعِرْضِهِ وَمَالِهِ وَيُمْسِي مُسْتَحِلًّا لَهُ وَيُمْسِي مُحَرِّمًا لِدَمِ أَخِيهِ وَعِرْضِهِ وَمَالِهِ وَيُصْبِحُ مُسْتَحِلًّا لَهُ","id":"Telah menceritakan kepada kami [Shalih bin Abdullah] telah menceritakan kepada kami [Ja'far bin Sulaiman] dari [Hisyam] dari [Al Hasan] berkata: beliau bersabda dalam hadits ini: \"Di pagi hari seseorang beriman dan di sore hari menjadi kafir, beriman di waktu sore dan di pag hari menjadi kafir.\" Beliau bersabda: \"Di pagi hari seseorang mengharamkan darah, kehormatan dan harta saudaranya tapi di sore hari menghalalkannya, di sore hari mengharamkan darah, kehormatan dan harta saudaranya dan si pagi hari menghalalkannya.\""},"2125":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا شُعْبَةُ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ عَلْقَمَةَ بْنِ وَائِلِ بْنِ حُجْرٍ عَنْ أَبِيهِ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَجُلٌ سَأَلَهُ فَقَالَ أَرَأَيْتَ إِنْ كَانَ عَلَيْنَا أُمَرَاءُ يَمْنَعُونَا حَقَّنَا وَيَسْأَلُونَا حَقَّهُمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْمَعُوا وَأَطِيعُوا فَإِنَّمَا عَلَيْهِمْ مَا حُمِّلُوا وَعَلَيْكُمْ مَا حُمِّلْتُمْ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Khollal] telah menceritakan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Syu'bah] telah mengkhabarkan kepada kami [Simak bin Harb] dari [Al Qomah bin Wa'il bin Hujr] dari [bapaknya] dia berkata: Aku mendengar Rasulullah Shallallahu 'alaihi wa Salam bersabda ketika ada seorang bertanya kepadanya: Bagaimana pendapat baginda jika para pemimpin kami menahan hak hak kami sementara mereka menuntuk hak mereka kepada kami? Rasulullah Shallallahu 'alaihi wa Salam menjawab: \"Mendengar dan taatlah kalian, karena kewajiban mereka adalah apa yang mereka emban dan kewajiban kalian adalah apa yang ada pada kalian.\" Abu Isa berkata: hadits ini hasan shahih."},"2126":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ شَقِيقِ بْنِ سَلَمَةَ عَنْ أَبِي مُوسَى قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ وَرَائِكُمْ أَيَّامًا يُرْفَعُ فِيهَا الْعِلْمُ وَيَكْثُرُ فِيهَا الْهَرْجُ قَالُوا يَا رَسُولَ اللَّهِ مَا الْهَرْجُ قَالَ الْقَتْلُ قَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَخَالِدِ بْنِ الْوَلِيدِ وَمَعْقِلِ بْنِ يَسَارٍ وَهَذَا حَدِيثٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Syaqiq bin Salamah] dari [Abu Musa] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \" dibelakang kalian ada hari-hari yang ketika itu ilmu dihilangkan dan banyak haraj.\" Mereka bertanya: Apa itu haraj wahai Rasulullah? Rasulullah Shallallahu 'alaihi wa Salam menjawab: \"Pembunuhan.\" Berkata Abu Isa:; dalam hal ini ada hadits serupa dari Abu Hurairah, Khalid bin Al Walid, Ma'qal bin Yasar dan hadits ini shahih."},"2127":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ الْمُعَلَّى بْنِ زِيَادٍ رَدَّهُ إِلَى مُعَاوِيَةَ بْنِ قُرَّةَ رَدَّهُ إِلَى مَعْقِلِ بْنِ يَسَارٍ رَدَّهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْعِبَادَةُ فِي الْهَرْجِ كَالْهِجْرَةِ إِلَيَّ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ صَحِيحٌ غَرِيبٌ إِنَّمَا نَعْرِفُهُ مِنْ حَدِيثِ حَمَّادِ بْنِ زَيْدٍ عَنْ الْمُعَلَّى","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Hammad bin Zaid] dari [Mu'alla bin Ziyad] mengembalikannya kepada [Mu'awiyah bin Qurrah] mengembalikannya kepada [Ma'qil bin Yasar] mengembalikannya kepada nabi Shallallahu 'alaihi wa Salam bersabda: \"Ibadah saat terjadi pembunuhan sama seperti hijrah kepadaku.\" Berkata Abu Isa: Hadits ini gharib, kami hanya mengetahuinya dari hadits Hammad bin Zaid dari Mu'alla."},"2128":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي أَسْمَاءَ عَنْ ثَوْبَانَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا وُضِعَ السَّيْفُ فِي أُمَّتِي لَمْ يُرْفَعْ عَنْهَا إِلَى يَوْمِ الْقِيَامَةِ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Abu Qilabah] dari [Abu Asma`] dari [Tsauban] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Bila pedang telah diletakkan ditengah-tengah ummatku tidak akan terangkat hingga hari kiamat.\" Berkata Abu Isa: hadits ini hasan shahih."},"2129":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ عَبْدِ اللَّهِ بْنِ عُبَيْدٍ عَنْ عُدَيْسَةَ بِنْتِ أُهْبَانَ بْنِ صَيْفِيٍّ الْغِفَارِيِّ قَالَتْ جَاءَ عَلِيُّ بْنُ أَبِي طَالِبٍ إِلَى أَبِي فَدَعَاهُ إِلَى الْخُرُوجِ مَعَهُ فَقَالَ لَهُ أَبِي إِنَّ خَلِيلِي وَابْنَ عَمِّكَ عَهِدَ إِلَيَّ إِذَا اخْتَلَفَ النَّاسُ أَنْ أَتَّخِذَ سَيْفًا مِنْ خَشَبٍ فَقَدْ اتَّخَذْتُهُ فَإِنْ شِئْتَ خَرَجْتُ بِهِ مَعَكَ قَالَتْ فَتَرَكَهُ قَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ مُحَمَّدِ بْنِ مَسْلَمَةَ وَهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ عَبْدِ اللَّهِ بْنِ عُبَيْدٍ","id":"Telah menceritakan kepada kami ['Ali bin Hujr] telah menceritakan kepada kami [Isma'il bin Ibrahim] dari [Abdullah bin 'Ubaid] dari ['Udaisah binti Uhban bin Shaifi Al Ghifari] berkata: 'Ali bin Abi Thalib mendatangi ayahku lalu mengajaknya pergi, [ayahku] berkata kepada 'Ali: kekasihku dan putra pamanmu (Rasulullah Shallallahu 'alaihi wa Salam) memerintahkanku bila orang-orang berseteru agar aku membuat pedang dari kayu dan aku sudah membuatnya, bila kau mau, aku akan membawanya bersamamu. Berkata 'Udaisah: Lalu 'Ali meninggalkannya. Berkata Abu Isa: dalam hal ini ada hadits serupa dari Muhammad bin Maslamah dan hadits ini hasan gharib, kami hanya mengetahuinya dari hadits Abdullah bin 'Ubaid."},"2130":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ حَدَّثَنَا سَهْلُ بْنُ حَمَّادٍ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا مُحَمَّدُ بْنُ جُحَادَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ ثَرْوَانَ عَنْ هُزَيْلِ بْنِ شُرَحْبِيلَ عَنْ أَبِي مُوسَىعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ فِي الْفِتْنَةِ كَسِّرُوا فِيهَا قَسِيَّكُمْ وَقَطِّعُوا فِيهَا أَوْتَارَكُمْ وَالْزَمُوا فِيهَا أَجْوَافَ بُيُوتِكُمْ وَكُونُوا كَابْنِ آدَمَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ صَحِيحٌ وَعَبْدُ الرَّحْمَنِ بْنُ ثَرْوَانَ هُوَ أَبُو قَيْسٍ الْأَوْدِيُّ","id":"Telah menceritakan kepada kami [Abdullah bin Abdurrahman] telah menceritakan kepada kami [Sahl bin Hammad] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Muhammad bin Juhadah] telah menceritakan kepada kami [Abdurrahman bin Tsarwan] dari [Huzail bin Syurahbil] dari [Abu Musa] dari Nabi Shallallahu 'alaihi wa Salam bersabda tentang fitnah: \"Patahkanlah busur busur panah kalian pada saat itu, putuskanlah tali tali busur kalian, menetaplah dalam rumah rumah kalian dan jadilah seperti putra Adam.\" Abu Isa berkata: Hadits ini hasan gharib shahih, Abdurrahman bin Tsarwan adalah Abu Qais Al Audi."},"2131":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا النَّضْرُ بْنُ شُمَيْلٍ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّهُ قَالَأُحَدِّثُكُمْ حَدِيثًا سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُحَدِّثُكُمْ أَحَدٌ بَعْدِي أَنَّهُ سَمِعَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ أَشْرَاطِ ا��سَّاعَةِ أَنْ يُرْفَعَ الْعِلْمُ وَيَظْهَرَ الْجَهْلُ وَيَفْشُوَ الزِّنَا وَتُشْرَبَ الْخَمْرُ وَيَكْثُرَ النِّسَاءُ وَيَقِلَّ الرِّجَالُ حَتَّى يَكُونَ لِخَمْسِينَ امْرَأَةٍ قَيِّمٌ وَاحِدٌقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أَبِي مُوسَى وَأَبِي هُرَيْرَةَ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [An Nadlr bin Syumail] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Anas bin Malik] berkata: Aku akan menceritakan suatu hadits kepada kalian yang aku dengar dari Rasulullah Shallallahu 'alaihi wa Salam, tidak akan ada seorang pun yang menceritakannya kepada kalian sepeninggalku, ia mendengar Rasulullah Shallallahu 'alaihi wa Salam. Berkata Anas: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Diantara tanda-tanda kiamat; hilangnya ilmu, munculnya kebodohan, tersebarnya perzihanan, khamar diminum, banyaknya wanita sementara lelaki sedikit hingga limapuluh wanita diurus oleh seorang lelaki.\" Berkata Abu Isa: dalam hal ini ada hadits serupa dari Abu Musa dan Abu Hurairah dan hadits ini hasan shahih."},"2132":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ سُفْيَانَ الثَّوْرِيِّ عَنْ الزُّبَيْرِ بْنِ عَدِيٍّ قَالَدَخَلْنَا عَلَى أَنَسِ بْنِ مَالِكٍ فَشَكَوْنَا إِلَيْهِ مَا نَلْقَى مِنْ الْحَجَّاجِ فَقَالَ مَا مِنْ عَامٍ إِلَّا الَّذِي بَعْدَهُ شَرٌّ مِنْهُ حَتَّى تَلْقَوْا رَبَّكُمْ سَمِعْتُ هَذَا مِنْ نَبِيِّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Sufyan Ats Tsauri] dari [Az Zubair bin 'Adi] berkata: Kami bertamu ke kediaman [Anas bin Malik], kami mengeluhkan perlakuan yang kami terima dari Al Hajjaj kepadanya lalu ia berkata: Tidaklah ada suatu tahun melainkan setelahnya akan lebih buruk lagi hingga kalian menemui Rabb, aku mendengar ini dari nabi kalian Shallallahu 'alaihi wa Salam. Berkata Abu Isa: Hadits ini hasan shahih."},"2133":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ حُمَيْدٍ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقُومُ السَّاعَةُ حَتَّى لَا يُقَالَ فِي الْأَرْضِ اللَّهُ اللَّهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ عَنْ حُمَيْدٍ عَنْ أَنَسٍ نَحْوَهُ وَلَمْ يَرْفَعْهُ وَهَذَا أَصَحُّ مِنْ الْحَدِيثِ الْأَوَّلِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Ibnu Abi 'Adi] dari [Humaid] dari [Anas] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Kiamat tidak akan terjadi hingga di bumi tidak ada yang mengucapkan: Allah, Allah.\" Berkata Abu Isa: Hadits ini hasan. Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Khalid bin Al Harits] dari [Humaid] dari [Anas] sepertinya tapi ia tidak memarfu'kannya dan hadits ini lebih shahih dari hadits pertama."},"2134":{"ar":"حَدَّثَنَا وَاصِلُ بْنُ عَبْدِ الْأَعْلَى الْكُوفِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَقِيءُ الْأَرْضُ أَفْلَاذَ كَبِدِهَا أَمْثَالَ الْأُسْطُوَانِ مِنْ الذَّهَبِ وَالْفِضَّةِ قَالَ فَيَجِيءُ السَّارِقُ فَيَقُولُ فِي مِثْلِ هَذَا قُطِعَتْ يَدِي وَيَجِيءُ الْقَاتِلُ فَيَقُولُ فِي هَذَا قَتَلْتُ وَيَجِيءُ الْقَاطِعُ فَيَقُولُ فِي هَذَا قَطَعْتُ رَحِمِي ثُمَّ يَدَعُونَهُ فَلَا يَأْخُذُونَ مِنْهُ شَيْئًاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Washil bin Abdul A'la Al Kufi] telah menceritakan kepada kami [Muhammad bin Fudlail] telah menceritakan kepada [bapakku] dari [Abu Hazim] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Bumi akan mengeluarkan isinya seperti tiang tiang dari emas dan perak, \" berkata Abu Hurairah: Nabi Shallallahu 'alaihi wa Salam bersabda: \"Lalu datanglah seorang pencuri lalu berkata: Untuk seperti ini tanganku terpotong, kemudian datang seorang pembunuh lalu berkata: Untuk seperti ini aku membunuh, kemudian datanglah seorang yang memutuskan tali silaturahim lalu berkata: Aku telah memutuskan tali silaturrahim, kemudian mereka meninggalkan harta itu dan tidak mengambilnya sedikitpun.\" Abu Isa berkata: Hadits ini hasan shahih gharib, kami tidak mengetahuinya kecuali dari jalur sanad ini."},"2135":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ عَمْرِو بْنِ أَبِي عَمْرٍو قَالَ ح و حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا إِسْمَعِيلُ بْنُ جَعْفَرٍ عَنْ عَمْرِو بْنِ أَبِي عَمْرٍو عَنْ عَبْدِ اللَّهِ وَهُوَ ابْنُ عَبْدِ الرَّحْمَنِ الْأَنْصَارِيُّ الْأَشْهَلِيُّ عَنْ حُذَيْفَةَ بْنِ الْيَمَانِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقُومُ السَّاعَةُ حَتَّى يَكُونَ أَسْعَدَ النَّاسِ بِالدُّنْيَا لُكَعُ ابْنُ لُكَعٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ إِنَّمَا نَعْرِفُهُ مِنْ حَدِيثِ عَمْرِو بْنِ أَبِي عَمْرٍو","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami ['Abdul 'Aziz bin Muhammad] dari ['Amru bin Abu 'Amru] berkata, dan telah menceritakan kepada kami ['Ali bin Hujr] telah memberitakan kepada kami [Isma'il bin Ja'far bin Abu 'Amru] dari [Abdullah bin Abdurrahman Al Anshari Al Asyhali] dari [Hudzaifah bin Al Yaman] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Kiamat tidak akan terjadi hingga orang yang paling bahagia di dunia adalah orang hina putra orang hina.\" Berkata Abu Isa: hadits ini hasan, kami hanya mengetahuinya dari hadits 'Amru bin Abu 'Amru."},"2136":{"ar":"حَدَّثَنَا صَالِحُ بْنُ عَبْدِ اللَّهِ التِّرْمِذِيُّ حَدَّثَنَا الْفَرَجُ بْنُ فَضَالَةَ أَبُو فَضَالَةَ الشَّامِيُّ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ عَلِيٍّ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا فَعَلَتْ أُمَّتِي خَمْسَ عَشْرَةَ خَصْلَةً حَلَّ بِهَا الْبَلَاءُ فَقِيلَ وَمَا هُنَّ يَا رَسُولَ اللَّهِ قَالَ إِذَا كَانَ الْمَغْنَمُ دُوَلًا وَالْأَمَانَةُ مَغْنَمًا وَالزَّكَاةُ مَغْرَمًا وَأَطَاعَ الرَّجُلُ زَوْجَتَهُ وَعَقَّ أُمَّهُ وَبَرَّ صَدِيقَهُ وَجَفَا أَبَاهُ وَارْتَفَعَتْ الْأَصْوَاتُ فِي الْمَسَاجِدِ وَكَانَ زَعِيمُ الْقَوْمِ أَرْذَلَهُمْ وَأُكْرِمَ الرَّجُلُ مَخَافَةَ شَرِّهِ وَشُرِبَتْ الْخُمُورُ وَلُبِسَ الْحَرِيرُ وَاتُّخِذَتْ الْقَيْنَاتُ وَالْمَعَازِفُ وَلَعَنَ آخِرُ هَذِهِ الْأُمَّةِ أَوَّلَهَا فَلْيَرْتَقِبُوا عِنْدَ ذَلِكَ رِيحًا حَمْرَاءَ أَوْ خَسْفًا وَمَسْخًا قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ مِنْ حَدِيثِ عَلِيِّ بْنِ أَبِي طَالِبٍ إِلَّا مِنْ هَذَا الْوَجْهِ وَلَا نَعْلَمُ أَحَدًا رَوَاهُ عَنْ يَحْيَى بْنِ سَعِيدٍ الْأَنْصَارِيِّ غَيْرَ الْفَرَجِ بْنِ فَضَالَةَ وَالْفَرَجُ بْنُ فَضَالَةَ قَدْ تَكَلَّمَ فِيهِ بَعْضُ أَهْلِ الْحَدِيثِ وَضَعَّفَهُ مِنْ قِبَلِ حِفْظِهِ وَقَدْ رَوَاهُ عَنْهُ وَكِيعٌ وَغَيْرُ وَاحِدٍ مِنْ الْأَئِمَّةِ","id":"Telah menceritakan kepada kami [Shalih bin 'Abdillah At Tirmidzi] telah menceritakan kepada kami [Al Faraj bin Fadlalah Abu Fadlalah Asy Syami] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Muhammad bin 'Amru bin 'Ali] dari ['Ali bin Abu Tholib] berkata bahwa Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Jika ummatku mengerjakan lima belas perkara maka bencana pasti akan menimpa mereka, \" ditanyakan kepada beliau: Apa perkara itu wahai Rasulullah Shallallahu 'alaihi wa Salam? beliau menjawab: \"Apabila harta rampasan dimonopoli kelompok tertentu, amanat dijadikan harta rampasan, zakat dijadikan sebagai denda, laki laki tunduk kepada istrinya, durhaka kepada ibunya, berbuat baik kepada temannya, kasar terhadap bapaknya, meninggikan suara di masjid masjid, pemimpin suatu kaum adalah orang yang paling hina, seseorang dihormati karena dikhawatirkan dari kejahatannya, meminum khomer, memakai sutra, mengambil para wanita penyanyi dan alat alat musik, dan akhir ummat ini melaknat orang orang pendahulu, maka tunggulah saat itu akan datang angin merah atau longsor atau diganti rupanya.\" Abu Isa berkata: Hadits gharib, kami tidak mengetahuinya dari hadits Ali bin Abu Tholib kecuali dari jalur sanad ini, dan kami tidak mengetahui seorangpun yang telah meriwayatkannya dari Yahya bin Sa'id Al Anshari selain dari Al Faraj bin Fadlalah, sebagian ahli hadits telah membicarakannya dalam hadits ini dan melemahkannya dari sisi hafalannya, [Waki'] dan para ulama yang lain telah meriwayatkan hadits darinya."},"2137":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ حَدَّثَنَا مُحَمَّدُ بْنُ يَزِيدَ الْوَاسِطِيُّ عَنْ الْمُسْتَلِمِ بْنِ سَعِيدٍ عَنْ رُمَيْحٍ الْجُذَامِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اتُّخِذَ الْفَيْءُ دُوَلًا وَالْأَمَانَةُ مَغْنَمًا وَالزَّكَاةُ مَغْرَمًا وَتُعُلِّمَ لِغَيْرِ الدِّينِ وَأَطَاعَ الرَّجُلُ امْرَأَتَهُ وَعَقَّ أُمَّهُ وَأَدْنَى صَدِيقَهُ وَأَقْصَى أَبَاهُ وَظَهَرَتْ الْأَصْوَاتُ فِي الْمَسَاجِدِ وَسَادَ الْقَبِيلَةَ فَاسِقُهُمْ وَكَانَ زَعِيمُ الْقَوْمِ أَرْذَلَهُمْ وَأُكْرِمَ الرَّجُلُ مَخَافَةَ شَرِّهِ وَظَهَرَتْ الْقَيْنَاتُ وَالْمَعَازِفُ وَشُرِبَتْ الْخُمُورُ وَلَعَنَ آخِرُ هَذِهِ الْأُمَّةِ أَوَّلَهَا فَلْيَرْتَقِبُوا عِنْدَ ذَلِكَ رِيحًا حَمْرَاءَ وَزَلْزَلَةً وَخَسْفًا وَمَسْخًا وَقَذْفًا وَآيَاتٍ تَتَابَعُ كَنِظَامٍ بَالٍ قُطِعَ سِلْكُهُ فَتَتَابَعَ قَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عَلِيٍّ وَهَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami ['Ali bin Hujr] telah menceritakan kepada kami [Muhammad bin Yazid Al Washiti] telah menceritakan kepada kami [Mustalim bin Sa'id] dari [Rumaih Al Judzami] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Jika harta rampasan perang dimonopoli oleh kelompok tertentu, amanat dijadikan harta rampasan, zakat dijadikan sebagai denda, yang dipelajari selain agama, seorang suami tunduk kepada istrinya, durhaka kepada ibunya, akrab dengan sahabatnya, menjauh dari bapaknya, suara suara mengeras di masjid masjid, pemimpin suatu kabilah adalah orang yang fasik di antara mereka, pemimpin suatu kaum adalah orang yang paling hina di antara mereka, seseorang dihormati karena dikhawatirkan kejahatannya, bermunculannya para wanita penyanyi dan alat alat musik, meminum khamar dan orang yang terakhir dari Ummat ini melaknat orang orang pendahulu, maka tunggulah saat itu akan datangnya angin merah, gempa, longsor, digantinya rupa, lemparan dan tanda tanda kiamat yang susul-menyusul seperti susunan perhiasan yang usang yang terputus talinya kemudian susul-menyusul.\" Abu Isa berkata: dalam hal ini ada hadits serupa dari 'Ali, dan ini adalah hadits gharib kami tidak mengetahuinya kecuali jalur sanad ini."},"2138":{"ar":"حَدَّثَنَا عَبَّادُ بْنُ يَعْقُوبَ الْكُوفِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الْقُدُّوسِ عَنْ الْأَعْمَشِ عَنْ هِلَالِ بْنِ يَسَافٍ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي هَذِهِ الْأُمَّةِ خَسْفٌ وَمَسْخٌ وَقَذْفٌ فَقَالَ رَجُلٌ مِنْ الْمُسْلِمِينَ يَا رَسُولَ اللَّهِ وَمَتَى ذَاكَ قَالَ إِذَا ظَهَرَتْ الْقَيْنَاتُ وَالْمَعَازِفُ وَشُرِبَتْ الْخُمُورُ قَالَ أَبُو عِيسَى وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ الْأَعْمَشِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَابِطٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْسَلٌ وَهَذَا حَدِيثٌ غَرِيبٌ","id":"Telah menceritakan kepada kami ['Abbad bin Ya'qub Al Kufi] telah menceritakan kepada kami [Abdullah bin Abdul Quddus] telah menceritakan kepada kami [Al A'masy] dari [Hilal bin Yasaf] dari ['Imran bin Hushain] Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Akan terjadi pada ummat ini bencana longsor, digantinya rupanya dan angin ribut yang menghempaskan manusia, \" bertanyalah seseorang dari kaum muslimin: Wahai Rasulullah, kapan itu terjadi? beliau menjawab: \"Apabila bermunculan para wanita penyanyi dan alat alat musik dan orang meminum minuman khamar.\" Abu Isa berkata: Hadits ini diriwayatkan dari [Al A'masy] dari [Abdurrahman bin Tsabit] dari Nabi Shallallahu 'alaihi wa Salam secara mursal dan hadits ini gharib."},"2139":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُمَرَ بْنِ هَيَّاجٍ الْأَسَدِيُّ الْكُوفِيُّ حَدَّثَنَا يَحْيَى بْنُ عَبْدِ الرَّحْمَنِ الْأَرْحَبِيُّ حَدَّثَنَا عُبَيْدَةُ بْنُ الْأَسْوَدِ عَنْ مُجَالِدٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنْ الْمُسْتَوْرِدِ بْنِ شَدَّادٍ الْفِهْرِيِّ رَوَىعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بُعِثْتُ فِي نَفَسِ السَّاعَةِ فَسَبَقْتُهَا كَمَا سَبَقَتْ هَذِهِ هَذِهِ لِأُصْبُعَيْهِ السَّبَّابَةِ وَالْوُسْطَىقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ مِنْ حَدِيثِ الْمُسْتَوْرِدِ بْنِ شَدَّادٍ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Umar bin Hayyaj Al Asadi Al Kufi] telah menceritakan kepada kami [Yahya bin Abdurrahman Al Arhabi] telah menceritakan kepada kami ['Ubaidah bin Al Aswad] telah menceritakan kepada kami dari [Mujalid] dari [Qais bin Abu Hazim] dari [Al Mustawrid bin Syaddad Al Fihri] dia telah meriwayatkan dari Nabi Shallallahu 'alaihi wa Salam, beliau bersabda: \"Aku diutus pada saat menjelang hari kiamat maka aku mendahuluinya sebagaimana ini mengejar yang ini, untuk jari telunjuk dan jari tengah (maksudnya sangat dekat).\" Abu Isa berkata: Hadits ini gharib dari hadits Al Mustawrid bin Syaddad, kami tidak mengetahuinya kecuali dari jalur sanad ini."},"2140":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ أَنْبَأَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بُعِثْتُ أَنَا وَالسَّاعَةُ كَهَاتَيْنِ وَأَشَارَ أَبُو دَاوُدَ بِالسَّبَّابَةِ وَالْوُسْطَى فَمَا فَضَّلَ إِحْدَاهُمَا عَلَى الْأُخْرَىقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Dawud] telah memberitakan kepada kami [Syu'bah] dari [Qatadah] dari [Anas] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Aku diutus bersamaan dengan hari kiamat seperti dua ini (maksudnya sangat dekat).\" Abu Dawud mengisyaratkan jari telunjuk dan jari tengah, ia tidak melebihkan salah satunya atas yang lain. berkata Abu Isa: Hadits ini hasan shahih."},"2141":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عَبْدِ الرَّحْمَنِ الْمَخْزُومِيُّ وَعَبْدُ الْجَبَّارِ بْنُ الْعَلَاءِ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيِّبِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَقُومُ السَّاعَةُ حَتَّى تُقَاتِلُوا قَوْمًا نِعَالُهُمْ الشَّعَرُ وَلَا تَقُومُ السَّاعَةُ حَتَّى تُقَاتِلُوا قَوْمًا كَأَنَّ وُجُوهَهُمْ الْمَجَانُّ الْمُطْرَقَةُقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أَبِي بَكْرٍ الصِّدِّيقِ وَبُرَيْدَةَ وَأَبِي سَعِيدٍ وَعَمْرِو بْنِ تَغْلِبَ وَمُعَاوِيَةَ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Sa'id bin Abdurrahman Al Makhzumi] dan ' [Abdul Jabbar bin Al 'Alla'] berkata: telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Sa'id bin Al Musayyib] dari [Abu Hurairah], nabi Shallallahu 'alaihi wa Salam bersabda: \"Kiamat tidak akan terjadi hingga kalian memerangi kaum bersandalkan rambut dan kiamat tidak akan terjadi hingga kalian memerangi kaum sepertinya wajah-wajah mereka perisai yang ditambal.\" Berkata Abu Isa: dalam hal ini ada hadits serupa dari Abu Bakar Ash Shiddiq, Buraidah, Abu Sa'id, 'Amru bin Taghlab dan Mu'awiyah dan hadits ini hasan shahih."},"2142":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عَبْدِ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيِّبِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا هَلَكَ كِسْرَى فَلَا كِسْرَى بَعْدَهُ وَإِذَا هَلَكَ قَيْصَرُ فَلَا قَيْصَرَ بَعْدَهُ وَالَّذِي نَفْسِي بِيَدِهِ لَتُنْفَقَنَّ كُنُوزُهُمَا فِي سَبِيلِ اللَّهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Sa'id bin Abdurrahman] telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Sa'id bin Al Musayyib] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Bila Kisra mati, tidak ada Kisra lain setelahnya, bila Kaisar mati, tidak ada Kaisar lagi setelahnya, demi Dzat yang jiwaku berada ditanganNya, harta simpanan keduanya akan dibelanjakan di jalan Allah.\" Berkata Abu Isa: Hadits ini hasan shahih."},"2143":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا حُسَيْنُ بْنُ مُحَمَّدٍ الْبَغْدَادِيُّ حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي قِلَابَةَ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَتَخْرُجُ نَارٌ مِنْ حَضْرَمَوْتَ أَوْ مِنْ نَحْوِ بَحْرِ حَضْرَمَوْتَ قَبْلَ يَوْمِ الْقِيَامَةِ تَحْشُرُ النَّاسَ قَالُوا يَا رَسُولَ اللَّهِ فَمَا تَأْمُرُنَا قَالَ عَلَيْكُمْ بِالشَّامِقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ حُذَيْفَةَ بْنِ أَسِيدٍ وَأَنَسٍ وَأَبِي هُرَيْرَةَ وَأَبِي ذَرٍّ وَهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ صَحِيحٌ مِنْ حَدِيثِ ابْنِ عُمَرَ","id":"Telah menceritakan kepada kami ['Ahmad bin Mani'] telah menceritakan kepada kami [Husain bin Muhammad Al Bagdhdadi] telah menceritakan kepada kami [Syaiban] dari [Yahya bin Abu Katsir] dari [Abu Qilabah] dari [Salim bin Abdullah bin Umar] dari [ayahnya] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Api akan muncul dari Hadlramaut atau dari arah laut Hadlramaut sebelum hari kiamat mengumpulkan manusia.\" Mereka bertanya: Wahai Rasulullah, apa yang baginda perintahkan kepada kami? Rasulullah Shallallahu 'alaihi wa Salam menjawab: \"Hendaklah kalian berada di Syam.\" Berkata Abu Isa: dalam hal ini ada hadits serupa dari Hudzaifah bin Usaid, Anas, Abu Hurairah dan Abu Dzarr dan hadits ini hasan gharib shahih dari hadits Ibnu Umar."},"2144":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقُومُ السَّاعَةُ حَتَّى يَنْبَعِثَ دَجَّالُونَ كَذَّابُونَ قَرِيبٌ مِنْ ثَلَاثِينَ كُلُّهُمْ يَزْعُمُ أَنَّهُ رَسُولُ اللَّهِقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ جَابِرِ بْنِ سَمُرَةَ وَابْنِ عُمَرَ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abdurrazzaq] telah memberitakan kepada kami [Ma'mar] dari [Hammamn bin Munabbih] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Kiamat tidak terjadi hingga para Dajjal pendusta hampir mencapai tigapuluh muncul, masing-masing semua mengaku sebagai utusan Allah.\" Berkata Abu Isa: dalam hal ini ada hadits serupa dari Jabir bin Samurah, Ibnu Umar dan hadits ini hasan shahih."},"2145":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي أَسْمَاءَ الرَّحَبِيِّ عَنْ ثَوْبَانَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقُومُ السَّاعَةُ حَتَّى تَلْحَقَ قَبَائِلُ مِنْ أُمَّتِي بِالْمُشْرِكِينَ وَحَتَّى يَعْبُدُوا الْأَوْثَانَ وَإِنَّهُ سَيَكُونُ فِي أُمَّتِي ثَلَاثُونَ كَذَّابُونَ كُلُّهُمْ يَزْعُمُ أَنَّهُ نَبِيٌّ وَأَنَا خَاتَمُ النَّبِيِّينَ لَا نَبِيَّ بَعْدِيقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Abu Qilabah] dari [Abu Asma` Ar Rahbi] dari [Tsauban] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Kiamat tidak terjadi hingga kabilah-kabilah dari ummatku bertemu kaum musyrikin dan hingga patung-patung disembah dan ditengah-tengah ummatku akan ada tigapuluh pendusta, semuanya mengaku nabi padahal aku adalah penutup para nabi, tidak ada nabi setelahku.\" Berkata Abu Isa: Hadits ini hasan shahih."},"2146":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى عَنْ شَرِيكِ بْنِ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عُصْمٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ثَقِيفٍ كَذَّابٌ وَمُبِيرٌقَالَ أَبُو عِيسَى يُقَالُ الْكَذَّابُ الْمُخْتَارُ بْنُ أَبِي عُبَيْدٍ وَالْمُبِيرُ الْحَجَّاجُ بْنُ يُوسُفَ حَدَّثَنَا أَبُو دَاوُدَ سُلَيْمَانُ بْنُ سَلْمٍ الْبَلْخِيُّ أَخْبَرَنَا النَّضْرُ بْنُ شُمَيْلٍ عَنْ هِشَامِ بْنِ حَسَّانَ قَالَ أَحْصَوْا مَا قَتَلَ الْحَجَّاجُ صَبْرًا فَبَلَغَ مِائَةَ أَلْفٍ وَعِشْرِينَ أَلْفَ قَتِيلٍ قَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ وَاقِدٍ حَدَّثَنَا شَرِيكٌ نَحْوَهُ بِهَذَا الْإِسْنَادِ وَهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ حَدِيثِ ابْنِ عُمَرَ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ شَرِيكٍ وَشَرِيكٌ يَقُولُ عَبْدُ اللَّهِ بْنُ عُصْمٍ وَإِسْرَائِيلُ يَقُولُ عَبْدُ اللَّهِ بْنُ عِصْمَةَ","id":"Telah menceritakan kepada kami ['Ali bin Hujr] telah menceritakan kepada kami [Al Fafdll bin Musa'] telah menceritakan kepada kami [Syarik bin Abdullah] dari [Abdullah bin 'Ushmi] dari [Ibnu Umar] dia berkata bahwa Rasulullah Shallallahu 'alaihi wa Salam bersabda: \" Di kabilah Tsaqif ini ada seorang pendusta dan seorang yang sadis.\" Abu Isa berkata: Dikatakan: Pendusta adalah Al Mukhtar bin Abu 'Ubaid sedangkan orang sadis adalah Al Hajjaj bin Yusuf. Telah menceritakan kepada kami Abu Daud Sulaiman bin Salm Al Balkhi telah menceritakan kepada kami An Nadlar bin Syumail telah mengkhabarkan kepada kami Hisyam bin Hassan dia berkata: Mereka menghitung jumlah orang orang yang dibunuh Al Hajjaj dengan sabar mencapai seratus dua puluh ribu korban. Abu Isa berkata: dalam hal ini ada hadits serupa dari Asma` binti Abu Bakar, telah menceritakan kepada kami [Abdurrahman bin Waqid] telah menceritakan kepada kami [Syarik] hadits yang semakna dengan sanad ini dan hadits ini hasan gharib dari hadits Ibnu Umar, kami tidak mengetahuinya kecuali dari hadits Syarik, sedangkan Syarik mengatakan: Abdullah bin 'Ushmi sementara Isra'il mengatakan Abdullah bin 'Ishmah."},"2147":{"ar":"حَدَّثَنَا وَاصِلُ بْنُ عَبْدِ الْأَعْلَى حَدَّثَنَا مُحَمَّدُ بْنُ الْفُضَيْلِ عَنْ الْأَعْمَشِ عَنْ عَلِيِّ بْنِ مُدْرِكٍ عَنْ هِلَالِ بْنِ يَسَافٍ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ خَيْرُ النَّاسِ قَرْنِي ثُمَّ الَّذِينَ يَلُونَهُمْ ثُمَّ الَّذِينَ يَلُونَهُمْ ثُمَّ يَأْتِي مِنْ بَعْدِهِمْ قَوْمٌ يَتَسَمَّنُونَ وَيُحِبُّونَ السِّمَنَ يُعْطُونَ الشَّهَادَةَ قَبْلَ أَنْ يُسْأَلُوهَاقَالَ أَبُو عِيسَى هَكَذَا رَوَى مُحَمَّدُ بْنُ فُضَيْلٍ هَذَا الْحَدِيثَ عَنْ الْأَعْمَشِ عَنْ عَلِيِّ بْنِ مُدْرِكٍ عَنْ هِلَالِ بْنِ يَسَافٍ وَرَوَى غَيْرُ وَاحِدٍ مِنْ الْحُفَّاظِ هَذَا الْحَدِيثَ عَنْ الْأَعْمَشِ عَنْ هِلَالِ بْنِ يَسَافٍ وَلَمْ يَذْكُرُوا فِيهِ عَلِيَّ بْنَ مُدْرِكٍ قَالَ و حَدَّثَنَا الْحُسَيْنُ بْنُ حُرَيْثٍ حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ حَدَّثَنَا هِلَالُ بْنُ يَسَافٍ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ نَحْوَهُ وَهَذَا أَصَحُّ عِنْدِي مِنْ حَدِيثِ مُحَمَّدِ بْنِ فُضَيْلٍ وَقَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ عِمْرَانَ بْنِ حُصَيْنِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Washil bin 'Abdul A'la] telah menceritakan kepada kami [Muhammad bin Al Fudlail] dari [Al A'masy] dari ['Ali bin Mudrik] dari [Hilal bin Yasaf] dari ['Imran bin Hushain] berkata: Aku mendengar Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Manusia terbaik adalah generasiku kemudian setelahnya kemudian setelahnya, setelah itu datanglah kaum yang kegemarannya mempergemuk dan suka kegemukan, mereka memberikan kesaksian sebelum mereka diminta.\" Berkata Abu Isa: seperti itulah Muhammad bin Fudlail telah meriwayatkan hadits ini dari Al A'masy dari 'Ali bin Mudrik dari Hilal bin Yasaf dan yang lain bukan hanya seorang meriwayatkan hadits ini dari pada hafidz dari Al A'masy dari Hilal bin Yasaf, mereka tidak menyebut 'Ali bin Mudrik didalamnya, berkata Abu Isa: telah menceritakan kepada kami [Al Husain bin Huraits] telah menceritakan kepada kami [Waki'] dari [Al A'masy] telah menceritakan kepada kami [Hilal bin Yasaf] dari ['Imran bin Hushain] dari Nabi Shallallahu 'alaihi wa Salam, lalu ia menyebutkan sepertinya dan ini bagi saya lebih shahih dari hadits Muhammad bin Fudlail dan diriwayatkan bukan hanya dari seorang perawi dari 'Imran bin Hushain dari nabi Shallallahu 'alaihi wa Salam."},"2148":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرُ أُمَّتِي الْقَرْنُ الَّذِي بُعِثْتُ فِيهِمْ ثُمَّ الَّذِينَ يَلُونَهُمْ قَالَ وَلَا أَعْلَمُ ذَكَرَ الثَّالِثَ أَمْ لَا ثُمَّ يَنْشَأُ أَقْوَامٌ يَشْهَدُونَ وَلَا يُسْتَشْهَدُونَ وَيَخُونُونَ وَلَا يُؤْتَمَنُونَ وَيَفْشُو فِيهِمْ السِّمَنُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abu 'Awanah] dari [Qatadah] dari [Zurarah bin Aufa] dari ['Imran bin Hushain] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Ummatku yang terbaik adalah masa ketika aku diutus ditengah-tengah mereka kemudian setelah mereka -berkata 'Imran: Saya tidak tahu apakah beliau menyebut yang ketiga atau tidak- setelah itu muncul kaum-kaum yang bersaksi dan mereka tidak dijadikan saksi, mereka berkhianat dan tidak dipercaya, tersebar kegemukan ditengah-tengah mereka.\" berkata Abu Isa: hadits ini hasan shahih."},"2149":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا عُمَرُ بْنُ عُبَيْدٍ الطَّنَافِسِيُّ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَكُونُ مِنْ بَعْدِي اثْنَا عَشَرَ أَمِيرًا قَالَ ثُمَّ تَكَلَّمَ بِشَيْءٍ لَمْ أَفْهَمْهُ فَسَأَلْتُ الَّذِي يَلِينِي فَقَالَ كُلُّهُمْ مِنْ قُرَيْشٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا عُمَرُ بْنُ عُبَيْدٍ عَنْ أَبِيهِ عَنْ أَبِي بَكْرِ بْنِ أَبِي مُوسَى عَنْ جَابِرِ بْنِ سَمُرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَ هَذَا الْحَدِيثِ وَقَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ يُسْتَغْرَبُ مِنْ حَدِيثِ أَبِي بَكْرِ بْنِ أَبِي مُوسَى عَنْ جَابِرِ بْنِ سَمُرَةَ وَفِي الْبَاب عَنْ ابْنِ مَسْعُودٍ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو","id":"Telah menceritakan kepada kami [Abu Kuraib Muhammad bin Al 'Alla`] telah menceritakan kepada kami [Umar bin 'Ubaid Ath Thanafisi] dari [Simak bin Harb] dari [Jabir bin Samurah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Akan ada sepeninggalku dua belas pemimpin -berkata Jabir: Lalu beliau mengucapkan sesuatu yang tidak aku fahami lalu aku bertanya kepada yang ada dibelakangku lalu beliau bersabda: \"Kalian semua dari Quraisy.\" Berkata Abu Isa: hadits ini hasan shahih. telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Umar bin 'Ubaid] dari [ayahnya] dari [Abu Bakr bin Abu Musa] dari [Jabir bin Samurah] dari nabi Shallallahu 'alaihi wa Salam seperti hadits ini dan diriwayatkan bukan hanya dari satu sanad saja dari Jabir bin Samurah. Berkata Abu Isa: Hadits ini hasan shahih gharib yang dianggap gharib dari hadits Abu Bakru bin Abu Musa dari Jabir bin Samurah dan dalam hal ini ada hadits serupa dari Ibnu Mas'ud dan Abdullah bin 'Amru."},"2150":{"ar":"حَدَّثَنَا بُنْدَارٌ حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا حُمَيْدُ بْنُ مِهْرَانَ عَنْ سَعْدِ بْنِ أَوْسٍ عَنْ زِيَادِ بْنِ كُسَيْبٍ الْعَدَوِيِّ قَالَكُنْتُ مَعَ أَبِي بَكْرَةَ تَحْتَ مِنْبَرِ ابْنِ عَامِرٍ وَهُوَ يَخْطُبُ وَعَلَيْهِ ثِيَابٌ رِقَاقٌ فَقَالَ أَبُو بِلَالٍ انْظُرُوا إِلَى أَمِيرِنَا يَلْبَسُ ثِيَابَ الْفُسَّاقِ فَقَالَ أَبُو بَكْرَةَ اسْكُتْ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ أَهَانَ سُلْطَانَ اللَّهِ فِي الْأَرْضِ أَهَانَهُ اللَّهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Bundar] telah menceritakan kepada kami [Abu Dawud] telah menceritakan kepada kami [Humaid bin Mihran] dari [Sa'ad bin Aus] dari [Ziyad bin Kusaib Al 'Adawi] berkata: Aku pernah bersama [Abu Bakrah] di bawah mimbar Ibnu 'Amir saat ia berkhotbah, ia mengenakan baju tipis lalu Bilal berkata: Lihatlah pemimpin kita mengenakan baju orang-orang fasik. Abu Bakrah berkata: Diam, aku pernah mendengar Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Barangsiapa menghina pemimpin Allah di bumi, Allah akan menghinakannya.\" Berkata Abu Isa: Hadits ini hasan gharib."},"2151":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُوسَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ أَبِيهِ قَالَ قِيلَ لِعُمَرَ بْنِ الْخَطَّابِلَوْ اسْتَخْلَفْتَ قَالَ إِنْ أَسْتَخْلِفْ فَقَدْ اسْتَخْلَفَ أَبُو بَكْرٍ وَإِنْ لَمْ أَسْتَخْلِفْ لَمْ يَسْتَخْلِفْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ أَبُو عِيسَى وَفِي الْحَدِيثِ قِصَّةٌ وَهَذَا حَدِيثٌ صَحِيحٌ قَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ ابْنِ عُمَرَ","id":"Telah menceritakan kepada kami [Yahya bin Musa] telah menceritakan kepada kami [Abdurrazzaq] telah mengkabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Salm bin Abdullah bin Umar] dari [ayahnya] berkata: Dikatakan kepada [Umar bin Al Khaththab]: Andai saja kau memegang kekhilafahan. Ia berkata: andai saja aku mengangkat seorang khalifah, Abu Bakar telah dijadikan sebagai khalifah dan bila aku tidak mengangkat seorang khalifah, Rasulullah Shallallahu 'alaihi wa Salam tidak mengangkat khalifah. Berkata Abu Isa: Ada kisah berkenaan dengan hadits ini dan hadits ini shahih dan diriwayatkan bukan hanya dari satu sanad dari Ibnu Umar."},"2152":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا سُرَيْجُ بْنُ النُّعْمَانِ حَدَّثَنَا حَشْرَجُ بْنُ نُبَاتَةَ عَنْ سَعِيدِ بْنِ جُمْهَانَ قَالَ حَدَّثَنِي سَفِينَةُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْخِلَافَةُ فِي أُمَّتِي ثَلَاثُونَ سَنَةً ثُمَّ مُلْكٌ بَعْدَ ذَلِكَ ثُمَّ قَالَ لِي سَفِينَةُ أَمْسِكْ خِلَافَةَ أَبِي بَكْرٍ ثُمَّ قَالَ وَخِلَافَةَ عُمَرَ وَخِلَافَةَ عُثْمَانَ ثُمَّ قَالَ لِي أَمْسِكْ خِلَافَةَ عَلِيٍّ قَالَ فَوَجَدْنَاهَا ثَلَاثِينَ سَنَةً قَالَ سَعِيدٌ فَقُلْتُ لَهُ إِنَّ بَنِي أُمَيَّةَ يَزْعُمُونَ أَنَّ الْخِلَافَةَ فِيهِمْ قَالَ كَذَبُوا بَنُو الزَّرْقَاءِ بَلْ هُمْ مُلُوكٌ مِنْ شَرِّ الْمُلُوكِقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عُمَرَ وَعَلِيٍّ قَالَا لَمْ يَعْهَدْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْخِلَافَةِ شَيْئًا وَهَذَا حَدِيثٌ حَسَنٌ قَدْ رَوَاهُ غَيْرُ وَاحِدٍ عَنْ سَعِيدِ بْنِ جُمْهَانَ وَلَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ سَعِيدِ بْنِ جُمْهَانَ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Suraij bin An Nu 'man] telah menceritakan kepada kami [Hasyraj bin Nubatah] dari [Sa'id bin Jumhan] berkata: telah menceritakan kepadaku [Safinah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Khilafah di ummatku selama tigapuluh tahun kemudian setelah itu kerajaan.\" Setelah itu Safinah berkata kepadaku: Peganglah, khilafah Abu Bakar, khilafah Umar, khilafah 'Utsman, kemudian Safinah berkata padaku: Peganglah khilafah 'Ali. Berkata Sa'id: Ternyata kami menemukan (lamanya waktu khilafah) selama tigapuluh tahun. Berkata Sa'id: Lalu aku berkata padanya: Bani 'Umaiyah mengklaim, khilafah berlaku ditengah-tengah mereka. ia berkata: Bani Zarqa` berdusta, tapi mereka adalah kerajaan, termasuk kerajaan-kerajaan terburuk. Berkata Abu Isa: dalam hal ini ada hadits serupa dari Umar dan 'Ali keduanya berkata: nabi Shallallahu 'alaihi wa Salam tidak mewasiatkan apa pun dalam kekhilafahan. Hadits ini hasan dan diriwayatkan bukan hahya oleh seorang perawi dari Sa'id bin Jumhan dan kami hanya mengetahuinya dari Sa'id bin Jumhan."},"2153":{"ar":"حَدَّثَنَا حُسَيْنُ بْنُ مُحَمَّدٍ الْبَصْرِيُّ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا شُعْبَةُ عَنْ حَبِيبِ بْنِ الزُّبَيْرِ قَال سَمِعْتُ عَبْدَ اللَّهِ بْنَ أَبِي الْهُذَيْلِ يَقُولُكَانَ نَاسٌ مِنْ رَبِيعَةَ عِنْدَ عَمْرِو بْنِ الْعَاصِ فَقَالَ رَجُلٌ مِنْ بَكْرِ بْنِ وَائِلٍ لَتَنْتَهِيَنَّ قُرَيْشٌ أَوْ لَيَجْعَلَنَّ اللَّهُ هَذَا الْأَمْرَ فِي جُمْهُورٍ مِنْ الْعَرَبِ غَيْرِهِمْ فَقَالَ عَمْرُو بْنُ الْعَاصِ كَذَبْتَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ قُرَيْشٌ وُلَاةُ النَّاسِ فِي الْخَيْرِ وَالشَّرِّ إِلَى يَوْمِ الْقِيَامَةِقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ ابْنِ مَسْعُودٍ وَابْنِ عُمَرَ وَجَابِرٍ وَهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Husain bin Muhammad Al Bashri] telah menceritakan kepada kami [Khalid bin Al Harits] telah menceritakan kepada kami [Syu'bah] dari [Habib bin Az Zubair] berkata: Aku mendengar [Abdullah bin Abu Al Hudzail] berkata: Beberapa orang dari kabilah Rabi'ah berada dikediaman Amru bin Al 'Ash lalu seseorang dari kabilah Bakru bin Wa`il berkata: Hendaklah Quraisy berhenti atau Allah akan menjadikan urusan ini pada mayoritas bangsa arab selain mereka. berkata [Amru bin Al 'Ash]: engkau berdusta, aku pernah mendengar Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Quraisy adalah para pemimpin manusia dalam kebaikan dan keburukan hingga hari kiamat.\" Berkata Abu Isa: dalam hal ini ada hadits serupa dari Ibnu Mas'ud, Ibnu Umar dan Jabir dan hadits ini hasan gharib shahih."},"2154":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ الْعَبْدِيُّ حَدَّثَنَا أَبُو بَكْرٍ الْحَنَفِيُّ عَنْ عَبْدِ الْحَمِيدِ بْنِ جَعْفَرٍ عَنْ عُمَرَ بْنِ الْحَكَمِ قَال سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَذْهَبُ اللَّيْلُ وَالنَّهَارُ حَتَّى يَمْلِكَ رَجُلٌ مِنْ الْمَوَالِي يُقَالُ لَهُ جَهْجَاهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar Al 'Abdi] telah menceritakan kepada kami [Abu Bakar Al Hanafi] telah menceritakan kepada kami ['Abdul Hamid bin Ja'far] dari [Umar bin Al Hakam] dia berkata: Aku telah mendengar [Abu Hurairah] berkata bahwa Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Malam dan siang tidak akan lenyap sampai seorang lelaki budak berkuasa, namanya Jahjah.\" Abu Isa berkata: Hadits ini hasan gharib."},"2155":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي أَسْمَاءَ الرَّحَبِيِّ عَنْ ثَوْبَانَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا أَخَافُ عَلَى أُمَّتِي الْأَئِمَّةَ الْمُضِلِّينَ قَالَ وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَزَالُ طَائِفَةٌ مِنْ أُمَّتِي عَلَى الْحَقِّ ظَاهِرِينَ لَا يَضُرُّهُمْ مَنْ يَخْذُلُهُمْ حَتَّى يَأْتِيَ أَمْرُ اللَّهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ سَمِعْت مُحَمَّدَ بْنَ إِسْمَعِيلَ يَقُولُ سَمِعْتُ عَلِيَّ بْنَ الْمَدِينِيِّ يَقُولُ وَذَكَرَ هَذَا الْحَدِيثَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَزَالُ طَائِفَةٌ مِنْ أُمَّتِي ظَاهِرِينَ عَلَى الْحَقِّ فَقَالَ عَلِيٌّ هُمْ أَهْلُ الْحَدِيثِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Abu Qilabah] dari [Abu Asma` Ar Rahbi] dari [Tsauban] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \" yang aku takutkan atas umatku adalah pemimpin-pemimpiny menyesatkan.\" Berkata Tsauban: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Sekelompok dari umatku akan senantiasa berada diatas kebenaran dan menang, tidaklah membahayakan mereka orang yang menghinakan mereka hingga urusan Allah tiba.\" Berkata Abu Isa: hadits ini hasan shahih. aku mendengar Muhammad bin Isma'il berkata: Aku mendengar 'Ali bin Al Madini berkata dan ia menyebutkan hadits dari nabi Shallallahu 'alaihi wa Salam: \"Sekelompok dari ummatku akan senantiasa menang diatas kebenaran.\" Berkata 'Ali: Mereka adalah ahli hadits."},"2156":{"ar":"حَدَّثَنَا عُبَيْدُ بْنُ أَسْبَاطِ بْنِ مُحَمَّدٍ الْقُرَشِيُّ الْكُوفِيُّ قَالَ حَدَّثَنِي أَبِي حَدَّثَنَا سُفْيَانُ الثَّوْرِيُّ عَنْ عَاصِمِ بْنِ بَهْدَلَةَ عَنْ زِرٍّ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَذْهَبُ الدُّنْيَا حَتَّى يَمْلِكَ الْعَرَبَ رَجُلٌ مِنْ أَهْلِ بَيْتِي يُوَاطِئُ اسْمُهُ اسْمِيقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عَلِيٍّ وَأَبِي سَعِيدٍ وَأُمِّ سَلَمَةَ وَأَبِي هُرَيْرَةَ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami ['Ubaid bin Asbath bin Muhammad Al Qurosyi Al Kufi] berkata: telah menceritakan kepada kami [bapakku] telah menceritakan kepadaku [Sufyan Ats Tsauri] telah menceritakan kepada kami dari ['Ashim bin Bahdalah] dari [Zirr] dari [Abdullah] berkata bahwa Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Dunia tidak akan hilang sampai seorang lelaki dari ahli baitku menguasai orang orang arab, namanya sama dengan namaku.\" Abu Isa berkata: Dan dalam bab ini ada hadits dari 'Ali, Abu Sa'id, Ummu Salamah dan Abu Hurairah, dan hadits ini hasan shahih."},"2157":{"ar":"حَدَّثَنَا عَبْدُ الْجَبَّارِ بْنُ الْعَلَاءِ بْنِ عَبْدِ الْجَبَّارِ الْعَطَّارُ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَاصِمٍ عَنْ زِرٍّ عَنْ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَلِي رَجُلٌ مِنْ أَهْلِ بَيْتِي يُوَاطِئُ اسْمُهُ اسْمِيقَالَ عَاصِمٌ وَأَخْبَرَنَا أَبُو صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَ لَوْ لَمْ يَبْقَ مِنْ الدُّنْيَا إِلَّا يَوْمٌ لَطَوَّلَ اللَّهُ ذَلِكَ الْيَوْمَ حَتَّى يَلِيَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Abdul Jabbar bin Al Ala' bin Abdul Jabbar Al Athar] telah menceritakan kepada kami [Sufyan bin 'Uyainah] telah menceritakan kepada kami ['Ashim] dari [Zirr] dari [Abdullah] dari nabi Shallallahu 'alaihi wa Salam, beliau bersabda: \"Akan berkuasa seseorang dari ahli baitku yang namanya sama dengan namaku. 'Ashim berkata: Abu Sholih telah mengabarkan kepada kami dari Abu Hurairah berkata: \"Seandainya tidak akan tersisa dari dunia ini kecuali sehari niscaya Allah akan memanjangkan hari itu sehingga dia berkuasa.\" Abu Isa berkata: Hadits ini hasan shahih."},"2158":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ قَال سَمِعْتُ زَيْدًا الْعَمِّيَّ قَال سَمِعْتُ أَبَا الصِّدِّيقِ النَّاجِيَّ يُحَدِّثُ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَخَشِينَا أَنْ يَكُونَ بَعْدَ نَبِيِّنَا حَدَثٌ فَسَأَلْنَا نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ فِي أُمَّتِي الْمَهْدِيَّ يَخْرُجُ يَعِيشُ خَمْسًا أَوْ سَبْعًا أَوْ تِسْعًا زَيْدٌ الشَّاكُّ قَالَ قُلْنَا وَمَا ذَاكَ قَالَ سِنِينَ قَالَ فَيَجِيءُ إِلَيْهِ رَجُلٌ فَيَقُولُ يَا مَهْدِيُّ أَعْطِنِي أَعْطِنِي قَالَ فَيَحْثِي لَهُ فِي ثَوْبِهِ مَا اسْتَطَاعَ أَنْ يَحْمِلَهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ وَقَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ أَبِي سَعِيدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو الصِّدِّيقِ النَّاجِيُّ اسْمُهُ بَكْرُ بْنُ عَمْرٍو وَيُقَالُ بَكْرُ بْنُ قَيْسٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dia berkata: Aku mendengar [Zaid Al 'Ammi] berkata: Aku mendengar [Abu Ash Shiddiq An Naji] menceritakan dari [Abu sa'id Al Khudri] dia berkata: Kami takut akan terjadi hal hal yang diada-adakan sepeninggal nabi kami, lalu kami bertanya kepada Nabi Allah, lalu beliau bersabda: \"Dalam ummatku ini akan ada Al Mahdi yang muncul, ia hidup selama lima, tujuh atau sembilan -Zaid ragu- Abu Sa'id berkata: kami bertanya: yang benar lamanya berapa? beliau menjawab \"Beberapa tahun, \" beliau bersabda: \"Seseorang datang kepadanya lalu berkata: Wahai Mahdi berilah aku, berilah aku.\" beliau bersabda: \" Lalu Imam Mahdi memberinya dengan kedua telapak tangannya dibajunya sampai dia tidak mampu untuk membawanya.\" Abu Isa berkata: Hadits ini hasan, dan telah diriwayatkan dari berbagai jalur sanad dari Abu Sa'id dari Nabi Shallallahu 'alaihi wa Salam adapun Abu Ash shiddiq An Naji namanya Bakar bin 'Amru dan dinamakan juga Bakar bin Qais."},"2159":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ لَيُوشِكَنَّ أَنْ يَنْزِلَ فِيكُمْ ابْنُ مَرْيَمَ حَكَمًا مُقْسِطًا فَيَكْسِرُ الصَّلِيبَ وَيَقْتُلُ الْخِنْزِيرَ وَيَضَعُ الْجِزْيَةَ وَيَفِيضُ الْمَالُ حَتَّى لَا يَقْبَلَهُ أَحَدٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits bin Sa'ad] dari [Ibnu Syihab] dari [Sa'id bin Al Musayyib] dari [Abu Hurairah] Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Demi Dzat yang jiwaku berada ditanganNya, hampir saja putra Maryam turun pada kalian sebagai hakim adil lalu ia menghancurkan salib, membunuh babi, membatalkan jizyah dan harta melimpah hingga tidak ada seorang pun mendatanginya.\" Berkata Abu Isa: Hadits ini hasan shahih."},"2160":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُعَاوِيَةَ الْجُمَحِيُّ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ عَنْ عَبْدِ اللَّهِ بْنِ سُرَاقَةَ عَنْ أَبِي عُبَيْدَةَ بْنِ الْجَرَّاحِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّهُ لَمْ يَكُنْ نَبِيٌّ بَعْدَ نُوحٍ إِلَّا قَدْ أَنْذَرَ الدَّجَّالَ قَوْمَهُ وَإِنِّي أُنْذِرُكُمُوهُ فَوَصَفَهُ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَعَلَّهُ سَيُدْرِكُهُ بَعْضُ مَنْ رَآنِي أَوْ سَمِعَ كَلَامِي قَالُوا يَا رَسُولَ اللَّهِ فَكَيْفَ قُلُوبُنَا يَوْمَئِذٍ قَالَ مِثْلُهَا يَعْنِي الْيَوْمَ أَوْ خَيْرٌقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ بُسْرٍ وَعَبْدِ اللَّهِ بْنِ الْحَارِثِ بْنِ جُزَيٍّ وَعَبْدِ اللَّهِ بْنِ مُغَفَّلٍ وَأَبِي هُرَيْرَةَ وَهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ حَدِيثِ أَبِي عُبَيْدَةَ بْنِ الْجَرَّاحِ","id":"Telah menceritakan kepada kami [Abdullah bin Mu'awiyah Al Jumahi] telah menceritakan kepada kami [Hammad bin Salamah] dari [Khalid Al Hadzdza`] dari [Abdullah bin Syaqiq] dari [Abdullah bin Suraqah] dari [Abu 'Ubaidah bin Al Jarrah] berkata: Aku mendengar Rasulullah Shallallahu 'alaihi wa Salam bersabda: \" tidak ada nabi pun setelah Nuh melainkan pasti mengingatkan Dajjal pada kaumnya dan aku mengingatkan kalian padanya.\" Rasulullah Shallallahu 'alaihi wa Salam menyebutkan ciri-cirinya untuk kami, beliau bersabda: \"Sepertinya ia akan dijumpai oleh sebagian orang yang melihatku atau mendengarku sabdaku.\" Mereka bertanya: Wahai Rasulullah, lalu bagaimana dengan hati kami saat itu.\" Beliau menjawab: \"Sepertinya -maksud beliau seperti saat ini- atau lebih baik.\" Berkata Abu Isa: dalam hal ini ada hadits serupa dari Abdullah bin Busr, Abdullah bin Al Harits bin Juzai, Abdullah bin Mughaffal dan Abu Hurairah, dan hadits ini hasan gharib dari hadits Abu 'Ubaidah bin Jarrah."},"2161":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ قَالَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي النَّاسِ فَأَثْنَى عَلَى اللَّهِ بِمَا هُوَ أَهْلُهُ ثُمَّ ذَكَرَ الدَّجَّالَ فَقَالَ إِنِّي لَأُنْذِرُكُمُوهُ وَمَا مِنْ نَبِيٍّ إِلَّا وَقَدْ أَنْذَرَ قَوْمَهُ وَلَقَدْ أَنْذَرَ نُوحٌ قَوْمَهُ وَلَكِنِّي سَأَقُولُ لَكُمْ فِيهِ قَوْلًا لَمْ يَقُلْهُ نَبِيٌّ لِقَوْمِهِ تَعْلَمُونَ أَنَّهُ أَعْوَرُ وَإِنَّ اللَّهَ لَيْسَ بِأَعْوَرَقَالَ الزُّهْرِيُّ وَأَخْبَرَنِي عُمَرُ بْنُ ثَابِتٍ الْأَنْصَارِيُّ أَنَّهُ أَخْبَرَهُ بَعْضُ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَوْمَئِذٍ لِلنَّاسِ وَهُوَ يُحَذِّرُهُمْ فِتْنَتَهُ تَعْلَمُونَ أَنَّهُ لَنْ يَرَى أَحَدٌ مِنْكُمْ رَبَّهُ حَتَّى يَمُوتَ وَإِنَّهُ مَكْتُوبٌ بَيْنَ عَيْنَيْهِ ك ف ر يَقْرَؤُهُ مَنْ كَرِهَ عَمَلَهُ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Abd bin Humaid] telah mengkabarkan kepada kami [Abdurrazzaq] telah mengkabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Salim] dari [Ibnu Umar] berkata: Rasulullah Shallallahu 'alaihi wa Salam berdiri ditengah-tengah orang, beliau memuji Allah selayaknya, setelah itu beliau menyebut Dajjal, beliau bersabda: \" aku mengingatkan kalian padanya, tidak ada seorang nabi pun melainkan pasti mengingatkan kaumnya dan Nuh telah mengingatkan kaumnya, tapi aku akan menuturkan suatu sabda pada kalian yang belum pernah diucapkan oleh seorang nabi pun kepada kaumnya, kalian mengetahui bahwa ia (Dajjal) buta sebelah mata dan tidak buta sebelah mata.\" Berkata [Az Zuhri]: Telah mengkhabarkan kepadaku [Umar bin Tsabit Al Anshari] bahwa ia diberitahu oleh [seorang sahabat nabi Shallallahu 'alaihi wa Salam], nabi Shallallahu 'alaihi wa Salam bersabda saat itu, beliau mengingatkan mereka pada fitnahnya: \"Kalian tahu bahwa tidak ada seorang pun diantara kalian melihat Rabbnya hingga meninggal dan diantara kedua matanya (Dajjal) tertulis K A F I R yang bisa dibaca oleh orang yang membenci perbuatannya.\" Berkata Abu Isa: Hadits ini hasan shahih."},"2162":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تُقَاتِلُكُمْ الْيَهُودُ فَتُسَلَّطُونَ عَلَيْهِمْ حَتَّى يَقُولَ الْحَجَرُ يَا مُسْلِمُ هَذَا يَهُودِيٌّ وَرَائِي فَاقْتُلْهُقَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Abd bin Humaid] telah menceritakan kepada kami [Abdurrazzaq] telah mengkabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Salim] dari [Ibnu Umar] Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Yahudi akan memerangi kalian yang selanjutnya kalian akan menguasai mereka hingga batu berkata: Hai muslim, ini orang Yahudi di belakangku, bunuhlah dia.\" Berkata Abu Isa: hadits ini hasan shahih."},"2163":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَأَحْمَدُ بْنُ مَنِيعٍ قَالَا حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ أَبِي التَّيَّاحِ عَنْ الْمُغِيرَةِ بْنِ سُبَيْعٍ عَنْ عَمْرِو بْنِ حُرَيْثٍ عَنْ أَبِي بَكْرٍ الصِّدِّيقِ قَالَحَدَّثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الدَّجَّالُ يَخْرُجُ مِنْ أَرْضٍ بِالْمَشْرِقِ يُقَالُ لَهَا خُرَاسَانُ يَتْبَعُهُ أَقْوَامٌ كَأَنَّ وُجُوهَهُمْ الْمَجَانُّ الْمُطْرَقَةُقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَعَائِشَةَ وَهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَقَدْ رَوَاهُ عَبْدُ اللَّهِ بْنُ شَوْذَبٍ وَغَيْرُ وَاحِدٍ عَنْ أَبِي التَّيَّاحِ وَلَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ أَبِي التَّيَّاحِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] dan [Ahmad bin Mani'] keduanya berkata: telah menceritakan kepada kami [Rauh bin 'Ubadah] telah menceritakan kepada kami [Sa'id bin Abu 'Urubah] dari [Abu At Tayyah] dari [Al Mughirah bin Subai'] dari ['Amru bin Huraits] dari [Abu Bakar Ash Shiddiq] berkata: Telah menceritakan kepada kami Rasulullah Shallallahu 'alaihi wa Salam, beliau bersabda: \"Dajjal akan muncul dari suatu negeri di timur bernama Khurasan, ia diikuti oleh kaum-kaum, sepertinya wajah mereka perisai yang ditambal.\" Berkata Abu Isa: dalam hal ini ada hadits serupa dari Abu Hurairah dan 'Aisyah dan hadits ini hasan gharib, hadits ini diriwayatkan oleh [Abdullah bin Syaudzab] dan beberapa perawi dari Abu At Tayyah, kami hanya mengetahuinya dari hadits Abu At Tayyah."},"2164":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ أَخْبَرَنَا الْحَكَمُ بْنُ الْمُبَارَكِ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ أَبِي بَكْرِ بْنِ أَبِي مَرْيَمَ عَنْ الْوَلِيدِ بْنِ سُفْيَانَ عَنْ يَزِيدَ بْنِ قُطَيْبٍ السَّكُونِيِّ عَنْ أَبِي بَحْرِيَّةَ صَاحِبِ مُعَاذٍ عَنْ مُعَاذِ بْنِ جَبَلٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمَلْحَمَةُ الْعُظْمَى وَفَتْحُ الْقُسْطَنْطِينِيَّةِ وَخُرُوجُ الدَّجَّالِ فِي سَبْعَةِ أَشْهُرٍقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ الصَّعْبِ بْنِ جَثَّامَةَ وَعَبْدِ اللَّهِ بْنِ بُسْرٍ وَعَبْدِ اللَّهِ بْنِ مَسْعُودٍ وَأَبِي سَعِيدٍ الْخُدْرِيِّ وَهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Abdullah bin Abdurrahman] telah mengkabarkan kepada kami [Al Hakam bin Al Mubarak] telah menceritakan kepada kami [Al Walid bin Muslim] dari [Abu Bakar bin Abu Maryam] dari [Al Walid bin Sufyan] dari [Yazid bin Quthaib As Sukaini] dari [Abu Bahriyah, teman Mu'adz bin Jabal] dari [Mu'adz bin Jabal] dari nabi Shallallahu 'alaihi wa Salam bersabda: \"Peperangan besar, penaklukan Kostantinopel, dan munculnya Dajjal selama tujuh bulan.\" Berkata Abu Isa: dalam hal ini ada hadits serupa dari Sha'bu bin Jatstsamah, Abdullah bin Busr, Abdullah bin Mas'ud dan Abu Sa'id Al Khudri dan ini adalah hadits hasan gharib, kami hanya mengetahuinya dari jalur sanad ini."},"2165":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ عَنْ شُعْبَةَ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَفَتْحُ الْقُسْطَنْطِينِيَّةِ مَعَ قِيَامِ السَّاعَةِقَالَ مَحْمُودٌ هَذَا حَدِيثٌ غَرِيبٌ وَالْقُسْطَنْطِينِيَّةُ هِيَ مَدِينَةُ الرُّومِ تُفْتَحُ عِنْدَ خُرُوجِ الدَّجَّالِ وَالْقُسْطَنْطِينِيَّةُ قَدْ فُتِحَتْ فِي زَمَانِ بَعْضِ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Dawud] dari [Syu'bah] dari [Yahya bin Sa'id] dari [Anas bin Malik] berkata: Penaklukan kostantinopel bersamaan dengan terjadinya kiamat.\" Berkata Mahmud: hadits ini gharib dan Kostantinopel -ibu kota Romawi- akan ditaklukkan saat Dajjal muncul dan Kostantinopel telah ditaklukkan di masa sebagaian sahabat nabi Shallallahu 'alaihi wa Salam."},"2166":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا الْوَلِيدُ بْنُ مُسْلِمٍ وَعَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ بْنِ جَابِرٍ دَخَلَ حَدِيثُ أَحَدِهِمَا فِي حَدِيثِ الْآخَرِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ بْنِ جَابِرٍ عَنْ يَحْيَى بْنِ جَابِرٍ الطَّائِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ جُبَيْرٍ عَنْ أَبِيهِ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ النَّوَّاسِ بْنِ سَمْعَانَ الْكِلَابِيِّ قَالَذَكَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الدَّجَّالَ ذَاتَ غَدَاةٍ فَخَفَّضَ فِيهِ وَرَفَّعَ حَتَّى ظَنَنَّاهُ فِي طَائِفَةِ النَّخْلِ قَالَ فَانْصَرَفْنَا مِنْ عِنْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ رَجَعْنَا إِلَيْهِ فَعَرَفَ ذَلِكَ فِينَا فَقَالَ مَا شَأْنُكُمْ قَالَ قُلْنَا يَا رَسُولَ اللَّهِ ذَكَرْتَ الدَّجَّالَ الْغَدَاةَ فَخَفَّضْتَ فِيهِ وَرَفَّعْتَ حَتَّى ظَنَنَّاهُ فِي طَائِفَةِ النَّخْلِ قَالَ غَيْرُ الدَّجَّالِ أَخْوَفُ لِي عَلَيْكُمْ إِنْ يَخْرُجْ وَأَنَا فِيكُمْ فَأَنَا حَجِيجُهُ دُونَكُمْ وَإِنْ يَخْرُجْ وَلَسْتُ فِيكُمْ فَامْرُؤٌ حَجِيجُ نَفْسِهِ وَاللَّهُ خَلِيفَتِي عَلَى كُلِّ مُسْلِمٍ إِنَّهُ شَابٌّ قَطَطٌ عَيْنُهُ طَافِئَةٌ شَبِيهٌ بِعَبْدِ الْعُزَّى بْنِ قَطَنٍ فَمَنْ رَآهُ مِنْكُمْ فَلْيَقْرَأْ فَوَاتِحَ سُورَةِ أَصْحَابِ الْكَهْفِ قَالَ يَخْرُجُ مَا بَيْنَ الشَّامِ وَالْعِرَاقِ فَعَاثَ يَمِينًا وَشِمَالًا يَا عِبَادَ اللَّهِ اثْبُتُوا قَالَ قُلْنَا يَا رَسُولَ اللَّهِ وَمَا لَبْثُهُ فِي الْأَرْضِ قَالَ أَرْبَعِينَ يَوْمًا يَوْمٌ كَسَنَةٍ وَيَوْمٌ كَشَهْرٍ وَيَوْمٌ كَجُمُعَةٍ وَسَائِرُ أَيَّامِهِ كَأَيَّامِكُمْ قَالَ قُلْنَا يَا رَسُولَ اللَّهِ أَرَأَيْتَ الْيَوْمَ الَّذِي كَالسَّنَةِ أَتَكْفِينَا فِيهِ صَلَاةُ يَوْمٍ قَالَ لَا وَلَكِنْ اقْدُرُوا لَهُ قَالَ قُلْنَا يَا رَسُولَ اللَّهِ فَمَا سُرْعَتُهُ فِي الْأَرْضِ قَالَ كَالْغَيْثِ اسْتَدْبَرَتْهُ الرِّيحُ فَيَأْتِي الْقَوْمَ فَيَدْعُوهُمْ فَيُكَذِّبُونَهُ وَيَرُدُّونَ عَلَيْهِ قَوْلَهُ فَيَنْصَرِفُ عَنْهُمْ فَتَتْبَعُهُ أَمْوَالُهُمْ وَيُصْبِحُونَ لَيْسَ بِأَيْدِيهِمْ شَيْءٌ ثُمَّ يَأْتِي الْقَوْمَ فَيَدْعُوهُمْ فَيَسْتَجِيبُونَ لَهُ وَيُصَدِّقُونَهُ فَيَأْمُرُ السَّمَاءَ أَنْ تُمْطِرَ فَتُمْطِرَ وَيَأْمُرُ الْأَرْضَ أَنْ تُنْبِتَ فَتُنْبِتَ فَتَرُوحُ عَلَيْهِمْ سَارِحَتُهُمْ كَأَطْوَلِ مَا كَانَتْ ذُرًا وَأَمَدِّهِ خَوَاصِرَ وَأَدَرِّهِ ضُرُوعًا قَالَ ثُمَّ يَأْتِي الْخَرِبَةَ فَيَقُولُ لَهَا أَخْرِجِي كُنُوزَكِ فَيَنْصَرِفُ مِنْهَا فَيَتْبَعُهُ كَيَعَاسِيبِ النَّحْلِ ثُمَّ يَدْعُو رَجُلًا شَابًّا مُمْتَلِئًا شَبَابًا فَيَضْرِبُهُ بِالسَّيْفِ فَيَقْطَعُهُ جِزْلَتَيْنِ ثُمَّ يَدْعُوهُ فَيُقْبِلُ يَتَهَلَّلُ وَجْهُهُ يَضْحَكُ فَبَيْنَمَا هُوَ كَذَلِكَ إِذْ هَبَطَ عِيسَى ابْنُ مَرْيَمَ عَلَيْهِ السَّلَام بِشَرْقِيِّ دِمَشْقَ عِنْدَ الْمَنَارَةِ الْبَيْضَاءِ بَيْنَ مَهْرُودَتَيْنِ وَاضِعًا يَدَيْهِ عَلَى أَجْنِحَةِ مَلَكَيْنِ إِذَا طَأْطَأَ رَأْسَهُ قَطَرَ وَإِذَا رَفَعَهُ تَحَدَّرَ مِنْهُ جُمَّانٌ كَاللُّؤْلُؤِ قَالَ وَلَا يَجِدُ رِيحَ نَفْسِهِ يَعْنِي أَحَدًا إِلَّا مَاتَ وَرِيحُ نَفْسِهِ مُنْتَهَى بَصَرِهِ قَالَ فَيَطْلُبُهُ حَتَّى يُدْرِكَهُ بِبَابِ لُدٍّ فَيَقْتُلَهُ قَالَ فَيَلْبَثُ كَذَلِكَ مَا شَاءَ اللَّهُ قَالَ ثُمَّ يُوحِي اللَّهُ إِلَيْهِ أَنْ حَوِّزْ عِبَادِي إِلَى الطُّورِ فَإِنِّي قَدْ أَنْزَلْتُ عِبَادًا لِي لَا يَدَانِ لِأَحَدٍ بِقِتَالِهِمْ قَالَ وَيَبْعَثُ اللَّهُ يَأْجُوجَ وَمَأْجُوجَ وَهُمْ كَمَا قَالَ اللَّهُ{ مِنْ كُلِّ حَدَبٍ يَنْسِلُونَ }قَالَ فَيَمُرُّ أَوَّلُهُمْ بِبُحَيْرَةِ الطَّبَرِيَّةِ فَيَشْرَبُ مَا فِيهَا ثُمَّ يَمُرُّ بِهَا آخِرُهُمْ فَيَقُولُ لَقَدْ كَانَ بِهَذِهِ مَرَّةً مَاءٌ ثُمَّ يَسِيرُونَ حَتَّى يَنْتَهُوا إِلَى جَبَلِ بَيْتِ مَقْدِسٍ فَيَقُولُونَ لَقَدْ قَتَلْنَا مَنْ فِي الْأَرْضِ فَهَلُمَّ فَلْنَقْتُلْ مَنْ فِي السَّمَاءِ فَيَرْمُونَ بِنُشَّابِهِمْ إِلَى السَّمَاءِ فَيَرُدُّ اللَّهُ عَلَيْهِمْ نُشَّابَهُمْ مُحْمَرًّا دَمًا وَيُحَاصَرُ عِيسَى ابْنُ مَرْيَمَ وَأَصْحَابُهُ حَتَّى يَكُونَ رَأْسُ الثَّوْرِ يَوْمَئِذٍ خَيْرًا لِأَحَدِهِمْ مِنْ مِائَةِ دِينَارٍ لِأَحَدِكُمْ الْيَوْمَ قَالَ فَيَرْغَبُ عِيسَى ابْنُ مَرْيَمَ إِلَى اللَّهِ وَأَصْحَابُهُ قَالَ فَيُرْسِلُ اللَّهُ إِلَيْهِمْ النَّغَفَ فِي رِقَابِهِمْ فَيُصْبِحُونَ فَرْسَى مَوْتَى كَمَوْتِ نَفْسٍ وَاحِدَةٍ قَالَ وَيَهْبِطُ عِيسَى وَأَصْحَابُهُ فَلَا يَجِدُ مَوْضِعَ شِبْرٍ إِلَّا وَقَدْ مَلَأَتْهُ زَهَمَتُهُمْ وَنَتَنُهُمْ وَدِمَاؤُهُمْ قَالَ فَيَرْغَبُ عِيسَى إِلَى اللَّهِ وَأَصْحَابُهُ قَالَ فَيُرْسِلُ اللَّهُ عَلَيْهِمْ طَيْرًا كَأَعْنَاقِ الْبُخْتِ قَالَ فَتَحْمِلُهُمْ فَتَطْرَحُهُمْ بِالْمَهْبِلِ وَيَسْتَوْقِدُ الْمُسْلِمُونَ مِنْ قِسِيِّهِمْ وَنُشَّابِهِمْ وَجِعَابِهِمْ سَبْعَ سِنِينَ قَالَ وَيُرْسِلُ اللَّهُ عَلَيْهِمْ مَطَرًا لَا يُكَنُّ مِنْهُ بَيْتُ وَبَرٍ وَلَا مَدَرٍ قَالَ فَيَغْسِلُ الْأَرْضَ فَيَتْرُكُهَا كَالزَّلَفَةِ قَالَ ثُمَّ يُقَالُ لِلْأَرْضِ أَخْرِجِي ثَمَرَتَكِ وَرُدِّي بَرَكَتَكِ فَيَوْمَئِذٍ تَأْكُلُ الْعِصَابَةُ مِنْ الرُّمَّانَةِ وَيَسْتَظِلُّونَ بِقَحْفِهَا وَيُبَارَكُ فِي الرِّسْلِ حَتَّى إِنَّ الْفِئَامَ مِنْ النَّاسِ لَيَكْتَفُونَ بِاللِّقْحَةِ مِنْ الْإِبِلِ وَإِنَّ الْقَبِيلَةَ لَيَكْتَفُونَ بِاللِّقْحَةِ مِنْ الْبَقَرِ وَإِنَّ الْفَخِذَ لَيَكْتَفُونَ بِاللِّقْحَةِ مِنْ الْغَنَمِ فَبَيْنَمَا هُمْ كَذَلِكَ إِذْ بَعَثَ اللَّهُ رِيحًا فَقَبَضَتْ رُوحَ كُلِّ مُؤْمِنٍ وَيَبْقَى سَائِرُ النَّاسِ يَتَهَارَجُونَ كَمَا تَتَهَارَجُ الْحُمُرُ فَعَلَيْهِمْ تَقُومُ السَّاعَةُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ بْنِ جَابِرٍ","id":"Telah menceritakan kepada kami ['Ali bin Hujr] telah mengkabarkan kepada kami [Al Walid bin Muslim] dan [Abdullah bin Abdurrahman bin Yazid bin Jabir] hadits salah satu dari keduanya masuk ke dalam hadits yang lainnya, dari [Abdurrahman bin Yazid bin Jabir] dari [Yahya bin Jabir Ath Tho`i] dari [Abdurrahman bin Jubair] dari [ayahnya, Jubair bin Nufair] dari [An Nawwas bin Sam'an Al Kila'i] berkata: Pada suatu pagi hari, Rasulullah Shallallahu 'alaihi wa Salam menyebut Dajjal, beliau melirihkan suara dan mengeraskannya hingga kami mengiranya berada disekelompok pohon kurma. Kami pergi meninggalkan Rasulullah Shallallahu 'alaihi wa Salam lalu kami kembali lagi, beliau mengetahui hal itu lalu beliau bertanya: \"Kenapa kalian?\" kami menjawab: wahai Rasulullah, baginda menyebut Dajjal pada suatu pagi, baginda melirihkan dan mengeraskan suara hingga kami mengiranya ada disekelompok pohon kurma, beliau bersabda: \"Selain Dajjal yang lebih aku khawatirkan pada kalian, bila ia muncul dan aku berada ditengah-tengah kalian, aku akan mengalahkannya, bukan kalian dan bila ia muncul dan aku sudah tidak ada ditengah-tengah kalian, maka setiap orang adalah pembela dirinya sendiri dan Allah adalah penggantiku atas setiap muslim, ia adalah pemuda ikal, matanya menonjol, mirip 'Abdu Al 'Uzza bin Qathan. Siapa pun diantara kalian yang melihatnya hendaklah membaca permulaan surat para penghuni goa (Al Kahfi), ia muncul diantara Syam dan 'Irak lalu banyak membuat kerusakan dikanan dan dikiri, wahai hamba-hamba Allah, teguhlah kalian.\" Kami bertanya: Berapa lama ia tinggal di bumi? Rasulullah Shallallahu 'alaihi wa Salam menjawab: \"Empat puluh hari, satu hari seperti setahun, satu hari seperti sebulan, satu hari seperti satu pecan dan hari-hari lainnya seperti hari-hari kalian.\" Berkata An Nawwas: Kami bertanya: wahai Rasulullah, bagaimana menurut baginda tentang satu hari yang seperti satu tahun, cukupkah bagi kami shalat sehari? Rasulullah Shallallahu 'alaihi wa Salam menjawab: Tidak, tapi perkirakanlah untuknya.\" Berkata An Nawwas: Kami bertanya: Wahai Rasulullah, bagaimana kecepatannya di bumi? Rasulullah Shallallahu 'alaihi wa Salam menjawab: Seperti hujan yang diterbangkan angin lalu ia mendatangi kaum lalu menyeru mereka, mereka mendustakannya dan mereka membalikkan kata-katanya, ia meninggalkan mereka lalu ia diikuti oleh harta-harta mereka hingga mereka tidak lagi memiliki apa pun, setelah itu ia mendatangi kaum dan menyeru mereka, mereka menerimanya, ia memerintahkan langit agar menurunkan hujan, langit lalu menurunkan hujan, ia memerintahkan bumi agar mengeluarkan tumbuh-tumbuhan, bumi lalu mengeluarkan tumbuh-tumbuhan, lalu binatang ternak mereka pulang dengan punuk yang panjang, lambung yang lebar dan kantong susu yang berisi, lalu dajjal mendatangi perkampungan yang tinggal puing-puing dan berkata kepadanya: \"Keluarkan harta simpananmu lalu dajjal meninggalkannya dan kekayaan-kekayaan bumi mengikutinya seperti ratu lebah lalu ia memanggil seorang pemuda belia, ia menebasnya dengan pedang lalu memutusnya menjadi dua bagian lalu memanggilnya, dan anak muda itu tiba-tiba bisa datang wajahnya yang berseri-seri seraya tertawa, saat ia seperti itu, tiba-tiba 'Isa putra Maryam turun di sebelah timur Damaskus di menara putih dengan mengenakan dua baju bercelup minyak za'faran seraya meletakkan kedua tangannya diatas sayap dua malaikat, bila ia menundukkan kepala, air menetes dan bila ia mengangkat kepala keringat bercucuran seperti mutiara.\" Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Tidaklah seorang mencium bau nafasnya melainkan pasti meninggal dunia dan bau nafasnya sejauh matanya memandang.\" Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"'Isa mencari Dajjal hingga menemuinya di pintu Ludd lalu membunuhnya.\" Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Ia juga tinggal lama hingga Allah mewahyukan padanya agar menggiring manusia ke Thursina karena Aku telah menempatkan hamba-hambaKu yang tidak seorang pun bisa memeranginya.\" Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Allah mengirim Ya'juj dan Ma'juj, mereka seperti yang difirmankan: \"Dari benteng-benteng tinggi mereka turun dengan cepat.\" (QS. Al-Anbiya' 96), Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Lalu yang terdepan melintasi danau Thabariyah dan minum kemudian yang belakang melintasi, ia berkata: Tadi disini ada airnya. Mereka berjalan hingga sampai gunung Baitul Maqdis, mereka berkata: Kami telah membunuh orang-orang yang ada di bumi, ayo kita bunuh yang ada di langit. Mereka pun melesakkan panah mereka ke langit lalu Allah membalikkan panah mereka bermerah darah. 'Isa putra Maryam dan para sahabatnya terkepung hingga kepala kerbau saat itu lebih baik bagi salah seorang dari mereka dari pada seratus dinar milik salah seorang dari kalian hari ini lalu 'Isa putra Maryam dan para sahabatnya berdoa kepada Allah.\" Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Lalu Allah mengutus cacing di leher mereka lalu mereka mati seperti matinya satu jiwa, lalu 'Isa dan para sahabatnya datang, tidak ada satu sejengkal tempat pun melainkan telah dipenuhi oleh bangkai dan bau busuk darah mereka.\" Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Lalu 'Isa dan para sahabatnya berdoa kepada Allah lalu Allah mengirim burung seperti leher unta.\" Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Burung itu membawa mereka dan melemparkan mereka lubang tanah, kaum muslimin menjadikan panah, anak panah dan wadah panah mereka sebagai bahan bakar selama tujuh tahun.\" Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Lalu Allah mengirim hujan kepada mereka, tidak ada rumah dari bulu atau rumah dari tanah yang menghalangi turunnya hujan.\" Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Hujan itu membasuh bumi dan meninggalkan genangan dimana-mana.\" Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Setelah itu dikatakan kepada bumi: Keluarkan buah-buahanmu dan kembalikan berkahmu. Saat itu sekelompok manusia memakan delima, mereka menjadikan kulitnya sebagai tempat berteduh, susu diberkahi hingga sekelompok manusia mencukupkan diri dengan unta perahan, satu kabilah mencukupkan diri dengan sapi perahan dan beberapa kerabat mencukupkan diri dengan kambing perahan. Saat mereka seperti itu, tiba-tiba Allah Subhaanahu wa Ta'ala mengirim angin lalu mencabut nyawa setiap orang mu`min dan orang-orang yang masih ada melakukan hubungan badan secara tenang-terangan seperti keledai kawin. Maka atas mereka itulah kiamat terjadi.\" Berkata Abu Isa: hadits ini hasan shahih gharib, kami hanya mengetahuinya dari hadits Abdurrahman bin Yazid bin Jabir."},"2167":{"ar":"حَدَّثَنَا مُحَمّدُ بْنُ عَبْدِ الْأَعْلَى الصَّنْعَانِيُّ حَدَّثَنَا الْمُعْتَمِرُ بْنُ سُلَيْمَانَ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ سُئِلَ عَنْ الدَّجَّالِ فَقَالَ أَلَا إِنَّ رَبَّكُمْ لَيْسَ بِأَعْوَرَ أَلَا وَإِنَّهُ أَعْوَرُ عَيْنُهُ الْيُمْنَى كَأَنَّهَا عِنَبَةٌ طَافِيَةٌقَالَ وَفِي الْبَاب عَنْ سَعْدٍ وَحُذَيْفَةَ وَأَبِي هُرَيْرَةَ وَأَسْمَاءَ وَجَابِرِ بْنِ عَبْدِ اللَّهِ وَأَبِي بَكْرَةَ وَعَائِشَةَ وَأَنَسٍ وَابْنِ عَبَّاسٍ وَالْفَلَتَانِ بْنِ عَاصِمٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ حَدِيثِ عَبْدِ اللَّهِ بْنِ عُمَرَ","id":"Telah menceritakan kepada kami [Muhammad bin 'Abdul A'la Ash Shan'ani] telah menceritakan kepada kami [Al Mu'tamir bin Sulaiman] dari ['Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] dari nabi Shallallahu 'alaihi wa Salam, beliau ditanya tentang Dajjal, beliau menjawab: \"Ingat, Rabb kalian tidak buta sebelah mata dan ia (Dajjal) buta sebelah mata kanannya seperti anggur yang menjorok.\" Dalam hal ini ada hadits serupa dari Sa'ad, Khudzaifah, Abu Hurairah, Asma`, Jabir bin Abdullah, Abu Bakrah, 'A`isyah, Anas, Ibnu 'Abbas, Al Falatan bin 'Ashim. Berkata Abu Isa: Hadits ini hasan shahih gharib dari hadits Abdullah bin Umar."},"2168":{"ar":"حَدَّثَنَا عَبْدَةُ بْنُ عَبْدِ اللَّهِ الْخُزَاعِيُّ الْبَصْرِيُّ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْتِي الدَّجَّالُ الْمَدِينَةَ فَيَجِدُ الْمَلَائِكَةَ يَحْرُسُونَهَا فَلَا يَدْخُلُهَا الطَّاعُونُ وَلَا الدَّجَّالُ إِنْ شَاءَ اللَّهُقَالَ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَفَاطِمَةَ بِنْتِ قَيْسٍ وَأُسَامَةَ بْنِ زَيْدٍ وَسَمُرَةَ بْنِ جُنْدَبٍ وَمِحْجَنٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Abdah bin Abdullah Al Khuza'I Al Bashri] telah menceritakan kepada kami [Yazid bin Harun] telah mengkhabarkan kepada kami [Syu'bah] dari [Qatadah] dari [Anas] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Dajjal mendatangi Madinah lalu ia mendapati malaikat-malaikat menjaganya, ia tidak bisa dimasuki oleh Tha'un dan Dajjal, insya Allah.\" Dalam hal ini ada hadits serupa dari Abu Hurairah, Fathimah binti Qais, Usamah bin Zaid, Samurah bin Jundub dan Mihjan. Berkata Abu Isa: hadits ini hasan shahih."},"2169":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْإِيمَانُ يَمَانٍ وَالْكُفْرُ مِنْ قِبَلِ الْمَشْرِقِ وَالسَّكِينَةُ لِأَهْلِ الْغَنَمِ وَالْفَخْرُ وَالرِّيَاءُ فِي الْفَدَّادِينَ أَهْلِ الْخَيْلِ وَأَهْلِ الْوَبَرِ يَأْتِي الْمَسِيحُ إِذَا جَاءَ دُبُرَ أُحُدٍ صَرَفَتْ الْمَلَائِكَةُ وَجْهَهُ قِبَلَ الشَّامِ وَهُنَالِكَ يَهْلَكُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami ['Abdul 'Aziz bin Muhammad] dari [Al 'Alla` bin Abdurrahman] dari [ayahnya] dari [Abu Hurairah] Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Iman itu ada di Yaman, kekufuran berasal dari arah timur, ketenangan itu untuk para pemilik kambing, bangga dan riya' ada dikalangan Faddani, para pemilik kuda dan bulu, Al Masih saat tiba mendatangi belakang Uhud lalu para malaikat memalingkan wajahnya ke arah Syam dan disanalah ia binasa.\" Berkata Abu Isa: hadits ini hasan shahih."},"2170":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ أَنَّهُ سَمِعَ عُبَيْدَ اللَّهِ بْنَ عَبْدِ اللَّهِ بْنِ ثَعْلَبَةَ الْأَنْصَارِيَّ يُحَدِّثُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ الْأَنْصَارِيِّ مِنْ بَنِي عَمْرِو بْنِ عَوْفٍ يَقُولُ سَمِعْتُ عَمِّي مُجَمِّعَ ابْنَ جَارِيَةَ الْأَنْصَارِيَّ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَقْتُلُ ابْنُ مَرْيَمَ الدَّجَّالَ بِبَابِ لُدٍّقَالَ وَفِي الْبَاب عَنْ عِمْرَانَ بْنِ حُصَيْنٍ وَنَافِعِ بْنِ عُتْبَةَ وَأَبِي بَرْزَةَ وَحُذَيْفَةَ بْنِ أَسِيدٍ وَأَبِي هُرَيْرَةَ وَكَيْسَانَ وَعُثْمَانَ بْنِ أَبِي الْعَاصِ وَجَابِرٍ وَأَبِي أُمَامَةَ وَابْنِ مَسْعُودٍ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو وَسَمُرَةَ بْنِ جُنْدَبٍ وَالنَّوَّاسِ بْنِ سَمْعَانَ وَعَمْرِو بْنِ عَوْفٍ وَحُذَيْفَةَ بْنِ الْيَمَانِ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Lais] dari [Ibnu Syihab] ia mendengar ['Ubaidullah bin Abdullah bin Tsa'labah Al Anshari] menceritakan dari [Abdurrahman bin Yazid Al Anshari dari Bani 'Amru bin 'Auf] berkata: Aku mendengar pamanku [Mujammi' bin Jariyah Al Anshari] berkata: Aku mendengar Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Ibnu Maryam membunuh Dajjal di pintu Ludd.\" Berkata Abu Isa: Dalam hal ini ada hadits serupa dari 'Imran bin Hushain, Nafi' bin 'Utbah, Abu Barzah, Hudzaifah bin Usaid, Abu Hurairah, Kaisan, 'Utsman bin Abu Al 'Ash, Jabir, Abu Umamah, Ibnu Mas'ud, Abdullah bin 'Amru, Samurah bin Jundub, Nawwas bin Sam'an, 'Amru bin 'Auf, Hudzaifah bin Al Yaman. Berkata Abu Isa: hadits ini hasan shahih."},"2171":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ قَال سَمِعْتُ أَنَسًا قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ نَبِيٍّ إِلَّا وَقَدْ أَنْذَرَ أُمَّتَهُ الْأَعْوَرَ الْكَذَّابَ أَلَا إِنَّهُ أَعْوَرُ وَإِنَّ رَبَّكُمْ لَيْسَ بِأَعْوَرَ مَكْتُوبٌ بَيْنَ عَيْنَيْهِ ك ف رهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] berkata: Aku mendengar [Anas] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Tidaklah seorang nabi pun melainkan mengingatkan kaumnya dari si buta sebelah mata si pendusta, Rabb kalian tidaklah buta sebelah mata, diantara kedua matanya tertulis K A F I R.\" Hadits ini hasan shahih."},"2172":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ وَكِيعٍ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ الْجُرَيْرِيِّ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ قَالَصَحِبَنِي ابْنُ صَائِدٍ إِمَّا حُجَّاجًا وَإِمَّا مُعْتَمِرِينَ فَانْطَلَقَ النَّاسُ وَتُرِكْتُ أَنَا وَهُوَ فَلَمَّا خَلَصْتُ بِهِ اقْشَعْرَرْتُ مِنْهُ وَاسْتَوْحَشْتُ مِنْهُ مِمَّا يَقُولُ النَّاسُ فِيهِ فَلَمَّا نَزَلْتُ قُلْتُ لَهُ ضَعْ مَتَاعَكَ حَيْثُ تِلْكَ الشَّجَرَةِ قَالَ فَأَبْصَرَ غَنَمًا فَأَخَذَ الْقَدَحَ فَانْطَلَقَ فَاسْتَحْلَبَ ثُمَّ أَتَانِي بِلَبَنٍ فَقَالَ لِي يَا أَبَا سَعِيدٍ اشْرَبْ فَكَرِهْتُ أَنْ أَشْرَبَ مِنْ يَدِهِ شَيْئًا لِمَا يَقُولُ النَّاسُ فِيهِ فَقُلْتُ لَهُ هَذَا الْيَوْمُ يَوْمٌ صَائِفٌ وَإِنِّي أَكْرَهُ فِيهِ اللَّبَنَ قَالَ لِي يَا أَبَا سَعِيدٍ هَمَمْتُ أَنْ آخُذَ حَبْلًا فَأُوثِقَهُ إِلَى شَجَرَةٍ ثُمَّ أَخْتَنِقَ لِمَا يَقُولُ النَّاسُ لِي وَفِيَّ أَرَأَيْتَ مَنْ خَفِيَ عَلَيْهِ حَدِيثِي فَلَنْ يَخْفَى عَلَيْكُمْ أَلَسْتُمْ أَعْلَمَ النَّاسِ بِحَدِيثِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا مَعْشَرَ الْأَنْصَارِ أَلَمْ يَقُلْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهُ كَافِرٌ وَأَنَا مُسْلِمٌ أَلَمْ يَقُلْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهُ عَقِيمٌ لَا يُولَدُ لَهُ وَقَدْ خَلَّفْتُ وَلَدِي بِالْمَدِينَةِ أَلَمْ يَقُلْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَدْخُلُ أَوْ لَا تَحِلُّ لَهُ مَكَّةُ وَالْمَدِينَةُ أَلَسْتُ مِنْ أَهْلِ الْمَدِينَةِ وَهُوَ ذَا أَنْطَلِقُ مَعَكَ إِلَى مَكَّةَ فَوَاللَّهِ مَا زَالَ يَجِيءُ بِهَذَا حَتَّى قُلْتُ فَلَعَلَّهُ مَكْذُوبٌ عَلَيْهِ ثُمَّ قَالَ يَا أَبَا سَعِيدٍ وَاللَّهِ لَأُخْبِرَنَّكَ خَبَرًا حَقًّا وَاللَّهِ إِنِّي لَأَعْرِفُهُ وَأَعْرِفُ وَالِدَهُ وَأَعْرِفُ أَيْنَ هُوَ السَّاعَةَ مِنْ الْأَرْضِ فَقُلْتُ تَبًّا لَكَ سَائِرَ الْيَوْمِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Sufyan bin Waki'] telah menceritakan kepada kami ['Abdul A'la] telah menceritakan kepada kami [Al Jurairi] dari [Abu Nadlrah] dari [Abu Sa'id] dia berkata: Ibnu Sha'id menemaniku ketika haji maupun umroh, orang orang berangkat sementara aku dan dia tertinggal, setelah aku menyendiri dengan dia aku merasa merinding dan ngeri darinya karena apa yang telah dikatakan orang orang tentangnya, setelah aku turun aku berkata kepadanya: Letakkan barang bawaanmu di pohon itu. dia (Abu sa'id) berkata: Dia melihat seekor kambing dan mengambil wadah lalu pergi memerah susu kemudian dia datang kepadaku dengan membawa susu dan berkata kepadaku: wahai Abu sa'id minumlah, namun aku tidak suka untuk minum sesuatu melalui tangannya karena apa yang telah dikatakan orang orang tentangnya, lalu aku berkata kepadanya: Hari ini adalah hari yang panas dan aku tidak ingin untuk minum susu. lalu dia berkata kepadaku: Wahai Abu Sa'id, aku berniat untuk mengambil seutas tali kemudian aku ikatkan pada sebuah pohon lalu aku mencekikkan diriku karena apa apa yang telah dikatakan oleh orang orang kepadaku dan tentangku, tidakkah kalian tahu bahwa barangsiapa yang ucapanku samar baginya, namun sekali-kali tidak samar bagi kalian, bukankah engkau adalah orang yang paling tahu tentang sabda Rasulullah Shallallahu 'alahi wa Salam, wahai orang orang Anshar bukankah Rasulullah Shallallahu 'alahi wa Salam pernah bersabda bahwa dia kafir (Dajjal) sedangkan aku adalah orang muslim, bukankah Rasulullah Shallallahu 'alahi wa Salam pernah bersabda: \" dia adalah orang yang mandul tidak melahirkan anak sedangkan aku telah meninggalkan anak anakku di Madinah, bukankah Rasulullah Shallallahu 'alahi wa Salam pernah bersabda bahwa dia tidak masuk atau tidak halal baginya Makkah dan Madinah, bukankah aku termasuk penduduk Madinah? dia (Ibnu Sha'id) berkata: inilah aku sekarang berjalan bersamamu menuju Makkah. Demi Allah dia terus menerus mengatakan hal ini sampai aku mengatakan: Mungkin dia berbohong, kemudian dia berkata: wahai Abu Sa'id, demi Allah pasti aku akan ceritakan kepadamu suatu berita yang benar, demi Allah aku mengetahuinya (Dajjal), aku mengetahui bapaknya, dan mengetahui di mana sekarang ia berada. Aku berkata: Celaka kamu sepanjang hari. Abu Isa berkata \" Hadits ini hasan shahih."},"2173":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ وَكِيعٍ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ الْجُرَيْرِيِّ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ قَالَلَقِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ابْنَ صَائِدٍ فِي بَعْضِ طُرُقِ الْمَدِينَةِ فَاحْتَبَسَهُ وَهُوَ غُلَامٌ يَهُودِيٌّ وَلَهُ ذُؤَابَةٌ وَمَعَهُ أَبُو بَكْرٍ وَعُمَرُ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَشْهَدُ أَنِّي رَسُولُ اللَّهِ فَقَالَ أَتَشْهَدُ أَنْتَ أَنِّي رَسُولُ اللَّهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ آمَنْتُ بِاللَّهِ وَمَلَائِكَتِهِ وَكُتُبِهِ وَرُسُلِهِ وَالْيَوْمِ الْآخِرِ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا تَرَى قَالَ أَرَى عَرْشًا فَوْقَ الْمَاءِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَرَى عَرْشَ إِبْلِيسَ فَوْقَ الْبَحْرِ قَالَ فَمَا تَرَى قَالَ أَرَى صَادِقًا وَكَاذِبِينَ أَوْ صَادِقِينَ وَكَاذِبًا قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لُبِسَ عَلَيْهِ فَدَعَاهُقَالَ وَفِي الْبَاب عَنْ عُمَرَ وَحُسَيْنِ بْنِ عَلِيٍّ وَابْنِ عُمَرَ وَأَبِي ذَرٍّ وَابْنِ مَسْعُودٍ وَجَابِرٍ وَحَفْصَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Sufyan bin Waki'] telah menceritakan kepada kami ['Abdul A'la] dari [Al Jurairi] dari [Abu Nadlrah] dari [Abu Sa'id] berkata: Rasulullah Shallallahu 'alahi wa Salam bertemu dengan Ibnu Sha'id di suatu jalan Madinah lalu beliau menahannya, ia adalah budak Yahudi dan ia memiliki rambut yang dipintal, saat itu Rasulullah Shallallahu 'alahi wa Salam bersama Abu Bakar dan Umar, Rasulullah Shallallahu 'alahi wa Salam bertanya padanya: \"Apa kau bersaksi bahwa aku utusan Allah?\" ia balik bertanya: Apa kau bersaksi bahwa aku utusan Allah? Nabi Shallallahu 'alaihi wa Salam bersabda: \"Aku beriman kepada Allah, malaikat, kitab, rasul dan hari akhir.\" Nabi Shallallahu 'alaihi wa Salam: \"Apa yang kau lihat?\" Abu Sha'id menjawab: Aku melihat 'arsy diatas air. Nabi Shallallahu 'alaihi wa Salam bersabda: \"Kau melihat 'arsynya iblis diatas laut.\" Beliau bertanya: \"Apa yang kau lihat?\" Ibnu Sha'id menjawab: Aku melihat seorang jujur dan dua pendusta atau dua orang jujur dan seorang pendusta. Nabi Shallallahu 'alaihi wa Salam bersabda: \"Disamarkan baginya.\" Lalu nabi Shallallahu 'alaihi wa Salam memanggilnya. Berkata Abu Isa: Dalam hal ini ada hadits serupa dari Umar, Husain bin Ali, Ibnu Umar, Abu Dzarr, Ibnu Mas'ud, Jabir, Hafshah. Berkata Abu Isa: Hadits ini hasan."},"2174":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُعَاوِيَةَ الْجُمَحِيُّ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْكُثُ أَبُو الدَّجَّالِ وَأُمُّهُ ثَلَاثِينَ عَامًا لَا يُولَدُ لَهُمَا وَلَدٌ ثُمَّ يُولَدُ لَهُمَا غُلَامٌ أَعْوَرُ أَضَرُّ شَيْءٍ وَأَقَلُّهُ مَنْفَعَةً تَنَامُ عَيْنَاهُ وَلَا يَنَامُ قَلْبُهُ ثُمَّ نَعَتَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبَوَيْهِ فَقَالَ أَبُوهُ طِوَالٌ ضَرْبُ اللَّحْمِ كَأَنَّ أَنْفَهُ مِنْقَارٌ وَأُمُّهُ فِرْضَاخِيَّةٌ طَوِيلَةُ الْيَدَيْنِ فَقَالَ أَبُو بَكْرَةَ فَسَمِعْنَا بِمَوْلُودٍ فِي الْيَهُودِ بِالْمَدِينَةِ فَذَهَبْتُ أَنَا وَالزُّبَيْرُ بْنُ الْعَوَّامِ حَتَّى دَخَلْنَا عَلَى أَبَوَيْهِ فَإِذَا نَعْتُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيهِمَا فَقُلْنَا هَلْ لَكُمَا وَلَدٌ فَقَالَا مَكَثْنَا ثَلَاثِينَ عَامًا لَا يُولَدُ لَنَا وَلَدٌ ثُمَّ وُلِدَ لَنَا غُلَامٌ أَعْوَرُ أَضَرُّ شَيْءٍ وَأَقَلُّهُ مَنْفَعَةً تَنَامُ عَيْنَاهُ وَلَا يَنَامُ قَلْبُهُ قَالَ فَخَرَجْنَا مِنْ عِنْدِهِمَا فَإِذَا هُوَ مُنْجَدِلٌ فِي الشَّمْسِ فِي قَطِيفَةٍ لَهُ وَلَهُ هَمْهَمَةٌ فَتَكَشَّفَ عَنْ رَأْسِهِ فَقَالَ مَا قُلْتُمَا قُلْنَا وَهَلْ سَمِعْتَ مَا قُلْنَا قَالَ نَعَمْ تَنَامُ عَيْنَايَ وَلَا يَنَامُ قَلْبِيقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ حَمَّادِ بْنِ سَلَمَةَ","id":"Telah menceritakan kepada kami [Abdullah bin Mua'wiyah Al Jumhi] telah menceritakan kepada kami [Hammad bin Salamah] dari ['Ali bin Zaid] dari [Abdurrahman bin Abu Bakrah] dari [ayahnya] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Ayah dan ibu Dajjal tinggal selama tigapuluh tahun, keduanya tidak memiliki anak, setelah itu keduanya melahirkan bayi buta sebelah mata, ia paling berbahaya dan sedikit manfaatnya, matanya tidur tapi hatinya tidak.\" Setelah itu Rasulullah Shallallahu 'alahi wa Salam menyebutkan ciri-ciri kedua orang tua Dajjal, beliau bersabda: \"Ayahnya tinggi, kurus, hidungnya seperti paruh dan ibunya gemuk bertangan panjang.\" Berkata Abu Bakrah: Kami mendengar bayi lahir dikalangan yahudi Madinah, lalu aku pergi bersama Zubair bin Awwam hingga kami memasuki kediaman kedua orang tuanya, ternyata ciri-ciri yang disebutkan Rasulullah Shallallahu 'alahi wa Salam ada pada keduanya, kami bertanya: Apa kalian punya anak? Keduanya menjawab: Kami tinggal selama tigapuluh tahun tapi tidak punya anak, setelah itu kami punya anak buta sebelah mata, ia membahayakan dan sedikit sekali manfaatnya, matanya tertidur tapi hatinya tidak. Berkata Abu Bakrah: Lalu kami keluar dari kediaman mereka berdua ternyata ia tengah tergeletak di tanah di bawah terik matahari dalam kain beludru dan ia berbicara tapi tidak difahami. Lalu ia membuka penutup kepalanya, ia bertanya: Apa yang kalian berdua katakan? Kami menjawab: Apa kau mendengar ucapan kami? Ia menjawab: Ya, kedua mataku tidur tapi hatiku tidak. Berkata Abu Isa: hadits ini hasan gharib, hanya kami ketahui dari hadits Hammad bin Salamah."},"2175":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِابْنِ صَيَّادٍ فِي نَفَرٍ مِنْ أَصْحَابِهِ فِيهِمْ عُمَرُ بْنُ الْخَطَّابِ وَهُوَ يَلْعَبُ مَعَ الْغِلْمَانِ عِنْدَ أُطُمِ بَنِي مَغَالَةَ وَهُوَ غُلَامٌ فَلَمْ يَشْعُرْ حَتَّى ضَرَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ظَهْرَهُ بِيَدِهِ ثُمَّ قَالَ أَتَشْهَدُ أَنِّي رَسُولُ اللَّهِ فَنَظَرَ إِلَيْهِ ابْنُ صَيَّادٍ قَالَ أَشْهَدُ أَنَّكَ رَسُولُ الْأُمِّيِّينَ ثُمَّ قَالَ ابْنُ صَيَّادٍ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَشْهَدُ أَنْتَ أَنِّي رَسُولُ اللَّهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ آمَنْتُ بِاللَّهِ وَبِرُسُلِهِ ثُمَّ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا يَأْتِيكَ قَالَ ابْنُ صَيَّادٍ يَأْتِينِي صَادِقٌ وَكَاذِبٌ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُلِّطَ عَلَيْكَ الْأَمْرُ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي خَبَأْتُ لَكَ خَبِيئًا وَخَبَأَ لَهُ{ يَوْمَ تَأْتِي السَّمَاءُ بِدُخَانٍ مُبِينٍ }فَقَالَ ابْنُ صَيَّادٍ هُوَ الدُّخُّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اخْسَأْ فَلَنْ تَعْدُوَ قَدْرَكَ قَالَ عُمَرُ يَا رَسُولَ اللَّهِ ائْذَنْ لِي فَأَضْرِبَ عُنُقَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ يَكُ حَقًّا فَلَنْ تُسَلَّطَ عَلَيْهِ وَإِنْ لَا يَكُنْهُ فَلَا خَيْرَ لَكَ فِي قَتْلِهِقَالَ عَبْدُ الرَّزَّاقِ يَعْنِي الدَّجَّالَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami ['Abd bin Humaid] telah mengkhabarkan kepada kami [Abdurrazzaq] telah mengkhabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Salim] dari [Ibnu Umar], Rasulullah Shallallahu 'alahi wa Salam melewati Ibnu Shayyad bersama beberapa sahabat, diantara mereka ada Umar bin Al Khaththab, ia bermain bersama anak-anak kecil didekat Uthum bin Maghalah, ia adalah seorang budak, ia tidak merasa hingga Rasulullah Shallallahu 'alahi wa Salam memukul punggungnya lalu beliau bertanya: \"Apa kau bersaksi bahwa aku utusan Allah?\" Ibnu Shayyad memandang beliau, ia menjawab: Aku bersaksi bahwa engkau adalah rasul kaum ummi. Selanjutnya Ibnu Shayyad bertanya: Apa kau bersaksi bahwa aku utusan Allah? Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Aku beriman kepada Allah dan rasulNya.\" Setelah itu nabi Shallallahu 'alaihi wa Salam bertanya: \"Apa yang mendatangimu?\" Ibnu Shayyad menjawab: Seorang jujur dan seorang pendusta mendatangiku. Nabi Shallallahu 'alaihi wa Salam bersabda: \"Urusan dicampur adukkan padamu.\" Setelah itu Rasulullah Shallallahu 'alahi wa Salam bertanya: \" aku menyembunyikan sesuatu padamu.\" Nabi Shallallahu 'alaihi wa Salam ketika itu menyembunyikan kutipan ayat yang berbunyi \"dan ingatlah ketika langit membawa asap yang nyata (QS. Addukhan: 10). Ibnu Shayyad menjawab: Itu adalah asap. Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Hinalah engkau, engkau tidak bakalan melampaui batas kemampuanmu sebagai dukun!.\" Umar berkata: Wahai Rasulullah, izinkan aku menebas lehernya. Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Bila ia benar, kau tidak akan bisa menguasainya dan bila tidak, tidak ada baiknya bagimu untuk membunuhnya.\" Berkata 'Abdur Razza: Maksud beliau Dajjal. Berkata Abu Isa: Hadits ini hasan shahih. "},"2176":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا عَلَى الْأَرْضِ نَفْسٌ مَنْفُوسَةٌ يَعْنِي الْيَوْمَ تَأْتِي عَلَيْهَا مِائَةُ سَنَةٍقَالَ وَفِي الْبَاب عَنْ ابْنِ عُمَرَ وَأَبِي سَعِيدٍ وَبُرَيْدَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir] dia berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \" Tidak ada suatu jiwa yang hidup di atas bumi yaitu pada hari ini untuk seratus tahun kemudian.\" Berkata Abu Isa: Dan dalam bab ini ada hadits dari Ibnu Umar, Abu Sa'id dan Buraidah. Abu Isa berkata: Hadits ini hasan."},"2177":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ وَأَبِي بَكْرِ بْنِ سُلَيْمَانَ وَهُوَ ابْنُ أَبِي حَثْمَةَ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ قَالَصَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ لَيْلَةٍ صَلَاةَ الْعِشَاءِ فِي آخِرِ حَيَاتِهِ فَلَمَّا سَلَّمَ قَامَ فَقَالَ أَرَأَيْتَكُمْ لَيْلَتَكُمْ هَذِهِ عَلَى رَأْسِ مِائَةِ سَنَةٍ مِنْهَا لَا يَبْقَى مِمَّنْ هُوَ عَلَى ظَهْرِ الْأَرْضِ أَحَدٌ قَالَ ابْنُ عُمَرَ فَوَهِلَ النَّاسُ فِي مَقَالَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تِلْكَ فِيمَا يَتَحَدَّثُونَهُ مِنْ هَذِهِ الْأَحَادِيثِ عَنْ مِائَةِ سَنَةٍ وَإِنَّمَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَبْقَى مِمَّنْ هُوَ الْيَوْمَ عَلَى ظَهْرِ الْأَرْضِ أَحَدٌ يُرِيدُ بِذَلِكَ أَنْ يَنْخَرِمَ ذَلِكَ الْقَرْنُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Abd bin Humaid] telah mengkhabarkan kepada kami [Abdurrazzaq] telah mengkhabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Salim bin Abdullah] dan [Abu Bakar bin Sulaiman bin Abu Hatsmah] bahwa [Abdullah bin Umar] berata: Rasulullah Shallallahu 'alahi wa Salam shalat 'isya` bersama kami pada suatu malam diakhir hidup beliau, saat salam beliau berdiri lalu bersabda: \"Tahukah kalian malam kalian ini diatas penghujung seratus tahun ini, tidak ada seorang pun diatas muka bumi ini yang hidup (setelah seratus tahun berikutnya, pent.).\" Ibnu Umar berkata: Orang-orang takut akan sabda Rasulullah Shallallahu 'alahi wa Salam itu seperti yang mereka perpincangkan berupa perkataan-perkataan tentang seribu tahun, Rasulullah Shallallahu 'alahi wa Salam hanya bersabda: \"Tidak akan ada seorang pun saat ini ada di atas muka bumi akan hidup (saat itu, pent.) \" Maksud beliau melintasi abad tersebut. Berkata Abu Isa: Hadits ini shahih."},"2178":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ بْنِ حَبِيبِ بْنِ الشَّهِيدِ الْبَصْرِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ حَدَّثَنَا الْأَعْمَشُ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ ذَرٍّ عَنْ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَسُبُّوا الرِّيحَ فَإِذَا رَأَيْتُمْ مَا تَكْرَهُونَ فَقُولُوا اللَّهُمَّ إِنَّا نَسْأَلُكَ مِنْ خَيْرِ هَذِهِ الرِّيحِ وَخَيْرِ مَا فِيهَا وَخَيْرِ مَا أُمِرَتْ بِهِ وَنَعُوذُ بِكَ مِنْ شَرِّ هَذِهِ الرِّيحِ وَشَرِّ مَا فِيهَا وَشَرِّ مَا أُمِرَتْ بِهِقَالَ وَفِي الْبَاب عَنْ عَائِشَةَ وَأَبِي هُرَيْرَةَ وَعُثْمَانَ بْنِ أَبِي الْعَاصِ وَأَنَسٍ وَابْنِ عَبَّاسٍ وَجَابِرٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim bin Habib bin Asy Syahid Al Bashri] telah menceritakan kepada kami [Muhammad bin Fudlail] telah menceritakan kepada kami [Al A'masy] dari [Habib bin Abu Tsabit] dari [Dzarr] dari [Sa'id bin Abdurrahman bin Abza] dari [ayahnya] dari [Ubai bin Ka'ab] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Janganlah kalian mencela angin, bila kalian melihat yang tidak kalian suka, ucapkanlah: ALLOOHUMMA INNAA NAS\"ALUKA MIN KHOIRI HAADZIHIRRIIHI WA KHOIRI MAA FIIHAA, WA KHOIRI MAA UMIROT BIHI WANA'UUDZU BIKA MIN SYARRI HAADZIHIR RIIKHI WA SYARRI MAA FIIHAA WASYARRI MAA UMIROT BIHI \"Ya Allah, kami meminta kebaikan angin ini padaMu, kebaikan yang ada padanya, dan kebaikan yang diperintahkan kepadanya dan kami berlindung kepadaMu dari keburukan angin ini dan keburukan yang diperintahkan kepadanya.\" Berkata Abu Isa: Dalam hal ini ada hadits serupa dari 'A`isyah, Abu Hurairah, 'Utsman bin Abu Al 'Ash, Anas, Ibnu 'Abbas, Jabir. Berkata Abu Isa: Hadits ini hasan shahih."},"2179":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنَا أَبِي عَنْ قَتَادَةَ عَنْ الشَّعْبِيِّ عَنْ فَاطِمَةَ بِنْتِ قَيْسٍأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَعِدَ الْمِنْبَرَ فَضَحِكَ فَقَالَ إِنَّ تَمِيمًا الدَّارِيَّ حَدَّثَنِي بِحَدِيثٍ فَفَرِحْتُ فَأَحْبَبْتُ أَنْ أُحَدِّثَكُمْ حَدَّثَنِي أَنَّ نَاسًا مِنْ أَهْلِ فِلَسْطِينَ رَكِبُوا سَفِينَةً فِي الْبَحْرِ فَجَالَتْ بِهِمْ حَتَّى قَذَفَتْهُمْ فِي جَزِيرَةٍ مِنْ جَزَائِرِ الْبَحْرِ فَإِذَا هُمْ بِدَابَّةٍ لَبَّاسَةٍ نَاشِرَةٍ شَعْرَهَا فَقَالُوا مَا أَنْتِ قَالَتْ أَنَا الْجَسَّاسَةُ قَالُوا فَأَخْبِرِينَا قَالَتْ لَا أُخْبِرُكُمْ وَلَا أَسْتَخْبِرُكُمْ وَلَكِنْ ائْتُوا أَقْصَى الْقَرْيَةِ فَإِنَّ ثَمَّ مَنْ يُخْبِرُكُمْ وَيَسْتَخْبِرُكُمْ فَأَتَيْنَا أَقْصَى الْقَرْيَةِ فَإِذَا رَجُلٌ مُوثَقٌ بِسِلْسِلَةٍ فَقَالَ أَخْبِرُونِي عَنْ عَيْنِ زُغَرَ قُلْنَا مَلْأَى تَدْفُقُ قَالَ أَخْبِرُونِي عَنْ الْبُحَيْرَةِ قُلْنَا مَلْأَى تَدْفُقُ قَالَ أَخْبِرُونِي عَنْ نَخْلِ بَيْسَانَ الَّذِي بَيْنَ الْأُرْدُنِّ وَفِلَسْطِينَ هَلْ أَطْعَمَ قُلْنَا نَعَمْ قَالَ أَخْبِرُونِي عَنْ النَّبِيِّ هَلْ بُعِثَ قُلْنَا نَعَمْ قَالَ أَخْبِرُونِي كَيْفَ النَّاسُ إِلَيْهِ قُلْنَا سِرَاعٌ قَالَ فَنَزَّى نَزْوَةً حَتَّى كَادَ قُلْنَا فَمَا أَنْتَ قَالَ أَنَا الدَّجَّالُ وَإِنَّهُ يَدْخُلُ الْأَمْصَارَ كُلَّهَا إِلَّا طَيْبَةَ وَطَيْبَةُ الْمَدِينَةُقَالَ أَبُو عِيسَى وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ حَدِيثِ قَتَادَةَ عَنْ الشَّعْبِيِّ وَقَدْ رَوَاهُ غَيْرُ وَاحِدٍ عَنْ الشَّعْبِيِّ عَنْ فَاطِمَةَ بِنْتِ قَيْسٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Mu'adz bin Hisyam] telah menceritakan kepada kami [ayahku] dari [Qatadah] dari [Asy Sya'bi] dari [Fathimah binti Qais], nabi Shallallahu 'alaihi wa Salam naik mimbar lalu beliau tertawa, setelah itu beliau bersabda: \" Tamim Ad Dari menceritakan sesuatu padaku lalu aku gembira, karena itu aku ingin menceritakan kisahku pada kalian; beberapa orang dari penduduk Palestina naik perahu di laut lalu perahu itu membawa mereka berkeliling hingga menghempaskan mereka ke salah satu pulau di laut, ternyata ada sebuah binatang banyak mengenakan pakaian dan panjang rambutnya. Mereka bertanya: Apa kau ini? ia menjawab: Aku adalah pencari-cari khabar. Mereka berkata: Beritahulah kami. Binatang itu menjawab: Aku tidak akan memberitahu kalian dan aku tidak akan bertanya kepada kalian, tapi pergilah ke ujung kampung, di sana akan ada yang memberitahu kalian dan bertanya pada kalian. Kami mendatangi ujung kampung, ternyata disana ada seseorang yang tengah dirantai. Orang itu bertanya: Beritahukan padaku tentang mata air Zughar. Kami berkata: Penuh dan memancar. Ia bertanya: Beritahukan padaku tentang danau. Kami berkata: Penuh dan memancar. Ia bertanya: Beritahukan padaku tentang kurma Baisan yang ada di antara Urdun dan Palestina, apakah sudah berbuah? Kami menjawab: Ya. Ia bertanya: Beritahukan padaku tentang nabi Shallallahu 'alaihi wa Salam, apakah sudah diutus? Kami menjawab: Ya. Ia bertanya: Beritahukan padaku bagaimana orang-orang mendatanginya? Kami menjawab: Cepat. Lalu ia meloncat hingga kami hampir bertanya: Siapa kamu? Ia menjawab: Aku Dajjal. Ia memasuki seluruh daerah kecuali Thaibah dan Thaibah adalah Madinah. Berkata Abu Isa: hadits ini hasan shahih gharib dari hadits Qatadah dari Sya'bi. Diriwayatkan oleh beberapa perawi dari Asy Sya'bi dari Fathimah binti Qais."},"2180":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ حَاتِمٍ الْمُكْتِبُ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الْأَنْصَارِيُّ حَدَّثَنَا حُمَيْدٌ الطَّوِيلُ عَنْ أَنَسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ انْصُرْ أَخَاكَ ظَالِمًا أَوْ مَظْلُومًا قُلْنَا يَا رَسُولَ اللَّهِ نَصَرْتُهُ مَظْلُومًا فَكَيْفَ أَنْصُرُهُ ظَالِمًا قَالَ تَكُفُّهُ عَنْ الظُّلْمِ فَذَاكَ نَصْرُكَ إِيَّاهُقَالَ وَفِي الْبَاب عَنْ عَائِشَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Hatim Al Muktib] telah menceritakan kepada kami [Muhammad bin Abdullah Al Anshari] telah menceritakan kepada kami [Humaid Ath Thawil] dari [Anas] dari nabi Shallallahu 'alaihi wa Salam bersabda: \"Tolonglah saudaramu yang berbuat lalim dan yang diperlakukan lalim.\" Kami berkata: Wahai Rasulullah, aku menolongnya bila diperlakukan lalim, lalu bagaimana aku menolongnya bila berbuat lalim? Beliau menjawab: \"Kau mencegahnya dari perbuatan lalim, itulah pertolonganmu untuknya.\" Berkata Abu Isa: Dalam hal ini ada hadits serupa dari 'A`isyah. Berkata Abu Isa: Hadits ini hasan shahih."},"2181":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي مُوسَى عَنْ وَهْبِ بْنِ مُنَبِّهٍ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ سَكَنَ الْبَادِيَةَ جَفَا وَمَنْ اتَّبَعَ الصَّيْدَ غَفَلَ وَمَنْ أَتَى أَبْوَابَ السُّلْطَانِ افْتَتَنَقَالَ وَفِي الْبَاب عَنْ أَبَي هُرَيْرَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ حَدِيثَ ابْنِ عَبَّاسٍ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ الثَّوْرِيِّ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Sufyan] dari [Abu Musa] dari [Wahab bin Munabbih] dari [Ibnu 'Abbas] dari nabi Shallallahu 'alaihi wa Salam bersabda: \"Barangsiapa tinggal dipedalaman akan keras (wataknya, pent.), Barangsiapa mengikuti buruan, dia akan lalai dan Barangsiapa mendatangi pintu-pintu penguasa akan terkena fitnah.\" Berkata Abu Isa: Dalam hal ini ada hadits serupa dari Abu Hurairah. Berkata Abu Isa: Hadits ini hasan shahih gharib dari hadits Ibnu 'Abbas, kami hanya mengetahuinya dari hadits Ats Tsauri."},"2182":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ أَنْبَأَنَا شُعْبَةُ عَنْ سِمَاكِ بْنِ حَرْبٍ قَال سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ يُحَدِّثُ عَنْ أَبِيهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّكُمْ مَنْصُورُونَ وَمُصِيبُونَ وَمَفْتُوحٌ لَكُمْ فَمَنْ أَدْرَكَ ذَلِكَ مِنْكُمْ فَلْيَتَّقِ اللَّهَ وَلْيَأْمُرْ بِالْمَعْرُوفِ وَلْيَنْهَ عَنْ الْمُنْكَرِ وَمَنْ كَذَبَ عَلَيَّ مُتَعَمِّدًا فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنْ النَّارِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah bacteria kepada kami [Mahmud bin Ghailan] telah bacteria kepada kami [Abu Dawud] telah memberitakan kepada kami [Syu'bah] dari [Simak bin Harb] berkata: Aku mendengar [Abdurrahman bin Abdullah bin Mas'ud] bercerita dari [ayahnya] berkata: Aku mendengar Rasulullah Shallallahu 'alaihi wa salam bersabda: \"kalian akan mendapatkan kemenangan, keberuntungan, dan penaklukan-penaklukan, maka barangsiapa diantara kalian memperoleh hal itu, hendaklah bertakwa kepada Allah, dan hendaklah memerintahkan kebaikan dan mencegah kemungkaran, barangsiapa berdusta atas namaku dengan sengaja, hendaklah menyiapkan tempatnya di neraka.\" Berkata Abu Isa: Hadits ini hasan shahih."},"2183":{"ar":"حَدَّثَنَا هَارُونُ بْنُ إِسْحَقَ الْهَمْدَانِيُّ حَدَّثَنِي مُحَمَّدُ بْنُ عَبْدِ الْوَهَّابِ عَنْ مِسْعَرٍ عَنْ أَبِي حَصِينٍ عَنْ الشَّعْبِيِّ عَنْ عَاصِمٍ الْعَدَوِيِّ عَنْ كَعْبِ بْنِ عُجْرَةَ قَالَخَرَجَ إِلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ تِسْعَةٌ خَمْسَةٌ وَأَرْبَعَةٌ أَحَدُ الْعَدَدَيْنِ مِنْ الْعَرَبِ وَالْآخَرُ مِنْ الْعَجَمِ فَقَالَ اسْمَعُوا هَلْ سَمِعْتُمْ أَنَّهُ سَيَكُونُ بَعْدِي أُمَرَاءُ فَمَنْ دَخَلَ عَلَيْهِمْ فَصَدَّقَهُمْ بِكَذِبِهِمْ وَأَعَانَهُمْ عَلَى ظُلْمِهِمْ فَلَيْسَ مِنِّي وَلَسْتُ مِنْهُ وَلَيْسَ بِوَارِدٍ عَلَيَّ الْحَوْضَ وَمَنْ لَمْ يَدْخُلْ عَلَيْهِمْ وَلَمْ يُعِنْهُمْ عَلَى ظُلْمِهِمْ وَلَمْ يُصَدِّقْهُمْ بِكَذِبِهِمْ فَهُوَ مِنِّي وَأَنَا مِنْهُ وَهُوَ وَارِدٌ عَلَيَّ الْحَوْضَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ صَحِيحٌ غَرِيبٌ لَا نَعْرِفُهُ مِنْ حَدِيثِ مِسْعَرٍ إِلَّا مِنْ هَذَا الْوَجْهِ قَالَ هَارُونُ فَحَدَّثَنِي مُحَمَّدُ بْنُ عَبْدِ الْوَهَّابِ عَنْ سُفْيَانَ عَنْ أَبِي حَصِينٍ عَنْ الشَّعْبِيِّ عَنْ عَاصِمٍ الْعَدَوِيِّ عَنْ كَعْبِ بْنِ عُجْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ قَالَ هَارُونُ وَحَدَّثَنِي مُحَمَّدٌ عَنْ سُفْيَانَ عَنْ زُبَيْدٍ عَنْ إِبْرَاهِيمَ وَلَيْسَ بِالنَّخَعِيِّ عَنْ كَعْبِ بْنِ عُجْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ حَدِيثِ مِسْعَرٍ قَالَ وَفِي الْبَاب عَنْ حُذَيْفَةَ وَابْنِ عُمَرَ","id":"Telah menceritakan kepada kami [Harun bin Ishaq Al Hamdani] telah menceritakan kepadaku [Muhammad bin 'Abdul Wahhab] dari [Mis'ar] dari [Abu Hushain] dari [Asy Sya'bi] dari ['Ashim Al 'Adawi] dari [Ka'ab bin 'Ujrah] berkata: Rasulullah Shallallahu 'alahi wa Salam menghampiri kami, kami berjumlah sembilan lima dan empat, salah satu bilangan dari arab sementara yang lain dari 'ajam, beliau bersabda: \"Dengarkan, apa kalian telah mendengar bahwa sepeninggalku nanti akan ada pemimpin-pemimpin, barangsiapa yang memasuki mereka lalu membenarkan kedustaan mereka serta menolong kelaliman mereka, ia tidak termasuk golonganku dan tidak akan mendatangi telagaku, barangsiapa tidak memasuki mereka, tidak membantu kelaliman mereka dan tidak membenarkan kedustaan mereka, ia termasuk golonganku, aku termasuk golongannya dan ia akan mendatangi telagaku.\" Berkata Abu Isa: Hadits ini shahih, gharib, kami hanya mengetahuinya dari hadits Mis'ar kecuali dari sanad ini. berkata [Harun] lalu [Muhammad bin 'Abdul Wahhab] menceritakan kepadaku dari [Sufyan] dari [Abu Hushain] dari [Asy Sya'bi] dari ['Ashim Al 'Adawi] dari [Ka'ab bin 'Ujrah] dari nabi Shallallahu 'alaihi wa Salam Sepertinya. Berkata [Harun] dan [Muhammad] menceritakan kepadaku dari [Sufyan] dari [Zubaid] dari [Ibrahim] bukan Ibrahim An Nakha'i dari [Ka'ab bin 'Ujrah] dari nabi Shallallahu 'alaihi wa Salam seperti hadits Mis'ar berkata: Dalam hal ini ada hadits serupa dari Hudzaifah dan Ibnu Umar."},"2184":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ مُوسَى الْفَزَارِيُّ ابْنُ بِنْتِ السُّدِّيِّ الْكُوفِيِّ حَدَّثَنَا عُمَرُ بْنُ شَاكِرٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْتِي عَلَى النَّاسِ زَمَانٌ الصَّابِرُ فِيهِمْ عَلَى دِينِهِ كَالْقَابِضِ عَلَى الْجَمْرِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَعُمَرُ بْنُ شَاكِرٍ شَيْخٌ بَصْرِيٌّ قَدْ رَوَى عَنْهُ غَيْرُ وَاحِدٍ مِنْ أَهْلِ الْعِلْمِ","id":"Telah menceritakan kepada kami [Isma'il bin Musa Al Fazari Ibnu binti As Suddi Al Kufi] telah bacteria kepada kami [Umar bin Syakir] dari [Anas bin Malik] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Akan datang kepada manusia suatu masa yang ketika itu orang yang sabar di atas agamanya seperti menggenggam bara api.\" Abu Isa berkata: Hadits ini gharib dari Jalur sanad ini, Umar bin Syakir adalah syeikh Bashrah, banyak ahlul ilmu meriwayatkan hadits darinya."},"2185":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا حُمَيْدٌ الطَّوِيلُ عَنْ الْحَسَنِ عَنْ أَبِي بَكْرَةَ قَالَعَصَمَنِي اللَّهُ بِشَيْءٍ سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا هَلَكَ كِسْرَى قَالَ مَنْ اسْتَخْلَفُوا قَالُوا ابْنَتَهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَنْ يُفْلِحَ قَوْمٌ وَلَّوْا أَمْرَهُمْ امْرَأَةً قَالَ فَلَمَّا قَدِمَتْ عَائِشَةُ يَعْنِي الْبَصْرَةَ ذَكَرْتُ قَوْلَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَصَمَنِي اللَّهُ بِهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Khalid bin Al Harits] telah menceritakan kepada kami [Humaid Ath Thawil] dari [Al Hasan] dari [Abu Bakrah] berkata: Allah menjagaku dengan sesuatu yang aku dengar dari Rasulullah Shallallahu 'alahi wa Salam saat Kisra mati, beliau bersabda: \"Siapa yang menjadi penggantinya?\" mereka menjawab: Putrinya, nabi Shallallahu 'alaihi wa Salam bersabda: \"Tidak akan beruntung suatu kaum yang menguasakan urusan mereka kepada seorang wanita.\" Berkata Abu Bakrah: Saat 'A`isyah tiba di Bashrah, aku sebutkan sabda Rasulullah Shallallahu 'alahi wa Salam lalu Allah Subhaanahu wa Ta'ala menjagaku dengan sabda itu. Berkata Abu Isa: Hadits ini hasan shahih."},"2186":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَفَ عَلَى أُنَاسٍ جُلُوسٍ فَقَالَ أَلَا أُخْبِرُكُمْ بِخَيْرِكُمْ مِنْ شَرِّكُمْ قَالَ فَسَكَتُوا فَقَالَ ذَلِكَ ثَلَاثَ مَرَّاتٍ فَقَالَ رَجُلٌ بَلَى يَا رَسُولَ اللَّهِ أَخْبِرْنَا بِخَيْرِنَا مِنْ شَرِّنَا قَالَ خَيْرُكُمْ مَنْ يُرْجَى خَيْرُهُ وَيُؤْمَنُ شَرُّهُ وَشَرُّكُمْ مَنْ لَا يُرْجَى خَيْرُهُ وَلَا يُؤْمَنُ شَرُّهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami ['Abdul 'Aziz bin Muhammad] dari [Al 'Alla` bin Abdurrahman] dari [bapaknya] dari [Abu Hurairah] Rasulullah Shallallahu 'alahi wa Salam berdiri di hadapan orang orang yang sedang duduk lalu beliau bersabda: \"Maukah kalian aku beritahu orang yang paling baik di antara kalian dari orang yang paling buruk di antara kalian?\" Abu Hurairah berkata: Para sahabat diam, beliau mengatakan demikian sampai tiga kali, kemudian salah seorang berkata: Ya, wahai Rasulullah, beritahukan kepada kami orang yang paling baik di antara kami dari orang yang paling buruk, beliau bersabda: \"Orang yang paling baik di antara kalian adalah orang yang diharapkan kebaikannya dan aman dari kejahatannya, dan orang yang paling buruk di antara kalian adalah orang yang tidak diharapkan kebaikannya dan tidak aman dari kejahatannya.\" Abu Isa berkata: Hadits ini hasan shahih."},"2187":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَامِرٍ الْعَقَدِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي حُمَيْدٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِيهِ عَنْ عُمَرَ بْنِ الخَطَّابِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَلَا أُخْبِرُكُمْ بِخِيَارِ أُمَرَائِكُمْ وَشِرَارِهِمْ خِيَارُهُمْ الَّذِينَ تُحِبُّونَهُمْ وَيُحِبُّونَكُمْ وَتَدْعُونَ لَهُمْ وَيَدْعُونَ لَكُمْ وَشِرَارُ أُمَرَائِكُمْ الَّذِينَ تُبْغِضُونَهُمْ وَيُبْغِضُونَكُمْ وَتَلْعَنُونَهُمْ وَيَلْعَنُونَكُمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ مُحَمَّدِ بْنِ أَبِي حُمَيْدٍ وَمُحَمَّدٌ يُضَعَّفُ مِنْ قِبَلِ حِفْظِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abu Amir Al Aqadi] telah menceritakan kepada kami [Muhammad bin Abu Humaid] dari [Zaid bin Aslam] dari [bapaknya] dari [Umar bin Al Khaththab] dari Nabi Shallallahu 'alaihi wa Salam bersabda: \"Maukah kalian aku beritahu pemimpin kalian yang terbaik dan pemimpin kalian yang terburuk? pemimpin yang terbaik adalah mereka yang kalian cintai dan mereka mencintai kalian, kalian mendoakan kebaikan kepada mereka dan mereka mendoakan kebaikan kepada kalian, sedangkan pemimpin kalian yang terburuk adalah mereka yang kalian benci dan merekapun membenci kalian, kalian melaknat mereka dan merekapun melaknat kalian.\" Abu Isa berkata: Hadits ini gharib, kami tidak mengetahuinya kecuali dari hadits Muhammad bin Abu Humaid, sedangkan Muhammad dilemahkan dari sisi hafalannya."},"2188":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الْوَهَّابِ الثَّقَفِيُّ حَدَّثَنَا أَيُّوبُ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اقْتَرَبَ الزَّمَانُ لَمْ تَكَدْ رُؤْيَا الْمُؤْمِنِ تَكْذِبُ وَأَصْدَقُهُمْ رُؤْيَا أَصْدَقُهُمْ حَدِيثًا وَرُؤْيَا الْمُسْلِمِ جُزْءٌ مِنْ سِتَّةٍ وَأَرْبَعِينَ جُزْءًا مِنْ النُّبُوَّةِ وَالرُّؤْيَا ثَلَاثٌ فَالرُّؤْيَا الصَّالِحَةُ بُشْرَى مِنْ اللَّهِ وَالرُّؤْيَا مِنْ تَحْزِينِ الشَّيْطَانِ وَالرُّؤْيَا مِمَّا يُحَدِّثُ بِهَا الرَّجُلُ نَفْسَهُ فَإِذَا رَأَى أَحَدُكُمْ مَا يَكْرَهُ فَلْيَقُمْ فَلْيَتْفُلْ وَلَا يُحَدِّثْ بِهَا النَّاسَ قَالَ وَأُحِبُّ الْقَيْدَ فِي النَّوْمِ وَأَكْرَهُ الْغُلَّ الْقَيْدُ ثَبَاتٌ فِي الدِّينِقَالَ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Nashr bin 'Ali] telah menceritakan kepada kami ['Abdul Wahhab Ats Tsaqafi] telah menceritakan kepada kami [Ayyub] dari [Muhammad bin Sirin] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Bila waktu sudah terasa ringkas, hampir mimpi mu`min bukanlah bohong, dan mimpi mereka yang paling benar adalah yang paling benar kata-katanya dan mimpi muslim adalah satu dari empatpuluh enam bagian kenabian, mimpi itu ada tiga; mimpi yang baik adalah khabar gembira dari Allah, mimpi dari kesedihan yang dibuat setan dan mimpi yang dibisikkan oleh jiwa seseorang, bila salah seorang dari kalian bermimpi sesuatu yang tidak ia suka, hendaklah meludah dan tidak memberitahukannya kepada orang-orang.\" Beliau bersabda: \"Aku suka ikatan dalam tidur dan aku tidak suka pengkhianatan, ikatan itu adalah teguh dalam agama.\" Berkata Abu Isa: Hadits hasan shahih."},"2189":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ عَنْ شُعْبَةَ عَنْ قَتَادَةَ أَنَّهُ سَمِعَ أَنَسًا يُحَدِّثُ عَنْ عُبَادَةَ بْنِ الصَّامِتِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رُؤْيَا الْمُؤْمِنِ جُزْءٌ مِنْ سِتَّةٍ وَأَرْبَعِينَ جُزْءًا مِنْ النُّبُوَّةِقَالَ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَأَبِي رَزِينٍ الْعُقَيْلِيِّ وَأَبِي سَعِيدٍ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو وَعَوْفِ بْنِ مَالِكٍ وَابْنِ عُمَرَ وَأَنَسٍ قَالَ وَحَدِيثُ عُبَادَةَ حَدِيثٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Daud] dari [Syu'bah] dari [Qatadah] dia telah mendengar [Anas] menceritakan dari ['Ubadah bin Ash Shamith] bahwa nabi Shallallahu 'alaihi wa Salam bersabda: Mimpi seorang mukmin adalah satu dari empat puluh enam bagian kenabian.\" Berkata Abu Isa: Dan dalam bab ini ada hadits dari Abu Hurairah, Abu Razin Al 'Uqaili, Abu sa'id, Abdullah bin 'Amru, 'Auf bin Malik, Ibnu Umar dan Anas. Berkata Abu Isa: Hadits Ubadah adalah hadits shahih."},"2190":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ مُحَمَّدٍ الزَّعْفَرَانِيُّ حَدَّثَنَا عَفَّانُ بْنُ مُسْلِمٍ حَدَّثَنَا عَبْدُ الْوَاحِدِ يَعْنِي ابْنَ زيَادٍ حَدَّثَنَا الْمُخْتَارُ بْنُ فُلْفُلٍ حَدَّثَنَا أَنَسُ بْنُ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الرِّسَالَةَ وَالنُّبُوَّةَ قَدْ انْقَطَعَتْ فَلَا رَسُولَ بَعْدِي وَلَا نَبِيَّ قَالَ فَشَقَّ ذَلِكَ عَلَى النَّاسِ فَقَالَ لَكِنْ الْمُبَشِّرَاتُ قَالُوا يَا رَسُولَ اللَّهِ وَمَا الْمُبَشِّرَاتُ قَالَ رُؤْيَا الْمُسْلِمِ وَهِيَ جُزْءٌ مِنْ أَجْزَاءِ النُّبُوَّةِوَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَحُذَيْفَةَ بْنِ أَسِيدٍ وَابْنِ عَبَّاسٍ وَأُمِّ كُرْزٍ وَأَبِي أَسِيدٍ قَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ مِنْ حَدِيثِ الْمُخْتَارِ بْنِ فُلْفُلٍ","id":"Telah menceritakan kepada kami [Al Hasan bin Muhammad Az Za'farani] telah menceritakan kepada kami ['Affan bin Muslim] telah menceritakan kepada kami ['Abdul Wahid bin Ziyad] telah menceritakan kepada kami [Al Mukhtar bin Fulful] bahwa [Anas bin Malik] telah menceritakan kepada kami, dia berkata bahwa Rasulullah Shallallahu 'alaihi wa salam bersabda: \" risalah dan kenabian telah terputus, maka tidak ada rasul dan nabi setelahku.\" Anas berkata: Hal itu memberatkan orang-orang, lalu beliau bersabda: \"Akan tetapi yang ada adalah mubasyyirat\" para sahabat bertanya: Apa yang dimaksud mubasyirat wahai Rosulullah? beliau menjawab: \"Mimpi seorang muslim adalah salah satu dari sekian bagian kenabian.\" Dan dalam bab ini ada hadits dari Abu Hurairah, Hudzaifah bin Asid, Ibnu 'Abbas, Ummu Kurz dan Abu Sa'id, Abu Isa berkata: Hadits ini hasan shahih gharib dari jalur sanad ini dari hadits Al Mukhtar bin Fulful."},"2191":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ رَجُلٍ مِنْ أَهْلِ مِصْرَ قَالَ سَأَلْتُ أَبَا الدَّرْدَاءِعَنْ قَوْلِ اللَّهِ تَعَالَى{ لَهُمْ الْبُشْرَى فِي الْحَيَاةِ الدُّنْيَا }فَقَالَ مَا سَأَلَنِي عَنْهَا أَحَدٌ غَيْرُكَ إِلَّا رَجُلٌ وَاحِدٌ مُنْذُ سَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا سَأَلَنِي عَنْهَا أَحَدٌ غَيْرُكَ مُنْذُ أُنْزِلَتْ هِيَ الرُّؤْيَا الصَّالِحَةُ يَرَاهَا الْمُسْلِمُ أَوْ تُرَى لَهُقَالَ وَفِي الْبَاب عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَ هَذَا حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Ibnu Abi Umar] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami dari [Muhammad bin Al Munkadir] dari ['Atho` bin Yasar] dari [seorang penduduk mesir] dia berkata: Aku bertanya kepada [Abu Darda'] tentang firman Allah Ta'ala \"Bagi mereka berita gembira di dalam kehidupan di dunia.\" (Yuunus: 64) dia menjawab: Tidak ada seorang pun yang bertanya tentang ayat ini kepadaku selain kamu, dan kecuali satu orang sejak aku bertanya kepada Rasulullah Shallallahu 'alahi wa Salam, beliau bersabda: \"Tidak ada seorangpun yang bertanya tentang ayat ini kepadaku sejak dia diturunkan\" maksudnya adalah mimpi yang benar yang dilihat seorang muslim atau diperlihatkan kepadanya. Berkata Abu Isa: Dan dalam bab ini ada hadits dari 'Ubadah bin Ash Shamith. Berkata Abu Isa: Hadits ini hasan."},"2192":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ دَرَّاجٍ عَنْ أَبِي الْهَيْثَمِ عَنْ أَبِي سَعِيدٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَصْدَقُ الرُّؤْيَا بِالْأَسْحَارِ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Darraj] dari [Abu Al Haitsam] dari [Abu Sa'id] dari nabi Shallallahu 'alaihi wa Salam bersabda: \"Mimpi yang paling benar adalah (mimpi) diwaktu sahur.\""},"2193":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا حَرْبُ بْنُ شَدَّادٍ وَعِمْرَانُ الْقَطَّانُ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ قَالَ نُبِّئْتُ عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ قَوْلِهِ{ لَهُمْ الْبُشْرَى فِي الْحَيَاةِ الدُّنْيَا }قَالَ هِيَ الرُّؤْيَا الصَّالِحَةُ يَرَاهَا الْمُؤْمِنُ أَوْ تُرَى لَهُقَالَ حَرْبٌ فِي حَدِيثِهِ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abu Dawud] telah menceritakan kepada kami [Harb bin Syaddad] dan ['Imran bin Al Qaththan] dari [Yahya bin Abu Katsir] dari [Abu Salamah] berkata: Saya telah diberitahu dari ['Ubadah bin Ash Shamit] berkata: Aku bertanya kepada Rasulullah Shallallahu 'alahi wa Salam tentang firmanNya: \"Bagi mereka berita gembira di dalam kehidupan di dunia.\" (Yuunus: 64) Rasulullah Shallallahu 'alahi wa Salam menjawab: \"Itu adalah mimpi yang baik yang dilihat seorang mu`min atau diperlihatkan kepadanya.\" Berkata Harb dalam haditsnya; telah menceritakan kepadaku Yahya bin Abu Katsir Berkata Abu Isa: Hadits ini hasan."},"2194":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ رَآنِي فِي الْمَنَامِ فَقَدْ رَآنِي فَإِنَّ الشَّيْطَانَ لَا يَتَمَثَّلُ بِيقَالَ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَأَبِي قَتَادَةَ وَابْنِ عَبَّاسٍ وَأَبِي سَعِيدٍ وَجَابِرٍ وَأَنَسٍ وَأَبِي مَالِكٍ الْأَشْجَعِيِّ عَنْ أَبِيهِ وَأَبِي بَكْرَةَ وَأَبِي جُحَيْفَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq] dari [Abu Al Ahwash] dari ['Abdullah] dari nabi Shallallahu 'alaihi wa Salam bersabda: \"Barangsiapa bermimpi melihatku berarti ia benar-benar melihatku karena setan tidak bisa menyerupaiku.\" Berkata Abu Isa: Dalam hal ini ada hadits serupa dari Abu Hurairah, Abu Qatadah, Ibnu 'Abbas, Abu Sa'id, Jabir, Anas, Abu Malik Al Asyja'I dari ayahnya, Abu Bakrah, Aub Juhaifah. Berkata Abu Isa: Hadits ini hasan shahih."},"2195":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي قَتَادَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ الرُّؤْيَا مِنْ اللَّهِ وَالْحُلْمُ مِنْ الشَّيْطَانِ فَإِذَا رَأَى أَحَدُكُمْ شَيْئًا يَكْرَهُهُ فَلْيَنْفُثْ عَنْ يَسَارِهِ ثَلَاثَ مَرَّاتٍ وَلْيَسْتَعِذْ بِاللَّهِ مِنْ شَرِّهَا فَإِنَّهَا لَا تَضُرُّهُقَالَ وَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو وَأَبِي سَعِيدٍ وَجَابِرٍ وَأَنَسٍ قَالَ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari [Yahya bin Sa'id] dari [Abu Salamah bin Abdurrahman] dari [Abu Qatadah] dari Rasulullah Shallallahu 'alahi wa Salam, beliau bersabda: \"Mimpi (baik) itu dari Allah dan mimpi (buruk) itu dari setan, bila salah seorang dari kalian bermimpi sesuatu yang tidak ia suka, hendaklah meludah ke kiri tiga kali dan hendaklah berlindung diri kepada Allah dari keburukannya, karena ia tidak membahayakannya.\" Berkata Abu Isa: Dalam hal ini ada hadits serupa dari 'Abdullah bin 'Amru, Abu Sa'id, Jabir dan Anas. Berkata Abu Isa: Hadits ini hasan shahih."},"2196":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ أَنْبَأَنَا شُعْبَةُ قَالَ أَخْبَرَنِي يَعْلَى بْنُ عَطَاءٍ قَال سَمِعْتُ وَكِيعَ بْنَ عُدُسٍ عَنْ أَبِي رَزِينٍ الْعُقَيْلِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رُؤْيَا الْمُؤْمِنِ جُزْءٌ مِنْ أَرْبَعِينَ جُزْءًا مِنْ النُّبُوَّةِ وَهِيَ عَلَى رِجْلِ طَائِرٍ مَا لَمْ يَتَحَدَّثْ بِهَا فَإِذَا تَحَدَّثَ بِهَا سَقَطَتْ قَالَ وَأَحْسَبُهُ قَالَ وَلَا يُحَدِّثُ بِهَا إِلَّا لَبِيبًا أَوْ حَبِيبًا","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Dawud] berkata: telah memberitakan kepada kami [Syu'bah] berkata: telah mengkhabarkan kepadaku [Ya'la bin 'Atho`] berkata: Aku mendengar [Waki' bin 'Udus] dari [Abu Razin Al 'Uqaili] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Mimpi seorang mu`min adalah satu dari empatpuluh bagian kenabian dan ia berada diatas kaki burung selama ia tidak diceritakan, bila diceritakan ia jatuh.\" Berkata Abu Razin: Aku kira beliau bersabda: \"Dan tidak diceritakan kecuali kepada orang cerdas atau terkasih.\""},"2197":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا شُعْبَةُ عَنْ يَعْلَى بْنِ عَطَاءٍ عَنْ وَكِيعِ بْنِ عُدُسٍ عَنْ عَمِّهِ أَبِي رَزِينٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رُؤْيَا الْمُسْلِمِ جُزْءٌ مِنْ سِتَّةٍ وَأَرْبَعِينَ جُزْءًا مِنْ النُّبُوَّةِ وَهِيَ عَلَى رِجْلِ طَائِرٍ مَا لَمْ يُحَدِّثْ بِهَا فَإِذَا حَدَّثَ بِهَا وَقَعَتْقَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَأَبُو رَزِينٍ الْعُقَيْلِيُّ اسْمُهُ لَقِيطُ بْنُ عَامِرٍ وَرَوَى حَمَّادُ بْنُ سَلَمَةَ عَنْ يَعْلَى بْنِ عَطَاءٍ فَقَالَ عَنْ وَكِيعِ بْنِ حُدُسٍ و قَالَ شُعْبَةُ وَأَبُو عَوَانَةَ وَهُشَيْمٌ عَنْ يَعْلَى بْنِ عَطَاءٍ عَنْ وَكِيعِ بْنِ عُدُسٍ وَهَذَا أَصَحُّ","id":"Telah menceritakan kepada kami [Al Hasan bin 'Ali Al Khallal] telah menceritakan kepada kami [Yazid bin Harun] telah mengkhabarkan kepada kami [Syu'bah] dari [Ya'la bin 'Atho`] dari [Waki' bin 'Udus] dari pamannya, [Abu Razin], dari nabi Shallallahu 'alaihi wa Salam bersabda: \"Mimpi seorang muslim adalah satu dari empatpuluh enam bagian kenabian, ia berada di kaki burung selama tidak diceritakan, bila diceritakan ia jatuh.\" Berkata Abu Isa: Hadits ini hasan shahih, Abu Razin Al 'Uqaili namanya Laqith bin 'Amir. [Hammad bin Salamah] meriwayatkan dari [Ya'la bin 'Atho`] lalu berkata: dari [Waki' bin Hudus], berkata [Syu'bah], [Abu 'Awanah] dan [Husyaim] dari [Ya'la bin 'Atho`] dari [Waki' bin 'Udus] dan ini lebih shahih. "},"2198":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ أَبِي عُبَيْدِ اللَّهِ السَّلِيمِيُّ الْبَصْرِيُّ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الرُّؤْيَا ثَلَاثٌ فَرُؤْيَا حَقٌّ وَرُؤْيَا يُحَدِّثُ بِهَا الرَّجُلُ نَفْسَهُ وَرُؤْيَا تَحْزِينٌ مِنْ الشَّيْطَانِ فَمَنْ رَأَى مَا يَكْرَهُ فَلْيَقُمْ فَلْيُصَلِّ وَكَانَ يَقُولُ يُعْجِبُنِي الْقَيْدُ وَأَكْرَهُ الْغُلَّ الْقَيْدُ ثَبَاتٌ فِي الدِّينِ وَكَانَ يَقُولُ مَنْ رَآنِي فَإِنِّي أَنَا هُوَ فَإِنَّهُ لَيْسَ لِلشَّيْطَانِ أَنْ يَتَمَثَّلَ بِي وَكَانَ يَقُولُ لَا تُقَصُّ الرُّؤْيَا إِلَّا عَلَى عَالِمٍ أَوْ نَاصِحٍوَفِي الْبَاب عَنْ أَنَسٍ وَأَبِي بَكْرَةَ وَأُمِّ الْعَلَاءِ وَابْنِ عُمَرَ وَعَائِشَةَ وَأَبِي مُوسَى وَجَابِرٍ وَأَبِي سَعِيدٍ وَابْنِ عَبَّاسٍ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ahmad bin Abu 'Ubaidillah As Salimi Al Bashri] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Muhammad bin Sirin] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Mimpi itu ada tiga; mimpi yang benar, mimpi yang dibisikkan oleh jiwa seseorang, dan mimpi dari kesedihan yang dibuat setan, bila salah seorang dari kalian bermimpi sesuatu yang tidak ia suka, hendaklah bangun lalu shalat.\" Beliau bersabda: \"Aku suka mimpi diikat tali dan aku tidak suka bermimpi kedua tanganku terikat ditengkuk, sebab terikat tali itu maknanya teguh dalam agama.\" Beliau bersabda: \"Barangsiapa bermimpi melihaku berarti ia benar-benar melihatku karena sesungguhnya setan tidak bisa menyerupaiku.\" Beliau bersabda: \"Jangan menceritakan mimpi kecuali kepada orang 'alim atau penasehat.\" Dalam hal ini ada hadits serupa dari Anas, Abu Bakrah, Ummu Al 'Alla`, Ibnu 'Umar, 'A`isyah, Abu Musa, Jabir, Abu Sa'id, Ibnu 'Abbas, 'Abdullah bin 'Amru. Berkata Abu Isa: Hadits ini hasan shahih."},"2199":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو أَحْمَدَ الزُّبَيْرِيُّ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الْأَعْلَى عَنْ أَبِي عَبْدِ الرَّحْمَنِ السُّلَمِيِّ عَنْ عَلِيٍّ قَالَأُرَاهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ كَذَبَ فِي حُلْمِهِ كُلِّفَ يَوْمَ الْقِيَامَةِ عَقْدَ شَعِيرَةٍحَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ عَبْدِ الْأَعْلَى عَنْ أَبِي عَبْدِ الرَّحْمَنِ السُّلَمِيِّ عَنْ عَلِيٍّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ قَالَ هَذَا حَدِيثٌ حَسَنٌ وَفِي الْبَاب عَنْ ابْنِ عَبَّاسٍ وَأَبِي هُرَيْرَةَ وَأَبِي شُرَيْحٍ وَوَاثِلَةَ قَالَ أَبُو عِيسَى وَهَذَا أَصَحُّ مِنْ الْحَدِيثِ الْأَوَّلِ","id":"Telah menceritakan kepada kami [Mahmaud bin Ghailan] telah menceritakan kepada kami [Abu Ahmad Az Zubairi] telah menceritakan kepada kami [Sufyan] dari ['Abdul A'la] dari [Abu Abdurrahman As Sulami] dari ['Ali] berkata: Menurutku dari nabi Shallallahu 'alaihi wa Salam, beliau bersabda: \"Barangsiapa berdusta dalam mimpinya, pada hari kiamat dia diperintahkan untuk menyatukan bubuk tepung.\" Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abu 'Awanah] dari ['Abdul A'la] dari [Abu Abdurrahman As Sulami] dari ['Ali] dari nabi Shallallahu 'alaihi wa Salam Sepertinya. Berkata Abu Isa: Hadits ini hasan. Dalam hal ini ada hadits serupa dari Ibnu 'Abbas, Abu Hurairah, Abu Syuraih dan Watsilah. Berkata Abu Isa: Dan hadits ini lebih shahih dari hadits yang pertama."},"2200":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا أَيُّوبُ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ تَحَلَّمَ كَاذِبًا كُلِّفَ يَوْمَ الْقِيَامَةِ أَنْ يَعْقِدَ بَيْنَ شَعِيرَتَيْنِ وَلَنْ يَعْقِدَ بَيْنَهُمَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami ['Abdul Wahhab] telah menceritakan kepada kami [Ayyub] dari ['Ikrimah] dari [Ibnu 'Abbas] dari nabi Shallallahu 'alaihi wa Salam bersabda: \"Barangsiapa mengaku-aku mimpi dengan dusta, para hari kiamat ia dipaksa untuk menyatukan dua bubuk tepung dan ia tidak akan bisa menyatukan antara keduanya.\" Berkata Abu Isa: Hadits ini hasan shahih."},"2201":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ الزُّهْرِيِّ عَنْ حَمْزَةَ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ ابْنِ عُمَرَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ بَيْنَمَا أَنَا نَائِمٌ إِذْ أُتِيتُ بِقَدَحِ لَبَنٍ فَشَرِبْتُ مِنْهُ ثُمَّ أَعْطَيْتُ فَضْلِي عُمَرَ بْنَ الْخَطَّابِ قَالُوا فَمَا أَوَّلْتَهُ يَا رَسُولَ اللَّهِ قَالَ الْعِلْمَقَالَ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَأَبِي بَكْرَةَ وَابْنِ عَبَّاسٍ وَعَبْدِ اللَّهِ بْنِ سَلَامٍ وَخُزَيْمَةَ وَالطُّفَيْلِ بْنِ سَخْبَرَةَ وَأَبِي أُمَامَةَ وَجَابِرٍ قَالَ حَدِيثُ ابْنِ عُمَرَ حَدِيثٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Az Zuhri] dari [Hamzah bin 'Abdullah bin 'Umar] dari [Ibnu 'Umar] berkata: Aku mendengar Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Saat aku tidur, tiba-tiba aku diberi segelas susu, lalu aku meminumnya, setelah itu aku berikan lebihannya kepada 'Umar bin Al Khaththab.\" Mereka bertanya: Bagaimana baginda menafsirkannya, wahai Rasulullah? Rasulullah Shallallahu 'alahi wa Salam menjawab: \"Itulah ilmu.\" Berkata Abu Isa: Dalam hal ini ada hadits serupa dari Abu Hurairah, Abu Bakrah, Ibnu 'Abbas, 'Abdullah bin Salam, Khuzaimah, Ath Thufail bin Sakhirah, Abu Umamah dan Jabir. Berkata Abu Isa: Hadits Ibnu Umar adalah hadits shahih."},"2202":{"ar":"حَدَّثَنَا الْحُسَيْنُ بْنُ مُحمَّدٍ الْحَرِيرِيُّ الْبَلْخِيُّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ أَبِي أُمَامَةَ بْنِ سَهْلِ بْنِ حُنَيْفٍ عَنْ بَعْضِ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَيْنَمَا أَنَا نَائِمٌ رَأَيْتُ النَّاسَ يُعْرَضُونَ عَلَيَّ وَعَلَيْهِمْ قُمُصٌ مِنْهَا مَا يَبْلُغُ الثُّدِيَّ وَمِنْهَا مَا يَبْلُغُ أَسْفَلَ مِنْ ذَلِكَ فَعُرِضَ عَلَيَّ عُمَرُ وَعَلَيْهِ قَمِيصٌ يَجُرُّهُ قَالُوا فَمَا أَوَّلْتَهُ يَا رَسُولَ اللَّهِ قَالَ الدِّينَحَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ بْنِ سَعْدٍ عَنْ أَبِيهِ عَنْ صَالِحِ بْنِ كَيْسَانَ عَنْ الزُّهْرِيِّ عَنْ أَبِي أُمَامَةَ بْنِ سَهْلِ بْنِ حُنَيْفٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ بِمَعْنَاهُ قَالَ وَهَذَا أَصَحُّ","id":"Telah menceritakan kepada kami [Al Husain bin Muhammad Al Hariri Al balkhi] telah menceritakan kepada kami ['Abdur Razzaq] dari [Ma'mar] dari [Az Zuhri] dari [Abu Umamah bin Sahal bin Hunaif] dari [sebagaian sahabat nabi Shallallahu 'alaihi wa Salam], nabi Shallallahu 'alaihi wa Salam bersabda: \"Saat aku tidur, aku memimpikan orang-orang didatangkan kepadaku, mereka mengenakan pakaian ada yang sampai dada, ada yang sampai sebawahnya, lalu 'Umar didatangkan kepada, ia mengenakan pakaian yang ia seret.\" Mereka bertanya: Bagaimana baginda menafsirkannya, wahai Rasulullah? Rasulullah Shallallahu 'alahi wa Salam menjawab: \"Itulah agama.\" Telah menceritakan kepada kami ['Abdu bin Humaid] telah menceritakan kepada kami [Ya'qub bin Ibrahim bin Sa'ad] dari [ayahnya] dari [Shalih bin Kaisan] dari [Az Zuhri] dari [Abu Umamah bin Sahal bin Hunaif] dari [Abu Sa'id Al Khudri] dari nabi Shallallahu 'alaihi wa Salam semakna dengan hadits diatas dan berkata: Hadits ini lebih shahih."},"2203":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا الْأَنْصَارِيُّ حَدَّثَنَا أَشْعَثُ عَنْ الْحَسَنِ عَنْ أَبِي بَكْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ذَاتَ يَوْمٍ مَنْ رَأَى مِنْكُمْ رُؤْيَا فَقَالَ رَجُلٌ أَنَا رَأَيْتُ كَأَنَّ مِيزَانًا نَزَلَ مِنْ السَّمَاءِ فَوُزِنْتَ أَنْتَ وَأَبُو بَكْرٍ فَرَجَحْتَ أَنْتَ بِأَبِي بَكْرٍ وَوُزِنَ أَبُو بَكْرٍ وَعُمَرُ فَرَجَحَ أَبُو بَكْرٍ وَوُزِنَ عُمَرُ وَعُثْمَانُ فَرَجَحَ عُمَرُ ثُمَّ رُفِعَ الْمِيزَانُ فَرَأَيْنَا الْكَرَاهِيَةَ فِي وَجْهِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Al Anshari] telah menceritakan kepada kami [Asy'ats] dari [Al Hasan] dari [Abu Bakrah] bahwa pada suatu hari Nabi Shallallahu 'alaihi wa Salam bertanya: \"Siapa di antara kalian yang bermimpi?\" kemudian seseorang berkata: Saya bermimpi seakan akan timbangan turun dari langit, kemudian ditimbanglah engkau dan Abu Bakar maka timbangan engkau lebih berat dari Abu Bakar, kemudian ditimbanglah Abu Bakar dan Umar maka timbangan Abu Bakar lebih berat dari timbangan Umar, kemudian ditimbanglah Umar dan Utsman maka timbangan Umar lebih berat dari timbangan Utsman, lalu timbangan itu diangkat. Kami melihat ketidak sukaan dari wajah Rasulullah Shallallahu 'alahi wa Salam. Abu Isa berkata: Hadits ini hasan shahih."},"2204":{"ar":"حَدَّثَنَا أَبُو مُوسَى الْأَنْصَارِيُّ حَدَّثَنَا يُونُسُ بْنُ بُكَيْرٍ حَدَّثَنِي عُثْمَانُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ وَرَقَةَ فَقَالَتْ لَهُ خَدِيجَةُ إِنَّهُ كَانَ صَدَّقَكَ وَلَكِنَّهُ مَاتَ قَبْلَ أَنْ تَظْهَرَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُرِيتُهُ فِي الْمَنَامِ وَعَلَيْهِ ثِيَابٌ بَيَاضٌ وَلَوْ كَانَ مِنْ أَهْلِ النَّارِ لَكَانَ عَلَيْهِ لِبَاسٌ غَيْرُ ذَلِكَقَالَ هَذَا حَدِيثٌ غَرِيبٌ وَعُثْمَانُ بْنُ عَبْدِ الرَّحْمَنِ لَيْسَ عِنْدَ أَهْلِ الْحَدِيثِ بِالْقَوِيِّ","id":"Telah menceritakan kepada kami [Abu Musa Al Anshari] telah menceritakan kepada kami [Yunus bin Bukair] telah menceritakan kepadaku ['Utsman bin Abdurrahman] dari [Az Zuhri] dari ['Urwah] dari ['Aisyah] berkata: Rasulullah Shallallahu 'alahi wa Salam ditanya tentang Waraqah lalu Khadijah berkata pada beliau: Ia dulu membenarkanmu dan meninggal sebelum kau muncul. Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Ia diperlihatkan padaku dalam mimpiku, ia mengenakan baju putih, bila ia termasuk penghuni neraka pastilah ia mengenakan baju selainnya.\" Berkata Abu Isa: Hadits ini gharib dan 'Utsman bin Abdurrahman menurut ahli hadits tidak kuat."},"2205":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَاصِمٍ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي مُوسَى بْنُ عُقْبَةَ أَخْبَرَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَعَنْ رُؤْيَا النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبِي بَكْرٍ وَعُمَرَ قَالَ رَأَيْتُ النَّاسَ اجْتَمَعُوا فَنَزَعَ أَبُو بَكْرٍ ذَنُوبًا أَوْ ذَنُوبَيْنِ فِيهِ ضَعْفٌ وَاللَّهُ يَغْفِرُ لَهُ ثُمَّ قَامَ عُمَرُ فَنَزَعَ فَاسْتَحَالَتْ غَرْبًا فَلَمْ أَرَ عَبْقَرِيًّا يَفْرِي فَرْيَهُ حَتَّى ضَرَبَ النَّاسُ بِعَطَنٍقَالَ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَهَذَا حَدِيثٌ صَحِيحٌ غَرِيبٌ مِنْ حَدِيثِ ابْنِ عُمَرَ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Abu 'Ashim] telah mengkhabarkan kepada kami [Ibnu Juraij] telah mengkhabarkan kepadaku [Musa bin 'Uqbah] telah mengkhabarkan kepadaku [Salim bin 'Abdullah] dari ['Abdullah bin 'Umar] tentang mimpi nabi Shallallahu 'alaihi wa Salam, Abu Bakar dan 'Umar. Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Aku memimpikan orang-orang berkumpul lalu Abu Bakar menarik satu dua timba tapi ia lemah, dan Allah mengampuninya. Setelah itu 'Umar berdiri lalu menarik timba yang lebih besar, aku tidak pernah melihat orang besar yang rajin melakukan pekerjaan besarnya hingga orang-orang puas meminumi untanya.\" Berkata Abu Isa: Dalam hal ini ada hadits serupa dari Abu Hurairah dan hadits ini shahih gharib dari hadits Ibnu 'Umar."},"2206":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَاصِمٍ حَدَّثَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي مُوسَى بْنُ عُقْبَةَ أَخْبَرَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَعَنْ رُؤْيَا النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رَأَيْتُ امْرَأَةً سَوْدَاءَ ثَائِرَةَ الرَّأْسِ خَرَجَتْ مِنْ الْمَدِينَةِ حَتَّى قَامَتْ بِمَهْيَعَةَ وَهِيَ الْجُحْفَةُ وَأَوَّلْتُهَا وَبَاءَ الْمَدِينَةِ يُنْقَلُ إِلَى الْجُحْفَةِقَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Abu 'Ashim] telah menceritakan kepada kami [Ibnu Juraij] telah mengkhabarkan kepadaku [Musa bin 'Uqbah] telah mengkhabarkan kepadaku [Salim bin 'Abdullah] dari [Abdullah bin 'Umar] tentang mimpi nabi Shallallahu 'alaihi wa Salam, beliau bersabda: \"Aku memimpikan wanita hitam berambut panjang keluar dari Madinah hingga berdiri di Mahya'ah, yaitu Juhfah dan aku mengartikannya bencana atau penyakit Madinah dipindahkan ke Juhfah.\" Berkata Abu Isa: Hadits ini hasan shahih gharib."},"2207":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ أَيُّوبَ عَنْ ابْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي آخِرِ الزَّمَانِ لَا تَكَادُ رُؤْيَا الْمُؤْمِنِ تَكْذِبُ وَأَصْدَقُهُمْ رُؤْيَا أَصْدَقُهُمْ حَدِيثًا وَالرُّؤْيَا ثَلَاثٌ الْحَسَنَةُ بُشْرَى مِنْ اللَّهِ وَالرُّؤْيَا يُحَدِّثُ الرَّجُلُ بِهَا نَفْسَهُ وَالرُّؤْيَا تَحْزِينٌ مِنْ الشَّيْطَانِ فَإِذَا رَأَى أَحَدُكُمْ رُؤْيَا يَكْرَهُهَا فَلَا يُحَدِّثْ بِهَا أَحَدًا وَلْيَقُمْ فَلْيُصَلِّقَالَ أَبُو هُرَيْرَةَ يُعْجِبُنِي الْقَيْدُ وَأَكْرَهُ الْغُلَّ الْقَيْدُ ثَبَاتٌ فِي الدِّينِ قَالَ وَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رُؤْيَا الْمُؤْمِنِ جُزْءٌ مِنْ سِتَّةٍ وَأَرْبَعِينَ جُزْءًا مِنْ النُّبُوَّةِ قَالَ أَبُو عِيسَى وَقَدْ رَوَى عَبْدُ الْوَهَّابِ الثَّقَفِيُّ هَذَا الْحَدِيثَ عَنْ أَيُّوبَ مَرْفُوعًا وَرَوَاهُ حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ وَوَقَفَهُ","id":"Telah menceritakan kepada kami [Al Hasan bin 'Ali Al Khallal] telah menceritakan kepada kami ['Abdur Razzaq] telah mengkhabarkan kepada kami [Ma'mar] dari [Ayyub] dari [Ibnu Sirin] dari [Abu Hurairah] dari nabi Shallallahu 'alaihi wa Salam bersabda: \"Di akhir zaman, hampir mimpi mu`min tidak berdusta dan mimpi mereka yang paling benar adalah yang paling benar kata-katanya dan, mimpi itu ada tiga; mimpi yang baik adalah khabar gembira dari Allah, mimpi yang dibisikkan oleh jiwa seseorang dan mimpi dari kesedihan yang dibuat setan dan bila salah seorang dari kalian bermimpi sesuatu yang tidak ia suka, jangan memberitahukannya kepada siapa pun, hendaklah ia bangun lalu shalat.\" Abu Hurairah berkata: Aku suka bermimpi diikat tali dalam tidur dan aku tidak suka bermimpi kedua tanganku diikat diatas tengkuk, sebab diikat tali itu maknanya adalah teguh dalam agama. Nabi Shallallahu 'alaihi wa Salam bersabda: \"Mimpi seorang mu`min adalah satu dari empatpuluh enam bagian kenabian. Berkata Abu Isa: ['Abdul Wahhab Ats Tsaqafi] meriwayatkan hadits ini dari [Ayyub] secara marfu' dan [Hammad bin Zaid] meriwayatkannya dari [Ayyub], ia memauqufkannya."},"2208":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعِيدٍ الْجَوْهَرِيُّ الْبَغْدَادِيُّ حَدَّثَنَا أَبُو الْيَمَانِ عَنْ شُعَيْبٍ وَهُوَ ابْنُ أَبِي حَمْزَةَ عَنْ ابْنِ أَبِي حُسَيْنٍ وَهُوَ عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ بْنِ أَبِي حُسَيْنٍ عَنْ نَافِعِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَيْتُ فِي الْمَنَامِ كَأَنَّ فِي يَدَيَّ سِوَارَيْنِ مِنْ ذَهَبٍ فَهَمَّنِي شَأْنُهُمَا فَأُوحِيَ إِلَيَّ أَنْ أَنْفُخَهُمَا فَنَفَخْتُهُمَا فَطَارَا فَأَوَّلْتُهُمَا كَاذِبَيْنِ يَخْرُجَانِ مِنْ بَعْدِي يُقَالُ لِأَحَدِهِمَا مُسَيْلِمَةُ صَاحِبُ الْيَمَامَةِ وَالْعَنْسِيُّ صَاحِبُ صَنْعَاءَقَالَ هَذَا حَدِيثٌ صَحِيحٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Ibrahim bin Sa'id Al Jauhari Al Baghdadi] telah menceritakan kepada kami [Abu Al Yaman] dari [Syu'aib bin Abu Hamzah] dari [Ibnu Abi Husain 'Abdullah bin Abdurrahman bin Abu Husain] dari [Nafi' bin Jubair] dari [Ibnu 'Abbas] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Aku bermimpi seolah-olah di tanganku ada dua gelang emas, kondisi keduanya membuatku sedih lalu aku diberi wahyu agar aku meniup keduanya, aku lalu meniup keduanya, keduanya terbang lalu aku menafsirkan keduanya sebagai dua pendusta yang muncul sepeninggalku, salah satunya bernama Musailamah, pemimpin Yamamah dan Al 'Unsi, pemimpin Shan'a`.\" Berkata Abu Isa: Hadits ini shahih gharib."},"2209":{"ar":"حَدَّثَنَا الْحُسَيْنُ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ قَالَ كَانَ أَبُو هُرَيْرَةَ يُحَدِّثُأَنَّ رَجُلًا جَاءَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنِّي رَأَيْتُ اللَّيْلَةَ ظُلَّةً يَنْطِفُ مِنْهَا السَّمْنُ وَالْعَسَلُ وَرَأَيْتُ النَّاسَ يَسْتَقُونَ بِأَيْدِيهِمْ فَالْمُسْتَكْثِرُ وَالْمُسْتَقِلُّ وَرَأَيْتُ سَبَبًا وَاصِلًا مِنْ السَّمَاءِ إِلَى الْأَرْضِ وَأَرَاكَ يَا رَسُولَ اللَّهِ أَخَذْتَ بِهِ فَعَلَوْتَ ثُمَّ أَخَذَ بِهِ رَجُلٌ بَعْدَكَ فَعَلَا ثُمَّ أَخَذَ بِهِ رَجُلٌ بَعْدَهُ فَعَلَا ثُمَّ أَخَذَ بِهِ رَجُلٌ فَقُطِعَ بِهِ ثُمَّ وُصِلَ لَهُ فَعَلَا بِهِ فَقَالَ أَبُو بَكْرٍ أَيْ رَسُولَ اللَّهِ بِأَبِي أَنْتَ وَأُمِّي وَاللَّهِ لَتَدَعَنِّي أَعْبُرُهَا فَقَالَ اعْبُرْهَا فَقَالَ أَمَّا الظُّلَّةُ فَظُلَّةُ الْإِسْلَامِ وَأَمَّا مَا يَنْطِفُ مِنْ السَّمْنِ وَالْعَسَلِ فَهُوَ الْقُرْآنُ لِينُهُ وَحَلَاوَتُهُ وَأَمَّا الْمُسْتَكْثِرُ وَالْمُسْتَقِلُّ فَهُوَ الْمُسْتَكْثِرُ مِنْ الْقُرْآنِ وَالْمُسْتَقِلُّ مِنْهُ وَأَمَّا السَّبَبُ الْوَاصِلُ مِنْ السَّمَاءِ إِلَى الْأَرْضِ فَهُوَ الْحَقُّ الَّذِي أَنْتَ عَلَيْهِ فَأَخَذْتَ بِهِ فَيُعْلِيكَ اللَّهُ ثُمَّ يَأْخُذُ بِهِ رَجُلٌ آخَرُ فَيَعْلُو بِهِ ثُمَّ يَأْخُذُ رَجُلٌ آخَرُ فَيَعْلُو بِهِ ثُمَّ يَأْخُذُ رَجُلٌ آخَرُ فَيَنْقَطِعُ بِهِ ثُمَّ يُوصَلُ لَهُ فَيَعْلُو أَيْ رَسُولَ اللَّهِ لَتُحَدِّثَنِّي أَصَبْتُ أَوْ أَخْطَأْتُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَصَبْتَ بَعْضًا وَأَخْطَأْتَ بَعْضًا قَالَ أَقْسَمْتُ بِأَبِي أَنْتَ وَأُمِّي لَتُخْبِرَنِّي مَا الَّذِي أَخْطَأْتُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُقْسِمْقَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Al Husain bin Muhammad] telah menceritakan kepada kami ['Abdur Razzaq] telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Ubaidillah bin 'Abdullah] dari [Ibnu 'Abbas] dia berkata bahwa [Abu Hurairah] menceritakan ada seorang lelaki datang kepada Nabi Shallallahu 'alaihi wa Salam lalu berkata: Tadi malam aku memimpikan gumpalan awan yang mengalirkan mentega dan madu, kemudian aku melihat orang orang menadahkan tangan mereka, diantara mereka ada yang mendapatkan banyak dan di antara mereka ada yang mendapatkan sedikit, lalu aku melihat tali yang menghubungkan dari langit ke bumi dan aku melihat engkau wahai Rasulullah mengambil tali itu sampai engkau naik ke atas, kemudian setelah engkau ada seorang lelaki yang mengambilnya lalu dia naik ke atas, kemudian setelahnya ada seorang lelaki lagi yang mengambilnya lalu dia naik ke atas, kemudian setelahnya ada seorang lelaki lagi yang mengambilnya namun terputus kemudian disambung lagi lalu dia naik ke atas, maka berkatalah Abu Bakar: Wahai Rasulullah, aku rela mengorbankan bapak ibuku demi baginda, demi Allah izinkanlah aku menyeberangi tali itu, lalu beliau bersabda: \"Menyeberanglah, \" kemudian beliau bersabda: \"Adapun gumpalan awan maksudnya adalah Islam, sedangkan yang mengalir berupa samin dan madu maksudnya adalah Al Qur'an karena lembut dan manisnya, adapun orang menadahkan dan mendapatkan banyak dan yang mendapatkan sedikit maksudnya adalah orang yang banyak mengambil Al Qur'an atau orang yang sedikit mengambilnya, sedangkan tali yang menghubungkan dari langit ke bumi maksudnya adalah kebenaran yang engkau jalani kemudian kamu mengambilnya lalu Allah mengangkatmu, kemudian ada seorang lelaki lain yang mengambilnya lalu dia terangkat dengannya, kemudian ada seorang lelaki lain lagi yang mengambilnya lalu dia terangkat dengannya, kemudian ada seorang lelaki lain yang mengambilnya namun terputus lalu disambungkan lagi kemudian dia terangkat.\" Orang itu bertanya: wahai Rasulullah, beritahukanlah kepadaku apakah aku benar atau salah? Nabi Shallallahu 'alaihi wa Salam menjawab: Kamu benar sebagian dan salah salah sebagian.\" Ia berkata: aku rela mengorbankan bapak dan ibuku demi baginda, hendaknya baginda memberitahukan kepadaku apa yang salah dariku? Nabi Shallallahu 'alaihi wa Salam menjawab: Janganlah kamu bersumpah.\" Berkata Abu Isa: hadits ini hasan shahih."},"2210":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا وَهْبُ بْنُ جَرِيرِ بْنِ حَازِمٍ عَنْ أَبِيهِ عَنْ أَبِي رَجَاءٍ عَنْ سَمُرَةَ بْنِ جُنْدَبٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّى بِنَا الصُّبْحَ أَقْبَلَ عَلَى النَّاسِ بِوَجْهِهِ وَقَالَ هَلْ رَأَى أَحَدٌ مِنْكُمْ اللَّيْلَةَ رُؤْيَاقَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَيُرْوَى هَذَا الْحَدِيثُ عَنْ عَوْفٍ وَجَرِيرِ بْنِ حَازِمٍ عَنْ أَبِي رَجَاءٍ عَنْ سَمُرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي قِصَّةٍ طَوِيلَةٍ قَالَ وَهَكَذَا رَوَى مُحَمَّدُ بْنُ بَشَّارٍ هَذَا الْحَدِيثَ عَنْ وَهْبِ بْنِ جَرِيرٍ مُخْتَصَرًا","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Wahab bin Jarir bin Hazim] dari [ayahnya] dari [Abu Raja`] dari [Samurah bin Jundub] berkata: Sesuai shalat shubuh bersama kami, nabi Shallallahu 'alaihi wa Salam menghadapkan wajah beliau ke arah kami dan bertanya: \"Apa ada salah seorang dari kalian yang bermimpi tadi malam?\" Berkata Abu Isa: Hadits ini hasan shahih. Dan hadits ini diriwayatkan dari ['Auf] dan [Jarir bin Hazim] dari [Abu Raja`] dari [Samurah] dari nabi Shallallahu 'alaihi wa Salam tentang kisah yang panjang. Berkata Abu Isa: Seperti itulah Muhammad bin Basyar meriwayatkan hadits ini dari Wahab bin Jarir secara ringkas."},"2211":{"ar":"حَدَّثَنَا الْأَنْصَارِيُّ حَدَّثَ��َا مَعْنٌ حَدَّثَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ عُثْمَانَ عَنْ أَبِي عَمْرَةَ الْأَنْصَارِيِّ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَلَا أُخْبِرُكُمْ بِخَيْرِ الشُّهَدَاءِ الَّذِي يَأْتِي بِالشَّهَادَةِ قَبْلَ أَنْ يُسْأَلَهَاحَدَّثَنَا أَحْمَدُ بْنُ الْحَسَنِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ نَحْوَهُ و قَالَ ابْنُ أَبِي عَمْرَةَ قَالَ هَذَا حَدِيثٌ حَسَنٌ وَأَكْثَرُ النَّاسِ يَقُولُونَ عَبْدُ الرَّحْمَنِ بْنُ أَبِي عَمْرَةَ وَاخْتَلَفُوا عَلَى مَالِكٍ فِي رِوَايَةِ هَذَا الْحَدِيثِ فَرَوَى بَعْضُهُمْ عَنْ أَبِي عَمْرَةَ وَرَوَى بَعْضُهُمْ عَنْ ابْنِ أَبِي عَمْرَةَ وَهُوَ عَبْدُ الرَّحْمَنِ بْنُ أَبِي عَمْرَةَ الْأَنْصَارِيُّ وَهَذَا أَصَحُّ لِأَنَّهُ قَدْ رُوِيَ مِنْ غَيْرِ حَدِيثِ مَالِكٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي عَمْرَةَ عَنْ زَيْدِ بْنِ خَالِدٍ وَقَدْ رُوِيَ عَنْ ابْنِ أَبِي عَمْرَةَ عَنْ زَيْدِ بْنِ خَالِدٍ غَيْرُ هَذَا الْحَدِيثِ وَهُوَ حَدِيثٌ صَحِيحٌ أَيْضًا وَأَبُو عَمْرَةَ مَوْلَى زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ وَلَهُ حَدِيثُ الْغُلُولِ وَأَكْثَرُ النَّاسِ يَقُولُونَ عَبْدُ الرَّحْمَنِ بْنُ أَبِي عَمْرَةَ","id":"Telah menceritakan kepada kami [Al Anshari] telah menceritakan kepada kami [Ma'an] telah menceritakan kepada kami [Malik] dari ['Abdullah bin Abu Bakar bin Muhammad bin 'Amru bin Hazm] dari [ayahnya] dari ['Abdullah bin 'Amru bin 'Utsman] dari [Abu 'Amrah Al Anshari] dari [Zaid bi Khalid Al Juhani] Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Maukah kalian aku beritahu saksi-saksi terbaik; yang membawa kesaksian sebelum diminta?\" telah menceritakan kepada kami [Ahmad bin Al Hasan] telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] Sepertinya. Berkata Ibnu Abi 'Amrah: Hadits ini hasan dan kebanyakan orang mengatakan Abdurrahman bin Abu 'Amrah, mereka memperselisihkan riwayat hadits ini atas Malik, sebagaian dari mereka meriwayatkan dari Abu 'Amrah, ada juga yang meriwayatkan dari Ibnu Abi 'Amrah, ia adalah Abdurrahman bin Abu 'Amrah Al Anshari dan inilah yang lebih benar karena diriwayatkan dari selain hadits Malik dari Abdurrahman bin Abu 'Amrah dari Zaid bin Khalid sementara selain hadits ini diriwayatkan dari Ibnu Abi 'Amrah dari Zaid bin Khalid, itu juga hadits shahih. Abu 'Amrah adalah budak milik Zaid bin Khalid Al Juhani, ia memiliki hadits tentang 'Ghulul' dan kebanyakan orang menyebut Abdurrahman bin Abu 'Amrah. "},"2212":{"ar":"حَدَّثَنَا بِشْرُ بْنُ آدَمَ ابْنُ بِنْتِ أَزْهَرَ السَّمَّانِ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ حَدَّثَنَا أُبَيُّ بْنُ عَبَّاسِ بْنِ سَهْلِ بْنِ سَعْدٍ حَدَّثَنِي أَبُو بَكْرِ بْنُ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ عَمْرِو بْنِ عُثْمَانَ حَدَّثَنِي خَارِجَةُ بْنُ زَيْدِ بْنِ ثَابِتٍ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ أَبِي عَمْرَةَ حَدَّثَنِي زَيْدُ بْنُ خَالِدٍ الْجُهَنِيُّأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ خَيْرُ الشُّهَدَاءِ مَنْ أَدَّى شَهَادَتَهُ قَبْلَ أَنْ يُسْأَلَهَاقَالَ هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepadaku [Bisyr bin Adam Ibnu binti Azhar As Samman] telah menceritakan kepada kami [Zaid bin Al Hubab] telah menceritakan kepada kami [Ubai bin 'Abbas bin Sahal bin Sa'ad] telah menceritakan kepadaku [Abu Bakr bin Muhammad bin 'Amru bin Hazm] telah menceritakan kepadaku ['Abdullah bin 'Amru bin 'Utsman] telah menceritakan kepadaku [Kharijah bin Zaid bin Tsabit] telah menceritakan kepadaku [Abdurrahman bin Abu 'Amrah] telah menceritakan kepadaku [Zaid bin Khalid Al Juhani] ia mendengar Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Saksi-saksi terbaik adalah orang yang menunaikan kesaksiannya sebelum diminta.\" Berkata Abu Isa: Hadits ini hasan gharib melalui sanad ini."},"2213":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا مَرْوَانُ الْفَزَارِيُّ عَنْ يَزِيدَ بْنِ زِيَادٍ الدِّمَشْقِيِّ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَجُوزُ شَهَادَةُ خَائِنٍ وَلَا خَائِنَةٍ وَلَا مَجْلُودٍ حَدًّا وَلَا مَجْلُودَةٍ وَلَا ذِي غِمْرٍ لِأَخِيهِ وَلَا مُجَرَّبِ شَهَادَةٍ وَلَا الْقَانِعِ أَهْلَ الْبَيْتِ لَهُمْ وَلَا ظَنِينٍ فِي وَلَاءٍ وَلَا قَرَابَةٍقَالَ الْفَزَارِيُّ الْقَانِعُ التَّابِعُ هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ يَزِيدَ بْنِ زِيَادٍ الدِّمَشْقِيِّ وَيَزِيدُ يُضَعَّفُ فِي الْحَدِيثِ وَلَا يُعْرَفُ هَذَا الْحَدِيثُ مِنْ حَدِيثِ الزُّهْرِيِّ إِلَّا مِنْ حَدِيثِهِ وَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَ وَلَا نَعْرِفُ مَعْنَى هَذَا الْحَدِيثِ وَلَا يَصِحُّ عِنْدِي مِنْ قِبَلِ إِسْنَادِهِ وَالْعَمَلُ عِنْدَ أَهْلِ الْعِلْمِ فِي هَذَا أَنَّ شَهَادَةَ الْقَرِيبِ جَائِزَةٌ لِقَرَابَتِهِ وَاخْتَلَفَ أَهْلُ الْعِلْمِ فِي شَهَادَةِ الْوَالِدِ لِلْوَلَدِ وَالْوَلَدِ لِوَالِدِهِ وَلَمْ يُجِزْ أَكْثَرُ أَهْلِ الْعِلْمِ شَهَادَةَ الْوَالِدِ لِلْوَلَدِ وَلَا الْوَلَدِ لِلْوَالِدِ و قَالَ بَعْضُ أَهْلِ الْعِلْمِ إِذَا كَانَ عَدْلًا فَشَهَادَةُ الْوَالِدِ لِلْوَلَدِ جَائِزَةٌ وَكَذَلِكَ شَهَادَةُ الْوَلَدِ لِلْوَالِدِ وَلَمْ يَخْتَلِفُوا فِي شَهَادَةِ الْأَخِ لِأَخِيهِ أَنَّهَا جَائِزَةٌ وَكَذَلِكَ شَهَادَةُ كُلِّ قَرِيبٍ لِقَرِيبِهِ و قَالَ الشَّافِعِيُّ لَا تَجُوزُ شَهَادَةٌ لِرَجُلٍ عَلَى الْآخَرِ وَإِنْ كَانَ عَدْلًا إِذَا كَانَتْ بَيْنَهُمَا عَدَاوَةٌ وَذَهَبَ إِلَى حَدِيثِ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْسَلًا لَا تَجُوزُ شَهَادَةُ صَاحِبِ إِحْنَةٍ يَعْنِي صَاحِبَ عَدَاوَةٍ وَكَذَلِكَ مَعْنَى هَذَا الْحَدِيثِ حَيْثُ قَالَ لَا تَجُوزُ شَهَادَةُ صَاحِبِ غِمْرٍ لِأَخِيهِ يَعْنِي صَاحِبَ عَدَاوَةٍ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Marwan Al Fazari] dari [Yazid bin Ziyad Ad Dimasyqi] dari [Az Zuhri] dari ['Urwah] dari ['Aisyah] dia berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Tidak dibolehkan persaksian dari seorang lelaki dan seorang perempuan yang pengkhianat, seorang lelaki dan seorang perempuan yang dihukum cambuk, seorang yang dengki kepada saudaranya, seorang yang terbiasa dengan saksi palsu, seorang yang menjadi pelayan dalam rumah tuannya dan dari seseorang yang tertuduh berwala' dan bernasab kepada yang lain -Al fazari berkata: Al Qoni' artinya yang mengikuti.\" Hadits ini gharib, kami tidak mengetahuinya kecuali dari hadits Yazid bin Ziyad Ad Dimasyqi, sedangkan Yazid bin Ziyad Ad Dimasyqi dilemahkan dalam masalah hadits, dan hadits ini tidak dikenal sebagai hadits Az Zuhri selain dari haditsnya Yazid bin Ziyad, dan dalam bab ini ada hadits dari 'Abdullah bin Amr, dia berkata \" kami tidak mengerti maksud dari hadits ini dan menurut kami hadits ini tidak sah dari sisi sanadnya, adapun yang diamalkan oleh ahli ilmu dalam masalah ini bahwa persaksian dari kerabat dekat untuk kerabatnya itu dibolehkan, namun ahli ilmu berbeda pendapat tentang persaksian seorang bapak untuk anaknya dan persaksian seorang anak untuk bapaknya, dan kebanyakan ahli ilmu tidak membolehkan persaksian seorang bapak untuk anaknya demikian juga persaksian seorang anak untuk bapaknya, sebagian ahli ilmu berpendapat jika orangnya adil, maka persaksian seorang bapak untuk anaknya dibolehkan demikian juga persaksian seorang anak untuk bapaknya, dan mereka tidak berbeda pendapat akan kebolehan persaksian seorang saudara laki laki untuk saudaranya demikian juga persaksian dari setiap orang kerabat terdekat untuk kerabatnya. Imam Syafi'I berpendapat, dibenarkan persaksian dari sseeorang untuk orang yang lain sekali pun dia adalah seorang yang jujur jika di antara keduanya ada permusuhan, ia berpendapat bahwa hadits Abdurrahman Al A'raj dari Nabi Shallallahu 'alaihi wa Salam adalah hadits mursal, bahwa tidak boleh persaksian dari seseorang yang mempunyai permusuhan demikian juga makna hadits ini, dia berkata: Tidak dibenarkan persaksian dari seorang pendengki kepada saudaranya yaitu orang yang punya permusuhan."},"2214":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ عَنْ سُفْيَانَ بْنِ زِيَادٍ الْأَسَدِيِّ عَنْ فَاتِكِ بْنِ فَضَالَةَ عَنْ أَيْمَنَ بْنِ خُرَيْمٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ خَطِيبًا فَقَالَ يَا أَيُّهَا النَّاسُ عَدَلَتْ شَهَادَةُ الزُّورِ إِشْرَاكًا بِاللَّهِ ثُمَّ قَرَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ فَاجْتَنِبُوا الرِّجْسَ مِنْ الْأَوْثَانِ وَاجْتَنِبُوا قَوْلَ الزُّورِ }قَالَ أَبُو عِيسَى وَهَذَا حَدِيثٌ غَرِيبٌ إِنَّمَا نَعْرِفُهُ مِنْ حَدِيثِ سُفْيَانَ بْنِ زِيَادٍ وَاخْتَلَفُوا فِي رِوَايَةِ هَذَا الْحَدِيثِ عَنْ سُفْيَانَ بْنِ زِيَادٍ وَلَا نَعْرِفُ لِأَيْمَنَ بْنِ خُرَيْمٍ سَمَاعًا مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Marwan bin Mu'awiyah] dari [Sufyan bin Ziyad Al Asadi] dari [Fatik bin Fadlalah] dari [Aiman bin Khuraim], nabi Shallallahu 'alaihi wa Salam berdiri berkhutbah, beliau bersabda: \"Kesaksikan palsu sebanding dengan menyekutukan Allah, \" kemudian beliau membaca: \"Maka jauhilah olehmu berhala-berhala yang najis itu dan jauhilah perkataan-perkataan dusta.\" (Al-Hajj: 30) Berkata Abu Isa: Hadits ini gharib, kami hanya mengetahuinya dari hadits Sufyan bin ZIyad, mereka memperselisihkan riwayat hadits ini dari Sufyan bin Ziyad dan kami tidak mengetahui pendengaran Aiman bin Khuraim dari nabi Shallallahu 'alaihi wa Salam."},"2215":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا سُفْيَانُ وَهُوَ ابْنُ زِيَادٍ الْعُصْفُرِيُّ عَنْ أَبِيهِ عَنْ حَبِيبِ بْنِ النُّعْمَانِ الْأَسَدِيِّ عَنْ خُرَيْمِ بْنِ فَاتِكٍ الْأَسَدِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى صَلَاةَ الصُّبْحِ فَلَمَّا انْصَرَفَ قَامَ قَائِمًا فَقَالَ عُدِلَتْ شَهَادَةُ الزُّورِ بِالشِّرْكِ بِاللَّهِ ثَلَاثَ مَرَّاتٍ ثُمَّ تَلَا هَذِهِ الْآيَةَ{ وَاجْتَنِبُوا قَوْلَ الزُّورِ }إِلَى آخِرِ الْآيَةِقَالَ أَبُو عِيسَى هَذَا عِنْدِي أَصَحُّ وَخُرَيْمُ بْنُ فَاتِكٍ لَهُ صُحْبَةٌ وَقَدْ رَوَى عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحَادِيثَ وَهُوَ مَشْهُورٌ","id":"Telah menceritakan kepada kami [Abd bin Humaid] telah menceritakan kepada kami [Muhammad bin 'Ubaid] telah menceritakan kepada kami [Sufyan bin Ziyad Al 'Ushfuri] dari [ayahnya] dari [Habib bin An Nu'man Al Asadi] dari [Khuraim bin Fatik Al Asadi], Rasulullah Shallallahu 'alahi wa Salam shalat shubuh, setelah usai beliau berdiri lalu bersabda: \"Kesaksikan palsu sebanding dengan menyekutukan Allah, \" (beliau ulangi ucapannya tiga kali), kemudian beliau membaca ayat ini: \"Maka jauhilah olehmu berhala-berhala yang najis itu dan jauhilah perkataan-perkataan dusta.\" (Al-Hajj: 30) hingga akhir ayat. Berkata Abu Isa: Menurutku hadits ini lebih shahih dan Khuraim bin Fatik memiliki status sahabat, ia meriwayatkan banyak hadits dari nabi Shallallahu 'alaihi wa Salam dan ia masyhur."},"2216":{"ar":"حَدَّثَنَا حُمَيْدُ بْنُ مَسْعَدَةَ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ عَنْ الْجُرَيْرِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرَةَ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَلَا أُخْبِرُكُمْ بِأَكْبَرِ الْكَبَائِرِ قَالُوا بَلَى يَا رَسُولَ اللَّهِ قَالَ الْإِشْرَاكُ بِاللَّهِ وَعُقُوقُ الْوَالِدَيْنِ وَشَهَادَةُ الزُّورِ أَوْ قَوْلُ الزُّورِ قَالَ فَمَا زَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُهَا حَتَّى قُلْنَا لَيْتَهُ سَكَتَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَفِي الْبَاب عَنْ عَبْدِ ��للَّهِ بْنِ عَمْرٍو","id":"Telah menceritakan kepada kami [Humaid bin Mas'adah] telah menceritakan kepada kami [Bisyr bin Al Mufadldlal] dari [Al Jurairi] dari [Abdurrahman bin Abu Bakrah] dari [ayahnya] Rasulullah Shallallahu 'alaihi wa salam bertanya: \"Maukah kalian aku beritahu dosa terbesar diantara dosa-dosa besar?\" mereka menjawab: Ya, wahai Rasulullah Shallallahu 'alahi wa Salam. Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Menyekutukan Allah, durhaka kepada kedua orang tua, kesaksian palsu atau perkataan palsu.\" Berkata Abu Bakrah: Rasulullah Shallallahu 'alahi wa Salam terus mengatakannya hingga kami berkata (dalam hati): Andai beliau diam. Berkata Abu Isa: Hadits ini hasan shahahi dan dalam hal ini ada hadits serupa dari 'Abdullah bin 'Amru."},"2217":{"ar":"حَدَّثَنَا وَاصِلُ بْنُ عَبْدِ الْأَعْلَى حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ الْأَعْمَشِ عَنْ عَلِيِّ بْنِ مُدْرِكٍ عَنْ هِلَالِ بْنِ يَسَافٍ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ خَيْرُ النَّاسِ قَرْنِي ثُمَّ الَّذِينَ يَلُونَهُمْ ثُمَّ الَّذِينَ يَلُونَهُمْ ثَلَاثًا ثُمَّ يَجِيءُ قَوْمٌ مِنْ بَعْدِهِمْ يَتَسَمَّنُونَ وَيُحِبُّونَ السِّمَنَ يُعْطُونَ الشَّهَادَةَ قَبْلَ أَنْ يُسْأَلُوهَاقَالَ أَبُو عِيسَى وَهَذَا حَدِيثٌ غَرِيبٌ مِنْ حَدِيثِ الْأَعْمَشِ عَنْ عَلِيِّ بْنِ مُدْرِكٍ وَأَصْحَابُ الْأَعْمَشِ إِنَّمَا رَوَوْا عَنْ الْأَعْمَشِ عَنْ هِلَالِ بْنِ يَسَافٍ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ حَدَّثَنَا أَبُو عَمَّارٍ الْحُسَيْنُ بْنُ حُرَيْثٍ حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ حَدَّثَنَا هِلَالُ بْنُ يَسَافٍ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ وَهَذَا أَصَحُّ مِنْ حَدِيثِ مُحَمَّدِ بْنِ فُضَيْلٍ قَالَ وَمَعْنَى هَذَا الْحَدِيثِ عِنْدَ بَعْضِ أَهْلِ الْعِلْمِ يُعْطُونَ الشَّهَادَةَ قَبْلَ أَنْ يُسْأَلُوهَا إِنَّمَا يَعْنِي شَهَادَةَ الزُّورِ يَقُولُ يَشْهَدُ أَحَدُهُمْ مِنْ غَيْرِ أَنْ يُسْتَشْهَدَ وَبَيَانُ هَذَا فِي حَدِيثِ عُمَرَ بْنِ الْخَطَّابِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خَيْرُ النَّاسِ قَرْنِي ثُمَّ الَّذِينَ يَلُونَهُمْ ثُمَّ الَّذِينَ يَلُونَهُمْ ثُمَّ يَفْشُو الْكَذِبُ حَتَّى يَشْهَدَ الرَّجُلُ وَلَا يُسْتَشْهَدُ وَيَحْلِفَ الرَّجُلُ وَلَا يُسْتَحْلَفُ وَمَعْنَى حَدِيثِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرُ الشُّهَدَاءِ الَّذِي يَأْتِي بِشَهَادَتِهِ قَبْلَ أَنْ يُسْأَلَهَا هُوَ عِنْدَنَا إِذَا أُشْهِدَ الرَّجُلُ عَلَى الشَّيْءِ أَنْ يُؤَدِّيَ شَهَادَتَهُ وَلَا يَمْتَنِعَ مِنْ الشَّهَادَةِ هَكَذَا وَجْهُ الْحَدِيثِ عِنْدَ بَعْضِ أَهْلِ الْعِلْمِ","id":"Telah menceritakan kepada kami [Washil bin 'Abdul A'la] telah menceritakan kepada kami [Muhammad bin Fudlail] dari [Al A'masy] dari ['Ali bin Mudri] dari [Hilal bin Yasaf] dari ['Imran bin Hushain] berkata: Aku mendengar Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Manusia terbaik adalah masaku kemudian setelah mereka kemudian setelah mereka -sebanyak tiga kali- setelah itu muncul kaum setelah mereka, mereka berusaha menggemukkan diri dan menyukai kegemukan, mereka memberikan persaksian sebelum diminta.\" Berkata Abu Isa: Hadits ini gharib dari hadits Al A'masy dari 'Ali bin Mudrik dan para sahabat Al A'masy hanya meriwayatkan dari Al A'masy dari Hilal bin Yasaf dari 'Imran bin Hushain. Telah menceritakan kepada kami [Abu 'Ammar Al Husain bin Huraits] telah menceritakan kepada kami [Waki'] dari [Al A'masy] telah menceritakan kepada kami [Hilal bin Yasaf] dari ['Imran bin Hushain] dari nabi Shallallahu 'alaihi wa Salam Sepertinya. Dan ini lebih shahih dari hadits Muhammad bin Fudlail. Berkata Abu Isa: Makna hadits ini menurut sebagaian ahlul ilmi; mereka memberikan persaksian sebelum diminta maksudnya adalah kesaksian palsu, Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Salah seorang dari mereka bersaksi padahal tidak diminta bersaksi.\" Penjelasannya ada dalam hadits 'Umar bin Al Khaththab dari nabi Shallallahu 'alaihi wa Salam bersabda: \"Manusia terbaik adalah masaku kemudian setelah mereka kemudian setelah mereka, kemudian setelah itu kedustaan menyebar hingga seseorang bersaksi padahal ia tidak diminta bersaksi, seseorang bersumpah padahal tidak diminta bersumpah.\" Dan meriwayatkan hadits nabi Shallallahu 'alaihi wa Salam; \"Saksi-saksi terbaik adalah orang yang membawa kesaksiannya sebelum diminta\" menurutku, bila seseorang diminta bersaksi atas sesuatu, ia menunaikan kesaksiannya dan tidak enggan untuk bersaksi. Seperti itulah makna hadits menurut sebagaian ahlul ilmi."},"2218":{"ar":"حَدَّثَنَا صَالِحُ بْنُ عَبْدِ اللَّهِ وَسُوَيْدُ بْنُ نَصْرٍ قَالَ صَالِحٌ حَدَّثَنَا و قَالَ سُوَيْدٌ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ عَبْدِ اللَّهِ بْنِ سَعِيدِ بْنِ أَبِي هِنْدٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نِعْمَتَانِ مَغْبُونٌ فِيهِمَا كَثِيرٌ مِنْ النَّاسِ الصِّحَّةُ وَالْفَرَاغُحَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدِ بْنِ أَبِي هِنْدٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ قَالَ وَفِي الْبَاب عَنْ أَنَسِ بْنِ مَالِكٍ و قَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَرَوَاهُ غَيْرُ وَاحِدٍ عَنْ عَبْدِ اللَّهِ بْنِ سَعِيدِ بْنِ أَبِي هِنْدٍ فَرَفَعُوهُ وَأَوْقَفَهُ بَعْضُهُمْ عَنْ عَبْدِ اللَّهِ بْنِ سَعِيدِ بْنِ أَبِي هِنْدٍ","id":"Telah menceritakan kepada kami [Shalih bin 'Abdullah] dan [Suwaid bin Nashr], berkata Shalih; telah menceritakan kepada kami, dan berkata Suwaid; telah mengkhabarkan kepada kami ['Abdullah bin Al Mubarak] dari ['Abdullah bin Sa'id bin Abu Hind] dari [ayahnya] dari [Ibnu 'Abbas] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Dua nikmat yang banyak dilalaikan manusia; kesehatan dan waktu luang.\" Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami ['Abdullah bin Sa'id bin Abu Hind] dari [ayahnya] dari [Ibnu 'Abbas] dari nabi Shallallahu 'alaihi wa Salam sepertinya. Berkata Abu Isa: Dalam hal ini ada hadits serupa dari Anas bin Malik dan hadits ini hasan shahih. Dan diriwayatkan oleh banyak perawi dari 'Abdullah bin Sa'id bin Abu Hind, mereka memarfu'kannya, sementara sebagaiannya memauqufkannya dari 'Abdullah bin Sa'id bin Abu Hind."},"2219":{"ar":"حَدَّثَنَا بِشْرُ بْنُ هِلَالٍ الصَّوَّافُ الْبَصْرِيُّ حَدَّثَنَا جَعْفَرُ بْنُ سُلَيْمَانَ عَنْ أَبِي طَارِقٍ عَنْ الْحَسَنِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ يَأْخُذُ عَنِّي هَؤُلَاءِ الْكَلِمَاتِ فَيَعْمَلُ بِهِنَّ أَوْ يُعَلِّمُ مَنْ يَعْمَلُ بِهِنَّ فَقَالَ أَبُو هُرَيْرَةَ فَقُلْتُ أَنَا يَا رَسُولَ اللَّهِ فَأَخَذَ بِيَدِي فَعَدَّ خَمْسًا وَقَالَ اتَّقِ الْمَحَارِمَ تَكُنْ أَعْبَدَ النَّاسِ وَارْضَ بِمَا قَسَمَ اللَّهُ لَكَ تَكُنْ أَغْنَى النَّاسِ وَأَحْسِنْ إِلَى جَارِكَ تَكُنْ مُؤْمِنًا وَأَحِبَّ لِلنَّاسِ مَا تُحِبُّ لِنَفْسِكَ تَكُنْ مُسْلِمًا وَلَا تُكْثِرْ الضَّحِكَ فَإِنَّ كَثْرَةَ الضَّحِكِ تُمِيتُ الْقَلْبَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ جَعْفَرِ بْنِ سُلَيْمَانَ وَالْحَسَنُ لَمْ يَسْمَعْ مِنْ أَبِي هُرَيْرَةَ شَيْئًا هَكَذَا رُوِيَ عَنْ أَيُّوبَ وَيُونُسَ بْنِ عُبَيْدٍ وَعَلِيِّ بْنِ زَيْدٍ قَالُوا لَمْ يَسْمَعْ الْحَسَنُ مِنْ أَبِي هُرَيْرَةَ وَرَوَى أَبُو عُبَيْدَةَ النَّاجِيُّ عَنْ الْحَسَنِ هَذَا الْحَدِيثَ قَوْلَهُ وَلَمْ يَذْكُرْ فِيهِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Bisyr bin Hilal Ash Shawwaf Al Bashri] telah menceritakan kepada kami [Ja'far bin Sulaiman] dari [Abu Thariq] dari [Al Hasan] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Siapa yang mau mengambil kalimat-kalimat itu dariku lalu mengamalkannya atau mengajarkan pada orang yang mengamalkannya?\" Abu Hurairah menjawab: Saya, wahai Rasulullah. beliau meraih tanganku lalu menyebut lima hal; jagalah dirimu dari keharaman-keharaman niscaya kamu menjadi orang yang paling ahli ibadah, terimalah pemberian Allah dengan rela niscaya kau menjadi orang terkaya, berbuat baiklah terhadap tetanggamu niscaya kamu menjadi orang mu`min, cintailah untuk sesama seperti yang kau cintai untuk dirimu sendiri niscaya kau menjadi orang muslim, jangan sering tertawa karena seringnya tertawa itu mematikan hati.\" Berkata Abu Isa: Hadits ini gharib, kami hanya mengetahuinya dari hadits Ja'far bin Sulaiman dan Al Hasan tidak mendengar apa pun dari Abu Hurairah. Seperti itulah diriwayatkan dari Ayyub, Yunus bin 'Ubaid, 'Ali bin Zaid, mereka berkata: Al Hasan tidak mendengar dari Abu Hurairah. Dan Abu 'Ubaidah An Naji meriwayatkan perkataan Al Hasan pada hadits ini dan ia tidak menyebutkan dari Abu Hurairah dari nabi Shallallahu 'alaihi wa Salam."},"2220":{"ar":"حَدَّثَنَا أَبُو مُصْعَبٍ عَنْ مُحْرِزِ بْنِ هَارُونَ عَنْ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَادِرُوا بِالْأَعْمَالِ سَبْعًا هَلْ تَنْتَظِرُونَ إِلَّا فَقْرًا مُنْسِيًا أَوْ غِنًى مُطْغِيًا أَوْ مَرَضًا مُفْسِدًا أَوْ هَرَمًا مُفَنِّدًا أَوْ مَوْتًا مُجْهِزًا أَوْ الدَّجَّالَ فَشَرُّ غَائِبٍ يُنْتَظَرُ أَوْ السَّاعَةَ فَالسَّاعَةُ أَدْهَى وَأَمَرُّقَالَ هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ مِنْ حَدِيثِ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ إِلَّا مِنْ حَدِيثِ مُحْرِزِ بْنِ هَارُونَ وَقَدْ رَوَى بِشْرُ بْنُ عُمَرَ وَغَيْرُهُ عَنْ مُحْرِزِ بْنِ هَارُونَ هَذَا وَقَدْ رَوَى مَعْمَرٌ هَذَا الْحَدِيثَ عَمَّنْ سَمِعَ سَعِيدًا الْمَقْبُرِيَّ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ وَقَالَ تَنْتَظِرُونَ","id":"Telah menceritakan kepada kami [Abu Mush'ab] dari [Muhriz bin Harun] dari [Abdurrahman Al A'raj] dari [Abu Hurairah], Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Segeralah beramal (sebelum kedatangan tujuh hal, tidaklah kalian menunggu selain kefakiran yang membuat lupa, kekayaan yang melampaui batas, penyakit yang merusak, masa tua yang menguruskan, kematian yang menyergap tiba-tiba, Dajjal, seburuk-buruk hal gaib yang dinanti-nanti, kiamat dan kiamat itu sangat membawa petaka dan sangat pahit.\" Berkata Abu Isa: Hadits ini hasan gharib, kami tidak mengetahui hadits Al A'raj dari Abu Hurairah kecuali dari hadits Muhriz bin Harun. [Bisyar bin 'Umar] dan lainnya meriwayatkan dari [Muhriz bin Harun ini]. [Ma'mar] meriwayatkan hadits ini dari [orang yang] mendengar [Sa'id Al Maqbari] dari [Abu Hurairah] dari nabi Shallallahu 'alaihi wa Salam Sepertinya, ia berkata dalam riwayatnya: Kalian menanti."},"2221":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكْثِرُوا ذِكْرَ هَاذِمِ اللَّذَّاتِ يَعْنِي الْمَوْتَقَالَ وَفِي الْبَاب عَنْ أَبِي سَعِيدٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Al Fadl bin Musa] dari [Muhammad bin 'Amru] dari [Abu Salamah] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Banyak-banyaklah mengingat pemutus kenikmatan yaitu kematian\" Berkata Abu Isa: Dalam hal ini ada hadits serupa dari Abu Sa'id. Berkata Abu Isa: Hadits ini hasan shahih gharib."},"2222":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا يَحْيَى بْنُ مَعِينٍ حَدَّثَنَا هِشَامُ بْنُ يُوسُفَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ بَحِيرٍ أَنَّهُ سَمِعَ هَانِئًا مَوْلَى عُثْمَانَ قَالَ كَانَ عُثْمَانُإِذَا وَقَفَ عَلَى قَبْرٍ بَكَى حَتَّى يَبُلَّ لِحْيَتَهُ فَقِيلَ لَهُ تُذْكَرُ الْجَنَّةُ وَالنَّارُ فَلَا تَبْكِي وَتَبْكِي مِنْ هَذَا فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْقَبْرَ أَوَّلُ مَنْزِلٍ مِنْ مَنَازِلِ الْآخِرَةِ فَإِنْ نَجَا مِنْهُ فَمَا بَعْدَهُ أَيْسَرُ مِنْهُ وَإِنْ لَمْ يَنْجُ مِنْهُ فَمَا بَعْدَهُ أَشَدُّ مِنْهُ قَالَ وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا رَأَيْتُ مَنْظَرًا قَطُّ إِلَّا الْقَبْرُ أَفْظَعُ مِنْهُقَالَ هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ هِشَامِ بْنِ يُوسُفَ","id":"Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Yahya bin Ma'in] telah menceritakan kepada kami [Hisyam bin Yusuf] telah menceritakan kepadaku ['Abdullah bin Bahir] ia mendengar [Hani`] budak 'Utsman, berkata: 'Utsman menangis bila berdiri diatas makam hingga jenggotnya basah. Dikatakan padanya: Surga dan neraka disebutkan tapi aku tidak menangis sementara kau menangis karena ini. ['Utsman] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Sesungguhnya makam adalah tempat akhirat pertama, bila seseorang selamat darinya maka setelahnya lebih mudah dan bila tidak selamat darinya maka setelahnya lebih sulit.\" 'Utsman berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Aku tidak melihat suatu pemandang pun melainkan pemakaman lebih mengerikan.\" Berkata Abu Isa: Hadits ini hasan gharib, kami hanya mengetahuinya dari hadits Hisyam bin Yusuf."},"2223":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ أَخْبَرَنَا شُعْبَةُ عَنْ قَتَادَةَ قَال سَمِعْتُ أَنَسًا يُحَدِّثُ عَنْ عُبَادَةَ بْنِ الصَّامِتِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَحَبَّ لِقَاءَ اللَّهِ أَحَبَّ اللَّهُ لِقَاءَهُ وَمَنْ كَرِهَ لِقَاءَ اللَّهِ كَرِهَ اللَّهُ لِقَاءَهُقَالَ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَعَائِشَةَ وَأَنَسٍ وَأَبِي مُوسَى قَالَ حَدِيثُ عُبَادَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Dawud] telah mengkhabarkan kepada kami [Syu'bah] dari [Qatadah] berkata: Aku mendengar [Anas] menceritakan dari [Ubadah bin Ash Shamit] dari nabi Shallallahu 'alaihi wa Salam, beliau bersabda: \"Barangsiapa senang bertemu Allah, Allah senang bertemu dengannya dan barangsiapa tidak senang bertemu Allah, Allah tidak senang bertemu dengannya.\" Berkata Abu Isa: Dalam hal ini ada hadits serupa dari Abu Hurairah, 'A`isyah, Anas, Abu Musa. Hadits 'Ubadah adalah hadits hasan shahih."},"2224":{"ar":"حَدَّثَنَا أَبُو الْأَشْعَثِ أَحْمَدُ بْنُ الْمِقْدَامِ الْعِجْلِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ الطُّفَاوِيُّ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ وَأَنْذِرْ عَشِيرَتَكَ الْأَقْرَبِينَ }قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا صَفِيَّةُ بِنْتَ عَبْدِ الْمُطَّلِبِ يَا فَاطِمَةُ بِنْتَ مُحَمَّدٍ يَا بَنِي عَبْدِ الْمُطَّلِبِ إِنِّي لَا أَمْلِكُ لَكُمْ مِنْ اللَّهِ شَيْئًا سَلُونِي مِنْ مَالِي مَا شِئْتُمْقَالَ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَأَبِي مُوسَى وَابْنِ عَبَّاسٍ قَالَ حَدِيثُ عَائِشَةَ حَدِيثٌ حَسَنٌ غَرِيبٌ هَكَذَا رَوَى بَعْضُهُمْ عَنْ هِشَامِ بْنِ عُرْوَةَ نَحْوَ هَذَا وَرَوَى بَعْضُهُمْ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْسَلًا لَمْ يَذْكُرْ فِيهِ عَنْ عَائِشَةَ","id":"Telah menceritakan kepada kami [Abu Al Asy'ats Ahmad bin Al Miqdam Al 'Ijlani] telah menceritakan kepada kami [Muhammad bin Abdurrahman Ath Thufawi] telah menceritakan kepada kami [Hisyam bin 'Urwah] dari [ayahnya] dari ['Aisyah] berkata: Ayat ini turun: \"Dan berilah peringatan kepada kerabat-kerabatmu yang terdekat.\" (Asy-Syu'araa`: 214) Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Hai Shafiyah binti 'Abdul Muththallib, hai Fathimah binti Muhammad, hai Bani 'Abdul Muththallib, sesungguhnya aku tidak memiliki kuasa apa pun untuk kalian dari Allah, mintalah hartaku semua kalian.\" Berkata Abu Isa: Dalam hal ini ada hadits serupa dari Abu Hurairah, Abu Musa dan Ibnu 'Abbas. Berkata Abu Isa: Hadits 'A`isyah adalah hadits hasan gharib, seperti itulah sebagian dari mereka meriwayatkan dari Hisyam bin 'Urwah seperti riwayat ini. Dan sebagian lagi meriwayatkan dari Hisyam dari ayahnya dari nabi Shallallahu 'alaihi wa Salam secara mursal, tidak disebutkan dari 'A`isyah."},"2225":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ الْمَسْعُودِيِّ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عِيسَى بْنِ طَلْحَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَلِجُ النَّارَ رَجُلٌ بَكَى مِنْ خَشْيَةِ اللَّهِ حَتَّى يَعُودَ اللَّبَنُ فِي الضَّرْعِ وَلَا يَجْتَمِعُ غُبَارٌ فِي سَبِيلِ اللَّهِ وَدُخَانُ جَهَنَّمَقَالَ وَفِي الْبَاب عَنْ أَبِي رَيْحَانَةَ وَابْنِ عَبَّاسٍ قَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَمُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ هُوَ مَوْلَى آلِ طَلْحَةَ وَهُوَ مَدَنِيٌّ ثِقَةٌ رَوَى عَنْهُ شُعْبَةُ وَسُفْيَانُ الثَّوْرِيُّ","id":"Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami ['Abdullah bin Al Mubarak] dari [Abdurrahman bin 'Abdullah Al Mas'udi] dari [Muhammad bin Abdurrahman] dari ['Isa bin Thalhah] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Tidak masuk neraka orang yang menangis karena takut Allah hingga susu kembali lagi ke kantung susu dan tidaklah menyatu debu dijalan Allah dan debu jahannam.\" Berkata Abu Isa: Dalam hal ini ada hadits serupa dari Abu Raihanah dan Ibnu 'Abbas. Hadits ini hasan shahih. Muhammad bin Abdurrahman adalah budak keluarga Thalhah, ia orang Madinah, terpercaya, Syu'bah dan Sufyan Ats Tsauri meriwayatkan darinya."},"2226":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا أَبُو أَحْمَدَ الزُّبَيْرِيُّ حَدَّثَنَا إِسْرَائِيلُ عَنْ إِبْرَاهِيمَ بْنِ الْمُهَاجِرِ عَنْ مُجَاهِدٍ عَنْ مُوَرِّقٍ عَنْ أَبِي ذَرٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي أَرَى مَا لَا تَرَوْنَ وَأَسْمَعُ مَا لَا تَسْمَعُونَ أَطَّتْ السَّمَاءُ وَحُقَّ لَهَا أَنْ تَئِطَّ مَا فِيهَا مَوْضِعُ أَرْبَعِ أَصَابِعَ إِلَّا وَمَلَكٌ وَاضِعٌ جَبْهَتَهُ سَاجِدًا لِلَّهِ وَاللَّهِ لَوْ تَعْلَمُونَ مَا أَعْلَمُ لَضَحِكْتُمْ قَلِيلًا وَلَبَكَيْتُمْ كَثِيرًا وَمَا تَلَذَّذْتُمْ بِالنِّسَاءِ عَلَى الْفُرُشِ وَلَخَرَجْتُمْ إِلَى الصُّعُدَاتِ تَجْأَرُونَ إِلَى اللَّهِ لَوَدِدْتُ أَنِّي كُنْتُ شَجَرَةً تُعْضَدُقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَعَائِشَةَ وَابْنِ عَبَّاسٍ وَأَنَسٍ قَالَ هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَيُرْوَى مِنْ غَيْرِ هَذَا الْوَجْهِ أَنَّ أَبَا ذَرٍّ قَالَ لَوَدِدْتُ أَنِّي كُنْتُ شَجَرَةً تُعْضَدُ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Abu Ahmad Az Zubairi] telah menceritakan kepada kami [Isra'il] dari [Ibrahim bin Al Muhajir] dari [Mujahid] dari [Muwarriq] dari [Abu Dzarr] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Sesungguhnya aku melihat yang tidak kalian lihat, mendengar yang tidak kalian dengar, langit merintih dan laik baginya merintih, tidaklah disana ada tempat untuk empat jari melainkan ada malaikat yang meletakkan dahinya seraya bersujud kepada Allah, andai kalian mengetahui yang aku ketahui, niscaya kalian jarang tertawa dan sering menangis, niscaya kalian tidak bersenang-senang dengan istri diatas ranjang dan niscaya kalian keluar menuju tanah datang tinggi, kalian berdoa memohon kepada Allah dengan mengiba-iba, aku ingin seandainya aku menjadi pohon yang ditebang.\" Berkata Abu Isa: Dalam hal ini ada hadits serupa dari Abu Hurairah, 'A`isyah, Ibnu 'Abbas dan Anas. Ia berkata: Hadits ini hasan gharib. Diriwayatkan dari selain riwayat ini bahwa Abu Dzarr berkata: \"Aku ingin seandainya aku menjadi pohon yang ditebang.\""},"2227":{"ar":"حَدَّثَنَا أَبُو حَفْصٍ عَمْرُو بْنُ عَلِيٍّ الْفَلَّاسُ حَدَّثَنَا عَبْدُ الْوَهَّابِ الثَّقَفِيُّ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ تَعْلَمُونَ مَا أَعْلَمُ لَضَحِكْتُمْ قَلِيلًا وَلَبَكَيْتُمْ كَثِيرًاهَذَا حَدِيثٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Abu Hafsh 'Amru bin 'Ali Al Fallas] telah menceritakan kepada kami ['Abdul Wahhab Ats Tsaqafi] dari [Muhammad bin 'Amru] dari [Abu Salamah] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Andai kalian tahu yang aku ketahui, niscaya kalian jarang tertawa dan sering menangis.\" Hadits ini shahih."},"2228":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ حَدَّثَنِي مُحَمَّدُ بْنُ إِبْرَاهِيمَ عَنْ عِيسَى بْنِ طَلْحَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الرَّجُلَ لَيَتَكَلَّمُ بِالْكَلِمَةِ لَا يَرَى بِهَا بَأْسًا يَهْوِي بِهَا سَبْعِينَ خَرِيفًا فِي النَّارِقَالَ هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Ibnu Abi 'Adi] dari [Muhammad bin Ishaq] telah menceritakan kepadaku [Muhammad bin Ibrahim] dari ['Isa bin Thalhah] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Bisa jadi seseorang mengatakan satu patah kata yang menurutnya tidak apa-apa tapi dengan kalimat itu ia jatuh ke neraka selama tujuhpuluh tahun.\" Berkata Abu Isa: hadits ini hasan gharib melalui sanad ini."},"2229":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا بَهْزُ بْنُ حَكِيمٍ حَدَّثَنِي أَبِي عَنْ جَدِّي قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ وَيْلٌ لِلَّذِي يُحَدِّثُ بِالْحَدِيثِ لِيُضْحِكَ بِهِ الْقَوْمَ فَيَكْذِبُ وَيْلٌ لَهُ وَيْلٌ لَهُقَالَ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ قَالَ هَذَا حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami [Bahz bin Hakim] telah menceritakan kepada kami [bapakku] dari [kakekku] dia berkata: Aku mendengar Nabi Shallallahu 'alaihi wa Salam bersabda: \"Celakalah bagi orang yang mengatakan sesuatu agar supaya ditertawakan oleh orang orang kemudian dia berbohong, celakalah baginya dan celakalah baginya.\" Berkata Abu Isa: Dan dalam hal ini ada hadits dari Abu Hurairah. Berkata Abu Isa: hadits ini hasan."},"2230":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ عَبْدِ الْجَبَّارِ الْبَغْدَادِيُّ حَدَّثَنَا عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ حَدَّثَنَا أَبِي عَنْ الْأَعْمَشِ عَنْ أَنَسٍ قَالَتُوُفِّيَ رَجُلٌ مِنْ أَصْحَابِهِ فَقَالَ يَعْنِي رَجُلًا أَبْشِرْ بِالْجَنَّةِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوَلَا تَدْرِي فَلَعَلَّهُ تَكَلَّمَ فِيمَا لَا يَعْنِيهِ أَوْ بَخِلَ بِمَا لَا يَنْقُصُهُقَالَ هَذَا حَدِيثٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Sulaiman bin 'Abdul Jabbar Al Baghdadi] telah menceritakan kepada kami ['Umar bin Hafs bin Ghiyats] telah menceritakan kepada kami [bapakku] dari [Al A'masy] dari [Anas] dia berkata: Salah seorang dari sahabatnya meninggal dunia, kemudian berkatalah seseorang: Bergembiralah dengan surga, Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Apa kau tidak tahu, mungkin saja dia mengatakan sesuatu yang tidak bermanfaat atau bakhil dengan sesuatu yang tidak akan menguranginya.\" Berkata Abu Isa: Hadits ini gharib."},"2231":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ نَصْرٍ النَّيْسَابُورِيُّ وَغَيْرُ وَاحِدٍ قَالُوا حَدَّثَنَا أَبُو مُسْهِرٍ عَنْ إِسْمَعِيلَ بْنِ عَبْدِ اللَّهِ بْنِ سَمَاعَةَ عَنْ الْأَوْزَاعِيِّ عَنْ قُرَّةَ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ حُسْنِ إِسْلَامِ الْمَرْءِ تَرْكُهُ مَا لَا يَعْنِيهِقَالَ هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ مِنْ حَدِيثِ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Ahmad bin Nashr An Naisaburi] dan yang lainnya telah menceritakan kepada kami mereka berkata bahwa [Abu Mushir] telah menceritakan kepada kami dari [Isma'il bin 'Abdullah bin Sama'ah] dari [Al Auza'i] dari [Qurroh] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] dia berkata bahwa Rasulullah Shallallahu 'alaihi wa salam bersabda: \" Di antara tanda baiknya Islam seseorang adalah meninggalkan sesuatu yang tidak bermanfaat baginya.\" Dia berkata: Hadits ini gharib, kami tidak mengetahuinya dari Hadits Abu Salamah dari Abu Hurairah dari Nabi Shallallahu 'alaihi wa Salam kecuali dari Jalur sanad ini."},"2232":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ الزُّهْرِيِّ عَنْ عَلِيِّ بْنِ حُسَيْنٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ حُسْنِ إِسْلَامِ الْمَرْءِ تَرْكَهُ مَا لَا يَعْنِيهِقَالَ أَبُو عِيسَى وَهَكَذَا رَوَى غَيْرُ وَاحِدٍ مِنْ أَصْحَابِ الزُّهْرِيِّ عَنْ الزُّهْرِيِّ عَنْ عَلِيِّ بْنِ حُسَيْنٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ حَدِيثِ مَالِكٍ مُرْسَلًا وَهَذَا عِنْدَنَا أَصَحُّ مِنْ حَدِيثِ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ وَعَلِيُّ بْنُ حُسَيْنٍ لَمْ يُدْرِكْ عَلِيَّ بْنَ أَبِي طَالِبٍ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Malik bin Anas] dari [Az Zuhri] dari ['Ali bin Husain] dia berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Sesungguhnya di antara ciri kebaikan keIslaman seseorang adalah meninggalkan sesuatu yang tidak bermanfaat baginya.\" Abu Isa berkata: Demikianlah kebanyakan perawi dari sahabat Az Zuhri telah meriwayatkannya dari Az Zuhri dari Ali bin Husain dari Nabi Shallallahu 'alaihi wa Salam dengann hadits yang semakna dengan hadits Malik secara mursal dan ini menurut kami yang lebih shahih dari pada hadits Abu Salamah dari Abu Hurairah, adapun 'Ali bin Husain tidak pernah bertemu dengan Ali bin Abu Thalib."},"2233":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا عَبْدَةُ عَنْ مُحَمَّدِ بْنِ عَمْرٍو حَدَّثَنِي أَبِي عَنْ جَدِّي قَال سَمِعْتُ بِلَالَ بْنَ الْحَارِثِ الْمُزَنِيَّ صَاحِبَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ أَحَدَكُمْ لَيَتَكَلَّمُ بِالْكَلِمَةِ مِنْ رِضْوَانِ اللَّهِ مَا يَظُنُّ أَنْ تَبْلُغَ مَا بَلَغَتْ فَيَكْتُبُ اللَّهُ لَهُ بِهَا رِضْوَانَهُ إِلَى يَوْمِ يَلْقَاهُ وَإِنَّ أَحَدَكُمْ لَيَتَكَلَّمُ بِالْكَلِمَةِ مِنْ سَخَطِ اللَّهِ مَا يَظُنُّ أَنْ تَبْلُغَ مَا بَلَغَتْ فَيَكْتُبُ اللَّهُ عَلَيْهِ بِهَا سَخَطَهُ إِلَى يَوْمِ يَلْقَاهُقَالَ وَفِي الْبَاب عَنْ أُمِّ حَبِيبَةَ قَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَهَكَذَا رَوَاهُ غَيْرُ وَاحِدٍ عَنْ مُحَمَّدِ بْنِ عَمْرٍو نَحْوَ هَذَا قَالُوا عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِيهِ عَنْ جَدِّهِ عَنْ بِلَالِ بْنِ الْحَارِثِ وَرَوَى هَذَا الْحَدِيثَ مَالِكٌ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِيهِ عَنْ بِلَالِ بْنِ الْحَارِثِ وَلَمْ يَذْكُرْ فِيهِ عَنْ جَدِّهِ","id":"Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami ['Abdah] dari [Muhammad bin 'Amru] telah menceritakan kepadaku [ayahku] dari [kakekku] berkata: Aku mendengar [Bilal bin Al Harits Al Muzanni], sahabat Rasulullah Shallallahu 'alahi wa Salam, berkata: Aku mendengar Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Bisa jadi salah seorang dari kalian mengucapkan sepatah kata yang membuat Allah ridha, ia tidak mengira kalimat itu sampai seperti itu, lalu karenanya Allah mencatat keridhaan untuknya hingga hari ia bertemu denganNya dan bisa jadi salah seorang diantara kalian mengucapkan sepatah kata yang membuat Allah murka, ia tidak mengira kalimat itu sampai seperti itu lalu Allah mencatat kemurkaanNya untuk orang itu hingga saat ia bertemu denganNya.\" Berkata Abu Isa: Dalam hal ini ada hadits serupa dari Ummu Habibah. Hadits ini hasan shahih. Seperti itulah yang diriwayatkan oleh beberapa perawi dari Muhammad bin 'Amru Sepertinya, mereka berkata: Dari Muhammad bin 'Amru dari ayahnya dari Bilal bin Al Harits dan hadits ini diriwayatkan oleh [Malik] dari [Muhammad bin 'Amru] dari [ayahnya] dari [Bilal bin Al Harits], ia tidak menyebut dalam riwayat ini; Dari kakeknya."},"2234":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ سُلَيْمَانَ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ كَانَتْ الدُّنْيَا تَعْدِلُ عِنْدَ اللَّهِ جَنَاحَ بَعُوضَةٍ مَا سَقَى كَافِرًا مِنْهَا شَرْبَةَ مَاءٍوَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ صَحِيحٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami ['Abdul Hamid bin Sulaiman] dari [Abu Hazim] dari [Sahl bin Sa'ad] dia berkata bahwa Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Seandainya dunia itu di sisi Allah sebanding dengan sayap nyamuk tentu Allah tidak mau memberi orang orang kafir walaupun hanya seteguk air.\" Dan dalam bab ini ada hadits dari Abu Hurairah, Abu Isa berkata: Hadits ini shahih gharib dari jalur sanad ini."},"2235":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ نَصْرٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ مُجَالِدٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنْ الْمُسْتَوْرِدِ بْنِ شَدَّادٍ قَالَكُنْتُ مَعَ الرَّكْبِ الَّذِينَ وَقَفُوا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى السَّخْلَةِ الْمَيِّتَةِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَرَوْنَ هَذِهِ هَانَتْ عَلَى أَهْلِهَا حِينَ أَلْقَوْهَا قَالُوا مِنْ هَوَانِهَا أَلْقَوْهَا يَا رَسُولَ اللَّهِ قَالَ فَالدُّنْيَا أَهْوَنُ عَلَى اللّ��هِ مِنْ هَذِهِ عَلَى أَهْلِهَاوَفِي الْبَاب عَنْ جَابِرٍ وَابْنِ عُمَرَ قَالَ أَبُو عِيسَى حَدِيثُ الْمُسْتَوْرِدِ حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Suwaid bin Nashr] telah mengkhabarkan kepada kami ['Abdullah bin Al Mubarak] dari [Mujalid] dari [Qais bin Abu Hazim] dari [Al Mustaurid bin Syaddad] berkata: Aku pernah bersama rombongan yang berhenti bersama Rasulullah Shallallahu 'alahi wa Salam didekat bangkai anak kambing lalu Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Tahukah kalian, bangkai ini hina bagi pemiliknya saat ia membuangnya.\" Mereka berkata: Karena hinanya itulah mereka membuangnya, wahai Rasulullah. beliau bersabda: \"Dunia itu lebih hina bagi Allah dari pada bangkai ini bagi pemiliknya.\" Dalam hal ini ada hadits serupa dari Jabir dan Ibnu 'Umar. Berkata Abu Isa: Hadits Al Mustaurid adalah hadits hasan."},"2236":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ حَاتِمٍ الْمُكْتِبُ حَدَّثَنَا عَلِيُّ بْنُ ثَابِتٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ ثَابِتِ بْنِ ثَوْبَانَ قَال سَمِعْتُ عَطَاءَ بْنَ قُرَّةَ قَال سَمِعْتُ عَبْدَ اللَّهِ بْنَ ضَمْرَةَ قَال سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَلَا إِنَّ الدُّنْيَا مَلْعُونَةٌ مَلْعُونٌ مَا فِيهَا إِلَّا ذِكْرُ اللَّهِ وَمَا وَالَاهُ وَعَالِمٌ أَوْ مُتَعَلِّمٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Muhammad bin Hatim Al Muktib] telah menceritakan kepada kami ['Ali bin Tsabit] telah menceritakan kepada kami [Abdurrahman bin Tsabit bin Tsauban] berkata: Aku telah mendengar ['Atho` bin Qurroh] berkata: aku telah mendengar ['Abdullah bin Dlamrah] berkata: aku telah mendengar [Abu Hurairah] berkata: aku mendengar Rasulullah Shallallahu 'alaihi wa salam bersabda: \" Ketahuilah sesungguhnya dunia itu terlaknat dan segala isinya pun juga terlaknat, kecuali dzikir kepada Allah dan apa yang berkaitan dengannya, dan orang yang alim atau orang yang belajar.\" Abu Isa berkata: Hadits ini hasan gharib."},"2237":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ حَدَّثَنَا قَيْسُ بْنُ أَبِي حَازِمٍ قَال سَمِعْتُ مُسْتَوْرِدًا أَخَا بَنِي فِهْرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا الدُّنْيَا فِي الْآخِرَةِ إِلَّا مِثْلُ مَا يَجْعَلُ أَحَدُكُمْ إِصْبَعَهُ فِي الْيَمِّ فَلْيَنْظُرْ بِمَاذَا يَرْجِعُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَإِسْمَعِيلُ بْنُ أَبِي خَالِدٍ يُكْنَى أَبَا عَبْدِ اللَّهِ وَوَالِدُ قَيْسٍ أَبُو حَازِمٍ اسْمُهُ عَبْدُ بْنُ عَوْفٍ وَهُوَ مِنْ الصَّحَابَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami [Isma'il bin Abu Khalid] telah menceritakan kepada kami [Qais bin Abu Hazim] bekata: Aku mendengar [Mustaurid] dari Bani Fihr, berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Dunia bagi akhirat itu tidak lain seperti salah seorang dari kalian mencelupkan jarinya ke laut lalu perhatikanlah apa yang dibawa kembali.\" Berkata Abu Isa: Hadits ini hasan shahih. Isma'il bin Abu Khalid kuniahnya Abu 'Abdullah dan ayah Qais Abu Hazim namnya 'Abdu bin 'Auf, salah seorang sahabat."},"2238":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الدُّنْيَا سِجْنُ الْمُؤْمِنِ وَجَنَّةُ الْكَافِرِوَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami ['Abdul 'Aziz bin Muhammad] dari [Al 'Alla` bin Abdurrahman] dari [ayahnya] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Dunia adalah penjara bagi orang mu`min dan surga bagi orang kafir.\" Dalam hal ini ada hadits serupa dari 'Abdullah bin 'amru. Berkata Abu Isa: Hadits ini hasan shahih."},"2239":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا عُبَادَةُ بْنُ مُسْلِمٍ حَدَّثَنَا يُونُسُ بْنُ خَبَّابٍ عَنْ سَعِيدٍ الطَّائِيِّ أَبِي الْبَخْتَرِيِّ أَنَّهُ قَالَ حَدَّثَنِي أَبُو كَبْشَةَ الْأَنَّمَارِيُّ أَنَّهُسَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ ثَلَاثَةٌ أُقْسِمُ عَلَيْهِنَّ وَأُحَدِّثُكُمْ حَدِيثًا فَاحْفَظُوهُ قَالَ مَا نَقَصَ مَالُ عَبْدٍ مِنْ صَدَقَةٍ وَلَا ظُلِمَ عَبْدٌ مَظْلَمَةً فَصَبَرَ عَلَيْهَا إِلَّا زَادَهُ اللَّهُ عِزًّا وَلَا فَتَحَ عَبْدٌ بَابَ مَسْأَلَةٍ إِلَّا فَتَحَ اللَّهُ عَلَيْهِ بَابَ فَقْرٍ أَوْ كَلِمَةً نَحْوَهَا وَأُحَدِّثُكُمْ حَدِيثًا فَاحْفَظُوهُ قَالَ إِنَّمَا الدُّنْيَا لِأَرْبَعَةِ نَفَرٍ عَبْدٍ رَزَقَهُ اللَّهُ مَالًا وَعِلْمًا فَهُوَ يَتَّقِي فِيهِ رَبَّهُ وَيَصِلُ فِيهِ رَحِمَهُ وَيَعْلَمُ لِلَّهِ فِيهِ حَقًّا فَهَذَا بِأَفْضَلِ الْمَنَازِلِ وَعَبْدٍ رَزَقَهُ اللَّهُ عِلْمًا وَلَمْ يَرْزُقْهُ مَالًا فَهُوَ صَادِقُ النِّيَّةِ يَقُولُ لَوْ أَنَّ لِي مَالًا لَعَمِلْتُ بِعَمَلِ فُلَانٍ فَهُوَ بِنِيَّتِهِ فَأَجْرُهُمَا سَوَاءٌ وَعَبْدٍ رَزَقَهُ اللَّهُ مَالًا وَلَمْ يَرْزُقْهُ عِلْمًا فَهُوَ يَخْبِطُ فِي مَالِهِ بِغَيْرِ عِلْمٍ لَا يَتَّقِي فِيهِ رَبَّهُ وَلَا يَصِلُ فِيهِ رَحِمَهُ وَلَا يَعْلَمُ لِلَّهِ فِيهِ حَقًّا فَهَذَا بِأَخْبَثِ الْمَنَازِلِ وَعَبْدٍ لَمْ يَرْزُقْهُ اللَّهُ مَالًا وَلَا عِلْمًا فَهُوَ يَقُولُ لَوْ أَنَّ لِي مَالًا لَعَمِلْتُ فِيهِ بِعَمَلِ فُلَانٍ فَهُوَ بِنِيَّتِهِ فَوِزْرُهُمَا سَوَاءٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Isma'il] telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami ['Ubadah bin Muslim] telah menceritakan kepada kami [Yunus bin Khabbab] dari [Sa'id Ath Tho'i Abu Al Bakhtari] berkata: telah menceritakan kepadaku [Abu Kabsyah Al Anmari] ia mendengar Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Tiga hal, aku bersumpah atasnya dan aku akan mengatakan suatu hal pada kalian, hendaklah kalian menjaganya.\" Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Tidaklah harta seorang berkurang karena sedekah, tidaklah seseorang diperlakukan secara lalim lalu ia bersabar melainkan Allah akan menambahkan kemuliaan untuknya dan tidaklah seorang hamba membuka pintu minta-minta melainkan Allah akan membukakan pintu kemiskinan untuknya -atau kalimat sepertinya- dan aku akan mengatakan suatu hal pada kalian, hendaklah kaian menjaganya.\" Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Sesungguhnya dunia itu untuk empat orang; Pertama, seorang hamba yang dikarunia Allah harta dan ilmu, dengan ilmu ia bertakwa kepada Allah dan dengan harta ia menyambung silaturrahim dan ia mengetahui Allah memiliki hak padanya dan ini adalah tingkatan yang paling baik, Kedua, selanjutnya hamba yang diberi Allah ilmu tapi tidak diberi harta, niatnya tulus, ia berkata: Andai saja aku memiliki harta niscaya aku akan melakukan seperti amalan si fulan, maka ia mendapatkan apa yang ia niatkan, pahala mereka berdua sama, Ketiga, selanjutnya hamba yang diberi harta oleh Allah tapi tidak diberi ilmu, ia melangkah serampangan tanpa ilmu menggunakan hartanya, ia tidak takut kepada Rabbinya dengan harta itu dan tidak menyambung silaturrahimnya serta tidak mengetahui hak Allah padanya, ini adalah tingkatan terburuk, Keempat, selanjutnya orang yang tidak diberi Allah harta atau pun ilmu, ia bekata: Andai aku punya harta tentu aku akan melakukan seperti yang dilakukan si fulan yang serampangan meneglola hartanya, dan niatnya benar, dosa keduanya sama.\" Berkata Abu Isa: hadits ini hasan shahih."},"2240":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ بَشِيرٍ أَبِي إِسْمَعِيلَ عَنْ سَيَّارٍ عَنْ طَارِقِ بْنِ شِهَابٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ نَزَلَتْ بِهِ فَاقَةٌ فَأَنْزَلَهَا بِالنَّاسِ لَمْ تُسَدَّ فَاقَتُهُ وَمَنْ نَزَلَتْ بِهِ فَاقَةٌ فَأَنْزَلَهَا بِاللَّهِ فَيُوشِكُ اللَّهُ لَهُ بِرِزْقٍ عَاجِلٍ أَوْ آجِلٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Sufyan] dari [Basyir Abu Isma'il] dari [Sayyar] dari [Thariq bin Syihab] dari ['Abdullah bin Mas'ud] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Barangsiapa tertimpa kesusahan lalu mengeluh-ngeluhkannya kepada manusia maka kesusahannya tidak akan tertutupi dan barangsiapa tertimpa kesusahan lalu mengeluh-ngeluhkan kepada Allah, hampir saja Allah memberinya rizki, cepat atau lambat.\" Berkata Abu Isa: Hadits ini hasan shahih gharib."},"2241":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا سُفْيَانُ عَنْ مَنْصُورٍ وَالْأَعْمَشِ عَنْ أَبِي وَائِلٍ قَالَجَاءَ مُعَاوِيَةُ إِلَى أَبِي هَاشِمِ بْنِ عُتْبَةَ وَهُوَ مَرِيضٌ يَعُودُهُ فَقَالَ يَا خَالُ مَا يُبْكِيكَ أَوَجَعٌ يُشْئِزُكَ أَمْ حِرْصٌ عَلَى الدُّنْيَا قَالَ كُلٌّ لَا وَلَكِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَهِدَ إِلَيَّ عَهْدًا لَمْ آخُذْ بِهِ قَالَ إِنَّمَا يَكْفِيكَ مِنْ جَمِيعِ الْمَالِ خَادِمٌ وَمَرْكَبٌ فِي سَبِيلِ اللَّهِ وَأَجِدُنِي الْيَوْمَ قَدْ جَمَعْتُقَالَ أَبُو عِيسَى وَقَدْ رَوَى زَائِدَةُ وَعَبِيدَةُ بْنُ حُمَيْدٍ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ عَنْ سَمُرَةَ بْنِ سَهْمٍ قَالَ دَخَلَ مُعَاوِيَةُ عَلَى أَبِي هَاشِمٍ فَذَكَرَ نَحْوَهُ وَفِي الْبَاب عَنْ بُرَيْدَةَ الْأَسْلَمِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami ['Abdur Razzaq] telah menceritakan kepada kami [Sufyan] dari [Manshur] dan [Al A'masy] dari [Abu Wa'il] dia berkata bahwa Mua'wiyah datang kepada [Abu Hasyim bin 'Utbah] yang sedang sakit dia datang menjenguknya lalu berkata: Wahai paman apa yang membuatmu menangis apakah rasa sakit yang menggelisahkanmu atau karena ketamakan terhadap dunia? dia menjawab: Semuanya bukan, akan tetapi karena Rasulullah pernah memberikan wasiat kepadaku namun aku tidak melakukannya, beliau bersabda: \"Cukuplah bagimu dari semua harta; pelayan, kendaraan untuk di jalan Allah dan pada hari ini aku telah dapat mengumpulkannya. Abu Isa berkata: [Za'idah] dan [Ubaidah bin Humaid] meriwayatkan dari [Manshur] dari [Abu Wa'il] dari [Samurah bin Sahm] dia berkata: Mu'awiyah datang menemui [Abu Hasyim], kemudian dia menyebutkan hadits yang semakna, dan dalam bab ini ada hadits dari Buraidah Al Aslami dari Nabi Shallallahu 'alaihi wa Salam."},"2242":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ شِمْرِ بْنِ عَطِيَّةَ عَنْ الْمُغِيرَةِ بْنِ سَعْدِ بْنِ الْأَخْرَمِ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَتَّخِذُوا الضَّيْعَةَ فَتَرْغَبُوا فِي الدُّنْيَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Syimr bin 'Athiyyah] dari [Al Mughirah bin Sa'ad bin Al Akhram] dari [ayahnya] dari ['Abdullah bin Mas'ud] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Janganlah kalian berkutat pada ladang dan perdagangan, sehingga kalian menyukai dunia.\" Berkata Abu Isa: Hadits ini hasan."},"2243":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا زَيْدُ بْنُ حُبَابٍ عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ عَنْ عَمْرِو بْنِ قَيْسٍ عَنْ عَبْدِ اللَّهِ بْنِ بُسْرٍأَنَّ أَعْرَابِيًّا قَالَ يَا رَسُولَ اللَّهِ مَنْ خَيْرُ النَّاسِ قَالَ مَنْ طَالَ عُمُرُهُ وَحَسُنَ عَمَلُهُوَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَجَابِرٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Zaid bin Hubab] dari [Mu'awiyah bin Shalih] dari ['Amru bin Qais] dari ['Abdullah bin Busr], seorang badui bertanya: Wahai Rasulullah, siapa orang terbaik itu? Rasulullah Shallallahu 'alahi wa Salam menjawab: \"Orang yang panjang umurnya dan baik amalnya.\" Dalam hal ini ada hadits serupa dari Abu Hurairah dan Jabir. Berkata Abu Isa: Hadits ini hasan gharib melalui jalur sanad ini."},"2244":{"ar":"حَدَّثَنَا أَبُو حَفْصٍ عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا شُعْبَةُ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرَةَ عَنْ أَبِيهِأَنَّ رَجُلًا قَالَ يَا رَسُولَ اللَّهِ أَيُّ النَّاسِ خَيْرٌ قَالَ مَنْ طَالَ عُمُرُهُ وَحَسُنَ عَمَلُهُ قَالَ فَأَيُّ النَّاسِ شَرٌّ قَالَ مَنْ طَالَ عُمُرُهُ وَسَاءَ عَمَلُهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Abu Hafsh 'Amru bin 'Ali] telah menceritakan kepada kami [Khalid bin Al Harits] telah menceritakan kepada kami [Syu'bah] dari ['Ali bin Zaid] dari [Abdurrahman bin Abu Bakrah] dari [ayahnya], seseorang bertanya: siapa orang terbaik itu? Rasulullah Shallallahu 'alahi wa Salam menjawab: \"Orang ya ng panjang umurnya dan baik amalnya.\" Ia bertanya: Lalu siapa orang yang terburuk itu? Rasulullah Shallallahu 'alahi wa Salam menjawab: \"Orang yang panjang umurnya tapi buruk amalnya.\" Berkata Abu Isa: Hadits ini hasan shahih."},"2245":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعِيدٍ الْجَوْهَرِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ رَبِيعَةَ عَنْ كَامِلٍ أَبِي الْعَلَاءِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عُمْرُ أُمَّتِي مِنْ سِتِّينَ سَنَةً إِلَى سَبْعِينَ سَنَةًقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ حَدِيثِ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ وَقَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ أَبِي هُرَيْرَةَ","id":"Telah menceritakan kepada kami [Ibrahim bin Sa'id Al Jauhari] telah menceritakan kepada kami [Muhammad bin Rabi'ah] dari [Kamil Abul Ala'] dari [Abu Shalih] dari [Abu Hurairah] dia berkata bahwa Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Umur ummatku berkisar antara enam puluh sampai tujuh puluh tahun.\" Abu Isa berkata: Hadits ini hasan gharib dari hadits Abu Shalih dari Abu Hurairah, dan hadits ini diriwayatkan juga dari jalur sanad yang banyak dari Abu Hurairah."},"2246":{"ar":"حَدَّثَنَا عَبَّاسُ بْنُ مُحَمَّدٍ الدُّورِيُّ حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُمَرَ الْعُمَرِيُّ عَنْ سَعْدِ بْنِ سَعِيدٍ الْأَنْصَارِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقُومُ السَّاعَةُ حَتَّى يَتَقَارَبَ الزَّمَانُ فَتَكُونُ السَّنَةُ كَالشَّهْرِ وَالشَّهْرُ كَالْجُمُعَةِ وَتَكُونُ الْجُمُعَةُ كَالْيَوْمِ وَيَكُونُ الْيَوْمُ كَالسَّاعَةِ وَتَكُونُ السَّاعَةُ كَالضَّرَمَةِ بِالنَّارِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَسَعْدُ بْنُ سَعِيدٍ هُوَ أَخُو يَحْيَى بْنِ سَعِيدٍ","id":"Telah menceritakan kepada kami ['Abbas bin Muhammad Ad Dauri] telah menceritakan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami ['Abdullah bin 'Umar Al 'Umari] dari [Sa'ad bin Sa'id Al Anshari] dari [Anas bin Malik] dia berkata bahwa Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Kiamat tidak akan terjadi sampai waktu terasa pendek (ringkas), satu tahun menjadi seperti satu bulan, satu bulan menjadi seperti satu jum'at, satu Jum'at menjadi seperti satu hari, satu hari menjadi seperti sesaat dan sesaat menjadi seperti sambaran api.\" Abu Isa berkata: Hadits ini gharib dari jalur sanad ini, adapun Sa'ad bin Sa'id dia adalah saudara Yahya bin Sa'id."},"2247":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو أَحْمَدَ حَدَّثَنَا سُفْيَانُ عَنْ لَيْثٍ عَنْ مُجَاهِدٍ عَنْ ابْنِ عُمَرَ قَالَأَخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِبَعْضِ جَسَدِي فَقَالَ كُنْ فِي الدُّنْيَا كَأَنَّكَ غَرِيبٌ أَوْ عَابِرُ سَبِيلٍ وَعُدَّ نَفْسَكَ فِي أَهْلِ الْقُبُورِفَقَالَ لِي ابْنُ عُمَرَ إِذَا أَصْبَحْتَ فَلَا تُحَدِّثْ نَفْسَكَ بِالْمَسَاءِ وَإِذَا أَمْسَيْتَ فَلَا تُحَدِّثْ نَفْسَكَ بِالصَّبَاحِ وَخُذْ مِنْ صِحَّتِكَ قَبْلَ سَقَمِكَ وَمِنْ حَيَاتِكَ قَبْلَ مَوْتِكَ فَإِنَّكَ لَا تَدْرِي يَا عَبْدَ اللَّهِ مَا اسْمُكَ غَدًا قَالَ أَبُو عِيسَى وَقَدْ رَوَى هَذَا الْحَدِيثَ الْأَعْمَشُ عَنْ مُجَاهِدٍ عَنْ ابْنِ عُمَرَ نَحْوَهُ حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ الضَّبِّيُّ الْبَصْرِيُّ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ لَيْثٍ عَنْ مُجَاهِدٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Ahmad] telah menceritakan kepada kami [Sufyan] dari [Laits] dari [Mujahid] dari [Ibnu 'Umar] berkata: Rasulullah Shallallahu 'alahi wa Salam meraih sebagaian badanku lalu bersabda: Jadilah didunia seperti orang asing atau pelintas jalan dan anggaplah dirimu termasuk penghuni kubur.\" Ibnu 'Umar berkata kepadaku: Bila di waktu pagi, jangan kau bisiku dirimu bisa peroleh sore hari dan bila di waktu sore jangan bisiki dirimu bisa kau peroleh waktu pagi, manfaatkan kesehatanku sebelum kau sakit dan hidupmu sebelum kau mati karena sesungguhnya kau tidak tahu wahai hamba Allah siapa namamu esok.\" Berkata Abu Isa: [Al A'masy] meriwayatkan hadits ini dari [Mujahid] dari [Ibnu 'Umar] sepertinya. Telah menceritakan kepada kami [Ahmad bin 'Abdah Adl Dlabyi Al Bashri] telah menceritakan kepada kami [Hammad bin Zaid] dari [Laits] dari [Mujahid] dari [Ibnu 'Umar] dari nabi Shallallahu 'alaihi wa Salam Sepertinya."},"2248":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ نَصْرٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي بَكْرِ بْنِ أَنَسٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا ابْنُ آدَمَ وَهَذَا أَجَلُهُ وَوَضَعَ يَدَهُ عِنْدَ قَفَاهُ ثُمَّ بَسَطَهَا فَقَالَ وَثَمَّ أَمَلُهُ وَثَمَّ أَمَلُهُ وَثَمَّ أَمَلُهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَفِي الْبَاب عَنْ أَبِي سَعِيدٍ","id":"Telah menceritakan kepada kami [Suwaid bin Nashr] telah mengkhabarkan kepada kami ['Abdullah bin Al Mubarak] dari [Hammad bin Salamah] dari ['Ubaidullah bin Abu Bakar bin Anas] dari [Anas bin Malik] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Ini adalah manusia dan ini adalah ajalnya\" beliau meletakkan tangan ke tengkuk kemudian beliau membentangkannya lalu bersabda: \"Dan di sana angan-angannya, di sana angan-angannya.\" Berkata Abu Isa: Hadits ini hasan shahih dan halam hal ini ada hadits serupa dari Abu Sa'id."},"2249":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي السَّفَرِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَمَرَّ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ نُعَالِجُ خُصًّا لَنَا فَقَالَ مَا هَذَا فَقُلْنَا قَدْ وَهَى فَنَحْنُ نُصْلِحُهُ قَالَ مَا أَرَى الْأَمْرَ إِلَّا أَعْجَلَ مِنْ ذَلِكَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَأَبُو السَّفَرِ اسْمُهُ سَعِيدُ بْنُ يُحْمِدَ وَيُقَالُ ابْنُ أَحْمَدَ الثَّوْرِيُّ","id":"Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu As Safar] dari ['Abdullah bin 'Amru] berkata: Rasulullah Shallallahu 'alahi wa Salam melintasi kami saat kami memperbaiki gubug milik kami, beliau bertanya: \"Apa ini?\" kami menjawab: Gubug ini sudah lemah, kami memperbaikinya. Beliau bersabda: \"Aku tidak melihat kematian melainkan lebih cepat dari gubuk itu roboh\" Berkata Abu Isa: Hadits ini hasan shahih. Abu As Safar namanya Sa'id bin Yuhmad dan disebut Ibnu Ahmad Ats Tsauri."},"2250":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا الْحَسَنُ بْنُ سَوَّارٍ حَدَّثَنَا لَيْثُ بْنُ سَعْدٍ عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ جُبَيْرِ بْنِ نُفَيْرٍ حَدَّثَهُ عَنْ أَبِيهِ عَنْ كَعْبِ بْنِ عِيَاضٍ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ لِكُلِّ أُمَّةٍ فِتْنَةً وَفِتْنَةُ أُمَّتِي الْمَالُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ إِنَّمَا نَعْرِفُهُ مِنْ حَدِيثِ مُعَاوِيَةَ بْنِ صَالِحٍ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Al Hasan bin Sawwar] telah menceritakan kepada kami [Laits bin Sa'ad] dari [Mu'awiyah bin Shalih], [Abdurrahman bin Jubair bin Nufair] barceita kepadanya dari [ayahnya] dari [Ka'ab bin 'Iyadl] berkata: Aku mendengar nabi Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya setiap ummat itu memiliki fitnah dan fitnah ummatku adalah harta.\" Berkata Abu Isa: Hadits ini hasan shahih gharib, kami hanya mengetahuinya dari hadits Mu'awiyah bin Shalih."},"2251":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي زِيَادٍ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ بْنِ سَعْدٍ حَدَّثَنَا أَبِي عَنْ صَالِحِ بْنِ كَيْسَانَ عَنْ ابْنِ شِهَابٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ كَانَ لِابْنِ آدَمَ وَادِيَانِ مِنْ ذَهَبٍ لَأَحَبَّ أَنْ يَكُونَ لَهُ ثَالِثٌ وَلَا يَمْلَأُ فَاهُ إِلَّا التُّرَابُ وَيَتُوبُ اللَّهُ عَلَى مَنْ تَابَوَفِي الْبَاب عَنْ أُبَيِّ بْنِ كَعْبٍ وَأَبِي سَعِيدٍ وَعَائِشَةَ وَابْنِ الزُّبَيْرِ وَأَبِي وَاقِدٍ وَجَابِرٍ وَابْنِ عَبَّاسٍ وَأَبِي هُرَيْرَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami ['Abdullah bin Abu Ziyad] telah menceritakan kepada kami [Ya'qub bin Ibrahim bin Sa'ad] telah menceritakan kepada kami [ayahku] dari [Shalih bin Kaisan] dari [Ibnu Syihab] dari [Anas bin Malik] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Andai anak Adam memiliki dua lembah emas, nicaya ia menginginkan lembah lagi dan tidak ada yang memenuhi mulutnya kecuali tanah dan Allah menerima taubat orang yang bertubat.\" Dalam hal ini ada hadits serupa dari Ubai bin Ka'ab, Abu Sa'id, 'A`isyah, Ibnu Az Zubair, Abu Waqid, Jabir, Ibnu 'Abbas dan Abu Hurairah. Berkata Abu Isa: Hadits ini hasan shahih gharib melalui jalur sanad ini."},"2252":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ عَجْلَانَ عَنْ الْقَعْقَاعِ بْنِ حَكِيمٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَلْبُ الشَّيْخِ شَابٌّ عَلَى حُبِّ اثْنَتَيْنِ طُولِ الْحَيَاةِ وَكَثْرَةِ الْمَالِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari [Ibnu 'Ajlan] dari [Al Qa'qa' bin Hakim] dari [Abu Shalih] dari [Abu Hurairah], nabi Shallallahu 'alaihi wa Salam bersabda: \"Orang tua berhati muda dalam mencintai dua hal; umur panjang dan banyak harta.\" Berkata Abu Isa: Hadits ini hasan shahih."},"2253":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَهْرَمُ ابْنُ آدَمَ وَيَشِبُّ مِنْهُ اثْنَتَانِ الْحِرْصُ عَلَى الْعُمُرِ وَالْحِرْصُ عَلَى الْمَالِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abu 'Awanah] dari [Qatadah] dari [Anas bin Malik] Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Anak Adam tua sementara itu ada dua hal yang membuatnya merasa muda; ketamakan atas usia dan ketamakaan atas harta.\" Abu Isa berkata: Hadits ini hasan shahih."},"2254":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُبَارَكِ حَدَّثَنَا عَمْرُو بْنُ وَاقِدٍ حَدَّثَنَا يُونُسُ بْنُ حَلْبَسٍ عَنْ أَبِي إِدْرِيسَ الْخَوْلَانِيِّ عَنْ أَبِي ذَرٍّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الزَّهَادَةُ فِي الدُّنْيَا لَيْسَتْ بِتَحْرِيمِ الْحَلَالِ وَلَا إِضَاعَةِ الْمَالِ وَلَكِنَّ الزَّهَادَةَ فِي الدُّنْيَا أَنْ لَا تَكُونَ بِمَا فِي يَدَيْكَ أَوْثَقَ مِمَّا فِي يَدَيْ اللَّهِ وَأَنْ تَكُونَ فِي ثَوَابِ الْمُصِيبَةِ إِذَا أَنْتَ أُصِبْتَ بِهَا أَرْغَبَ فِيهَا لَوْ أَنَّهَا أُبْقِيَتْ لَكَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ وَأَبُو إِدْرِيسَ الْخَوْلَانِيُّ اسْمُهُ عَائِذُ اللَّهِ بْنُ عَبْدِ اللَّهِ وَعَمْرُو بْنُ وَاقِدٍ مُنْكَرُ الْحَدِيثِ","id":"Telah menceritakan kepada kami ['Abdullah bin Abdurrahman] telah menceritakan kepada kami [Muhammad bin Al Mubarak] telah mengkhabarkan kepada kami ['Amru bin Waqid] telah menceritakan kepada kami [Yunus bin Halbas] dari [Abu Idris Al Khaulani] dari [Abu Dzarr] dari Nabi Shallallahu 'alaihi wa Salam beliau bersabda: \"Zuhud terhadap dunia bukan berarti mengharamkan yang halal dan bukan juga menyia-nyiakan harta, akan tetapi zuhud terhadap dunia adalah keyakinan apa yang ada di tanganmu tidak lebih kuat dari apa yang ada di tangan Allah dan engkau berada dalam pahala musibah jika tertimpa musibah, lebih kau senangi daripada jika itu tetap ada padamu.\" Abu Isa berkata: Hadits ini gharib, kami tidak mengetahuinya kecuali dari jalur sanad ini, adapun Abu Idris Al Khaulani namanya adalah A'idzullah bin 'Abdullah, sedangkan 'Amru bin Waqid dia adalah seorang yang munkar haditsnya."},"2255":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنَا حُرَيْثُ بْنُ السَّائِبِ قَال سَمِعْتُ الْحَسَنَ يَقُولُ حَدَّثَنِي حُمْرَانُ بْنُ أَبَانَ عَنْ عُثْمَانَ بْنِ عَفَّانَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ لِابْنِ آدَمَ حَقٌّ فِي سِوَى هَذِهِ الْخِصَالِ بَيْتٌ يَسْكُنُهُ وَثَوْبٌ يُوَارِي عَوْرَتَهُ وَجِلْفُ الْخُبْزِ وَالْمَاءِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَهُوَ حَدِيثُ الْحُرَيْثِ بْنِ السَّائِبِ وَسَمِعْتُ أَبَا دَاوُدَ سُلَيْمَانَ بْنَ سَلْمٍ الْبَلْخِيَّ يَقُولُ قَالَ النَّضْرُ بْنُ شُمَيْلٍ جِلْفُ الْخُبْزِ يَعْنِي لَيْسَ مَعَهُ إِدَامٌ","id":"Telah menceritakan kepada kami ['Abd bin Humaid] telah menceritakan kepada kami ['Abdush Shamad bin 'Abdul Warits] telah menceritakan kepada kami [Huraits bin As Sa`ib] berkata: Aku mendengar [Al Hasan] berkata: telah menceritakan kepadaku [Humran bin Aban] dari ['Utsman bin 'Affan], nabi Shallallahu 'alaihi wa Salam bersabda: \"Anak Adam tidak memiliki hak selain dalam hal-hal berikut; rumah yang ia tinggali, pakaian yang menutupi auratnya, roti keras dan air.\" Berkata Abu Isa: Hadits ini hasan shahih, hadits Al Huraits bin As Sa`ib dan aku mendengar Abu Dawud Sulaiman bin Salmn Al Balkhi berkata: Berkata An Nadl bin Syumail: Roti keras maksudnya tanpa lauk."},"2256":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ مُطَرِّفٍ عَنْ أَبِيهِأَنَّهُ انْتَهَى إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَقُولُ{ أَلْهَاكُمْ التَّكَاثُرُ }قَالَ يَقُولُ ابْنُ آدَمَ مَالِي مَالِي وَهَلْ لَكَ مِنْ مَالِكَ إِلَّا مَا تَصَدَّقْتَ فَأَمْضَيْتَ أَوْ أَكَلْتَ فَأَفْنَيْتَ أَوْ لَبِسْتَ فَأَبْلَيْتَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Wahb bin Jarir] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Muththarrif] dari [ayahnya], ia tiba di hadapan nabi Shallallahu 'alaihi wa Salam, beliau bersabda: \"Bermegah-megahan telah melalaikanmu.\" Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Anak Adam berkata: Hartaku, hartaku. Kau tidak memiliki harta selain yang kau sedekahkan lalu kau habiskan, yang kau makan lalu kau habiskan atau yang kau pakai hingga usang.\" Berkata Abu Isa: Hadits ini hasan shahih."},"2257":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عُمَرُ بْنُ يُونُسَ هُوَ الْيَمَامِيُّ حَدَّثَنَا عِكْرِمَةُ بْنُ عَمَّارٍ حَدَّثَنَا شَدَّادُ بْنُ عَبْدِ اللَّهِ قَال سَمِعْتُ أَبَا أُمَامَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا ابْنَ آدَمَ إِنَّكَ إِنْ تَبْذُلْ الْفَضْلَ خَيْرٌ لَكَ وَإِنْ تُمْسِكْهُ شَرٌّ لَكَ وَلَا تُلَامُ عَلَى كَفَافٍ وَابْدَأْ بِمَنْ تَعُولُ وَالْيَدُ الْعُلْيَا خَيْرٌ مِنْ الْيَدِ السُّفْلَىقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَشَدَّادُ بْنُ عَبْدِ اللَّهِ يُكْنَى أَبَا عَمَّارٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami ['Umar bin Yunus Al Yamami] telah menceritakan kepada kami ['Ikrimah bin 'Ammar] telah menceritakan kepada kami [Syaddad bin 'Abdullah] berkata: Aku mendengar [Abu Umamah] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Hai anak cucu Adam, sesungguhnya bila kau memberikan harta lebihan itu lebih baik bagimu dan bila kau menahannya itu buruk bagimu, dan kamu tidak tercela jika menggunakan harta sekedar cukup (wajar), mulailah dari orang yang menjadi tanggunganmu dan tangan di atas itu lebih baik dari tangan di bawah.\" Berkata Abu Isa: Hadits ini hasan shahih, Syaddad bin 'Abdullah kuniahnya Abu 'Ammar."},"2258":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ سَعِيدٍ الْكِنْدِيُّ حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ حَيْوَةَ بْنِ شُرَيْحٍ عَنْ بَكْرِ بْنِ عَمْرٍو عَنْ عَبْدِ اللَّهِ بْنِ هُبَيْرَةَ عَنْ أَبِي تَمِيمٍ الْجَيْشَانِيِّ عَنْ عُمَرَ بْنِ الْخَطَّابِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ أَنَّكُمْ كُنْتُمْ تَوَكَّلُونَ عَلَى اللَّهِ حَقَّ تَوَكُّلِهِ لَرُزِقْتُمْ كَمَا يُرْزَقُ الطَّيْرُ تَغْدُو خِمَاصًا وَتَرُوحُ بِطَانًاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ وَأَبُو تَمِيمٍ الْجَيْشَانِيُّ اسْمُهُ عَبْدُ اللَّهِ بْنُ مَالِكٍ","id":"Telah menceritakan kepada kami ['Ali bin Sa'id Al Kindi] telah menceritakan kepada kami [Ibnu Al Mubarak] dari [Haiwah bin Syuraih] dari [Bakr bin 'Amru] dari ['Abdullah bin Hubairah] dari [Abu Tamim Al Jaisyani] dari [Umar bin Al Khaththab] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Andai saja kalian bertawakal kepada Allah dengan sebenarnya, niscaya kalian diberi rizki seperti rizkinya burung, pergi dengan perut kosong di pagi hari dan pulang di sore hari dengan perut terisi penuh.\" Berkata Abu Isa: Hadits ini hasan shahih, kami hanya mengetahuinya melalui jalur sanad ini dan nama Abu Tamim Al Jaisyani adalah 'Abdullah bin Malik."},"2259":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو دَاوُدَ الطَّيَالِسِيُّ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ أَخَوَانِ عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَانَ أَحَدُهُمَا يَأْتِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْآخَرُ يَحْتَرِفُ فَشَكَا الْمُحْتَرِفُ أَخَاهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَعَلَّكَ تُرْزَقُ بِهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Abu Daud Ath Thayalisi] telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Anas bin Malik] dia berkata: Ada dua orang lelaki bersaudara pada masa Nabi Shallallahu 'alaihi wa Salam, salah satunya datang kepada Nabi Shallallahu 'alaihi wa Salam (maksudnya untuk memburu ilmu) dan yang satunya lagi bekerja, maka saudaranya yang bekerja mengadukan perihal saudaranya kepada Nabi Shallallahu 'alaihi wa Salam, beliau menjawab: \"Bisa jadi kamu diberi rizki karena dia.\" Abu Isa berkata: hadits ini hasan shahih."},"2260":{"ar":"حَدَّثَنَا عَمْرُو بْنُ مَالِكٍ وَمَحْمُودُ بْنُ خِدَاشٍ الْبَغْدَادِيُّ قَالَا حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي شُمَيْلَةَ الْأَنْصَارِيُّ عَنْ سَلَمَةَ بْنِ عُبَيْدِ اللَّهِ بْنِ مِحْصَنٍ الْخَطْمِيِّ عَنْ أَبِيهِ وَكَانَتْ لَهُ صُحْبَةٌ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَصْبَحَ مِنْكُمْ آمِنًا فِي سِرْبِهِ مُعَافًى فِي جَسَدِهِ عِنْدَهُ قُوتُ يَوْمِهِ فَكَأَنَّمَا حِيزَتْ لَهُ الدُّنْيَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ مَرْوَانَ بْنِ مُعَاوِيَةَ وَحِيزَتْ جُمِعَتْ حَدَّثَنَا بِذَلِكَ مُحَمَّدُ بْنُ إِسْمَعِيلَ حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ نَحْوَهُ وَفِي الْبَاب عَنْ أَبِي الدَّرْدَاءِ","id":"Telah menceritakan kepada kami ['Amru bin Malik] dan [Mahmud bin Khidasy Al Baghdadi] keduanya berkata: telah menceritakan kepada kami [Marwan bin Mu'awiyah] telah menceritakan kepada kami [Abdurrahman bin Abu Syumailah Al Anshari] dari [Salamah bin 'Ubaidillah bin Mihshan Al Khatmi] dari [bapaknya] yang pernah bertemu dengan Nabi Shallallahu 'alaihi wa Salam dia berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Barangsiapa di antara kalian di pagi hari aman ditengah-tengah keluarganya, sehat jasmaninya, memiliki kebutuhan pokok untuk sehari-harinya, maka seakan akan dunia telah dikumpulkan untuknya.\" Abu Isa berkata: hadits ini hasan gharib, kami tidak mengetahuinya kecuali dari hadits Marwan bin Mu'awiyah, makna: hizat adalah Jumi'at (terkumpul). Telah menceritakan kepada kami [Muhammad bin Isma'il] telah menceritakan demikian kepada kami [Al Humaidi] telah menceritakan kepada kami [Marwan bin Mu'awiyah] hadits yang semakna, dan dalam bab ini ada hadits dari Abu Darda`."},"2261":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ يَحْيَى بْنِ أَيُّوبَ عَنْ عُبَيْدِ اللَّهِ بْنِ زَحْرٍ عَنْ عَلِيِّ بْنِ يَزِيدَ عَنْ الْقَاسِمِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ أَبِي أُمَامَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ أَغْبَطَ أَوْلِيَائِي عِنْدِي لَمُؤْمِنٌ خَفِيفُ الْحَاذِ ذُو حَظٍّ مِنْ الصَّلَاةِ أَحْسَنَ عِبَادَةَ رَبِّهِ وَأَطَاعَهُ فِي السِّرِّ وَكَانَ غَامِضًا فِي النَّاسِ لَا يُشَارُ إِلَيْهِ بِالْأَصَابِعِ وَكَانَ رِزْقُهُ كَفَافًا فَصَبَرَ عَلَى ذَلِكَ ثُمَّ نَقَرَ بِيَدِهِ فَقَالَ عُجِّلَتْ مَنِيَّتُهُ قَلَّتْ بَوَاكِيهِ قَلَّ تُرَاثُهُ","id":"Telah mengkhabarkan kepada kami [Suwaid bin Nashr] telah mengkhabarkan kepada kami ['Abdullah bin Al Mubarak] dari [Yahya bin Ayyub] dari ['Ubaidillah bin Zahr] dari ['Ali bin Yazid] dari [Al Qasim Abu Abdurrahman] dari [Abu Umamah] dari nabi Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya wali-wali yang terbaik menurutku adalah orang mu`min yang ringan kondisinya, punya bagian dari shalat, menyembah Rabbnya dengan baik, menaati-Nya saat sepi, tidak dikenali orang dan tidak ditunjuk dengan jari, rizkinya pas-pasan lalu ia bersabar atas hal itu\" setelah itu beliau mematok-matokkan tangan beliau lalu bersabda: \"Kematiannya dipercepat, sedikit wanita yang menangisi dan sedikit harta peninggalannya.\" "},"2262":{"ar":"وَبِهَذَا الْإِسْنَادِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عَرَضَ عَلَيَّ رَبِّي لِيَجْعَلَ لِي بَطْحَاءَ مَكَّةَ ذَهَبًا قُلْتُ لَا يَا رَبِّ وَلَكِنْ أَشْبَعُ يَوْمًا وَأَجُوعُ يَوْمًا وَقَالَ ثَلَاثًا أَوْ نَحْوَ هَذَا فَإِذَا جُعْتُ تَضَرَّعْتُ إِلَيْكَ وَذَكَرْتُكَ وَإِذَا شَبِعْتُ شَكَرْتُكَ وَحَمِدْتُكَقَالَ هَذَا حَدِيثٌ حَسَنٌ وَفِي الْبَاب عَنْ فَضَالَةَ بْنِ عُبَيْدٍ وَالْقَاسِمُ هَذَا هُوَ ابْنُ عَبْدِ الرَّحْمَنِ وَيُكْنَى أَبَا عَبْدِ الرَّحْمَنِ وَيُقَالُ أَيْضًا يُكْنَى أَبَا عَبْدِ الْمَلِكِ وَهُوَ مَوْلَى عَبْدِ الرَّحْمَنِ بْنِ خَالِدِ بْنِ يَزِيدَ بْنِ مُعَاوِيَةَ وَهُوَ شَامِيٌّ ثِقَةٌ وَعَلِيُّ بْنُ يَزِيدَ ضَعِيفُ الْحَدِيثِ وَيُكْنَى أَبَا عَبْدِ الْمَلِكِ","id":"Dan dengan sanad yang sama (Yaitu Telah mengkhabarkan kepada kami [Suwaid bin Nashr] telah mengkhabarkan kepada kami ['Abdullah bin Al Mubarak] dari [Yahya bin Ayyub] dari ['Ubaidillah bin Zahr] dari ['Ali bin Yazid] dari [Al Qasim Abu Abdurrahman] dari [Abu Umamah]) dari nabi Shallallahu 'alaihi wa Salam, beliau bersabda: \"Rabbku menawarkanku untuk merubah padang pasir Makkah menjadi emas, aku berkata: Rabb, aku hanya ingin kenyang sehari dan lapar sehari -beliau mengucapkan sebanyak tiga kali atau sepertinya- bila aku lapar, aku menundukkan diri padaMu, mengingatMu dan bila aku kenyang, aku bersyukur padaMu dan memujiMu.\" Berkata Abu Isa: Hadits ini hasan. Dalam hal ini ada hadits serupa dari Fadlalah bin 'Ubaid dan Al Qasim ini adalah Ibnu Abdurrahman, kuniahnya Abu Abdurrahman. Dikatakan juga, kuniahnya Abu 'Abdul Malik, ia adalah budak Abdurrahman bin Khalid bin Yazid bin Mu'awiyah, ia orang Syam, terpercaya, sementara 'Ali bin Yazid adalah perawi yang lemah haditsnya, kuniahnya Abu 'Abdul Malik."},"2263":{"ar":"حَدَّثَنَا الْعَبَّاسُ الدُّورِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ الْمُقْرِئُ حَدَّثَنَا سَعِيدُ بْنُ أَبِي أَيُّوبَ عَنْ شُرَحْبِيلَ بْنِ شَرِيكٍ عَنْ أَبِي عَبْدِ الرَّحْمَنِ الْحُبُلِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَدْ أَفْلَحَ مَنْ أَسْلَمَ وَكَانَ رِزْقُهُ كَفَافًا وَقَنَّعَهُ اللَّهُقَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Al Abbas Ad Dauri] telah menceritakan kepada kami ['Abdullah bin Yazid Al Muqri] telah menceritakan kepada kami [Sa'id bin Abu Ayyub] dari [Syurahbil bin Syarik] dari [Abu Abdurrahman Al Hubuli] dari ['Abdullah bin 'Amru] bahwa Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Beruntunglah orang yang berserah diri, rizqinya dicukupkan dan Allah menjadikannya menerima apa adanya.\" Dia (Abu Isa) berkata: hadits ini hasan shahih."},"2264":{"ar":"حَدَّثَنَا الْعَبَّاسُ الدُّورِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ الْمُقْرِئُ أَخْبَرَنَا حَيْوَةُ بْنُ شُرَيْحٍ أَخْبَرَنِي أَبُو هَانِئٍ الْخَوْلَانِيُّ أَنَّ أَبَا عَلِيٍّ عَمْرَو بْنَ مَالِكٍ الْجَنْبِيَّ أَخْبَرَهُ عَنْ فَضَالَةَ بْنِ عُبَيْدٍأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ طُوبَى لِمَنْ هُدِيَ إِلَى الْإِسْلَامِ وَكَانَ عَيْشُهُ كَفَافًا وَقَنَعَقَالَ وَأَبُو هَانِئٍ اسْمُهُ حُمَيْدُ بْنُ هَانِئٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Al 'Abbas Ad Daruri] telah menceritakan kepada kami ['Abdullah bin Yazid Al Muqri`] telah mengkhabarkan kepada kami [Haiwah bin Syuraih] telah mengkhabarkan kepadaku [Abu Hani` Al Khaulani] bahwa [Abu 'Ali 'Amru bin Malik Al Janbi] telah mengkhabarkan kepadanya dari [Fadlalah bin 'Ubaid] ia mendengar Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Beruntunglah orang yang diberi petunjuk menuju Islam, hidupnya pas-pasan dan menerima apa adanya.\" Berkata Abu Isa: Abu Hani` namanya Humaid bin Hani`. Berkata Abu Isa: Hadits ini hasan shahih."},"2265":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرِو بْنِ نَبْهَانَ بْنِ صَفْوَانَ الثَّقَفِيُّ الْبَصْرِيُّ حَدَّثَنَا رَوْحُ بْنُ أَسْلَمَ حَدَّثَنَا شَدَّادٌ أَبُو طَلْحَةَ الرَّاسِبِيُّ عَنْ أَبِي الْوَازِعِ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ قَالَقَالَ رَجُلٌ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا رَسُولَ اللَّهِ وَاللَّهِ إِنِّي لَأُحِبُّكَ فَقَالَ انْظُرْ مَاذَا تَقُولُ قَالَ وَاللَّهِ إِنِّي لَأُحِبُّكَ فَقَالَ انْظُرْ مَاذَا تَقُولُ قَالَ وَاللَّهِ إِنِّي لَأُحِبُّكَ ثَلَاثَ مَرَّاتٍ فَقَالَ إِنْ كُنْتَ تُحِبُّنِي فَأَعِدَّ لِلْفَقْرِ تِجْفَافًا فَإِنَّ الْفَقْرَ أَسْرَعُ إِلَى مَنْ يُحِبُّنِي مِنْ السَّيْلِ إِلَى مُنْتَهَاهُحَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ حَدَّثَنَا أَبِي عَنْ شَدَّادٍ أَبِي طَلْحَةَ نَحْوَهُ بِمَعْنَاهُ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَأَبُو الْوَازِعِ الرَّاسِبِيُّ اسْمُهُ جَابِرُ بْنُ عَمْرٍو وَهُوَ بَصْرِيٌّ","id":"Telah menceritakan kepada kami [Muhammad bin 'Amru bin Nabhan bin Shafwan Ats Tsaqafi Al Bashri] telah menceritakan kepada kami [Rauh bin Aslam] telah menceritakan kepada kami [Syaddad Abu Thalhah Ar Rasibi] dari [Abul Wazi'] dari ['Abdullah bin Mughaffal] dia berkata bahwa ada seorang lelaki berkata kepada Nabi Shallallahu 'alaihi wa Salam: Wahai Rasulullah, sesungguhnya aku sangat mencintai baginda. Beliau bersabda: \"Perhatikan apa yang kamu katakan.\" Dia berkata lagi: Demi Allah sungguh aku sangat mencintai baginda. Nabi bersabda lagi: \"Perhatikan apa yang kamu katakan.\" Dia berkata lagi: Demi Allah sungguh aku sangat mencintai baginda. tiga kali dia mengucapkannya, lalu beliau bersabda: \"Jia kamu mencintaiku maka persiapkanlah perisai untuk kefakiran, karena kefakiran lebih cepat kepada orang yang mencintaiku melebihi aliran menuju hilir.\" Telah menceritakan kepada kami [Nashr bin 'Ali] telah menceritakan kepada kami [bapakku] dari [Syaddad Abu Thalhah] dengan hadits yang semakna, Abu Isa berkata: Hadits ini hasan gharib, adapun Abul Waza' Ar Rasibi namanya adalah Jabir bin 'Amru, dia adalah orang Bashrah."},"2266":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُوسَى الْبَصْرِيُّ حَدَّثَنَا زِيَادُ بْنُ عَبْدِ اللَّهِ عَنْ الْأَعْمَشِ عَنْ عَطِيَّةَ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فُقَرَاءُ الْمُهَاجِرِينَ يَدْخُلُونَ الْجَنَّةَ قَبْلَ أَغْنِيَائِهِمْ بِخَمْسِ مِائَةِ سَنَةٍوَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو وَجَابِرٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Musa Al Bashri] telah menceritakan kepada kami [Ziyad bin 'Abdullah] dari [Al A'masy] dari ['Athiyyah] dari [Abu Sa'id] dia berkata bahwa Rasulullah Shallallahu 'alaihi wa salam bersabda: \" \"Orang-orang fakir dari kalangan muhajirin mereka lima ratus tahun lebih dahulu masuk syurga sebelum orang orang kaya mereka.\" Dan dalam bab ini ada hadits dari Abu Hurairah, 'Abdullah bin Amr dan Jabir. Abu Isa berkata: Hadits ini hasan gharib dari jalur sanad ini."},"2267":{"ar":"حَدَّثَنَا عَبْدُ الْأَعْلَى بْنُ وَاصِلٍ الْكُوفِيُّ حَدَّثَنَا ثَابِتُ بْنُ مُحَمَّدٍ الْعَابِدُ الْكُوفِيُّ حَدَّثَنَا الْحَارِثُ بْنُ النُّعْمَانِ اللَّيْثِيُّ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اللَّهُمَّ أَحْيِنِي مِسْكِينًا وَأَمِتْنِي مِسْكِينًا وَاحْشُرْنِي فِي زُمْرَةِ الْمَسَاكِينِ يَوْمَ الْقِيَامَةِ فَقَالَتْ عَائِشَةُ لِمَ يَا رَسُولَ اللَّهِ قَالَ إِنَّهُمْ يَدْخُلُونَ الْجَنَّةَ قَبْلَ أَغْنِيَائِهِمْ بِأَرْبَعِينَ خَرِيفًا يَا عَائِشَةُ لَا تَرُدِّي الْمِسْكِينَ وَلَوْ بِشِقِّ تَمْرَةٍ يَا عَائِشَةُ أَحِبِّي الْمَسَاكِينَ وَقَرِّبِيهِمْ فَإِنَّ اللَّه�� يُقَرِّبُكِ يَوْمَ الْقِيَامَةِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ","id":"Telah menceritakan kepada kami ['Abdul A'la bin Washil Al Kufi] telah menceritakan kepada kami [Tsabit bin Muhammad Al 'Abid Al Kufi] telah menceritakan kepada kami [Al Harits bin An Nu'man Al Laitsi] dari [Anas] bahwa Rasulullah Shallallahu 'alahi wa Salam membaca do'a: ALLAAHUMMA AHYINII MISKIINAW WA AMITNII MISKIINAW WAHSYURNII FI ZUMRATIL MASAAKIINI YAUMAL QIYAAMATI (Ya Allah hidupkanlah aku dalam keadaan miskin dan wafatkanlah aku dalam keadaan miskin dan kumpulkanlah aku pada hari kiamat bersama golongan orang orang miskin), 'A`isyah bertanya: Kenapa wahai Rasulullah? beliau menjawab: \"Sesungguhnya mereka akan masuk surga empat puluh tahun lebih dahulu dari pada orang orang kaya, wahai A'isyah jangan kamu tolak orang orang miskin walaupun hanya dengan memberikan secuil kurma, wahai A'isyah cintailah orang orang miskin dan dekatilah mereka karena Allah akan mendekatkan padamu pada hari kiamat.\" Abu Isa berkata: Hadits ini gharib."},"2268":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا قَبِيصَةُ حَدَّثَنَا سُفْيَانُ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْخُلُ الْفُقَرَاءُ الْجَنَّةَ قَبْلَ الْأَغْنِيَاءِ بِخَمْسِ مِائَةِ عَامٍ نِصْفِ يَوْمٍقَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] Telah menceritakan kepada kami [Qabishah] telah menceritakan kepada kami [Sufyan] dari [Muhammad bin 'Amru] dari [Abu Salamah] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Orang-orang miskin masuk surga limaratus tahun setengah hari terlebih dahulu sebelum orang-orang kaya.\" Berkata Abu Isa: Hadits ini hasan shahih."},"2269":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا الْمُحَارِبِيُّ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْخُلُ فُقَرَاءُ الْمُسْلِمِينَ الْجَنَّةَ قَبْلَ أَغْنِيَائِهِمْ بِنِصْفِ يَوْمٍ وَهُوَ خَمْسُ مِائَةِ عَامٍوَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Al Muharibi] dari [Muhammad bin 'Amru] dari [Abu Salamah] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Orang-orang miskin masuk surga setengah hari terlebih dahulu sebelum orang-orang kaya, lamanya limaratus tahun.\" Berkata Abu Isa: Hadits ini hasan shahih."},"2270":{"ar":"حَدَّثَنَا الْعَبَّاسُ الدُّورِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ الْمُقْرِئُ حَدَّثَنَا سَعِيدُ بْنُ أَبِي أَيُّوبَ عَنْ عَمْرِو بْنِ جَابِرٍ الْحَضْرَمِيِّ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَدْخُلُ فُقَرَاءُ الْمُسْلِمِينَ الْجَنَّةَ قَبْلَ أَغْنِيَائِهِمْ بِأَرْبَعِينَ خَرِيفًاهَذَا حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Al 'Abbas Ad Duri] telah menceritakan kepada kami ['Abdullah bin Yazid Al Muqri`] telah menceritakan kepada kami [Sa'id bin Abu Ayyub] dari ['Amru bin Jabir Al Hadlrami] dari [Jabir bin 'Abdullah], Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Orang-orang miskin masuk empatpuluh tahun terlebih dahulu sebelum orang-orang kaya.\" Berkata Abu Isa: Hadits ini hasan."},"2271":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا عَبَّادُ بْنُ عَبَّادٍ عَنْ مُجَالِدٍ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ قَالَدَخَلْتُ عَلَى عَائِشَةَ فَدَعَتْ لِي بِطَعَامٍ وَقَالَتْ مَا أَشْبَعُ مِنْ طَعَامٍ فَأَشَاءُ أَنْ أَبْكِيَ إِلَّا بَكَيْتُ قَالَ قُلْتُ لِمَ قَالَتْ أَذْكُرُ الْحَالَ الَّتِي فَارَقَ عَلَيْهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الدُّنْيَا وَاللَّهِ مَا شَبِعَ مِنْ خُبْزٍ وَلَحْمٍ مَرَّتَيْنِ فِي يَوْمٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami ['Abbad bin 'Abbad] dari [Mujalid] dari [Asy sya'bi] dari [Masruq] dia berkata: aku masuk menemui [Aisyah] lalu dia memanggilku untuk makan dan berkata: Tidaklah aku kenyang karena makanan melainkan aku ingin menangis. Masruq berkata: Aku bertanya: Kenapa? dia menjawab: Aku teringat saat-saat yang ditinggalkan Rasulullah Shallallahu 'alahi wa Salam, demi Allah beliau tidak pernah kenyang dari roti dan daging dalam sehari sampai dua kali. Abu Isa berkata: Hadits ini hasan shahih."},"2272":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ أَنْبَأَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ قَال سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ يَزِيدَ يُحَدِّثُ عَنْ الْأَسْوَدِ بْنِ يَزِيدَ عَنْ عَائِشَةَ قَالَتْمَا شَبِعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ خُبْزِ شَعِيرٍ يَوْمَيْنِ مُتَتَابِعَيْنِ حَتَّى قُبِضَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Dawud] telah memberitakan kepada kami [Syu'bah] dari [Abu Ishaq] berkata: Aku mendengar [Abdurrahman bin Yazid] bercerita dari [Al Aswad bin Yazid] dari ['Aisyah] berkata: Rasulullah Shallallahu 'alahi wa Salam tidak pernah kenyang makan roti dan gandum selama dua hari berturut-turut hingga beliau wafat. Berkata Abu Isa: Hadits ini hasan shahih. Dalam hal ini ada hadits serupa dari Abu Hurairah."},"2273":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا الْمُحَارِبِيُّ حَدَّثَنَا يَزِيدُ بْنُ كَيْسَانَ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَمَا شَبِعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَهْلُهُ ثَلَاثًا تِبَاعًا مِنْ خُبْزِ الْبُرِّ حَتَّى فَارَقَ الدُّنْيَاهَذَا حَدِيثٌ صَحِيحٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Al Muharibi] telah menceritakan kepada kami [Yazid bin Kaisan] dari [Abu Hazim] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alahi wa Salam dan keluarga beliau tidak pernah kenyang makan roti gandum selama tiga kali berturut-turut hingga beliau meninggal dunia. Hadits ini shahih hasan gharib melalui jalur sanad ini."},"2274":{"ar":"حَدَّثَنَا عَبَّاسُ بْنُ مُحَمَّدٍ الدُّورِيُّ حَدَّثَنَا يَحْيَى بْنُ أَبِي بُكَيْرٍ حَدَّثَنَا حَرِيزُ بْنُ عُثْمَانَ عَنْ سُلَيْمِ بْنِ عَامِرٍ قَال سَمِعْتُ أَبَا أُمَامَةَ يَقُولُمَا كَانَ يَفْضُلُ عَنْ أَهْلِ بَيْتِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُبْزُ الشَّعِيرِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَيَحْيَى بْنُ أَبِي بُكَيْرٍ هَذَا كُوفِيٌّ وَأَبُو بُكَيْرٍ وَالِدُ يَحْيَى رَوَى لَهُ سُفْيَانُ الثَّوْرِيُّ وَيَحْيَى بْنُ عَبْدِ اللَّهِ بْنِ بُكَيْرٍ مِصْرِيٌّ صَاحِبُ اللَّيْثِ","id":"Telah menceritakan kepada kami ['Abbas bin Muhammad Ad Dauri] telah menceritakan kepada kami [Yahya bin Abu Bukair] telah menceritakan kepada kami [Hariz bin 'Utsman] dari [Sulaim bin 'Amir] berkata: Aku mendengar [Abu Umamah] berkata: Tidak ada makanan keluarga nabi Shallallahu 'alaihi wa Salam yang lebih baik dari roti gandum. Berkata Abu Isa: Hadits ini hasan shahih gharib melalui sanad ini dan Yahya bin Bukair tersebut adalah orang kufi, Abu Bukair adalah ayah dari Yahya, Sufyan Ats Tsauri meriwayatkan untuknya, sedangkan Yahya bin 'Abdullah bin Bukair adalah orang Mesir, teman Al Laits."},"2275":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُعَاوِيَةَ الْجُمَحِيُّ حَدَّثَنَا ثَابِتُ بْنُ يَزِيدَ عَنْ هِلَالِ بْنِ خَبَّابٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَبِيتُ اللَّيَالِي الْمُتَتَابِعَةَ طَاوِيًا وَأَهْلُهُ لَا يَجِدُونَ عَشَاءً وَكَانَ أَكْثَرُ خُبْزِهِمْ خُبْزَ الشَّعِيرِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami ['Abdullah bin Mu'awiyah Al Jumahi] telah menceritakan kepada kami [Tsabit bin Yazid] dari [Hilal bin Khabbab] dari [Ikrimah] dari [Ibnu 'Abbas] berkata: Rasulullah Shallallahu 'alahi wa Salam pernah tidur beberapa malam secara berturut-turut dengan perut kosong dan keluarganya tidak memiliki makan malam, roti mereka yang paling banyak adalah roti gandum. Berkata Abu Isa: Hadits ini hasan shahih."},"2276":{"ar":"حَدَّثَنَا أَبُو عَمَّارٍ حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ عُمَارَةَ بْنِ الْقَعْقَاعِ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ اجْعَلْ رِزْقَ آلِ مُحَمَّدٍ قُوتًاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Abu 'Ammar] telah menceritakan kepada kami [Waqi'] dari [Al A'masy] dari ['Umarah bin Al Qa'qa'] dari [Abu Zur'ah] dari [Abu Hurairah] dia berkata \" Rasulullah Shallallahu 'alahi wa Salam membaca do'a: ALLAAHUMMAJ'AL RIZQA AALI MUHAMMADIN QUUTAN (Ya Allah jadikanlah rizki keluarga Muhammad dari bahan makanan pokok). Abu Isa berkata: Hadits ini hasan shahih."},"2277":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا جَعْفَرُ بْنُ سُلَيْمَانَ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَدَّخِرُ شَيْئًا لِغَدٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ جَعْفَرِ بْنِ سُلَيْمَانَ عَنْ ثَابِتٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْسَلًا","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Ja'far bin Sulaiman] dari [Tsabit] dari [Anas] dia berkata bahwa Nabi Shallallahu 'alaihi wa Salam tidak pernah menyimpan sesuatu apapun untuk esok hari.\" Abu Isa berkata: hadits ini gharib, hadits ini diriwayatkan dari Ja'far bin Sulaiman dari Tsabit dari Nabi Shallallahu 'alaihi wa Salam secara mursal."},"2278":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ أَخْبَرَنَا أَبُو مَعْمَرٍ عَبْدُ اللَّهِ بْنُ عَمْرٍو حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَمَا أَكَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى خِوَانٍ وَلَا أَكَلَ خُبْزًا مُرَقَّقًا حَتَّى مَاتَقَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ حَدِيثِ سَعِيدِ بْنِ أَبِي عَرُوبَةَ","id":"Telah menceritakan kepada kami ['Abdullah bin Abdurrahman] telah mengkhabarkan kepada kami [Abu Ma'mar 'Abdullah bin 'Amru] telah menceritakan kepada kami ['Abdul Warits] dari [Sa'id bin Abu 'Urubah] dari [Qatadah] dari [Anas] berkata: Rasulullah Shallallahu 'alahi wa Salam tidak pernah makan di atas meja makan dan tidak pernah makan roti lembut hingga meninggal dunia. Berkata Abu Isa: Hadits ini hasan shahih gharib dari hadits Sa'id ibn Abu 'Urubah."},"2279":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ الْحَنَفِيُّ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ دِينَارٍ أَخْبَرَنَا أَبُو حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍأَنَّهُ قِيلَ لَهُ أَكَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّقِيَّ يَعْنِي الْحُوَّارَى فَقَالَ سَهْلٌ مَا رَأَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّقِيَّ حَتَّى لَقِيَ اللَّهَ فَقِيلَ لَهُ هَلْ كَانَتْ لَكُمْ مَنَاخِلُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا كَانَتْ لَنَا مَنَاخِلُ قِيلَ فَكَيْفَ كُنْتُمْ تَصْنَعُونَ بِالشَّعِيرِ قَالَ كُنَّا نَنْفُخُهُ فَيَطِيرُ مِنْهُ مَا طَارَ ثُمَّ نُثَرِّيهِ فَنَعْجِنُهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَاهُ مَالِكُ بْنُ أَنَسٍ عَنْ أَبِي حَازِمٍ","id":"Telah menceritakan kepada kami ['Abdullah bin Abdurrahman] telah mengkhabarkan kepada kami ['Ubaidullah bin 'Abdul Majid Al Hanafi] telah menceritakan kepada kami [Abdurrahman bin 'Abdullah bin Dinar] telah mengkhabarkan kepada kami [Abu Hazim] dari [Sahal bin Sa'ad], ia diberitahu bahwa katanya Rasulullah Shallallahu 'alahi wa Salam pernah menyantap gandum halus (bubuk gandum). Langsung Sahal menjawab: Rasulullah Shallallahu 'alahi wa Salam tidak pernah melihat gandum halus (bubuk gandum) hingga bertemu Allah. Ia ditanya: Apakah ada ayakan (tapis) dimasa Rasulullah Shallallahu 'alahi wa Salam? Sahal menjawab: Kami dulu tidak memiliki ayakan (tapis). Ia ditanya: Lalu gandum kalian apakah? Sahal menjawab: Kami meniupnya hingga berterbangan, lalu kami basahi, setelah itu kami jadikan adonan. Berkata Abu Isa: Hadits ini hasan shahih. [Malik bin Anas] meriwayatkannya dari [Abu Hazim]."},"2280":{"ar":"حَدَّثَنَا عُمَرُ بْنُ إِسْمَعِيلَ بْنِ مُجَالِدِ بْنِ سَعِيدٍ حَدَّثَنَا أَبِي عَنْ بَيَانٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ قَال سَمِعْتُ سَعْدَ بْنَ أَبِي وَقَّاصٍ يَقُولُإِنِّي لَأَوَّلُ رَجُلٍ أَهْرَاقَ دَمًا فِي سَبِيلِ اللَّهِ وَإِنِّي لَأَوَّلُ رَجُلٍ رَمَى بِسَهْمٍ فِي سَبِيلِ اللَّهِ وَلَقَدْ رَأَيْتُنِي أَغْزُو فِي الْعِصَابَةِ مِنْ أَصْحَابِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا نَأْكُلُ إِلَّا وَرَقَ الشَّجَرِ وَالْحُبْلَةِ حَتَّى إِنَّ أَحَدَنَا لَيَضَعُ كَمَا تَضَعُ الشَّاةُ أَوْ الْبَعِيرُ وَأَصْبَحَتْ بَنُو أَسَدٍ يُعَزِّرُونِي فِي الدِّينِ لَقَدْ خِبْتُ إِذًا وَضَلَّ عَمَلِيقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ حَدِيثِ بَيَانٍ","id":"Telah menceritakan kepada kami ['Umar bin Isma'il bin Mujalid bin Sa'id] telah menceritakan kepada kami [ayahku] dari [Bayan] dari [Qais bin Abu Hazim] berkata: Aku mendengar [Sa'ad bin Abu Waqqash] berkata: Aku adalah orang pertama yang menumpahkan darah di jalan Allah, aku adalah orang pertama yang melesakkan panah di jalan Allah, aku berperang bersama sekelompok sahabat Muhammad Shallallahu 'alahi wa Salam, kami hanya makan dedaunan pohon dan pohon anggur hingga salah seorang diantara kami merebah seperti kambing atau unta. Di kemudian hari Bani Asad mencelaku dan menjelek-jelekkanku karena agamaku (yang dianggapnya kurang baik), kalau itu benar, rugilah aku dan sesatlah amalku. Berkata Abu Isa: Hadits ini hasan shahih gharib dari hadits Bayan. "},"2281":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ حَدَّثَنَا قَيْسٌ قَال سَمِعْتُ سَعْدَ بْنَ مَالِكٍ يَقُولُإِنِّي أَوَّلُ رَجُلٍ مِنْ الْعَرَبِ رَمَى بِسَهْمٍ فِي سَبِيلِ اللَّهِ وَلَقَدْ رَأَيْتُنَا نَغْزُو مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَا لَنَا طَعَامٌ إِلَّا الْحُبْلَةَ وَهَذَا السَّمُرَ حَتَّى إِنَّ أَحَدَنَا لَيَضَعُ كَمَا تَضَعُ الشَّاةُ ثُمَّ أَصْبَحَتْ بَنُو أَسَدٍ يُعَزِّرُونِي فِي الدِّينِ لَقَدْ خِبْتُ إِذًا وَضَلَّ عَمَلِيقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَفِي الْبَاب عَنْ عُتْبَةَ بْنِ غَزْوَانَ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami [Isma'il bin Abu Khalid] telah menceritakan kepada kami [Qais] berkata: Aku mendengar [Sa'ad bin Malik] berkata: Aku adalah orang arab pertama yang melesakkan panah di jalan Allah, aku berperang bersama Rasulullah Shallallahu 'alahi wa Salam, kami hanya memiliki makanan berupa pohon anggur dan rumput ini, hingga salah seorang diantara kami merebah seperti kambing. Di kemudian hari Bani Asad mencelaku dan menjelek-jelekkanku karena agamaku yang dianggapnya kurang baik, kalau itu benar, tentu rugilah aku dan sesatlah amalku. Berkata Abu Isa: Hadits ini hasan shahih dan salam hal ini ada hadits serupa dari 'Utbah bin Ghazwan."},"2282":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ قَالَكُنَّا عِنْدَ أَبِي هُرَيْرَةَ وَعَلَيْهِ ثَوْبَانِ مُمَشَّقَانِ مِنْ كَتَّانٍ فَتَمَخَّطَ فِي أَحَدِهِمَا ثُمَّ قَالَ بَخٍ بَخٍ يَتَمَخَّطُ أَبُو هُرَيْرَةَ فِي الْكَتَّانِ لَقَدْ رَأَيْتُنِي وَإِنِّي لَأَخِرُّ فِيمَا بَيْنَ مِنْبَرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَحُجْرَةِ عَائِشَةَ مِنْ الْجُوعِ مَغْشِيًّا عَلَيَّ فَيَجِيءُ الْجَائِي فَيَضَعُ رِجْلَهُ عَلَى عُنُقِي يَرَى أَنَّ بِيَ الْجُنُونَ وَمَا بِي جُنُونٌ وَمَا هُوَ إِلَّا الْجُوعُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Muhammad bin Sirin] berkata: Kami pernah berada didekat [Abu Hurairah], ia mengenakan dua baju katun berwantek tanah merah, ia menggigil di salah satunya, ia berkata: Beruntunglah, beruntunglah, Abu Hurairah menggigil di kain katun. Sungguh kulihat diriku tersungkur pingsan di antara mimbar Rasulullah Shallallahu 'alahi wa Salam dan kamar 'Aisyah karena lapar, lalu ada seseorang mendatangiku, ia letakkan kakinya di atas leherku, menurutnya aku gila padahal tidak, itu tidak lain hanya karena aku kelaparan. Berkata Abu Isa: Hadits ini hasan shahih gharib dari jalur sanad ini."},"2283":{"ar":"حَدَّثَنَا الْعَبَّاسُ الدُّورِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنَا حَيْوَةُ بْنُ شُرَيْحٍ أَخْبَرَنِي أَبُو هَانِئٍ الْخَوْلَانِيُّ أَنَّ أَبَا عَلِيٍّ عَمْرَو بْنَ مَالِكٍ الْجَنْبِيَّ أَخْبَرَهُ عَنْ فَضَالَةَ بْنِ عُبَيْدٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا صَلَّى بِالنَّاسِ يَخِرُّ رِجَالٌ مِنْ قَامَتِهِمْ فِي الصَّلَاةِ مِنْ الْخَصَاصَةِ وَهُمْ أَصْحَابُ الصُّفَّةِ حَتَّى يَقُولَ الْأَعْرَابُ هَؤُلَاءِ مَجَانِينُ أَوْ مَجَانُونَ فَإِذَا صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْصَرَفَ إِلَيْهِمْ فَقَالَ لَوْ تَعْلَمُونَ مَا لَكُمْ عِنْدَ اللَّهِ لَأَحْبَبْتُمْ أَنْ تَزْدَادُوا فَاقَةً وَحَاجَةً قَالَ فَضَالَةُ وَأَنَا يَوْمَئِذٍ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Al 'Abbas Ad Duri] telah menceritakan kepada kami ['Abdullah bin Yazid] telah menceritakan kepada kami [Haiwah bin Syuraih] telah mengkhabarkan kepadaku [Abu Hani` Al Khaulani] bahwa [Abu 'Ali bin Malik Al Janbi] memberitahu padanya dari [Fadlalah bin 'Ubaid], saat Rasulullah Shallallahu 'alahi wa Salam shalat bersama orang-orang, beberapa orang jatuh tersungkur saat berdiri dalam shalat karena lapar, mereka adalah para penghuni emperan masjid hingga orang-orang badui berkata: Mereka orang-orang gila. Sesuai shalat, Rasulullah Shallallahu 'alahi wa Salam menghampiri mereka lalu bersabda: \"Andai kalian mengetahui bagian milik kalian di sisi Allah, niscaya kalian akan suka untuk lebih miskin dan susah.\" Berkata Fadlalah: Saat itu aku bersama Rasulullah Shallallahu 'alahi wa Salam. Berkata Abu Isa: Hadits ini shahih."},"2284":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ حَدَّثَنَا شَيْبَانُ أَبُو مُعَاوِيَةَ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ عُمَيْرٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ قَالَخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَاعَةٍ لَا يَخْرُجُ فِيهَا وَلَا يَلْقَاهُ فِيهَا أَحَدٌ فَأَتَاهُ أَبُو بَكْرٍ فَقَالَ مَا جَاءَ بِكَ يَا أَبَا بَكْرٍ فَقَالَ خَرَجْتُ أَلْقَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنْظُرُ فِي وَجْهِهِ وَالتَّسْلِيمَ عَلَيْهِ فَلَمْ يَلْبَثْ أَنْ جَاءَ عُمَرُ فَقَالَ مَا جَاءَ بِكَ يَا عُمَرُ قَالَ الْجُوعُ يَا رَسُولَ اللَّهِ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا قَدْ وَجَدْتُ بَعْضَ ذَلِكَ فَانْطَلَقُوا إِلَى مَنْزِلِ أَبِي الْهَيْثَمِ بْنِ التَّيْهَانِ الْأَنْصَارِيِّ وَكَانَ رَجُلًا كَثِيرَ النَّخْلِ وَالشَّاءِ وَلَمْ يَكُنْ لَهُ خَدَمٌ فَلَمْ يَجِدُوهُ فَقَالُوا لِامْرَأَتِهِ أَيْنَ صَاحِبُكِ فَقَالَتْ انْطَلَقَ يَسْتَعْذِبُ لَنَا الْمَاءَ فَلَمْ يَلْبَثُوا أَنْ جَاءَ أَبُو الْهَيْثَمِ بِقِرْبَةٍ يَزْعَبُهَا فَوَضَعَهَا ثُمَّ جَاءَ يَلْتَزِمُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيُفَدِّيهِ بِأَبِيهِ وَأُمِّهِ ثُمَّ انْطَلَقَ بِهِمْ إِلَى حَدِيقَتِهِ فَبَسَطَ لَهُمْ بِسَاطًا ثُمَّ انْطَلَقَ إِلَى نَخْلَةٍ فَجَاءَ بِقِنْوٍ فَوَضَعَهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفَلَا تَنَقَّيْتَ لَنَا مِنْ رُطَبِهِ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي أَرَدْتُ أَنْ تَخْتَارُوا أَوْ قَالَ تَخَيَّرُوا مِنْ رُطَبِهِ وَبُسْرِهِ فَأَكَلُوا وَشَرِبُوا مِنْ ذَلِكَ الْمَاءِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا وَالَّذِي نَفْسِي بِيَدِهِ مِنْ النَّعِيمِ الَّذِي تُسْأَلُونَ عَنْهُ يَوْمَ الْقِيَامَةِ ظِلٌّ بَارِدٌ وَرُطَبٌ طَيِّبٌ وَمَاءٌ بَارِدٌ فَانْطَلَقَ أَبُو الْهَيْثَمِ لِيَصْنَعَ لَهُمْ طَعَامًا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَذْبَحَنَّ ذَاتَ دَرٍّ قَالَ فَذَبَحَ لَهُمْ عَنَاقًا أَوْ جَدْيًا فَأَتَاهُمْ بِهَا فَأَكَلُوا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ لَكَ خَادِمٌ قَالَ لَا قَالَ فَإِذَا أَتَانَا سَبْيٌ فَأْتِنَا فَأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِرَأْسَيْنِ لَيْسَ مَعَهُمَا ثَالِثٌ فَأَتَاهُ أَبُو الْهَيْثَمِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اخْتَرْ مِنْهُمَا فَقَالَ يَا نَبِيَّ اللَّهِ اخْتَرْ لِي فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْمُسْتَشَارَ مُؤْتَمَنٌ خُذْ هَذَا فَإِنِّي رَأَيْتُهُ يُصَلِّي وَاسْتَوْصِ بِهِ مَعْرُوفًا فَانْطَلَقَ أَبُو الْهَيْثَمِ إِلَى امْرَأَتِهِ فَأَخْبَرَهَا بِقَوْلِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ امْرَأَتُهُ مَا أَنْتَ بِبَالِغٍ مَا قَالَ فِيهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا أَنْ تَعْتِقَهُ قَالَ فَهُوَ عَتِيقٌ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ لَمْ يَبْعَثْ نَبِيًّا وَلَا خَلِيفَةً إِلَّا وَلَهُ بِطَانَتَانِ بِطَانَةٌ تَأْمُرُهُ بِالْمَعْرُوفِ وَتَنْهَاهُ عَنْ الْمُنْكَرِ وَبِطَانَةٌ لَا تَأْلُوهُ خَبَالًا وَمَنْ يُوقَ بِطَانَةَ السُّوءِ فَقَدْ وُقِيَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ حَدَّثَنَا صَالِحُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ يَوْمًا وَأَبُو بَكْرٍ وَعُمَرُ فَذَكَرَ نَحْوَ هَذَا الْحَدِيثِ وَلَمْ يَذْكُرْ فِيهِ عَنْ أَبِي هُرَيْرَةَ وَحَدِيثُ شَيْبَانَ أَتَمُّ مِنْ حَدِيثِ أَبِي عَوَانَةَ وَأَطْوَلُ وَشَيْبَانُ ثِقَةٌ عِنْدَهُمْ صَاحِبُ كِتَابٍ وَقَدْ رُوِيَ عَنْ أَبِي هُرَيْرَةَ هَذَا الْحَدِيثُ مِنْ غَيْرِ هَذَا الْوَجْهِ وَرُوِيَ عَنْ ابْنِ عَبَّاسٍ أَيْضًا","id":"Telah menceritakan kepada kami [Muhammad bin Isma'il] telah menceritakan kepada kami [Adam bin Abu Iyas] telah menceritakan kepada kami [Syaiban Abu Mu'awiyah] telah menceritakan kepada kami ['Abdul Malik bin 'Umair] dari [Abu Salamah bin Abdur Rahman] dari [Abu Hurairah] dia berkata: Nabi Shallallahu 'alaihi wa Salam keluar rumah pada saat yang tidak biasa beliau keluar dan tidak ada seorang pun yang bertemu dengannya, kemudian Abu Bakar menemuinya lalu beliau bertanya: \"Apa yang membuatmu datang wahai Abu Bakar?\" Abu Bakar menjawab: Aku keluar untuk menemui Rasulullah Shallallahu 'alahi wa Salam dan aku melihat ke arah wajah beliau dan beliau menerimanya. Tidak lama kemudian datanglah Umar lalu beliau bertanya: \"Apa yang membuatmu datang wahai 'Umar?\" 'Umar menjawab: Karena lapar wahai Rasulullah Shallallahu 'alahi wa Salam. Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Saya juga merasakan sedikit lapar, maka pergilah kalian ke rumah Abul Haitsam bin At Taihan Al Anshari, dia adalah seorang lelaki yang mempunyai banyak kurma dan kambing tapi dia tidak mempunyai pelayan, \" namun mereka tidak menemukannya, mereka bertanya kepada istrinya: Dimana suamimu? istrinya menjawab: Dia sedang mengambil air untuk kami. Tidak lama mereka menunggu tiba-tiba datanglah Abul Haitsam dengan membawa tempat air yang berisi air penuh lalu dia meletakkannya, kemudian dia datang dan mendekap Nabi Shallallahu 'alaihi wa Salam sambil bersumpah rela mengorbankan bapak dan ibunya demi beliau, kemudian dia pergi bersama mereka menuju perkebunannya dan menghamparkan tikar untuk mereka, lalu dia pergi menuju sebuah pohon kurma dan kembali dengan membawa setangkai kurma kemudian meletakkannya, Nabi Shallallahu 'alaihi wa Salam bertanya: \"Maukah kamu memilihkan kurma basahnya untuk kami?\" dia menjawab: Wahai Rasulullah, aku ingin baginda sendiri yang memilihnya -atau dia berkata: Silahkan kalian pilih kurma basah dan kurma mudanya, lalu mereka makan kurma dan minum dari air itu, setelah itu Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Demi Dzat yang jiwaku ada di tanganNya, ini termasuk kenikmatan yang akan ditanyakan kepada kalian kelak pada hari kiamat; tempat berteduh yang dingin, kurma basah yang lezat dan air tawar.\" Abul Haitsam pergi untuk membuatkan makanan untuk mereka lalu Nabi Shallallahu'alaihiwasallam berkata \" Janganlah kamu menyembelih hewan yang ada air susunya. Abu Hurairah berkata: Abul Haitsam menyembelih seekor kambing kacang betina atau jantan (perawi ragu apakah betina atau jantan) untuk mereka lalu mereka menyantapnya, Nabi Shallallahu 'alaihi wa Salam bertanya: \"Apakah kamu punya seorang pelayan?\" Dia menjawab: Tidak. Abu Hurairah berkata: Tiba tiba seorang tawanan datang kepada kami, lalu Nabi Shallallahu 'alaihi wa Salam di serahi dua orang budak yang didatangkan oleh Abul Haitsam, Nabi Shallallahu 'alaihi wa Salam bersabda: \"Pilih salah satu dari keduanya!\" Abul Haitsam berkata: Wahai nabi Allah pilihkan untuk saya, \" Nabi Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya orang yang dimintai pendapat adalah orang yang jujur, maka ambillah yang ini karena sesungguhnya aku melihat dia shalat, perlakukanlah dia dengan baik, \" Abul Haitsam pergi menemui istrinya dan menceritakan kepadanya apa yang dikatakan oleh Rasulullah Shallallahu 'alahi wa Salam, istrinya berkata: Tidaklah kamu menyampaikan apa yang dikatakan oleh Nabi kecuali hendaknya kamu memerdekakannya. Abul Haitsam berkata: Dia merdeka. Nabi Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya Allah tidak mengutus seorang Nabi dan tidak juga khalifah kecuali memiliki dua kubu, satu kubu yang menyuruhnya kepada kebaikan dan mencegahnya dari kemunkaran, dan kubu lain yang tidak henti-hentinya (menimbulkan) kemudharatan bagimu, dan barangsiapa yang dihindarkan dari teman yang jahat maka dia telah terjaga.\" Abu Isa berkata: hadits ini hasan shahih gharib. Telah menceritakan kepada kami [Shalih bin 'Abdullah] telah menceritakan kepada kami [Abu Awanah] dari ['Abdul Malik bin 'Umair] dari [Abu Salamah bin Abdurrahman], pada suatu hari Rasulullah Shallallahu 'alahi wa Salam, Abu Bakar dan Umar keluar, kemudian dia menyebutkan hadits yang semakna dengan hadits ini, namun dalam isinya tidak menyebutkan: dari Abu Hurairah dan hadits Syaiban lebih sempurna dan lebih lengkap dari hadits Abu Awanah, Syaiban adalah perawi terpercaya menurut mereka dan dia memiliki kitab, hadits ini diriwayatkan dari Abu Hurairah dari jalur sanad yang lain dan diriwayatkan juga dari Ibnu Abbas."},"2285":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي زِيَادٍ حَدَّثَنَا سَيَّارُ بْنُ حَاتِمٍ عَنْ سَهْلِ بْنِ أَسْلَمَ عَنْ يَزِيدَ بْنِ أَبِي مَنْصُورٍ عَنْ أَنَسِ بْنِ مَالِكٍ عَنْ أَبِي طَلْحَةَ قَالَشَكَوْنَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْجُوعَ وَرَفَعْنَا عَنْ بُطُونِنَا عَنْ حَجَرٍ حَجَرٍ فَرَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ حَجَرَيْنِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami ['Abdullah bin Abu Ziyad] telah menceritakan kepada kami [Sayyar bin Hatim] dari [Sahl bin Aslam] dari [Yazid bin Abu Manshur] dari [Anas bin Malik] dari [Abu Thalhah] dia berkata: Kami mengadukan kelaparan kami kepada Rasulullah Shallallahu 'alahi wa Salam dan kami mengganjal perut kami dengan satu batu sedangkan Rasulullah Shallallahu 'alahi wa Salam mengganjal dengan dua batu. Abu Isa berkata: Hadits ini gharib, kami tidak mengetahuinya kecuali dari jalur sanad ini."},"2286":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ سِمَاكِ بْنِ حَرْبٍ قَال سَمِعْتُ النُّعْمَانَ بْنَ بَشِيرٍ يَقُولُأَلَسْتُمْ فِي طَعَامٍ وَشَرَابٍ مَا شِئْتُمْ لَقَدْ رَأَيْتُ نَبِيَّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَا يَجِدُ مِنْ الدَّقَلِ مَا يَمْلَأُ بِهِ بَطْنَهُقَالَ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ قَالَ أَبُو عِيسَى وَرَوَى أَبُو عَوَانَةَ وَغَيْرُ وَاحِدٍ عَنْ سِمَاكِ بْنِ حَرْبٍ نَحْوَ حَدِيثِ أَبِي الْأَحْوَصِ وَرَوَى شُعْبَةُ هَذَا الْحَدِيثَ عَنْ سِمَاكٍ عَنْ النُّعْمَانِ بْنِ بَشِيرٍ عَنْ عُمَرَ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abu Al Ahwash] dari [Simak bin Harb] berkata: Aku mendengar [An Nu'man bin Basyir] berkata: Bukankah kalian makan dan minum semau kalian? Dulu aku melihat nabi kalian Shallallahu 'alahi wa Salam sekedar kurma jelek (kualitas rendah) pun tidak beliau miliki, untuk sekedar mengganjal perut. Berkata Abu Isa: Hadits ini hasan shahih. [Abu Awanah] dan perawi lain meriwayatkan dari [Simak bin Harb] seperti hadits Abu Al Ahwash, sementara [Syu'bah] meriwayatkan hadits ini dari [Simak] dari [An Nu'man bin Basyir] dari ['Umar]."},"2287":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ بُدَيْلِ بْنِ قُرَيْشٍ الْيَامِيُّ الْكُوفِيُّ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ أَبِي حَصِينٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ الْغِنَى عَنْ كَثْرَةِ الْعَرَضِ وَلَكِنَّ الْغِنَى غِنَى النَّفْسِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَأَبُو حَصِينٍ اسْمُهُ عُثْمَانُ بْنُ عَاصِمٍ الْأَسَدِيُّ","id":"Telah menceritakan kepada kami [Ahmad bin Budail bin Quraisy Al Yamami Al Kufi] telah menceritakan kepada kami [Abu Bakr bin 'Ayyasy] dari [Abu Hashin] dari [Abu Shalih] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Orang kaya itu bukan yang banyak barangnya tapi orang kaya adalah orang yang kaya hati.\" Berkata Abu Isa: Hadits ini hasan shahih dan nama Abu Hashin adalah 'Utsman bin 'Ashim Al Asadi."},"2288":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي الْوَلِيدِ قَال سَمِعْتُ خَوْلَةَ بِنْتَ قَيْسٍ وَكَانَتْ تَحْتَ حَمْزَةَ بْنِ عَبْدِ الْمُطَّلِبِ تَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ هَذَا الْمَالَ خَضِرَةٌ حُلْوَةٌ مَنْ أَصَابَهُ بِحَقِّهِ بُورِكَ لَهُ فِيهِ وَرُبَّ مُتَخَوِّضٍ فِيمَا شَاءَتْ بِهِ نَفْسُهُ مِنْ مَالِ اللَّهِ وَرَسُولِهِ لَيْسَ لَهُ يَوْمَ الْقِيَامَةِ إِلَّا النَّارُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَأَبُو الْوَلِيدِ اسْمُهُ عُبَيْدُ سَنُوطَى","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari [Sa'id Al Maqburi] dari [Abu Al Walid] berkata: Aku mendengar [Khaulah binti Qais], saat itu ia adalah istri Hamzah bin Abdul Muththallib, berkata: Aku mendengar Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Sesungguhnya harta ini hijau ranau manis, barangsiapa mengambilnya sesuai haknya, ia diberkahi dalam harta itu, dan berapa banyak orang yang mengelola harta Allah dan rasulNya sesuai kehendak nafsunya sendiri, yang pada hari kiamat tidak ada balasan baginya selain neraka.\" Berkata Abu Isa: Hadits ini hasan shahih dan Abu Al Walid namanya 'Ubaid Sanutha."},"2289":{"ar":"حَدَّثَنَا بِشْرُ بْنُ هِلَالٍ الصَّوَّافُ حَدَّثَنَا عَبْدُ الْوَارِثِ بْنُ سَعِيدٍ عَنْ يُونُسَ عَنْ الْحَسَنِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لُعِنَ عَبْدُ الدِّينَارِ لُعِنَ عَبْدُ الدِّرْهَمِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَقَدْ رُوِيَ هَذَا الْحَدِيث مِنْ غَيْرِ هَذَا الْوَجْهِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيْضًا أَتَمَّ مِنْ هَذَا وَأَطْوَلَ","id":"Telah menceritakan kepada kami [Bisyr bin Hilal Ash Shawwaf] telah menceritakan kepada kami ['Abdul Warits bin Sa'id] dari [Yunus] dari [Al Hasan] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Terlaknatlah hamba dinar dan hamba dirham.\" Abu Isa berkata: Hadits ini hasan gharib dari jalur sanad ini, dan hadits ini diriwayatkan juga dari jalur yang lain dari [Abu Shalih] dari [Abu Hurairah] dari Nabi Shallallahu 'alaihi wa Salam dengan lebih sempurna dan lebih lengkap. "},"2290":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ نَصْرٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ سَعْدِ بْنِ زُرَارَةَ عَنْ ابْنِ كَعْبِ بْنِ مَالِكٍ الْأَنْصَارِيِّ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا ذِئْبَانِ جَائِعَانِ أُرْسِلَا فِي غَنَمٍ بِأَفْسَدَ لَهَا مِنْ حِرْصِ الْمَرْءِ عَلَى الْمَالِ وَالشَّرَفِ لِدِينِهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَيُرْوَى فِي هَذَا الْبَابِ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا يَصِحُّ إِسْنَادُهُ","id":"Telah menceritakan kepada kami [Suwaid bin Nashr] telah mengkhabarkan kepada kami ['Abdullah bin Al Mubarak] dari [Zakariya bin Abu Za`idah] dari [Muhammad bin Abdurrahman bin Sa'ad bin Ruzarah] dari [Ibnu Ka'ab bin Malik Al Anshari] dari [ayahnya] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Dua serigala lapar yang dilepas menyerang sekawanan kambing, pengrusakannya tidak melebihi ambisi seseorang untuk memperoleh harta dan kemuliaan yang merusak agamanya.\" Berkata Abu Isa: Hadits ini hasan shahih dan ada hadits serupa diriwayatkan berkenaan dengan hal ini dari Ibnu 'Umar dari nabi Shallallahu 'alaihi wa Salam tapi sanadnya tidak shahih."},"2291":{"ar":"حَدَّثَنَا مُوسَى بْنُ عَبْدِ الرَّحْمَنِ الْكِنْدِيُّ حَدَّثَنَا زَيْدُ بْنُ حُبَابٍ أَخْبَرَنِي الْمَسْعُودِيُّ حَدَّثَنَا عَمْرُو بْنُ مُرَّةَ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَنَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى حَصِيرٍ فَقَامَ وَقَدْ أَثَّرَ فِي جَنْبِهِ فَقُلْنَا يَا رَسُولَ اللَّهِ لَوْ اتَّخَذْنَا لَكَ وِطَاءً فَقَالَ مَا لِي وَمَا لِلدُّنْيَا مَا أَنَا فِي الدُّنْيَا إِلَّا كَرَاكِبٍ اسْتَظَلَّ تَحْتَ شَجَرَةٍ ثُمَّ رَاحَ وَتَرَكَهَاقَالَ وَفِي الْبَاب عَنْ ابْنِ عُمَرَ وَابْنِ عَبَّاسٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Musa bin Abdurrahman Al Kindi] telah menceritakan kepada kami [Zaid bin Hubab] telah mengkhabarkan kepadaku [Al Mas'udi] telah menceritakan kepada kami ['Amru bin Murrah] dari [Ibrahim] dari [Alqamah] dari ['Abdullah] berkata: Rasulullah Shallallahu 'alahi wa Salam tidur diatas tikar lalu beliau bangun, tikar itu membekas di lambung beliau, kami berkata: Andai kami membuatkan hamparan lunak untuk anda. Beliau bersabda: \"Apa urusanku dengan dunia, aku di dunia tidak lain seperti pengendara yang bernaung di bawah pohon setelah itu pergi dan meninggalkannya.\" Berkata Abu Isa: Dalam hal ini ada hadits serupa dari Ibnu 'Umar dan Ibnu 'Abbas. Berkata Abu Isa: Hadits ini hasan shahih."},"2292":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَامِرٍ وَأَبُو دَاوُدَ قَالَا حَدَّثَنَا زُهَيْرُ بْنُ مُحَمَّدٍ حَدَّثَنِي مُوسَى بْنُ وَرْدَانَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الرَّجُلُ عَلَى دِينِ خَلِيلِهِ فَلْيَنْظُرْ أَحَدُكُمْ مَنْ يُخَالِلُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Abu 'Amir] dan [Abu Dawud] keduanya berkata: Telah menceritakan kepada kami [Zuhair bin Muhammad] telah menceritakan kepadaku [Musa bin Wardan] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Seseorang itu akan mengikuti agama temannya, karenanya hendaklah salah seorang diantara kalian mencermati kepada siapa ia berteman.\" Berkata Abu Isa: Hadits ini hasan gharib."},"2293":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ نَصْرٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ سُفْيَانَ بْنِ عُيَيْنَةَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ هُوَ ابْنُ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ الْأَنْصَارِيُّ قَال سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتْبَعُ الْمَيِّتَ ثَلَاثٌ فَيَرْجِعُ اثْنَانِ وَيَبْقَى وَاحِدٌ يَتْبَعُهُ أَهْلُهُ وَمَالُهُ وَعَمَلُهُ فَيَرْجِعُ أَهْلُهُ وَمَالُهُ وَيَبْقَى عَمَلُهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Suwaid bin Nashr] telah mengkhabarkan kepada kami [Abdullah bin Al Mubarak] dari [Sufyan bin 'Uyainah] dari [Abdullah bin Abu Bakar bin Muhammad bin 'Amru bin Hazm Al Anshari] berkata: Aku mendengar [Anas bin Malik] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Mayit diikuti oleh tiga hal, yang dua kembali dan yang satu menetap; ia diikuti keluarga, harta dan amalnya, keluar dan hartanya kembali sedangkan amalnya menetap.\" Berkata Abu Isa: Hadits ini hasan shahih."},"2294":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ نَصْرٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ أَخْبَرَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ حَدَّثَنِي أَبُو سَلَمَةَ الْحِمْصِيُّ وَحَبِيبُ بْنُ صَالِحٍ عَنْ يَحْيَى بْنِ جَابِرٍ الطَّائِيِّ عَنْ مِقْدَامِ بْنِ مَعْدِي كَرِبَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مَلَأَ آدَمِيٌّ وِعَاءً شَرًّا مِنْ بَطْنٍ بِحَسْبِ ابْنِ آدَمَ أُكُلَاتٌ يُقِمْنَ صُلْبَهُ فَإِنْ كَانَ لَا مَحَالَةَ فَثُلُثٌ لِطَعَامِهِ وَثُلُثٌ لِشَرَابِهِ وَثُلُثٌ لِنَفَسِهِحَدَّثَنَا الْحَسَنُ بْنُ عَرَفَةَ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ نَحْوَهُ و قَالَ الْمِقْدَامُ بْنُ مَعْدِي كَرِبَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ يَذْكُرْ فِيهِ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Suwaid bin Nashr] telah mengkhabarkan kepada kami [Abdullah bin Al Mubarak] telah mengkhabarkan kepada kami [Isma'il bin 'Ayyasy] telah menceritakan kepadaku [Abu Salamah Al Himshi] dan [Habib bin Shalih] dari [Yahya bin Jabir Ath Tho`i] dari [Miqdam bin Ma'dikarib] berkata: Aku mendengar Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Manusia tidak memenuhi wadah yang buruk melebihi perut, cukup bagi manusia beberapa suapan yang menegakkan tulang punggungnya, bila tidak bisa maka sepertiga untuk makanannya, sepertiga untuk minumnya dan sepertiga untuk nafasnya.\" Telah menceritakan kepada kami [Al Hasan bin 'Arafah] telah menceritakan kepada kami [Isma'il bin 'Ayyasy] Sepertinya dan berkata Al Miqdam bin Ma'dikarib dari Nabi Shallallahu 'alaihi wa Salam namun didalamnya ia tidak menyebut: Aku mendengar nabi Shallallahu 'alaihi wa Salam. Berkata Abu Isa: Hadits ini hasan shahih."},"2295":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا مُعَاوِيَةُ بْنُ هِشَامٍ عَنْ شَيْبَانَ عَنْ فِرَاسٍ عَنْ عَطِيَّةَ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ يُرَائِي يُرَائِي اللَّهُ بِهِ وَمَنْ يُسَمِّعْ يُسَمِّعْ اللَّهُ بِهِ قَالَ وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ لَا يَرْحَمْ النَّاسَ لَا يَرْحَمْهُ اللَّهُوَفِي الْبَاب عَنْ جُنْدَبٍ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Mua'wiyah bin Hisyam] dari [Syaiban] dari [Firas] dari ['Athiyah] dari [Abu Sa'id] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Barangsiapa tidak menyayangi sesama, Allah tidak menyayanginya.\" Dalam hal ini ada hadits serupa dari Jundub dan Abdullah bin 'Amru. Berkata Abu Isa: Hadits ini hasan shahih gharib melalui sanad ini."},"2296":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ نَصْرٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ أَخْبَرَنَا حَيْوَةُ بْنُ شُرَيْحٍ أَخْبَرَنِي الْوَلِيدُ بْنُ أَبِي الْوَلِيدِ أَبُو عُثْمَانَ الْمَدَائِنِيُّ أَنَّ عُقْبَةَ بْنَ مُسْلِمٍ حَدَّثَهُ أَنَّ شُفَيًّا الْأَصْبَحِيَّ حَدَّثَهُأَنَّهُ دَخَلَ الْمَدِينَةَ فَإِذَا هُوَ بِرَجُلٍ قَدْ اجْتَمَعَ عَلَيْهِ النَّاسُ فَقَالَ مَنْ هَذَا فَقَالُوا أَبُو هُرَيْرَةَ فَدَنَوْتُ مِنْهُ حَتَّى قَعَدْتُ بَيْنَ يَدَيْهِ وَهُوَ يُحَدِّثُ النَّاسَ فَلَمَّا سَكَتَ وَخَلَا قُلْتُ لَهُ أَنْشُدُكَ بِحَقٍّ وَبِحَقٍّ لَمَا حَدَّثْتَنِي حَدِيثًا سَمِعْتَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَقَلْتَهُ وَعَلِمْتَهُ فَقَالَ أَبُو هُرَيْرَةَ أَفْعَلُ لَأُحَدِّثَنَّكَ حَدِيثًا حَدَّثَنِيهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَقَلْتُهُ وَعَلِمْتُهُ ثُمَّ نَشَغَ أَبُو هُرَيْرَةَ نَشْغَةً فَمَكَثَ قَلِيلًا ثُمَّ أَفَاقَ فَقَالَ لَأُحَدِّثَنَّكَ حَدِيثًا حَدَّثَنِيهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هَذَا الْبَيْتِ مَا مَعَنَا أَحَدٌ غَيْرِي وَغَيْرُهُ ثُمَّ نَشَغَ أَبُو هُرَيْرَةَ نَشْغَةً أُخْرَى ثُمَّ أَفَاقَ فَمَسَحَ وَجْهَهُ فَقَالَ لَأُحَدِّثَنَّكَ حَدِيثًا حَدَّثَنِيهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا وَهُوَ فِي هَذَا الْبَيْتِ مَا مَعَنَا أَحَدٌ غَيْرِي وَغَيْرُهُ ثُمَّ نَشَغَ أَبُو هُرَيْرَةَ نَشْغَةً أُخْرَى ثُمَّ أَفَاقَ وَمَسَحَ وَجْهَهُ فَقَالَ أَفْعَلُ لَأُحَدِّثَنَّكَ حَدِيثًا حَدَّثَنِيهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا مَعَهُ فِي هَذَا الْبَيْتِ مَا مَعَهُ أَحَدٌ غَيْرِي وَغَيْرُهُ ثُمَّ نَشَغَ أَبُو هُرَيْرَةَ نَشْغَةً شَدِيدَةً ثُمَّ مَالَ خَارًّا عَلَى وَجْهِهِ فَأَسْنَدْتُهُ عَلَيَّ طَوِيلًا ثُمَّ أَفَاقَ فَقَالَ حَدَّثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ اللَّهَ تَبَارَكَ وَتَعَالَى إِذَا كَانَ يَوْمُ الْقِيَامَةِ يَنْزِلُ إِلَى الْعِبَادِ لِيَقْضِيَ بَيْنَهُمْ وَكُلُّ أُمَّةٍ جَاثِيَةٌ فَأَوَّلُ مَنْ يَدْعُو بِهِ رَجُلٌ جَمَعَ الْقُرْآنَ وَرَجُلٌ يَقْتَتِلُ فِي سَبِيلِ اللَّهِ وَرَجُلٌ كَثِيرُ الْمَالِ فَيَقُولُ اللَّهُ لِلْقَارِئِ أَلَمْ أُعَلِّمْكَ مَا أَنْزَلْتُ عَلَى رَسُولِي قَالَ بَلَى يَا رَبِّ قَالَ فَمَاذَا عَمِلْتَ فِيمَا عُلِّمْتَ قَالَ كُنْتُ أَقُومُ بِهِ آنَاءَ اللَّيْلِ وَآنَاءَ النَّهَارِ فَيَقُولُ اللَّهُ لَهُ كَذَبْتَ وَتَقُولُ لَهُ الْمَلَائِكَةُ كَذَبْتَ وَيَقُولُ اللَّهُ بَلْ أَرَدْتَ أَنْ يُقَالَ إِنَّ فُلَانًا قَارِئٌ فَقَدْ قِيلَ ذَاكَ وَيُؤْتَى بِصَاحِبِ الْمَالِ فَيَقُولُ اللَّهُ لَهُ أَلَمْ أُوَسِّعْ عَلَيْكَ حَتَّى لَمْ أَدَعْكَ تَحْتَاجُ إِلَى أَحَدٍ قَالَ بَلَى يَا رَبِّ قَالَ فَمَاذَا عَمِلْتَ فِيمَا آتَيْتُكَ قَالَ كُنْتُ أَصِلُ الرَّحِمَ وَأَتَصَدَّقُ فَيَقُولُ اللَّهُ لَهُ كَذَبْتَ وَتَقُولُ لَهُ الْمَلَائِكَةُ كَذَبْتَ وَيَقُولُ اللَّهُ تَعَالَى بَلْ أَرَدْتَ أَنْ يُقَالَ فُلَانٌ جَوَادٌ فَقَدْ قِيلَ ذَاكَ وَيُؤْتَى بِالَّذِي قُتِلَ فِي سَبِيلِ اللَّهِ فَيَقُولُ اللَّهُ لَهُ فِي مَاذَا قُتِلْتَ فَيَقُولُ أُمِرْتُ بِالْجِهَادِ فِي سَبِيلِكَ فَقَاتَلْتُ حَتَّى قُتِلْتُ فَيَقُولُ اللَّهُ تَعَالَى لَهُ كَذَبْتَ وَتَقُولُ لَهُ الْمَلَائِكَةُ كَذَبْتَ وَيَقُولُ اللَّهُ بَلْ أَرَدْتَ أَنْ يُقَالَ فُلَانٌ جَرِيءٌ فَقَدْ قِيلَ ذَاكَ ثُمَّ ضَرَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى رُكْبَتِي فَقَالَ يَا أَبَا هُرَيْرَةَ أُولَئِكَ الثَّلَاثَةُ أَوَّلُ خَلْقِ اللَّهِ تُسَعَّرُ بِهِمْ النَّارُ يَوْمَ الْقِيَامَةِو قَالَ الْوَلِيدُ أَبُو عُثْمَانَ فَأَخْبَرَنِي عُقْبَةُ بْنُ مُسْلِمٍ أَنَّ شُفَيًّا هُوَ الَّذِي دَخَلَ عَلَى مُعَاوِيَةَ فَأَخْبَرَهُ بِهَذَا قَالَ أَبُو عُثْمَانَ وَحَدَّثَنِي الْعَلَاءُ بْنُ أَبِي حَكِيمٍ أَنَّهُ كَانَ سَيَّافًا لِمُعَاوِيَةَ فَدَخَلَ عَلَيْهِ رَجُلٌ فَأَخْبَرَهُ بِهَذَا عَنْ أَبِي هُرَيْرَةَ فَقَالَ مُعَاوِيَةُ قَدْ فُعِلَ بِهَؤُلَاءِ هَذَا فَكَيْفَ بِمَنْ بَقِيَ مِنْ النَّاسِ ثُمَّ بَكَى مُعَاوِيَةُ بُكَاءً شَدِيدًا حَتَّى ظَنَنَّا أَنَّهُ هَالِكٌ وَقُلْنَا قَدْ جَاءَنَا هَذَا الرَّجُلُ بِشَرٍّ ثُمَّ أَفَاقَ مُعَاوِيَةُ وَمَسَحَ عَنْ وَجْهِهِ وَقَالَ صَدَقَ اللَّهُ وَرَسُولُهُ{ مَنْ كَانَ يُرِيدُ الْحَيَاةَ الدُّنْيَا وَزِينَتَهَا نُوَفِّ إِلَيْهِمْ أَعْمَالَهُمْ فِيهَا وَهُمْ فِيهَا لَا يُبْخَسُونَ أُولَئِكَ الَّذِينَ لَيْسَ لَهُمْ فِي الْآخِرَةِ إِلَّا النَّارُ وَحَبِطَ مَا صَنَعُوا فِيهَا وَبَاطِلٌ مَا كَانُوا يَعْمَلُونَ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Suwaid bin Nashr] telah mengkhabarkan kepada kami [Abdullah bin Al Mubarak] telah mengkhabarkan kepada kami [Haiwah bin Syuraih] telah mengkhabarkan kepadaku [Al Walid bin Abu Al Walid Abu 'Utsman Al Mada`ini] bahwa ['Uqbah bin Muslim] telah menceritakan padanya bahwa [Syufaiya Al Ashbahi] telah menceritakan padanya bahwa ia masuk ke Madina, ternyata ada seseorang yang dikerumuni orang-orang. Syufaiya bertanya: Siapa dia? Mereka menjawab: Abu Hurairah. Aku mendekatinya hingga aku duduk di hadapannya sementara ia tengah menceritakan kepada orang-orang. Saat diam dan selesai, aku berkata padanya: Aku menyumpahmu dengan kebenaran dan dengan kebenaran, ceritakanlah suatu hadits padaku yang kau dengar dari Rasulullah Shallallahu 'alahi wa Salam yang kau fahami dan yang kau ketahui. Berkata [Abu Hurairah]: Baik, aku akan menceritakan suatu hadits kepadamu yang diceritakan Rasulullah Shallallahu 'alahi wa Salam kepadaku yang aku fahami dan aku ketahui. Abu Hurairah terisak-isak, setelah itu ia diam sejenak, setelah sadar ia berkata: Aku akan menceritakan kepada hadits yang diceritakan Rasulullah Shallallahu 'alahi wa Salam kepadaku di rumah ini, tidak ada orang lain bersamaku. Setelah itu Abu Hurairah terisak-isak lagi, setelah mereda ia membasuh wajahnya lalu berkata: Aku akan menceritakan kepadamu hadits yang diceritakan Rasulullah Shallallahu 'alahi wa Salam kepadaku, aku dan beliau di rumah ini, tidak ada orang lain bersamamu. Setelah itu Abu Hurairah terisak-isak lagi, setelah mereda ia membeslah wajahnya lalu berkata: Baik, aku akan menceritakan suatu hadis kepadamu yang diceritakan Rasulullah Shallallahu 'alahi wa Salam kepadaku, aku bersama beliau di rumah ini, tidak ada orang lain bersama beliau selain aku. Setelah itu Abu Hurairah terisak-isak dengan keras, setelah itu ia miring tersungkur di atas wajahnya lalu aku menyandarkannya dibadanku selang berapa lama, setelah sadar ia berkata: Telah menceritakan kepadaku Rasulullah Shallallahu 'alahi wa Salam, bahwa Allah Tabaaraka wa Ta'ala pada hari kiamat akan turun kepada para hamba untuk memutuskan di antara mereka dan masing-masing ummat berlutut. Orang pertama yang dipanggil adalah orang hafal al-Qur`an, orang yang terbunuh di jalan Allah dan orang yang banyak hartanya lalu Allah berkata kepada penghafal al-Qur`an: Bukankah Aku mengajarimu sesuatu yang Aku turunkan pada rasulKu? Ia menjawab: Benar, wahai Rabb. Allah bertanya: Apa yang kau amalkan dari ilmu yang diajarkan padamu? Ia menjawab: Dengannya, dulu aku bangun shalat di malam hari dan di siang hari. Allah berfirman padanya: Kau dusta. Para malaikat berkata padanya: Kau dusta. Allah berfirman: Tapi kau ingin memperoleh pujian bahwa si fulan ahli baca al-Qur`an dan memang telah kau peroleh ujian itu. Setelah itu pemilik harta didatangkan lalu Allah bertanya kepadanya: Bukankah Aku melapangkan rizkimu hingga Aku tidak membiarkanmu memerlukan kepada siapa pun? Orang itu menjawab: Benar, wahai Rabb. Allah bertanya: Lalu apa yang kau lakukan dengan apa yang Aku berikan padamu? Ia menjawab: Aku menyambung silaturrahim dan bersedekah. Allah berfirman padanya: Kau dusta. para malaikat berkata padanya: Kau dusta. Allah berfirman: Tapi kau ingin peroleh gelar bahwa si fulan dermawan dan memang telah kau peroleh gelar itu. Kemudian orang yang terbunuh di jalan Allah didatangkan, Allah bertanya kepadanya: Karena apa kau terbunuh? Ia menjawab: Aku diperintahkan berjihad di jalanMu lalu aku berperang hingga aku terbunuh. Allah berfirman padanya: Kau dusta. para malaikat berkata padanya: Kau dusta. Allah berfirman: Tapi kau ingin peroleh gelar si fulan pemberani dan menag telah kau peroleh gelar itu.\" Setelah itu Rasulullah Shallallahu 'alahi wa Salam memukul lututku dan bersabda: \"Hai Abu Hurairah, ketiga orang itulah makhluk Allah pertama-tama yang neraka dinyalakan karena mereka pada hari kiamat.\" Berkata Al Walid Abu 'Utsman: telah mengkhabarkan kepadaku 'Uqbah bin Muslim bahwa Syufaiya dialah yang menemui Mu'awiyah lalu memberitahukan hadits ini padanya. Berkata [Abu 'Utsman]: telah menceritakan kepadaku [Al 'Alla` bin Abu Hakim] ia adalah algojo Mu'awiyah, ia memasuki kediamannya, ia bersama seseorang lalu ia memberitahukan hadits dari Abu Hurairah ini padanya lalu Mu'awiyah berkata: Mereka diperlakukan seperti itu lalu bagaimana sekiranya dengan semua orang? Mu'awiyah menangis dengan keras hingga kami mengira ia meninggal. Kami berkata: Orang ini datang membawa keburukan. Setelah itu Mu'awiyah sadar dan membeslah wajahnya, ia berkata: Maha Benar Allah dan rasulNya: \"Barangsiapa yang menghendaki kehidupan dunia dan perhiasannya, niscaya kami berikan kepada mereka balasan pekerjaan mereka di dunia dengan sempurna dan mereka di dunia itu tidak akan dirugikan. Itulah orang-orang yang tidak memperoleh di akhirat, kecuali neraka dan lenyaplah di akhirat itu apa yang Telah mereka usahakan di dunia dan sia-sialah apa yang Telah mereka kerjakan.\" (Huud: 15-16) Berkata Abu Isa: Hadits ini hasan gharib."},"2297":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنِي الْمُحَارِبِيُّ عَنْ عَمَّارِ بْنِ سَيْفٍ الضَّبِّيِّ عَنْ أَبِي مُعَانٍ الْبَصْرِيِّ عَنْ ابْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَعَوَّذُوا بِاللَّهِ مِنْ جُبِّ الْحَزَنِ قَالُوا يَا رَسُولَ اللَّهِ وَمَا جُبُّ الْحَزَنِ قَالَ وَادٍ فِي جَهَنَّمَ تَتَعَوَّذُ مِنْهُ جَهَنَّمُ كُلَّ يَوْمٍ مِائَةَ مَرَّةٍ قُلْنَا يَا رَسُولَ اللَّهِ وَمَنْ يَدْخُلُهُ قَالَ الْقُرَّاءُ الْمُرَاءُونَ بِأَعْمَالِهِمْقَالَ هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepadaku [Al Muharibi] dari ['Ammar bin Saif Adl Dluba'I] dari [Abu Mu'an Al Bashri] dari [Ibnu Sirin] dari [Abu Hurairah] dia berkata bahwa Rasulullah Shallallahu 'alaihi wa Salam bersabda: Berlindunglah kalian kepada Allah dari dari Jubbil hazan.\" para sahabat bertanya: Apa itu jubbil hazan wahai Rasulullah? beliau menjawab: \"Sebuah lembah di neraka jahannam, sementara neraka jahannam sendiri berlindung darinya setiap hari sebanyak seratus kali, \" kami bertanya: Dan siapakah yang akan memasukinya? beliau menjawab: Para pembaca Al Qur`an yang memamerkan perbuatan mereka.\" Dia (Abu Isa) berkata: Hadits ini hasan gharib."},"2298":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا أَبُو سِنَانٍ الشَّيْبَانِيُّ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ الرَّجُلُ يَعْمَلُ الْعَمَلَ فَيُسِرُّهُ فَإِذَا اطُّلِعَ عَلَيْهِ أَعْجَبَهُ ذَلِكَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَهُ أَجْرَانِ أَجْرُ السِّرِّ وَأَجْرُ الْعَلَانِيَةِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَقَدْ رَوَى الْأَعْمَشُ وَغَيْرُهُ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ أَبِي صَالِحٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْسَلًا وَأَصْحَابُ الْأَعْمَشِ لَمْ يَذْكُرُوا فِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَ أَبُو عِيسَى وَقَدْ فَسَّرَ بَعْضُ أَهْلِ الْعِلْمِ هَذَا الْحَدِيثَ فَقَالَ إِذَا اطُّلِعَ عَلَيْهِ فَأَعْجَبَهُ فَإِنَّمَا مَعْنَاهُ أَنْ يُعْجِبَهُ ثَنَاءُ النَّاسِ عَلَيْهِ بِالْخَيْرِ لِقَوْلِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْتُمْ شُهَدَاءُ اللَّهِ فِي الْأَرْضِ فَيُعْجِبُهُ ثَنَاءُ النَّاسِ عَلَيْهِ لِهَذَا لِمَا يَرْجُو بِثَنَاءِ النَّاسِ عَلَيْهِ فَأَمَّا إِذَا أَعْجَبَهُ لِيَعْلَمَ النَّاسُ مِنْهُ الْخَيْرَ لِيُكْرَمَ عَلَى ذَلِكَ وَيُعَظَّمَ عَلَيْهِ فَهَذَا رِيَاءٌ و قَالَ بَعْضُ أَهْلِ الْعِلْمِ إِذَا اطُّلِعَ عَلَيْهِ فَأَعْجَبَهُ رَجَاءَ أَنْ يَعْمَلَ بِعَمَلِهِ فَيَكُونُ لَهُ مِثْلُ أُجُورِهِمْ فَهَذَا لَهُ مَذْهَبٌ أَيْضًا","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Abu Daud] telah menceritakan kepada kami [Abu Sinan Asy Syaibani] dari [Habib bin Abu Tsabit] dari [Abu Shalih] dari [Abu Hurairah] dia berkata: Seseorang berkata: Wahai Rasulullah ada seseorang yang berbuat suatu amal kemudian dia rahasiakan namun apabila diketahui oleh orang dia menjadi takjub karenanya. Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Baginya dua pahala; pahala dia merahasiakan dan pahala dia menampakkan.\" Abu Isa berkata: Hadits ini hasan gharib, [Al A'masy] dan yang lainnya telah meriwayatkan dari [Habib bin Abu Tsabit] dari [Abu Shalih] dari Nabi Shallallahu 'alaihi wa Salam secara mursal, dan sahabat sahabat Al A'masy tidak menyebutkan dalam hadits: Dari Abu Hurairah. Abu Isa berkata: Sebagian ahli ilmu menafsirkan hadits ini dan berkata: Apabila diketahui dan dia takjub karenanya maka itu artinya dia takjub dengan pujian baik orang orang kepadanya, karena sabda Rasulullah Shallallahu 'alaihi wa Salam: Kalian adalah saksi saksi Allah di bumi.\" Alhasil, pujian manusia terhadapnya, memang hanyalah sekedar untuk syahadat (persaksian manusia) yang diharapkan. adapun jika dia takjub agar orang orang tahu kebaikannya supaya dihormati karenanya dan diagungkan karenanya maka ini namanya riya'. Dan sebagian ahli ilmu berpendapat jika diketahui amalnya oleh orang lalu dia takjub dengan harapan orang melakukan apa yang dia lakukan sehingga dia mendapatkan seperti pahala mereka, maka ini ada pendapat lain lagi."},"2299":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا إِسْمَعِيلُ بْنُ جَعْفَرٍ عَنْ حُمَيْدٍ عَنْ أَنَسٍ أَنَّهُ قَالَجَاءَ رَجُلٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ مَتَى قِيَامُ السَّاعَةِ فَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الصَّلَاةِ فَلَمَّا قَضَى صَلَاتَهُ قَالَ أَيْنَ السَّائِلُ عَنْ قِيَامِ السَّاعَةِ فَقَالَ الرَّجُلُ أَنَا يَا رَسُولَ اللَّهِ قَالَ مَا أَعْدَدْتَ لَهَا قَالَ يَا رَسُولَ اللَّهِ مَا أَعْدَدْتُ لَهَا كَبِيرَ صَلَاةٍ وَلَا صَوْمٍ إِلَّا أَنِّي أُحِبُّ اللَّهَ وَرَسُولَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَرْءُ مَعَ مَنْ أَحَبَّ وَأَنْتَ مَعَ مَنْ أَحْبَبْتَ فَمَا رَأَيْتُ فَرِحَ الْمُسْلِمُونَ بَعْدَ الْإِسْلَامِ فَرَحَهُمْ بِهَذَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ صَحِيحٌ","id":"Telah menceritakan kepada kami ['Ali bin Hujar] telah mengkhabarkan kepada kami [Isma'il bin Ja'far] dari [Humaid] dari [Anas] ia berkata: Seseorang mendatangi Rasulullah Shallallahu 'alahi wa Salam lalu bertanya: Wahai Rasulullah, kapankah kiamat terjadi? Lalu nabi Shallallahu 'alaihi wa Salam berdiri untuk shalat, seusai shalat Rasulullah Shallallahu 'alahi wa Salam bertanya: \"Mana si penanya tentang hari kiamat tadi?\" orang itu menjawab: Saya wahai Rasulullah. Rasulullah Shallallahu 'alaihi wa salam bertanya: \"Apa yang telah kau persiapkan untuknya?\" orang itu menjawab: Aku tidak menyiapkan sekian banyak shalat dan puasa untuknya, hanya saja aku mencintai Allah dan rasulNya. Rasulullah Shallallahu 'alahi wa Salam bersabda: \"Seseorang bersama orang yang ia cintai dan engkau bersama orang yang kau cintai.\" Aku tidak mengetahui kebahagian kaum muslimin setelah Islam seperti kegembiraan mereka karena hal ini. Berkata Abu Isa: Hadits ini shahih."},"2300":{"ar":"حَدَّثَنَا أَبُو هِشَامٍ الرِّفَاعِيُّ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ أَشْعَثَ عَنْ الْحَسَنِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَرْءُ مَعَ مَنْ أَحَبَّ وَلَهُ مَا اكْتَسَبَوَفِي الْبَاب عَنْ عَلِيٍّ وَعَبْدِ اللَّهِ بْنِ مَسْعُودٍ وَصَفْوَانَ بْنِ عَسَّالٍ وَأَبِي هُرَيْرَةَ وَأَبِي مُوسَى قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ حَدِيثِ الْحَسَنِ عَنْ أَنَسِ بْنِ مَالِكٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ مِنْ غَيْرِ وَجْهٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu Hisyam Ar Rafi'i] telah menceritakan kepada kami [Hafsh bin Ghiyats] dari [Asy'ats] dari [Al Hasan] dari [Anas bin Malik] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Orang itu bersama orang yang ia cintai dan ia mendapatkan apa yang ia kerjakannya.\" Dalam hal ini ada hadits serupa dari 'Ali, Abdullah bin Mas'ud, Shafwan bin 'Assal, Abu Hurairah, Abu Musa. Berkata Abu Isa: Hadits ini hasan gharib dari hadits Al Hasan dari Anas bin Malik dari nabi Shallallahu 'alaihi wa Salam. Hadits ini juga diriwayatkan melalui banyak sanad dari nabi Shallallahu 'alaihi wa Salam."},"2301":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا سُفْيَانُ عَنْ عَاصِمٍ عَنْ زِرِّ بْنِ حُبَيْشٍ عَنْ صَفْوَانَ بْنِ عَسَّالٍ قَالَجَاءَ أَعْرَابِيٌّ جَهْوَرِيُّ الصَّوْتِ قَالَ يَا مُحَمَّدُ الرَّجُلُ يُحِبُّ الْقَوْمَ وَلَمَّا يَلْحَقْ بِهِمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَرْءُ مَعَ مَنْ أَحَبَّقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ الضَّبِّيُّ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَاصِمٍ عَنْ زِرٍّ عَنْ صَفْوَانَ بْنِ عَسَّالٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ حَدِيثِ مَحْمُودٍ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Yahya bin Adam] telah menceritakan kepada kami [Sufyan] dar ['Ashim] dari [Zirr bin Hubaisy] dari [Shafwan bin 'Assal] berkata: Seorang badui bersuara lantang datang, ia bertanya: Hai Muhammad, bagaimana nasib seseorang yang mencintai suatu kaum tapi tidak bertemu dengan meraka? Rasulullah Shallallahu 'alahi wa Salam menjawab: \"Orang itu bersama yang ia cintai.\" Berkata Abu Isa: Hadits ini hasan shahih. Telah menceritakan kepada kami [Ahmad bin 'Abdah Adl Dlabyi] telah menceritakan kepada kami [Hammad bin Zaid] dari ['Ashim] dari [Zirr] dari [Shafwan bin 'Assal] dari nabi Shallallahu 'alaihi wa Salam seperti hadits Mahmud."},"2302":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا وَكِيعٌ عَنْ جَعْفَرِ بْنِ بُرْقَانَ عَنْ يَزِيدَ بْنِ الْأَصَمِّ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ يَقُولُ أَنَا عِنْدَ ظَنِّ عَبْدِي بِي وَأَنَا مَعَهُ إِذَا دَعَانِيقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Waki'] dari [Ja'far bin Burqan] dari [Yazid bin Al Asham] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Allah berfirman: Aku berada pada prasangka hamba-Ku terhadapKu dan Aku bersamanya bila ia menyeruKu.\" Berkata Abu Isa: Hadits ini hasan shahih."},"2303":{"ar":"حَدَّثَنَا مُوسَى بْنُ عَبْدِ الرَّحْمَنِ الْكِنْدِيُّ الْكُوفِيُّ حَدَّثَنَا زَيْدُ بْنُ حُبَابٍ حَدَّثَنَا مُعَاوِيَةُ بْنُ صَالِحٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ جُبَيْرِ بْنِ نُفَيْرٍ الْحَضْرَمِيُّ عَنْ أَبِيهِ عَنْ النَّوَّاسِ بْنِ سَمْعَانَأَنَّ رَجُلًا سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْبِرِّ وَالْإِثْمِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبِرُّ حُسْنُ الْخُلُقِ وَالْإِثْمُ مَا حَاكَ فِي نَفْسِكَ وَكَرِهْتَ أَنْ يَطَّلِعَ عَلَيْهِ النَّاسُحَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا مُعَاوِيَةُ بْنُ صَالِحٍ نَحْوَهُ إِلَّا أَنَّهُ قَالَ سَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Musa bin Abdurrahman Al Kindi Al Kufi] telah menceritakan kepada kami [Zaid bin Hubab] telah menceritakan kepada kami [Mu'awiyah bin Shali] telah menceritakan kepada kami [Abdurrahman bin Jubair bin Nufair Al Hadlrami] dari [ayahnya] dari [An Nawwas bin Sam'an], seseorang bertanya kepada Rasulullah Shallallahu 'alahi wa Salam tentang kebajikan dan dosa, nabi Shallallahu 'alaihi wa Salam menjawab: \"Kebajikan adalah akhlak yang baik dan dosa adalah sesuatu yang menggelisahkan dalam jiwamu dan kau tidak mau orang-orang mengetahuinya.\" Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Mu'awiyah bin Shalih] sepertinya hanya saja ia berkata: Aku bertanya kepada nabi Shallallahu 'alaihi wa Salam. Berkata Abu Isa: Hadits ini hasan shahih."},"2304":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا كَثِيرُ بْنُ هِشَامٍ حَدَّثَنَا جَعْفَرُ بْنُ بُرْقَانَ حَدَّثَنَا حَبِيبُ بْنُ أَبِي مَرْزُوقٍ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ أَبِي مُسْلِمٍ الْخَوْلَانِيِّ حَدَّثَنِي مُعَاذُ بْنُ جَبَلٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ قَالَ اللَّهُ عَزَّ وَجَلَّ الْمُتَحَابُّونَ فِي جَلَالِي لَهُمْ مَنَابِرُ مِنْ نُورٍ يَغْبِطُهُمْ النَّبِيُّونَ وَالشُّهَدَاءُوَفِي الْبَاب عَنْ أَبِي الدَّرْدَاءِ وَابْنِ مَسْعُودٍ وَعُبَادَةَ بْنِ الصَّامِتِ وَأَبِي هُرَيْرَةَ وَأَبِي مَالِكٍ الْأَشْعَرِيِّ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَأَبُو مُسْلِمٍ الْخَوْلَانِيُّ اسْمُهُ عَبْدُ اللَّهِ بْنُ ثَوْبَ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Katsir bin Hisyam] telah menceritakan kepada kami [Ja'far bin Burqan] telah menceritakan kepada kami [Habib bin Abu Marzuq] dari ['Atho` bin Abu Rabah] dari [Abu Muslim Al Khaulani] telah menceritakan kepadaku [Mu'adz bin Jabal] berkata: Aku mendengar Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Allah 'azza wajalla berfirman: Orang-orang yang saling mencintai karena keluhuranKu, mereka mendapatkan mimbar-mimbar dari cahaya yang membuat para nabi dan syuhada` iri.\" Dalam hal ini ada hadits serupa dari Abu Darda`, Ibnu Mas'ud, 'Ubadah bin Shamid, Abu Hurairah dan Abu Malik Al Asy'ari. Berkata Abu Isa: Hadits ini hasan shahih dan Abu Muslim Al Khaulani namanya Abdullah bin Tsaub."},"2305":{"ar":"حَدَّثَنَا الْأَنْصَارِيُّ حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكٌ عَنْ خُبَيْبِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ حَفْصِ بْنِ عَاصِمٍ عَنْ أَبِي هُرَيْرَةَ أَوْ عَنْ أَبِي سَعِيدٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَبْعَةٌ يُظِلُّهُمْ اللَّهُ فِي ظِلِّهِ يَوْمَ لَا ظِلَّ إِلَّا ظِلُّهُ إِمَامٌ عَادِلٌ وَشَابٌّ نَشَأَ بِعِبَادَةِ اللَّهِ وَرَجُلٌ كَانَ قَلْبُهُ مُعَلَّقًا بِالْمَسْجِدِ إِذَا خَرَجَ مِنْهُ حَتَّى يَعُودَ إِلَيْهِ وَرَجُلَانِ تَحَابَّا فِي اللَّهِ فَاجْتَمَعَا عَلَى ذَلِكَ وَتَفَرَّقَا وَرَجُلٌ ذَكَرَ اللَّهَ خَالِيًا فَفَاضَتْ عَيْنَاهُ وَرَجُلٌ دَعَتْهُ امْرَأَةٌ ذَاتُ حَسَبٍ وَجَمَالٍ فَقَالَ إِنِّي أَخَافُ اللَّهَ وَرَجُلٌ تَصَدَّقَ بِصَدَقَةٍ فَأَخْفَاهَا حَتَّى لَا تَعْلَمَ شِمَالُهُ مَا تُنْفِقُ يَمِينُهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَهَكَذَا رُوِيَ هَذَا الْحَدِيثُ عَنْ مَالِكِ بْنِ أَنَسٍ مِنْ غَيْرِ وَجْهٍ مِثْلَ هَذَا وَشَكَّ فِيهِ وَقَالَ عَنْ أَبِي هُرَيْرَةَ أَوْ عَنْ أَبِي سَعِيدٍ وَعُبَيْدُ اللَّهِ بْنُ عُمَرَ رَوَاهُ عَنْ خُبَيْبِ بْنِ عَبْدِ الرَّحْمَنِ وَلَمْ يَشُكَّ فِيهِ يَقُولُ عَنْ أَبِي هُرَيْرَةَ حَدَّثَنَا سَوَّارُ بْنُ عَبْدِ اللَّهِ الْعَنْبَرِيُّ وَمُحَمَّدُ بْنُ الْمُثَنَّى قَالَا حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ حَدَّثَنِي خُبَيْبٌ عَنْ حَفْصِ بْنِ عَاصِمٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ حَدِيثِ مَالِكِ بْنِ أَنَسٍ بِمَعْنَاهُ إِلَّا أَنَّهُ قَالَ كَانَ قَلْبُهُ مُعَلَّقًا بِالْمَسَاجِدِ وَقَالَ ذَاتُ مَنْصِبٍ وَجَمَالٍ","id":"Telah menceritakan kepada kami [Al Anshari] telah menceritakan kepada kami [Ma'an] telah menceritakan kepada kami [Malik] dari [Khubaib bin Abdurrahman] dari [Hafsh bin 'Ashim] dari [Abu Hurairah] atau dari [Abu Sa'id], Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Tujuh (golongan) yang akan dinaungi Allah pada hari di mana tidak ada naungan lain kecuali naunganNya; pemimpin adil, pemuda yang tumbuh dalam beribadah kepada Allah, orang yang hatinya terkait dengan masjid bila ia keluar meninggalkannya hingga ia kembali lagi, dua orang yang saling mencintai karena Allah, keduanya berkumpul karena itu dan berpisah karena itu, orang yang mengingat Allah saat menyendiri lalu kedua matanya berlinang, lelaki yang diajak oleh wanita yang memiliki kedudukan dan kecantikan lalu ia berkata: Aku takut Allah, seseorang bersedekah lalu menyembunyikannya hingga tangan kirinya tidak mengetahui apa yang diinfakkan oleh tangan kanannya.\" Berkata Abu Isa: Hadits ini hasan shahih. Seperti itulah hadits ini diriwayatkan dari Malik bin Anas tanpa sanad seperti ini dan ia ragu didalamnya. Ia berkata: Dari Abu Hurairah, atau dari Abu Sa'id dan 'Ubaidullah bin Umar. Ia meriwayatkannya dari Khubaib bin Abdurrahman, ia tidak ragu dalam sanad ini, ia berkata: Dari Abu Hurairah. Telah menceritakan kepada kami [Sawwar bin Abdullah Al 'Anbari] dan [Muhammad bin Al Mutsanna] keduanya berkata: Telah menceritakan kepada kami [Yahya bin Sa'id] dari ['Ubaidullah bin Umar] telah menceritakan kepadaku [Khubaib] dari [Hafsh bin 'Ashim] dari [Abu Hurairah] dari nabi Shallallahu 'alaihi wa Salam seperti makna hadits Malik bin Anas, hanya saja ia berkata dalam riwayatnya: Hatinya terpaut dengan masjid. Ia juga berkata dalam riwayatnya: Yang memiliki kedudukan dan kecantikan."},"2306":{"ar":"حَدَّثَنَا بُنْدَارٌ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ حَدَّثَنَا ثَوْرُ بْنُ يَزِيدَ عَنْ حَبِيبِ بْنِ عُبَيْدٍ عَنْ الْمِقْدَامِ بْنِ مَعْدِي كَرِبَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَحَبَّ أَحَدُكُمْ أَخَاهُ فَلْيُعْلِمْهُ إِيَّاهُوَفِي الْبَاب عَنْ أَبِي ذَرٍّ وَأَنَسٍ قَالَ أَبُو عِيسَى حَدِيثُ الْمِقْدَامِ حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ وَالْمِقْدَامُ يُكْنَى أَبَا كَرِيمَةَ","id":"Telah menceritakan kepada kami [Bundar] telah menceritakan kepada kami [Yahya bin Sa'id Al Qaththan] telah menceritakan kepada kami [Tsaur bin Yazid] dari [Habib bin 'Ubaid] dari [Al Miqdam bin Ma'dikarib] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Bila salah seorang dari kalian mencintai saudaranya, hendaklah memberitahukan padanya.\" Dalam hal ini ada hadits serupa dari Abu Dzarr dan Anas. Berkata Abu Isa: Hadits Al Miqdam adalah hadits hasan shahih gharib dan Al Miqdam kuniahnya Abu Karimah."},"2307":{"ar":"حَدَّثَنَا هَنَّادٌ وَقُتَيْبَةُ قَالَا حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ عَنْ عِمْرَانَ بْنِ مُسْلِمٍ الْقَصِيرِ عَنْ سَعِيدِ بْنِ سَلْمَانَ عَنْ يَزِيدَ بْنِ نَعَامَةَ الضَّبِّيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا آخَى الرَّجُلُ الرَّجُلَ فَلْيَسْأَلْهُ عَنْ اسْمِهِ وَاسْمِ أَبِيهِ وَمِمَّنْ هُوَ فَإِنَّهُ أَوْصَلُ لِلْمَوَدَّةِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ وَلَا نَعْرِفُ لِيَزِيدَ بْنِ نَعَامَةَ سَمَاعًا مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيُرْوَى عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ هَذَا وَلَا يَصِحُّ إِسْنَادُهُ","id":"Telah menceritakan kepada kami [Hannad] dan [Qutaibah] keduanya berkata: telah menceritakan kepada kami [Hatim bin Isam'il] dari ['Imran bin Muslim Al Qashir] dari [Sa'id bin Salman] dari [Yazid bin Na'amah Ad Dabbi] berkata bahwa Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Jika seseorang berteman dengan seseorang maka hendaknya dia menanyakan tentang siapa namanya, siapa nama bapaknya dan dari mana asalnya, Karena hal itu dapat lebih menyambung rasa kecintaan.\" Abu Isa berkata: Hadits ini gharib, kami tidak mengetahuinya kecuali dari jalur sanad ini, dan kami tidak mengetahui Yazid bin Nu'amah pernah mendengar dari Nabi Shallallahu 'alaihi wa Salam, dan telah diriwayatkan dari Ibnu Umar dari Nabi Shallallahu 'alaihi wa Salam hadits yang semakna dengan ini namun sanadnya tidak shahih."},"2308":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ مُجَاهِدٍ عَنْ أَبِي مَعْمَرٍ قَالَقَامَ رَجُلٌ فَأَثْنَى عَلَى أَمِيرٍ مِنْ الْأُمَرَاءِ فَجَعَلَ الْمِقْدَادُ يَحْثُو فِي وَجْهِهِ التُّرَابَ وَقَالَ أَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَحْثُوَ فِي وُجُوهِ الْمَدَّاحِينَ التُّرَابَوَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَى زَائِدَةُ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ وَحَدِيثُ مُجَاهِدٍ عَنْ أَبِي مَعْمَرٍ أَصَحُّ وَأَبُو مَعْمَرٍ اسْمُهُ عَبْدُ اللَّهِ بْنُ سَخْبَرَةَ وَالْمِقْدَادُ بْنُ الْأَسْوَدِ هُوَ الْمِقْدَادُ بْنُ عَمْرٍو الْكِنْدِيُّ وَيُكْنَى أَبَا مَعْبَدٍ وَإِنَّمَا نُسِبَ إِلَى الْأَسْوَدِ بْنِ عَبْدِ يَغُوثَ لِأَنَّهُ كَانَ قَدْ تَبَنَّاهُ وَهُوَ صَغِيرٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Sufyan] dari [Habib bin Abu Tsabit] dari [Mujahid] dari [Abu Ma'mar] berkata: Seseorang berdiri lalu dia memuji salah seorang pemimpin, kemudian [Al Miqdad] menaburkan debu ke wajahnya, dia berkata: Rasulullah Shallallahu 'alaihi wa Salam memerintahkan kami untuk menaburkan debu ke wajah orang orang yang suka memuji. Dan dalam bab ini ada hadits dari Abu Hurairah, Abu Isa berkata: Hadits ini hasan shahih, [Za'idah] telah meriwayatkan dari [Yazid bin Abu Ziyad] dari [Mujahid] dari [Ibnu 'Abbas], adapun hadits Mujahid dari Abu Ma'mar lebih shahih, Nama Abu Ma'mar adalah Abdullah bin Syakhbarah sedangkan Al Miqdad dia adalah Al Miqdad bin 'Amru Al Kindi dan kuniyahnya Abu Ma'bad, hanyasannya dinisbatkan kepada Al Aswad bin Abdi Yaghuts karena dia telah merawatnya semasa dia kecil."},"2309":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُثْمَانَ الْكُوفِيُّ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ سَالِمٍ الْخَيَّاطِ عَنْ الْحَسَنِ عَنْ أَبِي هُرَيْرَةَ قَالَأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَحْثُوَ فِي أَفْوَاهِ الْمَدَّاحِينَ التُّرَابَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ مِنْ حَدِيثِ أَبِي هُرَيْرَةَ","id":"Telah menceritakan kepada kami [Muhammad bin 'Utsman Al Kufi] telah menceritakan kepada kami ['Ubaidullah bin Musa] dari [Salim Al Khayyath] dari [Al Hasan] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa Salam memerintahkan kami agar menaburkan debu ke mulut orang orang yang suka menyanjung. Abu Isa berkata: Hadits ini gharib dari hadits Abu Hurairah."},"2310":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ نَصْرٍ أَخْبَرَنَا ابْنُ الْمُبَارَكِ عَنْ حَيْوَةَ بْنِ شُرَيْحٍ حَدَّثَنِي سَالِمُ بْنُ غَيْلَانَ أَنَّ الْوَلِيدَ بْنَ قَيْسٍ التُّجِيبِيَّ أَخْبَرَهُ أَنَّهُ سَمِعَ أَبَا سَعِيدٍ الْخُدْرِيَّ قَالَ سَالِمٌ أَوْ عَنْ أَبِي الْهَيْثَمِ عَنْ أَبِي سَعِيدٍأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تُصَاحِبْ إِلَّا مُؤْمِنًا وَلَا يَأْكُلْ طَعَامَكَ إِلَّا تَقِيٌّقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ إِنَّمَا نَعْرِفُهُ مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Suwaid bin Nashr] telah mengkhabarkan kepada kami [Ibnu Al Mubarak] dari [Haiwah bin Syuraih] telah menceritakan kepadaku [Salim bin Ghailan] bahwa [Al Waid bin Qais At Tijiyi] telah memberitakan kepadanya bahwa ia mendengar [Abu Sa'id Al Khudri], berkata Salim atau dari [Abu Al Haitsman] dari [Abu Sa'id] ia mendengar Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Janganlah berteman kecuali dengan orang mu`min dan jangan ada yang memakan makananmu kecuali orang yang bertakwa.\" Berkata Abu Isa: Hadits ini hanya kami ketahui dari sanad ini."},"2311":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ سَعْدِ بْنِ سِنَانٍ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَرَادَ اللَّهُ بِعَبْدِهِ الْخَيْرَ عَجَّلَ لَهُ الْعُقُوبَةَ فِي الدُّنْيَا وَإِذَا أَرَادَ اللَّهُ بِعَبْدِهِ الشَّرَّ أَمْسَكَ عَنْهُ بِذَنْبِهِ حَتَّى يُوَافِيَ بِهِ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari [Yazid bin Abu Habib] dari [Sa'id bin Sinan] dari [Anas] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Apabila Allah menghendaki kebaikan kepada hambaNya, maka Allah menyegerakan hukumannya di dunia, dan apabila Allah menghendaki keburukan kepada hambaNya maka Allah menahan dosanya sehingga dia terima kelak di hari Kiamat.\""},"2312":{"ar":"وَبِهَذَا الْإِسْنَادِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ عِظَمَ الْجَزَاءِ مَعَ عِظَمِ الْبَلَاءِ وَإِنَّ اللَّهَ إِذَا أَحَبَّ قَوْمًا ابْتَلَاهُمْ فَمَنْ رَضِيَ فَلَهُ الرِّضَا وَمَنْ سَخِطَ فَلَهُ السَّخَطُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ","id":"Dan dengan sanad ini (Yaitu; Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari [Yazid bin Abu Habib] dari [Sa'id bin Sinan] dari [Anas] berkata:) dari Nabi Shallallahu 'alaihi wa Salam beliau bersabda: \"Sesungguhnya besarnya balasan tergantung dari besarnya ujian, dan apabila Allah cinta kepada suatu kaum Dia akan menguji mereka, barangsiapa yang ridla maka baginya keridlaan Allah, namun barangsiapa yang murka maka baginya kemurkaan Allah.\" Abu Isa berkata: Hadits ini hasan gharib dari jalur sanad ini."},"2313":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ أَخْبَرَنَا شُعْبَةُ عَنْ الْأَعْمَشِ قَال سَمِعْتُ أَبَا وَائِلٍ يَقُولُ قَالَتْ عَائِشَةُمَا رَأَيْتُ الْوَجَعَ عَلَى أَحَدٍ أَشَدَّ مِنْهُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Dawud] telah mengkhabarkan kepada kami [Syu'bah] dari [Al A'masy] berkata: Aku mendengar [Abu Wa`il] berkata: Berkata ' [Aisyah]: Belum pernah kulihat rasa sakit pada seseorang melebihi rasa sakitnya Rasulullah Shallallahu 'alahi wa Salam. Berkata Abu Isa: Hadits ini hasan shahih."},"2314":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَاصِمِ بْنِ بَهْدَلَةَ عَنْ مُصْعَبِ بْنِ سَعْدٍ عَنْ أَبِيهِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَيُّ النَّاسِ أَشَدُّ بَلَاءً قَالَ الْأَنْبِيَاءُ ثُمَّ الْأَمْثَلُ فَالْأَمْثَلُ فَيُبْتَلَى الرَّجُلُ عَلَى حَسَبِ دِينِهِ فَإِنْ كَانَ دِينُهُ صُلْبًا اشْتَدَّ بَلَاؤُهُ وَإِنْ كَانَ فِي دِينِهِ رِقَّةٌ ابْتُلِيَ عَلَى حَسَبِ دِينِهِ فَمَا يَبْرَحُ الْبَلَاءُ بِالْعَبْدِ حَتَّى يَتْرُكَهُ يَمْشِي عَلَى الْأَرْضِ مَا عَلَيْهِ خَطِيئَةٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَأُخْتِ حُذَيْفَةَ بْنِ الْيَمَانِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ أَيُّ النَّاسِ أَشَدُّ بَلَاءً قَالَ الْأَنْبِيَاءُ ثُمَّ الْأَمْثَلُ فَالْأَمْثَلُ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Hammad bin Zaid] dari ['Ashim bin Bahdalah] dari [Mush'ab bin Sa'ad] dari [ayahnya] berkata: Aku berkata: Wahai Rasulullah, siapakah manusia yang paling berat ujiannya? Beliau menjawab: \"Para nabi, kemudian yang sepertinya, kemudian yang sepertinya, sungguh seseorang itu diuji berdasarkan agamanya, bila agamanya kuat, ujiannya pun berat, sebaliknya bila agamanya lemah, ia diuji berdasarkan agamanya, ujian tidak akan berhenti menimpa seorang hamba hingga ia berjalan dimuka bumi dengan tidak mempunyai kesalahan.\" Berkata Abu Isa: Hadits ini hasan shahih. Dalam hal ini ada hadits serupa dari Abu Hurairah dan saudari Hudzaifah bin Al Yaman, nabi Shallallahu 'alaihi wa Salam ditanya tentang siapa orang yang paling berat ujiannya, beliau menjawab: \"Para nabi, kemudian orang-orang serupa kemudian orang-orang serupa.\""},"2315":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا يَزَالُ الْبَلَاءُ بِالْمُؤْمِنِ وَالْمُؤْمِنَةِ فِي نَفْسِهِ وَوَلَدِهِ وَمَالِهِ حَتَّى يَلْقَى اللَّهَ وَمَا عَلَيْهِ خَطِيئَةٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin 'Abdu A'la] telah menceritakan kepada kami [Yazid bin Zurai'] dari [Muhammad bin 'Amru] dari [Abu Salamah] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Ujian senantiasa menimpa orang mu`min pada diri, anak dan hartanya hingga ia bertemu Allah dengan tidak membawa satu kesalahan pun atasnya.\" Berkata Abu Isa: Hadits ini hasan shahih."},"2316":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُعَاوِيَةَ الْجُمَحِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُسْلِمٍ حَدَّثَنَا أَبُو ظِلَالٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ يَقُولُ إِذَا أَخَذْتُ كَرِيمَتَيْ عَبْدِي فِي الدُّنْيَا لَمْ يَكُنْ لَهُ جَزَاءٌ عِنْدِي إِلَّا الْجَنَّةَوَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَزَيْدِ بْنِ أَرْقَمَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَأَبُو ظِلَالٍ اسْمُهُ هِلَالٌ","id":"Telah menceritakan kepada kami [Abdullah bin Mu'awiyah Al Jumahi] telah menceritakan kepada kami [Abdul Aziz bin Muslim] telah menceritakan kepada kami [Abu Dzilal] dari [Anas bin Malik] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \" Allah berfirman: \"Bila Aku ambil kedua biji mata hamba di dunia, tidak ada balasan baginya disisi-Ku selain surga.\" Dalam hal ini ada hadits serupa dari Abu Hurairah, Zaid bin Arqam. Berkata Abu Isa: Hadits ini hasan gharib dari sisi sanad ini dan nama Abu Dzilal adalah Hilal."},"2317":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَرَفَعَهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَقُولُ اللَّهُ عَزَّ وَجَلَّ مَنْ أَذْهَبْتُ حَبِيبَتَيْهِ فَصَبَرَ وَاحْتَسَبَ لَمْ أَرْضَ لَهُ ثَوَابًا دُونَ الْجَنَّةِوَفِي الْبَاب عَنْ عِرْبَاضِ بْنِ سَارِيَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami ['Abdur Razzaq] telah mengkhabarkan kepada kami [Sufyan] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia memarfu'kannya kepada nabi Shallallahu 'alaihi wa Salam, ia berkata: Allah 'azza wajalla berfirman: \"Barangsiapa yang Aku lenyapkan kedua matanya, lantas ia bersabar dan mengharap pahala, aku tidak merelakan pahala baginya selain surga.\" Dalam hal ini ada hadits serupa dari 'Irbadl bin Sariyah. Berkata Abu Isa: Hadits ini hasan shahih."},"2318":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ حُمَيْدٍ الرَّازِيُّ وَيُوسُفُ بْنُ مُوسَى الْقَطَّانُ الْبَغْدَادِيُّ قَالَا حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَغْرَاءَ أَبُو زُهَيْرٍ عَنْ الْأَعْمَشِ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوَدُّ أَهْلُ الْعَافِيَةِ يَوْمَ الْقِيَامَةِ حِينَ يُعْطَى أَهْلُ الْبَلَاءِ الثَّوَابَ لَوْ أَنَّ جُلُودَهُمْ كَانَتْ قُرِضَتْ فِي الدُّنْيَا بِالْمَقَارِيضِوَهَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ بِهَذَا الْإِسْنَادِ إِلَّا مِنْ هَذَا الْوَجْهِ وَقَدْ رَوَى بَعْضُهُمْ هَذَا الْحَدِيثَ عَنْ الْأَعْمَشِ عَنْ طَلْحَةَ بْنِ مُصَرِّفٍ عَنْ مَسْرُوقٍ قَوْلَهُ شَيْئًا مِنْ هَذَا","id":"Telah menceritakan kepada kami [Muhammad bin Humaid Ar Razi] dan [Yusuf bin Musa Al Qattan Al Baghdadi] keduanya berkata: telah menceritakan kepada kami [Abdurrahman bin Maghra' Abu Zuhair] dari [Al A'masy] dari [Abu Az Zubair] dari [Jabir] berkata bahwa Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Pada hari Kiamat ketika orang orang yang di uji diberi pahala, orang orang yang sehat menginginkan seandainya kulit-kulit mereka di dunia dipotong dengan gunting.\" Hadits ini gharib, kami tidak mengetahuinya dengan sanad seperti ini kecuali dari jalur sanad ini, sebagian rawi telah meriwayatkan hadits ini dari Al A'masy dari Thalhah bin Musharrif dari perkataan Masruq yang mirip sedikit dengan hadits ini."},"2319":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ نَصْرٍ أَخْبَرَنَا ابْنُ الْمُبَارَكِ أَخْبَرَنَا يَحْيَى بْنُ عُبَيْدِ اللَّهِ قَال سَمِعْتُ أَبِي يَقُولُ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ أَحَدٍ يَمُوتُ إِلَّا نَدِمَ قَالُوا وَمَا نَدَامَتُهُ يَا رَسُولَ اللَّهِ قَالَ إِنْ كَانَ مُحْسِنًا نَدِمَ أَنْ لَا يَكُونَ ازْدَادَ وَإِنْ كَانَ مُسِيئًا نَدِمَ أَنْ لَا يَكُونَ نَزَعَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ إِنَّمَا نَعْرِفُهُ مِنْ هَذَا الْوَجْهِ وَيَحْيَى بْنُ عُبَيْدِ اللَّهِ قَدْ تَكَلَّمَ فِيهِ شُعْبَةُ وَهُوَ يَحْيَى بْنُ عُبَيْدِ اللَّهِ بْنِ مَوْهَبٍ مَدَنِيٌّ","id":"Telah menceritakan kepada kami [Suwaid bin Nashr] telah menceritakan kepada kami [Ibnu Al Mubarak] telah mengkhabarkan kepada kami [Yahya bin 'Ubaidillah] berkata: Aku mendengar [bapakku] berkata: Aku mendengar [Abu Hurairah] berkata bahwa Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Tidak ada seorangpun yang meninggal dunia kecuali dia merasa menyesal, \" para sahabat bertanya: Apa penyesalannya wahai Rasulullah? beliau menjawab: \"Jika orang baik dia menyesal kenapa tidak menambah (kebaikannya) dan jika orang jahat dia menyesal kenapa tidak melepaskannya (kejahatannya).\" Abu Isa berkata: Hadits ini kami mengetahuinya hanya dari jalur sanad ini, sedangkan Yahya bin 'Ubaidillah telah dibicarakan oleh Syu'bah, dia adalah Yahya bin 'Ubaidillah bin Mauhab orang Madinah."},"2320":{"ar":"حَدَّثَنَا سُوَيْدٌ أَخْبَرَنَا ابْنُ الْمُبَارَكِ أَخْبَرَنَا يَحْيَى بْنُ عُبَيْدِ اللَّهِ قَال سَمِعْتُ أَبِي يَقُولُ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْرُجُ فِي آخِرِ الزَّمَانِ رِجَالٌ يَخْتِلُونَ الدُّنْيَا بِالدِّينِ يَلْبَسُونَ لِلنَّاسِ جُلُودَ الضَّأْنِ مِنْ اللِّينِ أَلْسِنَتُهُمْ أَحْلَى مِنْ السُّكَّرِ وَقُلُوبُهُمْ قُلُوبُ الذِّئَابِ يَقُولُ اللَّهُ عَزَّ وَجَلَّ أَبِي يَغْتَرُّونَ أَمْ عَلَيَّ يَجْتَرِئُونَ فَبِي حَلَفْتُ لَأَبْعَثَنَّ عَلَى أُولَئِكَ مِنْهُمْ فِتْنَةً تَدَعُ الْحَلِيمَ مِنْهُمْ حَيْرَانًاوَفِي الْبَاب عَنْ ابْنِ عُمَرَ","id":"Telah menceritakan kepada kami [Suwaid] telah menceritakan kepada kami [Ibnu Al Mubarak] telah mengkhabarkan kepada kami [Yahya bin 'Ubaidillah] berkata: Aku mendengar [bapakku] berkata: Aku mendengar [Abu Hurairah] berkata bahwa Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Pada akhir zaman nanti akan bermunculan orang-orang yang mencari dunia dengan agama, mereka mengenakan pakaian di antara manusia dengan bulu domba kerena saking halusnya, lisan mereka lebih manis dari gula dan hati mereka adalah seperti hati serigala, Allah 'azza wajalla berfirman: Apakah terhadap-Ku mereka berbuat tipu daya, ataukah kepadaku mereka menantang, maka dengan nama-Ku aku bersumpah, akan Aku kirimkan sebuah fitnah di kalangan mereka yang membuat orang sabar kebingungan.\" Dan Dalam bab ini ada hadits dari Ibnu Umar."},"2321":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ سَعِيدٍ الدَّارِمِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ عَبَّادٍ أَخْبَرَنَا حَاتِمُ بْنُ إِسْمَعِيلَ أَخْبَرَنَا حَمْزَةُ بْنُ أَبِي مُحَمَّدٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ تَعَالَى قَالَ لَقَدْ خَلَقْتُ خَلْقًا أَلْسِنَتُهُمْ أَحْلَى مِنْ الْعَسَلِ وَقُلُوبُهُمْ أَمَرُّ مِنْ الصَّبْرِ فَبِي حَلَفْتُ لَأُتِيحَنَّهُمْ فِتْنَةً تَدَعُ الْحَلِيمَ مِنْهُمْ حَيْرَانًا فَبِي يَغْتَرُّونَ أَمْ عَلَيَّ يَجْتَرِئُونَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ حَدِيثِ ابْنِ عُمَرَ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Ahmad bin Sa'id Ad Darimi] telah menceritakan kepada kami [Muhammad bin 'Abbad] telah menceritakan kepada kami [Hatim bin Isma'il] telah mengkhabarkan kepada kami [Hamzah bin Abu Muhammad] dari [Abdullah bin Dinar] dari [Ibnu Umar] dari Nabi Shallallahu 'alaihi wa Salam beliau bersabda: \"Allah Ta'ala berfirman: telah Aku ciptakan suatu makhluk yang lidah mereka lebih manis daripada madu sedang hati mereka lebih pahit dari pohon shabir, maka dengan nama-Ku Aku bersumpah, pasti akan Ku-turunkan fitnah kepada mereka sehingga membuat orang sabar kebingungan, maka apakah mereka memperdayakan-Ku atau mereka menantang kepada-Ku?\" Abu Isa berkata: Hadits ini hasan gharib dari Hadits Ibnu Umar, kami tidak mengetahuinya kecuali dari jalur sanad ini."},"2322":{"ar":"حَدَّثَنَا صَالِحُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا ابْنُ الْمُبَارَكِ ح و حَدَّثَنَا سُوَيْدٌ أَخْبَرَنَا ابْنُ الْمُبَارَكِ عَنْ يَحْيَى بْنِ أَيُّوبَ عَنْ عُبَيْدِ اللَّهِ بْنِ زَحْرٍ عَنْ عَلِيِّ بْنِ يَزِيدَ عَنْ الْقَاسِمِ عَنْ أَبِي أُمَامَةَ عَنْ عُقْبَةَ بْنِ عَامِرٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ مَا النَّجَاةُ قَالَ أَمْسِكْ عَلَيْكَ لِسَانَكَ وَلْيَسَعْكَ بَيْتُكَ وَابْكِ عَلَى خَطِيئَتِكَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Shalih bin Abdullah] telah menceritakan kepada kami [Ibnu Al Mubarak], dan telah menceritakan kepada kami [Suwaid] telah menceritakan kepada kami [Ibnu Al Mubarak] dari [Yahya bin Ayyub] dari ['Ubaidillah bin Zahr] dari ['Ali bin Yazid] dari [Al Qasim] dari [Abu Umamah] dari ['Uqbah bin 'Amir] berkata, Aku bertanya: Wahai Rasulullah bagaimana supaya selamat? beliau menjawab: \"Jagalah lisanmu, hendaklah rumahmu membuatmu lapang dan menangislah karena dosa dosamu.\" Abu Isa berkata: Hadits ini hasan."},"2323":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُوسَى الْبَصْرِيُّ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَبِي الصَّهْبَاءِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رَفَعَهُ قَالَإِذَا أَصْبَحَ ابْنُ آدَمَ فَإِنَّ الْأَعْضَاءَ كُلَّهَا تُكَفِّرُ اللِّسَانَ فَتَقُولُ اتَّقِ اللَّهَ فِينَا فَإِنَّمَا نَحْنُ بِكَ فَإِنْ اسْتَقَمْتَ اسْتَقَمْنَا وَإِنْ اعْوَجَجْتَ اعْوَجَجْنَاحَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ حَمَّادِ بْنِ زَيْدٍ نَحْوَهُ وَلَمْ يَرْفَعْهُ وَهَذَا أَصَحُّ مِنْ حَدِيثِ مُحَمَّدِ بْنِ مُوسَى قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ حَمَّادِ بْنِ زَيْدٍ وَقَدْ رَوَاهُ غَيْرُ وَاحِدٍ عَنْ حَمَّادِ بْنِ زَيْدٍ وَلَمْ يَرْفَعُوهُ حَدَّثَنَا صَالِحُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَبِي الصَّهْبَاءِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَ أَحْسِبُهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Musa Al Bashri] telah menceritakan kepada kami [Hammad bin Zaid] dari [Abu Ash Shahba`] dari [Sa'id bin Jubair] dari [Abu Sa'id Al Khudri] ia memarfu'kannya, ia berkata: \"Bila manusia berada di waktu pagi, seluruh anggota badan menutupi (kesalahan) lisan lalu berkata: Takutlah pada Allah tentang kami, kami bergantung padamu, bila kau lurus kami lurus dan bila kamu bengkok kami bengkok.\" Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Abu Usamah] dari [Hammad bin Zaid] sepertinya tapi ia tidak memarfu'kannya. Dan ini lebih shahih dari hadits Muhammad bin Musa. Berkata Abu Isa: Hadits ini hanya kami ketahui dari hadits Hammad bin Zaid, banyak perawi meriwayatkannya dari Hammad bin Zaid tapi ia tidak memarfu'kannya. Telah menceritakan kepada kami [Shalih bin Abdullah] telah menceritakan kepada kami [Hammad bin Zaid] dari [Abu Ash Shahba`] dari [Sa'id bin Jubair] dari [Abu Sa'id Al Khudri] berkata: Aku mengiranya dari nabi Shallallahu 'alaihi wa Salam, lalu ia menyebut sepertinya."},"2324":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى الصَّنْعَانِيُّ حَدَّثَنَا عُمَرُ بْنُ عَلِيٍّ الْمُقَدَّمِيُّ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ يَتَكَفَّلْ لِي مَا بَيْنَ لَحْيَيْهِ وَمَا بَيْنَ رِجْلَيْهِ أَتَكَفَّلْ لَهُ بِالْجَنَّةِوَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَابْنِ عَبَّاسٍ ��َالَ أَبُو عِيسَى حَدِيثُ سَهْلٍ حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ حَدِيثِ سَهْلِ بْنِ سَعْدٍ","id":"Telah menceritakan kepada kami [Muhammad bin 'Abdul A'la Ash Shan'ani] telah menceritakan kepada kami [Umar bin 'Ali Al Muqaddami] dari [Abu Hazim] dari [Sahal bin Sa'ad] berkata: \"Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Barangsiapa menjamin apa yang ada diantara dua jambangnya (lisan) dan apa yang diantara kedua kakinya (kemaluan) untukku, aku menjamin surga baginya.\" Dalam hal ini ada hadits serupa dari Abu Hurairah dan Ibnu 'Abbas. Berkata Abu Isa: Hadits Sahal adalah hadits hasan gharib dari hadits Sahal bin Sa'id."},"2325":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ الْأَشَجُّ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ ابْنِ عَجْلَانَ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ وَقَاهُ اللَّهُ شَرَّ مَا بَيْنَ لَحْيَيْهِ وَشَرَّ مَا بَيْنَ رِجْلَيْهِ دَخَلَ الْجَنَّةَقَالَ أَبُو عِيسَى أَبُو حَازِمٍ الَّذِي رَوَى عَنْ أَبِي هُرَيْرَةَ اسْمُهُ سَلْمَانُ مَوْلَى عَزَّةَ الْأَشْجَعِيَّةِ وَهُوَ كُوفِيٌّ وَأَبُو حَازِمٍ الَّذِي رَوَى عَنْ سَهْلِ بْنِ سَعْدٍ هُوَ أَبُو حَازِمٍ الزَّاهِدُ مَدَنِيٌّ وَاسْمُهُ سَلَمَةُ بْنُ دِينَارٍ وَهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Abu Sa'id Al Asyaj] telah menceritakan kepada kami [Abu Khalid Al Ahmar] dari [Ibnu 'Ajlan] dari [Abu Hazim] dari [Abu Hurairah] dia berkata Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Barangsiapa yang dijaga Allah dari kejahatan sesuatu yang ada di antara kedua jambangnya (lisan) dan kejahatan apa yang ada di antara kedua kakinya (kemaluan) maka dia masuk surga.\" Abu Isa berkata: Abu Hazim yang telah meriwayatkan dari Abu Hurairah namanya adalah Salman budak 'Azzah Al Asyja'iyyah dia adalah orang Kufah, sedangkan Abu Hazim yang telah meriwayatkan dari Sahl bin Sa'ad dia adalah Abu Hazim Az Zahid dan dia adalah orang Madinah, namanya Salamah bin Dinar, dan hadits ini hasan gharib."},"2326":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ نَصْرٍ أَخْبَرَنَا ابْنُ الْمُبَارَكِ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ مَاعِزٍ عَنْ سُفْيَانَ بْنِ عَبْدِ اللَّهِ الثَّقَفِيِّ قَالَقُلْتُ يَا رَسُولَ اللَّهِ حَدِّثْنِي بِأَمْرٍ أَعْتَصِمُ بِهِ قَالَ قُلْ رَبِّيَ اللَّهُ ثُمَّ اسْتَقِمْ قُلْتُ يَا رَسُولَ اللَّهِ مَا أَخْوَفُ مَا تَخَافُ عَلَيَّ فَأَخَذَ بِلِسَانِ نَفْسِهِ ثُمَّ قَالَ هَذَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ سُفْيَانَ بْنِ عَبْدِ اللَّهِ الثَّقَفِيِّ","id":"Telah menceritakan kepada kami [Suwaid bin Nashr] telah mengkhabarkan kepada kami [Ibnu Al Mubarak] dari [Ma'mar] dari [Az Zuhri] dari [Abdurrahman bin Ma'iz] dari [Sufyan bin Abdullah Ats Tsaqafi] berkata: Aku berkata: Wahai Rasulullah, ceritakan padaku suatu hal yang aku jadikan pedoman. Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Katakan: Rabbku Allah kemudian beristiqamahlah.\" Aku bertanya: Wahai Rasulullah, apa yang paling anda takutkan padaku? Beliau memegang lidah beliau lalu menjawab: \"Ini.\" Berkata Abu Isa: Hadits ini hasan shahih dan telah diriwayatkan melalui beberapa sanad dari Sufyan bin Abdullah Ats Tsaqafi."},"2327":{"ar":"حَدَّثَنَا أَبُو عَبْدِ اللَّهِ مُحَمَّدُ بْنُ أَبِي ثَلْجٍ الْبَغْدَادِيُّ صَاحِبُ أَحْمَدَ بْنِ حَنْبَلٍ حَدَّثَنَا عَلِيُّ بْنُ حَفْصٍ حَدَّثَنَا إِبْرَاهِيمُ بْنُ عَبْدِ اللَّهِ بْنِ حَاطِبٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُكْثِرُوا الْكَلَامَ بِغَيْرِ ذِكْرِ اللَّهِ فَإِنَّ كَثْرَةَ الْكَلَامِ بِغَيْرِ ذِكْرِ اللَّهِ قَسْوَةٌ لِلْقَلْبِ وَإِنَّ أَبْعَدَ النَّاسِ مِنْ اللَّهِ الْقَلْبُ الْقَاسِيحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي النَّضْرِ حَدَّثَنِي أَبُو النَّضْرِ عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ اللَّهِ بْنِ حَاطِبٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ بِمَعْنَاهُ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ إِبْرَاهِيمَ بْنِ عَبْدِ اللَّهِ بْنِ حَاطِبٍ","id":"Telah menceritakan kepada kami [Abu 'Abdillah Muhammad bin Abu Tsalj Al Baghdadi] sahabat Ahmad bin Hambal, telah menceritakan kepada kami ['Ali bin Hafsh] telah menceritakan kepada kami [Ibrahim bin 'Abdillah bin Hatib] dari [Abdullah bin Dinar] dari [Ibnu Umar] berkata bahwa Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Janganlah kalian banyak bicara tanpa berdzikir kepada Allah, karena banyak bicara tanpa berdzikir kepada Allah membuat hati menjadi keras, dan orang yang paling jauh dari Allah adalah orang yang berhati keras.\" Telah menceritakan kepada kami [Abu Bakar bin Abu An Nadlar] telah menceritakan kepada kami [Abu An Nadlar] dari [Ibrahim bin Abdullah bin Hatib] dari [Abdullah bin Dinar] dari [Ibnu Umar] dari Nabi Shallallahu 'alaihi wa Salam dengan hadits yang semakna. Abu Isa berkata: Hadits ini hasan gharib, kami tidak mengetahuinya kecuali dari hadits Ibrahim bin Abdullah bin Hatib."},"2328":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَغَيْرُ وَاحِدٍ قَالُوا حَدَّثَنَا مُحَمَّدُ بْنُ يَزِيدَ بْنِ خُنَيْسٍ الْمَكِّيُّ قَال سَمِعْتُ سَعِيدَ بْنَ حَسَّانَ الْمَخْزُومِيَّ قَالَ حَدَّثَتْنِي أُمُّ صَالِحٍ عَنْ صَفِيَّةَ بِنْتِ شَيْبَةَ عَنْ أُمِّ حَبِيبَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُلُّ كَلَامِ ابْنِ آدَمَ عَلَيْهِ لَا لَهُ إِلَّا أَمْرٌ بِمَعْرُوفٍ أَوْ نَهْيٌ عَنْ مُنْكَرٍ أَوْ ذِكْرُ اللَّهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ مُحَمَّدِ بْنِ يَزِيدَ بْنِ خُنَيْسٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] dan yang lainnya mereka berkata: telah menceritakan kepada kami [Muhammad bin Yazid bin Khunais Al Makki] dia berkata: Aku mendengar [Sa'id bin Hassan Al Makhzumi] berkata: telah menceritakan kepadaku [Ummu Shalih] dari [Shafiyyah binti Syaibah] dari [Ummu Habibah] istri Nabi Shallallahu 'alaihi wa Salam dari Nabi Shallallahu 'alaihi wa Salam beliau bersabda: \"Setiap perkataan anak cucu Adam itu membahayakannya, tidak berguna baginya kecuali amar ma'ruf, nahi munkar, atau berdzikir kepada Allah.\" Abu Isa berkata: Hadits ini hasan gharib, kami tidak mengetahuinya kecuali dari hadits Muhammad bin Yazid bin Khunais."},"2329":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا جَعْفَرُ بْنُ عَوْنٍ حَدَّثَنَا أَبُو الْعُمَيْسِ عَنْ عَوْنِ بْنِ أَبِي جُحَيْفَةَ عَنْ أَبِيهِ قَالَآخَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ سَلْمَانَ وَبَيْنَ أَبِي الدَّرْدَاءِ فَزَارَ سَلْمَانُ أَبَا الدَّرْدَاءِ فَرَأَى أُمَّ الدَّرْدَاءِ مُتَبَذِّلَةً فَقَالَ مَا شَأْنُكِ مُتَبَذِّلَةً قَالَتْ إِنَّ أَخَاكَ أَبَا الدَّرْدَاءِ لَيْسَ لَهُ حَاجَةٌ فِي الدُّنْيَا قَالَ فَلَمَّا جَاءَ أَبُو الدَّرْدَاءِ قَرَّبَ إِلَيْهِ طَعَامًا فَقَالَ كُلْ فَإِنِّي صَائِمٌ قَالَ مَا أَنَا بِآكِلٍ حَتَّى تَأْكُلَ قَالَ فَأَكَلَ فَلَمَّا كَانَ اللَّيْلُ ذَهَبَ أَبُو الدَّرْدَاءِ لِيَقُومَ فَقَالَ لَهُ سَلْمَانُ نَمْ فَنَامَ ثُمَّ ذَهَبَ يَقُومُ فَقَالَ لَهُ نَمْ فَنَامَ فَلَمَّا كَانَ عِنْدَ الصُّبْحِ قَالَ لَهُ سَلْمَانُ قُمْ الْآنَ فَقَامَا فَصَلَّيَا فَقَالَ إِنَّ لِنَفْسِكَ عَلَيْكَ حَقًّا وَلِرَبِّكَ عَلَيْكَ حَقًّا وَلِضَيْفِكَ عَلَيْكَ حَقًّا وَإِنَّ لِأَهْلِكَ عَلَيْكَ حَقًّا فَأَعْطِ كُلَّ ذِي حَقٍّ حَقَّهُ فَأَتَيَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَا ذَلِكَ فَقَالَ لَهُ صَدَقَ سَلْمَانُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ صَحِيحٌ وَأَبُو الْعُمَيْسِ اسْمُهُ عُتْبَةُ بْنُ عَبْدِ اللَّهِ وَهُوَ أَخُو عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ الْمَسْعُودِيِّ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Ja'far bin 'Aun] telah menceritakan kepada kami [Abul 'Umais] dari ['Aun bin Abu Juhaifah] dari [bapaknya] berkata: Rasulullah Shallallahu 'alaihi wa Salam mempersaudarakan antara Salman dengan Abu Darda`, kemudian Salman mengunjungi Abu Darda` dan melihat Ummu Darda` berpenampilan kusam, lalu Salman bertanya kepadanya: Kenapa kamu berpenampilan kusam? dia menjawab: Sesungguhnya saudaramu (yaitu Abu Darda`) tidak memerlukan dunia. Abu Juhaifah berkata: Ketika Abu Darda` tiba, didekatkanlah makanan kepada Salman lalu dia (Abu Darda`) berkata: Makanlah karena aku sedang berpuasa, Salman menjawab: Saya tidak akan makan sampai kamu ikut makan. Abu Juhaifah berkata: Abu Darda` akhirnya makan, kemudian ketika tiba waktu malam Abu Darda` pergi untuk melaksanakan shalat namun Salman berkata kepadanya: Tidurlah. Dia pun tidur, kemudian dia pergi untuk sholat malam dan Salman berkata kepadanya: Tidurlah, akhirnya dia tidur, dan ketika menjelang shubuh Salman berkata kepadanya: Sekarang bangunlah, akhirnya keduanya bangun dan melaksanakan sholat, Salman berkata: Sesungguhnya dirimu mempunyai hak atasmu, Rabbmu juga mempunyai hak atasmu, tamumu juga mempunyai hak atasmu dan keluargamu juga mempunyai hak atasmu."},"2330":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ نَصْرٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ عَبْدِ الْوَهَّابِ بْنِ الْوَرْدِ عَنْ رَجُلٍ مِنْ أَهْلِ الْمَدِينَةِ قَالَكَتَبَ مُعَاوِيَةُ إِلَى عَائِشَةَ أُمِّ الْمُؤْمِنِينَ رَضِيَ اللَّهُ عَنْهَا أَنْ اكْتُبِي إِلَيَّ كِتَابًا تُوصِينِي فِيهِ وَلَا تُكْثِرِي عَلَيَّ فَكَتَبَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَا إِلَى مُعَاوِيَةَ سَلَامٌ عَلَيْكَ أَمَّا بَعْدُ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ الْتَمَسَ رِضَا اللَّهِ بِسَخَطِ النَّاسِ كَفَاهُ اللَّهُ مُؤْنَةَ النَّاسِ وَمَنْ الْتَمَسَ رِضَا النَّاسِ بِسَخَطِ اللَّهِ وَكَلَهُ اللَّهُ إِلَى النَّاسِ وَالسَّلَامُ عَلَيْكَحَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ الثَّوْرِيِّ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ أَنَّهَا كَتَبَتْ إِلَى مُعَاوِيَةَ فَذَكَرَ الْحَدِيثَ بِمَعْنَاهُ وَلَمْ يَرْفَعْهُ","id":"Telah menceritakan kepada kami [Suwaid bin Nashr] telah menceritakan kepada kami [Abdullah bin Al Mubarak] dari ['Abdul Wahhab bin Al Ward] dari [seorang penduduk Madinah], dia berkata: Mu'awiyah menulis surat kepada Aisyah Ummul Mu`minin radliallahu 'anha supaya dia menulis surat yang berisi wasiat kepadanya dan isinya tidak panjang panjang, [Aisyah] menulis surat kepada Mu'awiyah: SALAAMUN 'ALAIKA, aku mendengar Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Barangsiapa yang mencari keridlaan Allah sekalipun memperoleh kebencian manusia, Allah akan mencukupkan dia dari ketergantungan kepada manusia dan barangsiapa yang mencari keridlaan manusia dengan mendatangkan kemurkaan dari Allah, maka Allah akan menjadikannya bergantung kepada manusia, WASSALAMU 'ALAIKA. Telah menceritakan kepada kami [Muhammad bin Yahya] telah menceritakan kepada kami [Muhammad bin Yusuf] dari [Sufyan Ats Tsauri] dari [Hisyam bin 'Urwah] dari [bapaknya] dari ['Aisyah], dia menulis surat kepada Mu'awiyah, kemudian dia menyebutkan hadits yang semakna namun tidak memarfu'kannya (tidak menyambungkan sampai Nabi)."},"2331":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ خَيْثَمَةَ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْكُمْ مِنْ رَجُلٍ إِلَّا سَيُكَلِّمُهُ رَبُّهُ يَوْمَ الْقِيَامَةِ وَلَيْسَ بَيْنَهُ وَبَيْنَهُ تُرْجُمَانٌ فَيَنْظُرُ أَيْمَنَ مِنْهُ فَلَا يَرَى شَيْئًا إِلَّا شَيْئًا قَدَّمَهُ ثُمَّ يَنْظُرُ أَشْأَمَ مِنْهُ فَلَا يَرَى شَيْئًا إِلَّا شَيْئًا قَدَّمَهُ ثُمَّ يَنْظُرُ تِلْقَاءَ وَجْهِهِ فَتَسْتَقْبِلُهُ النَّارُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ اسْتَطَاعَ مِنْكُمْ أَنْ يَقِيَ وَجْهَهُ حَرَّ النَّارِ وَلَوْ بِشِقِّ تَمْرَةٍ فَلْيَفْعَل��قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ حَدَّثَنَا أَبُو السَّائِبِ حَدَّثَنَا وَكِيعٌ يَوْمًا بِهَذَا الْحَدِيثِ عَنْ الْأَعْمَشِ فَلَمَّا فَرَغَ وَكِيعٌ مِنْ هَذَا الْحَدِيثِ قَالَ مَنْ كَانَ هَا هُنَا مِنْ أَهْلِ خُرَاسَانَ فَلْيَحْتَسِبْ فِي إِظْهَارِ هَذَا الْحَدِيثِ بِخُرَاسَانَ لِأَنَّ الْجَهْمِيَّةَ يُنْكِرُونَ هَذَا اسْمُ أَبِي السَّائِبِ سَلْمُ بْنُ جُنَادَةَ بْنِ سَلْمِ بْنِ خَالِدِ بْنِ جَابِرِ بْنِ سَمُرَةَ الْكُوفِيُّ","id":"Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Khaitsamah] dari ['Adi bin Hatim] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Tidaklah ada seorang dari kalian melainkan akan diajak bicara Rabbnya pada hari kiamat yang tidak ada penerjemah antara keduanya, ia melihat ke sisi paling membawa berkahnya, ia tidak melihat apa pun kecuali sesuatu yang telah diperbuat, lalu ia melihat ke sisi kirinya, ia tidak melihat apa pun selain sesuatu yang telah diperbuat lalu ia melihat ke arah depannya, lalu neraka menyambutnya.\" Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Barangsiapa di antara kalian bisa menjaga wajahnya dari panasnya neraka meski dengan sebelah kurma hendaklah ia lakukan.\" Berkata Abu Isa: Hadits ini hasan shahih. Telah menceritakan kepada kami [Abu As Sa`ib] telah menceritakan kepada kami [Waki'] pada suatu hari hadits ini dari [Al A'masy], setelah usai menyebut hadits ini Waki' berkata: Siapa pun penduduk Khurasan yang ada di sini, hendaklah mengharap pahala dengan menyebarkan hadits ini di Khurasan karena jahmiyah mengingkari hadits ini. nama Abu As Sa`ib adalah Salm bin Junadah bin Salm bin Khalid bin Jabir bin Samurah Al Kufi."},"2332":{"ar":"حَدَّثَنَا حُمَيْدُ بْنُ مَسْعَدَةَ حَدَّثَنَا حُصَيْنُ بْنُ نُمَيْرٍ أَبُو مِحْصَنٍ حَدَّثَنَا حُسَيْنُ بْنُ قَيْسٍ الرَّحَبِيُّ حَدَّثَنَا عَطَاءُ بْنُ أَبِي رَبَاحٍ عَنْ ابْنِ عُمَرَ عَنْ ابْنِ مَسْعُودٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَزُولُ قَدَمُ ابْنِ آدَمَ يَوْمَ الْقِيَامَةِ مِنْ عِنْدِ رَبِّهِ حَتَّى يُسْأَلَ عَنْ خَمْسٍ عَنْ عُمُرِهِ فِيمَ أَفْنَاهُ وَعَنْ شَبَابِهِ فِيمَ أَبْلَاهُ وَمَالِهِ مِنْ أَيْنَ اكْتَسَبَهُ وَفِيمَ أَنْفَقَهُ وَمَاذَا عَمِلَ فِيمَا عَلِمَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ مِنْ حَدِيثِ ابْنِ مَسْعُودٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا مِنْ حَدِيثِ الْحُسَيْنِ بْنِ قَيْسٍ وَحُسَيْنُ بْنُ قَيْسٍ يُضَعَّفُ فِي الْحَدِيثِ مِنْ قِبَلِ حِفْظِهِ وَفِي الْبَاب عَنْ أَبِي بَرْزَةَ وَأَبِي سَعِيدٍ","id":"Telah menceritakan kepada kami [Humaid bin Mas'adah] telah menceritakan kepada kami [Hushain bin Numair Abu Mihshan] telah menceritakan kepada kami [Husain bin Qais Ar Rahabi] telah menceritakan kepada kami ['Atho` bin Abu Rabah] dari [Ibnu Umar] dari [Ibnu Mas'ud] dari Nabi Shallallahu 'alaihi wa Salam beliau bersabda: \"Kaki Anak Adam tidaklah bergeser pada hari Kiamat dari sisi Rabbnya sehingga ditanya tentang lima hal; tentang umurnya untuk apa dia habiskan, tentang masa mudanya untuk apa dia pergunakan, tentang hartanya dari mana dia peroleh dan kemana dia infakkan dan tentang apa yang telah dia lakukan dengan ilmunya.\" Abu Isa berkata: Hadits ini gharib, kami tidak mengetahuinya dari hadits Ibnu Mas'ud dari Nabi Shallallahu 'alaihi wa Salam kecuali dari Hadits Al Husain bin Qais, sementara Husain bin Qais dilemahkan dalam masalah hadits karena sisi hafalannya, dan dalam bab ini ada hadits dari Abu Barzah dan Abu Sa'id."},"2333":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ أَخْبَرَنَا الْأَسْوَدُ بْنُ عَامِرٍ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ الْأَعْمَشِ عَنْ سَعِيدِ بْنِ عَبْدِ اللَّهِ بْنِ جُرَيْجٍ عَنْ أَبِي بَرْزَةَ الْأَسْلَمِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَزُولُ قَدَمَا عَبْدٍ يَوْمَ الْقِيَامَةِ حَتَّى يُسْأَلَ عَنْ عُمُرِهِ فِيمَا أَفْنَاهُ وَعَنْ عِلْمِهِ فِيمَ فَعَلَ وَعَنْ مَالِهِ مِنْ أَيْنَ اكْتَسَبَهُ وَفِيمَ أَنْفَقَهُ وَعَنْ جِسْمِهِ فِيمَ أَبْلَاهُقَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَسَعِيدُ بْنُ عَبْدِ اللَّهِ بْنِ جُرَيْجٍ هُوَ بَصْرِيٌّ وَهُوَ مَوْلَى أَبِي بَرْزَةَ وَأَبُو بَرْزَةَ اسْمُهُ نَضْلَةُ بْنُ عُبَيْدٍ","id":"Telah menceritakan kepada kami [Abdullah bin Abdurrahman] telah menceritakan kepada kami [Al Aswad bin 'Amir] telah mengkhabarkan kepada kami [Abu Bakar bin Ayyasy] dari [Al A'masy] dari [Sa'id bin Abdullah bin Juraij] dari [Abu Barzah Al Aslami] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Kedua telapak kaki seorang hamba tidak akan bergeser pada hari kiamat sampai ditanya tentang umurnya untuk apa dia habiskan, tentang ilmunya untuk apa dia amalkan, tentang hartanya dari mana dia peroleh dan kemana dia infakkan dan tentang tubuhnya untuk apa dia gunakan.\" Dia berkata: Hadits ini hasan shahih, adapun Sa'id bin Abdullah bin Juraij dia adalah orang Bashrah dan dia adalah budak Abu Barzah, sedangkan Abu Barzah namanya adalah Nadlah bin 'Ubaid."},"2334":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَتَدْرُونَ مَا الْمُفْلِسُ قَالُوا الْمُفْلِسُ فِينَا يَا رَسُولَ اللَّهِ مَنْ لَا دِرْهَمَ لَهُ وَلَا مَتَاعَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُفْلِسُ مِنْ أُمَّتِي مَنْ يَأْتِي يَوْمَ الْقِيَامَةِ بِصَلَاتِهِ وَصِيَامِهِ وَزَكَاتِهِ وَيَأْتِي قَدْ شَتَمَ هَذَا وَقَذَفَ هَذَا وَأَكَلَ مَالَ هَذَا وَسَفَكَ دَمَ هَذَا وَضَرَبَ هَذَا فَيَقْعُدُ فَيَقْتَصُّ هَذَا مِنْ حَسَنَاتِهِ وَهَذَا مِنْ حَسَنَاتِهِ فَإِنْ فَنِيَتْ حَسَنَاتُهُ قَبْلَ أَنْ يُقْتَصَّ مَا عَلَيْهِ مِنْ الْخَطَايَا أُخِذَ مِنْ خَطَايَاهُمْ فَطُرِحَ عَلَيْهِ ثُمَّ طُرِحَ فِي النَّارِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Al 'Alla` bin Abdurrahman] dari [ayahnya] dari [Abu Hurairah] Rasulullah Shallallahu 'alaihi wa salam bertanya: \"Tahukah kalian siapa orang yang rugi itu?\" mereka menjawab: Orang rugi di antara kami wahai Rasulullah adalah orang yang tidak memiliki dirham dan barang. Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Orang rugi dari ummatku adalah orang yang membawa shalat, puasa dan zakat pada hari kiamat, ia datang sementara ia dulu pernah mencela si anu, menuduh berzina si anu, memakan harta si anu, menumpahkan darah si anu dan memukul si anu. Ia duduk lalu kebaikan-kebaikan si ini diqisas dari kebaikan-kebaikannya, bila kebaikan-kebaikannya habis sebelum sepadan dengan kesalahan-kesalahannya, kesalahan-kesalahan mereka diambil lalu dibuang kepadanya, setelah itu dia dilempar ke neraka.\" Berkata Abu Isa: Hadits ini hasan shahih."},"2335":{"ar":"حَدَّثَنَا هَنَّادٌ وَنَصْرُ بْنُ عَبْدِ الرَّحْمَنِ الْكُوفِيُّ قَالَا حَدَّثَنَا الْمُحَارِبِيُّ عَنْ أَبِي خَالِدٍ يَزِيدَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ زَيْدِ بْنِ أَبِي أُنَيْسَةَ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَحِمَ اللَّهُ عَبْدًا كَانَتْ لِأَخِيهِ عِنْدَهُ مَظْلَمَةٌ فِي عِرْضٍ أَوْ مَالٍ فَجَاءَهُ فَاسْتَحَلَّهُ قَبْلَ أَنْ يُؤْخَذَ وَلَيْسَ ثَمَّ دِينَارٌ وَلَا دِرْهَمٌ فَإِنْ كَانَتْ لَهُ حَسَنَاتٌ أُخِذَ مِنْ حَسَنَاتِهِ وَإِنْ لَمْ تَكُنْ لَهُ حَسَنَاتٌ حَمَّلُوا عَلَيْهِ مِنْ سَيِّئَاتِهِمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ حَدِيثِ سَعِيدٍ الْمَقْبُرِيِّ وَقَدْ رَوَاهُ مَالِكُ بْنُ أَنَسٍ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Hannad] dan [Nashr bin Abdurrahman Al Kufi] keduanya berkata: telah menceritakan kepada kami [Al Muharibi] dari [Abu Khalid Yazid bin Abdurrahman] dari [Zaid bin Abu 'Unaisah] dari [Sa'id Al Maqburi] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Allah memberikan rahmat kepada seorang hamba yang dizhalimi harga diri dan hartanya oleh saudaranya, kemudian dia (yang zhalim) mendatanginya dan dia (yang dizhalimi) merelakannya sebelum meninggal, tidak ada balasan uang dinar maupun dirham (di akhirat), jika dia (orang yang dizhalimi) memiliki kebaikan niscaya akan dipenuhi kebaikannya namun jika tidak mempunyai kebaikan maka (dosa dosa yang zhalimi) akan di berikan kepadanya (orang yang menzhalimi).\" Abu Isa berkata: Hadits ini hasan shahih gharib dari hadits Sa'id Al Maqburi, [Malik bin Anas] telah meriwayatkannya dari [Sa'id Al Maqburi] dari [Abu Hurairah] dari Nabi Shallallahu 'alaihi wa Salam dengan hadits yang semakna."},"2336":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَتُؤَدُّنَّ الْحُقُوقَ إِلَى أَهْلِهَا حَتَّى يُقَادَ لِلشَّاةِ الْجَلْحَاءِ مِنْ الشَّاةِ الْقَرْنَاءِوَفِي الْبَاب عَنْ أَبِي ذَرٍّ وَعَبْدِ اللَّهِ بْنِ أُنَيْسٍ قَالَ أَبُو عِيسَى وَحَدِيثُ أَبِي هُرَيْرَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Al 'Alla` bin Abdurrahman] dari [ayahnya] dari [Abu Hurairah] Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Hak-hak akan ditunaikan kepada pemiliknya hingga kambing bertanduk di qisas karena kambing botak.\" Dalam hal ini ada hadits serupa dari Abu Hurairah, Abu Dzarr, Abdullah bin Unais. Berkata Abu Isa: Hadits Abu Hurairah hasan shahih."},"2337":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ نَصْرٍ أَخْبَرَنَا ابْنُ الْمُبَارَكِ أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ يَزِيدَ بْنِ جَابِرٍ حَدَّثَنِي سُلَيْمُ بْنُ عَامِرٍ حَدَّثَنَا الْمِقْدَادُ صَاحِبُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا كَانَ يَوْمُ الْقِيَامَةِ أُدْنِيَتْ الشَّمْسُ مِنْ الْعِبَادِ حَتَّى تَكُونَ قِيدَ مِيلٍ أَوْ اثْنَيْنِ قَالَ سُلَيْمٌ لَا أَدْرِي أَيَّ الْمِيلَيْنِ عَنَى أَمَسَافَةُ الْأَرْضِ أَمْ الْمِيلُ الَّذِي تُكْتَحَلُ بِهِ الْعَيْنُ قَالَ فَتَصْهَرُهُمْ الشَّمْسُ فَيَكُونُونَ فِي الْعَرَقِ بِقَدْرِ أَعْمَالِهِمْ فَمِنْهُمْ مَنْ يَأْخُذُهُ إِلَى عَقِبَيْهِ وَمِنْهُمْ مَنْ يَأْخُذُهُ إِلَى رُكْبَتَيْهِ وَمِنْهُمْ مَنْ يَأْخُذُهُ إِلَى حِقْوَيْهِ وَمِنْهُمْ مَنْ يُلْجِمُهُ إِلْجَامًا فَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُشِيرُ بِيَدِهِ إِلَى فِيهِ أَيْ يُلْجِمُهُ إِلْجَامًاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَفِي الْبَاب عَنْ أَبِي سَعِيدٍ وَابْنِ عُمَرَ","id":"Telah menceritakan kepada kami [Suwaid bin Nashr] telah mengkhabarkan kepada kami [Ibnu Al Mubarak] telah mengkhabarkan kepada kami [Abdurrahman bin Yazid bin Jabir] telah menceritakan kepadaku [Sulaim bin 'Amir] telah menceritakan kepada kami [Al Miqdad] sahabat Rasulullah Shallallahu 'alahi wa Salam, berkata: Aku mendengar Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Pada hari kiamat, matahari di dekatkan ke manusia hingga sebatas satu atau dua mil -berkata Sulam: Aku tidak tahu apakah maksud dua mil itu jarak bumi ataukah mil yang dipakai bercalak mata- lalu matahari melehkan mereka, lalu mereka berada dalam keringat sesuai amal perbuatan mereka, di antara mereka ada yang berkeringat hingga tumitnya, ada yang berkeringat hingga lututnya, ada yang berkeringat hingga pinggang dan ada yang benar-benar tenggelam oleh keringat.\" Aku melihat Rasulullah Shallallahu 'alahi wa Salam menunjukkan tangan ke mulut, maksudnya benar-benar tenggelam. Berkata Abu Isa: Hadits ini hasan shahih dan dalam hal ini ada hadits serupa dari Abu Sa'id dan Ibnu Umar."},"2338":{"ar":"حَدَّثَنَا أَبُو زَكَرِيَّا يَحْيَى بْنُ دُرُسْتَ الْبَصْرِيُّ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَ حَمَّادٌ وَهُوَ عِنْدَنَا مَرْفُوعٌ{ يَوْمَ يَقُومُ النَّاسُ لِرَبِّ الْعَالَمِينَ }قَالَ يَقُومُونَ فِي الرَّشْحِ إِلَى أَنْصَافِ آذَانِهِمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ حَدَّثَنَا هَنَّادٌ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ ابْنِ عَوْنٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Abu Zakariya Yahya bin Durusta Al Bashri] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar], berkata Hammad: Itu menurut kami marfu': Pada hari manusia berdiri untuk Rabb semesta alam. Ia berkata: Mereka berdiri dalam keringat hingga mencapai pertengahan telinga mereka. Berkata Abu Isa: Hadits ini hasan shahih. Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami ['Isa bin Yunus] dari [Ibnu 'Aun] dari [Nafi'] dari [Ibnu Umar] dari nabi Shallallahu 'alaihi wa Salam sepertinya."},"2339":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو أَحْمَدَ الزُّبَيْرِيُّ حَدَّثَنَا سُفْيَانُ عَنْ الْمُغِيرَةِ بْنِ النُّعْمَانِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحْشَرُ النَّاسُ يَوْمَ الْقِيَامَةِ حُفَاةً عُرَاةً غُرْلًا كَمَا خُلِقُوا ثُمَّ قَرَأَ{ كَمَا بَدَأْنَا أَوَّلَ خَلْقٍ نُعِيدُهُ وَعْدًا عَلَيْنَا إِنَّا كُنَّا فَاعِلِينَ }وَأَوَّلُ مَنْ يُكْسَى مِنْ الْخَلَائِقِ إِبْرَاهِيمُ وَيُؤْخَذُ مِنْ أَصْحَابِي بِرِجَالٍ ذَاتَ الْيَمِينِ وَذَاتَ الشِّمَالِ فَأَقُولُ يَا رَبِّ أَصْحَابِي فَيُقَالُ إِنَّكَ لَا تَدْرِي مَا أَحْدَثُوا بَعْدَكَ إِنَّهُمْ لَمْ يَزَالُوا مُرْتَدِّينَ عَلَى أَعْقَابِهِمْ مُنْذُ فَارَقْتَهُمْ فَأَقُولُ كَمَا قَالَ الْعَبْدُ الصَّالِحُ{ إِنْ تُعَذِّبْهُمْ فَإِنَّهُمْ عِبَادُكَ وَإِنْ تَغْفِرْ لَهُمْ فَإِنَّكَ أَنْتَ الْعَزِيزُ الْحَكِيمُ }حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَمُحَمَّدُ بْنُ الْمُثَنَّى قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ شُعْبَةَ عَنْ الْمُغِيرَةِ بْنِ النُّعْمَانِ بِهَذَا الْإِسْنَادِ فَذَكَرَ نَحْوَهُ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Ahmad Az Zubairi] telah menceritakan kepada kami [Sufyan] dari [Al Mughirah bin An Nu'man] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Manusia dikumpulkan pada hari kiamat dalam kondisi tanpa alas kaki, telanjang dan belum disunat.\" Kemudian beliau membaca: \"Sebagaimana kami telah memulai panciptaan pertama begitulah Kami akan mengulanginya. Itulah suatu janji yang pasti kami tepati.\" (Al-Anbiyaa`: 104) dan makhluk pertama yang diberi pakaian adalah Ibrahim dan di antara para sahabat-sahabat kami ada yang diambil dari kiki dan kanan, aku berkata: Wahai Rabb, sahabat-sahabatku. Dikatakan: Sesungguhnya engkau tidak tahu apa yang mereka buat-buat setelahmu, mereka tetap murtad sejak kau tinggalkan mereka. Lalu aku berkata seperti yang diucapkan hamba shalih: \"Jika Engkau menyiksa mereka, maka sesungguhnya mereka adalah hamba-hamba Engkau, dan jika Engkau mengampuni mereka, maka sesungguhnya Engkaulah yang Maha Perkasa lagi Maha Bijaksana.\" (Al-Maa`idah: 118) Telah menceritakan kepada kami [Muhammad bin Basyar] dan [Muhammad bin Al Mutsanna] keduanya berkata: telah menceritakan kepada kami [Muhammad bin Ja'far] dari [Syu'bah] dari [Al Mughirah bin An Nu'man] dengan sanad ini lalu ia menyebut sepertinya. Berkata Abu Isa: Hadits ini hasan shahih."},"2340":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا بَهْزُ بْنُ حَكِيمٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّكُمْ مَحْشُورُونَ رِجَالًا وَرُكْبَانًا وَتُجَرُّونَ عَلَى وُجُوهِكُمْوَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Yazid bin Harun] telah mengkhabarkan kepada kami [Bahz bin Hakim] dari [ayahnya] dari [kakeknya] berkata: Aku mendengar Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Sesungguhnya kalian akan dikumpulkan dengan berjalan kaki, berkendaraan dan diseret di atas muka-muka kalian.\" Dalam hal ini ada hadits serupa dari Abu Hurairah. Berkata Abu Isa: Hadits ini hasan shahih."},"2341":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا وَكِيعٌ عَنْ عَلِيِّ بْنِ عَلِيٍّ عَنْ الْحَسَنِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعْرَضُ النَّاسُ يَوْمَ الْقِيَامَةِ ثَلَاثَ عَرْضَاتٍ فَأَمَّا عَرْضَتَانِ فَجِدَالٌ وَمَعَاذِيرُ وَأَمَّا الْعَرْضَةُ الثَّالِثَةُ فَعِنْدَ ذَلِكَ تَطِيرُ الصُّحُفُ فِي الْأَيْدِي فَآخِذٌ بِيَمِينِهِ وَآخِذٌ بِشِمَالِهِقَالَ أَبُو عِيسَى وَلَا يَصِحُّ هَذَا الْحَدِيثُ مِنْ قِبَلِ أَنَّ الْحَسَنَ لَمْ يَسْمَعْ مِنْ أَبِي هُرَيْرَةَ وَقَدْ رَوَاهُ بَعْضُهُمْ عَنْ عَلِيٍّ الرِّفَاعِيِّ عَنْ الْحَسَنِ عَنْ أَبِي مُوسَى عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو عِيسَى وَلَا يَصِحُّ هَذَا الْحَدِيثُ مِنْ قِبَلِ أَنَّ الْحَسَنَ لَمْ يَسْمَعْ مِنْ أَبِي مُوسَى","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Waki'] dari ['Ali bin 'Ali] dari [Al Hasan] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Pada hari kiamat manusia diajukan sebanyak tiga kali, dua kali pengajuan untuk bantahan dan alasan-alasan dan pada pengajuan ketiga, saat itu lembaran-lembaran berterbangan ditangan, ada yang mengambil dengan tangan kanannya dan ada yang mengambil dengan tangan kirinya.\" Berkata Abu Isa: Hadits ini tidak shahih karena Al Hasan tidak mendengar dari Abu Hurairah dan sebagaian dari mereka meriwayatkannya dari ['Ali Ar Rifa'i] dari [Al Hasan] dari [Abu Musa] dari nabi Shallallahu 'alaihi wa Salam. Berkata Abu Isa: Hadits ini tidak shahih karena Al Hasan tidak mendengar dari Abu Musa."},"2342":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ نَصْرٍ أَخْبَرَنَا ابْنُ الْمُبَارَكِ عَنْ عُثْمَانَ بْنِ الْأَسْوَدِ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ عَائِشَةَ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ نُوقِشَ الْحِسَابَ هَلَكَ قُلْتُ يَا رَسُولَ اللَّهِ إِنَّ اللَّهَ تَعَالَى يَقُولُ{ فَأَمَّا مَنْ أُوتِيَ كِتَابَهُ بِيَمِينِهِ فَسَوْفَ يُحَاسَبُ حِسَابًا يَسِيرًا }قَالَ ذَلِكَ الْعَرْضُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ صَحِيحٌ حَسَنٌ وَرَوَاهُ أَيُّوبُ أَيْضًا عَنْ ابْنِ أَبِي مُلَيْكَةَ","id":"Telah menceritakan kepada kami [Suwaid bin Nashr] telah mengkhabarkan kepada kami [Ibnu Al Mubarak] dari ['Utsman bin Al Aswad] dari [Ibnu Abi Malikah] dari ['Aisyah] berkata: Aku mendengar Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Barangsiapa didebat saat penghisaban, ia celaka.\" Aku berkata: Wahai Rasulullah, Allah Ta'ala berfirman: \"Adapun orang yang diberikan kitabnya dari sebelah kanannya, maka dia akan diperiksa dengan pemeriksaan yang mudah.\" (Al-Insyiqaaq: 7-8) Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Itu pengajuan.\" Berkata Abu Isa: Hadits ini shahih hasan, dan [Ayyub] juga meriwayatkannya dari [Ibnu Abi Malikah]."},"2343":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ نَصْرٍ أَخْبَرَنَا ابْنُ الْمُبَارَكِ أَخْبَرَنَا إِسْمَعِيلُ بْنُ مُسْلِمٍ عَنْ الْحَسَنِ وَقَتَادَةَ عَنْ أَنَسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُجَاءُ بِابْنِ آدَمَ يَوْمَ الْقِيَامَةِ كَأَنَّهُ بَذَجٌ فَيُوقَفُ بَيْنَ يَدَيْ اللَّهِ فَيَقُولُ اللَّهُ لَهُ أَعْطَيْتُكَ وَخَوَّلْتُكَ وَأَنْعَمْتُ عَلَيْكَ فَمَاذَا صَنَعْتَ فَيَقُولُ يَا رَبِّ جَمَعْتُهُ وَثَمَّرْتُهُ فَتَرَكْتُهُ أَكْثَرَ مَا كَانَ فَارْجِعْنِي آتِكَ بِهِ فَيَقُولُ لَهُ أَرِنِي مَا قَدَّمْتَ فَيَقُولُ يَا رَبِّ جَمَعْتُهُ وَثَمَّرْتُهُ فَتَرَكْتُهُ أَكْثَرَ مَا كَانَ فَارْجِعْنِي آتِكَ بِهِ كُلِّهِ فَإِذَا عَبْدٌ لَمْ يُقَدِّمْ خَيْرًا فَيُمْضَى بِهِ إِلَى النَّارِقَالَ أَبُو عِيسَى وَقَدَ رَوَى هَذَا الْحَدِيثَ غَيْرُ وَاحِدٍ عَنْ الْحَسَنِ قَوْلَهُ وَلَمْ يُسْنِدُوهُ وَإِسْمَعِيلُ بْنُ مُسْلِمٍ يُضَعَّفُ فِي الْحَدِيثِ مِنْ قِبَلِ حِفْظِهِ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَأَبِي سَعِيدٍ الْخُدْرِيِّ","id":"Telah menceritakan kepada kami [Suwaid bin Nashr] telah menceritakan kepada kami [Ibnu Al Mubarak] telah mengkhabarkan kepada kami [Isma'il bin Muslim] dari [Al Hasan] dan [Qotadah] dari [Anas] dari Nabi Shallallahu 'alaihi wa Salam beliau bersabda: \"Pada hari Kiamat anak Adam akan didatangkan seperti anak domba kemudian terhenti di hadapan Allah lalu Allah bertanya kepadanya: Aku telah memberimu, menganugerahkan kepadamu dan memberimu nikmat, lalu apa yang telah kamu lakukan? dia menjawab: Wahai Rabbku, aku telah mengumpulkannya dan mengembangkannya lalu aku tinggalkan menjadi semakin banyak, maka kembalikanlah aku supaya aku bisa membawanya semuanya kepadamu, ternyata hamba ini tidak membawa kebaikan kemudian Allah menyeretnya ke neraka.\" Abu Isa berkata: Banyak perowi yang meriwayatkan hadits ini dari perkataan Al Hasan dan mereka tidak memusnadkannya (tidak menyambungkannya sampai Nabi), adapun Isma'il bin Muslim dia dilemahkan dalam masalah hadits dari sisi hafalannya, dan dalam bab ini ada hadits dari Abu Hurairah dan Abu Sa'id Al Khudri."},"2344":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ الزُّهْرِيُّ الْبَصْرِيُّ حَدَّثَنَا مَالِكُ بْنُ سُعَيْرٍ أَبُو مُحَمَّدٍ التَّمِيمِيُّ الْكُوفِيُّ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ وَعَنْ أَبِي سَعِيدٍ قَالَاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُؤْتَى بِالْعَبْدِ يَوْمَ الْقِيَامَةِ فَيَقُولُ اللَّهُ لَهُ أَلَمْ أَجْعَلْ لَكَ سَمْعًا وَبَصَرًا وَمَالًا وَوَلَدًا وَسَخَّرْتُ لَكَ الْأَنْعَامَ وَالْحَرْثَ وَتَرَكْتُكَ تَرْأَسُ وَتَرْبَعُ فَكُنْتَ تَظُنُّ أَنَّكَ مُلَاقِي يَوْمَكَ هَذَا قَالَ فَيَقُولُ لَا فَيَقُولُ لَهُ الْيَوْمَ أَنْسَاكَ كَمَا نَسِيتَنِيقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ صَحِيحٌ غَرِيبٌ وَمَعْنَى قَوْلِهِ الْيَوْمَ أَنْسَاكَ يَقُولُ الْيَوْمَ أَتْرُكُكَ فِي الْعَذَابِ هَكَذَا فَسَّرُوهُ قَالَ أَبُو عِيسَى وَقَدْ فَسَّرَ بَعْضُ أَهْلِ الْعِلْمِ هَذِهِ الْآيَةَ{ فَالْيَوْمَ نَنْسَاهُمْ }قَالُوا إِنَّمَا مَعْنَاهُ الْيَوْمَ نَتْرُكُهُمْ فِي الْعَذَابِ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad Az Zuhri Al Bashri] telah menceritakan kepada kami [Malik bin Syu'air Abu Muhammad At Tamimi Al Kufi] telah menceritakan kepada kami [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dan [Abu Sa'id] keduanya bercerita bahwa Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Pada hari Kiamat seorang hamba akan didatangkan kemudian Allah bertanya kepadanya: Bukankah Aku telah membuatkan pendengaran, penglihatan, harta dan anak untuku, dan Aku telah menundukkan hewan ternak dan tanaman untukmu, Aku telah tingagalkan kamu menjadi pemimpin dan mendapatkan seperempat (harta rampasan), apakah kamu mengira akan menemuiKu saat ini?\" hamba itu menjawab: Tidak. kemudian Allah berfirman kepadanya: Pada hari ini Aku melupakanmu sebagaimana kamu telah melupakanKu.\" Abu Isa berkata: Hadits ini shahih gharib, adapun makna firman Allah \"Pada hari ini Aku melupakanmu, \" dia berkata maksudnya pada hari ini Aku biarkan kamu berada dalam siksaan. Demikianlah para ulama menafsirkan firman tersebut. Abu Isa berkata: Sebagian ahli Ilmu menafsirkan ayat ini \" FAL YAUMA NANSAAHUM (maka pada hari ini (akhirat) kami melupakan mereka) \". (Al A'raaf: 51) mereka berkata: Maknanya adalah pada hari ini Kami biarkan mereka berada dalam siksaan."},"2345":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ نَصْرٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ أَخْبَرَنَا سَعِيدُ بْنُ أَبِي أَيُّوبَ حَدَّثَنَا يَحْيَى بْنُ أَبِي سُلَيْمَانَ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَقَرَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ يَوْمَئِذٍ تُحَدِّثُ أَخْبَارَهَا }قَالَ أَتَدْرُونَ مَا أَخْبَارُهَا قَالُوا اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ فَإِنَّ أَخْبَارَهَا أَنْ تَشْهَدَ عَلَى كُلِّ عَبْدٍ أَوْ أَمَةٍ بِمَا عَمِلَ عَلَى ظَهْرِهَا أَنْ تَقُولَ عَمِلَ كَذَا وَكَذَا يَوْمَ كَذَا وَكَذَا قَالَ فَهَذِهِ أَخْبَارُهَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Suwaid bin Nashr] telah mengkhabarkan kepada kami [Abdullah bin Al Mubarak] telah mengkhabarkan kepada kami [Sa'id bin Abu Ayyub] telah menceritakan kepada kami [Yahya bin Abu Sulaiman] dari [Sa'id Al Maqbari] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alahi wa Salam membaca: \"Pada hari itu bumi menceritakan beritanya.\" (Al-Zalzalah: 4), belia bertanya: \"Tahukah kalian apa berita-beritanya?\" mereka menjawab: Allah dan rasulNya lebih tahu. Beliau bersabda: \"Berita-beritanya adalah perbuatan-perbuatan yang dilakukan oleh hamba lelaki atau perempuan di atas bumi berkata: Ia melakukan ini dan ini, pada hari ini dan ini.\" beliau bersabda: \"Itulah berita-beritanya.\" Berkata Abu Isa: Hadits ini hasan gharib."},"2346":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ نَصْرٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ أَخْبَرَنَا سُلَيْمَانُ التَّيْمِيُّ عَنْ أَسْلَمَ الْعِجْلِيِّ عَنْ بِشْرِ بْنِ شَغَافٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِ قَالَجَاءَ أَعْرَابِيٌّ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا الصُّورُ قَالَ قَرْنٌ يُنْفَخُ فِيهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ وَقَدْ رَوَى غَيْرُ وَاحِدٍ عَنْ سُلَيْمَانَ التَّيْمِيِّ وَلَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِهِ","id":"Telah menceritakan kepada kami [Suwaid bin Nashr] telah mengkhabarkan kepada kami ['Abdulah bin Al Mubarak] telah mengkhabarkan kepada kami [Sulaiman At Taimi] dari [Aslam Al 'Ijli] dari [Bisyr bin Syaghaf] dar [Abdullah bin 'Amru bin Al 'Ash] berkata: Seorang badui mendatangi nabi Shallallahu 'alaihi wa Salam, ia berkata: Apa itu sangkakala? Beliau menjawab: \"Tanduk yang ditiup.\" Berkata Abu Isa: Hadits ini hasan dan beberapa perawi meriwayatkan dari Sulaiman At Taimi, kami hanya mengetahuinya dari hadits Sulaiman."},"2347":{"ar":"حَدَّثَنَا سُوَيْدٌ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا أَبُو الْعَلَاءِ عَنْ عَطِيَّةَ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَيْفَ أَنْعَمُ وَصَاحِبُ الْقَرْنِ قَدْ الْتَقَمَ الْقَرْنَ وَاسْتَمَعَ الْإِذْنَ مَتَى يُؤْمَرُ بِالنَّفْخِ فَيَنْفُخُ فَكَأَنَّ ذَلِكَ ثَقُلَ عَلَى أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُمْ قُولُوا حَسْبُنَا اللَّهُ وَنِعْمَ الْوَكِيلُ عَلَى اللَّهِ تَوَكَّلْنَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ وَقَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ هَذَا الْحَدِيثُ عَنْ عَطِيَّةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Suwaid] telah mengkhabarkan kepada kami [Abdullah] telah mengkhabarkan kepada kami [Abu Al 'Alla`] dari ['Athiyah] dari [Abu Sa'id] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Bagaimana aku bersenang-senang sementara malaikat peniup sangkakala telah menelan tanduk (terompet) dan mendengar izin kapankan diperintahkan untuk meniup lalu ia akan meniup.\" Sepertinya hal itu terasa berat oleh para sahabat nabi Shallallahu 'alaihi wa Salam lalu beliau bersabda kepada mereka: \"Ucapkan: HASBUNALLAAH WA NI'MAL WAKILL 'ALALLAAHI TAWAKKALNAA.\" Berkata Abu Isa: Hadits ini hasan dan hadits ini diriwayatkan melalui beberapa sanad dari 'Athiyah dari Abu Sa'id Al Khudri dari nabi Shallallahu 'alaihi wa Salam sepertinya."},"2348":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ إِسْحَقَ عَنْ النُّعْمَانِ بْنِ سَعْدٍ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شِعَارُ الْمُؤْمِنِ عَلَى الصِّرَاطِ رَبِّ سَلِّمْ سَلِّمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ مِنْ حَدِيثِ الْمُغِيرَةِ بْنِ شُعْبَةَ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ عَبْدِ الرَّحْمَنِ بْنِ إِسْحَقَ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ","id":"Telah menceritakan kepada kami ['Ali bin Hujr] telah menceritakan kepada kami ['Ali bin Mushir] dari [Abdurrahman bin Ishaq] dari [An Nu'man bin Sa'ad] dari [Al Mughirah bin Syu'bah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Syi'arnya orang mukmin pada saat di atas shirath (jembatan penyeberangan) adalah: Wahai Rabb selamatkanlah, selamatkanlah.\" Abu Isa berkata: Hadits ini gharib dari hadits Al Mughirah bin Syu'bah, kami tidak mengetahuinya kecuali dari hadits Abdurrahman bin Ishaq, dan dalam bab ini ada hadits dari Abu Hurairah."},"2349":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الصَّبَّاحِ الْهَاشِمِيُّ حَدَّثَنَا بَدَلُ بْنُ الْمُحَبَّرِ حَدَّثَنَا حَرْبُ بْنُ مَيْمُونٍ الْأَنْصَارِيُّ أَبُو الْخَطَّابِ حَدَّثَنَا النَّضْرُ بْنُ أَنَسِ بْنِ مَالِكٍ عَنْ أَبِيهِ قَالَسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَشْفَعَ لِي يَوْمَ الْقِيَامَةِ فَقَالَ أَنَا فَاعِلٌ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ فَأَيْنَ أَطْلُبُكَ قَالَ اطْلُبْنِي أَوَّلَ مَا تَطْلُبُنِي عَلَى الصِّرَاطِ قَالَ قُلْتُ فَإِنْ لَمْ أَلْقَكَ عَلَى الصِّرَاطِ قَالَ فَاطْلُبْنِي عِنْدَ الْمِيزَانِ قُلْتُ فَإِنْ لَمْ أَلْقَكَ عِنْدَ الْمِيزَانِ قَالَ فَاطْلُبْنِي عِنْدَ الْحَوْضِ فَإِنِّي لَا أُخْطِئُ هَذِهِ الثَّلَاثَ الْمَوَاطِنَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Abdullah bin Ash Shabbah Al Hasyimi] telah menceritakan kepada kami [Badal bin Al Muhabbir] telah menceritakan kepada kami [Harb bin Maimun Al Anshari Abu Al Khaththab] telah menceritakan kepada kami [An Nadlr bin Anas bin Malik] dari [ayahnya] berkata: Aku meminta nabi Shallallahu 'alaihi wa Salam agar memberiku syafaat pada hari kiamat, beliau bersabda: \"Aku akan melakukannya.\" Ia bertanya: Wahai Rasulullah, ke mana aku mencari baginda? Beliau menjawab: \"Carilah aku pada saat pertama kali kau mencari di atas shirath.\" Ia bertanya: Bila aku tidak bertemu dengan baginda di atas shirath? Beliau menjawab: \"Carilah aku di dekat mizan.\" Ia bertanya: Bila aku tidak bertemu dengan baginda di dekat mizan? Beliau menjawab: \"Carilah aku di dekat telaga, karena aku tidak luput dari tiga tempat itu.\" Berkata Abu Isa: Hadits ini hasan gharib, kami hanya mengetahuinya melalui jalur sanad ini."},"2350":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ أَخْبَرَنَا أَبُو حَيَّانَ التَّيْمِيُّ عَنْ أَبِي زُرْعَةَ بْنِ عَمْرِو بْنِ جَرِيرٍ عَنْ أَبِي هُرَيْرَةَ قَالَأُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِلَحْمٍ فَرُفِعَ إِلَيْهِ الذِّرَاعُ فَأَكَلَهُ وَكَانَتْ تُعْجِبُهُ فَنَهَسَ مِنْهَا نَهْسَةً ثُمَّ قَالَ أَنَا سَيِّدُ النَّاسِ يَوْمَ الْقِيَامَةِ هَلْ تَدْرُونَ لِمَ ذَاكَ يَجْمَعُ اللَّهُ النَّاسَ الْأَوَّلِينَ وَالْآخِرِينَ فِي صَعِيدٍ وَاحِدٍ فَيُسْمِعُهُمْ الدَّاعِي وَيَنْفُذُهُمْ الْبَصَرُ وَتَدْنُو الشَّمْسُ مِنْهُمْ فَبَلَغَ النَّاسُ مِنْ الْغَمِّ وَالْكَرْبِ مَا لَا يُطِيقُونَ وَلَا يَحْتَمِلُونَ فَيَقُولُ النَّاسُ بَعْضُهُمْ لِبَعْضٍ أَلَا تَرَوْنَ مَا قَدْ بَلَغَكُمْ أَلَا تَنْظُرُونَ مَنْ يَشْفَعُ لَكُمْ إِلَى رَبِّكُمْ فَيَقُولُ النَّاسُ بَعْضُهُمْ لِبَعْضٍ عَلَيْكُمْ بِآدَمَ فَيَأْتُونَ آدَمَ فَيَقُولُونَ أَنْتَ أَبُو الْبَشَرِ خَلَقَكَ اللَّهُ بِيَدِهِ وَنَفَخَ فِيكَ مِنْ رُوحِهِ وَأَمَرَ الْمَلَائِكَةَ فَسَجَدُوا لَكَ اشْفَعْ لَنَا إِلَى رَبِّكَ أَلَا تَرَى مَا نَحْنُ فِيهِ أَلَا تَرَى مَا قَدْ بَلَغَنَا فَيَقُولُ لَهُمْ آدَمُ إِنَّ رَبِّي قَدْ غَضِبَ الْيَوْمَ غَضَبًا لَمْ يَغْضَبْ قَبْلَهُ وَلَنْ يَغْضَبَ بَعْدَهُ مِثْلَهُ وَإِنَّهُ قَدْ نَهَانِي عَنْ الشَّجَرَةِ فَعَصَيْتُ نَفْسِي نَفْسِي نَفْسِي اذْهَبُوا إِلَى غَيْرِي اذْهَبُوا إِلَى نُوحٍ فَيَأْتُونَ نُوحًا فَيَقُولُونَ يَا نُوحُ أَنْتَ أَوَّلُ الرُّسُلِ إِلَى أَهْلِ الْأَرْضِ وَقَدْ سَمَّاكَ اللَّهُ عَبْدًا شَكُورًا اشْفَعْ لَنَا إِلَى رَبِّكَ أَلَا تَرَى إِلَى مَا نَحْنُ فِيهِ أَلَا تَرَى مَا قَدْ بَلَغَنَا فَيَقُولُ لَهُمْ نُوحٌ إِنَّ رَبِّي قَدْ غَضِبَ الْيَوْمَ غَضَبًا لَمْ يَغْضَبْ قَبْلَهُ مِثْلَهُ وَلَنْ يَغْضَبَ بَعْدَهُ مِثْلَهُ وَإِنَّهُ قَدْ كَانَ لِي دَعْوَةٌ دَعَوْتُهَا عَلَى قَوْمِي نَفْسِي نَفْسِي نَفْسِي اذْهَبُوا إِلَى غَيْرِي اذْهَبُوا إِلَى إِبْرَاهِيمَ فَيَأْتُونَ إِبْرَاهِيمَ فَيَقُولُونَ يَا إِبْرَاهِيمُ أَنْتَ نَبِيُّ اللَّهِ وَخَلِيلُهُ مِنْ أَهْلِ الْأَرْضِ اشْفَعْ لَنَا إِلَى رَبِّكَ أَلَا تَرَى مَا نَحْنُ فِيهِ فَيَقُولُ إِنَّ رَبِّي قَدْ غَضِبَ الْيَوْمَ غَضَبًا لَمْ يَغْضَبْ قَبْلَهُ مِثْلَهُ وَلَنْ يَغْضَبَ بَعْدَهُ مِثْلَهُ وَإِنِّي قَدْ كَذَبْتُ ثَلَاثَ كَذِبَاتٍ فَذَكَرَهُنَّ أَبُو حَيَّانَ فِي الْحَدِيثِ نَفْسِي نَفْسِي نَفْسِي اذْهَبُوا إِلَى غَيْرِي اذْهَبُوا إِلَى مُوسَى فَيَأْتُونَ مُوسَى فَيَقُولُونَ يَا مُوسَى أَنْتَ رَسُولُ اللَّهِ فَضَّلَكَ اللَّهُ بِرِسَالَتِهِ وَبِكَلَامِهِ عَلَى الْبَشَرِ اشْفَعْ لَنَا إِلَى رَبِّكَ أَلَا تَرَى مَا نَحْنُ فِيهِ فَيَقُولُ إِنَّ رَبِّي قَدْ غَضِبَ الْيَوْمَ غَضَبًا لَمْ يَغْضَبْ قَبْلَهُ مِثْلَهُ وَلَنْ يَغْضَبَ بَعْدَهُ مِثْلَهُ وَإِنِّي قَدْ قَتَلْتُ نَفْسًا لَمْ أُومَرْ بِقَتْلِهَا نَفْسِي نَفْسِي نَفْسِي اذْهَبُوا إِلَى غَيْرِي اذْهَبُوا إِلَى عِيسَى فَيَأْتُونَ عِيسَى فَيَقُولُونَ يَا عِيسَى أَنْتَ رَسُولُ اللَّهِ وَكَلِمَتُهُ أَلْقَاهَا إِلَى مَرْيَمَ وَرُوحٌ مِنْهُ وَكَلَّمْتَ النَّاسَ فِي الْمَهْدِ اشْفَعْ لَنَا إِلَى رَبِّكَ أَلَا تَرَى مَا نَحْنُ فِيهِ فَيَقُولُ عِيسَى إِنَّ رَبِّي قَدْ غَضِبَ الْيَوْمَ غَضَبًا لَمْ يَغْضَبْ قَبْلَهُ مِثْلَهُ وَلَنْ يَغْضَبَ بَعْدَهُ مِثْلَهُ وَلَمْ يَذْكُرْ ذَنْبًا نَفْسِي نَفْسِي نَفْسِي اذْهَبُوا إِلَى غَيْرِي اذْهَبُوا إِلَى مُحَمَّدٍ قَالَ فَيَأْتُونَ مُحَمَّدًا فَيَقُولُونَ يَا مُحَمَّدُ أَنْتَ رَسُولُ اللَّهِ وَخَاتَمُ الْأَنْبِيَاءِ وَقَدْ غُفِرَ لَكَ مَا تَقَدَّمَ مِنْ ذَنْبِكَ وَمَا تَأَخَّرَ اشْفَعْ لَنَا إِلَى رَبِّكَ أَلَا تَرَى مَا نَحْنُ فِيهِ فَأَنْطَلِقُ فَآتِي تَحْتَ الْعَرْشِ فَأَخِرُّ سَاجِدًا لِرَبِّي ثُمَّ يَفْتَحُ اللَّهُ عَلَيَّ مِنْ مَحَامِدِهِ وَحُسْنِ الثَّنَاءِ عَلَيْهِ شَيْئًا لَمْ يَفْتَحْهُ عَلَى أَحَدٍ قَبْلِي ثُمَّ يُقَالَ يَا مُحَمَّدُ ارْفَعْ رَأْسَكَ سَلْ تُعْطَهْ وَاشْفَعْ تُشَفَّعْ فَأَرْفَعُ رَأْسِي فَأَقُولُ يَا رَبِّ أُمَّتِي يَا رَبِّ أُمَّتِي يَا رَبِّ أُمَّتِي فَيَقُولُ يَا مُحَمَّدُ أَدْخِلْ مِنْ أُمَّتِكَ مَنْ لَا حِسَابَ عَلَيْهِ مِنْ الْبَابِ الْأَيْمَنِ مِنْ أَبْوَابِ الْجَنَّةِ وَهُمْ شُرَكَاءُ النَّاسِ فِيمَا سِوَى ذَلِكَ مِنْ الْأَبْوَابِ ثُمَّ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ مَا بَيْنَ الْمِصْرَاعَيْنِ مِنْ مَصَارِيعِ الْجَنَّةِ كَمَا بَيْنَ مَكَّةَ وَهَجَرَ وَكَمَا بَيْنَ مَكَّةَ وَبُصْرَىوَفِي الْبَاب عَنْ أَبِي بَكْرٍ الصِّدِّيقِ وَأَنَسٍ وَعُقْبَةَ بْنِ عَامِرٍ وَأَبِي سَعِيدٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَأَبُو حَيَّانَ التَّيْمِيُّ اسْمُهُ يَحْيَى بْنُ سَعِيدِ بْنِ حَيَّانَ كُوفِيٌّ وَهُوَ ثِقَةٌ وَأَبُو زُرْعَةَ بْنُ عَمْرِو بْنِ جَرِيرٍ اسْمُهُ هَرِمٌ","id":"Telah menceritakan kepada kami [Suwaid bin Nashr] telah mengkhabarkan kepada kami [Abdullah bin Al Mubarak] telah mengkhabarkan kepada kami [Abu Hayyan At Taimi] dari [Abu Zur'ah bin 'Amru bin Jarir] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alahi wa Salam diberi daging lalu lengan diangkat pada belia, beliau memakannya dan lengan itu membuat beliau senang, beliau lalu menggigitnya, setelah itu beliau bersabda: \"Aku pemimpin manusia pada hari kiamat, tahukah kalian kenapa? Allah mengumpulkan semua manusia dari yang pertama hingga yang akhir dalam satu tanah lapang, penyeru memperdengarkan mereka, pandangan menembus mereka dan matahari mendekat, duka dan kesusahan manusia sampai pada batas yang tidak mereka mampu dan tidak mampu mereka pikul. Orang-orang saling berkata satu sama lain: Apa kalian tidak melihat yang telah menimpa kalian, apakah kalian tidak melihat siapa yang memberi kalian syafaat kepada Rabb kalian. Orang-orang saling berkata satu sama lain: Hendaklah kalian menemui Adam. Mereka menemui Adam lalu berkata: Engkau adalah nenek moyang manusia, Allah menciptakanmu dengan tanganNya, meniupkan ruhnya padamu dan memerintahkan para malaikat lalu mereka sujud padamu, berilah kami syafaat kepada Rabbmu, apa kau tidak lihat kondisi kami, apa kau tidak melihat yang menimpa kami? Adam berkata kepada mereka: Rabbku saat ini benar-benar marah, Ia tidak pernah marah seperti itu sebelumnya dan tidak akan pernah seperti itu sesudahnya, dulu Ia melarangku mendekati pohon tapi aku durhaka, diriku, diriku, diriku. Pergilah pada selainku, pergilah ke Nuh. Mereka mendatangi Nuh lalu berkata: Hai Nuh, engkau adalah rasul pertama untuk penduduk bumi, Allah menyebutmu hamba yang sangat bersyukur, berilah kami syafaat kepada Rabbmu, apa kau tidak lihat kondisi kami, apa kau tidak melihat yang menimpa kami? Nuh berkata kepada mereka: Rabbku saat ini benar-benar marah, Ia tidak pernah marah seperti itu sebelumnya dan tidak akan pernah seperti itu sesudahnya, dulu aku pernah berdoa keburukan untuk kaumku, diriku, diriku, diriku, pergilah kepada selainku, pergilah ke Ibrahim. Mereka mendatangi Ibrahim lalu berkata: Wahai Ibrahim, engkau nabi Allah dan kekasihNya dari penduduk bumi, berilah kami syafaat kepada Rabbmu, apa kau tidak lihat kondisi kami, apa kau tidak melihat yang menimpa kami? Nuh berkata kepada mereka: Rabbku saat ini benar-benar marah, Ia tidak pernah marah seperti itu sebelumnya dan tidak akan pernah seperti itu sesudahnya, dulu aku pernah bedusta tiga kali -Abu Hayyan menyebut ketiga-tiganya dalam hadits ini- diriku, diriku, diriku, pergilah kepada selainku, pergilah ke Musa. Mereka menemui Musa lalu berkata: Wahai Musa, engkau utusan Allah, Allah melebihkanmu dengan risalah dan kalamNya atas seluruh manusia, berilah kami syafaat kepada Rabbmu, apa kau tidak lihat kondisi kami, apa kau tidak melihat yang menimpa kami? Musa berkata kepada mereka: Rabbku saat ini benar-benar marah, Ia tidak pernah marah seperti itu sebelumnya dan tidak akan pernah seperti itu sesudahnya, dulu aku pernah membunuh jiwa padahal aku tidak diperintahkan untuk membunuhnya, diriku, diriku, diriku, pergilah kepada selainku, pergilah ke 'Isa. Mereka mendatangi 'Isa lalu berkata: Hai 'Isa, engkau adalah utusan Allah, kalimatNya yang disampaikan ke maryam, ruh dariNya, engkau berbicara pada manusia saat masih berada dalam buaian, berilah kami syafaat kepada Rabbmu, apa kau tidak lihat kondisi kami, apa kau tidak melihat yang menimpa kami? Isa berkata kepada mereka: Rabbku saat ini benar-benar marah, Ia tidak pernah marah seperti itu sebelumnya dan tidak akan pernah seperti itu sesudahnya, ia tidak menyebut dosa, diriku, diriku, diriku, pergilah ke selainku, pergilah ke Muhammad. Mereka mendatangi Muhammad lalu berkata: Wahai Muhammad, engkau adalah utusan Allah, penutup para nabi, dosamu yang telah lau dan yang kemudian telah diampuni, berilah kami syafaat kepada Rabbmu, apa kau tidak lihat kondisi kami. Lalu aku pergi hingga sampai di bawah 'arsy, aku tersungkur sujud pada Rabbku lalu Allah memulai dengan pujian dan sanjungan untukku yang belum pernah disampaikan pada seorang pun sebelumku, lalu ada suara: Hai Muhammad, angkatlah kepalamu, mintalah pasti kau diberi, berilah syafaat nicaya kau diizinkan untuk memberi syafaat. Lalu aku mengangkat kepalaku, aku berkata: Wahai Rabb, ummatku, wahai Rabb, ummatku, wahai Rabb, ummatku. Ia berkata: Hai Muhammad, masukkan orang yang tidak dihisab dari ummatmu melalui pintu-pintu surga sebelah kanan dan mereka adalah sekutu semua manusia selain pintu-pintu itu.\" Setelah itu beliau bersabda: \"Demi Dzat yang jiwaku berada ditanganNya, jarak antara dua daun pintu-pintu surga seperti jarak antara Makakah dan Hajar dan seperti jarak antara Makkah dan Bashrah.\" Dalam hal ini ada hadits serupa dari Abu Bakar Ash Shiddiq, Anas, 'Uqbah bin 'Amir, Abu Sa'id. Berkata Abu Isa: Hadits ini hasan shahih dan nama Abu Hayyan At Taimi adalah Yahya bin Sa'id bin Hayyan, orang kufi, terpercaya, dan nama Abu Zur'ah bin 'Amru bin Jarir adalah Harim."},"2351":{"ar":"حَدَّثَنَا الْعَبَّاسُ الْعَنْبَرِيُّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَفَاعَتِي لِأَهْلِ الْكَبَائِرِ مِنْ أُمَّتِيقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَفِي الْبَاب عَنْ جَابِر��","id":"Telah menceritakan kepada kami [Al 'Abbas Al 'Ambari] telah menceritakan kepada kami ['Abdur Razzaq] dari [Ma'mar] dari [Tsabit] dari [Anas] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Syafaatku untuk pemilik dosa-dosa besar dari ummatku.\" Berkata Abu Isa: Hadits ini hasan shahih gharib melalui sanad ini dan dalam hal ini ada hadits serupa dari Jabir."},"2352":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو دَاوُدَ الطَّيَالِسِيُّ عَنْ مُحَمَّدِ بْنِ ثَابِتٍ الْبُنَانِيِّ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَفَاعَتِي لِأَهْلِ الْكَبَائِرِ مِنْ أُمَّتِيقَالَ مُحَمَّدُ بْنُ عَلِيٍّ فَقَالَ لِي جَابِرٌ يَا مُحَمَّدُ مَنْ لَمْ يَكُنْ مِنْ أَهْلِ الْكَبَائِرِ فَمَا لَهُ وَلِلشَّفَاعَةِ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ يُسْتَغْرَبُ مِنْ حَدِيثِ جَعْفَرِ بْنِ مُحَمَّدٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Abu Daud Ath Thayalisi] dari [Muhammad bin Tsabit Al Bunani] dari [Ja'far bin Muhammad] dari [bapaknya] dari [Jabir bin Abdullah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Syafa'atku untuk ummatku yang berbuat dosa dosa besar.\" Muhammad bin Ali berkata: kemudian Jabir berkata kepadaku: Wahai Muhammad orang yang tidak melakukan dosa besar tidak lagi membutuhkan syafa'at. Abu Isa berkata: Hadits ini hasan gharib dari jalur sanad ini, dan dianggap gharib dari hadits Ja'far bin Muhammad."},"2353":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَرَفَةَ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ عَنْ مُحَمَّدِ بْنِ زِيَادٍ الْأَلْهَانِيِّ قَال سَمِعْتُ أَبَا أُمَامَةَ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ وَعَدَنِي رَبِّي أَنْ يُدْخِلَ الْجَنَّةَ مِنْ أُمَّتِي سَبْعِينَ أَلْفًا لَا حِسَابَ عَلَيْهِمْ وَلَا عَذَابَ مَعَ كُلِّ أَلْفٍ سَبْعُونَ أَلْفًا وَثَلَاثُ حَثَيَاتٍ مِنْ حَثَيَاتِهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Al Hasan bin 'Arafah] telah menceritakan kepada kami [Isma'il bin 'Ayyasy] dari [Muhammad bin Ziyad Al Alhani] berkata: Aku mendengar [Abu Umamah] berkata: Aku mendengar Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Rabbku berjanji padaku untuk memasukkan tujuhpuluh ribu orang dari ummatku tanpa hisab dan adzab, setiap seribunya bersama tujuhpuluh ribu dan tiga tangkup (mengambil dengan dua telapak tangan) dari tangkupan (tangan) Nya.\" Berkata Abu Isa: Hadits ini hasan gharib."},"2354":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ قَالَكُنْتُ مَعَ رَهْطٍ بِإِيلِيَاءَ فَقَالَ رَجُلٌ مِنْهُمْ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَدْخُلُ الْجَنَّةَ بِشَفَاعَةِ رَجُلٍ مِنْ أُمَّتِي أَكْثَرُ مِنْ بَنِي تَمِيمٍ قِيلَ يَا رَسُولَ اللَّهِ سِوَاكَ قَالَ سِوَايَ فَلَمَّا قَامَ قُلْتُ مَنْ هَذَا قَالُوا هَذَا ابْنُ أَبِي الْجَذْعَاءِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ وَابْنُ أَبِي الْجَذْعَاءِ هُوَ عَبْدُ اللَّهِ وَإِنَّمَا يُعْرَفُ لَهُ هَذَا الْحَدِيثُ الْوَاحِدُ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Isma'il bin Ibrahim] dari [Khalid Al Hadzdza`] dari [Abdullah bin Syaqiq] berkata: Aku pernah bersama serombongan orang di Iliya`, seseorang dari mereka berkata: Aku mendengar Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Akan masuk surga karena syafaat seseorang dari ummatku lebih banyak dari Bani Tamim.\" Dikatakan: Wahai Rasulullah, selain baginda? Beliau menjawab: \"Selain aku.\" Saat ia berdiri, aku bertanya: Siapa dia? Mereka menjawab: Dia [Ibnu Abi Al Jadz 'Abdullah']. Berkata Abu Isa: Hadits ini hasan shahih gharib dan Ibnu Abi Al Jadz'a` adalah Abdullah, hanya satu hadits ini saja yang dikenal miliknya."},"2355":{"ar":"حَدَّثَنَا أَبُو هِشَامٍ الرِّفَاعِيُّ الْكُوفِيُّ قَالَ حَدَّثَنَا يَحْيَى بْنُ الْيَمَانِ عَنْ جِسْرٍ أَبِي جَعْفَرٍ عَنْ الْحَسَنِ الْبَصْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَشْفَعُ عُثْمَانُ بْنُ عَفَّانَ رَضِيَ اللَّهُ عَنْهُ يَوْمَ الْقِيَامَةِ بِمِثْلِ رَبِيعَةَ وَمُضَرَ","id":"Telah menceritakan kepada kami [Abu Hisyam Ar Rifa'I Al Kufi] berkata: telah menceritakan kepada kami [Yahya bin Al Yaman] dari [Jisr Abu Ja'far] dari [Al Hasan Al Bashri] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"'Utsman bin 'Affan radliallahu 'anhu pada hari Kiamat memberikan syafa'at untuk seperti kabilah Rabi'ah dan Mudlar.\""},"2356":{"ar":"حَدَّثَنَا أَبُو عَمَّارٍ الْحُسَيْنُ بْنُ حُرَيْثٍ أَخْبَرَنَا الْفَضْلُ بْنُ مُوسَى عَنْ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ عَنْ عَطِيَّةَ عَنْ أَبِي سَعِيدٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ مِنْ أُمَّتِي مَنْ يَشْفَعُ لِلْفِئَامِ مِنْ النَّاسِ وَمِنْهُمْ مَنْ يَشْفَعُ لِلْقَبِيلَةِ وَمِنْهُمْ مَنْ يَشْفَعُ لِلْعَصَبَةِ وَمِنْهُمْ مَنْ يَشْفَعُ لِلرَّجُلِ حَتَّى يَدْخُلُوا الْجَنَّةَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Abu 'Ammar Al Husain bin Huraits] telah mengkhabarkan kepada kami [Al Fadll bin Musa] dari [Zakariya bin Abu Za`idah] dari ['Athiyah] dari [Abu Sa'id] Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Sesungguhnya diantara ummatku ada yang memberi syafaat kepada sekelompok orang, ada yang memberi syafaat untuk sekabilah, ada yang memberi syafaat untuk segolongan dan ada yang memberi syafaat untuk seseorang hingga mereka masuk surga.\" Berkata Abu Isa: Hadits ini hasan. "},"2357":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا عَبْدَةُ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ أَبِي الْمَلِيحِ عَنْ عَوْفِ بْنِ مَالِكٍ الْأَشْجَعِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَانِي آتٍ مِنْ عِنْدِ رَبِّي فَخَيَّرَنِي بَيْنَ أَنْ يُدْخِلَ نِصْفَ أُمَّتِي الْجَنَّةَ وَبَيْنَ الشَّفَاعَةِ فَاخْتَرْتُ الشَّفَاعَةَ وَهِيَ لِمَنْ مَاتَ لَا يُشْرِكُ بِاللَّهِ شَيْئًاوَقَدْ رُوِيَ عَنْ أَبِي الْمَلِيحِ عَنْ رَجُلٍ آخَرَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ يَذْكُرْ عَنْ عَوْفِ بْنِ مَالِكٍ وَفِي الْحَدِيثِ قِصَّةٌ طَوِيلَةٌ حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ أَبِي الْمَلِيحِ عَنْ عَوْفِ بْنِ مَالِكٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami ['Abdah] dari [Sa'id] dari [Qatadah] dari [Abu Al Malih] dari ['Auf bin Malik Al Asyja'i] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Ada yang mendatangiku dari Rabbku lalu memberiku pilihan antara separuh dari ummatku masuk surga atau syafaat lalu aku memilih syafaat, syafaat tersebut untuk orang yang meninggal tanpa menyekutukan Allah dengan apa pun.\" Diriwayatkan dari Abu Al Malih dari seorang sahabat nabi Shallallahu 'alaihi wa Salam lain dari nabi Shallallahu 'alaihi wa Salam, ia tidak menyebutkan: Dari 'Auf bin Malik. Dan dalam hadits ini ada kisah panjang. Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abu 'Awanah] dari [Qaadah] dari [Abu Al Malih] dari ['Auf bin Malik] dari nabi Shallallahu 'alaihi wa Salam sepertinya."},"2358":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا بِشْرُ بْنُ شُعَيْبِ بْنِ أَبِي حَمْزَةَ حَدَّثَنِي أَبِي عَنْ الزُّهْرِيِّ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ فِي حَوْضِي مِنْ الْأَبَارِيقِ بِعَدَدِ نُجُومِ السَّمَاءِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] telah menceritakan kepada kami [Bisyr bin Syu'aib bin Abu Hamzah] telah menceritakan kepadaku [ayahku] dari [Az Zuhri] dari [Anas bin Malik], Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Sesungguhnya gelas-gelas di telagaku sejumlah bintang-bintang di langit.\" Berkata Abu Isa: Hadits ini hasan shahih gharib dari jalur sanad ini."},"2359":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ نِيْزَكَ الْبَغْدَادِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ بَكَّارٍ الدِّمَشْقِيُّ حَدَّثَنَا سَعِيدُ بْنُ بَشِيرٍ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ لِكُلِّ نَبِيٍّ حَوْضًا وَإِنَّهُمْ يَتَبَاهَوْنَ أَيُّهُمْ أَكْثَرُ وَارِدَةً وَإِنِّي أَرْجُو أَنْ أَكُونَ أَكْثَرَهُمْ وَارِدَةًقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ وَقَدْ رَوَى الْأَشْعَثُ بْنُ عَبْدِ الْمَلِكِ هَذَا الْحَدِيثَ عَنْ الْحَسَنِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْسَلًا وَلَمْ يَذْكُرْ فِيهِ عَنْ سَمُرَةَ وَهُوَ أَصَحُّ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad bin Nizak Al Baghdadi] telah menceritakan kepada kami [Muhammad bin Bakkar Ad Dimasyqi] telah menceritakan kepada kami [Sa'id bin Basyir] dari [Qatadah] dari [Al Hasan] dari [Samrah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya tiap tiap nabi itu memiliki telaga, dan sesungguhnya mereka saling membangga-banggakan telaga siapakah di antara mereka yang paling banyak pengunjungnya, dan sesungguhnya aku berharap menjadi orang yang paling banyak pengunjungnya.\" Abu Isa berkata: Hadits ini gharib, [Al Asy'ats bin Abdul Malik] telah meriwayatkan hadits ini dari [Al Hasan] dari Nabi Shallallahu 'alaihi wa Salam secara mursal dan di dalamnya tidak menyebutkan: Dari Samuroh dan inilah yang lebih shahih.\""},"2360":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ حَدَّثَنَا يَحْيَى بْنُ صَالِحٍ حَدَّثَنَا مُحَمَّدُ بْنُ الْمُهَاجِرِ عَنْ الْعَبَّاسِ عَنْ أَبِي سَلَّامٍ الْحَبَشِيِّ قَالَبَعَثَ إِلَيَّ عُمَرُ بْنُ عَبْدِ الْعَزِيزِ فَحُمِلْتُ عَلَى الْبَرِيدِ قَالَ فَلَمَّا دَخَلَ عَلَيْهِ قَالَ يَا أَمِيرَ الْمُؤْمِنِينَ لَقَدْ شَقَّ عَلَى مَرْكَبِي الْبَرِيدُ فَقَالَ يَا أَبَا سَلَّامٍ مَا أَرَدْتُ أَنْ أَشُقَّ عَلَيْكَ وَلَكِنْ بَلَغَنِي عَنْكَ حَدِيثٌ تُحَدِّثُهُ عَنْ ثَوْبَانَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْحَوْضِ فَأَحْبَبْتُ أَنْ تُشَافِهَنِي بِهِ قَالَ أَبُو سَلَّامٍ حَدَّثَنِي ثَوْبَانُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ حَوْضِي مِنْ عَدَنَ إِلَى عَمَّانَ الْبَلْقَاءِ مَاؤُهُ أَشَدُّ بَيَاضًا مِنْ اللَّبَنِ وَأَحْلَى مِنْ الْعَسَلِ وَأَكَاوِيبُهُ عَدَدُ نُجُومِ السَّمَاءِ مَنْ شَرِبَ مِنْهُ شَرْبَةً لَمْ يَظْمَأْ بَعْدَهَا أَبَدًا أَوَّلُ النَّاسِ وُرُودًا عَلَيْهِ فُقَرَاءُ الْمُهَاجِرِينَ الشُّعْثُ رُءُوسًا الدُّنْسُ ثِيَابًا الَّذِينَ لَا يَنْكِحُونَ الْمُتَنَعِّمَاتِ وَلَا تُفْتَحُ لَهُمْ السُّدَدُقَالَ عُمَرُ لَكِنِّي نَكَحْتُ الْمُتَنَعِّمَاتِ وَفُتِحَ لِيَ السُّدَدُ وَنَكَحْتُ فَاطِمَةَ بِنْتَ عَبْدِ الْمَلِكِ لَا جَرَمَ أَنِّي لَا أَغْسِلُ رَأْسِي حَتَّى يَشْعَثَ وَلَا أَغْسِلُ ثَوْبِي الَّذِي يَلِي جَسَدِي حَتَّى يَتَّسِخَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ مَعْدَانَ بْنِ أَبِي طَلْحَةَ عَنْ ثَوْبَانَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو سَلَّامٍ الْحَبَشِيُّ اسْمُهُ مَمْطُورٌ وَهُوَ شَامِيٌّ ثِقَةٌ","id":"Telah menceritakan kepada kami [Muhammad bin Isma'il] telah menceritakan kepada kami [Yahya bin Shalih] telah menceritakan kepada kami [Muhammad bin Al Muhajir] dari [Al 'Abbas] dari [Abu Sallam Al Habasyi] berkata: Umar bin Abdul Aziz mengutusku untuk menjadi tukang antar surat, Abu sallam berkata: Ketika masuk dia berkata: Wahai Amirul mukminin kendaraanku telah keberatan untuk dijadikan transportsi surat menyurat. lalu Umar bin Abdul aziz berkata: Wahai Abu Sallam, aku tidak ingin memberatkanmu akan tetapi karena telah sampai kepadaku hadits yang diriwayatkan olehmu yang kamu ceritakan dari [Tsauban] dari Nabi Shallallahu 'alaihi wa Salam dalam masalah telaga, maka aku ingin bertatap muka denganmu dalam masalah ini, Abu Sallam berkata: Tsauban telah menceritakan kepadaku dari Nabi Shallallahu 'alaihi wa Salam beliau bersabda: \"Luasnya telagaku adalah seluas antara Aden sampai Oman Al Balqa', airnya lebih putih dari air susu, lebih manis dari madu dan cangkir-cangkirnya sebanyak bilangan bintang di langit, barangsiapa yang minum satu tegukan air darinya niscaya setelah itu tidak akan merasa haus selamanya, orang yang pertama kali akan mengunjunginya adalah orang orang fakir dari sahabat muhajirin, yang rambut kepalanya acak acakan, pakaiannya kumal dan mereka mereka yang tidak menikahi wanita wanita yang hidup dalam kemewahan, dan orang yang tidak dibukakan pintu (apabila bertamu atau mengetuk pintu rumah orang).\" Umar berkata: Akan tetapi aku telah menikahi seorang wanita yang hidup dalam kemewahan, pintu-pintu rumah juga dibukakan bagiku, dan aku telah menikahi Fathimah binti 'Abdul Malik, tidak ada salahnya aku tidak membasuh kepalaku hingga menjadi acak acakan, aku tidak mencuci pakaian yang ada di tubuhku sampai menjadi kumal.\" Abu Isa berkata: Hadits ini gharib dari jalur sanad ini, hadits ini telah diriwayatkan dari [Ma'dan bin Abu Thalhah] dari [Tsauban] dari Nabi Shallallahu 'alaihi wa Salam, adapun Abu sallam Al Habasyi namanya adalah Mamthur dan dia adalah orang Syam yang tsiqah.\""},"2361":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَبْدِ الصَّمَدِ الْعَمِّيُّ عَبْدُ الْعَزِيزِ بْنُ عَبْدِ الصَّمَدِ حَدَّثَنَا أَبُو عِمْرَانَ الْجَوْنِيُّ عَنْ عَبْدِ اللَّهِ بْنِ الصَّامِتِ عَنْ أَبِي ذَرٍّ قَالَقُلْتُ يَا رَسُولَ اللَّهِ مَا آنِيَةُ الْحَوْضِ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ لَآنِيَتُهُ أَكْثَرُ مِنْ عَدَدِ نُجُومِ السَّمَاءِ وَكَوَاكِبِهَا فِي لَيْلَةٍ مُظْلِمَةٍ مُصْحِيَةٍ مِنْ آنِيَةِ الْجَنَّةِ مَنْ شَرِبَ مِنْهَا شَرْبَةً لَمْ يَظْمَأْ آخِرَ مَا عَلَيْهِ عَرْضُهُ مِثْلُ طُولِهِ مَا بَيْنَ عُمَانَ إِلَى أَيْلَةَ مَاؤُهُ أَشَدُّ بَيَاضًا مِنْ اللَّبَنِ وَأَحْلَى مِنْ الْعَسَلِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ وَفِي الْبَاب عَنْ حُذَيْفَةَ بْنِ الْيَمَانِ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو وَأَبِي بَرْزَةَ الْأَسْلَمِيِّ وَابْنِ عُمَرَ وَحَارِثَةَ بْنِ وَهْبٍ وَالْمُسْتَوْرِدِ بْنِ شَدَّادٍ وَرُوِي عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ حَوْضِي كَمَا بَيْنَ الْكُوفَةِ إِلَى الْحَجَرِ الْأَسْوَدِ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Abu 'Abdush Shamad Al 'Ammi Abdul Aziz bin 'Abdush Shamad] telah menceritakan kepada kami [Abu 'Imran Al Juwaini] dari [Abdullah bin Ash Shamit] dari [Abu Dzarr] berkata: Aku bertanya: Wahai Rasulullah, telaga itu bejananya apa? Beliau menjawab: Demi Dzat yang jiwaku berada di tanganNya, sungguh bejana-bejananya lebih banyak melebihi bilangan bintang-bintang langit pada malam gelap yang tidak ada mendung dan awan, bejana itu kesemuanya dari bejana-bejana surga, barangsiapa meminum satu tegukan darinya, ia tidak akan dahaga hingga tanggungan terakhirnya, lausnya seluas antara Omman hingga Aila, airnya lebih putih dari susu, lebih manis dari madu.\" Berkata Abu Isa: Hadits ini hasan shahih gharib. Dalam hal ini ada hadits serupa dari Hudzaifah bin Al Yaman, Abdullah bin 'AMru, abu Barzah Al Aslami, Ibnu Umar, Haritsah bin Wahab, Al Mustaurid bin Syadad. Dan diriwayatkan dari Ibnu Umar dari nabi Shallallahu 'alaihi wa Salam bersabda: Telagaku sepanjang antara Kufah hingga hajar aswad."},"2362":{"ar":"حَدَّثَنَا أَبُو حَصِينٍ عَبْدُ اللَّهِ بْنُ أَحْمَدَ بْنِ يُونُسَ كُوفِيٌّ حَدَّثَنَا عَبْثَرُ بْنُ الْقَاسِمِ حَدَّثَنَا حُصَيْنٌ هُوَ ابْنُ عَبْدِ الرَّحْمَنِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَلَمَّا أُسْرِيَ بِالنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَعَلَ يَمُرُّ بِالنَّبِيِّ وَالنَّبِيَّيْنِ وَمَعَهُمْ الْقَوْمُ وَالنَّبِيِّ وَالنَّبِيَّيْنِ وَمَعَهُمْ الرَّهْطُ وَالنَّبِيِّ وَالنَّبِيَّيْنِ وَلَيْسَ مَعَهُمْ أَحَدٌ حَتَّى مَرَّ بِسَوَادٍ عَظِيمٍ فَقُلْتُ مَنْ هَذَا قِيلَ مُوسَى وَقَوْمُهُ وَلَكَنِ ارْفَعْ رَأْسَكَ فَانْظُرْ قَالَ فَإِذَا سَوَادٌ عَظِيمٌ قَدْ سَدَّ الْأُفُقَ مِنْ ذَا الْجَانِبِ وَمِنْ ذَا الْجَانِبِ فَقِيلَ هَؤُلَاءِ أُمَّتُكَ وَسِوَى هَؤُلَاءِ مِنْ أُمَّتِكَ سَبْعُونَ أَلْفًا يَدْخُلُونَ الْجَنَّةَ بِغَيْرِ حِسَابٍ فَدَخَلَ وَلَمْ يَسْأَلُوهُ وَلَمْ يُفَسِّرْ لَهُمْ فَقَالُوا نَحْنُ هُمْ وَقَالَ قَائِلُونَ هُمْ أَبْنَاؤُنَا الَّذِينَ وُلِدُوا عَلَى الْفِطْرَةِ وَالْإِسْلَامِ فَخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ هُمْ الَّذِينَ لَا يَكْتَوُونَ وَلَا يَسْتَرْقُونَ وَلَا يَتَطَيَّرُونَ وَعَلَى رَبِّهِمْ يَتَوَكَّلُونَ فَقَامَ عُكَّاشَةُ بْنُ مِحْصَنٍ فَقَالَ أَنَا مِنْهُمْ يَا رَسُولَ اللَّهِ قَالَ نَعَمْ ثُمَّ قَامَ آخَرُ فَقَالَ أَنَا مِنْهُمْ فَقَالَ سَبَقَكَ بِهَا عُكَّاشَةُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَفِي الْبَاب عَنْ ابْنِ مَسْعُودٍ وَأَبِي هُرَيْرَةَ","id":"Telah menceritakan kepada kami [Abu Hashin Abdullah bin Ahmad bin Yunus Kufi] telah menceritakan kepada kami ['Abtsar bin Al Qasim] telah menceritakan kepada kami [Hushain bin Abdurrahman] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas] berkata: Saat nabi Shallallahu 'alaihi wa Salam isra`, ia melintasi satu nabi dan beberapa nabi Shallallahu 'alaihi wa Salam bersama kaum mereka, satu nabi dan beberapa nabi Shallallahu 'alaihi wa Salam bersama beberapa orang, satu nabi dan beberapa nabi Shallallahu 'alaihi wa Salam tidak bersama seorang pun hingga beliau melewati sekumpulan besar manusia, aku bertanya: Siapa dia? Dijawab: Musa dan kaumnya, tapi angkatlah kepalamu lau lihatlah. Ternyata sekelompok besar manusia menutupi ufuk dari sisi ini dan sisi ini. dikatakan: Mereka adalah ummatmu dan diantara ummatmu itu ada tujuhpuluh ribu yang masuk surga tanpa hisab. Beliau masuk lalu para sahabat tidak bertanya kepada beliau dan beliau tidak memberi penjelasan pada mereka, lalu mereka bertanya: Kamikah mereka itu? Ada yang menjawab: Mereka adalah anak-anak kami yang meninggal dunia diatas fitrah dan Islam. Lalu nabi Shallallahu 'alaihi wa Salam keluar dan bersabda: \"Mereka adalah orang-orang yang tidak mengecos (berobat dengan sundutan api), tidak meminta diruqyah, tidak berfirasat buruk karena kedatangan hewan dan mereka bertawakal kepada Rabb mereka.\" 'Ukkasyah bin Mihshan berdiri lalu bertanya: Saya termasuk dari mereka wahai Rasulullah? beliau menjawab: \"Ya.\" Yang lain berdiri lalu bertanya: Saya termasuk dari mereka? Beliau menjawab: \"Kau sudah didahului 'Ukkasyah.\" Berkata Abu Isa: Hadits ini hasan shahih dan dalam hal ini ada hadits serupa dari Ibnu Mas'ud dan Abu Hurairah."},"2363":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ بَزِيعٍ حَدَّثَنَا زِيَادُ بْنُ الرَّبِيعِ حَدَّثَنَا أَبُو عِمْرَانَ الْجَوْنِيُّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَمَا أَعْرِفُ شَيْئًا مِمَّا كُنَّا عَلَيْهِ عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ أَيْنَ الصَّلَاةُ قَالَ أَوَلَمْ تَصْنَعُوا فِي صَلَاتِكُمْ مَا قَدْ عَلِمْتُمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ مِنْ حَدِيثِ أَبِي عِمْرَانَ الْجَوْنِيِّ وَقَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ أَنَسٍ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Yazi'] telah menceritakan kepada kami [Ziyad bin Ar Rabi'] telah menceritakan kepada kami [Abu 'Imran Al Jauni] dari [Anas bin Malik] berkata: Aku tidak mengetahui apa pun yang ada pada kami di masa nabi Shallallahu 'alaihi wa Salam. Aku bertanya: Mana shalat? Ia menjawab: Bukankah kalian lakukan dalam shalat kalian yang telah kalian tahu? Berkata Abu Isa: Hadits ini hasan gharib dari jalur sanad ini dari hadits Abu 'Imran AL Juwaini dan diriwayatkan melalui beberapa sanad dari Anas."},"2364":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى الْأَزْدِيُّ الْبَصْرِيُّ حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنَا هَاشِمٌ وَهُوَ ابْنُ سَعِيدٍ الْكُوفِيُّ حَدَّثَنِي زَيْدٌ الْخَثْعَمِيُّ عَنْ أَسْمَاءَ بِنْتِ عُمَيْسٍ الْخَثْعَمِيَّةِ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ بِئْسَ الْعَبْدُ عَبْدٌ تَخَيَّلَ وَاخْتَالَ وَنَسِيَ الْكَبِيرَ الْمُتَعَالِ بِئْسَ الْعَبْدُ عَبْدٌ تَجَبَّرَ وَاعْتَدَى وَنَسِيَ الْجَبَّارَ الْأَعْلَى بِئْسَ الْعَبْدُ عَبْدٌ سَهَا وَلَهَا وَنَسِيَ الْمَقَابِرَ وَالْبِلَى بِئْسَ الْعَبْدُ عَبْدٌ عَتَا وَطَغَى وَنَسِيَ الْمُبْتَدَا وَالْمُنْتَهَى بِئْسَ الْعَبْدُ عَبْدٌ يَخْتِلُ الدُّنْيَا بِالدِّينِ بِئْسَ الْعَبْدُ عَبْدٌ يَخْتِلُ الدِّينَ بِالشُّبُهَاتِ بِئْسَ الْعَبْدُ عَبْدٌ طَمَعٌ يَقُودُهُ بِئْسَ الْعَبْدُ عَبْدٌ هَوًى يُضِلُّهُ بِئْسَ الْعَبْدُ عَبْدٌ رَغَبٌ يُذِلُّهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ وَلَيْسَ إِسْنَادُهُ بِالْقَوِيِّ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya Al Azdi Al Bashri] telah menceritakan kepada kami ['Abdus Shamad bin 'Abdul Warits] telah menceritakan kepada kami [Hasyim bin Sa'id Al Kufi] telah menceritakan kepada kami [Zaid Al Khats'ami] dari [Asma` binti 'Umais Al Khats'amiyah] berkata: Aku mendengar Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Seburuk buruk hamba adalah hamba yang sombong, berbangga diri dan lupa terhadap Dzat yang maha besar dan maha tinggi, seburuk buruk hamba adalah hamba yang diktator dan kejam dan dia lupa terhadap Dzat yang maha perkasa lagi maha tinggi, seburuk buruk hamba adalah hamba yang lupa dan lalai dan lupa akan kuburan dan ujian, seburuk buruk hamba adalah hamba yang melampaui batas dan berlebih lebihan, lupa terhadap adanya permulaan dan kesudahan, seburuk buruk hamba adalah hamba yang mencari dunia dengan mengorbankan agama, seburuk buruk hamba adalah hamba yang mencari agama dengan hal hal yang syubhat, seburuk buruk hamba adalah hamba yang dikendalikan oleh sifat tamak, seburuk buruk hamba adalah hamba yang dikuasai oleh hawa nafsu yang menyesatkannya dan seburuk buruk hamba adalah hamba yang dikuasai sifat rakus yang menjadikannya hina.\" Abu Isa berkata: Hadits ini gharib, kami tidak mengetahuinya kecuali dari jalur sanad ini sedangkan sanadnya tidak kuat.\""},"2365":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ حَاتِمٍ الْمُؤَدِّبُ حَدَّثَنَا عَمَّارُ بْنُ مُحَمَّدٍ ابْنُ أُخْتِ سُفْيَانَ الثَّوْرِيِّ حَدَّثَنَا أَبُو الْجَارُودِ الْأَعْمَى وَاسْمُهُ زِيَادُ بْنُ الْمُنْذِرِ الْهَمْدَانِيُّ عَنْ عَطِيَّةَ الْعَوْفِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّمَا مُؤْمِنٍ أَطْعَمَ مُؤْمِنًا عَلَى جُوعٍ أَطْعَمَهُ اللَّهُ يَوْمَ الْقِيَامَةِ مِنْ ثِمَارِ الْجَنَّةِ وَأَيُّمَا مُؤْمِنٍ سَقَى مُؤْمِنًا عَلَى ظَمَإٍ سَقَاهُ اللَّهُ يَوْمَ الْقِيَامَةِ مِنْ الرَّحِيقِ الْمَخْتُومِ وَأَيُّمَا مُؤْمِنٍ كَسَا مُؤْمِنًا عَلَى عُرْيٍ كَسَاهُ اللَّهُ مِنْ خُضْرِ الْجَنَّةِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ وَقَدْ رُوِيَ هَذَا عَنْ عَطِيَّةَ عَنْ أَبِي سَعِيدٍ مَوْقُوفًا وَهُوَ أَصَحُّ عِنْدَنَا وَأَشْبَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Hatim Al Mu`addib] telah menceritakan kepada kami ['Ammar bin Muhammad bin ukhti Sufyan Ats Tsauri] telah menceritakan kepada kami [Abu Al Jarud Al A'ma, namanya Ziyad bin Al Mundzir Al Hamdani] dari ['Athiyah Al 'Aufi] dari [Abu Sa'id Al Khudri] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Siapapun orang mu`min yang memberi makan mu`min lain saat lapar, Allah akan memberinya makan dari buah surga, siapapun mu`min yang memberi minum mu`min lain saat dahaga, Allah akan memberinya minum pada hari kiamat dengan minuman yang penghabisannya adalah beraroma wangi kesturi, siapapun mu`min yang memberi pakaian mu`min lain saat telanjang, Allah akan memberi pakaian dari sutera surga.\" Berkata Abu Isa: Hadits ini gharib. Hadits ini diriwayatkan dari 'Athiyah dari Abu Sa'id secara mauquf dan menurut kami itu lebih shahih dan lebih mirip."},"2366":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي النَّضْرِ حَدَّثَنَا أَبُو النَّضْرِ حَدَّثَنَا أَبُو عَقِيلٍ الثَّقَفِيُّ حَدَّثَنَا أَبُو فَرْوَةَ يَزِيدُ بْنُ سِنَانٍ التَّمِيمِيُّ حَدَّثَنِي بُكَيْرُ بْنُ فَيْرُوزَ قَال سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ خَافَ أَدْلَجَ وَمَنْ أَدْلَجَ بَلَغَ الْمَنْزِلَ أَلَا إِنَّ سِلْعَةَ اللَّهِ غَالِيَةٌ أَلَا إِنَّ سِلْعَةَ اللَّهِ الْجَنَّةُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ أَبِي النَّضْرِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Nadlar] telah menceritakan kepada kami [Abu An Nadlar] telah menceritakan kepada kami [Abu 'Aqil Ats Tsaqafi] telah menceritakan kepada kami [Abu Farwah Yazid bin Sinan At Tamimi] telah menceritakan kepadaku [Bukair bin Fairuz] berkata: Aku mendengar [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Barangsiapa yang takut maka dia berjalan, dan barangsiapa yang berjalan niscaya dia akan sampai ke tempat tinggal, ketahuilah sesungguhnya barang dagangan Allah itu sangat mahal, ketahuilah sesungguhnya barang dagangan Allah itu adalah surga.\" Abu Isa berkata: Hadits ini hasan gharib, kami tidak mengetahuinya kecuali dari hadits Abu An Nadlar."},"2367":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي النَّضْرِ حَدَّثَنَا أَبُو النَّضْرِ حَدَّثَنَا أَبُو عَقِيلٍ الثَّقَفِيُّ عَبْدُ اللَّهِ بْنُ عَقِيلٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنِي رَبِيعَةُ بْنُ يَزِيدَ وَعَطِيَّةُ بْنُ قَيْسٍ عَنْ عَطِيَّةَ السَّعْدِيِّ وَكَانَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَبْلُغُ الْعَبْدُ أَنْ يَكُونَ مِنْ الْمُتَّقِينَ حَتَّى يَدَعَ مَا لَا بَأْسَ بِهِ حَذَرًا لِمَا بِهِ الْبَأْسُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu An Nadlar] telah menceritakan kepada kami [Abu An Nadlar] telah menceritakan kepada kami [Abu 'Aqil Ats Tsaqafi Abdullah bin 'Aqil] telah menceritakan kepada kami [Abdullah bin Yazid] telah menceritakan kepada kami [Rabi'ah bin Yazid] dan ['Athiyyah bin Qais] dari ['Athiyyah As Sa'di] dia adalah termasuk sahabat Nabi Shallallahu 'alaihi wa Salam dia berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Seorang hamba tidak akan sampai pada derajat orang orang muttaqin sehingga dia meninggalkan sesuatu yang boleh (mubah) karena berhati-hati dari hal-hal yang dilarang.\" Abu Isa berkata: Hadits ini hasan gharib, kami tidak mengetahuinya kecuali dari jalur sanad ini.\""},"2368":{"ar":"حَدَّثَنَا عَبَّاسٌ الْعَنْبَرِيُّ حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا عِمْرَانٌ الْقَطَّانُ عَنْ قَتَادَةَ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ الشِّخِّيرِ عَنْ حَنْظَلَةَ الْأُسَيِّدِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ أَنَّكُمْ تَكُونُونَ كَمَا تَكُونُونَ عِنْدِي لَأَظَلَّتْكُمْ الْمَلَائِكَةُ بِأَجْنِحَتِهَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ مِنْ غَيْرِ هَذَا الْوَجْهِ عَنْ حَنْظَلَةَ الْأُسَيْدِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ","id":"Telah menceritakan kepada kami ['Abbas Al 'Anbari] telah menceritakan kepada kami [Abu Dawud] telah menceritakan kepada kami ['Imran Al Qaththan] dari [Qatadah] dari [Yazid bin Abdullah bin Asy Syakhir] dari [Hanzhalah Al Usaidi] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Andai saja kalian seperti saat berada didekatku niscaya para malaikat akan menaungi kalian dengan sayap-sayapnya.\" Berkata Abu Isa: Hadits ini hasan gharib dari jalur sanad ini. Dan hadits ini diriwayatkan melalui sanad lain dari Hanzhalah Al Usaidi dari nabi Shallallahu 'alaihi wa Salam dan dalam hal ini ada hadits serupa dari Abu Hurairah."},"2369":{"ar":"حَدَّثَنَا يُوسُفُ بْنُ سَلْمَانَ أَبُو عُمَرَ الْبَصْرِيُّ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ عَنْ ابْنِ عَجْلَانَ عَنْ الْقَعْقَاعِ بْنِ حَكِيمٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ لِكُلِّ شَيْءٍ شِرَّةً وَلِكُلِّ شِرَّةٍ فَتْرَةً فَإِنْ كَانَ صَاحِبُهَا سَدَّدَ وَقَارَبَ فَارْجُوهُ وَإِنْ أُشِيرَ إِلَيْهِ بِالْأَصَابِعِ فَلَا تَعُدُّوهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَقَدْ رُوِيَ عَنْ أَنَسِ بْنِ مَالِكٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ بِحَسْبِ امْرِئٍ مِنْ الشَّرِّ أَنْ يُشَارَ إِلَيْهِ بِالْأَصَابِعِ فِي دِينٍ أَوْ دُنْيَا إِلَّا مَنْ عَصَمَهُ اللَّهُ","id":"Telah menceritakan kepada kami [Yusuf bin Salman Abu 'Amir Al Bahsri] telah menceritakan kepada kami [Hatim bin Isma'il] dari [Ibnu 'Ajlan] dari [Al Qa'qa' bin Hakim] dari [Abu Shalih] dari [Abu Hurairah] dari Nabi Shallallahu 'alaihi wa Salam beliau bersabda: \"Sesungguhnya pada setiap sesuatu itu ada saat kesungguhannya dan setiap kesungguhan ada masa melemahnya, jika pelakunya senantiasa bersikap istiqomah dan mendekat, berharaplah dia bisa tetap (semangat), sebaliknya jika ia hanya ingin ditunjuk dengan jari (berbuat karena riya', pent.) maka janganlah orang itu kalian anggap (tidak termasuk orang yang baik, pent.) \". Abu Isa berkata: Hadits ini hasan shahih gharib dari jalur sanad ini, telah diriwayatkan dari Anas bin Malik dari Nabi Shallallahu 'alaihi wa Salam bahwa beliau bersabda: \"Cukuplah keburukan bagi seseorang dengan ditunjuk dengan jari (sekedar mencari perhatian) dalam masalah agama atau dunia kecuali orang yang di jaga oleh Allah.\""},"2370":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَهْرَمُ ابْنُ آدَمَ وَيَشِبُّ مِنْهُ اثْنَانِ الْحِرْصُ عَلَى الْمَالِ وَالْحِرْصُ عَلَى الْعُمُرِهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abu 'Awanah] dari [Qatadah] dari [Anas] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Anak cucu Adam tua sementara ada dua darinya yang muda; ketamakan terhadap harta dan ketamakan terhadap usia.\" Hadits ini hasan shahih."},"2371":{"ar":"حَدَّثَنَا أَبُو هُرَيْرَةَ مُحَمَّدُ بْنُ فِرَاسٍ الْبَصْرِيُّ حَدَّثَنَا أَبُو قُتَيْبَةَ سَلْمُ بْنُ قُتَيْبَةَ حَدَّثَنَا أَبُو الْعَوَّامِ وَهُوَ عِمْرَانُ الْقَطَّانُ عَنْ قَتَادَةَ عَنْ مُطَرِّفِ بْنِ عَبْدِ اللَّهِ بْنِ الشِّخِّيرِ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُثِّلَ ابْنُ آدَمَ وَإِلَى جَنْبِهِ تِسْعَةٌ وَتِسْعُونَ مَنِيَّةً إِنْ أَخْطَأَتْهُ الْمَنَايَا وَقَعَ فِي الْهَرَمِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Abu Hubairah Muhammad bin Firas Al Bashri] telah menceritakan kepada kami [Abu Qutaibah Salm bin Qutaibah] telah menceritakan kepada kami [Abu Al 'Awwam 'Imran Al Qaththan] dari [Qatadah] dari [Muththarrif bin Abdullah bin Asy Syakhir] dari [ayahnya] berkata: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Anak cucu adam dibentuk dan disampingnya ada sembilanpuluh sembilan kematian, bila kematian-kematian luput darinya, pada akhirnya ia jatuh pada masa tua juga.\" Berkata Abu Isa: Hadits ini hasan shahih gharib."},"2372":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا قَبِيصَةُ عَنْ سُفْيَانَ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ الطُّفَيْلِ بْنِ أُبَيِّ بْنِ كَعْبٍ عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا ذَهَبَ ثُلُثَا اللَّيْلِ قَامَ فَقَالَ يَا أَيُّهَا النَّاسُ اذْكُرُوا اللَّهَ اذْكُرُوا اللَّهَ جَاءَتْ الرَّاجِفَةُ تَتْبَعُهَا الرَّادِفَةُ جَاءَ الْمَوْتُ بِمَا فِيهِ جَاءَ الْمَوْتُ بِمَا فِيهِ قَالَ أُبَيٌّ قُلْتُ يَا رَسُولَ اللَّهِ إِنِّي أُكْثِرُ الصَّلَاةَ عَلَيْكَ فَكَمْ أَجْعَلُ لَكَ مِنْ صَلَاتِي فَقَالَ مَا شِئْتَ قَالَ قُلْتُ الرُّبُعَ قَالَ مَا شِئْتَ فَإِنْ زِدْتَ فَهُوَ خَيْرٌ لَكَ قُلْتُ النِّصْفَ قَالَ مَا شِئْتَ فَإِنْ زِدْتَ فَهُوَ خَيْرٌ لَكَ قَالَ قُلْتُ فَالثُّلُثَيْنِ قَالَ مَا شِئْتَ فَإِنْ زِدْتَ فَهُوَ خَيْرٌ لَكَ قُلْتُ أَجْعَلُ لَكَ صَلَاتِي كُلَّهَا قَالَ إِذًا تُكْفَى هَمَّكَ وَيُغْفَرُ لَكَ ذَنْبُكَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Qabishah] dari [Sufyan] dari [Abdullah bin Muhammad bin 'Uqail] dari [Ath Thufail bin Ubai bin Ka'ab] dari [ayahnya] berkata: Bila dua pertiga malam berlalu, Rasulullah Shallallahu 'alahi wa Salam bangun lalu bersabda: \"Wahai sekalian manusia, ingatlah Allah, ingatlah Allah, tiupan pertama datang dan diiringi oleh tiupan kedua, kematian datang dengan yang ada padanya, kematian datang dengan membawa segala kelanjutannya, kematian datang dengan membawa segala kelanjutannya.\" Berkata Ubai: Wahai Rasulullah, aku sering membawa shalawat untuk baginda, lalu seberapa banyak aku bershalawat untuk baginda? Rasulullah Shallallahu 'alaihi wa salam menjawab: \"Terserah.\" Aku bertanya: Seperempat? Rasulullah Shallallahu 'alahi wa Salam menjawab: \"Terserah, jika kau tambahi itu lebih baik bagimu.\" Aku bertanya: Setengah? Beliau menjawab: \"\"Terserah, jika kau tambahi itu lebih baik bagimu.\" Aku bertanya: Dua pertiga?\"Terserah, jika kau tambahi itu lebih baik bagimu.\" Aku berkata: Aku akan menjadikan seluruh doaku untuk baginda. Beliau bersabda: \"Kalau begitu, kau dicukupkan dari dukamu dan dosamu diampuni.\" Berkata Abu Isa: Hadits ini hasan shahih."},"2373":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ وَكِيعٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ أَبِي بَكْرِ بْنِ أَبِي مَرْيَمَ ح و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ أَخْبَرَنَا ابْنُ الْمُبَارَكِ عَنْ أَبِي بَكْرِ بْنِ أَبِي مَرْيَمَ عَنْ ضَمْرَةَ بْنِ حَبِيبٍ عَنْ شَدَّادِ بْنِ أَوْسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْكَيِّسُ مَنْ دَانَ نَفْسَهُ وَعَمِلَ لِمَا بَعْدَ الْمَوْتِ وَالْعَاجِزُ مَنْ أَتْبَعَ نَفْسَهُ هَوَاهَا وَتَمَنَّى عَلَى اللَّهِقَالَ هَذَا حَدِيثٌ حَسَنٌ قَالَ وَمَعْنَى قَوْلِهِ مَنْ دَانَ نَفْسَهُ يَقُولُ حَاسَبَ نَفْسَهُ فِي الدُّنْيَا قَبْلَ أَنْ يُحَاسَبَ يَوْمَ الْقِيَامَةِ وَيُرْوَى عَنْ عُمَرَ بْنِ الْخَطَّابِ قَالَ حَاسِبُوا أَنْفُسَكُمْ قَبْلَ أَنْ تُحَاسَبُوا وَتَزَيَّنُوا لِلْعَرْضِ الْأَكْبَرِ وَإِنَّمَا يَخِفُّ الْحِسَابُ يَوْمَ الْقِيَامَةِ عَلَى مَنْ حَاسَبَ نَفْسَهُ فِي الدُّنْيَا وَيُرْوَى عَنْ مَيْمُونِ بْنِ مِهْرَانَ قَالَ لَا يَكُونُ الْعَبْدُ تَقِيًّا حَتَّى يُحَاسِبَ نَفْسَهُ كَمَا يُحَاسِبُ شَرِيكَهُ مِنْ أَيْنَ مَطْعَمُهُ وَمَلْبَسُهُ","id":"Telah menceritakan kepada kami [Sufyan bin Waqi'] telah menceritakan kepada kami ['Isa bin Yunus] dari [Abu Bakar bin Abu Maryam], dan telah mengkhabarkan kepada kami [Abdullah bin Abdurrahman] telah mengkhabarkan kepada kami ['Amru bin 'Aun] telah mengkhabarkan kepada kami [Ibnu Al Mubarak] dari [Abu Bakar bin Abu Maryam] dari [Dlamrah bin Habib] dari [Syaddad bin Aus] dari Nabi Shallallahu 'alaihi wa Salam beliau bersabda: \"Orang yang cerdas adalah orang yang mempersiapkan dirinya dan beramal untuk hari setelah kematian, sedangkan orang yang bodoh adalah orang jiwanya mengikuti hawa nafsunya dan berangan angan kepada Allah.\" Dia berkata: Hadits ini hasan, dia berkata: Maksud sabda Nabi \"Orang yang mempersiapkan diri\" dia berkata: Yaitu orang yang selalu mengoreksi dirinya pada waktu di dunia sebelum di hisab pada hari Kiamat. Dan telah diriwayatkan dari Umar bin Al Khottob dia berkata: hisablah (hitunglah) diri kalian sebelum kalian dihitung dan persiapkanlah untuk hari semua dihadapkan (kepada Rabb Yang Maha Agung), hisab (perhitungan) akan ringan pada hari kiamat bagi orang yang selalu menghisab dirinya ketika di dunia.\" Dan telah diriwayatkan dari Maimun bin Mihran dia berkata: Seorang hamba tidak akan bertakwa hingga dia menghisab dirinya sebagaimana dia menghisab temannya dari mana dia mendapatkan makan dan pakaiannya.\""},"2374":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَحْمَدَ بْنِ مَدُّوَيْهِ حَدَّثَنَا الْقَاسِمُ بْنُ الْحَكَمِ الْعُرَنِيُّ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ الْوَلِيدِ الْوَصَّافِيُّ عَنْ عَطِيَّةَ عَنْ أَبِي سَعِيدٍ قَالَدَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُصَلَّاهُ فَرَأَى نَاسًا كَأَنَّهُمْ يَكْتَشِرُونَ قَالَ أَمَا إِنَّكُمْ لَوْ أَكْثَرْتُمْ ذِكْرَ هَاذِمِ اللَّذَّاتِ لَشَغَلَكُمْ عَمَّا أَرَى فَأَكْثِرُوا مِنْ ذِكْرِ هَاذِمِ اللَّذَّاتِ الْمَوْتِ فَإِنَّهُ لَمْ يَأْتِ عَلَى الْقَبْرِ يَوْمٌ إِلَّا تَكَلَّمَ فِيهِ فَيَقُولُ أَنَا بَيْتُ الْغُرْبَةِ وَأَنَا بَيْتُ الْوَحْدَةِ وَأَنَا بَيْتُ التُّرَابِ وَأَنَا بَيْتُ الدُّودِ فَإِذَا دُفِنَ الْعَبْدُ الْمُؤْمِنُ قَالَ لَهُ الْقَبْرُ مَرْحَبًا وَأَهْلًا أَمَا إِنْ كُنْتَ لَأَحَبَّ مَنْ يَمْشِي عَلَى ظَهْرِي إِ��َيَّ فَإِذْ وُلِّيتُكَ الْيَوْمَ وَصِرْتَ إِلَيَّ فَسَتَرَى صَنِيعِيَ بِكَ قَالَ فَيَتَّسِعُ لَهُ مَدَّ بَصَرِهِ وَيُفْتَحُ لَهُ بَابٌ إِلَى الْجَنَّةِ وَإِذَا دُفِنَ الْعَبْدُ الْفَاجِرُ أَوْ الْكَافِرُ قَالَ لَهُ الْقَبْرُ لَا مَرْحَبًا وَلَا أَهْلًا أَمَا إِنْ كُنْتَ لَأَبْغَضَ مَنْ يَمْشِي عَلَى ظَهْرِي إِلَيَّ فَإِذْ وُلِّيتُكَ الْيَوْمَ وَصِرْتَ إِلَيَّ فَسَتَرَى صَنِيعِيَ بِكَ قَالَ فَيَلْتَئِمُ عَلَيْهِ حَتَّى يَلْتَقِيَ عَلَيْهِ وَتَخْتَلِفَ أَضْلَاعُهُ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأَصَابِعِهِ فَأَدْخَلَ بَعْضَهَا فِي جَوْفِ بَعْضٍ قَالَ وَيُقَيِّضُ اللَّهُ لَهُ سَبْعِينَ تِنِّينًا لَوْ أَنْ وَاحِدًا مِنْهَا نَفَخَ فِي الْأَرْضِ مَا أَنْبَتَتْ شَيْئًا مَا بَقِيَتْ الدُّنْيَا فَيَنْهَشْنَهُ وَيَخْدِشْنَهُ حَتَّى يُفْضَى بِهِ إِلَى الْحِسَابِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا الْقَبْرُ رَوْضَةٌ مِنْ رِيَاضِ الْجَنَّةِ أَوْ حُفْرَةٌ مِنْ حُفَرِ النَّارِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Ahmad bin Maduwaih] telah menceritakan kepada kami [Al Qasim bin Al Hakam Al 'Urani] telah menceritakan kepada kami ['Ubaidullah bin Al Walid Al Washshafi] dari ['Athiyah] dari [Abu Sa'id] berkata: Rasulullah Shallallahu 'alahi wa Salam memasuki tempat shalat beliau lalu beliau melihat orang-orang, sepertinya mereka tertawa hingga terlihat gigi-giginya, beliau bersabda: \"Ingat, sesungguhnya bila kalian banyak-banyak mengingat pemutus segala kenikmatan niscaya kalian tidak sempat melakukan yang aku lihat, karena itu perbanyaklah mengingat pemutus segala kenikmatan, sesungguhnya tidaklah ada suatu hari melewati makam (pekuburan) melainkan ia berbicara; aku rumah keterasingan, aku rumah kesendirian, aku rumah tanah, aku rumah cacing. Bila seorang hamba mu`min disemayamkan, makam berkata padanya: Selamat datang, engkau adalah orang yang berjalan di atas punggungku yang paling aku sukai, karena saat ini aku diberi kuasa menanganimu dan kau kembali kepadaku, kau akan melihat apa yang akan aku lakukan padamu.\" Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Lalu diluaskan baginya sejauh mata memandang dan dibukakan baginya pintu menuju surga. Dan bila hamba keji atau kafir dikubur, makam berkata padanya: Tidak selamat datang, engkau adalah orang yang melintasi di atas punggungku yang paling aku benci, karena saat ini aku diberi kuasa menanganimu dan kau kembali padaku, kau akan mengetahui apa yang akan aku lakukan padamu.\" Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Lalu kubur menghimpitnya hingga mengenainya sehingga tulang tulangnya tidak karu-karuan (amburadul), \" -Rasul memperagakan dengan memasukkan sebagian jari-jemarinya ke sebagian yang lain-- Berkata Abu Sa'id: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Allah menguasakan untuknya tujuhpuluh ular besar, andai satu diantaranya menghembus di bumi nicaya tidak akan menumbuhkan apa pun selama dunia masih ada, lalu semua mengigit dan melukainya hingga ia sampai ke penghisaban.\" Berkata Abu Sa'id: Rasulullah Shallallahu 'alaihi wa salam bersabda: \"Sesungguhnya kubur adalah salah satu taman surga atau salah satu liang neraka.\" Berkata Abu Isa: Hadits ini gharib, kami hanya mengetahuinya dari sanad ini."},"2375":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ نَصْرٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ مَعْمَرٍ وَيُونُسَ عَنْ الزُّهْرِيِّ أَنَّ عُرْوَةَ بْنَ الزُّبَيْرِ أَخْبَرَهُ أَنَّ الْمِسْوَرَ بْنَ مَخْرَمَةَ أَخْبَرَهُ أَنَّ عَمْرَو بْنَ عَوْفٍ وَهُوَ حَلِيفُ بَنِي عَامِرِ بْنِ لُؤَيٍّ وَكَانَ شَهِدَ بَدْرًا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ أَبَا عُبَيْدَةَ بْنَ الْجَرَّاحِ فَقَدِمَ بِمَالٍ مِنْ الْبَحْرَيْنِ وَسَمِعَتْ الْأَنْصَارُ بِقُدُومِ أَبِي عُبَيْدَةَ فَوَافَوْا صَلَاةَ الْفَجْرِ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْصَرَفَ فَتَعَرَّضُوا لَهُ فَتَبَسَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ رَآهُمْ ثُمَّ قَالَ أَظُنُّكُمْ سَمِعْتُمْ أَنْ أَبَا عُبَيْدَةَ قَدِمَ بِشَيْءٍ قَالُوا أَجَلْ يَا رَسُولَ اللَّهِ قَالَ فَأَبْشِرُوا وَأَمِّلُوا مَا يَسُرُّكُمْ فَوَاللَّهِ مَا الْفَقْرَ أَخْشَى عَلَيْكُمْ وَلَكِنِّي أَخْشَى أَنْ تُبْسَطَ الدُّنْيَا عَلَيْكُمْ كَمَا بُسِطَتْ عَلَى مَنْ قَبْلَكُمْ فَتَنَافَسُوهَا كَمَا تَنَافَسُوهَا فَتُهْلِكَكُمْ كَمَا أَهْلَكَتْهُمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Suwaid bin Nashr] telah mengkhabarkan kepada kami [Abdullah bin Al Mubarak] dari [Ma'mar] dan [Yunus] dari [Az Zuhri] bahwa ['Urwah bin Az Zubair] memberitahunya bahwa [Al Miswar bin Makhramah] memberitahunya bahwa [Amru bin 'Auf], yang ia adalah sekutu Bani 'Amir bin Lu`ai, yang ia turut serta dalam perang Badar bersama Rasulullah Shallallahu 'alahi wa Salam, ia memberitahunya bahwa Rasulullah Shallallahu 'alahi wa Salam mengutus Abu 'Ubaidah bin Al Jarrah lalu ia datang membawa harta dari Bahrain dan kaun Anshar mendengar kedatangan Abu 'Ubaidah lalu mereka shalat fajar bersama Rasulullah Shallallahu 'alahi wa Salam, seusai shalat Rasulullah Shallallahu 'alahi wa Salam bergegas lalu mereka menghadang beliau, Rasulullah Shallallahu 'alahi wa Salam tersenyum saat melihat mereka, setelah itu beliau bersabda: \"Aku kira kalian mendengar bahwa Abu 'Ubaidah datang membawa sesuatu.\" Mereka berkata: Benar, wahai Rasulullah. beliau bersabda: \"Bergembiralah dan berharaplah apa yang menggembirakan kalian, demi Allah bukan kemiskinan yang aku takutkan pada kalian, tapi aku takut dunia dibentangkan untuk kalian seperti halnya dibentangkan pada orang sebelum kalian, lalu kalian memperlombakannya sebagaimana mereka memperlombakannya lalu ia membinasakan kalian seperti halnya mereka.\" Berkata Abu Isa: Hadits ini shahih."},"2376":{"ar":"حَدَّثَنَا سُوَيْدٌ أَخْبَرَنَا عَبْدُ اللَّهِ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ وَابْنِ الْمُسَيَّبِ أَنَّ حَكِيمَ بْنَ حِزَامٍ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَعْطَانِي ثُمَّ سَأَلْتُهُ فَأَعْطَانِي ثُمَّ سَأَلْتُهُ فَأَعْطَانِي ثُمَّ قَالَ يَا حَكِيمُ إِنَّ هَذَا الْمَالَ خَضِرَةٌ حُلْوَةٌ فَمَنْ أَخَذَهُ بِسَخَاوَةِ نَفْسٍ بُورِكَ لَهُ فِيهِ وَمَنْ أَخَذَهُ بِإِشْرَافِ نَفْسٍ لَمْ يُبَارَكْ لَهُ فِيهِ وَكَانَ كَالَّذِي يَأْكُلُ وَلَا يَشْبَعُ وَالْيَدُ الْعُلْيَا خَيْرٌ مِنْ الْيَدِ السُّفْلَى فَقَالَ حَكِيمٌ فَقُلْتُ يَا رَسُولَ اللَّهِ وَالَّذِي بَعَثَكَ بِالْحَقِّ لَا أَرْزَأُ أَحَدًا بَعْدَكَ شَيْئًا حَتَّى أُفَارِقَ الدُّنْيَا فَكَانَ أَبُو بَكْرٍ يَدْعُو حَكِيمًا إِلَى الْعَطَاءِ فَيَأْبَى أَنْ يَقْبَلَهُ ثُمَّ إِنَّ عُمَرَ دَعَاهُ لِيُعْطِيَهُ فَأَبَى أَنْ يَقْبَلَ مِنْهُ شَيْئًا فَقَالَ عُمَرُ إِنِّي أُشْهِدُكُمْ يَا مَعْشَرَ الْمُسْلِمِينَ عَلَى حَكِيمٍ أَنِّي أَعْرِضُ عَلَيْهِ حَقَّهُ مِنْ هَذَا الْفَيْءِ فَيَأْبَ أَنْ يَأْخُذَهُ فَلَمْ يَرْزَأْ حَكِيمٌ أَحَدًا مِنْ النَّاسِ شَيْئًا بَعْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى تُوُفِّيَقَالَ هَذَا حَدِيثٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Suwaid] telah mengkhabarkan kepada kami [Abdullah] dari [Yunus] dari [Az Zuhri] dari ['Urwah] dan [Ibnu Al Musayyib] bahwa [Hakim bin Hizam] berkata: Aku meminta Rasulullah Shallallahu 'alahi wa Salam lalu beliau memberiku, setelah itu aku meminta pada beliau, beliau memberiku, kemudian aku meminta pada beliau, beliau memberiku, setelah itu beliau bersabda: \"Hai Hakim, sesungguhnya harta ini hijau manis, barangsiapa yang mengambilnya dengan kedermawanan jiwa, ia diberkahi, sebaliknya barangsiapa mengambilnya dengan ambisius dan ketamakan jiwa, ia tidak diberkahi dan seperti orang makan namun tidak kenyang, tangan di atas lebih baik dari tangan di bawah.\" Berkata Hakim: Aku berkata: Wahai Rasulullah, demi yang mengutusmu dengan kebenaran, aku tidak akan meminta apa pun kepada siapa pun sepeninggal baginda hingga aku meninggalkan dunia. Abu Bakar memanggil Hakim untuk diberi sesuatu, ia enggan menerimanya, setelah itu Umar memanggilnya untuk diberi sesuatu, ia sama sekali tidak menerimanya lalu Umar berkata: Aku menjadikan kalian wahai kaum muslimin sebagai saksi atas Hakim, sesungguhnya aku telah menawarkan haknya dari harta rampasan perang ini tapi ia enggan mengambilnya. Hakim tidak menerima sesuatu pun dari siapa pun setelah Rasulullah Shallallahu 'alahi wa Salam hingga ia meninggal. Berkata Abu Isa: Hadits ini shahih."},"2377":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا أَبُو صَفْوَانَ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ قَالَابْتُلِينَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالضَّرَّاءِ فَصَبَرْنَا ثُمَّ ابْتُلِينَا بِالسَّرَّاءِ بَعْدَهُ فَلَمْ نَصْبِرْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abu Shofwan] dari [Yunus] dari [Az Zuhri] dari [Humaid bin Abdurrahman] dari [Abdurrahman bin 'Auf] berkata: Ketika bersama Rasulullah kami di uji dengan kesusahan dan kami bersabar, kemudian setelah beliau meninggal kami diuji dengan kesenangan dan kami tidak bersabar.\" Abu Isa berkata: Hadits ini hasan."},"2378":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ خَشْرَمٍ أَخْبَرَنَا عِيسَى بْنُ يُونُسَ عَنْ عِمْرَانَ بْنِ زَائِدَةَ بْنِ نَشِيطٍ عَنْ أَبِيهِ عَنْ أَبِي خَالِدٍ الْوَالِبِيِّ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ تَعَالَى يَقُولُ يَا ابْنَ آدَمَ تَفَرَّغْ لِعِبَادَتِي أَمْلَأْ صَدْرَكَ غِنًى وَأَسُدَّ فَقْرَكَ وَإِلَّا تَفْعَلْ مَلَأْتُ يَدَيْكَ شُغْلًا وَلَمْ أَسُدَّ فَقْرَكَقَالَ هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَأَبُو خَالِدٍ الْوَالِبِيُّ اسْمُهُ هُرْمُزُ","id":"Telah menceritakan kepada kami ['Ali bin Khasyram] telah menceritakan kepada kami ['Isa bin Yunus] dari ['Imran bin Za'idah bin Nasyith] dari [bapaknya] dari [Abu Khalid Al Walibi] dari [Abu Hurairah] dari Nabi Shallallahu 'alaihi wa Salam beliau bersabda: \"Sesungguhnya Allah Ta'ala berfirman: Wahai anak Adam, fokuskanlah untuk beribadah kepadaku niscaya Aku penuhi dadamu dengan rasa cukup dan aku tutupi kefakiranmu, jika kamu tidak mengerjakannya Aku akan penuhi kedua tanganmu dengan kesibukan dan Aku tidak menutupi kefakiranmu.\" Dia berkata: Hadits ini hasan gharib, adapun Abu Kholid Al Walibi namanya adalah Hurmuz."},"2379":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ إِنَّ فِي الْجَنَّةِ لَشَجَرَةً يَسِيرُ الرَّاكِبُ فِي ظِلِّهَا مِائَةَ سَنَةٍوَفِي الْبَاب عَنْ أَنَسٍ وَأَبِي سَعِيدٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari [Sa'id bin Abu Sa'id Al Maqbari] dari [ayahnya] dari [Abu Hurairah] dari Rasulullah Shallallahu 'alaihi wa Salam, beliau bersabda: \"Sesungguhnya di surga ada pohon, seorang pengendara berjalan di dalam naungannya selama seratus tahun.\" Dalam hal ini ada hadits serupa dari Anas dan Abu Sa'id. Berkata Abu Isa: Hadits ini shahih."},"2380":{"ar":"حَدَّثَنَا عَبَّاسٌ الدُّورِيُّ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ شَيْبَانَ عَنْ فِرَاسٍ عَنْ عَطِيَّةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي الْجَنَّةِ شَجَرَةٌ يَسِيرُ الرَّاكِبُ فِي ظِلِّهَا مِائَةَ عَامٍ لَا يَقْطَعُهَا وَقَالَ ذَلِكَ الظِّلُّ الْمَمْدُودُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مَنْ حَدِيثِ أَبِي سَعِيدٍ","id":"Telah menceritakan kepada kami [Abbas Ad Duri] telah bercerita kepada kami [Ubaidullah bin Musa] dari [Syaiban] dari [Firas] dari ['Athiyyah] dari [Abu Sa'id Al Khudri] dari Nabi Shallallahu 'alaihi wa Salam beliau bersabda: \"Di dalam syurga ada pohon (yang panjangnya sejauh) seorang pengendara berjalan di bawah naungannya selama seratus tahun dan tidak bisa menyelesaikannya, \" dan beliau berkata: Itulah maksud naungan yang terbentang luas.\" Abu Isa berkata: Hadits ini hasan gharib dari hadits Abu Sa'id."},"2381":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ الْأَشَجُّ حَدَّثَنَا زِيَادُ بْنُ الْحَسَنِ بْنِ الْفُرَاتِ الْقَزَّازُ عَنْ أَبِيهِ عَنْ جَدِّهِ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا فِي الْجَنَّةِ شَجَرَةٌ إِلَّا وَسَاقُهَا مِنْ ذَهَبٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Abu Sa'id Al Asyaj] telah bercerita kepada kami [Ziyad bin Al Hasan bin Al Furath Al Qazzaz] dari [bapaknya] dari [kakeknya] dari [Abu Hazim] dari [Abu Hurairah] berkata Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Tidak ada pohon di surga kecuali dahannya terbuat dari emas.\" Abu Isa berkata: Hadits ini hasan gharib."},"2382":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ حَمْزَةَ الزَّيَّاتِ عَنْ زِيَادٍ الطَّائِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَقُلْنَا يَا رَسُولَ اللَّهِ مَا لَنَا إِذَا كُنَّا عِنْدَكَ رَقَّتْ قُلُوبُنَا وَزَهِدْنَا فِي الدُّنْيَا وَكُنَّا مِنْ أَهْلِ الْآخِرَةِ فَإِذَا خَرَجْنَا مِنْ عِنْدِكَ فَآنَسْنَا أَهَالِينَا وَشَمَمْنَا أَوْلَادَنَا أَنْكَرْنَا أَنْفُسَنَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ أَنَّكُمْ تَكُونُونَ إِذَا خَرَجْتُمْ مِنْ عِنْدِي كُنْتُمْ عَلَى حَالِكُمْ ذَلِكَ لَزَارَتْكُمْ الْمَلَائِكَةُ فِي بُيُوتِكُمْ وَلَوْ لَمْ تُذْنِبُوا لَجَاءَ اللَّهُ بِخَلْقٍ جَدِيدٍ كَيْ يُذْنِبُوا فَيَغْفِرَ لَهُمْ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ مِمَّ خُلِقَ الْخَلْقُ قَالَ مِنْ الْمَاءِ قُلْنَا الْجَنَّةُ مَا بِنَاؤُهَا قَالَ لَبِنَةٌ مِنْ فِضَّةٍ وَلَبِنَةٌ مِنْ ذَهَبٍ وَمِلَاطُهَا الْمِسْكُ الْأَذْفَرُ وَحَصْبَاؤُهَا اللُّؤْلُؤُ وَالْيَاقُوتُ وَتُرْبَتُهَا الزَّعْفَرَانُ مَنْ دَخَلَهَا يَنْعَمُ لَا يَبْأَسُ وَيَخْلُدُ لَا يَمُوتُ لَا تَبْلَى ثِيَابُهُمْ وَلَا يَفْنَى شَبَابُهُمْ ثُمَّ قَالَ ثَلَاثَةٌ لَا تُرَدُّ دَعْوَتُهُمْ الْإِمَامُ الْعَادِلُ وَالصَّائِمُ حِينَ يُفْطِرُ وَدَعْوَةُ الْمَظْلُومِ يَرْفَعُهَا فَوْقَ الْغَمَامِ وَتُفَتَّحُ لَهَا أَبْوَابُ السَّمَاءِ وَيَقُولُ الرَّبُّ عَزَّ وَجَلَّ وَعِزَّتِي لَأَنْصُرَنَّكِ وَلَوْ بَعْدَ حِينٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ لَيْسَ إِسْنَادُهُ بِذَاكَ الْقَوِيِّ وَلَيْسَ هُوَ عِنْدِي بِمُتَّصِلٍ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ بِإِسْنَادٍ آخَرَ عَنْ أَبِي مُدِلَّةَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Muhammad bin Fudlail] dari [Hamzah Az Zayyat] dari [Ziyad Ath Tho`i] dari [Abu Hurairah] berkata: Kami berkata: Wahai Rasulullah, kenapa kami bila berada di dekat baginda, hati kami melunak, kami zuhud di dunia dan kami termasuk ahli akhirat, tapi bila kami bergegas meninggalkan baginda lalu kami bergaul dengan keluargaku, mencium anak-anak kami, kami mengingkari diri kami sendiri (maksudnya agamis seperti semula). Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Andai kalian bila pergi meninggalkanku berada dalam kondisi kalian seperti itu, niscaya para malaikat mengunjungi kalian di rumah-rumah kalian dan seandainya kalian tidak berbuat dosa, niscaya Allah menciptakan makhluk baru agar mereka berbuat dosa lalu Allah akan mengampuni mereka.\" Berkata Abu Hurairah: Aku berkata: Wahai Rasulullah, dari apa makhluk diciptakan? Rasulullah Shallallahu 'alaihi wa Salam menjawab: \"Dari air.\" Kami bertanya: Surga, apa bangunanya? Beliau menjawab: Bata dari perak dan bata dari emas, semennya minyak kesturi yang harum, tanahnya mutiara dan permata, debunya za'faran, barangsiapa memasukinya, ia bersenang-senang dengan tidak jemu, kekal, tidak mati, baju mereka tidak usang, kemudaan mereka tidak lenyap.\" Setelah itu beliau bersabda: \"Tiga orang yang doanya tidak tertolak; imam adil, orang puasa saat berbuka dan doa orang yang terzhalimi, doanya diangkat diatas awan dan pintu-pintu langit dibukakan, Rabb 'azza wajalla berfirman: Demi keperkasaanKu, aku akan menolongmu meski setelah selang berapa lama.\" Berkata Abu Isa: Hadits ini sanadnya tidak kuat dan menurutku tidak tersambung. Hadits ini diriwayatkan dengan sanad lain dari [Abu Mudillah] dari [Abu Hurairah] dari nabi Shallallahu 'alaihi wa Salam."},"2383":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ إِسْحَقَ عَنْ النُّعْمَانِ بْنِ سَعْدٍ عَنْ عَلِيٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ فِي الْجَنَّةِ لَغُرَفًا يُرَى ظُهُورُهَا مِنْ بُطُونِهَا وَبُطُونُهَا مِنْ ظُهُورِهَا فَقَامَ إِلَيْهِ أَعْرَابِيٌّ فَقَالَ لِمَنْ هِيَ يَا رَسُولَ اللَّهِ قَالَ هِيَ لِمَنْ أَطَابَ الْكَلَامَ وَأَطْعَمَ الطَّعَامَ وَأَدَامَ الصِّيَامَ وَصَلَّى لِلَّهِ بِاللَّيْلِ وَالنَّاسُ نِيَامٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ وَقَدْ تَكَلَّمَ بَعْضُ أَهْلِ الْعِلْمِ فِي عَبْدِ الرَّحْمَنِ بْنِ إِسْحَقَ هَذَا مِنْ قِبَلِ حِفْظِهِ وَهُوَ كُوفِيٌّ وَعَبْدُ الرَّحْمَنِ بْنُ إِسْحَقَ الْقُرَشِيُّ مَدَنِيٌّ وَهُوَ أَثْبَتُ مِنْ هَذَا","id":"Telah menceritakan kepada kami [Ali bin Hujr] telah menceritakan kepada kami [Ali bin Mashir] dari [Abdurrahman bin Ishaq] dari [An Nu'man bin Sa'ad] dari [Ali] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya di surga ada kamar-kamar, luarnya terlihat dari dalam dan dalamnya terlihat dari luar.\" Seorang badui menghampiri beliau, ia bertanya: Itu untuk siapa, wahai Rasulullah? Beliau menjawab: \"Bagi yang membiasakan ucapannya baik, memberi makan, puasa secara kontinyu, shalat malam untuk Allah saat orang-orang tidur.\" Berkata Abu Isa: Hadits ini gharib. Sebagian ahlul ilmi membicarakan Abdurrahman bin Ishaq dari sisi hafalannya, ia orang Kufah, sementara Abdurrahman bin Ishaq Al Qurasy, orang Madinah, lebih kuat hafalannya dari dia."},"2384":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ الصَّمَدِ أَبُو عَبْدِ الصَّمَدِ الْعَمِّيُّ عَنْ أَبِي عِمْرَانَ الْجَوْنِيِّ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ اللَّهِ بْنِ قَيْسٍ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ فِي الْجَنَّةِ جَنَّتَيْنِ آنِيَتُهُمَا وَمَا فِيهِمَا مِنْ فِضَّةٍ وَجَنَّتَيْنِ آنِيَتُهُمَا وَمَا فِيهِمَا مِنْ ذَهَبٍ وَمَا بَيْنَ الْقَوْمِ وَبَيْنَ أَنْ يَنْظُرُوا إِلَى رَبِّهِمْ إِلَّا رِدَاءُ الْكِبْرِيَاءِ عَلَى وَجْهِهِ فِي جَنَّةِ عَدْنٍوَبِهَذَا الْإِسْنَادِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ فِي الْجَنَّةِ لَخَيْمَةً مِنْ دُرَّةٍ مُجَوَّفَةٍ عَرْضُهَا سِتُّونَ مِيلًا فِي كُلِّ زَاوِيَةٍ مِنْهَا أَهْلٌ مَا يَرَوْنَ الْآخَرِينَ يَطُوفُ عَلَيْهِمْ الْمُؤْمِنُ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَأَبُو عِمْرَانَ الْجَوْنِيُّ اسْمُهُ عَبْدُ الْمَلِكِ بْنُ حَبِيبٍ وَأَبُو بَكْرِ بْنُ أَبِي مُوسَى قَالَ أَحْمَدُ بْنُ حَنْبَلٍ لَا يُعْرَفُ اسْمُهُ وَأَبُو مُوسَى الْأَشْعَرِيُّ اسْمُهُ عَبْدُ اللَّهِ بْنُ قَيْسٍ وَأَبُو مَالِكٍ الْأَشْعَرِيُّ اسْمُهُ سَعْدُ بْنُ طَارِقِ بْنِ أَشْيَمَ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Abdul Aziz bin Abdush Shamad Abu Abdush Shamad Al 'Ammi] dari [Abu 'Imran Al Jauni] dari [Abu Bakar bin Abdullah bin Qais] dari [ayahnya] dari nabi Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya di surga ada dua taman, wadah-wadahnya dan segala isinya terbuat dari perak, dua taman lain wadah-wadahnya dan segala isinya terbuat dari emas, tidak ada yang menghalangi kaum untuk melihat Rabb mereka kecuali selendang kesombongan yang ada di wajahNya di surga 'Aden.\" Dengan sanad ini dari nabi Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya di surga ada kemah dari mutiara-luasnya enampuluh mil, disetiap sisinya ada penghuninya, mereka tidak melihat yang lain, mereka dikelilingi orang mu`min.\" Berkata Abu Isa: Hadits ini hasan shahih. Abu 'Imran Al Jauni namanya 'Abdul Malik bin Hubaib dan Abu Bakar bin Abu Musa. Ahmad bin Hambal berkata: Namanya tidak dikenal dan Abu Musa Al Asy'ari namanya Abdullah bin Qais sementara Abu Malik Al Asy'ari namanya Sa'ad bin Thariq bin Asyam."},"2385":{"ar":"حَدَّثَنَا عَبَّاسٌ الْعَنْبَرِيُّ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا شَرِيكٌ عَنْ مُحَمَّدِ بْنِ جُحَادَةَ عَنْ عَطَاءٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْجَنَّةِ مِائَةُ دَرَجَةٍ مَا بَيْنَ كُلِّ دَرَجَتَيْنِ مِائَةُ عَامٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Abbas Al Anbari] telah bercerita kepada kami [Yazid bin Harun] telah bercerita kepada kami [Syarik] dari [Muhammad bin Juhadah] dari ['Atho'] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Di dalam syurga ada seratus tingkatan, jarak di antara satu tingkatan dengan yang lain adalah seratus tahun.\" Abu Isa berkata: Hadits ini hasan gharib."},"2386":{"ar":"حَدَّثَنَا قُتَيْبَةُ وَأَحْمَدُ بْنُ عَبْدَةَ الضَّبِّيُّ الْبَصْرِيُّ قَالَا حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ مُعَاذِ بْنِ جَبَلٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ صَامَ رَمَضَانَ وَصَلَّى الصَّلَوَاتِ وَحَجَّ الْبَيْتَ لَا أَدْرِي أَذَكَرَ الزَّكَاةَ أَمْ لَا إِلَّا كَانَ حَقًّا عَلَى اللَّهِ أَنْ يَغْفِرَ لَهُ إِنْ هَاجَرَ فِي سَبِيلِ اللَّهِ أَوْ مَكَثَ بِأَرْضِهِ الَّتِي وُلِدَ بِهَا قَالَ مُعَاذٌ أَلَا أُخْبِرُ بِهَذَا النَّاسَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَرْ النَّاسَ يَعْمَلُونَ فَإِنَّ فِي الْجَنَّةِ مِائَةَ دَرَجَةٍ مَا بَيْنَ كُلِّ دَرَجَتَيْنِ كَمَا بَيْنَ السَّمَاءِ وَالْأَرْضِ وَالْفِرْدَوْسُ أَعْلَى الْجَنَّةِ وَأَوْسَطُهَا وَفَوْقَ ذَلِكَ عَرْشُ الرَّحْمَنِ وَمِنْهَا تُفَجَّرُ أَنْهَارُ الْجَنَّةِ فَإِذَا سَأَلْتُمُ اللَّهَ فَسَلُوهُ الْفِرْدَوْسَقَالَ أَبُو عِيسَى هَكَذَا رُوِيَ هَذَا الْحَدِيثُ عَنْ هِشَامِ بْنِ سَعْدٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ مُعَاذِ بْنِ جَبَلٍ وَهَذَا عِنْدِي أَصَحُّ مِنْ حَدِيثِ هَمَّامٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ عُبَادَةَ بْنِ الصَّامِتِ وَعَطَاءٌ لَمْ يُدْرِكْ مُعَاذَ بْنَ جَبَلٍ وَمُعَاذٌ قَدِيمُ الْمَوْتِ مَاتَ فِي خِلَافَةِ عُمَرَ","id":"Telah menceritakan kepada kami [Qutaibah] dan [Ahmad bin 'Abdah Adl Dlabyi Al Bashri] keduanya berkata: Telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Zaid bin Aslam] dari ['Atho` bin Yasar] dari [Mu'adz bin Jabal], Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Barangsiapa puasa ramadlon, shalat lima waktu, haji ke baitullah -aku tidak tahu apakah beliau menyebut zakat atau tidak- kecuali laik bagi Allah untuk mengampuninya bila ia berhijrah di jalan Allah atau tinggal di kawasan tempat tinggalnya.\" Berkata Mu'adz: Bolehkah aku memberitahukannya kepada orang-orang? Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Biarkan mereka beramal karena sesungguhnya di surga ada seratus tingkat, masing-masing tingkat jaraknya antara langit dan bumi, dan Firdaus adalah surga tertinggi, tengah-tengahnya dan diatasnya 'arsy Ar Rahman, darinya sungai-sungai surga memancar. Bila kalian meminta pada Allah, mintalah Firdaus.\" Berkata Abu Isa: Seperti itulah hadits ini diriwayatkan dari Hisyam bin Sa'ad dari Zaid bin Aslam dari 'Atho bin Yasar dari Mu'adz bin Jabal dan menurutku ini lebih shahih dari hadits Hammam dari Zaid bin Aslam dari Atho bin Yasar dari Ubadah bin Ash Shamit. 'Atho` tidak bertemu Mu'adz bin Jabal, Mu'adz lebih dahulu meninggal dimasa khilafah Umar."},"2387":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا هَمَّامٌ حَدَّثَنَا زَيْدُ بْ��ُ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ عُبَادَةَ بْنِ الصَّامِتِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي الْجَنَّةِ مِائَةُ دَرَجَةٍ مَا بَيْنَ كُلِّ دَرَجَتَيْنِ كَمَا بَيْنَ الْأَرْضِ وَالسَّمَاءِ وَالْفِرْدَوْسُ أَعْلَاهَا دَرَجَةً وَمِنْهَا تُفَجَّرُ أَنْهَارُ الْجَنَّةِ الْأَرْبَعَةُ وَمِنْ فَوْقِهَا يَكُونُ الْعَرْشُ فَإِذَا سَأَلْتُمُ اللَّهَ فَسَلُوهُ الْفِرْدَوْسَحَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا هَمَّامٌ عَنْ زَيْدِ بْنِ أَسْلَمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Abdullah bin Abdurrahman] telah mengkhabarkan kepada kami [Yazid bin Harun] telah mengkhabarkan kepada kami [Hammam] telah menceritakan kepada kami [Zaid bin Aslam] dari ['Atho` bin Yasar] dari ['Ubadah bin Ash Shamit] Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Di surga ada seratus tingkat, jarak antara masing-masing tingkat seperti antara bumi dan langit dan Firdaus adalah surga tertinggi, darinya empat sungai surga memancar, di atasnya 'arsy, bila kalian meminta kepada Allah, mintalah Firdaus.\" Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Hammam] dari [Zaid bin Aslam] sepertinya."},"2388":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ دَرَّاجٍ عَنْ أَبِي الْهَيْثَمِ عَنْ أَبِي سَعِيدٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ فِي الْجَنَّةِ مِائَةَ دَرَجَةٍ لَوْ أَنَّ الْعَالَمِينَ اجْتَمَعُوا فِي إِحْدَاهُنَّ لَوَسِعَتْهُمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Darraj] dari [Abu Al Haitsam] dari [Abu Sa'id] dari nabi Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya di surga ada seratus tingkat, seandainya seluruh alam berkumpul di salah satunya pasti memuat mereka.\" Berkata Abu Isa: Hadits ini gharib."},"2389":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ حَدَّثَنَا فَرْوَةُ بْنُ أَبِي الْمَغْرَاءِ أَخْبَرَنَا عَبِيدَةُ بْنُ حُمَيْدٍ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ عَمْرِو بْنِ مَيْمُونٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْمَرْأَةَ مِنْ نِسَاءِ أَهْلِ الْجَنَّةِ لَيُرَى بَيَاضُ سَاقِهَا مِنْ وَرَاءِ سَبْعِينَ حُلَّةً حَتَّى يُرَى مُخُّهَا وَذَلِكَ بِأَنَّ اللَّهَ يَقُولُ{ كَأَنَّهُنَّ الْيَاقُوتُ وَالْمَرْجَانُ }فَأَمَّا الْيَاقُوتُ فَإِنَّهُ حَجَرٌ لَوْ أَدْخَلْتَ فِيهِ سِلْكًا ثُمَّ اسْتَصْفَيْتَهُ لَأُرِيتَهُ مِنْ وَرَائِهِحَدَّثَنَا هَنَّادٌ حَدَّثَنَا عَبِيدَةُ بْنُ حُمَيْدٍ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ عَمْرِو بْنِ مَيْمُونٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ عَمْرِو بْنِ مَيْمُونٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ نَحْوَهُ بِمَعْنَاهُ وَلَمْ يَرْفَعْهُ وَهَذَا أَصَحُّ مِنْ حَدِيثِ عَبِيدَةَ بْنِ حُمَيْدٍ وَهَكَذَا رَوَى جَرِيرٌ وَغَيْرُ وَاحِدٍ عَنْ عَطَاءِ بْنِ السَّائِبِ وَلَمْ يَرْفَعُوهُ حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا جَرِيرٌ عَنْ عَطَاءِ بْنِ السَّائِبِ نَحْوَ حَدِيثِ أَبِي الْأَحْوَصِ وَلَمْ يَرْفَعْهُ أَصْحَابُ عَطَاءٍ وَهَذَا أَصَحُّ","id":"Telah menceritakan kepada kami [Abdullah bin Abdurrahman] telah bercerita kepada kami [Farwah bin Abul Maghra'] telah bercerita kepada kami ['Abidah bin Humaid] dari ['Atho' bin As Sa'ib] dari [Amru bin Maimun] dari [Abdullah bin Mas'ud] dari Nabi Shallallahu 'alaihi wa Salam beliau bersabda: \"Sesungguhnya putih betisnya seorang wanita penghuni syurga akan tampak kelihatan dari balik tujuh puluh kalin sampai terlihat tulangnya yang jernih, yang demikian itu karena Allah telah berfirman \"Seakan-akan bidadari itu permata yakut dan marjan.\" (Ar-Rahmaan: 58) adapun permata yaqutnya terbuat dari batu yang jika di masukkan kabel ke dalamnya kemudian kamu bersihkan, niscaya kamu akan dapat melihat dari belakangnya.\" Telah menceritakan kepada kami [Hannad] telah bercerita kepada kami ['Abidah bin Humaid] dari ['Atho` bin As Sa'ib] dari [Amru bin Maimun] dari [Abdullah bin Mas'ud] dari Nabi Shallallahu 'alaihi wa Salam dengan hadits yang semakna. Telah menceritakan kepada kami [Hannad] telah bercerita kepada kami [Abu Al Ahwas] dari [Atho' bin As Sa'ib] dari [Amru bin Maimun] dari [Abdullah bin Mas'ud] dengan hadits yang semakna dengannya namun tidak memarfu'kanya dan ini lebih shahih dari hadits 'Abidah bin Humaid, demikianlah Jarir dan yang lainnya meriwayatkan dari 'Atho` bin As Sa'ib dan mereka tidak memarfu'kannya. Telah menceritakan kepada kami [Qutaibah] telah bercerita kepada kami [Jarir] dari ['Atho` bin As Sa'ib] yang semakna dengan hadits Abul Ahwas namun sahabat 'Atho' tidak memarfu'kannya dan ini yang lebih shahih."},"2390":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ وَكِيعٍ حَدَّثَنَا أَبِي عَنْ فُضَيْلِ بْنِ مَرْزُوقٍ عَنْ عَطِيَّةَ عَنْ أَبِي سَعِيدٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ أَوَّلَ زُمْرَةٍ يَدْخُلُونَ الْجَنَّةَ يَوْمَ الْقِيَامَةِ ضَوْءُ وُجُوهِهِمْ عَلَى مِثْلِ ضَوْءِ الْقَمَرِ لَيْلَةَ الْبَدْرِ وَالزُّمْرَةُ الثَّانِيَةُ عَلَى مِثْلِ أَحْسَنِ كَوْكَبٍ دُرِّيٍّ فِي السَّمَاءِ لِكُلِّ رَجُلٍ مِنْهُمْ زَوْجَتَانِ عَلَى كُلِّ زَوْجَةٍ سَبْعُونَ حُلَّةً يُرَى مُخُّ سَاقِهَا مِنْ وَرَائِهَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Sufyan bin Waki'] telah menceritakan kepada kami [ayahku] dari [Fudlail bin Marzuq] dari ['Athiyah] dari [Abu Sa'id] dari nabi Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya golongan pertama yang masuk surga pada hari kiamat (adalah yang) mukanya bersinar seperti sinar bulan di malam purnama dan golongan kedua seperti bintang bersinar terang terindah dilangit, setiap lelaki di antara mereka mendapatkan dua istri, setiap istri mengenakan tujuhpuluh perhiasan, sungsumnya terlihat dari belakang.\" Berkata Abu Isa: Hadits ini hasan shahih."},"2391":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ مُحَمَّدٍ الدُّورِيُّ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى أَخْبَرَنَا شَيْبَانُ عَنْ فِرَاسٍ عَنْ عَطِيَّةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَوَّلُ زُمْرَةٍ تَدْخُلُ الْجَنَّةَ عَلَى صُورَةِ الْقَمَرِ لَيْلَةَ الْبَدْرِ وَالثَّانِيَةُ عَلَى لَوْنِ أَحْسَنِ كَوْكَبٍ دُرِّيٍّ فِي السَّمَاءِ لِكُلِّ رَجُلٍ مِنْهُمْ زَوْجَتَانِ عَلَى كُلِّ زَوْجَةٍ سَبْعُونَ حُلَّةً يَبْدُو مُخُّ سَاقِهَا مِنْ وَرَائِهَاقَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Al Abbas bin Muhammad Ad Dauri] telah menceritakan kepada kami ['Ubaidullah bin Musa] telah mengkhabarkan kepada kami [Syaiban] dari [Firas] dari ['Athiyah] dari [Abu Sa'id Al Khudri] dari nabi Shallallahu 'alaihi wa Salam bersabda: \"Golongan pertama yang masuk surga mereka bagaikan bulan di malam purnama dan golongan kedua seperti warna bintang bersinar terang terindah dilangit, setiap lelaki di antara mereka mendapatkan dua istri, setiap istri mengenakan tujuhpuluh perhiasan, sungsumnya terlihat dari belakang.\" Berkata Abu Isa: Hadits ini hasan shahih."},"2392":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَمَحْمُودُ بْنُ غَيْلَانَ قَالَا حَدَّثَنَا أَبُو دَاوُدَ الطَّيَالِسِيُّ عَنْ عِمْرَانَ الْقَطَّانِ عَنْ قَتَادَةَ عَنْ أَنَسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُعْطَى الْمُؤْمِنُ فِي الْجَنَّةِ قُوَّةَ كَذَا وَكَذَا مِنْ الْجِمَاعِ قِيلَ يَا رَسُولَ اللَّهِ أَوَ يُطِيقُ ذَلِكَ قَالَ يُعْطَى قُوَّةَ مِائَةٍوَفِي الْبَاب عَنْ زَيْدِ بْنِ أَرْقَمَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ صَحِيحٌ غَرِيبٌ لَا نَعْرِفُهُ مِنْ حَدِيثِ قَتَادَةَ عَنْ أَنَسٍ إِلَّا مِنْ حَدِيثِ عِمْرَانَ الْقَطَّانِ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] dan [Mahmud bin Ghailan] keduanya berkata: telah menceritakan kepada kami [Abu Daud Ath Thayalisi] dari ['Imran Al Qattan] dari [Qatadah] dari [Anas] dari Nabi Shallallahu 'alaihi wa Salam beliau bersabda: \"Orang beriman kelak di syurga diberi kekuatan bersetubuh seperti ini dan seperti ini, \" ada yang bertanya: Wahai Rasulullah apakah mampu seperti itu? beliau menjawab: \"Mereka diberi kekuatan jima' sampai seratus kali lipat.\" Dan dalam bab ini ada hadits dari Zaid bin Arqam, Abu Isa berkata: Hadits ini shahih gharib, kami tidak mengetahuinya dari hadits Qotadah dari Anas kecuali dari hadits Imran Al Qattan."},"2393":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ نَصْرٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ أَخْبَرَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوَّلُ زُمْرَةٍ تَلِجُ الْجَنَّةَ صُورَتُهُمْ عَلَى صُورَةِ الْقَمَرِ لَيْلَةَ الْبَدْرِ لَا يَبْصُقُونَ فِيهَا وَلَا يَمْخُطُونَ وَلَا يَتَغَوَّطُونَ آنِيَتُهُمْ فِيهَا الذَّهَبُ وَأَمْشَاطُهُمْ مِنْ الذَّهَبِ وَالْفِضَّةِ وَمَجَامِرُهُمْ مِنْ الْأُلُوَّةِ وَرَشْحُهُمْ الْمِسْكُ وَلِكُلِّ وَاحِدٍ مِنْهُمْ زَوْجَتَانِ يُرَى مُخُّ سُوقِهِمَا مِنْ وَرَاءِ اللَّحْمِ مِنْ الْحُسْنِ لَا اخْتِلَافَ بَيْنَهُمْ وَلَا تَبَاغُضَ قُلُوبُهُمْ قَلْبُ رَجُلٍ وَاحِدٍ يُسَبِّحُونَ اللَّهَ بُكْرَةً وَعَشِيًّاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ صَحِيحٌ وَالْأُلُوَّةُ هُوَ الْعُودُ","id":"Telah menceritakan kepada kami [Suwaid bin Nashr] telah mengkhabarkan kepada kami [Abdullah bin Al Mubarak] telah mengkhabarkan kepada kami [Ma'mar] dari [Hammam bin Munabbih] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Golongan pertama yang masuk surga pada hari kiamat wujud mereka seperti sinar bulan di malam purnama, mereka tidak meludah didalamnya, tidak beringus dan tidak buang hajat, di surga, wadah-wadah mereka terbuat dari emas, sisir mereka terbuat dari emas dan perak, dupa mereka dari kayu cendana (uluwwah) dan keringat mereka kesturi, masing-masing dari mereka mendapat dua istri, sungsum keduanya terlihat dari balik daging karena indahnya, tidak ada sengketa di antara mereka dan hati mereka tidak saling murka, satu hati, mereka memahasucikan Allah dipagi dan disore hari.\" Berkata Abu Isa: Hadits ini shahih dan uluwwah adalah kayu cendana."},"2394":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ نَصْرٍ أَخْبَرَنَا ابْنُ الْمُبَارَكِ أَخْبَرَنَا ابْنُ لَهِيعَةَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ دَاوُدَ بْنِ عَامِرِ بْنِ سَعْدِ بْنِ أَبِي وَقَّاصٍ عَنْ أَبِيهِ عَنْ جَدِّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَوْ أَنَّ مَا يُقِلُّ ظُفُرٌ مِمَّا فِي الْجَنَّةِ بَدَا لَتَزَخْرَفَتْ لَهُ مَا بَيْنَ خَوَافِقِ السَّمَوَاتِ وَالْأَرْضِ وَلَوْ أَنَّ رَجُلًا مِنْ أَهْلِ الْجَنَّةِ اطَّلَعَ فَبَدَا أَسَاوِرُهُ لَطَمَسَ ضَوْءَ الشَّمْسِ كَمَا تَطْمِسُ الشَّمْسُ ضَوْءَ النُّجُومِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ بِهَذَا الْإِسْنَادِ إِلَّا مِنْ حَدِيثِ ابْنِ لَهِيعَةَ وَقَدْ رَوَى يَحْيَى بْنُ أَيُّوبَ هَذَا الْحَدِيثَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ وَقَالَ عَنْ عُمَرَ بْنِ سَعْدِ بْنِ أَبِي وَقَّاصٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Suwaid bin Nashr] telah mengkhabarkan kepada kami [Ibnu Al Mubarak] telah mengkhabarkan kepada kami [Ibnu Lahi'ah] dari [Yazid bin Abu Habib] dari [Dawud bin 'Amir bin Sa'ad bin Abi Waqqash] dari [ayahnya] dari [kakeknya] dari nabi Shallallahu 'alaihi wa Salam bersabda: \"Andai yang dibawa kuku dalam surga terlihat niscaya antara sisi-sisi langit dan bumi akan terhiasi karenanya, andai seorang penghuni surga muncul lalu gelang-gelangnya terlihat niscaya padamlah matahari seperti matahari melenyapkan cahaya bintang-bintang. Berkata Abu Isa: Hadits ini gharib, kami hanya mengetahui sanad ini dari hadits Ibnu Lahi'ah. [Yahya bin Ayyub] meriwayatkan hadits ini dari [Yazid bin Abu Habib] dan berkata: Dari [Umar bin Sa'ad bin Abi Waqqash] dari nabi Shallallahu 'alaihi wa Salam."},"2395":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَأَبُو هِشَامٍ الرِّفَاعِيُّ قَالَا حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ عَنْ أَبِيهِ عَنْ عَامِرٍ الْأَحْوَلِ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَهْلُ الْجَنَّةِ جُرْدٌ مُرْدٌ كُحْلٌ لَا يَفْنَى شَبَابُهُمْ وَلَا تَبْلَى ثِيَابُهُمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] dan [Abu Hisyam Ar Rifa'i] keduanya berkata: Telah menceritakan kepada kami [Mu'adz bin Hisyam] dari [ayahnya] dari ['Amir Al Ahwal] dari [Syahr bin Hausyab] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Penghuni surga itu tidak berbulu, tidak berjenggot, mengenakan calak mata, kemudaan mereka tidak hilang dan baju mereka tidak pernah usang.\" Berkata Abu Isa: Hadits ini hasan gharib."},"2396":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا رِشْدِينُ بْنُ سَعْدٍ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ دَرَّاجٍ أَبِي السَّمْحِ عَنْ أَبِي الْهَيْثَمِ عَنْ أَبِي سَعِيدٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي قَوْلِهِ{ وَفُرُشٍ مَرْفُوعَةٍ }قَالَ ارْتِفَاعُهَا لَكَمَا بَيْنَ السَّمَاءِ وَالْأَرْضِ مَسِيرَةَ خَمْسِ مِائَةِ سَنَةٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ رِشْدِينَ بْنِ سَعْدٍ و قَالَ بَعْضُ أَهْلِ الْعِلْمِ فِي تَفْسِيرِ هَذَا الْحَدِيثِ إِنَّ مَعْنَاهُ الْفُرُشَ فِي الدَّرَجَاتِ وَبَيْنَ الدَّرَجَاتِ كَمَا بَيْنَ السَّمَاءِ وَالْأَرْضِ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Risydin bin Sa'ad] dari [Amru bin Al Harits] dari [Darraj Abu As Samah] dari [Abu Al Haitsam] dari [Abu Sa'id] dari nabi Shallallahu 'alaihi wa Salam tentang firman Allah: \"Dan hamparan-hamparan (permadani-permadani) yang ditinggikan.\" (QS. Alwaqi'ah 64), Beliau bersabda: \"Tingginya sama seperti antara langit dan bumi, perjalanan limaratus tahun.\" Berkata Abu Isa: Hadits ini gharib, kami hanya mengetahuinya dari hadits Risydin bin Sa'ad. Sebagaian ahlul ilmi berkata tentang penafsiran hadits ini, maknanya tingkatan hamparan-hamparan dan jarak masing-masing tingkatan itu seperti antara langit dan bumi."},"2397":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا يُونُسُ بْنُ بُكَيْرٍ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ يَحْيَى بْنِ عَبَّادِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ أَبِيهِ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ وَذُكِرَ لَهُ سِدْرَةُ الْمُنْتَهَى قَالَ يَسِيرُ الرَّاكِبُ فِي ظِلِّ الْفَنَنِ مِنْهَا مِائَةَ سَنَةٍ أَوْ يَسْتَظِلُّ بِظِلِّهَا مِائَةُ رَاكِبٍ شَكَّ يَحْيَى فِيهَا فِرَاشُ الذَّهَبِ كَأَنَّ ثَمَرَهَا الْقِلَالُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah bercerita kepada kami [Yunus bin Bukair] dari [Muhammad bin Ishaq] dari [Yahya bin 'Abbad bin Abdullah bin Az Zubair] dari [bapaknya] dari [Asma' binti Abu Bakar] berkata: Aku mendengar Rasulullah Shallallahu 'alaihi wa Salam bersabda ketika disebutkan kepadanya Sidrotul Muntaha beliau bersabda: \"Seorang pengendara berjalan di bawah naungan dahan pohonnya selama seratus tahun atau seratus orang pengendara bernaung di bawahnya ---(Yahya ragu) kepastian redaksinya-yang dalam naungan itu sarat dengan anai anai dari emas, buahnya seperti tempayan.\" Abu Isa berkata: Hadits ini hasan shahih gharib."},"2398":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ مُسْلِمٍ عَنْ أَبِيهِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا الْكَوْثَرُ قَالَ ذَاكَ نَهْرٌ أَعْطَانِيهِ اللَّهُ يَعْنِي فِي الْجَنَّةِ أَشَدُّ بَيَاضًا مِنْ اللَّبَنِ وَأَحْلَى مِنْ الْعَسَلِ فِيهَا طَيْرٌ أَعْنَاقُهَا كَأَعْنَاقِ الْجُزُرِ قَالَ عُمَرُ إِنَّ هَذِهِ لَنَاعِمَةٌ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكَلَتُهَا أَحْسَنُ مِنْهَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَمُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ مُسْلِمٍ هُوَ ابْنُ أَخِي ابْنِ شِهَابٍ الزُّهْرِيِّ وَعَبْدُ اللَّهِ بْنُ مُسْلِمٍ قَدْ رَوَى عَنْ ابْنِ عُمَرَ وَأَنَسِ بْنِ مَالِكٍ","id":"Telah menceritakan kepada kami [Abd bin Humaid] telah mengkhabarkan kepada kami [Abdullah bin Maslamah] dari [Muhammad bin Abdullah bin Muslim] dari [bapaknya] dari [Anas bin Malik] berkata: Suatu ketika Rasulullah Shallallahu 'alaihi wa Salam ditanya: Apa artinya KAUTSAR? beliau menjawab: Itu adalah sungai yang Allah berikan kepadaku, yaitu di surga, warnanya lebih putih dari air susu dan rasanya lebih manis dari madu, di dalamnya ada burung yang lehernya seperti leher onta.\" Umar berkata: Sesungguhnya ini adalah benar benar kenikmatan, Rasulullah Shallallahu 'alaihi wa Salam bersabda: Aku telah memakan yang lebih baik darinya.\" Abu Isa berkata: Hadits ini hasan gharib, adapun Muhammad bin Abdullah bin Muslim dia adalah anak saudara Ibnu Syihab Az Zuhri, dan Abdullah bin Muslim meriwayatkan dari Ibnu Umar dan Anas bin Malik."},"2399":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ قَالَ أَخْبَرَنَا عَاصِمُ بْنُ عَلِيٍّ حَدَّثَنَا الْمَسْعُودِيُّ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ سُلَيْمَانَ بْنِ بُرَيْدَةَ عَنْ أَبِيهِأَنَّ رَجُلًا سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ هَلْ فِي الْجَنَّةِ مِنْ خَيْلٍ قَالَ إِنْ اللَّهُ أَدْخَلَكَ الْجَنَّةَ فَلَا تَشَاءُ أَنْ تُحْمَلَ فِيهَا عَلَى فَرَسٍ مِنْ يَاقُوتَةٍ حَمْرَاءَ يَطِيرُ بِكَ فِي الْجَنَّةِ حَيْثُ شِئْتَ قَالَ وَسَأَلَهُ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ هَلْ فِي الْجَنَّةِ مِنْ إِبِلٍ قَالَ فَلَمْ يَقُلْ لَهُ مِثْلَ مَا قَالَ لِصَاحِبِهِ قَالَ إِنْ يُدْخِلْكَ اللَّهُ الْجَنَّةَ يَكُنْ لَكَ فِيهَا مَا اشْتَهَتْ نَفْسُكَ وَلَذَّتْ عَيْنُكَحَدَّثَنَا سُوَيْدُ بْنُ نَصْرٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ سُفْيَانَ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَابِطٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ بِمَعْنَاهُ وَهَذَا أَصَحُّ مِنْ حَدِيثِ الْمَسْعُودِيِّ","id":"Telah menceritakan kepada kami [Abdullah bin Abdurrahman] berkata: Telah mengkhabarkan kepada kami ['Ashim bin Ali] telah menceritakan kepada kami [Al Mas'udi] dari ['Alqamah bin Murtsid] dari [Sulaiman bin Buraidah] dari [ayahnya], seseorang bertanya kepada Rasulullah Shallallahu 'alaihi wa Salam: Wahai Rasulullah, apakah di surga ada kuda? Beliau menjawab: Bila Allah memasukkanmu ke surga, kau akan dibawa di atas kuda dari permata merah di surga yang membawamu terbang di surga semaumu.\" Orang lain bertanya pada beliau: Wahai Rasulullah, apakah di surga ada unta? Beliau tidak menjawab seperti yang dikatakan kepada temannya, beliau bersabda: \"Bila Allah memasukkanmu ke surga, didalamnya ada segala yang diinginkan oleh jiwamu dan dipandang nikmat oleh matamu.\" Telah menceritakan kepada kami [Suwaid bin Nashr] telah mengkhabarkan kepada kami [Abdullah bin Al Mubarak] dari [Sufyan] dari ['Alqamah bin Murtsid] dari [Abdurrahman bin Sabith] dari nabi Shallallahu 'alaihi wa Salam sepertinya dengan maknanya dan ini lebih shahih dari hadits Al Mas'udi."},"2400":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ سَمُرَةَ الْأَحْمَسِيُّ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ وَاصِلٍ هُوَ ابْنُ السَّائِبِ عَنْ أَبِي سَوْرَةَ عَنْ أَبِي أَيُّوبَ قَالَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْرَابِيٌّ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي أُحِبُّ الْخَيْلَ أَفِي الْجَنَّةِ خَيْلٌ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ أُدْخِلْتَ الْجَنَّةَ أُتِيتَ بِفَرَسٍ مِنْ يَاقُوتَةٍ لَهُ جَنَاحَانِ فَحُمِلْتَ عَلَيْهِ ثُمَّ طَارَ بِكَ حَيْثُ شِئْتَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ لَيْسَ إِسْنَادُهُ بِالْقَوِيِّ وَلَا نَعْرِفُهُ مِنْ حَدِيثِ أَبِي أَيُّوبَ إِلَّا مِنْ هَذَا الْوَجْهِ وَأَبُو سَوْرَةَ هُوَ ابْنُ أَخِي أَبِي أَيُّوبَ يُضَعَّفُ فِي الْحَدِيثِ ضَعَّفَهُ يَحْيَى بْنُ مَعِينٍ جِدًّا قَالَ و سَمِعْت مُحَمَّدَ بْنَ إِسْمَعِيلَ يَقُولُ أَبُو سَوْرَةَ هَذَا مُنْكَرُ الْحَدِيثِ يَرْوِي مَنَاكِيرَ عَنْ أَبِي أَيُّوبَ لَا يُتَابَعُ عَلَيْهَا","id":"Telah menceritakan kepada kami [Muhammad bin Isma'il bin Samurah Al Ahmasi] telah bercerita kepada kami [Abu Mu'awiyah] dari [Washil bin As Sa'ib] dari [Abu Saurah] dari [Abu Ayyub] berkata: Seorang badui datang kepada Nabi Shallallahu 'alaihi wa Salam lalu berkata: Wahai Rasulullah sesungguhnya aku menyukai kuda apakah di syurga ada kuda? Rasulullah Shallallahu 'alaihi wa Salam menjawab: Jika kamu di masukkan ke dalam syurga maka kamu akan diberi kuda dari yaqut yang mempunyai dua sayap dan kamu akan dibawa kemudian terbang kemana saja yang kamu sukai.\" Abu Isa berkata: Hadits ini sanadnya tidak sedemikian kuat, kami tidak mengetahuinya dari hadits Abu Ayyub kecuali dari jalur sanad ini, adapun Abu Saurah dia adalah anak saudaranya Abu Ayyub, dia dilemahkan dalam masalah hadits, Yahya bin Ma'in telah melemahkannya sama sekali. Dia berkata: Aku mendengar Muhammad bin Isma'il berkata: Abu Saurah ini haditsnya munkar, dia banyak meriwayatkan hadits hadits munkar dari Abu Ayyub dan tidak ada yang mengikuti riwatatnya."},"2401":{"ar":"حَدَّثَنَا أَبُو هُرَيْرَةَ مُحَمَّدُ بْنُ فِرَاسٍ الْبَصْرِيُّ حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا عِمْرَانُ أَبُو الْعَوَّامِ عَنْ قَتَادَةَ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ غَنْمٍ عَنْ مُعَاذِ بْنِ جَبَلٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَدْخُلُ أَهْلُ الْجَنَّةِ الْجَنَّةَ جُرْدًا مُرْدًا مُكَحَّلِينَ أَبْنَاءَ ثَلَاثِينَ أَوْ ثَلَاثٍ وَثَلَاثِينَ سَنَةًقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَبَعْضُ أَصْحَابِ قَتَادَةَ رَوَوْا هَذَا عَنْ قَتَادَةَ مُرْسَلًا وَلَمْ يُسْنِدُوهُ","id":"Telah menceritakan kepada kami [Abu Hurairah Muhammad bin Firas Al Bashri] telah menceritakan kepada kami [Abu Dawud] telah menceritakan kepada kami ['Imran Abu Al 'Awwam] dari [Qatadah] dari [Syahr bin Hausyab] dari [Abdurrahman bin Ghanm] dari [Mu'adz bin Jabal] nabi Shallallahu 'alaihi wa Salam bersabda: \"Penghuni surga masuk surga dalam keadaan tidak berbulu, tidak berjenggot, mengenakan calak mata, berumur tigapuluh atau tigapuluh tiga tahun.\" Berkata Abu Isa: Hadits ini hasan gharib dan sebagian sahabat Qatadah meriwayatkan hadits ini dari Qatadah secara mursal, mereka tidak menyandarkannya."},"2402":{"ar":"حَدَّثَنَا حُسَيْنُ بْنُ يَزِيدَ الطَّحَّانُ الْكُوفِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ ضِرَارِ بْنِ مُرَّةَ عَنْ مُحَارِبِ بْنِ دِثَارٍ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَهْلُ الْجَنَّةِ عِشْرُونَ وَمِائَةُ صَفٍّ ثَمَانُونَ مِنْهَا مِنْ هَذِهِ الْأُمَّةِ وَأَرْبَعُونَ مِنْ سَائِرِ الْأُمَمِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ سُلَيْمَانَ بْنِ بُرَيْدَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْسَلًا وَمِنْهُمْ مَنْ قَالَ عَنْ سُلَيْمَانَ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ وَحَدِيثُ أَبِي سِنَانٍ عَنْ مُحَارِبِ بْنِ دِثَارٍ حَسَنٌ وَأَبُو سِنَانٍ اسْمُهُ ضِرَارُ بْنُ مُرَّةَ وَأَبُو سِنَانٍ الشَّيْبَانِيُّ اسْمُهُ سَعِيدُ بْنُ سِنَانٍ وَهُوَ بَصْرِيٌّ وَأَبُو سِنَانٍ الشَّامِيُّ اسْمُهُ عِيسَى بْنُ سِنَانٍ هُوَ الْقَسْمَلِيُّ","id":"Telah menceritakan kepada kami [Husain bin Yazid Ath Thahhan Al Kufi] telah menceritakan kepada kami [Muhammad bin Fudlail] dari [Dlirar bin Murrah] dari [Muharib bin Ditsar] dari [Ibnu Buraidah] dari [ayahnya] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Penghuni surga itu sebanyak seratus duapuluh baris, delapan puluh diantaranya dari ummat ini dan empatpuluhnya dari seluruh ummat.\" Berkata Abu Isa: Hadits ini hasan. Hadits ini diriwayatkan dari ['Alqamah bin Murtsid] dari [Sulaiman bin Buraidah] dari nabi Shallallahu 'alaihi wa Salam secara mursal. Diantara mereka ada yang berkata: Dari Sulaiman bin Buraidah dari ayahnya dan hadits Abu Sinan bin Ditsar adalah hadits hasan, namanya Dlirar bin Murrah dan Abu Sinan Asy Syaibani namanya Sa'id bin Sinan, ia orang Bashrah, Abu Sinan Asy Syami namanya 'Isa bin Sinan adalah orang Qasmali."},"2403":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ أَنْبَأَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ قَال سَمِعْتُ عَمْرَو بْنَ مَيْمُونٍ يُحَدِّثُ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي قُبَّةٍ نَحْوًا مِنْ أَرْبَعِينَ فَقَالَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَرْضَوْنَ أَنْ تَكُونُوا رُبُعَ أَهْلِ الْجَنَّةِ قَالُوا نَعَمْ قَالَ أَتَرْضَوْنَ أَنْ تَكُونُوا ثُلُثَ أَهْلِ الْجَنَّةِ قَالُوا نَعَمْ قَالَ أَتَرْضَوْنَ أَنْ تَكُونُوا شَطْرَ أَهْلِ الْجَنَّةِ إِنَّ الْجَنَّةَ لَا يَدْخُلُهَا إِلَّا نَفْسٌ مُسْلِمَةٌ مَا أَنْتُمْ فِي الشِّرْكِ إِلَّا كَالشَّعْرَةِ الْبَيْضَاءِ فِي جِلْدِ الثَّوْرِ الْأَسْوَدِ أَوْ كَالشَّعْرَةِ السَّوْدَاءِ فِي جِلْدِ الثَّوْرِ الْأَحْمَرِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَفِي الْبَاب عَنْ عِمْرَانَ بْنِ حُصَيْنٍ وَأَبِي سَعِيدٍ الْخُدْرِيِّ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Dawud] telah memberitakan kepada kami [Syu'bah] dari [Abu Ishaq] berkata: Aku mendengar [Amru bin Maimun] menceritakan dari [Abdullah bin Mas'ud] berkata: Kami bersama nabi Shallallahu 'alaihi wa Salam di kubah sekitar empat puluh orang lalu Rasulullah Shallallahu 'alaihi wa Salam bertanya kepada kami: \"Maukah kalian menjadi seperempat penghuni surga?\" mereka menjawab: Ya. Beliau bertanya: \"Maukah kalian menjadi sepertiga penghuni surga?\" mereka menjawab: Ya.\"Maukah kalian menjadi separuh penghuni surga, sesungguhnya surga hanya dimasuki oleh jiwa yang muslim, tidaklah kalian dalam kesyirikan kecuali seperti bulu putih di kulit kerbau atau seperti bulu hitam di kulit kerbau merah.\" Berkata Abu Isa: Hadits ini hasan shahih. Dalam hal ini ada hadits serupa dari 'Imran bin Hushain dan Abu Sa'id Al Khudri."},"2404":{"ar":"حَدَّثَنَا الْفَضْلُ بْنُ الصَّبَّاحِ الْبَغْدَادِيُّ حَدَّثَنَا مَعْنُ بْنُ عِيسَى الْقَزَّازُ عَنْ خَالِدِ بْنِ أَبِي بَكْرٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَابُ أُمَّتِي الَّذِي يَدْخُلُونَ مِنْهُ الْجَنَّةَ عَرْضُهُ مَسِيرَةُ الرَّاكِبِ الْمُجَوِّدِ ثَلَاثًا ثُمَّ إِنَّهُمْ لَيُضْغَطُونَ عَلَيْهِ حَتَّى تَكَادُ مَنَاكِبُهُمْ تَزُولُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ قَالَ سَأَلْتُ مُحَمَّدًا عَنْ هَذَا الْحَدِيثِ فَلَمْ يَعْرِفْهُ و قَالَ لِخَالِدِ بْنِ أَبِي بَكْرٍ مَنَاكِيرُ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ","id":"Telah menceritakan kepada kami [Al Fadlal bin Ash Shabbah Al Baghdadi] telah bercerita kepada kami [Ma'an bin 'Isa Al Fazari] dari [Khalid bin Abu Bakar] dari [Salim bin Abdullah] dari [bapaknya] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Pintu masuk masuk surga ummatku luasnya seperti perjalanan seorang penunggang kuda yang cakap selama tiga, kemudian mereka akan berdesak desakan memasukinya sampai hampir hampir punggung mereka hilang.\" Abu Isa berkata: Hadits ini gharib, dia berkata: Aku bertanya kepada Muhammad tentang hadits ini namun dia tidak mengetahuinya dan berkata: Khalid bin Abu Bakar mempunyai hadits-hadits munkar yang dia riwayatkan dari Salim bin Abdullah."},"2405":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ حَبِيبِ بْنِ أَبِي الْعِشْرِينَ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنَا حَسَّانُ بْنُ عَطِيَّةَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ أَنَّهُ لَقِيَ أَبَا هُرَيْرَةَفَقَالَ أَبُو هُرَيْرَةَ أَسْأَلُ اللَّهَ أَنْ يَجْمَعَ بَيْنِي وَبَيْنَكَ فِي سُوقِ الْجَنَّةِ فَقَالَ سَعِيدٌ أَفِيهَا سُوقٌ قَالَ نَعَمْ أَخْبَرَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ أَهْلَ الْجَنَّةِ إِذَا دَخَلُوهَا نَزَلُوا فِيهَا بِفَضْلِ أَعْمَالِهِمْ ثُمَّ يُؤْذَنُ فِي مِقْدَارِ يَوْمِ الْجُمُعَةِ مِنْ أَيَّامِ الدُّنْيَا فَيَزُورُونَ رَبَّهُمْ وَيُبْرِزُ لَهُمْ عَرْشَهُ وَيَتَبَدَّى لَهُمْ فِي رَوْضَةٍ مِنْ رِيَاضِ الْجَنَّةِ فَتُوضَعُ لَهُمْ مَنَابِرُ مِنْ نُورٍ وَمَنَابِرُ مِنْ لُؤْلُؤٍ وَمَنَابِرُ مِنْ يَاقُوتٍ وَمَنَابِرُ مِنْ زَبَرْجَدٍ وَمَنَابِرُ مِنْ ذَهَبٍ وَمَنَابِرُ مِنْ فِضَّةٍ وَيَجْلِسُ أَدْنَاهُمْ وَمَا فِيهِمْ مِنْ دَنِيٍّ عَلَى كُثْبَانِ الْمِسْكِ وَالْكَافُورِ وَمَا يَرَوْنَ أَنَّ أَصْحَابَ الْكَرَاسِيِّ بِأَفْضَلَ مِنْهُمْ مَجْلِسًا قَالَ أَبُو هُرَيْرَةَ قُلْتُ يَا رَسُولَ اللَّهِ وَهَلْ نَرَى رَبَّنَا قَالَ نَعَمْ قَالَ هَلْ تَتَمَارَوْنَ فِي رُؤْيَةِ الشَّمْسِ وَالْقَمَرِ لَيْلَةَ الْبَدْرِ قُلْنَا لَا قَالَ كَذَلِكَ لَا تُمَارَوْنَ فِي رُؤْيَةِ رَبِّكُمْ وَلَا يَبْقَى فِي ذَلِكَ الْمَجْلِسِ رَجُلٌ إِلَّا حَاضَرَهُ اللَّهُ مُحَاضَرَةً حَتَّى يَقُولَ لِلرَّجُلِ مِنْهُمْ يَا فُلَانُ بْنَ فُلَانٍ أَتَذْكُرُ يَوْمَ قُلْتَ كَذَا وَكَذَا فَيُذَكَّرُ بِبَعْضِ غَدْرَاتِهِ فِي الدُّنْيَا فَيَقُولُ يَا رَبِّ أَفَلَمْ تَغْفِرْ لِي فَيَقُولُ بَلَى فَسَعَةُ مَغْفِرَتِي بَلَغَتْ بِكَ مَنْزِلَتَكَ هَذِهِ فَبَيْنَمَا هُمْ عَلَى ذَلِكَ غَشِيَتْهُمْ سَحَابَةٌ مِنْ فَوْقِهِمْ فَأَمْطَرَتْ عَلَيْهِمْ طِيبًا لَمْ يَجِدُوا مِثْلَ رِيحِهِ شَيْئًا قَطُّ وَيَقُولُ رَبُّنَا تَبَارَكَ وَتَعَالَى قُومُوا إِلَى مَا أَعْدَدْتُ لَكُمْ مِنْ الْكَرَامَةِ فَخُذُوا مَا اشْتَهَيْتُمْ فَنَأْتِي سُوقًا قَدْ حَفَّتْ بِهِ الْمَلَائِكَةُ فِيهِ مَا لَمْ تَنْظُرْ الْعُيُونُ إِلَى مِثْلِهِ وَلَمْ تَسْمَعْ الْآذَانُ وَلَمْ يَخْطُرْ عَلَى الْقُلُوبِ فَيُحْمَلُ لَنَا مَا اشْتَهَيْنَا لَيْسَ يُبَاعُ فِيهَا وَلَا يُشْتَرَى وَفِي ذَلِكَ السُّوقِ يَلْقَى أَهْلُ الْجَنَّةِ بَعْضُهُمْ بَعْضًا قَالَ فَيُقْبِلُ الرَّجُلُ ذُو الْمَنْزِلَةِ الْمُرْتَفِعَةِ فَيَلْقَى مَنْ هُوَ دُونَهُ وَمَا فِيهِمْ دَنِيٌّ فَيَرُوعُهُ مَا يَرَى عَلَيْهِ مِنْ اللِّبَاسِ فَمَا يَنْقَضِي آخِرُ حَدِيثِهِ حَتَّى يَتَخَيَّلَ إِلَيْهِ مَا هُوَ أَحْسَنُ مِنْهُ وَذَلِكَ أَنَّهُ لَا يَنْبَغِي لِأَحَدٍ أَنْ يَحْزَنَ فِيهَا ثُمَّ نَنْصَرِفُ إِلَى مَنَازِلِنَا فَيَتَلَقَّانَا أَزْوَاجُنَا فَيَقُلْنَ مَرْحَبًا وَأَهْلًا لَقَدْ جِئْتَ وَإِنَّ بِكَ مِنْ الْجَمَالِ أَفْضَلَ مِمَّا فَارَقْتَنَا عَلَيْهِ فَيَقُولُ إِنَّا جَالَسْنَا الْيَوْمَ رَبَّنَا الْجَبَّارَ وَيَحِقُّنَا أَنْ نَنْقَلِبَ بِمِثْلِ مَا انْقَلَبْنَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ وَقَدْ رَوَى سُوَيْدُ بْنُ عَمْرٍو عَنْ الْأَوْزَاعِيِّ شَيْئًا مِنْ هَذَا الْحَدِيثِ","id":"Telah menceritakan kepada kami [Muhammad bin Isma'il] telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Abdul Hamid bin Habib bin Abu Al 'Isyrin] telah menceritakan kepada kami [Al Auza'i] telah menceritakan kepada kami [Hassan bin 'Athiyah] dari [Sa'id bin Al Musayyib] ia bertemu [Abu Hurairah] lalu Abu Hurairah berkata: Aku meminta kepada Allah semoga menyatukanku denganmu di pasar surga. Sa'id bertanya: Apa disana ada pasar? Abu Hurairah menjawab: Ya, telah menghabarkan kepadaku Rasulullah Shallallahu 'alaihi wa Salam, bahwa penghuni surga bila masuk surga, mereka tinggal di sana karena keutamaan amal-amal mereka, kemudian diizinkan seukuran hari jum'at dari hari-hari dunia lalu mereka mengunjungi Rabb mereka kemudian Rabb menampakkan 'arsyNya pada mereka, salah satu taman surga nampak pada mereka kemudian mimbar-mimbar dari cahaya, mimbar-mimbar dari mutiara, mimbar-mimbar dari yaqut, mimbar-mimbar dari permata, mimbar-mimbar dari emas, mimbar-mimbar dari perak diletakkan untuk mereka, yang paling rendah di antara mereka beserta tingkat kerendahannya duduk di atas gundukan tanah kesturi dan kafur dan mereka beranggapan tempat duduk para pemilik kursi tidak lebih baik dari mereka.\" Abu Hurairah bertanya: Wahai Rasulullah, apakah kita akan melihat Rabb kita? Beliau menjawab: \"Ya.\" Rasulullah Shallallahu 'alaihi wa Salam bertanya: \"Apakah kalian kesulitan saat melihat matahari dan bulan di malam purnama?\" Kami menjawab: Tidak. Beliau bersabda: \"Seperti itu juga kalian tidak kesulitan dalam melihat Rabb kalian. Dan dimajlis itu tidaklah ada seorang pun melainkan Allah mendatanginya dengan sebenarnya hingga Ia bertanya kepada seseorang dari mereka: Hai fulan bin fulan, ingatkah kau saat berkata begini dan begini? Allah mengingatkan sebagian kemaksiatan-kemaksiatannya didunia. Orang itu berkata: Wahai Rabb, apa Kau tidak mengampuniku? Allah menjawab: Ya, luasnya ampunanku sampai pada tempatmu ini. Saat mereka seperti, mega menaungi mereka di atas mereka lalu turun hujan minyak wangi yang baunya sama sekali belum pernah mereka temukan, Rabb kita Tabaaraka wa Ta'ala berfirman: Berdirilah menuju kemuliaan yang telah Aku persiapkan untuk kalian lalu ambillah yang kalian inginkan. Lalu kami mendatangi pasar yang diliputi oleh malaikat, di dalamnya ada yang belum pernah dilihat mata sepertinya, belum pernah terdengar oleh telinga dan tidak terlintas dihati, lalu apa yang kami inginkan dibawakan untuk kami, di sana tidak dijual dan tidak dibeli. Di pasar itu, para penghuni surga saling bertemu satu sama lain.\" Beliau meneruskan: \"Seseorang yang tinggal di flat (derajat tinggi) surga lantas datang lalu bertemu dengan orang yang tingkatnya berada dibawahnya beserta kerendahan yang ada padanya lalu ia kaget terhadap pakaian yang diperlihatkan padanya, akhir kata-katanya belum juga habis hingga ia menghayal yang lebih baik darinya, karenanya tidak layak bagi siapa pun untuk bersedih di surga. Setelah itu kami pulang ke rumah-rumah kami, kami disambut oleh istri-istri kami, mereka berkata: Selamat datang, kau datang dengan keindahan yang lebih baik dari saat kau tinggalkan kami. Ia berkata: Sesungguhnya kami menemani Rabb kami Al Jabbar hari ini, laik bagi kami untuk pulang seperti ini.\" Berkata Abu Isa: Hadits ini hasan gharib, kami hanya mengetahuinya dari jalur sanad ini. [Suwaid bin Amru] meriwayatkan sebagaian hadits ini dari [Al Auza'i]."},"2406":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ وَهَنَّادٌ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِسْحَقَ عَنْ النُّعْمَانِ بْنِ سَعْدٍ عَنْ عَلِيٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ فِي الْجَنَّةِ لَسُوقًا مَا فِيهَا شِرَاءٌ وَلَا بَيْعٌ إِلَّا الصُّوَرَ مِنْ الرِّجَالِ وَالنِّسَاءِ فَإِذَا اشْتَهَى الرَّجُلُ صُورَةً دَخَلَ فِيهَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] dan [Hannad] berkata: telah menceritakan kepada kami [Abu Mu'awiyah] telah menceritakan kepada kami [Abdurrahman bin Ishaq] dari [An Nu'man bin Sa'ad] dari [Ali] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya di surga ada pasar, tidak ada jual belinya kecuali foto kaum lelaki dan perempuan, bila seorang lelaki berselera terhadap foto itu, ia langsung bisa masuk ke menemuinya.\" Berkata Abu Isa: Hadits ini gharib."},"2407":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا وَكِيعٌ عَنْ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنْ جَرِيرِ بْنِ عَبْدِ اللَّهِ الْبَجَلِيِّ قَالَكُنَّا جُلُوسًا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَظَرَ إِلَى الْقَمَرِ لَيْلَةَ الْبَدْرِ فَقَالَ إِنَّكُمْ سَتُعْرَضُونَ عَلَى رَبِّكُمْ فَتَرَوْنَهُ كَمَا تَرَوْنَ هَذَا الْقَمَرَ لَا تُضَامُونَ فِي رُؤْيَتِهِ فَإِنْ اسْتَطَعْتُمْ أَنْ لَا تُغْلَبُوا عَلَى صَلَاةٍ قَبْلَ طُلُوعِ الشَّمْسِ وَصَلَاةٍ قَبْلَ غُرُوبِهَا فَافْعَلُوا ثُمَّ قَرَأَ فَ{ سَبِّحْ بِحَمْدِ رَبِّكَ قَبْلَ طُلُوعِ الشَّمْسِ وَقَبْلَ الْغُرُوبِ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Waki'] dari [Isma'il bin Abu Khalid] dari [Qais bin Abu Hazim] dari [Jarir bin Abdullah Al Bajali] berkata: Kami dudu di dekat nabi Shallallahu 'alaihi wa Salam, beliau melihat rembulan di malam purnama lalu bersabda: \"Sesungguhnya kalian akan di hadapkan kepada Rabb kalian, kalian melihatNya seperti kalian melihat rembulan ini, kalian tidak berdesakan dalam melihatNya, karena itu bila kalian mampu untuk tidak dikalahkan shalat sebelum terbitnya matahari dan shalat sebelum terbenamnya matahari, lakukanlah.\" Setelah itu beliau membaca: \"Maka mahasucikanlah Rabbmu sebelum terbitnya matahari dan sebelum tenggelamnya (matahari).\" (QS. Qaf 39), Abu Isa berkata: Hadits ini hasan shahih. "},"2408":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ صُهَيْبٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي قَوْلِهِ{ لِلَّذِينَ أَحْسَنُوا الْحُسْنَى وَزِيَادَةٌ }قَالَ إِذَا دَخَلَ أَهْلُ الْجَنَّةِ الْجَنَّةَ نَادَى مُنَادٍ إِنَّ لَكُمْ عِنْدَ اللَّهِ مَوْعِدًا قَالُوا أَلَمْ يُبَيِّضْ وُجُوهَنَا وَيُنَجِّنَا مِنْ النَّارِ وَيُدْخِلْنَا الْجَنَّةَ قَالُوا بَلَى قَالَ فَيَنْكَشِفُ الْحِجَابُ قَالَ فَوَاللَّهِ مَا أَعْطَاهُمْ شَيْئًا أَحَبَّ إِلَيْهِمْ مِنْ النَّظَرِ إِلَيْهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ إِنَّمَا أَسْنَدَهُ حَمَّادُ بْنُ سَلَمَةَ وَرَفَعَهُ وَرَوَى سُلَيْمَانُ بْنُ الْمُغِيرَةِ وَحَمَّادُ بْنُ زَيْدٍ هَذَا الْحَدِيثَ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى قَوْلَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit Al Bunani] dari [Abdurrahman bin Abu Laila] dari [Shuhaib] dari nabi Shallallahu 'alaihi wa Salam tentang firmanNya: \"Bagi orang-orang yang berbuat baik, ada pahala yang terbaik (surga) dan tambahannya.\" (Yuunus: 26) beliau bersabda: \"Bila penghuni surga masuk surga, ada yang menyeru: Sesungguhnya kalian memiliki janji disisi Allah. Mereka berkata: Bukankah Ia telah memutihkan wajah-wajah kami, menyelamatkan kami dari neraka dan memasukkan kami ke surga? Mereka menjawab: Benar. Lalu hijab di buka.\" Beliau bersabda: \"Demi Allah, Ia tidak memberi sesuatu pun kepada mereka yang lebih mereka sukai daripada pemberian-Nya agar mereka bisa melihat-Nya.\" Abu Isa berkata: Hadits ini diisnadkan dan dimarfu'kan oleh Hammad bin Salamah. Sulaiman bin Al Mughirah dan Hammad bin Zaid meriwayatkan sabda Rasulullah shallallahu 'alaihi wasallam dalam hadits ini dari Tsabit Al Bannani dari Abdurrahman bin Abu Laila."},"2409":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ أَخْبَرَنِي شَبَابَةُ عَنْ إِسْرَائِيلَ عَنْ ثُوَيْرٍ قَال سَمِعْتُ ابْنَ عُمَرَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَدْنَى أَهْلِ الْجَنَّةِ مَنْزِلَةً لَمَنْ يَنْظُرُ إِلَى جِنَانِهِ وَأَزْوَاجِهِ وَنَعِيمِهِ وَخَدَمِهِ وَسُرُرِهِ مَسِيرَةَ أَلْفِ سَنَةٍ وَأَكْرَمَهُمْ عَلَى اللَّهِ مَنْ يَنْظُرُ إِلَى وَجْهِهِ غَدْوَةً وَعَشِيَّةً ثُمَّ قَرَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ وُجُوهٌ يَوْمَئِذٍ نَاضِرَةٌ إِلَى رَبِّهَا نَاظِرَةٌ }قَالَ أَبُو عِيسَى وَقَدْ رُوِيَ هَذَا الْحَدِيثُ مِنْ غَيْرِ وَجْهٍ عَنْ إِسْرَائِيلَ عَنْ ثُوَيْرٍ عَنْ ابْنِ عُمَرَ مَرْفُوعًا وَرَوَاهُ عَبْدُ الْمَلِكِ بْنُ أَبْجَرَ عَنْ ثُوَيْرٍ عَنْ ابْنِ عُمَرَ مَوْقُوفًا وَرَوَى عُبَيْدُ اللَّهِ الْأَشْجَعِيُّ عَنْ سُفْيَانَ عَنْ ثُوَيْرٍ عَنْ مُجَاهِدٍ عَنْ ابْنِ عُمَرَ قَوْلَهُ وَلَمْ يَرْفَعْهُ حَدَّثَنَا بِذَلِكَ أَبُو كُرَيْبٍ مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا عُبَيْدُ اللَّهِ الْأَشْجَعِيُّ عَنْ سُفْيَانَ عَنْ ثُوَيْرٍ عَنْ مُجَاهِدٍ عَنْ ابْنِ عُمَرَ نَحْوَهُ وَلَمْ يَرْفَعْهُ","id":"Telah menceritakan kepada kami [Abd bin Humaid] telah mengkhabarkan kepadaku [Syababah] dari [Isra`il] dari [Tsuwair] berkata: Aku mendengar [Ibnu Umar] berkata: Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya tingkatan penghuni surga terendah adalah orang yang memandang taman, istri-istri, kenikmatan, pelayan dan tempat tidurnya sejauh perjalanan seribu tahun dan yang paling mulia dari mereka adalah yang melihat wajahnya dipagi dan sore hari.\" Selanjutnya beliau membaca: \"Wajah-wajah (orang-orang mukmin) pada hari itu berseri-seri. Kepada Tuhan-Nyalah mereka Melihat.\" (Al Qiyaamah: 22-23) Abu Isa berkata: Hadits ini diriwayatkan melalui sanad lain dari Isra`il dari Tsuwair dari Ibnu Umar secara marfu' dan diriwayatkan oleh [Abdul Malik bin Abjar] dari [Tsuwair] dari [Ibnu Umar] secara mauquf. Diriwayatkan oleh [Ubaidullah Al Asyja'i] dari [Sufyan] dari [Tsuwair] dari [Mujahid] dari [Ibnu Umar] tapi ia tidak memarfu'kannya. Telah menceritakan kepada kami seperti itu [Abu Kuraib Muhammad bin Al Ala] telah menceritakan kepada kami [Ubaidullah Al Asyja'i] dari [Sufyan] dari [Tsuwair] dari [Mujahid] dari [Ibnu Umar] sepertinya tapi ia tidak memarfu'kannya."},"2410":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ طَرِيفٍ الْكُوفِيُّ حَدَّثَنَا جَابِرُ بْنُ نُوحٍ الْحِمَّانِيُّ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتُضَامُونَ فِي رُؤْيَةِ الْقَمَرِ لَيْلَةَ الْبَدْرِ وَتُضَامُونَ فِي رُؤْيَةِ الشَّمْسِ قَالُوا لَا قَالَ فَإِنَّكُمْ سَتَرَوْنَ رَبَّكُمْ كَمَا تَرَوْنَ الْقَمَرَ لَيْلَةَ الْبَدْرِ لَا تُضَامُونَ فِي رُؤْيَتِهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ وَهَكَذَا رَوَى يَحْيَى بْنُ عِيسَى الرَّمْلِيُّ وَغَيْرُ وَاحِدٍ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَوَى عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي سَعِيدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَحَدِيثُ ابْنِ إِدْرِيسَ عَنْ الْأَعْمَشِ غَيْرُ مَحْفُوظٍ وَحَدِيثُ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَصَحُّ وَهَكَذَا رَوَاهُ سُهَيْلُ بْنُ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ رُوِيَ عَنْ أَبِي سَعِيدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ غَيْرِ هَذَا الْوَجْهِ مِثْلُ هَذَا الْحَدِيثِ وَهُوَ حَدِيثٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Tharif Al Kufi] telah menceritakan kepada kami [Jabir bin Nuh Al Himmanni] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] berkata: Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah kalian kesulitan saat melihat rembulan di malam purnama dan (apakah) kalian kesulitan melihat matahari?\" mereka menjawab: Tidak. beliau bersabda: \"Sesungguhnya kalian akan melihat Rabb kalian seperti kalian melihat rembulan di malam purnama, kalian tidak kesulitan saat melihatNya.\" Abu Isa berkata: Hadits ini hasan shahih gharib. Dan seperti ini [Yahya bin Isa Ar Ramli] dan lainnya meriwayatkan dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dari nabi Shallallahu 'alaihi wa Salam. Dan [Abdullah bin Idris] meriwayatkan dari [A'masy] dari [Abu Shalih] dari [Abu Sa'id] dari nabi Shallallahu 'alaihi wa Salam. Hadits Ibnu Idris dari A'masy tidak terjaga dan hadits Abu Shalih dari Abu Hurairah dari nabi Shallallahu 'alaihi wa Salam lebih shahih. Demikian pula yang diriwayatkan oleh [Suhail bin Abu Shalih] dari [ayahnya] dari [Abu Hurairah] dari nabi Shallallahu 'alaihi wa Salam. Abu Sa'id meriwayatkan dari nabi Shallallahu 'alaihi wa Salam melalui sanad lain seperti hadits ini dan hadits itu shahih."},"2411":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ نَصْرٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ أَخْبَرَنَا مَالِكُ بْنُ أَنَسٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ يَقُولُ لِأَهْلِ الْجَنَّةِ يَا أَهْلَ الْجَنَّةِ فَيَقُولُونَ لَبَّيْكَ رَبَّنَا وَسَعْدَيْكَ فَيَقُولُ هَلْ رَضِيتُمْ فَيَقُولُونَ مَا لَنَا لَا نَرْضَى وَقَدْ أَعْطَيْتَنَا مَا لَمْ تُعْطِ أَحَدًا مِنْ خَلْقِكَ فَيَقُولُ أَنَا أُعْطِيكُمْ أَفْضَلَ مِنْ ذَلِكَ قَالُوا أَيُّ شَيْءٍ أَفْضَلُ مِنْ ذَلِكَ قَالَ أُحِلُّ عَلَيْكُمْ رِضْوَانِي فَلَا أَسْخَطُ عَلَيْكُمْ أَبَدًاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Suwaid bin Nashr] telah mengkhabarkan kepada kami [Abdullah bin Al Mubarak] telah mengkhabarkan kepada kami [Malik bin Anas] dari [Zaid bin Aslam] dari [Atho` bin Yasar] dari [Abu Sa'id Al Khudri] bersabda: Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah berfirman kepada penghuni surga: Wahai penghuni surga! Mereka menjawab: Baik, Rabb kami. Ia bertanya: Apa kalian ridha? Mereka menjawab: Kenapa kami tidak ridha sementara Engkau telah memberi kami sesuatu yang tidak Kau berikan kepada seorang pun dari maklukMu. Ia berfirman: Aku memberi kalian yang lebih baik darinya. Mereka bertanya: Apa yang lebih baik darinya? Ia menjawab: Aku menghalalkan keridhanKu untuk kalian, Aku tidak akan murka kepada kalian selamanya.\" Abu Isa berkata: Hadits ini hasan shahih."},"2412":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ نَصْرٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ أَخْبَرَنَا فُلَيْحُ بْنُ سُلَيْمَانَ عَنْ هِلَالِ بْنِ عَلِيٍّ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ أَهْلَ الْجَنَّةِ لَيَتَرَاءَوْنَ فِي الْغُرْفَةِ كَمَا تَتَرَاءَوْنَ الْكَوْكَبَ الشَّرْقِيَّ أَوْ الْكَوْكَبَ الْغَرْبِيَّ الْغَارِبَ فِي الْأُفُقِ وَالطَّالِعَ فِي تَفَاضُلِ الدَّرَجَاتِ فَقَالُوا يَا رَسُولَ اللَّهِ أُولَئِكَ النَّبِيُّونَ قَالَ بَلَى وَالَّذِي نَفْسِي بِيَدِهِ وَأَقْوَامٌ آمَنُوا بِاللَّهِ وَرَسُولِهِ وَصَدَّقُوا الْمُرْسَلِينَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Suwaid bin Nashr] telah mengkhabarkan kepada kami [Abdullah bin Al Mubarak] telah mengkhabarkan kepada kami [Fulaih bin Sulaiman] dari [Hilal bin Ali] dari [Atho` bin Yasar] dari [Abu Hurairah] dari nabi Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya penghuni surga saling melihat dalam kamar-kamar seperti mereka melihat bintang timur atau bintang barat dan bintang yang tinggi karena berbedaan derajat.\" Mereka bertanya: wahai Rasulullah, apakah mereka itu para nabi? Beliau menjawab: \"Benar, demi Dzat yang jiwaku berada ditanganNya, dan para kaum yang beriman kepada Allah dan membenarkan para rasul.\" Abu Isa berkata: Hadits ini hasan shahih."},"2413":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَجْمَعُ اللَّهُ النَّاسَ يَوْمَ الْقِيَامَةِ فِي صَعِيدٍ وَاحِدٍ ثُمَّ يَطَّلِعُ عَلَيْهِمْ رَبُّ الْعَالَمِينَ فَيَقُولُ أَلَا يَتْبَعُ كُلُّ إِنْسَانٍ مَا كَانُوا يَعْبُدُونَهُ فَيُمَثَّلُ لِصَاحِبِ الصَّلِيبِ صَلِيبُهُ وَلِصَاحِبِ التَّصَاوِيرِ تَصَاوِيرُهُ وَلِصَاحِبِ النَّارِ نَارُهُ فَيَتْبَعُونَ مَا كَانُوا يَعْبُدُونَ وَيَبْقَى الْمُسْلِمُونَ فَيَطَّلِعُ عَلَيْهِمْ رَبُّ الْعَالَمِينَ فَيَقُولُ أَلَا تَتَّبِعُونَ النَّاسَ فَيَقُولُونَ نَعُوذُ بِاللَّهِ مِنْكَ نَعُوذُ بِاللَّهِ مِنْكَ اللَّهُ رَبُّنَا هَذَا مَكَانُنَا حَتَّى نَرَى رَبَّنَا وَهُوَ يَأْمُرُهُمْ وَيُثَبِّتُهُمْ ثُمَّ يَتَوَارَى ثُمَّ يَطَّلِعُ فَيَقُولُ أَلَا تَتَّبِعُونَ النَّاسَ فَيَقُولُونَ نَعُوذُ بِاللَّهِ مِنْكَ نَعُوذُ بِاللَّهِ مِنْكَ اللَّهُ رَبُّنَا وَهَذَا مَكَانُنَا حَتَّى نَرَى رَبَّنَا وَهُوَ يَأْمُرُهُمْ وَيُثَبِّتُهُمْ قَالُوا وَهَلْ نَرَاهُ يَا رَسُولَ اللَّهِ قَالَ وَهَلْ تُضَارُّونَ فِي رُؤْيَةِ الْقَمَرِ لَيْلَةَ الْبَدْرِ قَالُوا لَا يَا رَسُولَ اللَّهِ قَالَ فَإِنَّكُمْ لَا تُضَارُّونَ فِي رُؤْيَتِهِ تِلْكَ السَّاعَةَ ثُمَّ يَتَوَارَى ثُمَّ يَطَّلِعُ فَيُعَرِّفُهُمْ نَفْسَهُ ثُمَّ يَقُولُ أَنَا رَبُّكُمْ فَاتَّبِعُونِي فَيَقُومُ الْمُسْلِمُونَ وَيُوضَعُ الصِّرَاطُ فَيَمُرُّونَ عَلَيْهِ مِثْلَ جِيَادِ الْخَيْلِ وَالرِّكَابِ وَقَوْلُهُمْ عَلَيْهِ سَلِّمْ سَلِّمْ وَيَبْقَى أَهْلُ النَّارِ فَيُطْرَحُ مِنْهُمْ فِيهَا فَوْجٌ ثُمَّ يُقَالُ هَلْ امْتَلَأْتِ فَتَقُولُ هَلْ مِنْ مَزِيدٍ ثُمَّ يُطْرَحُ فِيهَا فَوْجٌ فَيُقَالُ هَلْ امْتَلَأْتِ فَتَقُولُ هَلْ مِنْ مَزِيدٍ حَتَّى إِذَا أُوعِبُوا فِيهَا وَضَعَ الرَّحْمَنُ قَدَمَهُ فِيهَا وَأَزْوَى بَعْضَهَا إِلَى بَعْضٍ ثُمَّ قَالَ قَطْ قَالَتْ قَطْ قَطْ فَإِذَا أَدْخَلَ اللَّهُ أَهْلَ الْجَنَّةِ الْجَنَّةَ وَأَهْلَ النَّارِ النَّارَ قَالَ أُتِيَ بِالْمَوْتِ مُلَبَّبًا فَيُوقَفُ عَلَى السُّورِ بَيْنَ أَهْلِ الْجَنَّةِ وَأَهْلِ النَّارِ ثُمَّ يُقَالُ يَا أَهْلَ الْجَنَّةِ فَيَطَّلِعُونَ خَائِفِينَ ثُمَّ يُقَالُ يَا أَهْلَ النَّارِ فَيَطَّلِعُونَ مُسْتَبْشِرِينَ يَرْجُونَ الشَّفَاعَةَ فَيُقَالُ لِأَهْلِ الْجَنَّةِ وَأَهْلِ النَّارِ هَلْ تَعْرِفُونَ هَذَا فَيَقُولُونَ هَؤُلَاءِ وَهَؤُلَاءِ قَدْ عَرَفْنَاهُ هُوَ الْمَوْتُ الَّذِي وُكِّلَ بِنَا فَيُضْجَعُ فَيُذْبَحُ ذَبْحًا عَلَى السُّورِ الَّذِي بَيْنَ الْجَنَّةِ وَالنَّارِ ثُمَّ يُقَالُ يَا أَهْلَ الْجَنَّةِ خُلُودٌ لَا مَوْتَ وَيَا أَهْلَ النَّارِ خُلُودٌ لَا مَوْتَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رِوَايَاتٌ كَثِيرَةٌ مِثْلُ هَذَا مَا يُذْكَرُ فِيهِ أَمْرُ الرُّؤْيَةِ أَنَّ النَّاسَ يَرَوْنَ رَبَّهُمْ وَذِكْرُ الْقَدَمِ وَمَا أَشْبَهَ هَذِهِ الْأَشْيَاءَ وَالْمَذْهَبُ فِي هَذَا عِنْدَ أَهْلِ الْعِلْمِ مِنْ الْأَئِمَّةِ مِثْلِ سُفْيَانَ الثَّوْرِيِّ وَمَالِكِ بْنِ أَنَسٍ وَابْنِ الْمُبَارَكِ وَابْنِ عُيَيْنَةَ وَوَكِيعٍ وَغَيْرِهِمْ أَنَّهُمْ رَوَوْا هَذِهِ الْأَشْيَاءَ ثُمَّ قَالُوا تُرْوَى هَذِهِ الْأَحَادِيثُ وَنُؤْمِنُ بِهَا وَلَا يُقَالُ كَيْفَ وَهَذَا الَّذِي اخْتَارَهُ أَهْلُ الْحَدِيثِ أَنْ تُرْوَى هَذِهِ الْأَشْيَاءُ كَمَا جَاءَتْ وَيُؤْمَنُ بِهَا وَلَا تُفَسَّرُ وَلَا تُتَوَهَّمُ وَلَا يُقَالُ كَيْفَ وَهَذَا أَمْرُ أَهْلِ الْعِلْمِ الَّذِي اخْتَارُوهُ وَذَهَبُوا إِلَيْهِ وَمَعْنَى قَوْلِهِ فِي الْحَدِيثِ فَيُعَرِّفُهُمْ نَفْسَهُ يَعْنِي يَتَجَلَّى لَهُمْ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Al Ala bin Abdurrahman] dari [ayahnya] dari [Abu Hurairah] Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah mengumpulkan manusia pada hari kiamat di satu tanah lapang kemudian Ia mendatangi mereka, ia berfirman: Ingat, setiap manusia mengikuti apa yang pernah disembahnya. Lalu penyembah salib diperlihatkan penjelmaan salibnya, penyembah patung diperlihatkan penjelmaan patungnya dan penyembah api diperlihatkan penjelmaan apinya lalu mereka mereka mengikuti yang pernah mereka sembah dan kaum muslimin tetap tinggal, setelah itu Rabb semesta alam mendatangi mereka, Ia bertanya: Apa kau tidak mengikuti mereka? Mereka berkata: Kami berlindung diri kepada Allah darimu, kami berlindung diri kepada Allah darimu, Rabb kami ini adalah tempat kami hingga kami melihat Rabb kami. Ia memerintah mereka dan meneguhkan mereka kemudian bersembunyi, setelah itu datang dan bertanya: Apa kau tidak mengikuti mereka? Mereka berkata: Kami berlindung diri pada Allah darimu, kami berlindung diri pada Allah darimu, Rabb kami ini adalah tempat kami hingga kami melihat Rabb kami. Ia memerintah mereka dan meneguhkan mereka.\" Mereka bertanya: Apakah kita melihatNya, wahai Rasulullah? beliau balik bertanya: \"Apakah kalian kesulitan saat melihat rembulan di malam purnama?\" mereka menjawab: Tidak, wahai Rasulullah. beliau bersabda: \"Sesungguhnya kalian tidaklah kesulitan melihatNya saat itu. Setelah itu Dia bersembunyi lalu muncul lalu Dia mengenalkan diriNya kepada mereka, IA berfirman: Aku Rabb kalian, ikutilah aku. Kaum muslimin berdiri, kemudian shirath di letakkan, mereka pun melintasinya seperti kuda-kuda terbaik dan pengendara, kata-kata mereka saat berada di atas shirat: Selamatkan, selamatkan. Setelah itu yang tersisa hanyalah penghuni neraka, di antara mereka ada segolongan besar dilemparkan ke neraka, setelah itu neraka di tanya: Apa kau sudah penuh? Neraka menjawab: Apa ada yang lain? Setelah itu yang tersisa penghuni neraka, di antara mereka ada segolongan besar di lemparkan ke neraka, setelah itu neraka ditanya: Apa kau sudah penuh? Neraka menjawab: Apa ada yang lain? Hingga setelah mereka semua di periksa, Allah Yang Maha Pemurah meletakkan kaki-Nya di neraka dan menghimpitkannya satu sama lain. Ia bertanya: Sudah Cukupkah? Neraka menjawab: Cukup, cukup. Setelah Allah memasukkan penghuni surga ke surga dan penghuni neraka ke neraka, kematian didatangkan dengan diseret kemudian didirikan di atas benteng antara penghuni surga dan penghuni neraka, setelah itu dikatakan kepada penghuni surga: Hai penghuni surga! Mereka melihat dalam keadaan takut. Dan dikatakan kepada penghuni neraka: Wahai penghuni neraka! Mereka melihat dalam keadaan senang, mereka berharap mendapatkan syafaat. Lalu dikatakan kepada penghuni surga dan penghuni neraka: Apa kalian mengetahui ini? mereka menjawab: Kami mengetahuinya, itu adalah kematian yang diserahi untuk (mencabut nyawa) kami. Ia dibaringkan lalu disembelih di atas benteng antara surga dan neraka, setelah itu dikatakan: Wahai penghuni surga, Sekarang tiba saatnya kekekalan, tiada lagi kematian dan wahai penghuni neraka, kalian juga kekal tiada kematian.\" Abu Isa berkata: Hadits ini hasan shahih. Dan banyak sekali riwayat serupa yang diriwayatkan dari nabi Shallallahu 'alaihi wa Salam yang tidak menyebutkan bahwa manusia melihat Rabb mereka, tidak menyebut kedatangkan Rabb dan hal-hal serupa. Madzhab yang benar tentang hal ini menurut ahlul ilmi dari kalangan para imam serperti Sufyan Ats Tsauri, Malik bin Anas, Ibnu Al Mubarak, Ibnu Uyainah, Waki' dan lainnya bahwa mereka (di akhirat) melihat hal-hal tersebut. Mereka berkata: Hadits-hadits ini diriwayatkan dan kami mengimaninya, tidak ditanyakan bagaimananya (tekhnisnya). Inilah madzhab yang dipilih oleh ahli hadits; hal-hal itu akan terlihat seperti yang disebutkan dalam hadits dan seperti yang diimani, tidak ditafsirkan, diduga dan ditanyakan bagaimananya. Inilah pandangan ahlul ilmi yang mereka pilih dan kemukakan. Makna sabda Rasulullah shallallahu 'alaihi wasallam: \"Lalu mengenalkan diriNya pada mereka\" maksudnya menampakkan diri kepada mereka."},"2414":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ وَكِيعٍ حَدَّثَنَا أَبِي عَنْ فُضَيْلِ بْنِ مَرْزُوقٍ عَنْ عَطِيَّةَ عَنْ أَبِي سَعِيدٍيَرْفَعُهُ قَالَ إِذَا كَانَ يَوْمُ الْقِيَامَةِ أُتِيَ بِالْمَوْتِ كَالْكَبْشِ الْأَمْلَحِ فَيُوقَفُ بَيْنَ الْجَنَّةِ وَالنَّارِ فَيُذْبَحُ وَهُمْ يَنْظُرُونَ فَلَوْ أَنَّ أَحَدًا مَاتَ فَرَحًا لَمَاتَ أَهْلُ الْجَنَّةِ وَلَوْ أَنَّ أَحَدًا مَاتَ حُزْنًا لَمَاتَ أَهْلُ النَّارِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Sufyan bin Waki'] telah menceritakan kepada kami [ayahku] dari [Fudlail bin Marzuq] dari [Athiyah] dari [Abu Sa'id] ia memarfu'kannya, ia berkata: Pada hari kiamat, kematian didatangkan seperti domba kelabu lalu didirikan diantara surga dan neraka, setelah itu disembelih dan mereka melihat. Andai ada seseorang meninggal karena senang tentulah para penghuni surga meninggal dan andai ada seseorang meninggal karena sedih, tentulah para penghuni neraka mati. Abu Isa berkata: Hadits ini hasan shahih."},"2415":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ أَخْبَرَنَا عَمْرُو بْنُ عَاصِمٍ أَخْبَرَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ حُمَيْدٍ وَثَابِتٍ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ حُفَّتْ الْجَنَّةُ بِالْمَكَارِهِ وَحُفَّتْ النَّارُ بِالشَّهَوَاتِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ صَحِيحٌ مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Abdullah bin Abdurrahman] telah mengkhabarkan kepada kami [Amru bin Ashim] telah mengkhabarkan kepada kami [Hammad bin Salamah] dari [Humaid] dan [Tsabit] dari [Anas] Rasulullah shallallahu 'alaihi wasallam bersabda: \"Surga diliputi hal-hal yang tidak menyenangkan dan neraka diliputi syahwat.\" Abu Isa berkata: Hadits ini hasan gharib shahih melalui sanad ini."},"2416":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ مُحَمَّدِ بْنِ عَمْرٍو حَدَّثَنَا أَبُو سَلَمَةَ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَمَّا خَلَقَ اللَّهُ الْجَنَّةَ وَالنَّارَ أَرْسَلَ جِبْرِيلَ إِلَى الْجَنَّةِ فَقَالَ انْظُرْ إِلَيْهَا وَإِلَى مَا أَعْدَدْتُ لِأَهْلِهَا فِيهَا قَالَ فَجَاءَهَا وَنَظَرَ إِلَيْهَا وَإِلَى مَا أَعَدَّ اللَّهُ لِأَهْلِهَا فِيهَا قَالَ فَرَجَعَ إِلَيْهِ قَالَ فَوَعِزَّتِكَ لَا يَسْمَعُ بِهَا أَحَدٌ إِلَّا دَخَلَهَا فَأَمَرَ بِهَا فَحُفَّتْ بِالْمَكَارِهِ فَقَالَ ارْجِعْ إِلَيْهَا فَانْظُرْ إِلَى مَا أَعْدَدْتُ لِأَهْلِهَا فِيهَا قَالَ فَرَجَعَ إِلَيْهَا فَإِذَا هِيَ قَدْ حُفَّتْ بِالْمَكَارِهِ فَرَجَعَ إِلَيْهِ فَقَالَ وَعِزَّتِكَ لَقَدْ خِفْتُ أَنْ لَا يَدْخُلَهَا أَحَدٌ قَالَ اذْهَبْ إِلَى النَّارِ فَانْظُرْ إِلَيْهَا وَإِلَى مَا أَعْدَدْتُ لِأَهْلِهَا فِيهَا فَإِذَا هِيَ يَرْكَبُ بَعْضُهَا بَعْضًا فَرَجَعَ إِلَيْهِ فَقَالَ وَعِزَّتِكَ لَا يَسْمَعُ بِهَا أَحَدٌ فَيَدْخُلَهَا فَأَمَرَ بِهَا فَحُفَّتْ بِالشَّهَوَاتِ فَقَالَ ارْجِعْ إِلَيْهَا فَرَجَعَ إِلَيْهَا فَقَالَ وَعِزَّتِكَ لَقَدْ خَشِيتُ أَنْ لَا يَنْجُوَ مِنْهَا أَحَدٌ إِلَّا دَخَلَهَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Abdah bin Sulaiman] dari [Muhammad bin Amru] telah menceritakan kepada kami [Abu Salamah] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam bersabda: \"Saat Allah menciptakan surga dan neraka, Allah mengutus Jibril ke surga. Ia melihatnya dan yang dipersiapkan untuk penghuninya. Setelah itu Jibril mendatangi neraka dan melihatnya serta segala yang dipersiapkan untuk penghuninya. Kemudian Jibril kembali kepada-Nya, ia berkata: Demi keperkasaanMu, tidaklah seseorang mendengarnya (surga) melainkan akan memasukinya. Kemudian Jibril diperintahkan untuk kembali ke surga dan ternyata surga diliputi oleh hal-hal yang tidak menyenangkan. Ia berfirman: Kembalilah ke surga lalu lihatlah apa yang telah Aku persiapkan untuk penghuninya. Jibril kembali ke surga, ternyata surga telah diliputi oleh hal-hal yang tidak menyenangkan. Jibril kembali padaNya, ia berkata: Demi keperkasaanMu, aku khawatir tidak akan ada seorang pun yang memasukinya. Ia berfirman: Pergilah ke neraka dan lihatlah apa yang telah Aku persiapkan untuk penghuninya. Ternyata neraka menumpuk satu sama lain lalu Jibril kembali dan berkata: Demi keperkasaanMu, tidak ada seseorang mendengarnya lalu (kepingin) memasukinya. Lalu Jibril diperintahkan untuk kembali menegok neraka, ternyata neraka diliputi oleh syahwat. Ia berfirman: Kembalilah ke neraka. Jibril kembali ke neraka lalu ia berkata: Demi keperkasaanM, aku khawatir tidak akan ada seorang pun yang selamat darinya melainkan akan memasukinya.\" Abu Isa berkata: Hadits ini hasan shahih."},"2417":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْتَجَّتْ الْجَنَّةُ وَالنَّارُ فَقَالَتْ الْجَنَّةُ يَدْخُلُنِي الضُّعَفَاءُ وَالْمَسَاكِينُ وَقَالَتْ النَّارُ يَدْخُلُنِي الْجَبَّارُونَ وَالْمُتَكَبِّرُونَ فَقَالَ لِلنَّارِ أَنْتِ عَذَابِي أَنْتَقِمُ بِكِ مِمَّنْ شِئْتُ وَقَالَ لِلْجَنَّةِ أَنْتِ رَحْمَتِي أَرْحَمُ بِكِ مَنْ شِئْتُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Abdah bin Sulaiman] dari [Muhammad bin Amru] dari [Abu Salamah] dari [Abu Hurairah] berkata: Rasulullah shallallahu 'alaihi wasallam bersabda: \"Surga dan neraka berbantah-bantahan, surga berkata: Orang-orang lemah dan orang-orang miskin memasukiku. Neraka berkata: Orang-orang congkak dan sombng memasukiku. Lalu Allah berfirman kepada neraka: Kau adalah siksaKu, denganmu Aku menyiksa siapa pun yang Aku kehendaki. Allah berfirman kepada surga: Kau adalah rahmatKu, denganmu Aku merahmati siapa saja yang Aku kehendaki.\" Abu Isa berkata: Hadits ini hasan shahih."},"2418":{"ar":"حَدَّثَنَا سُوَيْدٌ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا رِشْدِينُ بْنُ سَعْدٍ حَدَّثَنِي عَمْرُو بْنُ الْحَارِثِ عَنْ دَرَّاجٍ عَنْ أَبِي الْهَيْثَمِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَدْنَى أَهْلِ الْجَنَّةِ الَّذِي لَهُ ثَمَانُونَ أَلْفَ خَادِمٍ وَاثْنَتَانِ وَسَبْعُونَ زَوْجَةً وَتُنْصَبُ لَهُ قُبَّةٌ مِنْ لُؤْلُؤٍ وَزَبَرْجَدٍ وَيَاقُوتٍ كَمَا بَيْنَ الْجَابِيَةِ إِلَى صَنْعَاءَ","id":"Telah menceritakan kepada kami [Suwaid] telah mengkhabarkan kepada kami [Abdullah] telah mengkhabarkan kepada kami [Risydin bin Sa'ad] telah menceritakan kepadaku [Amru bin Al Harits] dari [Darraj] dari [Abu Al Haitsam] dari [Abu Sa'id Al Khudri] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Penghuni surga terendah memiliki delapanpuluh ribu pelayan, tujuhpuluh dua istri, untuknya didirikan kubah mutiara, permata dan yaqut yang besarnya seperti (jarak) antara Jabiyah ke Shan'a.\""},"2419":{"ar":"وَبِهَذَا الْإِسْنَادِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ مَاتَ مِنْ أَهْلِ الْجَنَّةِ مِنْ صَغِيرٍ أَوْ كَبِيرٍ يُرَدُّونَ أَبْنَاءَ ثَلَاثِينَ فِي الْجَنَّةِ لَا يَزِيدُونَ عَلَيْهَا أَبَدًا وَكَذَلِكَ أَهْلُ النَّارِ وَبِهَذَا الْإِسْنَادِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ عَلَيْهِمْ التِّيجَانَ إِنَّ أَدْنَى لُؤْلُؤَةٍ مِنْهَا لَتُضِيءُ مَا بَيْنَ الْمَشْرِقِ وَالْمَغْرِبِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ رِشْدِينَ","id":"Dan dengan sanad ini (Yaitu; Telah menceritakan kepada kami [Suwaid] telah mengkhabarkan kepada kami [Abdullah] telah mengkhabarkan kepada kami [Risydin bin Sa'ad] telah menceritakan kepadaku [Amru bin Al Harits] dari [Darraj] dari [Abu Al Haitsam] dari [Abu Sa'id Al Khudri]) dari nabi Shallallahu 'alaihi wa Salam, beliau bersabda: \"Barangsiapa diantara calon penghuni surga yang meninggal dunia, baik yang masih kecil atau sudah besar akan dikembalikan dalam usia tigapuluh tahun di surga, mereka tidak melebihinya selamanya. Demikian juga penghuni neraka.\" Dan dengan sanad ini dari nabi Shallallahu 'alaihi wa Salam, beliau bersabda: \"Sesungguhnya mereka mengenakan mutiara, sesungguhnya mutiara terendahnya menerangi antara timur dan barat.\" Abu Isa berkata: Hadits ini gharib, kami hanya mengetahuinya dari hadits Risydin."},"2420":{"ar":"حَدَّثَنَا بُنْدَارٌ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنَا أَبِي عَنْ عَامِرٍ الْأَحْوَلِ عَنْ أَبِي الصِّدِّيقِ النَّاجِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُؤْمِنُ إِذَا اشْتَهَى الْوَلَدَ فِي الْجَنَّةِ كَانَ حَمْلُهُ وَوَضْعُهُ وَسِنُّهُ فِي سَاعَةٍ كَمَا يَشْتَهِيقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَقَدْ اخْتَلَفَ أَهْلُ الْعِلْمِ فِي هَذَا فَقَالَ بَعْضُهُمْ فِي الْجَنَّةِ جِمَاعٌ وَلَا يَكُونُ وَلَدٌ هَكَذَا رُوِيَ عَنْ طَاوُسٍ وَمُجَاهِدٍ وَإِبْرَاهِيمَ النَّخَعِيِّ و قَالَ مُحَمَّدٌ قَالَ إِسْحَقُ بْنُ إِبْرَاهِيمَ فِي حَدِيثِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اشْتَهَى الْمُؤْمِنُ الْوَلَدَ فِي الْجَنَّةِ كَانَ فِي سَاعَةٍ وَاحِدَةٍ كَمَا يَشْتَهِي وَلَكِنْ لَا يَشْتَهِي قَالَ مُحَمَّدٌ وَقَدْ رُوِيَ عَنْ أَبِي رَزِينٍ الْعُقَيْلِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ أَهْلَ الْجَنَّةِ لَا يَكُونُ لَهُمْ فِيهَا وَلَدٌ وَأَبُو الصِّدِّيقِ النَّاجِيِّ اسْمُهُ بَكْرُ بْنُ عَمْرٍو وَيُقَالُ بَكْرُ بْنُ قَيْسٍ أَيْضًا","id":"Telah menceritakan kepada kami [Bundar] telah bercerita kepada kami [Mu'adz bin Hisyam] telah bercerita kepada kami [bapakku] dari [Amir Al Ahwal] dari [Abu Ash Shiddiq An Naji] dari [Abu Sa'id Al Khudri] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Apabila seorang mukmin menginginkan anak di surga, maka kehamilannya, kelahirannya dan umur bayinya (terjadi) sesuai yang dia inginkan\". Abu Isa berkata: Hadits ini hasan gharib, para ahli ilmu berbeda pendapat dalam masalah ini, sebagian mereka mengatakan bahwa kelak di surga ada jima' (bersetubuh) namun tidak melahirkan anak. Demikianlah yang diriwayatkan dari Thawus, Mujahid dan Ibrahim An Nakha'I. Muhammad berkata: Ishaq bin Ibrahim berkata dalam hadits Nabi Shallallahu 'alaihi wa Salam: \"Apabila seorang mukmin menginginkan anak di syurga, maka akan dapat dalam sesaat sebagaimana yang dia inginkan, akan tetapi dia tidak menghendakinya.\" Muhammad berkata: Telah diriwayatkan dari Abu Razin Al Uqaili dari Nabi Shallallahu 'alaihi wa Salam, bersabda: \"Sesungguhnya penghuni surga tidak mempunyai anak di dalam surga.\" Abu Ash Shiddiq An Naji namanya adalah Bakar bin Amru, yang lain menyebut Bakar bin Qais."},"2421":{"ar":"حَدَّثَنَا هَنَّادٌ وَأَحْمَدُ بْنُ مَنِيعٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِسْحَقَ عَنْ النُّعْمَانِ بْنِ سَعْدٍ عَنْ عَلِيٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ فِي الْجَنَّةِ لَمُجْتَمَعًا لِلْحُورِ الْعِينِ يُرَفِّعْنَ بِأَصْوَاتٍ لَمْ يَسْمَعْ الْخَلَائِقُ مِثْلَهَا قَالَ يَقُلْنَ نَحْنُ الْخَالِدَاتُ فَلَا نَبِيدُ وَنَحْنُ النَّاعِمَاتُ فَلَا نَبْؤُسُ وَنَحْنُ الرَّاضِيَاتُ فَلَا نَسْخَطُ طُوبَى لِمَنْ كَانَ لَنَا وَكُنَّا لَهُوَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَأَبِي سَعِيدٍ وَأَنَسٍ قَالَ أَبُو عِيسَى حَدِيثِ عَلِيٍّ حَدِيثٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Hannad] dan [Ahmad bin Mani'] keduanya berkata: telah menceritakan kepada kami [Abu Muawiyah] berkata: telah menceritakan kepada kami [Abdurrahman bin Ishaq] dari [An Nu'man bin Sa'id] dari [Ali] berkata: Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnnya di surga ada perkumpulan para bidadari, mereka memanggil-manggil dengan suara keras, para makhluk belum pernah mendengar sepertinya. Mereka berkata: Kami wanita-wanita kekal, kami tidak lenyap, kami adalah wanita-wanita menyenangkan, kami tidak cemberut, kami wanita-wanita ridha, kami tidak marah. Beruntunglah siapa yang menjadi milik kami dan kami menjadi miliknya.\" Dalam hal ini ada hadits serupa dari Abu Hurairah, Abu Sa'id dan Anas. Abu Isa berkata: Hadits Ali gharib."},"2422":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ عَنْ الْأَوْزَاعِيِّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍفِي قَوْلِهِ عَزَّ وَجَلَّ{ فَهُمْ فِي رَوْضَةٍ يُحْبَرُونَ }قَالَ السَّمَّاعُوَمَعْنَى السَّمَّاعِ مِثْلَ مَا وَرَدَ فِي الْحَدِيثِ أَنَّ الْحُورَ الْعِينَ يُرَفِّعْنَ بِأَصْوَاتِهِنَّ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Rauh bin Ubadah] dari [Al Auza'] dari [Yahya bin Abu Katsir] tentang firman Allah 'azza wajalla: \"Mereka di dalam taman (surga) bergembira.\" (Ar Ruum: 15) beliau bersabda: \"Samma'\" makna samma' seperti yang disebutkan dalam hadits; para bidadari mengeraskan suara-suara mereka."},"2423":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ أَبِي الْيَقْظَانِ عَنْ زَاذَانَ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَةٌ عَلَى كُثْبَانِ الْمِسْكِ أُرَهُ قَالَ يَوْمَ الْقِيَامَةِ يَغْبِطُهُمْ الْأَوَّلُونَ وَالْآخِرُونَ رَجُلٌ يُنَادِي بِالصَّلَوَاتِ الْخَمْسِ فِي كُلِّ يَوْمٍ وَلَيْلَةٍ وَرَجُلٌ يَؤُمُّ قَوْمًا وَهُمْ بِهِ رَاضُونَ وَعَبْدٌ أَدَّى حَقَّ اللَّهِ وَحَقَّ مَوَالِيهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ سُفْيَانَ الثَّوْرِيِّ وَأَبُو الْيَقْظَانِ اسْمُهُ عُثْمَانُ بْنُ عُمَيْرٍ وَيُقَالُ ابْنُ قَيْسٍ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Abu Al Yaqadlan] dari [Zadzan] dari [Abdullah bin Umar] berkata: Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tiga orang berada di bukit pasir minyak kesturi -aku (Abdullah bin Umar) melihat beliau bersabda- pada hari kiamat, orang-orang pertama dan terakhir iri kepada mereka; orang yang menyeru shalat lima waktu setiap hari dan malam, orang memimpin suatu kaum dan mereka ridha kepadanya, dan hamba yang menunaikan hak Allah dan hak para majikannya.\" Abu Isa berkata: Hadits ini hasan gharib, kami hanya mengetahuinya dari hadits Sufyan Ats Tsauri. Abu Yaqadlan namanya Utsman bin Umair, ada yang menyebut Ibnu Qais."},"2424":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا يَحْيَى بْنُ آدَمَ عَنْ أَبِي بَكْرِ بْنِ عَيَّاشٍ عَنْ الْأَعْمَشِ عَنْ مَنْصُورٍ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍيَرْفَعُهُ قَالَ ثَلَاثَةٌ يُحِبُّهُمْ اللَّهُ رَجُلٌ قَامَ مِنْ اللَّيْلِ يَتْلُو كِتَابَ اللَّهِ وَرَجُلٌ تَصَدَّقَ صَدَقَةً بِيَمِينِهِ يُخْفِيهَا أُرَهُ قَالَ مِنْ شِمَالِهِ وَرَجُلٌ كَانَ فِي سَرِيَّةٍ فَانْهَزَمَ أَصْحَابُهُ فَاسْتَقْبَلَ الْعَدُوَّقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَهُوَ غَيْرُ مَحْفُوظٍ وَالصَّحِيحُ مَا رَوَى شُعْبَةُ وَغَيْرُهُ عَنْ مَنْصُورٍ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ عَنْ زَيْدِ بْنِ ظَبْيَانَ عَنْ أَبِي ذَرٍّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرِ بْنُ عَيَّاشٍ كَثِيرُ الْغَلَطِ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah bercerita kepada kami [Yahya bin Adam] dari [Abu Bakar bin Ayyasy] dari [Al A'masy] dari [Manshur] dari [Rib'I bin Hirasy] dari [Abdullah bin Mas'ud] ia memarfu'kannya, ia berkata: Tiga orang dicintai Allah; seseorang bangun di waktu malam kemudian membaca kitabullah, seseorang berinfak dengan tangan kanannya kemudian ia rahasiakan, (perawi) berkata: Aku mengira beliau mengatakan: Merahasiakan dari tangan kirinya, dan seseorang berada dalam pasukan perang kemudian sahabat sahabatnya terbunuh namun dia maju menyongsong musuh.\" Abu Isa berkata: Hadits ini gharib dari jalur sanad ini dan dia tidak mahfudz (terjaga), adapun yang shahih adalah yang diriwayatkan oleh [Syu'bah] dan yang lainnya dari [Manshur] dari [Rib'i bin Hirasy] dari [Zaid bin Dlabyan] dari [Abu Dzar] dari Nabi Shallallahu 'alaihi wa Salam. Abu Bakar bin Ayyasy banyak salahnya."},"2425":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَمُحَمَّدُ بْنُ الْمُثَنَّى قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورِ بْنِ الْمُعْتَمِرِ قَال سَمِعْتُ رِبْعِيَّ بْنَ حِرَاشٍ يُحَدِّثُ عَنْ زَيْدِ بْنِ ظَبْيَانَ يَرْفَعُهُ إِلَى أَبِي ذَرٍّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ثَلَاثَةٌ يُحِبُّهُمْ اللَّهُ وَثَلَاثَةٌ يُبْغِضُهُمْ اللَّهُ فَأَمَّا الَّذِينَ يُحِبُّهُمْ اللَّهُ فَرَجُلٌ أَتَى قَوْمًا فَسَأَلَهُمْ بِاللَّهِ وَلَمْ يَسْأَلْهُمْ بِقَرَابَةٍ بَيْنَهُ وَبَيْنَهُمْ فَمَنَعُوهُ فَتَخَلَّفَ رَجُلٌ بِأَعْقَابِهِمْ فَأَعْطَاهُ سِرًّا لَا يَعْلَمُ بِعَطِيَّتِهِ إِلَّا اللَّهُ وَالَّذِي أَعْطَاهُ وَقَوْمٌ سَارُوا لَيْلَتَهُمْ حَتَّى إِذَا كَانَ النَّوْمُ أَحَبَّ إِلَيْهِمْ مِمَّا يُعْدَلُ بِهِ نَزَلُوا فَوَضَعُوا رُءُوسَهُمْ فَقَامَ أَحَدُهُمْ يَتَمَلَّقُنِي وَيَتْلُو آيَاتِي وَرَجُلٌ كَانَ فِي سَرِيَّةٍ فَلَقِيَ الْعَدُوَّ فَهُزِمُوا وَأَقْبَلَ بِصَدْرِهِ حَتَّى يُقْتَلَ أَوْ يُفْتَحَ لَهُ وَالثَّلَاثَةُ الَّذِينَ يُبْغِضُهُمْ اللَّهُ الشَّيْخُ الزَّانِي وَالْفَقِيرُ الْمُخْتَالُ وَالْغَنِيُّ الظَّلُومُحَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا النَّضْرُ بْنُ شُمَيْلٍ عَنْ شُعْبَةَ نَحْوَهُ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ صَحِيحٌ وَهَكَذَا رَوَى شَيْبَانُ عَنْ مَنْصُورٍ نَحْوَ هَذَا وَهَذَا أَصَحُّ مِنْ حَدِيثِ أَبِي بَكْرِ بْنِ عَيَّاشٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] dan [Muhammad bin Al Mutsanna] keduanya berkata: telah menceritakan kepada kami [Muhammad bin Ja'far] telah bercerita kepada kami [Syu'bah] dari [Manshur bin Al Mu'tamir] berkata: aku telah mendengar [Rib'I bin Hirasy] dari [Zaid bin Dlabyan] ia memarfu'kannya melalui [Abu Dzar] dari Nabi Shallallahu 'alaihi wa Salam, beliau bersabda: \"Ada tiga orang yang dicintai oleh Allah dan tiga orang yang dibenci oleh Allah, adapun yang dicintai oleh Allah adalah; seseorang yang datang kepada suatu kaum lalu meminta kepada mereka dengan nama Allah, ia tidak meminta karena ada hubungan kekerabatan antaranya dengan mereka namun mereka menolaknya, lalu ada seseorang dari kaum itu pergi secara sembunyi-sembunyi dan memberikan sesuatu kepada lelaki yang meminta tadi dengan sembunyi sembunyi, tidak ada yang mengetahui pemberiannya kecuali hanya Allah dan orang yang diberi, suatu kaum yang berjalan di malam hari keinginan untuk tidur lebih mereka sukai dari yang lain, mereka pun singgah lalu meletakkan kepala mereka (tertidur), namun ada seorang lelaki yang bangun bermunajat kepadaNya dan membaca ayat ayatNya, dan seseorang berada dalam barisan pasukan lalu berhadapan dengan musuh, dan ketika pasukannya hancur, justeru dia maju dengan menghadapkan dadanya sampai dia terbunuh atau mendapat kemenangan. Sedangkan tiga orang yang dibenci oleh Allah adalah; orang tua yang berzina, orang fakir yang sombong dan orang kaya yang dzalim.\" Telah menceritakan kepada kami [Mahmud bin Ghailan] telah bercerita kepada kami [An Nadlar bin Syumail] dari [Syu'bah] dengan hadits yang semakna. Abu Isa berkata: Hadits ini shahih, seperti itu juga [Syaiban] meriwayatkan dari [Manshur] dan ini lebih shahih dari hadits Abu Bakar bin Ayyasy."},"2426":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ الْأَشَجُّ حَدَّثَنَا عُقْبَةُ بْنُ خَالِدٍ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ عَنْ خُبَيْبِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ جَدِّهِ حَفْصِ بْنِ عَاصِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوشِكُ الْفُرَاتُ يَحْسِرُ عَنْ كَنْزٍ مِنْ ذَهَبٍ فَمَنْ حَضَرَهُ فَلَا يَأْخُذْ مِنْهُ شَيْئًاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ حَدَّثَنَا أَبُو سَعِيدٍ الْأَشَجُّ حَدَّثَنَا عُقْبَةُ بْنُ خَالِدٍ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ إِلَّا أَنَّهُ قَالَ يَحْسِرُ عَنْ جَبَلٍ مِنْ ذَهَبٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Abu Sa'id Al Asyuj] telah menceritakan kepada kami [Uqbah bin Khalid] telah menceritakan kepada kami [Ubaidullah bin Umar] dari [Khubaib bin Abdurrahman] dari [kakeknya, Hafsh bin Ashim] dari [Abu Hurairah] berkata: Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hampir saja sungai Eufrat mengumpulkan harta simpanan dari emas, siapa pun mendatanginya jangan mengambil apa pun.\" Abu Isa berkata: Hadits ini hasan shahih. Telah menceritakan kepada kami [Abu Sa'id Al Asyuj] telah menceritakan kepada kami [Uqbah bin Khalid] telah menceritakan kepada kami [Ubaidullah] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] dari nabi Shallallahu 'alaihi wa Salam sepertinya, hanya saja ia berkata dalam riwayatnya: Mengumpulkan gunung emas. Abu Isa berkata: Hadits ini hasan shahih."},"2427":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا الْجُرَيْرِيُّ عَنْ حَكِيمِ بْنِ مُعَاوِيَةَ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ فِي الْجَنَّةِ بَحْرَ الْمَاءِ وَبَحْرَ الْعَسَلِ وَبَحْرَ اللَّبَنِ وَبَحْرَ الْخَمْرِ ثُمَّ تُشَقَّقُ الْأَنْهَارُ بَعْدُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَحَكِيمُ بْنُ مُعَاوِيَةَ هُوَ وَالِدُ بَهْزِ بْنِ حَكِيمٍ وَالْجُرَيْرِيُّ يُكْنَى أَبَا مَسْعُودٍ وَاسْمُهُ سَعِيدُ بْنُ إِيَاسٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Yazid bin Harun] telah mengkhabarkan kepada kami [Al Jurairi] dari [Hakim bin Mu'awiyah] dari [ayahnya] dari nabi Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya di surga ada samudera air, samudera madu, samudera susu dan samudera khamar, selanjutnya sungai-sungai menyabang kemana-mana.\" Abu Isa berkata: Hadits ini hasan shahih. Hakim bin Muawiyah adala ayah Bahz bin Hakim dan Al Jurairi kuniahnya Abu Mas'ud, namanya Sa'id bin Iyas."},"2428":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي إِسْحَقَ عَنْ بُرَيْدِ بْنِ أَبِي مَرْيَمَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ سَأَلَ اللَّهَ الْجَنَّةَ ثَلَاثَ مَرَّاتٍ قَالَتْ الْجَنَّةُ اللَّهُمَّ أَدْخِلْهُ الْجَنَّةَ وَمَنْ اسْتَجَارَ مِنْ النَّارِ ثَلَاثَ مَرَّاتٍ قَالَتْ النَّارُ اللَّهُمَّ أَجِرْهُ مِنْ النَّارِقَالَ هَكَذَا رَوَى يُونُسُ بْنُ أَبِي إِسْحَقَ عَنْ أَبِي إِسْحَقَ هَذَا الْحَدِيثَ عَنْ بُرَيْدِ بْنِ أَبِي مَرْيَمَ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ وَقَدْ رُوِيَ عَنْ أَبِي إِسْحَقَ عَنْ بُرَيْدِ بْنِ أَبِي مَرْيَمَ عَنْ أَنَسِ بْنِ مَالِكٍ مَوْقُوفًا أَيْضًا","id":"Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Abu Al Ahwash] dar [Abu Ishaq] dari [Buraid bin Abu Maryam] dari [Anas bin Malik] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Barangsiapa meminta surga kepada Allah sebanyak tiga kali, surga berkata: Ya Allah, masukkan ia ke surga. Dan barangsiapa meminta perlindungan dari neraka sebanyak tiga kali, neraka berkata: Ya Allah, lindungilah ia dari neraka.\" Abu Isa berkata: Demikian [Yunus bin Abu Ishaq] meriwayatkan hadits ini dari [Abu Ishaq] dari [Buraid bin Maryam] dari [Anas] dari nabi Shallallahu 'alaihi wa Salam sepertinya. Dan diriwayatkan dari Abu Ishaq dari Buraid bin Abu Maryam dari Anas bin Malik secara mauquf juga."},"2429":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ أَخْبَرَنَا عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ حَدَّثَنَا أَبِي عَنْ الْعَلَاءِ بْنِ خَالِدٍ الْكَاهِلِيِّ عَنْ شَقِيقِ بْنِ سَلَمَةَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُؤْتَى بِجَهَنَّمَ يَوْمَئِذٍ لَهَا سَبْعُونَ أَلْفَ زِمَامٍ مَعَ كُلِّ زِمَامٍ سَبْعُونَ أَلْفَ مَلَكٍ يَجُرُّونَهَاقَالَ عَبْدُ اللَّهِ وَالثَّوْرِيُّ لَا يَرْفَعُهُ حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ عَمْرٍو أَبُو عَامِرٍ الْعَقَدِيُّ عَنْ سُفْيَانَ عَنْ الْعَلَاءِ بْنِ خَالِدٍ بِهَذَا الْإِسْنَادِ نَحْوَهُ وَلَمْ يَرْفَعْهُ","id":"Telah menceritakan kepada kami [Abdullah bin Abdurrahman] telah bercerita kepada kami [Umar bin Hafs bin Ghiyats] telah mengkhabarkan kepada kami [bapakku] dari [Al Ala' bin Khalid Al Kahili] dari [Syaqiq bin Salamah] dari [Abdullah bin Mas'ud] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Pada hari itu, neraka Jahannam di datangkan, ia memiliki tujuh puluh ribu tali, pada tiap tali ada tujuh puluh ribu malaikat menyeretnya.\" Abdullah berkata: Ats Tsauri tidak menyambungkannya sampai kepada Nabi. Telah menceritakan kepada kami Abdu bin Humaid telah bercerita kepada kami Abdul Malik bin Amru dan Abu Amir Al Aqadi dari Sufyan dari Al Ala' bin Khlid dengan sanad ini sepertinya namun tidak memarfu'kannya."},"2430":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُعَاوِيَةَ الْجُمَحِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُسْلِمٍ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَخْرُجُ عُنُقٌ مِنْ النَّارِ يَوْمَ الْقِيَامَةِ لَهَا عَيْنَانِ تُبْصِرَانِ وَأُذُنَانِ تَسْمَعَانِ وَلِسَانٌ يَنْطِقُ يَقُولُ إِنِّي وُكِّلْتُ بِثَلَاثَةٍ بِكُلِّ جَبَّارٍ عَنِيدٍ وَبِكُلِّ مَنْ دَعَا مَعَ اللَّهِ إِلَهًا آخَرَ وَبِالْمُصَوِّرِينَوَفِي الْبَاب عَنْ أَبِي سَعِيدٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ صَحِيحٌ وَقَدْ رَوَاهُ بَعْضُهُمْ عَنْ الْأَعْمَشِ عَنْ عَطِيَّةَ عَنْ أَبِي سَعِيدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ هَذَا وَرَوَى أَشْعَثُ بْنُ سَوَّارٍ عَنْ عَطِيَّةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Abdullah bin Muawiyah Al Juhami] telah menceritakan kepada kami [Abdul Aziz bin Muslim] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \" Pada hari kiamat nanti, ada Leher keluar dari neraka, ia memiliki dua mata yang melihat, dua telinga yang mendengar dan lisan yang berbicara, ia berkata: Aku diberi kuasa pada setiap orang sombong lagi membangkang, pada orang yang menyeru tuhan lain bersama Allah dan pada orang-orang yang membuat gambar.\" Dalam hal ini ada hadits serupa dari Abu Sa'id. Abu Isa berkata: Hadits ini hasan gharib shahih. Sebagian meriwayatkan hadits ini dari [Al A'masy] dari [Athiyah] dari [Abu Sa'id] dari nabi Shallallahu 'alaihi wa Salam seperti ini. [Asy'ats bin Sawwar] meriwayatkan dari [Athiyah] dari [Abu Sa'id Al Khudri] dari nabi Shallallahu 'alaihi wa Salam sepertinya."},"2431":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا حُسَيْنُ بْنُ عَلِيٍّ الْجُعْفِيُّ عَنْ فُضَيْلِ بْنِ عِيَاضٍ عَنْ هِشَامٍ عَنْ الْحَسَنِ قَالَ قَالَ عُتْبَةُ بْنُ غَزْوَانَ عَلَى مِنْبَرِنَا هَذَا مِنْبَرِ الْبَصْرَةِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الصَّخْرَةَ الْعَظِيمَةَ لَتُلْقَى مِنْ شَفِيرِ جَهَنَّمَ فَتَهْوِي فِيهَا سَبْعِينَ عَامًا وَمَا تُفْضِي إِلَى قَرَارِهَاقَالَ وَكَانَ عُمَرُ يَقُولُ أَكْثِرُوا ذِكْرَ النَّارِ فَإِنَّ حَرَّهَا شَدِيدٌ وَإِنَّ قَعْرَهَا بَعِيدٌ وَإِنَّ مَقَامِعَهَا حَدِيدٌ قَالَ أَبُو عِيسَى لَا نَعْرِفُ لِلْحَسَنِ سَمَاعًا مِنْ عُتْبَةَ بْنِ غَزْوَانَ وَإِنَّمَا قَدِمَ عُتْبَةُ بْنُ غَزْوَانَ الْبَصْرَةَ فِي زَمَنِ عُمَرَ وَوُلِدَ الْحَسَنُ لِسَنَتَيْنِ بَقِيَتَا مِنْ خِلَافَةِ عُمَرَ","id":"Telah menceritakan kepada kami [Abd bin Humaid] telah menceritakan kepada kami [Husain bin Ali Al Ju'fi] dari [Fudlail bin Iyadl] dari [Hisyam] dari [Al Hasan] berkata: [Utbah bin Ghazwan] berkhutbah di atas mimbar Bashrah, dari nabi Shallallahu 'alaihi wa Salam beliau bersabda: \"Sesungguhnya batu besar di lemparkan dari tepi neraka jahanam lalu jatuh ke dalamnya selama tujuhpuluh tahun dan tidak juga sampai ke dasarnya.\" Berkata Al Hasan: Ibnu Umar berkata: Sering-seringlah mengingat neraka karena panasnya amat sangat, jurangnya jauh dan palu-palunya terbuat dari besi. Abu Isa berkata: Kami tidak mengetahui Al Hasan mendengar dari Utbah bin Ghazwan, Utbah bin Ghazwan hanya datang ke Bashrah di masa Umar, sementara Al Hasan lahir dua tahun di sisa masa khilafah Umar."},"2432":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا الْحَسَنُ بْنُ مُوسَى عَنْ ابْنِ لَهِيعَةَ عَنْ دَرَّاجٍ عَنْ أَبِي الْهَيْثَمِ عَنْ أَبِي سَعِيدٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الصَّعُودُ جَبَلٌ مِنْ نَارٍ يَتَصَعَّدُ فِيهِ الْكَافِرُ سَبْعِينَ خَرِيفًا وَيَهْوِي فِيهِ كَذَلِكَ أَبَدًاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ مَرْفُوعًا إِلَّا مِنْ حَدِيثِ ابْنِ لَهِيعَةَ","id":"Telah menceritakan kepada kami [Abd bin Humaid] telah menceritakan kepada kami [Al Hasan bin Musa] dari [Ibnu Lahi'ah] dari [Darraj] dari [Abu Al Hutsaim] dari [Abu Sa'id] dari Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Sha'ud adalah salah satu gunung neraka, orang kafir menaikinya selama empatpuluh tahun lalu terjun di dalamnya seperti itu juga selama itu selama-lamanya. Abu Isa berkata: Hadits ini gharib, kemarfu'annya hanya kami ketahui dari hadits Ibnu Lahi'ah."},"2433":{"ar":"حَدَّثَنَا عَبَّاسٌ الدُّورِيُّ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى أَخْبَرَنَا شَيْبَانُ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ غِلَظَ جِلْدِ الْكَافِرِ اثْنَانِ وَأَرْبَعُونَ ذِرَاعًا وَإِنَّ ضِرْسَهُ مِثْلُ أُحُدٍ وَإِنَّ مَجْلِسَهُ مِنْ جَهَنَّمَ كَمَا بَيْنَ مَكَّةَ وَالْمَدِينَةِهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ حَدِيثِ الْأَعْمَشِ","id":"Telah menceritakan kepada kami [Abbas Ad Duri] telah menceritakan kepada kami [Ubaidullah bin Musa] telah mengkhabarkan kepada kami [Syaiban] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dari nabi Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya kulit orang kafir itu setebal empatpuluh dua hasta, gigi gerahamnya seperti Uhud dan tempatnya di neraka jahanam seluas antara Makkah dan Madinah.\" Hadits ini hasan shahih gharib dari hadits Al A'masy."},"2434":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا مُحَمَّدُ بْنُ عَمَّارٍ حَدَّثَنِي جَدِّي مُحَمَّدُ بْنُ عَمَّارٍ وَصَالِحٌ مَوْلَى التَّوْأَمَةِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضِرْسُ الْكَافِرِ يَوْمَ الْقِيَامَةِ مِثْلُ أُحُدٍ وَفَخِذُهُ مِثْلُ الْبَيْضَاءِ وَمَقْعَدُهُ مِنْ النَّارِ مَسِيرَةُ ثَلَاثٍ مِثْلُ الرَّبَذَةِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَمِثْلُ الرَّبَذَةِ كَمَا بَيْنَ الْمَدِينَةِ وَالرَّبَذَةِ وَالْبَيْضَاءُ جَبَلٌ مِثْلُ أُحُدٍ","id":"Telah menceritakan kepada kami [Ali bin Hujr] telah mengabarkan kepada kami [Muhammad bin Ammar] telah menceritakan kepadaku [kakekku, Muhammad bin Ammar] dan [Shalih maula at-Tau`amah] dari [Abu Hurairah], dia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Gigi orang kafir pada hari kiamat seperti gunung Uhud, pahanya seperti gunung al Baidha', dan tempat duduknya dari api neraka sejarak tiga (malam) seperti ar Rabadzah.\" Abu Isa berkata; Ini hadits hasan gharib. Sedangkan kalimat, 'Seperti ar Rabadzah' adalah seperti jarak antara Madinah dan ar Rabazdah. Kata 'Al Baidha' adalah nama gunung sebagaimana Uhud."},"2435":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا مُصْعَبُ بْنُ الْمِقْدَامِ عَنْ فُضَيْلِ بْنِ غَزْوَانَ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَرَفَعَهُ قَالَ ضِرْسُ الْكَافِرِ مِثْلُ أُحُدٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ وَأَبُو حَازِمٍ هُوَ الْأَشْجَعِيُّ اسْمُهُ سَلْمَانُ مَوْلَى عَزَّةَ الْأَشْجَعِيَّةِ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Mush'ab bin al Miqdam] dari [Fudhail bin Ghazwan] dari [Abu Hazim] dari [Abu Hurairah] dia menyatakannya marfu', beliau bersabda; \"Geraham orang kafir seperti gunung Uhud.\" Abu Isa berkata; 'Ini hadits hasan. Sedangkan Abu Hazim adalah (bermarga) al Asyja'i, namanya Salman maula 'Azzah al Asyja'iyyah.\""},"2436":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ الْفَضْلِ بْنِ يَزِيدَ عَنْ أَبِي الْمُخَارِقِ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْكَافِرَ لَيُسْحَبُ لِسَانُهُ الْفَرْسَخَ وَالْفَرْسَخَيْنِ يَتَوَطَّؤُهُ النَّاسُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ إِنَّمَا نَعْرِفُهُ مِنْ هَذَا الْوَجْهِ وَالْفَضْلُ بْنُ يَزِيدَ هُوَ كُوفِيٌّ قَدْ رَوَى عَنْهُ غَيْرُ وَاحِدٍ مِنْ الْأَئِمَّةِ وَأَبُو الْمُخَارِقِ لَيْسَ بِمَعْرُوفٍ","id":"Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Ali bin Mushir] dari [al Fadhl bin Yazid] dari [Abu al Mukhariq] dari [Ibnu Umar] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya lisan orang kafir akan diseret sejarak satu farsakh dan dua farsakh, dan diinjak-injak oleh manusia.\" Abu Isa berkata; 'Ini hadits gharib. Kami hanya mengetahuinya dari jalur ini saja. Sedangkan Fadhl bin Yazid adalah seorang kufah. Bukan hanya satu imam yang meriwayatkan darinya. Sedangkan Abu al Mukhariq tidak dikenal.'"},"2437":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا رِشْدِينُ بْنُ سَعْدٍ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ دَرَّاجٍ عَنْ أَبِي الْهَيْثَمِ عَنْ أَبِي سَعِيدٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي قَوْلِهِ{ كَالْمُهْلِ }قَالَ كَعَكَرِ الزَّيْتِ فَإِذَا قَرَّبَهُ إِلَى وَجْهِهِ سَقَطَتْ فَرْوَةُ وَجْهِهِ فِيهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ رِشْدِينَ بْنِ سَعْدٍ وَرِشْدِينُ قَدْ تُكُلِّمَ فِيهِ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Risydin bin Sa'd] dari [Amru bin al Harits] dari [Darraj] dari [Abu al Haitsam] dari [Abu Sa'id] dari Nabi shallallahu 'alaihi wasallam dalam menjelaskan firman Nya, \"Seperti besi yang mendidih.\" Beliau bersabda: \"Maksudnya seperti endapan minyak. Maka apabila (orang yang bermaksiat) mendekatkannya kepada wajahnya, niscaya kulit mukanya akan jatuh mengelupas ke dalamnya.\" Abu Isa berkata; 'Ini hadits yang mana kita tidak mengenalnya kecuali dari hadits Risydin bin Sa'd, sedangkan Risydin kredibilitasnya diperbincangkan.'"},"2438":{"ar":"حَدَّثَنَا سُوَيْدٌ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا سَعِيدُ بْنُ يَزِيدَ عَنْ أَبِي السَّمْحِ عَنْ ابْنِ حُجَيْرَةَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْحَمِيمَ لَيُصَبُّ عَلَى رُءُوسِهِمْ فَيَنْفُذُ الْحَمِيمُ حَتَّى يَخْلُصَ إِلَى جَوْفِهِ فَيَسْلِتُ مَا فِي جَوْفِهِ حَتَّى يَمْرُقَ مِنْ قَدَمَيْهِ وَهُوَ الصَّهْرُ ثُمَّ يُعَادُ كَمَا كَانَوَسَعِيدُ بْنُ يَزِيدَ يُكْنَى أَبَا شُجَاعٍ وَهُوَ مِصْرِيٌّ وَقَدْ رَوَى عَنْهُ اللَّيْثُ بْنُ سَعْدٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ وَابْنُ حُجَيْرَةَ هُوَ عَبْدُ الرَّحْمَنِ بْنُ حُجَيْرَةَ الْمِصْرِيُّ","id":"Telah menceritakan kepada kami [Suwaid] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Sa'id bin Yazid] dari [Abu as Samh] dari [Ibnu Hujairah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya air yang panas tersebut pasti akan dituangkan ke atas kepala mereka, maka air panas tersebut menembus hingga masuk ke dalam perutnya dan memotong segala sesuatu yang berada dalam perutnya hingga keluar dari kedua telapak kakinya dalam bentuk cairan. Kemudian dia dikembalikan (utuh) sebagaimana sebelumnya.\" Sa'id bin Yazid diberi kunyah Abu Syuja', dia seorang Mesir. Al Laits bin Sa'd telah meriwayatkan darinya. Abu Isa berkata; 'Ini hadits hasan shahih gharib. Sedangkan Ibnu Hujairah adalah Abdurrahman bin Hujairah al Mishri.'"},"2439":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ نَصْرٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا صَفْوَانُ بْنُ عَمْرٍو عَنْ عُبَيْدِ اللَّهِ بْنِ بُسْرٍ عَنْ أَبِي أُمَامَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي قَوْلِهِ{ وَيُسْقَى مِنْ مَاءٍ صَدِيدٍ يَتَجَرَّعُهُ }قَالَ يُقَرَّبُ إِلَى فِيهِ فَيَكْرَهُهُ فَإِذَا أُدْنِيَ مِنْهُ شَوَى وَجْهَهُ وَوَقَعَتْ فَرْوَةُ رَأْسِهِ فَإِذَا شَرِبَهُ قَطَّعَ أَمْعَاءَهُ حَتَّى تَخْرُجَ مِنْ دُبُرِهِ يَقُولُ اللَّهُ{ وَسُقُوا مَاءً حَمِيمًا فَقَطَّعَ أَمْعَاءَهُمْ }وَيَقُولُ{ وَإِنْ يَسْتَغِيثُوا يُغَاثُوا بِمَاءٍ كَالْمُهْلِ يَشْوِي الْوُجُوهَ بِئْسَ الشَّرَابُ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ وَهَكَذَا قَالَ مُحَمَّدُ بْنُ إِسْمَعِيلَ عَنْ عُبَيْدِ اللَّهِ بْنِ بُسْرٍ وَلَا نَعْرِفُ عُبَيْدَ اللَّهِ بْنَ بُسْرٍ إِلَّا فِي هَذَا الْحَدِيثِ وَقَدْ رَوَى صَفْوَانُ بْنُ عَمْرٍو عَنْ عَبْدِ اللَّهِ بْنِ بُسْرٍ صَاحِبِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَيْرَ هَذَا الْحَدِيثِ وَعَبْدُ اللَّهِ بْنُ بُسْرٍ لَهُ أَخٌ قَدْ سَمِعَ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأُخْتُهُ قَدْ سَمِعَتْ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعُبَيْدُ اللَّهِ بْنُ بُسْرٍ الَّذِي رَوَى عَنْهُ صَفْوَانُ بْنُ عَمْرٍو هَذَا الْحَدِيثَ رَجُلٌ آخَرُ لَيْسَ بِصَاحِبٍ","id":"Telah menceritakan kepada kami [Suwaid bin Nashr] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Shafwan bin Amru] dari [Ubaidillah bin Busr] dari [Abu Umamah] dari Nabi shallallahu 'alaihi wasallam dalam menjelaskan firman Nya, \"Dan dia akan diberi minuman dengan air nanah, lalu dia minum air nanah itu.\" Beliau menjelaskan; '(Minuman itu) didekatkan kepada (orang yang bermaksiat tersebut), maka dia tidak menyukainya, ketika didekatkan kepadanya, minuman itu membakar wajahnya, maka kulit kepalanya jatuh mengelupas. Ketika dia meminumnya, minuman itu memutuskan lambungnya hingga keluar (cairan) dari duburnya. Allah berfirman: 'Dan mereka diberi minuman dengan air yang mendidih sehingga memotong ususnya.' Dan Allah berfirman: 'Dan jika mereka meminta minum, niscaya mereka akan diberi minum dengan air seperti besi yang mendidih yang menghanguskan muka. Itulah minuman yang paling buruk dan tempat istirahat yang paling jelek'.\" Abu Isa berkata; 'Ini hadits gharib. Demikianlah yang dikatakan Muhammad bin Isma'il dari Ubaidullah bin Busr. Dan kami tidak mengetahui Ubaidullah bin Busr kecuali dalam hadits ini. Shafwan telah meriwayatkan dari Amru dari Abdullah bin Busr, sahabat Nabi shallallahu 'alaihi wasallam selain hadits ini. Abdullah bin Busr mempunyai saudara yang telah mendengarkan (hadits) dari Nabi shallallahu 'alaihi wasallam, dan saudarinya juga telah mendengar dari Nabi shallallahu 'alaihi wasallam. Sedangkan Ubaidullah bin Busr yang mana Shafwan bin Amru meriwayatkan hadits ini darinya adalah laki-laki lain yang tidak termasuk kalangan shahabat.'"},"2440":{"ar":"حَدَّثَنَا سُوَيْدٌ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ أَخْبَرَنَا رِشْدِينُ بْنُ سَعْدٍ حَدَّثَنِي عَمْرُو بْنُ الْحَارِثِ عَنْ دَرَّاجٍ عَنْ أَبِي الْهَيْثَمِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ{ كَالْمُهْلِ }كَعَكَرِ الزَّيْتِ فَإِذَا قُرِّبَ إِلَيْهِ سَقَطَتْ فَرْوَةُ وَجْهِهِ فِيهِ","id":"Telah menceritakan kepada kami [Suwaid] telah mengabarkan kepada kami [Abdullah bin Al Mubarak] telah mengabarkan kepada kami [Risydin bin Sa'ad] telah menceritakan kepadaku [Amru bin Al Harits] dari [Darraj] dari [Abul Haitsam] dari [Abu Sa'id Al Khudri] dari Nabi shallallahu 'alaihi wasallam, beliau menjelaskan firmanNya; \"Seperti besi yang mendidih\" yaitu seperti endapan minyak, apabila didekatkan maka wajahnya (penghuni neraka) niscaya jatuh mengelupas ke dalamnya\"."},"2441":{"ar":"وَبِهَذَا الْإِسْنَادِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِسُرَادِقِ النَّارِ أَرْبَعَةُ جُدُرٍ كِثَفُ كُلِّ جِدَارٍ مِثْلُ مَسِيرَةِ أَرْبَعِينَ سَنَةً","id":"Dan dengan sanad ini (Yaitu; Telah menceritakan kepada kami [Suwaid] telah mengabarkan kepada kami [Abdullah bin Al Mubarak] telah mengabarkan kepada kami [Risydin bin Sa'ad] telah menceritakan kepadaku [Amru bin Al Harits] dari [Darraj] dari [Abul Haitsam] dari [Abu Sa'id Al Khudri]), dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tenda neraka memiliki empat dinding yang tebal. Setiap dinding memiliki ketebalan semisal jarak empat puluh tahun.\""},"2442":{"ar":"وَبِهَذَا الْإِسْنَادِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَوْ أَنَّ دَلْوًا مِنْ غَسَّاقٍ يُهَرَاقُ فِي الدُّنْيَا لَأَنْتَنَ أَهْلَ الدُّنْيَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ إِنَّمَا نَعْرِفُهُ مِنْ حَدِيثِ رِشْدِينَ بْنِ سَعْدٍ وَفِي رِشْدِينَ مَقَالٌ وَقَدْ تُكُلِّمَ فِيهِ مِنْ قِبَلِ حِفْظِهِ وَمَعْنَى قَوْلِهِ كِثَفُ كُلِّ جِدَارٍ يَعْنِي غِلَظَهُ","id":"Dan dengan sanad ini pula, (Yaitu; Telah menceritakan kepada kami [Suwaid] telah mengabarkan kepada kami [Abdullah bin Al Mubarak] telah mengabarkan kepada kami [Risydin bin Sa'ad] telah menceritakan kepadaku [Amru bin Al Harits] dari [Darraj] dari [Abul Haitsam] dari [Abu Sa'id Al Khudri]) dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Kalau seandainya satu timba dari nanah ahli neraka ditumpahkan ke dunia, niscaya penduduk dunia akan basi.\" Abu Isa berkata; 'Hadits ini hanya kami kenal dari hadits Risydin bin Sa'd. Namun pada (kredibilitas) Risydin terdapat perbincangan. Dia diperbincangkan pada hafalannya. Sedangkan makna sabdanya, 'Katsifu Kulli Jidar' maksudnya adalah ketebalan dindingnya."},"2443":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ أَخْبَرَنَا شُعْبَةُ عَنْ الْأَعْمَشِ عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ هَذِهِ الْآيَةَ{ اتَّقُوا اللَّهَ حَقَّ تُقَاتِهِ وَلَا تَمُوتُنَّ إِلَّا وَأَنْتُمْ مُسْلِمُونَ }قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ أَنَّ قَطْرَةً مِنْ الزَّقُّومِ قُطِرَتْ فِي دَارِ الدُّنْيَا لَأَفْسَدَتْ عَلَى أَهْلِ الدُّنْيَا مَعَايِشَهُمْ فَكَيْفَ بِمَنْ يَكُونُ طَعَامَهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Daud] telah menceritakan kepada kami [Syu'bah] dari [al A'masy] dari [Mujahid] dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam membaca ayat, \"Bertakwalah kamu sekalian kepada Allah dengan sebenar benarnya takwa, dan janganlah kamu sekalian meninggal melainkan kalian dalam keadaan muslim.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kalau seandainya setetes Zaqqum (nama pohon di neraka) menetes ke kampung dunia, niscaya akan merusakkan kehidupan penduduk dunia. Lalu bagaimana dengan (keadaan) orang-orang yang menjadikan zaqqum sebagai makanannya?\" Abu Isa berkata; 'Ini hadits hasan shahih.\""},"2444":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ أَخْبَرَنَا عَاصِمُ بْنُ يُوسُفَ حَدَّثَنَا قُطْبَةُ بْنُ عَبْدِ الْعَزِيزِ عَنْ الْأَعْمَشِ عَنْ شِمْرِ بْنِ عَطِيَّةَ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أُمِّ الدَّرْدَاءِ عَنْ أَبِي الدَّرْدَاءِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُلْقَى عَلَى أَهْلِ النَّارِ الْجُوعُ فَيَعْدِلُ مَا هُمْ فِيهِ مِنْ الْعَذَابِ فَيَسْتَغِيثُونَ فَيُغَاثُونَ بِطَعَامٍ مِنْ ضَرِيعٍ لَا يُسْمِنُ وَلَا يُغْنِي مِنْ جُوعٍ فَيَسْتَغِيثُونَ بِالطَّعَامِ فَيُغَاثُونَ بِطَعَامٍ ذِي غُصَّةٍ فَيَذْكُرُونَ أَنَّهُمْ كَانُوا يُجِيزُونَ الْغَصَصَ فِي الدُّنْيَا بِالشَّرَابِ فَيَسْتَغِيثُونَ بِالشَّرَابِ فَيُرْفَعُ إِلَيْهِمْ الْحَمِيمُ بِكَلَالِيبِ الْحَدِيدِ فَإِذَا دَنَتْ مِنْ وُجُوهِهِمْ شَوَتْ وُجُوهَهُمْ فَإِذَا دَخَلَتْ بُطُونَهُمْ قَطَّعَتْ مَا فِي بُطُونِهِمْ فَيَقُولُونَ ادْعُوا خَزَنَةَ جَهَنَّمَ فَيَقُولُونَ أَلَمْ{ تَكُ تَأْتِيكُمْ رُسُلُكُمْ بِالْبَيِّنَاتِ قَالُوا بَلَى قَالُوا فَادْعُوا وَمَا دُعَاءُ الْكَافِرِينَ إِلَّا فِي ضَلَالٍ }قَالَ فَيَقُولُونَ ادْعُوا مَالِكًا فَيَقُولُونَ{ يَا مَالِكُ لِيَقْضِ عَلَيْنَا رَبُّكَ }قَالَ فَيُجِيبُهُمْ{ إِنَّكُمْ مَاكِثُونَ }قَالَ الْأَعْمَشُ نُبِّئْتُ أَنَّ بَيْنَ دُعَائِهِمْ وَبَيْنَ إِجَابَةِ مَالِكٍ إِيَّاهُمْ أَلْفَ عَامٍ قَالَ فَيَقُولُونَ ادْعُوا رَبَّكُمْ فَلَا أَحَدَ خَيْرٌ مِنْ رَبِّكُمْ فَيَقُولُونَ{ رَبَّنَا غَلَبَتْ عَلَيْنَا شِقْوَتُنَا وَكُنَّا قَوْمًا ضَالِّينَ رَبَّنَا أَخْرِجْنَا مِنْهَا فَإِنْ عُدْنَا فَإِنَّا ظَالِمُونَ }قَالَ فَيُجِيبُهُمْ{ اخْسَئُوا فِيهَا وَلَا تُكَلِّمُونِ }قَالَ فَعِنْدَ ذَلِكَ يَئِسُوا مِنْ كُلِّ خَيْرٍ وَعِنْدَ ذَلِكَ يَأْخُذُونَ فِي الزَّفِيرِ وَالْحَسْرَةِ وَالْوَيْلِقَالَ عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ وَالنَّاسُ لَا يَرْفَعُونَ هَذَا الْحَدِيثَ قَالَ أَبُو عِيسَى إِنَّمَا نَعْرِفُ هَذَا الْحَدِيثَ عَنْ الْأَعْمَشِ عَنْ شِمْرِ بْنِ عَطِيَّةَ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أُمِّ الدَّرْدَاءِ عَنْ أَبِي الدَّرْدَاءِ قَوْلَهُ وَلَيْسَ بِمَرْفُوعٍ وَقُطْبَةُ بْنُ عَبْدِ الْعَزِيزِ هُوَ ثِقَةٌ عِنْدَ أَهْلِ الْحَدِيثِ","id":"Telah menceritakan kepada kami [Abdullah bin Abdurrahman] telah mengabarkan kepada kami ['Ashim bin Yusuf] telah menceritakan kepada kami [Quthbah bin Abdul Aziz] dari [Al A'masy] dari [Syimir bin Athiyyah] dari [Syahr bin Hausyab] dari [Ummu Ad Darda'] dari [Abu Ad Darda'] dia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan dicampakkan kepada penghuni neraka rasa lapar yang sebanding dengan siksa yang mereka alami, lalu mereka memohon pertolongan, kemudian mereka ditolong dengan diberi makanan dari \"dhari\" (pohon yang berduri) Yang tidak menggemukkan dan tidak pula menghilangkan lapar, kemudian mereka memohon diberikan makanan lalu mereka diberi makanan yang menyumbat di kerongkongan, kemudian mereka teringat bahwa dahulu di dunia mereka mengobati tersumbatnya kerongkongan mereka dengan minuman, maka mereka memohon untuk diberi minuman, lalu dituangkanlah air mendidih kepada mereka dengan \"Al Kalalib\" (besi yang bengkok ujungnya digunakan untuk mengangkat daging dari kendi) yang apabila telah dekat ke wajah mereka menjadi gosonglah wajah mereka, dan apabila masuk ke dalam perut mereka niscaya akan memotong motong organ yang ada dalam perut mereka, lalu mereka berkata sesama mereka; 'Memohonlah kepada penjaga neraka Jahannam' namun mereka membacakan ayat 'Dan apakah belum datang kepada kamu rasul-rasulmu dengan membawa keterangan keterangan' Mereka menjawab: 'Benar, sudah datang.' penjaga-penjaga Jahannam berkata: 'Berdoalah kamu.' Dan doa orang-orang kafir itu hanyalah sia-sia belaka\". (QS Ghafir: 50) Rasulullah berkata; \"Lalu mereka berkata; 'Memohonlah kepada Malaikat Malik, ' maka mereka berkata; (Hai Malik Biarlah Tuhanmu membunuh kami saja) \". QS Az-Zukhrf: 77. Nabi berkata: \"Dia menjawab; 'Kamu akan tetap tinggal (di neraka ini) '.\" -Al A'masy berkata; 'Aku diberi tahu bahwa jarak antara permohonan mereka dengan jawaban Malaikat Malik kepada mereka adalah seribu tahun, '- Nabi berkata: \"Lalu mereka saling berkata; 'Mohonlah kepada Rabb kalian karena tidak ada seorang pun yang lebih baik daripada Rabb kalian'. Lalu mereka memohon; 'Ya Tuhan kami, kami telah dikuasai oleh kejahatan kami, dan dahulu kami adalah orang-orang yang sesat. Ya Tuhan kami, keluarkanlah kami dari padanya (dan kembalikanlah kami ke dunia), maka jika kami kembali (juga kepada kekafiran), maka sesungguhnya kami adalah orang-orang yang zhalim.'\" QS Al Mukminun: 106-107. Nabi berkata: \"Lalu Allah menjawab kepada mereka; 'Tinggallah dengan hina di dalamnya, dan janganlah kamu berbicara dengan Aku'.\" QS Al Mukminun: 108. Nabi berkata: \"Maka ketika itu mereka putus asa dari segala kebaikan, dan ketika itu juga mereka meringkik dan menyesal serta celaka.\" Abdullah bin Abdurrahman berkata; \"Orang-orang tidak merafa'kan (menyambungkan sampai kepada Nabi) hadits ini\". Abu Isa berkata; 'Kami mengetahui hadits ini hanya dari Al A'masy dari Syimir bin Athiyyah dari Syahr bin Hasyab dari Ummu Ad Darda' dari perkataan Abu Ad Darda', dan ia tidak marfu'. Adapun Qutbah bin Abdul Aziz, maka dia adalah seorang yang tsiqah menurut para ahli hadits\"."},"2445":{"ar":"حَدَّثَنَا سُوَيْدٌ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ سَعِيدِ بْنِ يَزِيدَ أَبِي شُجَاعٍ عَنْ أَبِي السَّمْحِ عَنْ أَبِي الْهَيْثَمِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ{ وَهُمْ فِيهَا كَالِحُونَ }قَالَ تَشْوِيهِ النَّارُ فَتَقَلَّصُ شَفَتُهُ الْعُلْيَا حَتَّى تَبْلُغَ وَسَطَ رَأْسِهِ وَتَسْتَرْخِي شَفَتُهُ السُّفْلَى حَتَّى تَضْرِبَ سُرَّتَهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ وَأَبُو الْهَيْثَمِ اسْمُهُ سُلَيْمَانُ بْنُ عَمْرِو بْنِ عَبْدٍ الْعُتْوَارِيُّ وَكَانَ يَتِيمًا فِي حِجْرِ أَبِي سَعِيدٍ","id":"Telah menceritakan kepada kami [Suwaid] telah mengabarkan kepada kami [Abdullah bin al Mubarak] dari [Sa'id bin Yazid Abu Syuja'] dari [Abu as Samh] dari [Abu al Haitsam] dari [Abu Sa'id al Khudzri] dari Nabi shallallahu 'alaihi wasallam, beliau menjelaskan firmanNya: \"Dan mereka di dalam neraka itu dalam keadaan cacat.\" Beliau bersabda: \"Orang kafir dibakar oleh api neraka, maka bibir atasnya mengkerut (ke atas) sehingga mencapai pertengahan kepalanya, sedangkan bibir bawahnya menjulur hingga mendekati pusarnya.\" Abu Isa berkata; 'Ini hadits hasan shahih gharib. Dan Abu al Haitsam namanya adalah Sulaiman bin Amru bin Murrah bin Abd al Utwari. Dia adalah seorang yatim yang berada pada naungan Abu Sa'id.'"},"2446":{"ar":"حَدَّثَنَا سُوَيْدٌ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا سَعِيدُ بْنُ يَزِيدَ عَنْ أَبِي السَّمْحِ عَنْ عِيسَى بْنِ هِلَالٍ الصَّدَفِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِي قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ أَنَّ رَصَاصَةً مِثْلَ هَذِهِ وَأَشَارَ إِلَى مِثْلِ الْجُمْجُمَةِ أُرْسِلَتْ مِنْ السَّمَاءِ إِلَى الْأَرْضِ هِيَ مَسِيرَةُ خَمْسِ مِائَةِ سَنَةٍ لَبَلَغَتْ الْأَرْضَ قَبْلَ اللَّيْلِ وَلَوْ أَنَّهَا أُرْسِلَتْ مِنْ رَأْسِ السِّلْسِلَةِ لَسَارَتْ أَرْبَعِينَ خَرِيفًا اللَّيْلَ وَالنَّهَارَ قَبْلَ أَنْ تَبْلُغَ أَصْلَهَا أَوْ قَعْرَهَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ إِسْنَادُهُ حَسَنٌ صَحِيحٌ وَسَعِيدُ بْنُ يَزِيدَ هُوَ مِصْرِيٌّ وَقَدْ رَوَى عَنْهُ اللَّيْثُ بْنُ سَعْدٍ وَغَيْرُ وَاحِدٍ مِنْ الْأَئِمَّةِ","id":"Telah menceritakan kepada kami [Suwaid] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Sa'id bin Yazid] dari [Abu as Samh] dari [Isa bin Hilal ash Shadafi] dari [Abdullah bin Amru bin al 'Ash] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kalau seandainya timah seperti ini -dan beliau menunjuk seperti wadah kecil- dikirim dari langit menuju ke bumi yang jaraknya sepanjang perjalanan lima ratus tahun, niscaya ia akan sampai di bumi sebelum malam, dan kalau seandainya ia dikirim dari puncak 'rantai', niscaya akan (memerlukan) perjalanan empat puluh tahun siang dan malam sebelum mencapai dasarnya atau keraknya.\" Abu Isa berkata; 'Hadits ini sanadnya hasan shahih. Dan Sa'id bin Yazid adalah seorang Mesir. Al Laits bin Sa'id dan bukan satu imam saja yang telah meriwayatkan hadits darinya.\""},"2447":{"ar":"حَدَّثَنَا سُوَيْدٌ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَارُكُمْ هَذِهِ الَّتِي تُوقِدُونَ جُزْءٌ وَاحِدٌ مِنْ سَبْعِينَ جُزْءًا مِنْ حَرِّ جَهَنَّمَ قَالُوا وَاللَّهِ إِنْ كَانَتْ لَكَافِيَةً يَا رَسُولَ اللَّهِ قَالَ فَإِنَّهَا فُضِّلَتْ بِتِسْعَةٍ وَسِتِّينَ جُزْءًا كُلُّهُنَّ مِثْلُ حَرِّهَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَهَمَّامُ بْنُ مُنَبِّهٍ هُوَ أَخُو وَهْبِ بْنِ مُنَبِّهٍ وَقَدْ رَوَى عَنْهُ وَهْبٌ","id":"Telah menceritakan kepada kami [Suwaid] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Ma'mar] dari [Hammam bin Munabbih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Api kalian ini yang kalian gunakan untuk membakar adalah salah satu bagian dari tujuh puluh bagian panasnya api neraka.\" Mereka bertanya; \"Demi Allah, apabila api ini sungguh sudah cukup (panas untuk mengadzab orang yang bermaksiat, lalu mengapa harus ditambah panasnya) wahai Rasulullah?\" Beliau menjawab: \"Panasnya api neraka melebihi (panasnya api dunia) sembilan puluh sembilan bagian. Semua bagian api (yang berjumlah sembilan puluh sembilan) panasnya adalah seperti panas api neraka.\" (maksud jawaban Rasulullah adalah adzab Allah harus lebih besar daripada adzab manusia). Abu Isa berkata; 'Hadits ini hadits hasan shahih. Dan Hammam bin Munabbih adalah saudara Wahb bin Munabbih. Dan Wahb telah meriwayatkan hadits darinya.\""},"2448":{"ar":"حَدَّثَنَا الْعَبَّاسُ الدُّورِيُّ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى حَدَّثَنَا شَيْبَانُ عَنْ فِرَاسٍ عَنْ عَطِيَّةَ عَنْ أَبِي سَعِيدٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَارُكُمْ هَذِهِ جُزْءٌ مِنْ سَبْعِينَ جُزْءًا مِنْ نَارِ جَهَنَّمَ لِكُلِّ جُزْءٍ مِنْهَا حَرُّهَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ حَدِيثِ أَبِي سَعِيدٍ","id":"Telah menceritakan kepada kami [Al Abbas Ad Duri al Baghdadi] telah menceritakan kepada kami [Ubaidullah bin Musa] telah menceritakan kepada kami [Syaiban] dari [Firas] dari [Athiyyah] dari [Abu Sa'id] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Api kalian ini adalah satu bagian dari tujuh puluh bagian api neraka Jahannam, panas dari semua bagian adalah sama dengan panas api neraka\". Abu Isa berkata; 'Hadits ini hasan gharib dari hadits Abu Sa'id.'"},"2449":{"ar":"حَدَّثَنَا عَبَّاسٌ الدُّورِيُّ الْبَغْدَادِيُّ حَدَّثَنَا يَحْيَى بْنُ أَبِي بُكَيْرٍ حَدَّثَنَا شَرِيكٌ عَنْ عَاصِمٍ هُوَ ابْنُ بَهْدَلَةَ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أُوقِدَ عَلَى النَّارِ أَلْفَ سَنَةٍ حَتَّى احْمَرَّتْ ثُمَّ أُوقِدَ عَلَيْهَا أَلْفَ سَنَةٍ حَتَّى ابْيَضَّتْ ثُمَّ أُوقِدَ عَلَيْهَا أَلْفَ سَنَةٍ حَتَّى اسْوَدَّتْ فَهِيَ سَوْدَاءُ مُظْلِمَةٌحَدَّثَنَا سُوَيْدٌ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ شَرِيكٍ عَنْ عَاصِمٍ عَنْ أَبِي صَالِحٍ أَوْ رَجُلٍ آخَرَ عَنْ أَبِي هُرَيْرَةَ نَحْوَهُ وَلَمْ يَرْفَعْهُ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي هُرَيْرَةَ فِي هَذَا مَوْقُوفٌ أَصَحُّ وَلَا أَعْلَمُ أَحَدًا رَفَعَهُ غَيْرَ يَحْيَى بْنِ أَبِي بُكَيْرٍ عَنْ شَرِيكٍ","id":"Telah menceritakan kepada kami [Abbas Ad Duri Al Baghdadi] telah menceritakan kepada kami [Yahya bin Abu Bukair] telah menceritakan kepada kami [Syarik] dari ['Ashim, yaitu Ibnu Bahdalah] dari [Abu Shalih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Bara api neraka jahannam itu dipanaskan selama seribu tahun sampai menjadi merah, kemudian dipanaskan lagi selama seribu tahun sampai menjadi putih, kemudian dipanaskan lagi selama seribu tahun sampai menjadi hitam, maka dia menjadi hitam gelap\". Telah menceritakan kepada kami Suwaid telah mengabarkan kepada kami Abdullah bin Al Mubarak dari Syarik dari 'Ashim dari Abu Shalih atau seorang lelaki yang lain dari Abu Hurairah dengan hadits yang semakna namun dia tidak merafa'kannya. Abu Isa berkata; 'Hadits Abu Hurairah dalam masalah ini yang lebih shahih adalah hadits mauquf, dan saya tidak mengetahui seorang pun yang merafa'kannya selain Yahya bin Abu Bukair dari Syarik.'"},"2450":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُمَرَ بْنِ الْوَلِيدِ الْكِنْدِيُّ الْكُوفِيُّ حَدَّثَنَا الْمُفَضَّلُ بْنُ صَالِحٍ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اشْتَكَتْ النَّارُ إِلَى رَبِّهَا وَقَالَتْ أَكَلَ بَعْضِي بَعْضًا فَجَعَلَ لَهَا نَفَسَيْنِ نَفَسًا فِي الشِّتَاءِ وَنَفَسًا فِي الصَّيْفِ فَأَمَّا نَفَسُهَا فِي الشِّتَاءِ فَزَمْهَرِيرٌ وَأَمَّا نَفَسُهَا فِي الصَّيْفِ فَسَمُومٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ صَحِيحٌ قَدْ رُوِيَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ غَيْرِ وَجْهٍ وَالْمُفَضَّلُ بْنُ صَالِحٍ لَيْسَ عِنْدَ أَهْلِ الْحَدِيثِ بِذَلِكَ الْحَافِظِ","id":"Telah menceritakan kepada kami [Muhammad bin Umar bin al Walid al Kindi al Kufi] telah menceritakan kepada kami [al Mufadhdhal bin Shalih] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Neraka mengadu kepada Rabbnya seraya berkata; 'Sebagian anggotaku memakan sebagian anggota lainnya.' Lalu Allah menjadikan dua nafas untuknya, satu nafas di musim panas dan satu nafas di musim dingin. Adapun nafasnya di musim dingin maka (disebut) zamharir (angin dingin), sedangkan nafasnya di musim panas maka (disebut) samum (angin panas).\" Abu Isa berkata; 'Hadits ini hadits shahih, ia telah diriwayatkan dari Abu Hurairah dari Nabi shallallahu 'alaihi wasallam dari bukan satu jalur. Sedangkan al Mufadhdhal bin Shalih menurut ahli hadits pada jalur tersebut bukanlah hafidz.'"},"2451":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا شُعْبَةُ وَهِشَامٌ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَخْرُجُ مِنْ النَّارِ وَقَالَ شُعْبَةُ أَخْرِجُوا مِنْ النَّارِ مَنْ قَالَ لَا إِلَهَ إِلَّا اللَّهُ وَكَانَ فِي قَلْبِهِ مِنْ الْخَيْرِ مَا يَزِنُ شَعِيرَةً أَخْرِجُوا مِنْ النَّارِ مَنْ قَالَ لَا إِلَهَ إِلَّا اللَّهُ وَكَانَ فِي قَلْبِهِ مِنْ الْخَيْرِ مَا يَزِنُ بُرَّةً أَخْرِجُوا مِنْ النَّارِ مَنْ قَالَ لَا إِلَهَ إِلَّا اللَّهُ وَكَانَ فِي قَلْبِهِ مِنْ الْخَيْرِ مَا يَزِنُ ذَرَّةًو قَالَ شُعْبَةُ مَا يَزِنُ ذُرَةً مُخَفَّفَةً وَفِي الْبَاب عَنْ جَابِرٍ وَأَبِي سَعِيدٍ وَعِمْرَانَ بْنِ حُصَيْنٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kamu [Abu Daud] telah menceritakan kepada kami [Syu'bah] dan [Hisyam] dari [Qatadah] dari [Anas] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan keluar dari neraka -sedangkan Syu'bah mengungkapkan; 'Keluarkanlah dari neraka'- orang yang mengucapkan, La Ilaha illa Allah (tidak ada tuhan yang berhak disembah selain Allah) sedangkan di dalam hatinya terdapat sebagian dari kebaikan yang setara dengan biji gandum (sya'irah). Keluarkanlah dari neraka orang yang mengucapkan, La Ilaha illa Allah (tidak ada tuhan yang berhak disembah selain Allah) sedangkan di dalam hatinya terdapat sebagian dari kebaikan yang setara dengan biji gandum (burrah). Keluarkanlah dari neraka orang yang mengucapkan, La Ilaha illa Allah (tidak ada tuhan yang berhak disembah selain Allah) sedangkan di dalam hatinya terdapat sebagian dari kebaikan yang setara dengan biji gandum (dzarrah).\" Syu'bah berkata; \"Sesuatu yang setara dengan timbangan dzurrah yang ringan.\" Dan dalam bab tersebut dari Jabir dan Abu Sa'id serta Imran bin Hushain, Abu Isa berkata; 'Ini hadits hasan shahih.\""},"2452":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا أَبُو دَاوُدَ عَنْ مُبَارَكِ بْنِ فَضَالَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي بَكْرِ بْنِ أَنَسٍ عَنْ أَنَسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَقُولُ اللَّهُ أَخْرِجُوا مِنْ النَّارِ مَنْ ذَكَرَنِي يَوْمًا أَوْ خَافَنِي فِي مَقَامٍقَالَ هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Muhammad bin Rafi'] telah menceritakan kepada [Abu Daud] dari [Mubarak bin Fadlalah] dari [Ubaidullah bin Abu Bakar bin Anas] dari [Anas] dari Nabi shallallahu 'alaihi wasallam beliau berkata: \"Allah berfirman: 'Keluarkanlah dari neraka orang yang mengingat-Ku pada suatu hari atau takut kepada-Ku pada suatu tempat\". Dia berkata; \"Hadits ini hasan gharib\"."},"2453":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَبِيدَةَ السَّلْمَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي لَأَعْرِفُ آخِرَ أَهْلِ النَّارِ خُرُوجًا رَجُلٌ يَخْرُجُ مِنْهَا زَحْفًا فَيَقُولُ يَا رَبِّ قَدْ أَخَذَ النَّاسُ الْمَنَازِلَ قَالَ فَيُقَالُ لَهُ انْطَلِقْ فَادْخُلْ الْجَنَّةَ قَالَ فَيَذْهَبُ لِيَدْخُلَ فَيَجِدُ النَّاسَ قَدْ أَخَذُوا الْمَنَازِلَ فَيَرْجِعُ فَيَقُولُ يَا رَبِّ قَدْ أَخَذَ النَّاسُ الْمَنَازِلَ قَالَ فَيُقَالُ لَهُ أَتَذْكُرُ الزَّمَانَ الَّذِي كُنْتَ فِيهِ فَيَقُولُ نَعَمْ فَيُقَالُ لَهُ تَمَنَّ قَالَ فَيَتَمَنَّى فَيُقَالُ لَهُ فَإِنَّ لَكَ مَا تَمَنَّيْتَ وَعَشْرَةَ أَضْعَافِ الدُّنْيَا قَالَ فَيَقُولُ أَتَسْخَرُ بِي وَأَنْتَ الْمَلِكُ قَالَ فَلَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضَحِكَ حَتَّى بَدَتْ نَوَاجِذُهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Abu Mu'awiyah] dari [al A'masy] dari [Ibrahim] dari [Abidah as Salmani] dari [Abdullah bin Mas'ud] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya aku mengetahui penduduk neraka yang paling terakhir keluar, dia adalah seorang laki-laki yang keluar darinya dalam keadaan merangkak seraya berkata; 'Wahai Rabbku manusia telah mengambil tempat-tempatnya'.\" Rasulullah berkata; \"Lalu diperintahkan kepadanya; 'Pergilah, lalu masuklah surga'. Lalu dia pergi untuk masuk surga, dan dia mendapatkan manusia telah mengambil tempat-tempat mereka. Maka dia kembali seraya berkata; 'Wahai Rabbku, manusia telah mengambil tempat-tempatnya (sedangkan saya tidak memiliki tempat).' Lalu diperintahkan kepadanya; 'Apakah kamu mengingat zaman yang mana kamu berada di masanya.' Dia menjawab; 'Ya'. Lalu dikatakan kepadanya; 'Berangan anganlah (untuk tempatmu).' Maka dia mengangan angankannya. Kemudian dikatakan kepadanya; 'Sesungguhnya kamu mendapatkan sesuatu yang telah kamu angan angankan dan sepuluh kali lipat dunia.' Maka dia berkata; 'Apakah Engkau mengejekku (dengan pahala yang melimpah ini), sedangkan Engkau adalah Raja Diraja.'\" Perawi berkata; 'Sungguh aku telah melihat Rasulullah shallallahu 'alaihi wasallam tertawa sehingga tampaklah gigi gerahamnya.\" Abu Isa berkata; 'Hadits ini adalah hadits hasan shahih.\""},"2454":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ الْمَعْرُورِ بْنِ سُوَيْدٍ عَنْ أَبِي ذَرٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي لَأَعْرِفُ آخِرَ أَهْلِ النَّارِ خُرُوجًا مِنْ النَّارِ وَآخِرَ أَهْلِ الْجَنَّةِ دُخُولًا الْجَنَّةَ يُؤْتَى بِرَجُلٍ فَيَقُولُ سَلُوا عَنْ صِغَارِ ذُنُوبِهِ وَاخْبَئُوا كِبَارَهَا فَيُقَالُ لَهُ عَمِلْتَ كَذَا وَكَذَا يَوْمَ كَذَا وَكَذَا عَمِلْتَ كَذَا وَكَذَا فِي يَوْمِ كَذَا وَكَذَا قَالَ فَيُقَالُ لَهُ فَإِنَّ لَكَ مَكَانَ كُلِّ سَيِّئَةٍ حَسَنَةً قَالَ فَيَقُولُ يَا رَبِّ لَقَدْ عَمِلْتُ أَشْيَاءَ مَا أَرَاهَا هَا هُنَا قَالَ فَلَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضَحِكَ حَتَّى بَدَتْ نَوَاجِذُهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Abu Mu'awiyah] dari [al A'masy] dari [al Ma'rur bin Suwaid] dari [Abu Dzarr] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: Sesungguhnya aku mengetahui penduduk neraka yang paling terakhir keluar dari neraka dan penduduk surga yang paling terakhir masuk surga. (Pada hari kiamat) seorang laki-laki didatangkan, lalu Dia berfirman; 'Tanyakanlah kepadanya tentang dosa-dosa kecilnya, dan sembunyikanlah dosa-dosa besarnya.' Maka ditanyakan kepadanya; '(Apakah) kamu mengetahui peristiwa demikian dan demikian pada hari demikian dan demikian, (Apakah) kamu mengetahui peristiwa demikian dan demikian pada hari demikian dan demikian? ' Lalu dikatakan kepadanya; 'Sesungguhnya kamu mendapatkan pahala tempat segala kejelekan diganti menjadi kebaikan.' Lelaki tersebut berkata; '(benar) wahai Rabbku, sungguh saya telah mengetahui berbagai hal yang telah saya lihat di sini.'\" Perawi berkata; 'Sungguh aku telah melihat Rasulullah shallallahu 'alaihi wasallam tertawa sehingga tampaklah gigi gerahamnya.\" Abu Isa berkata; 'Hadits ini adalah hadits hasan shahih.\""},"2455":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعَذَّبُ نَاسٌ مِنْ أَهْلِ التَّوْحِيدِ فِي النَّارِ حَتَّى يَكُونُوا فِيهَا حُمَمًا ثُمَّ تُدْرِكُهُمْ الرَّحْمَةُ فَيُخْرَجُونَ وَيُطْرَحُونَ عَلَى أَبْوَابِ الْجَنَّةِ قَالَ فَيَرُشُّ عَلَيْهِمْ أَهْلُ الْجَنَّةِ الْمَاءَ فَيَنْبُتُونَ كَمَا يَنْبُتُ الْغُثَاءُ فِي حِمَالَةِ السَّيْلِ ثُمَّ يَدْخُلُونَ الْجَنَّةَقَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ جَابِرٍ","id":"Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Abu Mu'awiyah] dari [al A'masy] dari [Abu Sufyan] dari [Jabir] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Segolongan orang dari ahli tauhid diadzab di neraka sehingga mereka menjadi abu, kemudian mereka mendapatkan rahmat, lalu mereka dikeluarkan dan diletakkan di depan pintu surga.' Rasulullah berkata; 'Lalu penduduk surga menyiramkan air kepada mereka, maka mereka tumbuh kembali sebagaimana buih tumbuh dalam sesuatu yang dibawa aliran air, kemudian mereka masuk surga.\" Abu Isa berkata; 'Hadits ini hadits hasan shahih, ia telah diriwayatkan dari berbagai jalur dari Jabir.'"},"2456":{"ar":"حَدَّثَنَا سَلَمَةُ بْنُ شَبِيبٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُخْرَجُ مِنْ النَّارِ مَنْ كَانَ فِي قَلْبِهِ مِثْقَالُ ذَرَّةٍ مِنْ الْإِيمَانِقَالَ أَبُو سَعِيدٍ فَمَنْ شَكَّ فَلْيَقْرَأْ{ إِنَّ اللَّهَ لَا يَظْلِمُ مِثْقَالَ ذَرَّةٍ }قَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Salamah bin Syabib] telah menceritakan kepada kami [Abdurrazzaq] telah mengabarkan kepada kami [Ma'mar] dari [Zaid bin Aslam] dari [Atha' bin Yasar] dari [Abu Sa'id al Khudzri] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Akan keluar dari neraka, orang yang di dalam hatinya terdapat iman seberat gandum.\" Abu Sa'id berkata; \"Barangsiapa yang ragu-ragu maka hendaklah dia membaca, 'Sesungguhnya Allah tidak akan menzhalimi (walaupun kebaikan) seberat biji gandum.\" Abu Isa berkata; 'Hadits ini hadits hasan shahih.'"},"2457":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ نَصْرٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا رِشْدِينُ حَدَّثَنِي ابْنُ أَنْعُمَ عَنْ أَبِي عُثْمَانَ أَنَّهُ حَدَّثَهُ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ رَجُلَيْنِ مِمَّنْ دَخَلَ النَّارَ اشْتَدَّ صِيَاحُهُمَا فَقَالَ الرَّبُّ عَزَّ وَجَلَّ أَخْرِجُوهُمَا فَلَمَّا أُخْرِجَا قَالَ لَهُمَا لِأَيِّ شَيْءٍ اشْتَدَّ صِيَاحُكُمَا قَالَا فَعَلْنَا ذَلِكَ لِتَرْحَمَنَا قَالَ إِنَّ رَحْمَتِي لَكُمَا أَنْ تَنْطَلِقَا فَتُلْقِيَا أَنْفُسَكُمَا حَيْثُ كُنْتُمَا مِنْ النَّارِ فَيَنْطَلِقَانِ فَيُلْقِي أَحَدُهُمَا نَفْسَهُ فَيَجْعَلُهَا عَلَيْهِ بَرْدًا وَسَلَامًا وَيَقُومُ الْآخَرُ فَلَا يُلْقِي نَفْسَهُ فَيَقُولُ لَهُ الرَّبُّ عَزَّ وَجَلَّ مَا مَنَعَكَ أَنْ تُلْقِيَ نَفْسَكَ كَمَا أَلْقَى صَاحِبُكَ فَيَقُولُ يَا رَبِّ إِنِّي لَأَرْجُو أَنْ لَا تُعِيدَنِي فِيهَا بَعْدَ مَا أَخْرَجْتَنِي فَيَقُولُ لَهُ الرَّبُّ لَكَ رَجَاؤُكَ فَيَدْخُلَانِ جَمِيعًا الْجَنَّةَ بِرَحْمَةِ اللَّهِقَالَ أَبُو عِيسَى إِسْنَادُ هَذَا الْحَدِيثِ ضَعِيفٌ لِأَنَّهُ عَنْ رِشْدِينَ بْنِ سَعْدٍ وَرِشْدِينُ بْنُ سَعْدٍ هُوَ ضَعِيفٌ عِنْدَ أَهْلِ الْحَدِيثِ عَنْ ابْنِ أَنْعُمَ وَهُوَ الْأَفْرِيقِيُّ وَالْأَفْرِيقِيُّ ضَعِيفٌ عِنْدَ أَهْلِ الْحَدِيثِ","id":"Telah menceritakan kepada kami [Suwaid bin Nashr] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Risydin] telah menceritakan kepadaku [Ibnu An'um] dari [Abu Utsman] bahwa dia menceritakan kepadanya dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam; \"Sesunguhnya ada dua orang yang masuk ke dalam neraka, keduanya menjerit dengan suara keras, maka Rabb 'azza wajalla memerintahkan (kepada Malaikat Zabaniyah): 'Keluarkanlah keduanya! ' Setelah keduanya dikeluarkan, maka Allah bertanya kepada keduanya: 'Untuk apa kalian berdua menjerit dengan suara keras? ' Keduanya menjawab; 'Kami melakukan demikian agar supaya Engkau mengasihani kami, ' kemudian Allah berfirman, 'Sesungguhnya rahmat-Ku untuk kalian berdua, hendaklah kalian berdua pergi lalu menceburkan diri kalian di tempat kalian dahulu berada dalam neraka, ' maka keduanya pergi, dan salah seorang dari keduanya menceburkan dirinya ke dalam neraka, namun Allah menjadikannya dingin dan selamat atasnya, sedangkan yang lain tetap berdiri dan tidak menceburkan dirinya, kemudian Allah 'azza wajalla bertanya kepadanya; 'Apa yang menghalangimu untuk menceburkan dirimu sebagaimana temanmu telah menceburkan dirinya? ' dia menjawab; 'Wahai Rabbku sesungguhnya aku sangat mengharap agar supaya Engkau tidak mengembalikanku ke dalamnya (neraka) setelah Engkau keluarkan aku darinya.' Maka Allah berfirman: 'Kamu mendapatkan apa yang kamu harapkan.' Kemudian keduanya masuk Surga dengan rahmat Allah\". Abu Isa berkata; 'Isnad hadits ini lemah, karena ia berasal dari Risydin bin Sa'ad. Sedangkan Risydin bin Sa'ad adalah seorang yang dhaif (lemah) menurut ahli hadits dari Ibnu An'um, karena dia seorang warga Afrika, sedangkan orang Afrika adalah dhaif menurut ahli hadits.'"},"2458":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا الْحَسَنُ بْنُ ذَكْوَانَ عَنْ أَبِي رَجَاءٍ الْعُطَارِدِيِّ عَنْ عِمْرَانَ بْنِ حُصَيْنٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيَخْرُجَنَّ قَوْمٌ مِنْ أُمَّتِي مِنْ النَّارِ بِشَفَاعَتِي يُسَمَّوْنَ الْجَهَنَّمِيُّونَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَأَبُو رَجَاءٍ الْعُطَارِدِيُّ اسْمُهُ عِمْرَانُ بْنُ تَيْمٍ وَيُقَالُ ابْنُ مِلْحَانَ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami [Al Hasan bin Dzakwan] dari [Abu Raja' Al 'Utharidi] dari [Imran bin Hushain] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Suatu kaum dari Ummatku pasti akan keluar dari neraka dengan Syafa'atku, mereka dinamakan al Jahannamiyyun (orang-orang neraka jahannam) \". Abu Isa berkata; 'Hadits ini hasan shahih, adapun Abu Raja' al 'Utharidi namanya adalah Imran bin Taim, dan dinamakan juga Ibnu Milhan.'"},"2459":{"ar":"حَدَّثَنَا سُوَيْدٌ أَخْبَرَنَا عَبْدُ اللَّهِ عَنْ يَحْيَى بْنِ عُبَيْدِ اللَّهِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا رَأَيْتُ مِثْلَ النَّارِ نَامَ هَارِبُهَا وَلَا مِثْلَ الْجَنَّةِ نَامَ طَالِبُهَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ إِنَّمَا نَعْرِفُهُ مِنْ حَدِيثِ يَحْيَى بْنِ عُبَيْدِ اللَّهِ وَيَحْيَى بْنُ عُبَيْدِ اللَّهِ ضَعِيفٌ عِنْدَ أَكْثَرِ أَهْلِ الْحَدِيثِ تَكَلَّمَ فِيهِ شُعْبَةُ وَيَحْيَى بْنُ عُبَيْدِ اللَّهِ هُوَ ابْنُ مَوْهَبٍ وَهُوَ مَدَنِيٌّ","id":"Telah menceritakan kepada kami [Suwaid] telah mengabarkan kepada kami [Abdullah] dari [Yahya bin Ubaidillah] dari [bapaknya] dari [Abu Hurairah] dia berkata Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku tidak melihat seperti (ketakutan yang berlebihan terhadap) api neraka (membuat) tidur orang yang ingin lari darinya. Dan aku tidak melihat seperti (kesungguhan menuju) surga membuat tidur orang yang mencari surga.\" Abu Isa berkata; 'Kami hanya mengetahui hadits ini dari hadits Yahya bin Ubaidillah, sedangkan Yahya bin Ubaidillah adalah lemah menurut kebanyakan ahli hadits di mana Syu'bah telah membicarakannya, dan Yahya bin Ubaidillah adalah Ibnu Mauhab, dan dia orang Madinah\"."},"2460":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي رَجَاءٍ الْعُطَارِدِيِّ قَال سَمِعْتُ ابْنَ عَبَّاسٍ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اطَّلَعْتُ فِي الْجَنَّةِ فَرَأَيْتُ أَكْثَرَ أَهْلِهَا الْفُقَرَاءَ وَاطَّلَعْتُ فِي النَّارِ فَرَأَيْتُ أَكْثَرَ أَهْلِهَا النِّسَاءَ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Ismail bin Ibrahim] telah menceritakan kepada kami [Ayyub] dari [Abu Raja' al Utharidi], dia berkata, aku mendengar [Ibnu Abbas] berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Saya memperhatikan surga, maka saya melihat mayoritas penduduknya adalah kaum fakir, dan saya memeriksa neraka, maka saya melihat mayoritas penduduknya adalah kaum wanita.\""},"2461":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ وَمُحَمَّدُ بْنُ جَعْفَرٍ وَعَبْدُ الْوَهَّابِ الثَّقَفِيُّ قَالُوا حَدَّثَنَا عَوْفٌ هُوَ ابْنُ أَبِي جَمِيلَةَ عَنْ أَبِي رَجَاءٍ الْعُطَارِدِيِّ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اطَّلَعْتُ فِي النَّارِ فَرَأَيْتُ أَكْثَرَ أَهْلِهَا النِّسَاءَ وَاطَّلَعْتُ فِي الْجَنَّةِ فَرَأَيْتُ أَكْثَرَ أَهْلِهَا الْفُقَرَاءَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَهَكَذَا يَقُولُ عَوْفٌ عَنْ أَبِي رَجَاءٍ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ وَيَقُولُ أَيُّوبُ عَنْ أَبِي رَجَاءٍ عَنْ ابْنِ عَبَّاسٍ وَكِلَا الْإِسْنَادَيْنِ لَيْسَ فِيهِمَا مَقَالٌ وَيُحْتَمَلُ أَنْ يَكُونَ أَبُو رَجَاءٍ سَمِعَ مِنْهُمَا جَمِيعًا وَقَدْ رَوَى غَيْرُ عَوْفٍ أَيْضًا هَذَا الْحَدِيثَ عَنْ أَبِي رَجَاءٍ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Ibnu Abi 'Adi] dan [Muhammad bin Ja'far] serta [Abdul Wahhab ats Tsaqafi] mereka berkata, telah menceritakan kepada kami [Auf], dan dia adalah Ibnu Abi Jamilah, dari [Abu Raja' al Utharidi] dari [Imran bin Hushain] dia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Saya memperhatikan neraka, maka saya melihat mayoritas penduduknya adalah kaum wanita, dan saya memmperhatikan surga, maka saya melihat mayoritas penduduknya adalah kaum fakir.\" Abu Isa berkata; 'Ini hadits hasan shahih. Demikianlah Auf berkata dari Abu Raja' dari Imran bin Hushain. Dan [Ayyub] berkata dari [Abu Raja'] dari [Ibnu Abbas]. Dan kedua sanadnya tidak terdapat pembicaraan di dalamnya. Dan mengandung kemungkinan bahwa Abu Raja' mendengar hadits tersebut dari kedua jalur itu semua. Selain Auf juga telah meriwayatkan hadits ini dari Abu Raja' dari Imran bin Hushain.'"},"2462":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ عَنْ شُعْبَةَ عَنْ أَبِي إِسْحَقَ عَنْ النُّعْمَانِ بْنِ بَشِيرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ أَهْوَنَ أَهْلِ النَّارِ عَذَابًا يَوْمَ الْقِيَامَةِ رَجُلٌ فِي أَخْمَصِ قَدَمَيْهِ جَمْرَتَانِ يَغْلِي مِنْهُمَا دِمَاغُهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَفِي الْبَاب عَنْ الْعَبَّاسِ بْنِ عَبْدِ الْمُطَّلِبِ وَأَبِي سَعِيدٍ الْخُدْرِيِّ وَأَبِي هُرَيْرَةَ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Wahab bin Jarir] dari [Syu'bah] dari [Abu Ishaq] dari [an Nu'man bin Basyir] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya penduduk neraka yang adzabnya paling ringan pada hari kiamat adalah seorang laki-laki di mana pada tumit kedua kakinya terdapat dua bara api yang membuat otoknya mendidih disebabkan keduanya.\"Abu Isa berkata; 'Ini hadits hasan shahih. Dan dalam bab tersebut (juga diriwayatkan) dari al Abbas bin Abdul Muththalib dan Abu Sa'id al Khudri, serta Abu Hurairah.'"},"2463":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ مَعْبَدِ بْنِ خَالِدٍ قَال سَمِعْتُ حَارِثَةَ بْنَ وَهْبٍ الْخُزَاعِيَّ يَقُولُسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَلَا أُخْبِرُكُمْ بِأَهْلِ الْجَنَّةِ كُلُّ ضَعِيفٍ مُتَضَعِّفٍ لَوْ أَقْسَمَ عَلَى اللَّهِ لَأَبَرَّهُ أَلَا أُخْبِرُكُمْ بِأَهْلِ النَّارِ كُلُّ عُتُلٍّ جَوَّاظٍ مُتَكَبِّرٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Ma'bad bin Khalid] dia berkata, 'Saya mendengar [Haritsah bin Wahb al Khuza'i] berkata; Saya mendengar Nabi Shallallahu 'Alaihi Wasalam bersabda: \"Maukah kalian aku kabarkan tentang penduduk surga, yaitu setiap orang yang lemah lagi dilemahkan (diremehkan), kalau dia bersumpah (dengan nama Allah atas sesuatu) kepada Allah, niscaya Dia akan membaikinya (mengabulkannya). Maukah kalian aku beritahukan tentang penduduk neraka, yaitu setiap orang yang zhalim, keras lagi sombong.\" Abu Isa berkata; 'Ini hadits hasan shahih.'"},"2464":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُمِرْتُ أَنْ أُقَاتِلَ النَّاسَ حَتَّى يَقُولُوا لَا إِلَهَ إِلَّا اللَّهُ فَإِذَا قَالُوهَا مَنَعُوا مِنِّي دِمَاءَهُمْ وَأَمْوَالَهُمْ إِلَّا بِحَقِّهَا وَحِسَابُهُمْ عَلَى اللَّهِوَفِي الْبَاب عَنْ جَابِرٍ وَأَبِي سَعِيدٍ وَابْنِ عُمَرَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Abu Mu'awiyah] dari [al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Saya diperintahkan untuk memerangi manusia hingga mereka mengucapkan; 'Tidak ada tuhan (yang berhak disembah) selain Allah', apabila mereka mengucapkannya, maka mereka telah menghalangiku (untuk menumpahkan) darah dan (merampas) harta mereka, kecuali dengan haknya, sedangkan (apabila mereka menyembunyikan kekafiran dan kemaksiatan) maka Allah-lah yang menghisab mereka.\" Dan dalam bab tersebut (juga diriwayatkan) dari Jabir dan Abu Sa'id dan Ibnu Umar. Abu Isa berkata; 'Ini hadits hasan shahih.'"},"2465":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ الزُّهْرِيِّ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍ عَنْ أَبِي هُرَيْرَةَ قَالَلَمَّا تُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاسْتُخْلِفَ أَبُو بَكْرٍ بَعْدَهُ كَفَرَ مَنْ كَفَرَ مِنْ الْعَرَبِ فَقَالَ عُمَرُ بْنُ الْخَطَّابِ لِأَبِي بَكْرٍ كَيْفَ تُقَاتِلُ النَّاسَ وَقَدْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُمِرْتُ أَنْ أُقَاتِلَ النَّاسَ حَتَّى يَقُولُوا لَا إِلَهَ إِلَّا اللَّهُ وَمَنْ قَالَ لَا إِلَهَ إِلَّا اللَّهُ عَصَمَ مِنِّي مَالَهُ وَنَفْسَهُ إِلَّا بِحَقِّهِ وَحِسَابُهُ عَلَى اللَّهِ قَالَ أَبُو بَكْرٍ وَاللَّهِ لَأُقَاتِلَنَّ مَنْ فَرَّقَ بَيْنَ الزَّكَاةِ وَالصَّلَاةِ وَإِنَّ الزَّكَاةَ حَقُّ الْمَالِ وَاللَّهِ لَوْ مَنَعُونِي عِقَالًا كَانُوا يُؤَدُّونَهُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقَاتَلْتُهُمْ عَلَى مَنْعِهِفَقَالَ عُمَرُ بْنُ الْخَطَّابِ فَوَاللَّهِ مَا هُوَ إِلَّا أَنْ رَأَيْتُ أَنَّ اللَّهَ قَدْ شَرَحَ صَدْرَ أَبِي بَكْرٍ لِلْقِتَالِ فَعَرَفْتُ أَنَّهُ الْحَقُّ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَهَكَذَا رَوَى شُعَيْبُ بْنُ أَبِي حَمْزَةَ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي هُرَيْرَةَ وَرَوَى عِمْرَانُ الْقَطَّانُ هَذَا الْحَدِيثَ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ عَنْ أَبِي بَكْرٍ وَهُوَ حَدِيثٌ خَطَأٌ وَقَدْ خُولِفَ عِمْرَانُ فِي رِوَايَتِهِ عَنْ مَعْمَرٍ","id":"Telah menceritakan kepada kami [Qutaibah], telah menceritakan kepada kami [al Laits] dari [Uqail] dari [az Zuhri] telah mengabarkan kepadaku [Ubaidullah bin Abdullah bin Utbah bin Mas'ud] dari [Abu Hurairah] dia berkata, Ketika Rasulullah shallallahu 'alaihi wasallam wafat, Abu Bakar menggantikan beliau menjadi khalifah, maka kafirlah orang yang kafir dari kalangan orang Arab, [Umar bin al Khaththab] berkata kepada Abu Bakar; 'Bagaimana bisa kamu memerangi manusia, sedangkan Rasulullah shallallahu 'alaihi wasallam telah bersabda: 'Saya diperintahkan untuk memerangi manusia hingga mereka mengucapkan; 'Tidak ada tuhan (yang berhak disembah) selain Allah'. Dan barangsiapa yang mengucapan, 'Tidak ada tuhan (yang berhak disembah) selain Allah' maka dia telah terlindungi harta dan jiwanya dariku, kecuali dengan haknya, sedangkan (apabila mereka menyembunyikan kekafiran dan kemaksiatan) maka Allah-lah yang menghisab mereka.\" Maka [Abu Bakar] menjawab; 'Demi Allah, Saya akan memerangi orang yang membedakan antara zakat dan shalat, karena zakat adalah hak harta. Demi Allah, jika mereka menolakku untuk membayar seikat tali unta yang dulu mereka membayarkannya kepada Rasulullah shallallahu 'alaihi wasallam, niscaya Aku akan memerangi mereka atas pembangkangannya.' Maka Umar bin al Khaththab berkata, 'Demi Allah, tidaklah kebijakannya yang demikian itu melainkan karena Allah telah melapangkan dada Abu Bakar untuk memerangi mereka. Maka saya mengetahui bahwa dia benar'. Abu Isa berkata; 'Ini hadits hasan shahih. Demikianlah [Syu'aib bin Abi Hamzah] meriwayatkannya dari [az Zuhri] dari [Ubaidullah bin Abdillah] dari [Abu Hurairah]. Dan Imran al Qaththan meriwayatkan hadits ini dari Ma'mar dari az Zuhri dari Anas bin Malik dari Abu Bakar, dan ia merupakan hadits yang salah. Imran telah diselisihi (oleh ulama) dalam periwayatannya dari Ma'mar.\""},"2466":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ يَعْقُوبَ الطَّالِقَانِيُّ حَدَّثَنَا ابْنُ الْمُبَارَكِ أَخْبَرَنَا حُمَيْدٌ الطَّوِيلُ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُمِرْتُ أَنْ أُقَاتِلَ النَّاسَ حَتَّى يَشْهَدُوا أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ وَأَنْ يَسْتَقْبِلُوا قِبْلَتَنَا وَيَأْكُلُوا ذَبِيحَتَنَا وَأَنْ يُصَلُّوا صَلَاتَنَا فَإِذَا فَعَلُوا ذَلِكَ حُرِّمَتْ عَلَيْنَا دِمَاؤُهُمْ وَأَمْوَالُهُمْ إِلَّا بِحَقِّهَا لَهُمْ مَا لِلْمُسْلِمِينَ وَعَلَيْهِمْ مَا عَلَى الْمُسْلِمِينَوَفِي الْبَاب عَنْ مُعَاذِ بْنِ جَبَلٍ وَأَبِي هُرَيْرَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَقَدْ رَوَاهُ يَحْيَى بْنُ أَيُّوبَ عَنْ حُمَيْدٍ عَنْ أَنَسٍ نَحْوَ هَذَا","id":"Telah menceritakan kepada kami [Sa'id bin Ya'kub ath Thaliqani] telah menceritakan kepada kami [Ibnu al Mubarak] telah mengabarkan kepada kami [Humaid ath Thawil] dari [Anas bin Malik] dia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Saya diperintahkan untuk memerangi manusia hingga mereka mengucapkan, 'Tidak ada tuhan (yang berhak disembah) selain Allah dan bahwa Muhammad adalah hamba dan Rasul-Nya, dan menghadap kiblat kami, dan memakan sembelihan kami, dan melakukan shalat dengan shalat kami, apabila mereka melakukan hal tersebut, niscaya kami diharamkan (menumpahkan) darah dan harta mereka, kecuali dengan haknya. Mereka mendapatkan hak sebagaimana hak kaum muslimin, dan mereka berkewajiban sebagaimana kewajibannya kaum muslimin.\" Dan dalam bab tersebut (juga diriwayatkan) dari Mu'adz bin Jabal dan Abu Hurairah. Abu Isa berkata; 'Ini hadits hasan shahih gharib dari jalur ini. [Yahya bin Ayyub] telah meriwayatkannya dari [Humaid] dari [Anas] hadits seperti itu.'"},"2467":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ سُعَيْرِ بْنِ الْخِمْسِ التَّمِيمِيِّ عَنْ حَبيِبِ بْنِ أَبِي ثَابِتٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بُنِيَ الْإِسْلَامُ عَلَى خَمْسٍ شَهَادَةِ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ وَإِقَامِ الصَّلَاةِ وَإِيتَاءِ الزَّكَاةِ وَصَوْمِ رَمَضَانَ وَحَجِّ الْبَيْتِوَفِي الْبَاب عَنْ جَرِيرِ بْنِ عَبْدِ اللَّهِ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ هَذَا وَسُعَيْرُ بْنُ الْخِمْسِ ثِقَةٌ عِنْدَ أَهْلِ الْحَدِيثِ حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا وَكِيعٌ عَنْ حَنْظَلَةَ بْنِ أَبِي سُفْيَانَ الْجُمَحِيِّ عَنْ عِكْرِمَةَ بْنِ خَالِدٍ الْمَخْزُومِيِّ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ibnu Abi Umar], telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Su'air bin al Khims at Tamimi] dari [Habib bin Abi Tsabit] dari [Ibnu Umar] dia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Islam dibangun atas lima dasar: persaksian bahwa tidak ada tuhan (yang berhak disembah) selain Allah, dan bahwa Muhammad utusan Allah, mendirikan shalat, menunaikan zakat, berpuasa Ramadhan, dan haji ke Baitullah.\" Dan dalam bab tersebut (juga diriwayatkan) dari Jarir bin Abdullah. Abu Isa berkata; 'Ini hadits hasan shahih. Dan ia telah diriwayatkan dari bukan hanya satu jalan, dari Ibnu Umar, dari Nabi Shallallahu 'Alaihi Wasalam seperti ini. Sedangkan Su'air bin al Khims adalah seorang yang tsiqah menurut ahli hadits. [Abu Kuraib] menceritakan kepada kami, [Waki'] telah menceritakan kepada kami, dari [Hanzhalah bin Abi Sufyan al Jumahi], dari [Ikrimah bin Khalid al Makhzumi] dari [Ibnu Umar] dari Nabi Shallallahu 'Alaihi Wasalam semisalnya.\" Abu Isa berkata; 'Ini hadits hasan shahih.'"},"2468":{"ar":"حَدَّثَنَا أَبُو عَمَّارٍ الْحُسَيْنُ بْنُ حُرَيْثٍ الْخُزَاعِيُّ أَخْبَرَنَا وَكِيعٌ عَنْ كَهْمَسِ بْنِ الْحَسَنِ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ يَحْيَى بْنِ يَعْمَرَ قَالَأَوَّلُ مَنْ تَكَلَّمَ فِي الْقَدَرِ مَعْبَدٌ الْجُهَنِيُّ قَالَ فَخَرَجْتُ أَنَا وَحُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ الْحِمْيَرِيُّ حَتَّى أَتَيْنَا الْمَدِينَةَ فَقُلْنَا لَوْ لَقِينَا رَجُلًا مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلْنَاهُ عَمَّا أَحْدَثَ هَؤُلَاءِ الْقَوْمُ قَالَ فَلَقِينَاهُ يَعْنِي عَبْدَ اللَّهِ بْنَ عُمَرَ وَهُوَ خَارِجٌ مِنْ الْمَسْجِدِ قَالَ فَاكْتَنَفْتُهُ أَنَا وَصَاحِبِي قَالَ فَظَنَنْتُ أَنَّ صَاحِبِي سَيَكِلُ الْكَلَامَ إِلَيَّ فَقُلْتُ يَا أَبَا عَبْدِ الرَّحْمَنِ إِنَّ قَوْمًا يَقْرَءُونَ الْقُرْآنَ وَيَتَقَفَّرُونَ الْعِلْمَ وَيَزْعُمُونَ أَنْ لَا قَدَرَ وَأَنَّ الْأَمْرَ أُنُفٌ قَالَ فَإِذَا لَقِيتَ أُولَئِكَ فَأَخْبِرْهُمْ أَنِّي مِنْهُمْ بَرِيءٌ وَأَنَّهُمْ مِنِّي بُرَءَاءُ وَالَّذِي يَحْلِفُ بِهِ عَبْدُ اللَّهِ لَوْ أَنَّ أَحَدَهُمْ أَنْفَقَ مِثْلَ أُحُدٍ ذَهَبًا مَا قُبِلَ ذَلِكَ مِنْهُ حَتَّى يُؤْمِنَ بِالْقَدَرِ خَيْرِهِ وَشَرِّهِ قَالَ ثُمَّ أَنْشَأَ يُحَدِّثُ فَقَالَ قَالَ عُمَرُ بْنُ الْخَطَّابِ كُنَّا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ رَجُلٌ شَدِيدُ بَيَاضِ الثِّيَابِ شَدِيدُ سَوَادِ الشَّعَرِ لَا يُرَى عَلَيْهِ أَثَرُ السَّفَرِ وَلَا يَعْرِفُهُ مِنَّا أَحَدٌ حَتَّى أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَلْزَقَ رُكْبَتَهُ بِرُكْبَتِهِ ثُمَّ قَالَ يَا مُحَمَّدُ مَا الْإِيمَانُ قَالَ أَنْ تُؤْمِنَ بِاللَّهِ وَمَلَائِكَتِهِ وَكُتُبِهِ وَرُسُلِهِ وَا��ْيَوْمِ الْآخِرِ وَالْقَدَرِ خَيْرِهِ وَشَرِّهِ قَالَ فَمَا الْإِسْلَامُ قَالَ شَهَادَةُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ وَإِقَامُ الصَّلَاةِ وَإِيتَاءُ الزَّكَاةِ وَحَجُّ الْبَيْتِ وَصَوْمُ رَمَضَانَ قَالَ فَمَا الْإِحْسَانُ قَالَ أَنْ تَعْبُدَ اللَّهَ كَأَنَّكَ تَرَاهُ فَإِنَّكَ إِنْ لَمْ تَكُنْ تَرَاهُ فَإِنَّهُ يَرَاكَ قَالَ فِي كُلِّ ذَلِكَ يَقُولُ لَهُ صَدَقْتَ قَالَ فَتَعَجَّبْنَا مِنْهُ يَسْأَلُهُ وَيُصَدِّقُهُ قَالَ فَمَتَى السَّاعَةُ قَالَ مَا الْمَسْئُولُ عَنْهَا بِأَعْلَمَ مِنْ السَّائِلِ قَالَ فَمَا أَمَارَتُهَا قَالَ أَنْ تَلِدَ الْأَمَةُ رَبَّتَهَا وَأَنْ تَرَى الْحُفَاةَ الْعُرَاةَ الْعَالَةَ أَصْحَابَ الشَّاءِ يَتَطَاوَلُونَ فِي الْبُنْيَانِ قَالَ عُمَرُ فَلَقِيَنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ ذَلِكَ بِثَلَاثٍ فَقَالَ يَا عُمَرُ هَلْ تَدْرِي مَنْ السَّائِلُ ذَاكَ جِبْرِيلُ أَتَاكُمْ يُعَلِّمُكُمْ مَعَالِمَ دِينِكُمْحَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ أَخْبَرَنَا ابْنُ الْمُبَارَكِ أَخْبَرَنَا كَهْمَسُ بْنُ الْحَسَنِ بِهَذَا الْإِسْنَادِ نَحْوَهُ حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا مُعَاذُ بْنُ مُعَاذٍ عَنْ كَهْمَسٍ بِهَذَا الْإِسْنَادِ نَحْوَهُ بِمَعْنَاهُ وَفِي الْبَاب عَنْ طَلْحَةَ بْنِ عُبَيْدِ اللَّهِ وَأَنَسِ بْنِ مَالِكٍ وَأَبِي هُرَيْرَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ قَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ نَحْوُ هَذَا عَنْ عُمَرَ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالصَّحِيحُ هُوَ ابْنُ عُمَرَ عَنْ عُمَرَ عَنْ النَّبِيِّ","id":"Telah menceritakan kepada kami [Abu Ammar al Husain bin Huraits al Khuza'i] telah mengabarkan kepada kami [Waki'] dari [Kahmas bin al Hasan] dari [Abdullah bin Buraidah] dari [Yahya bin Ya'mar] dia berkata; Orang yang pertama kali membahas ilmu kalam tentang takdir adalah Ma'bad al Juhani'. Yahya menuturkan; 'Aku keluar bersama Humaid bin Abdurrahman al Himyari, hingga kami mencapai Madinah, maka kami berkata; 'Kalau seandainya kami bertemu dengan seorang laki-laki dari sahabat Nabi shallallahu 'alaihi wasallam maka kami akan menanyakannya tentang sesuatu yang diceritakan oleh para kaum itu.' Yahya berkata, 'Maka kami menjumpainya, yakni [Abdullah bin Umar], sedangkan dia keluar dari masjid. Lalu aku dan temanku menghadangnya'. Aku mengira bahwa temanku akan mewakilkan pembicaraan kepadaku, maka aku berkata; 'Wahai Abu Abdurrahman, sesungguhnya suatu kaum membaca al Qur'an dan mencari ilmu lalu mengklaim bahwa tidak ada takdir, dan perkaranya adalah baru (tidak didahului oleh takdir dan ilmu Allah).' Maka Abdullah bin Umar menjawab; 'Apabila kamu bertemu orang-orang tersebut, maka khabarkanlah kepada mereka bahwa saya berlepas diri dari mereka, dan bahwa mereka berlepas diri dariku. Dan demi Dzat yang mana hamba Allah bersumpah denganNya, kalau seandainya salah seorang dari kalian menafkahkan emas seperti gunung Uhud, niscaya sedekahnya tidak akan diterima hingga dia beriman kepada takdir baik dan buruk.' Yahya berkata, 'Kemudian dia mulai menceritakan hadits seraya berkata; ['Umar bin al Khaththab] berkata; 'Dahulu kami pernah berada di sisi Rasulullah shallallahu 'alaihi wasallam, lalu datanglah seorang laki-laki yang bajunya sangat putih, rambutnya sangat hitam, tidak tampak padanya bekas bekas perjelanan. Tidak seorang pun dari kami mengenalnya, hingga dia mendatangi Nabi Shallallahu 'Alaihi Wasalam lalu menyandarkan lututnya pada lutut Nabi Shallallahu 'Alaihi Wasalam kemudian berkata, 'Wahai Muhammad, apakah iman itu? ' Beliau menjawab: \"Kamu beriman kepada Allah, malaikat-malaikat-Nya, kitab-kitab-Nya, hari akhir, dan takdir baik dan buruk.\" Dia bertanya; 'Apa itu Islam? ' Nabi Shallallahu 'Alaihi Wasalam menjawab: \"Kesaksian bahwa tidak ada tuhan (yang berhak disembah) selain Allah dan bahwa Muhammad hamba dan utusan Nya, mendirikan shalat, menunaikan zakat, melakukan haji, dan puasa Ramadhan.\" Dia bertanya; 'Apakah ihsan itu? ' Beliau menjawab: \"Kamu menyembah Allah seakan akan kamu melihat-Nya, maka jika kamu tidak melihat-Nya, maka sesungguhnya Dia melihatmu.\" Umar berkata; 'Pada setiap jawaban beliau dia mengatakan; 'Kamu benar.' Umar berkata; 'Maka kami heran kepadanya, dia bertanya kepada beliau lalu membenarkannya.' Dia bertanya lagi; 'Kapankah hari akhir itu? ' Beliau menjawab: \"Tidaklah orang yang ditanya itu lebih mengetahui daripada orang yang bertanya.\" Dia bertanya; 'Lalu apa tanda-tandanya? ' Beliau menjawab: \"Apabila seorang budak melahirkan (anak) tuannya, dan kamu melihat orang yang tidak beralas kaki, telanjang, miskin, penggembala kambing, namun bermegah-megahan dalam membangun bangunan.\" Umar berkata; 'Maka Nabi Shallallahu 'Alaihi Wasalam menemuiku tiga (hari) setelah itu, seraya berkata: \"Wahai Umar, apakah kamu tahu siapa penanya tersebut? Itulah jibril, dia mendatangi kalian untuk mengajarkan kepada kalian tentang pengetahuan agama kalian.\" Telah menceritakan kepada kami [Ahmad bin Muhammad] telah mengabarkan kepada kami [Ibnu al Mubarak] telah mengabarkan kepada kami [Kahmas bin al Hasan] dengan semisal isnad ini. Telah menceritakan kepada kami [Muhammad bin al Mutsanna] telah menceritakan kepada kami [Mu'adz bin Mu'adz] dari [Kahmas] dengan semisal sanad ini dan maknanya. Dan dalam bab tersebut (juga diriwayatkan) dari Thalhah bin Ubaidullah dan Anas bin Malik dan Abu Hurairah. Abu Isa berkata; 'Hadits ini hadits hasan shahih. Dan ia telah diriwayatlah bukan hanya dari satu jalur seperti ini dari Umar. Hadits ini telah diriwayatkan dari Ibnu Umar dari Nabi Shallallahu 'Alaihi Wasalam, dan yang shahih adalah hadits tersebut diriwayatkan dari Ibnu Umar, dari Umar, dari Nabi Shallallahu 'Alaihi Wasalam.'"},"2469":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبَّادُ بْنُ عَبَّادٍ الْمُهَلَّبِيُّ عَنْ أَبِي جَمْرَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَدِمَ وَفْدُ عَبْدِ الْقَيْسِ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا إِنَّا هَذَا الْحَيَّ مِنْ رَبِيعَةَ وَلَسْنَا نَصِلُ إِلَيْكَ إِلَّا فِي أَشْهُرِ الْحَرَامِ فَمُرْنَا بِشَيْءٍ نَأْخُذُهُ عَنْكَ وَنَدْعُو إِلَيْهِ مَنْ وَرَاءَنَا فَقَالَ آمُرُكُمْ بِأَرْبَعٍ الْإِيمَانِ بِاللَّهِ ثُمَّ فَسَّرَهَا لَهُمْ شَهَادَةُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنِّي رَسُولُ اللَّهِ وَإِقَامِ الصَّلَاةِ وَإِيتَاءِ الزَّكَاةِ وَأَنْ تُؤَدُّوا خُمْسَ مَا غَنِمْتُمْحَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَبِي جَمْرَةَ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَأَبُو جَمْرَةَ الضُّبَعِيُّ اسْمُهُ نَصْرُ بْنُ عِمْرَانَ وَقَدْ رَوَاهُ شُعْبَةُ عَنْ أَبِي جَمْرَةَ أَيْضًا وَزَادَ فِيهِ أَتَدْرُونَ مَا الْإِيمَانُ شَهَادَةُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنِّي رَسُولُ اللَّهِ وَذَكَرَ الْحَدِيثَ سَمِعْت قُتَيْبَةَ بْنَ سَعِيدٍ يَقُولُ مَا رَأَيْتُ مِثْلَ هَؤُلَاءِ الْفُقَهَاءِ الْأَشْرَافِ الْأَرْبَعَةِ مَالِكِ بْنِ أَنَسٍ وَاللَّيْثِ بْنِ سَعْدٍ وَعَبَّادِ بْنِ عَبَّادٍ الْمُهَلَّبِيِّ وَعَبْدِ الْوَهَّابِ الثَّقَفِيِّ قَالَ قُتَيْبَةُ كُنَّا نَرْضَى أَنْ نَرْجِعَ مِنْ عِنْدِ عَبَّادٍ كُلَّ يَوْمٍ بِحَدِيثَيْنِ وَعَبَّادُ بْنُ عَبَّادٍ هُوَ مِنْ وَلَدِ الْمُهَلَّبِ بْنِ أَبِي صُفْرَةَ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abbad bin Abbad al Muhallabi] dari [Abu Jamrah] dari [Ibnu Abbas] dia berkata; Delegasi Abdul Qais datang kepada Rasulullah seraya berkata; 'Sesungguhnya kampung ini adalah (melewati) kampung Rabi'ah, dan tidaklah kita mengunjungimu kecuali pada bulan bulan haram, maka perintahkanlah kepada kami untuk melakukan sesuatu yang kami ambil darimu, dan kami akan mengajak orang-orang yang berada di belakang kami kepadanya, ' maka beliau bersabda; \"Saya perintahkan kalian dengan empat perkara; iman kepada Allah, \" kemudian beliau menafsirkannya untuk mereka, yaitu; \"kesaksian bahwa tidak ada tuhan (yang berhak disembah) selain Allah, dan bahwa aku adalah utusan Allah, mendirikan shalat, menunaikan zakat, menunaikan seperlima dari harta ghanimah kalian.\" Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Hammad bin Zaid] dari [Abu Jamrah] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam seperti itu. Abu Isa berkata; ini adalah hadits hasan shahih, dan Abu Jamrah Adl Dlaba'I namanya adalah Nadlr bin Imran. Dan [Syu'bah] juga meriwayatkannya dari [Abu Jamrah]. Dan dia menambahkan di dalamnya; \"Apakah kalian tahu apakah iman itu? Yaitu persaksian bahwa tidak ada tuhan (yang berhak disembah) selain Allah dan bahwa aku adalah utusan Allah…\" dan dia menyebutkan kesempurnaan hadits. Saya mendengar Qutaibah bin Sa'id berkata, 'Saya tidak pernah melihat seperti mereka empat ahli fikih yang mulia; Malik bin Anas, al Laits bin Sa'ad, Abbad bin Abbad al Muhallabi, dan Abdul Wahhab ats Tsaqafi. Qutaibah berkata; 'Kami rela untuk pulang dari sisi Abbad setiap hari dengan membawa dua hadits. Dan Abbad bin Abbad adalah termasuk putera al Muhallab bin Abi Shufrah."},"2470":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ الْبَغْدَادِيُّ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ حَدَّثَنَا خَالِدٌ الْحَذَّاءُ عَنْ أَبِي قِلَابَةَ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ أَكْمَلِ الْمُؤْمِنِينَ إِيمَانًا أَحْسَنُهُمْ خُلُقًا وَأَلْطَفُهُمْ بِأَهْلِهِوَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَأَنَسِ بْنِ مَالِكٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ صَحِيحٌ وَلَا نَعْرِفُ لِأَبِي قِلَابَةَ سَمَاعًا مِنْ عَائِشَةَ وَقَدْ رَوَى أَبُو قِلَابَةَ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ رَضِيعٍ لِعَائِشَةَ عَنْ عَائِشَةَ غَيْرَ هَذَا الْحَدِيثِ وَأَبُو قِلَابَةَ عَبْدُ اللَّهِ بْنُ زَيْدٍ الْجَرْمِيُّ حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ قَالَ ذَكَرَ أَيُّوبُ السَّخْتِيَانِيُّ أَبَا قِلَابَةَ فَقَالَ كَانَ وَاللَّهِ مِنْ الْفُقَهَاءِ ذَوِي الْأَلْبَابِ","id":"Telah menceritakan kepada kami [Ahmad bin Mani' al Baghdadi] telah menceritakan kepada kami [Isma'il bin Ulayyah] telah menceritakan kepada kami [Khalid al Hadzdza'] dari [Abu Qilabah] dari [Aisyah] dia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda; \"Sesungguhnya termasuk orang yang paling sempurna imannya adalah orang yang paling baik akhlaknya, dan paling lembut terhadap keluarganya.\" Dan dalam bab tersebut (juga diriwayatkan) dari Abu Hurairah dan Anas bin Malik. Abu Isa berkata; 'Ini hadits shahih, dan kami tidak mengetahui Abu Qilabah memiliki riwayat mendengar dari Aisyah. Abu Qilabah telah meriwayatkan dari Abdullah bin Yazid, susuan Aisyah, dari Aisyah selain hadits ini. Abu Qilabah Abdullah bin Zaid al Jarmi, telah menceritakan kepada kami Ibnu Abi Umar, telah menceritakan kepada kami Sufyan, dia berkata, Ayyub as Sakhtiyani menyebutkan Abu Qilabah berkata, \"Demi Allah, dia termasuk para fuqaha' yang memiliki ilmu.\""},"2471":{"ar":"حَدَّثَنَا أَبُو عَبْدِ اللَّهِ هُرَيْمُ بْنُ مِسْعَرٍ الْأَزْدِيُّ التِّرْمِذِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطَبَ النَّاسَ فَوَعَظَهُمْ ثُمَّ قَالَ يَا مَعْشَرَ النِّسَاءِ تَصَدَّقْنَ فَإِنَّكُنَّ أَكْثَرُ أَهْلِ النَّارِ فَقَالَتْ امْرَأَةٌ مِنْهُنَّ وَلِمَ ذَاكَ يَا رَسُولَ اللَّهِ قَالَ لِكَثْرَةِ لَعْنِكُنَّ يَعْنِي وَكُفْرِكُنَّ الْعَشِيرَ قَالَ وَمَا رَأَيْتُ مِنْ نَاقِصَاتِ عَقْلٍ وَدِينٍ أَغْلَبَ لِذَوِي الْأَلْبَابِ وَذَوِي الرَّأْيِ مِنْكُنَّ قَالَتْ امْرَأَةٌ مِنْهُنَّ وَمَا نُقْصَانُ دِينِهَا وَعَقْلِهَا قَالَ شَهَادَةُ امْرَأَتَيْنِ مِنْكُنَّ بِشَهَادَةِ رَجُلٍ وَنُقْصَانُ دِينِكُنَّ الْحَيْضَةُ تَمْكُثُ إِحْدَاكُنَّ الثَّلَاثَ وَالْأَرْبَعَ لَا تُصَلِّيوَفِي الْبَاب عَنْ أَبِي سَعِيدٍ وَابْنِ عُمَرَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ","id":"Telah bercerita kepada kami [Abu Abdillah Huraim bin Mis'ar Al Azdi At Tirmdzi] telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Suhail bin Abu Shalih] dari [bapaknya] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam berkhutbah di hadapan para sahabat lalu menasehati mereka kemudian berkata: \"Wahai para wanita berinfaqlah karena kalian adalah penghuni neraka yang paling banyak\". Maka salah seorang wanita bertanya; 'Kenapa demikian wahai Rasulullah? ' Beliau menjawab: \"Karena kalian banyak melaknat yaitu mengingkari terhadap (nikmat) suami, \" lalu beliau bersabda: \"Dan aku tidak melihat dari orang-orang yang sedikit akal dan agamanya lebih banyak orang yang memiliki hati dan pikiran daripada kalian\", salah seorang wanita bertanya, 'Apa kekurangan agama dan akal wanita? ' Beliau menjawab: \"Persaksian dua orang wanita dari kalian adalah sama dengan persaksian seorang lelaki sedangkan kekurangan din (agama) kalian adalah adanya masa haid yang dapat menahan salah seorang dari kalian tiga sampai empat hari dari melaksanakan sholat.\" Dan dalam bab ini ada hadits dari Abu Sa'id dan Ibnu Umar, Abu Isa berkata; 'Hadits ini hasan shahih gharib dari jalur sanad ini\"."},"2472":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْإِيمَانُ بِضْعٌ وَسَبْعُونَ بَابًا أَدْنَاهَا إِمَاطَةُ الْأَذَى عَنْ الطَّرِيقِ وَأَرْفَعُهَا قَوْلُ لَا إِلَهَ إِلَّا اللَّهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَهَكَذَا رَوَى سُهَيْلُ بْنُ أَبِي صَالِحٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ وَرَوَى عُمَارَةُ بْنُ غَزِيَّةَ هَذَا الْحَدِيثَ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْإِيمَانُ أَ��ْبَعَةٌ وَسِتُّونَ بَابًا قَالَ حَدَّثَنَا بِذَلِكَ قُتَيْبَةُ حَدَّثَنَا بَكْرُ بْنُ مُضَرَ عَنْ عُمَارَةَ بْنِ غَزِيَّةَ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Suhail bin Abi Shalih] dari [Abdullah] dari [Abu Shalih] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Iman itu adalah tujuh puluh tiga bab lebih, yang paling rendah adalah menyingkirkan bahaya (seperti duri) dari jalan, sedangkan yang paling tinggi adalah ucapan; 'Tidak ada tuhan (yang berhak disembah) selain Allah'.\" Ini hadits hasan shahih. Demikianlah Suhail bin Abi Shalih meriwayatkan dari Abdullah bin Dinar dari Abu Shalih dari Abu Hurairah. Dan Umarah bin Ghaziyah meriwayatkan hadits ini dari Abu Shalih dari Abu Hurairah dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Iman itu enam puluh empat bab.\" Abu Isa berkata; ' [Qutaibah] telah menceritakan kepada kami, [Bakar bin Mudhar] telah menceritakan kepada kami, dari [Umarah bin Ghaziyah] dari [Abu Shalih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam.\""},"2473":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ وَأَحْمَدُ بْنُ مَنِيعٍ الْمَعْنَى وَاحِدٌ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِرَجُلٍ وَهُوَ يَعِظُ أَخَاهُ فِي الْحَيَاءِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْحَيَاءُ مِنْ الْإِيمَانِقَالَ أَحْمَدُ بْنُ مَنِيعٍ فِي حَدِيثِهِ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَمِعَ رَجُلًا يَعِظُ أَخَاهُ فِي الْحَيَاءِ قَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَأَبِي بَكْرَةَ وَأَبِي أُمَامَةَ","id":"Telah menceritakan kepada kami [Ibnu Abi Umar] dan [Ahmad bin Mani'] dan maknanya adalah sama, keduanya berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [az Zuhri] dari [Salim] dari [bapaknya] bahwa Rasulullah shallallahu 'alaihi wasallam melewati seorang laki-laki yang sedang menasihati saudaranya dalam masalah malu, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Malu adalah sebagian dari iman.\" Ahmad bin Mani' berkata tentang haditsnya 'Sesungguhnya Nabi shallallahu 'alaihi wasallam mendengar seorang laki-laki menasihati saudaranya dalam masalah malu' maka dia berkata; 'Ini hadits hasan shahih. Dan dalam bab tersebut (juga diriwayatkan) dari Abu Bakrah dan Abu Umamah.'"},"2474":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُعَاذٍ الصَّنْعَانِيُّ عَنْ مَعْمَرٍ عَنْ عَاصِمِ بْنِ أَبِي النَّجُودِ عَنْ أَبِي وَائِلٍ عَنْ مُعَاذِ بْنِ جَبَلٍ قَالَكُنْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَأَصْبَحْتُ يَوْمًا قَرِيبًا مِنْهُ وَنَحْنُ نَسِيرُ فَقُلْتُ يَا رَسُولَ اللَّهِ أَخْبِرْنِي بِعَمَلٍ يُدْخِلُنِي الْجَنَّةَ وَيُبَاعِدُنِي عَنْ النَّارِ قَالَ لَقَدْ سَأَلْتَنِي عَنْ عَظِيمٍ وَإِنَّهُ لَيَسِيرٌ عَلَى مَنْ يَسَّرَهُ اللَّهُ عَلَيْهِ تَعْبُدُ اللَّهَ وَلَا تُشْرِكْ بِهِ شَيْئًا وَتُقِيمُ الصَّلَاةَ وَتُؤْتِي الزَّكَاةَ وَتَصُومُ رَمَضَانَ وَتَحُجُّ الْبَيْتَ ثُمَّ قَالَ أَلَا أَدُلُّكَ عَلَى أَبْوَابِ الْخَيْرِ الصَّوْمُ جُنَّةٌ وَالصَّدَقَةُ تُطْفِئُ الْخَطِيئَةَ كَمَا يُطْفِئُ الْمَاءُ النَّارَ وَصَلَاةُ الرَّجُلِ مِنْ جَوْفِ اللَّيْلِ قَالَ ثُمَّ تَلَا{ تَتَجَافَى جُنُوبُهُمْ عَنْ الْمَضَاجِعِ حَتَّى بَلَغَ يَعْمَلُونَ }ثُمَّ قَالَ أَلَا أُخْبِرُكَ بِرَأْسِ الْأَمْرِ كُلِّهِ وَعَمُودِهِ وَذِرْوَةِ سَنَامِهِ قُلْتُ بَلَى يَا رَسُولَ اللَّهِ قَالَ رَأْسُ الْأَمْرِ الْإِسْلَامُ وَعَمُودُهُ الصَّلَاةُ وَذِرْوَةُ سَنَامِهِ الْجِهَادُ ثُمَّ قَالَ أَلَا أُخْبِرُكَ بِمَلَاكِ ذَلِكَ كُلِّهِ قُلْتُ بَلَى يَا نَبِيَّ اللَّهِ فَأَخَذَ بِلِسَانِهِ قَالَ كُفَّ عَلَيْكَ هَذَا فَقُلْتُ يَا نَبِيَّ اللَّهِ وَإِنَّا لَمُؤَاخَذُونَ بِمَا نَتَكَلَّمُ بِهِ فَقَالَ ثَكِلَتْكَ أُمُّكَ يَا مُعَاذُ وَهَلْ يَكُبُّ النَّاسَ فِي النَّارِ عَلَى وُجُوهِهِمْ أَوْ عَلَى مَنَاخِرِهِمْ إِلَّا حَصَائِدُ أَلْسِنَتِهِمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ibnu Abi Umar] telah menceritakan kepada kami [Abdullah bin Mu'adz ash Shan'ani] dari [Ma'mar] dari ['Ashim bin Abi an Najud] dari [Abu Wail] dari [Mu'adz bin Jabal] dia berkata; Saya pernah bersama Nabi shallallahu 'alaihi wasallam dalam suatu perjalanan, suatu pagi aku berada dekat dari beliau, dan kami sedang bepergian, maka saya berkata; 'Wahai Rasulullah, kabarkanlah kepadaku tentang suatu amal yang akan memasukkanku kedalam surga dan menjauhkanku dari neraka.' Beliau menjawab: \"Kamu telah menanyakan kepadaku tentang perkara yang besar, padahal sungguh ia merupakan perkara ringan bagi orang yang telah Allah jadikan ringan baginya, yaitu: Kamu menyembah Allah dan tidak menyekutukannya dengan sesuatu apa pun, kamu mendirikan shalat, menunaikan zakat, berpuasa di bulan Ramadhan, berhaji ke Baitullah.\" Kemudian beliau bersabda: \"Maukah kamu aku tunjukkan pada pintu-pintu kebaikan? Puasa adalah perisai dan sedekah akan memadamkan kesalahan sebagaimana air memadamkan api, dan shalat seorang laki-laki pada pertengahan malam.\" Kemudian beliau membaca; \"Lambung mereka jauh dari tempat tidurnya, sedang mereka berdoa kepada Rabbnya dengan rasa takut dan harap, dan mereka menafkahkan sebagian dari rezki yang Kami berikan kepada mereka. (16) Seorang pun tidak mengetahui apa yang disembunyikan untuk mereka yaitu (bermacam-macam nikmat) yang menyedapkan pandangan mata sebagai balasan terhadap apa yang telah mereka kerjakan.\" (As-Sajdah: 16-17). Kemudian beliau bersabda: \"Maukah kamu aku tunjukkan pokok perkara agama, tiang dan puncaknya?\" Aku menjawab: \"Ya, wahai Rasulullah.\" Beliau bersabda: \"Pokok dari perkara agama adalah Islam, tiangnya adalah shalat, sedangkan puncaknya adalah jihad.' Kemudian beliau bersabda: \"Maukah kamu aku kabarkan dengan sesuatu yang menguatkan itu semua?\" Aku menjawab; 'Ya, wahai Nabi Allah.' Lalu beliau memegang lisannya, dan bersabda: \"'Tahanlah (lidah) mu ini.\" Aku bertanya; 'Wahai Nabi Allah, (Apakah) sungguh kita akan diadzab disebabkan oleh perkataan yang kita ucapkan? ' Beliau menjawab; \"(Celakalah kamu) ibumu kehilanganmu wahai Mu'adz, Tidaklah manusia itu disunggkurkan ke dalam neraka di atas muka atau hidung mereka melainkan karena hasil ucapan lisan mereka?\" Abu Isa berkata; 'Ini hadits hasan shahih.'"},"2475":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ دَرَّاجٍ أَبِي السَّمْحِ عَنْ أَبِي الْهَيْثَمِ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَأَيْتُمْ الرَّجُلَ يَتَعَاهَدُ الْمَسْجِدَ فَاشْهَدُوا لَهُ بِالْإِيمَانِ فَإِنَّ اللَّهَ تَعَالَى يَقُولُ{ إِنَّمَا يَعْمُرُ مَسَاجِدَ اللَّهِ مَنْ آمَنَ بِاللَّهِ وَالْيَوْمِ الْآخِرِ وَأَقَامَ الصَّلَاةَ وَآتَى الزَّكَاةَ }الْآيَةَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Ibnu Abi Umar] telah menceritakan kepada kami [Abdullah bin Wahb] dari [Amru bin al Harits] dari [Darraj Abu as Samh] dari [Abu al Haitsam] dari [Abu Sa'id] dia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda; \"Apabila kalian melihat seorang laki-laki memakmurkan masjid, maka persaksikanlah untuknya dengan keimanan, karena Allah berfirman; 'Sesungguhnya orang yang memakmurkan masjid hanyalah orang yang beriman kepada Allah dan hari akhir, mendirikan shalat, dan menunaikan zakat'.\" Abu Isa berkata; 'Ini hadits hasan gharib.'"},"2476":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا جَرِيرٌ وَأَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَيْنَ الْكُفْرِ وَالْإِيمَانِ تَرْكُ الصَّلَاةِحَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَسْبَاطُ بْنُ مُحَمَّدٍ عَنْ الْأَعْمَشِ بِهَذَا الْإِسْنَادِ نَحْوَهُ وَقَالَ بَيْنَ الْعَبْدِ وَبَيْنَ الشِّرْكِ أَوْ الْكُفْرِ تَرْكُ الصَّلَاةِ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَأَبُو سُفْيَانَ اسْمُهُ طَلْحَةُ بْنُ نَافِعٍ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Jarir] dan [Abu Mu'awiyah] dari [al A'masy] dari [Abu Sufyan] dari [Jabir] bahwa Nabi shallallahu 'alaihi wasallam bersabda; \"(Pemisah) antara kufur dan iman adalah meninggalkan shalat.\" Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Asbath bin Muhammad] dari [al A'masy] dengan semisal sanad ini dan bersabda; \"(Pemisah) antara seorang hamba dengan syirik dan kafir adalah meninggalkan shalat.\" Abu Isa berkata; 'Ini adalah hadits hasan shahih. Dan Abu Sufyan namanya adalah Thalhah bin Nafi'.'"},"2477":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ الْعَبْدِ وَبَيْنَ الْكُفْرِ تَرْكُ الصَّلَاةِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَأَبُو الزُّبَيْرِ اسْمُهُ مُحَمَّدُ بْنُ مُسْلِمِ بْنِ تَدْرُسَ","id":"Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Abu az Zubair] dari [Jabir] dia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda; \"(Pemisah) antara seorang hamba dengan kekufuran adalah meninggalkan shalat.\" Abu Isa berkata; 'Ini hadits hasan shahih, dan Abu az Zubair namanya adalah Muhammad bin Muslim bin Tadrus.'"},"2478":{"ar":"حَدَّثَنَا أَبُو عَمَّارٍ الْحُسَيْنُ بْنُ حُرَيْثٍ وَيُوسُفُ بْنُ عِيسَى قَالَا حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى عَنْ الْحُسَيْنِ بْنِ وَاقِدٍ قَالَ ح و حَدَّثَنَا أَبُو عَمَّارٍ الْحُسَيْنُ بْنُ حُرَيْثٍ وَمَحْمُودُ بْنُ غَيْلَانَ قَالَا حَدَّثَنَا عَلِيُّ بْنُ الْحُسَيْنِ بْنِ وَاقِدٍ عَنْ أَبِيهِ قَالَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ عَلِيِّ بْنِ الْحَسَنِ الشَّقِيقِيُّ وَمَحْمُودُ بْنُ غَيْلَانَ قَالَا حَدَّثَنَا عَلِيُّ بْنُ الْحَسَنِ بْنِ شَقِيقٍ عَنْ الْحُسَيْنِ بْنِ وَاقِدٍ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَهْدُ الَّذِي بَيْنَنَا وَبَيْنَهُمْ الصَّلَاةُ فَمَنْ تَرَكَهَا فَقَدْ كَفَرَوَفِي الْبَاب عَنْ أَنَسٍ وَابْنِ عَبَّاسٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Abu Ammar al Husain bin Huraits] dan [Yusuf bin Isa] keduanya berkata, telah menceritakan kepada kami [al Fadhl bin Musa] dari [al Husain bin Waqid] dia berkata. (Tahwil Sanad) Telah menceritakan kepada kami [Abu Ammar al Husain bin Huraits] dan [Mahmud bin Ghailan] keduanya berkata, telah menceritakan kepada kami [Ali bin al Husain bin Waqid] dari [bapaknya] dia berkata. (Tahwil Sanad) dan telah menceritakan kepada kami [Muhammad bin Ali bin al Hasan asy Syaqiqi] dan [Mahmud bin Ghailan] keduanya berkata, telah meriwayatkan kepada kami [Ali bin al Hasan bin Syaqiq] dari [al Husain bin Waqid] dari [Abdullah bin Buraidah] dari [bapaknya] dia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perjanjian antara kami dan mereka adalah shalat, maka barangsiapa yang meninggalkannya maka dia sungguh telah kafir'.\" Dan pada bab tersebut dari Anas dan Ibnu Abbas, Abu Isa berkata; 'Ini hadits hasan shahih gharib.'"},"2479":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ عَنْ الْجُرَيْرِيِّ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ الْعُقَيْلِيِّ قَالَكَانَ أَصْحَابُ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَرَوْنَ شَيْئًا مِنْ الْأَعْمَالِ تَرْكُهُ كُفْرٌ غَيْرَ الصَّلَاةِقَالَ أَبُو عِيسَى سَمِعْت أَبَا مُصْعَبٍ الْمَدَنِيَّ يَقُولُ مَنْ قَالَ الْإِيمَانُ قَوْلٌ يُسْتَتَابُ فَإِنْ تَابَ وَإِلَّا ضُرِبَتْ عُنُقُهُ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Bisyr bin al Mufadhdhal] dari [al Jurairi] dari [Abdullah bin Syaqiq al Uqaili] dia berkata; Dahulu para sahabat Muhammad shallallahu 'alaihi wasallam tidak berpendapat sesuatu dari amal perbuatan yang mana meninggalkannya adalah suatu kekufuran melainkan shalat.\" Abu Isa berkata; 'Saya mendengar Abu Mush'ab al Madani berkata; 'Barangsiapa yang berpendapat bahwa iman adalah suatu perkataan saja, maka dia diminta untuk bertaubat, apabila dia bertaubat (maka diterimalah taubatnya), namun jika tidak (bertaubat) maka lehernya dipenggal.\""},"2480":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ بْنِ الْحَارِثِ عَنْ عَامِرِ بْنِ سَعْدِ بْنِ أَبِي وَقَّاصٍ عَنْ الْعَبَّاسِ بْنِ عَبْدِ الْمُطَّلِبِأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ ذَاقَ طَعْمَ الْإِيمَانِ مَنْ رَضِيَ بِاللَّهِ رَبًّا وَبِالْإِسْلَامِ دِينًا وَبِمُحَمَّدٍ نَبِيًّاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [al Laits] dari [Ibnu al Had] dari [Muhammad bin Ibrahim bin al Harits] dari [Amir bin Sa'ad bin Abu Waqqashh] dari [al Abbas bin Abdul Muththalib] bahwasanya dia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan merasakan manisnya iman orang yang ridha menjadikan Allah sebagai Rabb dan Islam sebagai agama dan Muhammad sebagai Nabi.\" Abu Isa berkata; 'Ini hadits hasan shahih.'"},"2481":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا عَبْدُ الْوَهَّابِ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ثَلَاثٌ مَنْ كُنَّ فِيهِ وَجَدَ بِهِنَّ طَعْمَ الْإِيمَانِ مَنْ كَانَ اللَّهُ وَرَسُولُهُ أَحَبَّ إِلَيْهِ مِمَّا سِوَاهُمَا وَأَنْ يُحِبَّ الْمَرْءَ لَا يُحِبُّهُ إِلَّا لِلَّهِ وَأَنْ يَكْرَهَ أَنْ يَعُودَ فِي الْكُفْرِ بَعْدَ إِذْ أَنْقَذَهُ اللَّهُ مِنْهُ كَمَا يَكْرَهُ أَنْ يُقْذَفَ فِي النَّارِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَاهُ قَتَادَةُ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ibnu Abi Umar] telah menceritakan kepada kami [Abdul Wahhab] dari [Ayyub] dari [Abu Qilabah] dari [Anas] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ada tiga perkara yang jika terdapat pada diri seseorang akan mendapatkan manisnya iman: Barangsiapa yang menjadikan Allah dan RasulNya lebih dia cintai daripada selain keduanya, dia mencintai seseorang hanya karena Allah, membenci kembali kepada kekafiran setelah Allah menyelamatkannya dari azabnya sebagaimana dia membenci untuk dilemparkan ke dalam api neraka.\" Abu Isa berkata; 'Ini hadits hasan shahih. Dan [Qatadah] telah meriwayatkannya dari [Anas] dari Nabi shallallahu 'alaihi wasallam.'"},"2482":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا عَبِيدَةُ بْنُ حُمَيْدٍ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَزْنِي الزَّانِي حِينَ يَزْنِي وَهُوَ مُؤْمِنٌ وَلَا يَسْرِقُ السَّارِقُ حِينَ يَسْرِقُ وَهُوَ مُؤْمِنٌ وَلَكِنَّ التَّوْبَةَ مَعْرُوضَةٌوَفِي الْبَاب عَنْ ابْنِ عَبَّاسٍ وَعَائِشَةَ وَعَبْدِ اللَّهِ بْنِ أَبِي أَوْفَى قَالَ أَبُو عِيسَى حَدِيثُ أَبِي هُرَيْرَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَقَدْ رُوِيَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا زَنَى الْعَبْدُ خَرَجَ مِنْهُ الْإِيمَانُ فَكَانَ فَوْقَ رَأْسِهِ كَالظُّلَّةِ فَإِذَا خَرَجَ مِنْ ذَلِكَ الْعَمَلِ عَادَ إِلَيْهِ الْإِيمَانُ وَقَدْ رُوِيَ عَنْ أَبِي جَعْفَرٍ مُحَمَّدِ بْنِ عَلِيٍّ أَنَّهُ قَالَ فِي هَذَا خَرَجَ مِنْ الْإِيمَانِ إِلَى الْإِسْلَامِ وَقَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ فِي الزِّنَا وَالسَّرِقَةِ مَنْ أَصَابَ مِنْ ذَلِكَ شَيْئًا فَأُقِيمَ عَلَيْهِ الْحَدُّ فَهُوَ كَفَّارَةُ ذَنْبِهِ وَمَنْ أَصَابَ مِنْ ذَلِكَ شَيْئًا فَسَتَرَ اللَّهُ عَلَيْهِ فَهُوَ إِلَى اللَّهِ إِنْ شَاءَ عَذَّبَهُ يَوْمَ الْقِيَامَةِ وَإِنْ شَاءَ غَفَرَ لَهُ رَوَى ذَلِكَ عَلِيُّ بْنُ أَبِي طَالِبٍ وَعُبَادَةُ بْنُ الصَّامِتِ وَخُزَيْمَةُ بْنُ ثَابِتٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Abidah bin Humaid] dari [al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang pezina melakukan perzinaan sedangkan dia berstatus sebagai seorang mukmin yang sempurna imannya, dan tidaklah seorang pencuri melakukan pencurian sedangkan dia berstatus sebagai seorang mukmin yang sempurna imannya. Tetapi pintu taubat tetap ditawarkan kepadanya.\" Dan dalam bab tersebut (juga diriwayatkan) dari Ibnu Abbas dan Aisyah serta Abdullah bin Abi Aufa. Abu Isa berkata; 'Hadits Abu Hurairah adalah hadits hasan shahih gharib"},"2483":{"ar":"حَدَّثَنَا أَبُو عُبَيْدَةَ بْنُ أَبِي السَّفَرِ وَاسْمُهُ أَحْمَدُ بْنُ عَبْدِ اللَّهِ الْهَمْدَانِيُّ الْكُوفِيُّ قَالَ حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ عَنْ يُونُسَ بْنِ أَبِي إِسْحَقَ عَنْ أَبِي إِسْحَقَ الْهَمْدَانِيِّ عَنْ أَبِي جُحَيْفَةَ عَنْ عَلِيٍّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَصَابَ حَدًّا فَعُجِّلَ عُقُوبَتَهُ فِي الدُّنْيَا فَاللَّهُ أَعْدَلُ مِنْ أَنْ يُثَنِّيَ عَلَى عَبْدِهِ الْعُقُوبَةَ فِي الْآخِرَةِ وَمَنْ أَصَابَ حَدًّا فَسَتَرَهُ اللَّهُ عَلَيْهِ وَعَفَا عَنْهُ فَاللَّهُ أَكْرَمُ مِنْ أَنْ يَعُودَ إِلَى شَيْءٍ قَدْ عَفَا عَنْهُقَالَ أَبُو عِيسَى وَهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَهَذَا قَوْلُ أَهْلِ الْعِلْمِ لَا نَعْلَمُ أَحَدًا كَفَّرَ أَحَدًا بِالزِّنَا أَوْ السَّرِقَةِ وَشُرْبِ الْخَمْرِ","id":"Telah menceritakan kepada kami [Abu Ubaidah bin Abu As Safar], namanya Ahmad bin Abdullah Al Hamdani Al Kufi, dia berkata, telah menceritakan kepada kami [Hajjaj bin Muhammad] dari [Yunus bin Abu Ishaq] dari [Abu Ishaq Al Hamdani] dari [Abu Juhaifah] dari [Ali] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa terkena hukum had lalu siksanya di dunia disegerakan, maka Allah lebih adil daripada mengulangi dua kali siksanya di akhirat kepada hambaNya, dan barangsiapa yang terkena hukum had kemudian Allah menutupinya dan mengampuninya, maka Allah lebih mulia daripada mengulangi kepada sesuatu yang telah Dia maafkan\". Abu Isa berkata; 'Dan hadits ini hasan gharib, dan inilah pendapat ahli ilmu bahwa kami tidak mengetahui seorang pun yang mengkafirkan seseorang karena perbuatan zina atau mencuri atau meminum khamer.'"},"2484":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ عَجْلَانَ عَنْ الْقَعْقَاعِ بْنِ حَكِيمٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُسْلِمُ مَنْ سَلِمَ الْمُسْلِمُونَ مِنْ لِسَانِهِ وَيَدِهِ وَالْمُؤْمِنُ مَنْ أَمِنَهُ النَّاسُ عَلَى دِمَائِهِمْ وَأَمْوَالِهِمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [al Laits] dari [Ibnu 'Ajlan] dari [al Qa'qa' bin Hakim] dari [Abu Shalih] dari [Abu Hurairah] dia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang muslim (yang sejati) adalah orang yang mana orang muslim lainnya selamat dari (bahaya) lisan dan tangannya, dan seorang mukmin (yang sejati) adalah orang yang mana manusia lainnya selamat dari (bahayanya) pada darah dan harta mereka.\" Abu Isa berkata; 'Ini hadits hasan shahih.'"},"2485":{"ar":"وَيُرْوَى عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ سُئِلَ أَيُّ الْمُسْلِمِينَ أَفْضَلُ قَالَ مَنْ سَلِمَ الْمُسْلِمُونَ مِنْ لِسَانِهِ وَيَدِهِ وَفِي الْبَاب عَنْ جَابِرٍ وَأَبِي مُوسَى وَعَبْدِ اللَّهِ بْنِ عَمْرٍو حَدَّثَنَا بِذَلِكَ إِبْرَاهِيمُ بْنُ سَعِيدٍ الْجَوْهَرِيُّ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي بُرْدَةَ عَنْ جَدِّهِ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ أَيُّ الْمُسْلِمِينَ أَفْضَلُ قَالَ مَنْ سَلِمَ الْمُسْلِمُونَ مِنْ لِسَانِهِ وَيَدِهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ صَحِيحٌ غَرِيبٌ حَسَنٌ مِنْ حَدِيثِ أَبِي مُوسَى عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Dan diriwayatkan dari Nabi shallallahu 'alaihi wasallam bahwasanya beliau ditanya; \"Orang muslim yang manakah yang lebih afdhal?\" Beliau menjawab: \"seseorang yang muslim lainnya selamat dari (bahaya) lisan dan tangannya.\" Dan di dalam bab tersebut (juga diriwayatkan) dari Jabir, Abu Musa dan Abdullah bin Amru, telah menceritakan kepada kami dengan hadits tersebut [Ibrahim bin Sa'id al Jauhari] telah menceritakan kepada kami [Abu Usamah] dari [Buraid bin Abdullah bin Abu Burdah] dari [kakeknya, Abu Burdah] dari [Abu Musa al Asy'ari] bahwa Nabi shallallahu 'alaihi wasallam ditanya, \"Orang muslim yang manakah yang lebih afdhal?\" Beliau menjawab: \"seseorang yang mana muslim lainnya selamat dari (bahaya) lisan dan tangannya.\" Abu Isa berkata; 'Ini hadits shahih gharib hasan dari hadits Abu Musa dari Nabi shallallahu 'alaihi wasallam."},"2486":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ الْأَعْمَشِ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْإِسْلَامَ بَدَأَ غَرِيبًا وَسَيَعُودُ غَرِيبًا كَمَا بَدَأَ فَطُوبَى لِلْغُرَبَاءِوَفِي الْبَاب عَنْ سَعْدٍ وَابْنِ عُمَرَ وَجَابِرٍ وَأَنَسٍ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ حَدِيثِ ابْنِ مَسْعُودٍ إِنَّمَا نَعْرِفُهُ مِنْ حَدِيثِ حَفْصِ بْنِ غِيَاثٍ عَنْ الْأَعْمَشِ وَأَبُو الْأَحْوَصِ اسْمُهُ عَوْفُ بْنُ مَالِكِ بْنِ نَضْلَةَ الْجُشَمِيُّ تَفَرَّدَ بِهِ حَفْصٌ","id":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Hafsh bin Ghiyats] dari [al A'masy] dari [Abu Ishaq] dari [Abu al Ahwash] dari [Abdullah] dia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Islam itu bermula dalam keadaan asing dan akan kembali asing sebagaimana ia bermula, maka beruntunglah orang-orang yang asing, \" dan dalam bab tersebut (juga diriwayatkan) dari Sa'ad, Ibnu Umar, Jabir, Anas dan Abdullah bin Amru. Abu Isa berkata; 'Ini hadits hasan shahih gharib dari hadits Ibnu Mas'ud, Kami hanya mengetahuinya dari hadits Hafsh bin Ghiyats dari al A'masy, dan Abu al Ahwash namanya adalah 'Auf bin Malik bin Nadhlah al Jusyami, Hafsh meriwayatkannya sendirian."},"2487":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ أَخْبَرَنَا إِسْمَعِيلُ بْنُ أَبِي أُوَيْسٍ حَدَّثَنِي كَثِيرُ بْنُ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ عَوْفِ بْنِ زَيْدِ بْنِ مِلْحَةَ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الدِّينَ لَيَأْرِزُ إِلَى الْحِجَازِ كَمَا تَأْرِزُ الْحَيَّةُ إِلَى جُحْرِهَا وَلَيَعْقِلَنَّ الدِّينُ مِنْ الْحِجَازِ مَعْقِلَ الْأُرْوِيَّةِ مِنْ رَأْسِ الْجَبَلِ إِنَّ الدِّينَ بَدَأَ غَرِيبًا وَيَرْجِعُ غَرِيبًا فَطُوبَى لِلْغُرَبَاءِ الَّذِينَ يُصْلِحُونَ مَا أَفْسَدَ النَّاسُ مِنْ بَعْدِي مِنْ سُنَّتِيقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Abdullah bin Abdurrahman] telah mengabarkan kepada kami [Isma'il bin Abu Uwais] telah menceritakan kepada kami [Katsir bin Abdullah bin Amru bin Auf bin Zaid bin Milhah] dari [bapaknya] dari [kakeknya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda; \"Sesunggunya agama (Islam) akan kembali bersarang ke Hijaz sebagaimana ular bersarang ke liangnya, dan pasti agama ini akan terbentengi dengan Hijaz sebagaimana kambing betina menjadikan puncak gunung sebagai benteng. Sesungguhnya Islam itu bermula dalam keadaan asing dan akan kembali asing, maka beruntunglah orang-orang yang asing, yaitu orang orang yang memperbaiki salah satu dari sunnahku yang telah dirusak oleh orang-orang setelahku\". Abu Isa berkata; 'Hadits ini hasan shahih.'"},"2488":{"ar":"حَدَّثَنَا أَبُو حَفْصٍ عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا يَحْيَى بْنُ مُحَمَّدِ بْنِ قَيْسٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ آيَةُ الْمُنَافِقِ ثَلَاثٌ إِذَا حَدَّثَ كَذَبَ وَإِذَا وَعَدَ أَخْلَفَ وَإِذَا اؤْتُمِنَ خَانَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ حَدِيثِ الْعَلَاءِ وَقَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفِي الْبَاب عَنْ ابْنِ مَسْعُودٍ وَأنَسٍ وَجَابِرٍ حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ جَعْفَرٍ عَنْ أَبِي سُهَيْلِ بْنِ مَالِكٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ بِمَعْنَاهُ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ صَحِيحٌ وَأَبُو سُهَيْلٍ هُوَ عَمُّ مَالِكِ بْنِ أَنَسٍ وَاسْمُهُ نَافِعُ بْنُ مَالِكِ بْنِ أَبِي عَامِرٍ الْأَصْبَحِيُّ الْخَوْلَانِيُّ","id":"Telah menceritakan kepada kami [Abu Hafsh Amru bin Ali] telah menceritakan kepada kami [Yahya bin Muhammad bin Qais] dari [al Ala' bin Abdurrahman] dari [bapaknya] dari [Abu Hurairah] dia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda; \"Tanda-tanda orang munafik itu ada tiga; apabila dia berbicara berdusta, apabila berjanji dia mengingkari, apabila dia dipercaya dia khianat.\" Abu Isa berkata; 'Ini hadits hasan gharib dari hadits al Ala'. Dan ia diriwayatkan dari bukan hanya satu jalur dari Abu Hurairah dari Nabi shallallahu 'alaihi wasallam. Dan dalam bab tersebut (juga diriwayatkan) dari Ibnu Mas'ud, Anas, dan Jabir. Telah menceritakan kepada kami [Ali bin Hujr] telah menceritakan kepada kami [Ismail bin Ja'far] dari [Abu Suhail bin Malik] dari [bapaknya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam semisalnya dengan riwayat bil Makna. Abu Isa berkata; 'Ini hadits shahih. Abu Suhail adalah paman Malik bin Anas, namanya Nafi' bin Malik bin Abu Amir al Ashbahi al Khaulani.'"},"2489":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ سُفْيَانَ عَنْ الْأَعْمَشِ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَرْبَعٌ مَنْ كُنَّ فِيهِ كَانَ مُنَافِقًا وَإِنْ كَانَتْ خَصْلَةٌ مِنْهُنَّ فِيهِ كَانَتْ فِيهِ خَصْلَةٌ مِنْ النِّفَاقِ حَتَّى يَدَعَهَا مَنْ إِذَا حَدَّثَ كَذَبَ وَإِذَا وَعَدَ أَخْلَفَ وَإِذَا خَاصَمَ فَجَرَ وَإِذَا عَاهَدَ غَدَرَقَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ الْأَعْمَشِ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ بِهَذَا الْإِسْنَادِ نَحْوَهُ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَإِنَّمَا مَعْنَى هَذَا عِنْدَ أَهْلِ الْعِلْمِ نِفَاقُ الْعَمَلِ وَإِنَّمَا كَانَ نِفَاقُ التَّكْذِيبِ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَكَذَا رُوِيَ عَنْ الْحَسَنِ الْبَصْرِيِّ شَيْءٌ مِنْ هَذَا أَنَّهُ قَالَ النِّفَاقُ نِفَاقَانِ نِفَاقُ الْعَمَلِ وَنِفَاقُ التَّكْذِيبِ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Ubaidullah bin Musa] dari [Sufyan] dari [al A'masy] dari [Abdullah bin Murrah] dari [Masruq] dari [Abdullah bin Amru] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Ada empat perkara, barangsiapa yang empat perkara tersebut ada pada dirinya maka dia menjadi orang munafik, dan apabila salah satu sifat dari empat perkara tersebut ada pada dirinya, maka pada dirinya terdapat satu sifat dari kemunafikan hingga dia meninggalkannya: orang yang apabila berbicara dia bohong, dan apabila dia berjanji maka dia mengingkari, apabila dia memusuhi maka dia melakukan kekejian (dengan melampaui batas), dan apabila dia mengadakan perjanjian maka dia yang mulai membatalkannya.\" Abu Isa berkata; 'Ini hadits hasan shahih, telah menceritakan kepada kami [al Hasan bin Ali al Khallal] telah menceritakan kepada kami [Abdullah bin Numair] dari [al A'masy] dari [Abdullah bin Murrah] dengan sanad ini semisalnya. Abu Isa berkata; 'Ini hadits hasan shahih, makna ini menurut ahli ilmu hanyalah kemunafikan dalam amal, dan kemunafikan dalam berbohong hanya pada masa Rasulullah shallallahu 'alaihi wasallam. Demikianlah diriwayatkan dari al Hasan al Bashri sebagian dari hadits ini bahwa dia berkata, 'Kemunafikan itu ada dua: kemunafikan dalam amal dan kemunafikan dalam berbohong'.\""},"2490":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا إِبْرَاهِيمُ بْنُ طَهْمَانَ عَنْ عَلِيِّ بْنِ عَبْدِ الْأَعْلَى عَنْ أَبِي النُّعْمَانِ عَنْ أَبِي وَقَّاصٍ عَنْ زَيْدِ بْنِ أَرْقَمَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا وَعَدَ الرَّجُلُ وَيَنْوِي أَنْ يَفِيَ بِهِ فَلَمْ يَفِ بِهِ فَلَا جُنَاحَ عَلَيْهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ وَلَيْسَ إِسْنَادُهُ بِالْقَوِيِّ عَلِيُّ بْنُ عَبْدِ الْأَعْلَى ثِقَةٌ وَلَا يُعْرَفُ أَبُو النُّعْمَانِ وَلَا أَبُو وَقَّاصٍ وَهُمَا مَجْهُولَانِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abu 'Amir] telah menceritakan kepada kami [Ibrahim bin Thahman] dari [Ali bin Abdul A'la] dari [Abu An Nu'man] dari [Abu Waqqash] dari [Zaid bin Arqam] dia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika seseorang berjanji dan berniat untuk menepati janjinya, namun tidak menepatinya maka tidak ada dosa baginya\". Abu Isa berkata; 'Hadits ini gharib, dan isnadnya tidak kuat, Ali bin Abdul A'la adalah orang yang tsiqah sedangkan Abu An Nu'man dan Abu Waqqash tidak dikenal, keduanya majhul (tidak diketahui).'"},"2491":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ بَزِيعٍ حَدَّثَنَا عَبْدُ الْحَكِيمِ بْنُ مَنْصُورٍ الْوَاسِطِيُّ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قِتَالُ الْمُسْلِمِ أَخَاهُ كُفْرٌ وَسِبَابُهُ فُسُوقٌوَفِي الْبَاب عَنْ سَعْدٍ وَعَبْدِ اللَّهِ بْنِ مُغَفَّلٍ قَالَ أَبُو عِيسَى حَدِيثُ ابْنِ مَسْعُودٍ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ مِنْ غَيْرِ وَجْهٍ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Bazi'] telah menceritakan kepada kami [Abdul Hakim bin Manshur al Wasithi] dari [Abdul Malik bin Umair] dari [Abdurrahman bin Abdulllah bin Mas'ud] dari [bapaknya] dia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pembunuhan seorang muslim terhadap saudaranya adalah kekufuran, dan mencelanya adalah kefasikan.\" Dan dalam bab tersebut juga dari Sa'ad dan Abdullah bin Mughaffal. Abu Isa berkata; 'Hadits Ibnu Mas'ud adalah hadits hasan shahih. Hadits tersebut telah diriwayatkan dari Ibnu Mas'ud dari berbagai jalur.'"},"2492":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ زُبَيْدٍ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سِبَابُ الْمُسْلِمِ فُسُوقٌ وَقِتَالُهُ كُفْرٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَمَعْنَى هَذَا الْحَدِيثِ قِتَالُهُ كُفْرٌ لَيْسَ بِهِ كُفْرًا مِثْلَ الِارْتِدَادِ وَالْحُجَّةُ فِي ذَلِكَ مَا رُوِيَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ قُتِلَ مُتَعَمَّدًا فَأَوْلِيَاءُ الْمَقْتُولِ بِالْخِيَارِ إِنْ شَاءُوا قَتَلُوا وَإِنْ شَاءُوا عَفَوْا وَلَوْ كَانَ الْقَتْلُ كُفْرًا لَوَجَبَ وَقَدْ رُوِيَ عَنْ ابْنِ عَبَّاسٍ وَطَاوُسٍ وَعَطَاءٍ وَغَيْرِ وَاحِدٍ مِنْ أَهْلِ الْعِلْمِ قَالُوا كُفْرٌ دُونَ كُفْرٍ وَفُسُوقٌ دُونَ فُسُوقٍ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Zubaid] dari [Abu Wail] dari [Abdullah bin Mas'ud] dia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"celaan terhadap seorang muslim adalah kefasikan, sedangkan membunuhnya adalah kekufuran.\" Abu Isa berkata; 'Ini hadits hasan shahih. Dan makna hadits ini, 'Dan membunuhnya adalah kekafiran' bukanlah kekafiran seperti murtad. Dan alasan dalam hal tersebut adalah sesuatu hadits yang diriwayatkan dari Nabi shallallahu 'alaihi wasallam bahwa dia bersabda: 'Barangsiapa yang dibunuh secara sengaja maka para wali orang yang terbunuh berhak memilih, jika mereka berkehendak, maka mereka (berhak) membunuh (menuntut qishash), dan jika mereka berkehendak maka mereka (berhak) memaafkan.' Kalau seandainya membunuh itu suatu kekufuran niscaya wajib (qishash). Dan sungguh telah diriwayatkan dari Ibnu Abbas, Thawus, Atha' dan tidak hanya satu ahli ilmu berkata bahwa (membunuh) adalah kekufuran di bawah kekufuran, dan kefasikan di bawah kefasikan."},"2493":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا إِسْحَقُ بْنُ يُوسُفَ الْأَزْرَقُ عَنْ هِشَامٍ الدَّسْتُوَائِيِّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي قِلَابَةَ عَنْ ثَابِتِ بْنِ الضَّحَّاكِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ عَلَى الْعَبْدِ نَذْرٌ فِيمَا لَا يَمْلِكُ وَلَاعِنُ الْمُؤْمِنِ كَقَاتِلِهِ وَمَنْ قَذَفَ مُؤْمِنًا بِكُفْرٍ فَهُوَ كَقَاتِلِهِ وَمَنْ قَتَلَ نَفْسَهُ بِشَيْءٍ عَذَّبَهُ اللَّهُ بِمَا قَتَلَ بِهِ نَفْسَهُ يَوْمَ الْقِيَامَةِوَفِي الْبَاب عَنْ أَبِي ذَرٍّ وَابْنِ عُمَرَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Ishaq bin Yusuf al Arzaq] dari [Hisyam ad Dastuwa'i] dari [Yahya bin Abi Katsir] dari [Abu Qilabah] dari [Tsabit bin adh Dhahhak] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Seorang hamba tidak berkewajiban memenuhi nadzar pada sesuatu yang tidak dia miliki, pelaknat seorang mukmin adalah seperti pembunuhnya, dan barangsiapa menuduh seorang mukmin dengan kekufuran maka dia seperti membunuhnya, dan barangsiapa membunuh dirinya dengan suatu alat, niscaya Allah akan mengadzabnya dengan alat yang dia gunakan untuk membunuh dirinya pada hari kiamat.\" Dan dalam bab tersebut juga diriwayatkan dari Abu Dzar dan Ibnu Umar. Abu Isa berkata; 'Ini hadits hasan shahih.' "},"2494":{"ar":"حَدَّثَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَيُّمَا رَجُلٍ قَالَ لِأَخِيهِ كَافِرٌ فَقَدْ بَاءَ بِهِ أَحَدُهُمَاهَذَا حَدِيثٌ حَسَنٌ ص��حِيحٌ غَرِيبٌ وَمَعْنَى قَوْلِهِ بَاءَ يَعْنِي أَقَرَّ","id":"Telah menceritakan kepada kami [Qutaibah] dari [Malik] dari [Abdullah bin Dinar] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Siapa pun orang yang berkata kepada saudaranya (semuslim); 'Hai kafir' maka sungguh salah satu dari keduanya telah menempati (kedudukan) pengkafiran tersebut.\" Ini hadits hasan shahih gharib, sedangkan makna bâ'a adalah aqarra (menempati)."},"2495":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ عَجْلَانَ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ ابْنِ مُحَيْرِيزٍ عَنْ الصُّنَابِحِيِّ عَنْ عُبَادَةَ بْنِ الصَّامِتِ أَنَّهُ قَالَدَخَلْتُ عَلَيْهِ وَهُوَ فِي الْمَوْتِ فَبَكَيْتُ فَقَالَ مَهْلًا لِمَ تَبْكِي فَوَاللَّهِ لَئِنْ اسْتُشْهِدْتُ لَأَشْهَدَنَّ لَكَ وَلَئِنْ شُفِّعْتُ لَأَشْفَعَنَّ لَكَ وَلَئِنْ اسْتَطَعْتُ لَأَنْفَعَنَّكَ ثُمَّ قَالَ وَاللَّهِ مَا مِنْ حَدِيثٍ سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَكُمْ فِيهِ خَيْرٌ إِلَّا حَدَّثْتُكُمُوهُ إِلَّا حَدِيثًا وَاحِدًا وَسَوْفَ أُحَدِّثُكُمُوهُ الْيَوْمَ وَقَدْ أُحِيطَ بِنَفْسِي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ شَهِدَ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ حَرَّمَ اللَّهُ عَلَيْهِ النَّارَوَفِي الْبَاب عَنْ أَبِي بَكْرٍ وَعُمَرَ وَعُثْمَانَ وَعَلِيٍّ وَطَلْحَةَ وَجَابِرٍ وَابْنِ عُمَرَ وَزَيْدِ بْنِ خَالِدٍ قَالَ سَمِعْت ابْنَ أَبِي عُمَرَ يَقُولُ سَمِعْتُ ابْنَ عُيَيْنَةَ يَقُولُ مُحَمَّدُ بْنُ عَجْلَانَ كَانَ ثِقَةً مَأْمُونًا فِي الْحَدِيثِ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَالصُّنَابِحِيُّ هُوَ عَبْدُ الرَّحْمَنِ بْنُ عُسَيْلَةَ أَبُو عَبْدِ اللَّهِ وَقَدْ رُوِيَ عَنْ الزُّهْرِيِّ أَنَّهُ سُئِلَ عَنْ قَوْلِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَالَ لَا إِلَهَ إِلَّا اللَّهُ دَخَلَ الْجَنَّةَ فَقَالَ إِنَّمَا كَانَ هَذَا فِي أَوَّلِ الْإِسْلَامِ قَبْلَ نُزُولِ الْفَرَائِضِ وَالْأَمْرِ وَالنَّهْيِ قَالَ أَبُو عِيسَى وَوَجْهُ هَذَا الْحَدِيثِ عِنْدَ بَعْضِ أَهْلِ الْعِلْمِ أَنَّ أَهْلَ التَّوْحِيدِ سَيَدْخُلُونَ الْجَنَّةَ وَإِنْ عُذِّبُوا بِالنَّارِ بِذُنُوبِهِمْ فَإِنَّهُمْ لَا يُخَلَّدُونَ فِي النَّارِ وَقَدْ رُوِيَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ وَأَبِي ذَرٍّ وَعِمْرَانَ بْنِ حُصَيْنٍ وَجَابِرِ بْنِ عَبْدِ اللَّهِ وَابْنِ عَبَّاسٍ وَأَبِي سَعِيدٍ الْخُدْرِيِّ وَأَنَسِ بْنِ مَالِكٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ سَيَخْرُجُ قَوْمٌ مِنْ النَّارِ مِنْ أَهْلِ التَّوْحِيدِ وَيَدْخُلُونَ الْجَنَّةَ هَكَذَا رُوِيَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ وَإِبْرَاهِيمَ النَّخَعِيِّ وَغَيْرِ وَاحِدٍ مِنْ التَّابِعِينَ فِي تَفْسِيرِ هَذِهِ الْآيَةِ{ رُبَمَا يَوَدُّ الَّذِينَ كَفَرُوا لَوْ كَانُوا مُسْلِمِينَ }قَالُوا إِذَا أُخْرِجَ أَهْلُ التَّوْحِيدِ مِنْ النَّارِ وَأُدْخِلُوا الْجَنَّةَ وَدَّ الَّذِينَ كَفَرُوا لَوْ كَانُوا مُسْلِمِينَ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [al Laits] dari [Ibnu 'Ajlan] dari [Muhammad bin Yahya bin Habban] dari [Ibnu Muhairiz] dari [Ash Shunabihi] dari [Ubadah bin Ash Shamit] bahwasanya dia berkata; Saya mengunjungi Ubadah bin ash Shamit yang sedangkan berada di (ambang) kematian, aku pun menangis, maka dia berkata; 'Tahan dulu perlahan, kenapa kamu menangis? Demi Allah, jika aku mati syahid, niscaya aku bersaksi untukmu, dan jika aku diberi syafaat yang dikabulkan, niscaya aku memberikan syafaat untukmu, dan jika aku mampu, niscaya aku memberikan manfaat untukmu'. Kemudian dia berkata; 'Demi Allah, tidaklah ada hadits yang aku dengar dari Rasulullah shallallahu 'alaihi wasallam yang ada kebaikannya bagi kalian, melainkan aku telah menceritakannya kepada kalian kecuali satu hadits, namun sekarang aku akan menceritakannya kepada kalian, dan sungguh aku telah mendekati ajalku. Aku telah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bersaksi bahwa tidak ada tuhan (yang berhak disembah) selain Allah, dan bahwa Muhammad adalah Rasulullah niscaya Allah mengharamkan neraka atasnya.\" Dan dalam hadits bab tersebut juga diriwayatkan dari Abu Bakar, Umar, Utsman, Ali, Thalhah, Jabir, Ibnu Umar, dan Zaid bin Khalid. Dia berkata; saya mendengar Ibnu Abi Umar berkata, saya mendengar Ibnu Uyainah berkata, Muhammad bin 'Ajlan adalah seorang yang tsiqah terpercaya dalam hadits. Abu Isa berkata; 'Ini hadits hasan shahih gharib dari jalur sanad ini. Sedangkan ash Shunabihi adalah Abdurrahman bin Usailah Abu Abdullah, dan telah diriwayatkan dari az Zuhri bahwasanya dia ditanya tentang sabda Nabi shallallahu 'alaihi wasallam: \"Barangsiapa yang mengucapkan; 'Tidak ada tuhan (yang berhak disembah) selain Allah' niscaya dia masuk surga.' Maka dia menjelaskan; 'Hadits ini adalah pada awal Islam sebelum turunnya ibadah Fardhu, perintah dan larangan.' Abu Isa berkata; 'segi pendalilan dari hadits ini menurut sebagian ahli ilmu bahwa ahli tauhid akan masuk surga, walaupun mereka diadzab di neraka disebabkan dosa mereka, namun mereka tidak kekal di neraka. Dan telah diriwayatkan dari Abdullah bin Mas'ud, Abu Dzar, Imran bin Hushain, Jabir bin Abdullah, Ibnu Abbas, Abu Sa'id al Khudri, dan Anas bin Malik dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Akan keluar sejumlah kaum dari manusia dari golongan ahli tauhid, dan masuk surga.\" Demikianlah diriwayatkan dari Sa'id bin Jubair, Ibrahim an Nakha'i, dan tidak hanya satu orang dari kalangan tabi'in dalam menafsirkan ayat ini; 'Orang-orang yang kafir itu seringkali (nanti di akhirat) menginginkan, kiranya mereka dahulu (di dunia) menjadi orang-orang muslim.' (QS. 15: 2) ' Mereka memberikan penafsiran; 'Apabila ahli tauhid dikeluarkan dari neraka dan dimasukkan ke dalam surga, maka berkeinginanlah orang-orang kafir bahwa seandainya mereka dahulu menjadi orang-orang muslim'."},"2496":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ نَصْرٍ أَخْبَرَنَا عَبْدُ اللَّهِ عَنْ لَيْثِ بْنِ سَعْدٍ حَدَّثَنِي عَامِرُ بْنُ يَحْيَى عَنْ أَبِي عَبْدِ الرَّحْمَنِ الْمَعَافِرِيِّ ثُمَّ الْحُبُلِيِّ قَال سَمِعْتُ عَبْدَ اللَّهِ بْنَ عَمْرِو بْنِ الْعَاصِ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ سَيُخَلِّصُ رَجُلًا مِنْ أُمَّتِي عَلَى رُءُوسِ الْخَلَائِقِ يَوْمَ الْقِيَامَةِ فَيَنْشُرُ عَلَيْهِ تِسْعَةً وَتِسْعِينَ سِجِلًّا كُلُّ سِجِلٍّ مِثْلُ مَدِّ الْبَصَرِ ثُمَّ يَقُولُ أَتُنْكِرُ مِنْ هَذَا شَيْئًا أَظَلَمَكَ كَتَبَتِي الْحَافِظُونَ فَيَقُولُ لَا يَا رَبِّ فَيَقُولُ أَفَلَكَ عُذْرٌ فَيَقُولُ لَا يَا رَبِّ فَيَقُولُ بَلَى إِنَّ لَكَ عِنْدَنَا حَسَنَةً فَإِنَّهُ لَا ظُلْمَ عَلَيْكَ الْيَوْمَ فَتَخْرُجُ بِطَاقَةٌ فِيهَا أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ فَيَقُولُ احْضُرْ وَزْنَكَ فَيَقُولُ يَا رَبِّ مَا هَذِهِ الْبِطَاقَةُ مَعَ هَذِهِ السِّجِلَّاتِ فَقَالَ إِنَّكَ لَا تُظْلَمُ قَالَ فَتُوضَعُ السِّجِلَّاتُ فِي كَفَّةٍ وَالْبِطَاقَةُ فِي كَفَّةٍ فَطَاشَتْ السِّجِلَّاتُ وَثَقُلَتْ الْبِطَاقَةُ فَلَا يَثْقُلُ مَعَ اسْمِ اللَّهِ شَيْءٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ عَامِرِ بْنِ يَحْيَى بِهَذَا الْإِسْنَادِ نَحْوَهُ","id":"Telah menceritakan kepada kami [Suwaid bin Nashr] telah mengabarkan kepada kami [Abdullah] dari [Laits bin Sa'd] telah menceritakan kepada kami [Amir bin Yahya] dari [Abu Abdurrahman al Ma'afiri al Hubuli] dia berkata, saya mendengar [Abdullah bin Amru bin al Ash] berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah akan menyelamatkan seorang laki-laki dari umatku di hadapan manusia pada hari kiamat, lalu dia membuka buku catatan besar di hadapannya, setiap buku catatan besar lebarnya seperti sepanjang mata memandang, kemudian Dia berfirman; 'Apakah kamu mengingkari sesuatu dari ini? Apakah para penulisku yang menjaga (amal manusia) menzhalimimu? ' dia menjawab; 'Tidak wahai Rabbku.' Allah bertanya; 'Apakah kamu mempunyai alasan dalih (bagi amal burukmu)? ' Dia menjawab; 'Tidak wahai Rabbku.' Allah berfirman; 'Tidak demikian, sesungguhnya kamu mempunyai kebaikan di sisi Kami, karena itu tidak ada kezhaliman atasmu pada hari ini'. Lalu keluarlah kartu amal kebaikan, yang di dalamnya tercatat bahwa; saya bersaksi bahwa tidak ada tuhan (yang berhak disembah) selain Allah, dan saya bersaksi bahwa Muhammad adalah hamba dan RasulNya.' Lalu Allah berfirman; 'Hadirkan amal timbanganmu! ' dia berkata; 'Wahai Rabbku, apa (artinya) satu kartu amal ini (bila) dibandingkan buku catatan besar ini? ' Allah berfirman; 'Sesungguhnya kamu tidak akan dizhalimi.'\" Nabi melanjutkan; 'Lalu diletakkanlah buku catatan besar pada satu sisi, sedangkan kartu amal diletakkan pada sisi lainnya, maka buku catatan besar itu ringan (timbangannya) sedangkan kartu amal itu berat, maka tidak ada sesuatu pun yang lebih berat dibandingkan nama Allah.\" Abu Isa berkata; 'Ini hadits hasan gharib. Telah menceritakan kepada kami [Qutaibah], telah menceritakan kepada kami [Ibnu Lahi'ah], dari [Amir bin Yahya] dengan sanad ini hadits semisalnya."},"2497":{"ar":"حَدَّثَنَا الْحُسَيْنُ بْنُ حُرَيْثٍ أَبُو عَمَّارٍ حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَفَرَّقَتْ الْيَهُودُ عَلَى إِحْدَى وَسَبْعِينَ أَوْ اثْنَتَيْنِ وَسَبْعِينَ فِرْقَةً وَالنَّصَارَى مِثْلَ ذَلِكَ وَتَفْتَرِقُ أُمَّتِي عَلَى ثَلَاثٍ وَسَبْعِينَ فِرْقَةًوَفِي الْبَاب عَنْ سَعْدٍ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو وَعَوْفِ بْنِ مَالِكٍ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي هُرَيْرَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [al Husain bin Huraits Abu Ammar] telah menceritakan kepada kami [al Fadhl bin Musa] dari [Muhammad bin Amru] dari [Abu Salamah] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kaum Yahudi terpecah menjadi tujuh puluh satu atau tujuh puluh dua golongan. Sedangkan kaum Nashrani seperti itu juga. Dan umatku terpecah menjadi tujuh puluh tiga golongan.\" Dan dalam bab hadits tersebut juga diriwayatkan dari Sa'd dan Abdullah bin Amru serta Auf bin Malik. Abu Isa berkata; 'Hadits Abu Hurairah adalah hadits hasan shahih.\""},"2498":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ الْحَفَرِيُّ عَنْ سُفْيَانَ الثَّوْرِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ زِيَادٍ الْأَفْرِيقِيِّ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيَأْتِيَنَّ عَلَى أُمَّتِي مَا أَتَى عَلَى بَنِي إِسْرَائِيلَ حَذْوَ النَّعْلِ بِالنَّعْلِ حَتَّى إِنْ كَانَ مِنْهُمْ مَنْ أَتَى أُمَّهُ عَلَانِيَةً لَكَانَ فِي أُمَّتِي مَنْ يَصْنَعُ ذَلِكَ وَإِنَّ بَنِي إِسْرَائِيلَ تَفَرَّقَتْ عَلَى ثِنْتَيْنِ وَسَبْعِينَ مِلَّةً وَتَفْتَرِقُ أُمَّتِي عَلَى ثَلَاثٍ وَسَبْعِينَ مِلَّةً كُلُّهُمْ فِي النَّارِ إِلَّا مِلَّةً وَاحِدَةً قَالُوا وَمَنْ هِيَ يَا رَسُولَ اللَّهِ قَالَ مَا أَنَا عَلَيْهِ وَأَصْحَابِيقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مُفَسَّرٌ لَا نَعْرِفُهُ مِثْلَ هَذَا إِلَّا مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Daud Al Hafari] telah bercerita kepada kami [Sufyan Ats Tsauri] dari [Abdurrahman bin Ziyad Al Afriqi] dari [Abdullah bin Yazid] dari [Abdullah bin Amru] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pasti akan datang kepada ummatku, sesuatu yang telah datang pada bani Israil seperti sejajarnya sandal dengan sandal, sehingga apabila di antara mereka (bani Israil) ada orang yang menggauli ibu kandungnya sendiri secara terang terangan maka pasti di antara ummatku ada yang melakukan demikian, sesungguhnya bani Israil terpecah menjadi tujuh puluh dua golongan dan ummatku akan terpecah menjadi tujuh puluh tiga golongan semuanya masuk ke dalam neraka kecuali satu golongan, \" para sahabat bertanya, \"Siapakah mereka wahai Rasulullah?\" Beliau menjawab: \"Mereka adalah golongan yang mana aku dan para sahabatku berpegang teguh padanya\". Abu Isa berkata; 'Hadits ini hasan gharib mufassar, kami tidak mengetahuinya seperti ini kecuali dari jalur sanad seperti ini.'"},"2499":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَرَفَةَ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ عَنْ يَحْيَى بْنِ أَبِي عَمْرٍو السَّيْبَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ الدَّيْلَمِيِّ قَال سَمِعْتُ عَبْدَ اللَّهِ بْنَ عَمْرٍو يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ عَزَّ وَجَلَّ خَلَقَ خَلْقَهُ فِي ظُلْمَةٍ فَأَلْقَى عَلَيْهِمْ مِنْ نُورِهِ فَمَنْ أَصَابَهُ مِنْ ذَلِكَ النُّورِ اهْتَدَى وَمَنْ أَخْطَأَهُ ضَلَّ فَلِذَلِكَ أَقُولُ جَفَّ الْقَلَمُ عَلَى عِلْمِ اللَّهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Al Hasan bin 'Arafah] telah menceritakan kepada kami [Ismail bin 'Ayyasy] dari [Yahya bin Abu 'Amru asy Syaibani] dari [Abdullah bin ad Dailami] dia berkata, aku mendengar [Abdullah bin 'Amru] berkata, Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah telah menciptakan makhluknya dalam kegelapan, lalu Dia menimpakan sebagian dari cahayaNya kepada mereka, maka barangsiapa sebagian dari cahaya tersebut menimpanya niscaya dia mendapatkan cahaya, dan barangsiapa sebagian dari cahaya tersebut tidak mengenainya niscaya dia akan tersesat. Oleh karena itu, aku mengatakan; 'Pena telah kering berdasarkan pengetahuan Allah'.\" Abu Isa berkata; 'Ini hadits hasan.'"},"2500":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو أَحْمَدَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ عَمْرِو بْنِ مَيْمُونٍ عَنْ مُعَاذِ بْنِ جَبَلٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَدْرِي مَا حَقُّ اللَّهِ عَلَى الْعِبَادِ قُلْتُ اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ فَإِنَّ حَقَّهُ عَلَيْهِمْ أَنْ يَعْبُدُوهُ وَلَا يُشْرِكُوا بِهِ شَيْئًا قَالَ أَتَدْرِي مَا حَقُّهُمْ عَلَيْهِ إِذَا فَعَلَوْا ذَلِكَ قُلْتُ اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ أَنْ لَا يُعَذِّبَهُمْهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ مُعَاذِ بْنِ جَبَلٍ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Ahmad] telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq] dari ['Amru bin Maimun] dari [Mu'adz bin Jabal] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah kamu mengetahui apa hak Allah terhadap hambaNya? ' Saya menjawab; 'Allah dan rasulNya lebih mengetahui.' Beliau bersabda: \"Hak Allah atas mereka adalah agar mereka menyembahNya, dan tidak menyekutukanNya dengan sesuatu apapun.\" Beliau bertanya; \"Apakah hak mereka atas Allah apabila mereka telah melakukan hal tersebut? ' Aku menjawab; 'Allah dan RasulNya lebih tahu.' Beliau bersabda: \"Agar Allah tidak mengadzab mereka.\" Ini hadits hasan shahih, dan telah diriwayatkan dari bukan hanya satu sanad, dari Mu'adz bin Jabal."}};
